        teacherNode.addChildNode(makeTeacherGeometry())
        teacherCinematicRimNode.addChildNode(makeTeacherCinematicRimLayer())
        teacherCinematicRimNode.opacity = 0.28
        teacherNode.addChildNode(teacherCinematicRimNode)
