    private func configureWorld() {
        scene.background.contents = NSColor(calibratedRed: 0.025, green: 0.03, blue: 0.038, alpha: 1)
        scene.fogColor = NSColor(calibratedRed: 0.04, green: 0.052, blue: 0.062, alpha: 1)
        scene.fogStartDistance = 8
        scene.fogEndDistance = 28
        scene.lightingEnvironment.contents = NSColor(calibratedRed: 0.48, green: 0.54, blue: 0.68, alpha: 1)
        scene.lightingEnvironment.intensity = 0.55
    }

