    private func makeLensDirtLayer() -> SCNNode {
        let root = SCNNode()
        let colors = [
            NSColor(calibratedWhite: 0.96, alpha: 0.12),
            NSColor(calibratedRed: 0.9, green: 0.82, blue: 0.62, alpha: 0.08),
            NSColor(calibratedRed: 0.58, green: 0.72, blue: 1.0, alpha: 0.07)
        ]
        for index in 0..<18 {
            let x = -0.055 + Float((index * 37) % 110) / 1000
            let y = -0.035 + Float((index * 53) % 70) / 1000
            let speck = sphere(radius: 0.0018 + CGFloat(index % 3) * 0.0007, color: colors[index % colors.count], position: SCNVector3(x, y, 0), scale: SCNVector3(1.4, 0.55, 1))
            root.addChildNode(speck)
        }
        for index in 0..<5 {
            let smear = box(width: 0.032 + CGFloat(index) * 0.006, height: 0.0012, length: 0.001, color: NSColor(calibratedWhite: 0.88, alpha: 0.08), position: SCNVector3(-0.042 + Float(index) * 0.022, 0.028 - Float(index % 2) * 0.018, 0))
            smear.eulerAngles.z = -0.28 + CGFloat(index) * 0.11
            root.addChildNode(smear)
        }
        return root
    }

    private func makeLensFlareLayer() -> SCNNode {
        let root = SCNNode()
        let flareColor = NSColor(calibratedRed: 0.72, green: 0.86, blue: 1.0, alpha: 0.12)
        for index in 0..<4 {
            let flare = sphere(radius: 0.007 + CGFloat(index) * 0.003, color: flareColor, position: SCNVector3(-0.034 + Float(index) * 0.022, 0.024 - Float(index) * 0.012, 0), scale: SCNVector3(1.9, 0.42, 1))
            root.addChildNode(flare)
        }
        let streak = box(width: 0.09, height: 0.0015, length: 0.001, color: NSColor(calibratedRed: 0.86, green: 0.95, blue: 1.0, alpha: 0.1), position: SCNVector3(0.012, 0.018, 0))
        streak.eulerAngles.z = -0.14
        root.addChildNode(streak)
        return root
    }

