    private func makeForegroundOcclusionLayer() -> SCNNode {
        let root = SCNNode()
        let nearShadow = NSColor(calibratedWhite: 0.0, alpha: 0.22)
        let warmDesk = NSColor(calibratedRed: 0.12, green: 0.075, blue: 0.035, alpha: 0.28)
        let sleeve = NSColor(calibratedRed: 0.025, green: 0.035, blue: 0.07, alpha: 0.34)

        let deskLip = box(width: 0.15, height: 0.012, length: 0.001, color: warmDesk, position: SCNVector3(0, -0.052, 0))
        deskLip.name = "foregroundDeskLip"
        deskLip.eulerAngles.z = 0.015
        root.addChildNode(deskLip)

        let leftShoulder = sphere(radius: 0.018, color: nearShadow, position: SCNVector3(-0.066, -0.024, 0.001), scale: SCNVector3(1.2, 2.5, 0.18))
        leftShoulder.name = "foregroundLeftShoulder"
        root.addChildNode(leftShoulder)
        let rightSleeve = sphere(radius: 0.017, color: sleeve, position: SCNVector3(0.062, -0.036, 0.001), scale: SCNVector3(1.5, 1.8, 0.16))
        rightSleeve.name = "foregroundRightSleeve"
        root.addChildNode(rightSleeve)

        for index in 0..<5 {
            let strand = capsule(radius: 0.0016, height: 0.034 + CGFloat(index) * 0.004, color: NSColor(calibratedWhite: 0.01, alpha: 0.32), position: SCNVector3(-0.042 + Float(index) * 0.018, 0.052 - Float(index % 2) * 0.006, 0.002), rotation: SCNVector4(0, 0, 1, -0.25 + Float(index) * 0.12))
            strand.name = "foregroundHairStrand\(index)"
            strand.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: CGFloat(index % 2 == 0 ? 0.025 : -0.018), duration: 1.2 + Double(index) * 0.12),
                .rotateBy(x: 0, y: 0, z: CGFloat(index % 2 == 0 ? -0.025 : 0.018), duration: 1.6 + Double(index) * 0.1)
            ])), forKey: "foreground_hair_sway")
            root.addChildNode(strand)
        }

        for index in 0..<3 {
            let blur = box(width: 0.032 + CGFloat(index) * 0.018, height: 0.004, length: 0.001, color: NSColor(calibratedWhite: 0.02, alpha: 0.16), position: SCNVector3(-0.02 + Float(index) * 0.032, -0.015 + Float(index) * 0.018, 0.001))
            blur.name = "foregroundClassmateBlur\(index)"
            blur.eulerAngles.z = -0.16 + CGFloat(index) * 0.1
            root.addChildNode(blur)
        }
        return root
    }

    private func makeCameraDepthBokehLayer() -> SCNNode {
        let root = SCNNode()
        let colors = [
            NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.42, alpha: 0.12),
            NSColor(calibratedRed: 0.42, green: 0.68, blue: 1.0, alpha: 0.1),
            NSColor(calibratedWhite: 0.92, alpha: 0.08)
        ]
        for index in 0..<14 {
            let x = -0.067 + Float((index * 29) % 134) / 1000
            let y = -0.046 + Float((index * 41) % 92) / 1000
            let radius = 0.0035 + CGFloat(index % 4) * 0.0018
            let bokeh = sphere(radius: radius, color: colors[index % colors.count], position: SCNVector3(x, y, 0), scale: SCNVector3(1.8 + CGFloat(index % 3) * 0.35, 0.7, 0.2))
            bokeh.name = "cameraDepthBokeh\(index)"
            bokeh.geometry?.firstMaterial?.emission.contents = colors[index % colors.count]
            bokeh.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.04, duration: 1.4 + Double(index % 4) * 0.18),
                .fadeOpacity(to: 0.24, duration: 1.9 + Double(index % 5) * 0.16)
            ])), forKey: "bokeh_breathe")
            root.addChildNode(bokeh)
        }
        for index in 0..<4 {
            let streak = box(width: 0.052 + CGFloat(index) * 0.012, height: 0.001, length: 0.001, color: NSColor(calibratedRed: 0.78, green: 0.9, blue: 1.0, alpha: 0.07), position: SCNVector3(-0.046 + Float(index) * 0.03, 0.038 - Float(index % 2) * 0.028, 0.001))
            streak.name = "cameraAnamorphicBokeh\(index)"
            streak.eulerAngles.z = -0.08 + CGFloat(index) * 0.035
            root.addChildNode(streak)
        }
        return root
    }

