        let deskWood = NSColor(calibratedRed: 0.12, green: 0.07, blue: 0.032, alpha: 0.24)
        let windowCool = NSColor(calibratedRed: 0.18, green: 0.34, blue: 0.78, alpha: 0.09)
        let warmPaper = NSColor(calibratedRed: 1.0, green: 0.84, blue: 0.5, alpha: 0.07)
        let skinShadow = NSColor(calibratedRed: 0.08, green: 0.035, blue: 0.026, alpha: 0.16)
