        let bottomDesk = box(width: 0.17, height: 0.018, length: 0.001, color: deskWood, position: SCNVector3(0, -0.056, 0.001))
        bottomDesk.name = "foregroundDepthDeskEdgeMatte"
        bottomDesk.eulerAngles.z = 0.018
        root.addChildNode(bottomDesk)

        let leftCurtain = box(width: 0.018, height: 0.116, length: 0.001, color: matte.withAlphaComponent(0.14), position: SCNVector3(-0.074, -0.002, 0.001))
        leftCurtain.name = "foregroundDepthLeftCurtain"
        root.addChildNode(leftCurtain)

        let rightCurtain = box(width: 0.018, height: 0.116, length: 0.001, color: matte.withAlphaComponent(0.14), position: SCNVector3(0.074, -0.002, 0.001))
        rightCurtain.name = "foregroundDepthRightCurtain"
        root.addChildNode(rightCurtain)

        for index in 0..<4 {
            let slice = box(width: 0.018 + CGFloat(index) * 0.006, height: 0.002, length: 0.001, color: windowCool, position: SCNVector3(-0.052 + Float(index) * 0.035, 0.04 - Float(index % 2) * 0.066, 0.002))
            slice.name = "foregroundDepthWindowFrameSlice\(index)"
            slice.eulerAngles.z = -0.42 + CGFloat(index) * 0.08
            root.addChildNode(slice)
        }

        let paperLanding = box(width: 0.064, height: 0.012, length: 0.001, color: warmPaper, position: SCNVector3(-0.018, -0.036, 0.002))
        paperLanding.name = "foregroundDepthPaperLanding"
        paperLanding.eulerAngles.z = -0.04
        root.addChildNode(paperLanding)

        let shoulderMass = sphere(radius: 0.018, color: skinShadow, position: SCNVector3(-0.064, -0.034, 0.002), scale: SCNVector3(1.1, 2.2, 0.14))
        shoulderMass.name = "foregroundDepthShoulderMass"
        root.addChildNode(shoulderMass)

        let teacherGate = box(width: 0.048, height: 0.094, length: 0.001, color: teacherDark, position: SCNVector3(0.052, 0.0, 0.003))
        teacherGate.name = "foregroundDepthTeacherNearGate"
        teacherGate.eulerAngles.z = -0.05
