        let rearTunnel = box(width: 0.112, height: 0.018, length: 0.001, color: matte.withAlphaComponent(0.1), position: SCNVector3(0, 0.034, 0.002))
        rearTunnel.name = "foregroundDepthRearTunnelCap"
