        for index in 0..<5 {
            let mote = sphere(radius: 0.0018 + CGFloat(index % 2) * 0.0006, color: warmPaper.withAlphaComponent(0.11), position: SCNVector3(-0.054 + Float(index) * 0.026, -0.026 + Float(index % 3) * 0.018, 0.004), scale: SCNVector3(1.6, 0.6, 0.12))
