    private func makeCinematicFocusRackLayer() -> SCNNode {
        let root = SCNNode()
        let focusWarm = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.42, alpha: 0.07)
        let focusCool = NSColor(calibratedRed: 0.4, green: 0.72, blue: 1.0, alpha: 0.065)
        let pressureEdge = NSColor(calibratedWhite: 0.0, alpha: 0.14)
        let eventWarm = NSColor(calibratedRed: 1.0, green: 0.3, blue: 0.12, alpha: 0.06)

        let centerBreath = box(width: 0.07, height: 0.04, length: 0.001, color: focusWarm, position: SCNVector3(0, -0.006, 0))
        centerBreath.name = "focusRackCenterBreath"
        centerBreath.runAction(.repeatForever(.sequence([
            .scale(to: 1.08, duration: 1.1),
            .scale(to: 0.94, duration: 1.35)
        ])), forKey: "focus_center_breathe")
        root.addChildNode(centerBreath)

        let deskPlane = box(width: 0.11, height: 0.014, length: 0.001, color: focusWarm.withAlphaComponent(0.08), position: SCNVector3(-0.018, -0.037, 0.001))
        deskPlane.name = "focusRackDeskPlane"
        deskPlane.eulerAngles.z = -0.035
        root.addChildNode(deskPlane)

        let boardPlane = box(width: 0.096, height: 0.03, length: 0.001, color: focusCool, position: SCNVector3(0.014, 0.024, 0.001))
        boardPlane.name = "focusRackBoardPlane"
        boardPlane.eulerAngles.z = 0.018
        root.addChildNode(boardPlane)

        let teacherPressure = box(width: 0.042, height: 0.078, length: 0.001, color: eventWarm, position: SCNVector3(0.038, 0.002, 0.002))
        teacherPressure.name = "focusRackTeacherPressure"
        teacherPressure.eulerAngles.z = -0.08
        root.addChildNode(teacherPressure)

        let leftEdge = box(width: 0.012, height: 0.12, length: 0.001, color: pressureEdge, position: SCNVector3(-0.071, 0, 0.002))
        leftEdge.name = "focusRackLeftFalloff"
        root.addChildNode(leftEdge)
        let rightEdge = box(width: 0.012, height: 0.12, length: 0.001, color: pressureEdge, position: SCNVector3(0.071, 0, 0.002))
        rightEdge.name = "focusRackRightFalloff"
        root.addChildNode(rightEdge)

        for index in 0..<7 {
            let bokeh = sphere(radius: 0.0024 + CGFloat(index % 3) * 0.001, color: index % 2 == 0 ? focusWarm : focusCool, position: SCNVector3(-0.054 + Float(index) * 0.018, 0.04 - Float(index % 3) * 0.034, 0.003), scale: SCNVector3(2.0, 0.5, 0.15))
            bokeh.name = "focusRackMicroBokeh\(index)"
            bokeh.geometry?.firstMaterial?.emission.contents = index % 2 == 0 ? focusWarm : focusCool
            bokeh.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.03, duration: 0.8 + Double(index % 4) * 0.12),
                .fadeOpacity(to: 0.18, duration: 1.1 + Double(index % 3) * 0.16)
            ])), forKey: "focus_micro_bokeh")
            root.addChildNode(bokeh)
        }

        root.opacity = 0.08
        return root
    }

    private func makeFilmGrainLayer() -> SCNNode {
        let root = SCNNode()
        let speckColors = [
            NSColor(calibratedWhite: 1.0, alpha: 0.09),
            NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.58, alpha: 0.06),
            NSColor(calibratedRed: 0.42, green: 0.64, blue: 1.0, alpha: 0.055),
            NSColor(calibratedWhite: 0.05, alpha: 0.08)
        ]

        for index in 0..<44 {
            let x = -0.072 + Float((index * 31) % 144) / 1000
            let y = -0.052 + Float((index * 47) % 104) / 1000
            let grain = box(
                width: 0.0012 + CGFloat(index % 3) * 0.00045,
                height: 0.00065 + CGFloat(index % 2) * 0.00035,
                length: 0.001,
                color: speckColors[index % speckColors.count],
                position: SCNVector3(x, y, 0)
            )
            grain.name = "filmGrainSpeck\(index)"
            grain.eulerAngles.z = CGFloat(index % 9) * 0.17
            grain.geometry?.firstMaterial?.emission.contents = speckColors[index % speckColors.count]
            grain.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.02, duration: 0.18 + Double(index % 5) * 0.025),
                .fadeOpacity(to: 0.16, duration: 0.22 + Double(index % 7) * 0.025),
                .wait(duration: 0.12 + Double(index % 4) * 0.03)
            ])), forKey: "film_grain_flicker")
            root.addChildNode(grain)
        }

        for index in 0..<9 {
            let line = box(
                width: 0.14 - CGFloat(index % 3) * 0.018,
                height: 0.00045,
                length: 0.001,
                color: NSColor(calibratedWhite: 0.9, alpha: 0.035),
                position: SCNVector3(0, -0.048 + Float(index) * 0.012, 0.001)
            )
            line.name = "filmGateScanline\(index)"
            line.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.0018, z: 0, duration: 0.35 + Double(index) * 0.03),
                .moveBy(x: 0, y: -0.0018, z: 0, duration: 0.42 + Double(index) * 0.02)
            ])), forKey: "film_scanline_swim")
            root.addChildNode(line)
        }

        let subtleGate = box(width: 0.154, height: 0.001, length: 0.001, color: NSColor(calibratedWhite: 0.0, alpha: 0.1), position: SCNVector3(0, 0.056, 0.002))
        subtleGate.name = "filmGateTopPressure"
        root.addChildNode(subtleGate)
        let bottomGate = box(width: 0.154, height: 0.001, length: 0.001, color: NSColor(calibratedWhite: 0.0, alpha: 0.08), position: SCNVector3(0, -0.056, 0.002))
        bottomGate.name = "filmGateBottomPressure"
        root.addChildNode(bottomGate)
        return root
    }

    private func makeChromaticEdgeLayer() -> SCNNode {
        let root = SCNNode()
        let redSplit = NSColor(calibratedRed: 1.0, green: 0.12, blue: 0.05, alpha: 0.13)
        let cyanSplit = NSColor(calibratedRed: 0.08, green: 0.82, blue: 1.0, alpha: 0.12)
        let violetSplit = NSColor(calibratedRed: 0.54, green: 0.28, blue: 1.0, alpha: 0.09)

        let leftRed = box(width: 0.003, height: 0.11, length: 0.001, color: redSplit, position: SCNVector3(-0.075, 0, 0))
        leftRed.name = "chromaticLeftRed"
        let leftCyan = box(width: 0.0024, height: 0.108, length: 0.001, color: cyanSplit, position: SCNVector3(-0.071, -0.001, 0.001))
        leftCyan.name = "chromaticLeftCyan"
        let rightRed = box(width: 0.0024, height: 0.108, length: 0.001, color: redSplit, position: SCNVector3(0.071, 0.001, 0.001))
        rightRed.name = "chromaticRightRed"
        let rightCyan = box(width: 0.003, height: 0.11, length: 0.001, color: cyanSplit, position: SCNVector3(0.075, 0, 0))
        rightCyan.name = "chromaticRightCyan"
        root.addChildNode(leftRed)
        root.addChildNode(leftCyan)
        root.addChildNode(rightRed)
        root.addChildNode(rightCyan)

        let topCyan = box(width: 0.15, height: 0.0022, length: 0.001, color: cyanSplit, position: SCNVector3(0, 0.055, 0.001))
        topCyan.name = "chromaticTopCyan"
        let bottomRed = box(width: 0.15, height: 0.0022, length: 0.001, color: redSplit, position: SCNVector3(0, -0.055, 0.001))
        bottomRed.name = "chromaticBottomRed"
        root.addChildNode(topCyan)
        root.addChildNode(bottomRed)

        for index in 0..<6 {
            let corner = box(
                width: 0.024 + CGFloat(index % 3) * 0.006,
                height: 0.001,
                length: 0.001,
                color: index % 2 == 0 ? violetSplit : cyanSplit,
                position: SCNVector3(index < 3 ? -0.058 + Float(index) * 0.012 : 0.034 + Float(index - 3) * 0.012, index % 2 == 0 ? 0.044 : -0.044, 0.002)
            )
            corner.name = "chromaticCornerSplit\(index)"
            corner.eulerAngles.z = index % 2 == 0 ? -0.26 : 0.22
            corner.geometry?.firstMaterial?.emission.contents = index % 2 == 0 ? violetSplit : cyanSplit
            root.addChildNode(corner)
        }
        return root
    }

    private func makeExposureBreathLayer() -> SCNNode {
        let root = SCNNode()
        let warm = box(width: 0.13, height: 0.08, length: 0.001, color: NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.36, alpha: 0.055), position: SCNVector3(-0.01, -0.006, 0))
        warm.name = "exposureWarmBreath"
        warm.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.75, green: 0.35, blue: 0.12, alpha: 0.08)
        root.addChildNode(warm)

        let cool = box(width: 0.12, height: 0.07, length: 0.001, color: NSColor(calibratedRed: 0.16, green: 0.42, blue: 1.0, alpha: 0.045), position: SCNVector3(0.012, 0.008, 0.001))
        cool.name = "exposureCoolRecovery"
        cool.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.06, green: 0.2, blue: 0.72, alpha: 0.075)
        root.addChildNode(cool)

        let top = box(width: 0.16, height: 0.018, length: 0.001, color: NSColor(calibratedWhite: 0.0, alpha: 0.13), position: SCNVector3(0, 0.048, 0.002))
        top.name = "exposureTopRolloff"
        root.addChildNode(top)
        let bottom = box(width: 0.16, height: 0.018, length: 0.001, color: NSColor(calibratedWhite: 0.0, alpha: 0.12), position: SCNVector3(0, -0.049, 0.002))
        bottom.name = "exposureBottomRolloff"
        root.addChildNode(bottom)

        for index in 0..<5 {
            let pulse = sphere(
                radius: 0.004 + CGFloat(index) * 0.0012,
                color: NSColor(calibratedRed: 1.0, green: 0.9, blue: 0.62, alpha: 0.05),
                position: SCNVector3(-0.05 + Float(index) * 0.025, 0.028 - Float(index % 2) * 0.046, 0.003),
                scale: SCNVector3(2.2, 0.5, 0.12)
            )
            pulse.name = "exposureIrisGhost\(index)"
            pulse.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.9, green: 0.62, blue: 0.2, alpha: 0.055)
            pulse.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.03, duration: 1.1 + Double(index) * 0.16),
                .fadeOpacity(to: 0.18, duration: 1.35 + Double(index) * 0.12)
            ])), forKey: "exposure_iris_breathe")
            root.addChildNode(pulse)
        }
        return root
    }

    private func makeCinematicGradeLayer() -> SCNNode {
        let root = SCNNode()
        let highlight = box(width: 0.16, height: 0.105, length: 0.001, color: NSColor(calibratedRed: 1.0, green: 0.76, blue: 0.42, alpha: 0.035), position: SCNVector3(0.004, 0.006, 0))
        highlight.name = "gradeWarmHighlightRolloff"
