    private func makeEventCinematicOverlayLayer() -> SCNNode {
        let root = SCNNode()
        let darkEdge = NSColor(calibratedWhite: 0.0, alpha: 0.28)
        let warmCut = NSColor(calibratedRed: 1.0, green: 0.22, blue: 0.12, alpha: 0.16)
        let coolCut = NSColor(calibratedRed: 0.22, green: 0.58, blue: 1.0, alpha: 0.14)

        let left = box(width: 0.018, height: 0.13, length: 0.001, color: darkEdge, position: SCNVector3(-0.074, 0, 0))
        left.name = "eventLeftEdge"
        let right = box(width: 0.018, height: 0.13, length: 0.001, color: darkEdge, position: SCNVector3(0.074, 0, 0))
        right.name = "eventRightEdge"
        let top = box(width: 0.16, height: 0.012, length: 0.001, color: darkEdge, position: SCNVector3(0, 0.054, 0))
        top.name = "eventTopEdge"
        let bottom = box(width: 0.16, height: 0.014, length: 0.001, color: darkEdge, position: SCNVector3(0, -0.054, 0))
        bottom.name = "eventBottomEdge"
        root.addChildNode(left)
        root.addChildNode(right)
        root.addChildNode(top)
        root.addChildNode(bottom)

        let warm = box(width: 0.042, height: 0.006, length: 0.001, color: warmCut, position: SCNVector3(-0.024, 0.034, 0.001))
        warm.name = "eventWarmCut"
        warm.eulerAngles.z = -0.24
        root.addChildNode(warm)
        let cool = box(width: 0.052, height: 0.005, length: 0.001, color: coolCut, position: SCNVector3(0.03, -0.025, 0.001))
        cool.name = "eventCoolCut"
        cool.eulerAngles.z = 0.18
        root.addChildNode(cool)

        for index in 0..<7 {
            let scan = box(width: 0.13 - CGFloat(index % 3) * 0.012, height: 0.0008, length: 0.001, color: NSColor(calibratedWhite: 0.95, alpha: 0.055), position: SCNVector3(0, -0.042 + Float(index) * 0.014, 0.002))
            scan.name = "eventScanline\(index)"
            scan.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.02, duration: 0.28 + Double(index) * 0.02),
                .fadeOpacity(to: 0.12, duration: 0.36 + Double(index) * 0.03)
            ])), forKey: "scan_breathe")
            root.addChildNode(scan)
        }
        return root
    }

    private func applyCameraMode(game: GameManager, teacherPosition: SCNVector3) {
        switch game.viewMode {
        case .student:
            if game.freeRoam.isActive {
                cameraRig.position = SCNVector3(Float(game.freeRoam.positionX), 1.58, Float(game.freeRoam.positionZ))
                cameraRig.eulerAngles = SCNVector3(Float(game.freeRoam.pitch), Float(game.freeRoam.yaw), game.freeRoam.isSideways ? 0.08 : 0)
                cameraRig.camera?.fieldOfView = 92
            } else {
                let height: Float = game.player.posture == .standing ? 1.58 : 1.18
                let stressSway = Float(min(0.035, game.player.stress / 2_500))
                let attentionDip = Float(max(0, 35 - game.player.visualAttention) / 1_200)
                cameraRig.position = SCNVector3(-0.6 + stressSway, height - attentionDip, 1.5)
                cameraRig.eulerAngles = SCNVector3(Float(game.studentLookPitch), Float(game.studentLookYaw), 0)
                cameraRig.camera?.fieldOfView = 100
            }
        case .teacher:
            cameraRig.position = SCNVector3(teacherPosition.x, 1.48, teacherPosition.z + 0.18)
            let target = teacherCameraTarget(game: game)
            cameraRig.eulerAngles = teacherEulerAngles(from: cameraRig.position, to: target)
            cameraRig.camera?.fieldOfView = game.teacher.focusMode == .wholeClass ? 88 : 74
        }
        lastCameraBreathOffset = SCNVector3Zero
        lastCameraRollOffset = 0
    }

    private func applyCameraBreathing(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        cameraRig.position = SCNVector3(
            cameraRig.position.x - lastCameraBreathOffset.x,
            cameraRig.position.y - lastCameraBreathOffset.y,
            cameraRig.position.z - lastCameraBreathOffset.z
        )
        cameraRig.eulerAngles.z -= lastCameraRollOffset

        guard !game.freeRoam.isActive else {
            lastCameraBreathOffset = SCNVector3Zero
            lastCameraRollOffset = 0
            return
        }

        let time = Float(Date().timeIntervalSinceReferenceDate)
        let stress = Float((game.player.stress / 160).clamped(to: 0...1))
        let event = Float(eventIntensity.vignette.clamped(to: 0...1))
        let fatigue = Float((game.viewMode == .teacher ? game.teacher.fatigue / 130 : 1 - game.player.focusQuality).clamped(to: 0...1))
        let studentMultiplier: Float = game.viewMode == .student ? 1.0 : 0.45
        let offset = SCNVector3(
            sin(time * 1.17) * (0.0025 + stress * 0.004 + event * 0.008) * studentMultiplier,
            sin(time * 0.82) * (0.003 + fatigue * 0.004 + event * 0.009) * studentMultiplier,
            cos(time * 0.96) * (0.0015 + stress * 0.003 + event * 0.006) * studentMultiplier
        )
        let roll = sin(time * 1.5) * (0.002 + stress * 0.004 + event * 0.012) * studentMultiplier
        cameraRig.position = SCNVector3(cameraRig.position.x + offset.x, cameraRig.position.y + offset.y, cameraRig.position.z + offset.z)
        cameraRig.eulerAngles.z += roll
        lastCameraBreathOffset = offset
        lastCameraRollOffset = roll
    }

    private func updateCameraLensLayers(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let lowLight = max(0, 0.68 - game.classroomLightLevel)
        let stress = (game.player.stress / 140).clamped(to: 0...1)
        let event = eventIntensity.vignette.clamped(to: 0...1)
        let studentView = game.viewMode == .student ? 1.0 : 0.55
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        lensDirtNode.opacity = CGFloat((0.12 + lowLight * 0.28 + event * 0.18).clamped(to: 0.1...0.48))
        lensFlareNode.opacity = CGFloat((0.05 + (1 - lowLight) * 0.08 + event * 0.22 + (game.teacher.isNearPlayer ? 0.12 : 0)).clamped(to: 0.04...0.48))
        foregroundVignetteNode.opacity = CGFloat((0.12 + stress * 0.18 + event * 0.28 + teacherNear * 0.16).clamped(to: 0.1...0.72) * studentView)
        let deskView = game.cameraPose == .desk ? 1.0 : 0.0
        let seatedView = game.player.posture == .seated ? 1.0 : 0.45
        foregroundOcclusionNode.opacity = CGFloat((0.1 + deskView * 0.2 + stress * 0.16 + event * 0.22 + teacherNear * 0.18).clamped(to: 0.08...0.78) * studentView)
        foregroundOcclusionNode.childNode(withName: "foregroundDeskLip", recursively: true)?.opacity = CGFloat((0.22 + deskView * 0.48 + teacherNear * 0.16).clamped(to: 0.16...0.9))
        foregroundOcclusionNode.childNode(withName: "foregroundLeftShoulder", recursively: true)?.opacity = CGFloat((0.2 + stress * 0.28 + event * 0.22 + teacherNear * 0.14).clamped(to: 0.12...0.74) * seatedView)
        foregroundOcclusionNode.childNode(withName: "foregroundRightSleeve", recursively: true)?.opacity = CGFloat((0.16 + deskView * 0.36 + stress * 0.18 + teacherNear * 0.12).clamped(to: 0.1...0.7))
        for index in 0..<5 {
            foregroundOcclusionNode.childNode(withName: "foregroundHairStrand\(index)", recursively: true)?.opacity = CGFloat((0.08 + stress * 0.26 + event * 0.2).clamped(to: 0.04...0.48) * seatedView)
        }
        for index in 0..<3 {
            foregroundOcclusionNode.childNode(withName: "foregroundClassmateBlur\(index)", recursively: true)?.opacity = CGFloat((game.cameraPose == .rear ? 0.34 : 0.12) + event * 0.16)
        }
        foregroundOcclusionNode.eulerAngles.z = Float(stress * 0.025 + event * 0.04 + teacherNear * 0.018)
        foregroundOcclusionNode.scale = SCNVector3(1 + CGFloat(event) * 0.04 + CGFloat(teacherNear) * 0.03, 1 + CGFloat(stress) * 0.03 + CGFloat(teacherNear) * 0.025, 1)
        cameraDepthBokehNode.opacity = CGFloat((0.04 + lowLight * 0.24 + event * 0.22 + (game.cameraPose == .rear ? 0.12 : 0)).clamped(to: 0.03...0.58) * studentView)
        cameraDepthBokehNode.eulerAngles.z = Float(event * 0.035 - stress * 0.018)
        cameraDepthBokehNode.scale = SCNVector3(1 + CGFloat(event) * 0.08, 1 + CGFloat(lowLight) * 0.08, 1)
        for index in 0..<14 {
            cameraDepthBokehNode.childNode(withName: "cameraDepthBokeh\(index)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.28 + event * 0.26).clamped(to: 0.05...0.56))
        }
        let deskFocus = game.cameraPose == .desk ? 1.0 : 0.0
        let boardFocus = game.cameraPose == .board ? 1.0 : 0.0
        let rearFocus = game.cameraPose == .rear ? 1.0 : 0.0
        compositionFocusNode.opacity = CGFloat((0.08 + stress * 0.14 + event * 0.2 + lowLight * 0.08).clamped(to: 0.04...0.48) * studentView)
        compositionFocusNode.childNode(withName: "compositionDeskBottomMask", recursively: true)?.opacity = CGFloat((0.12 + deskFocus * 0.54 + stress * 0.12).clamped(to: 0.08...0.76))
        compositionFocusNode.childNode(withName: "compositionPaperFocusGlow", recursively: true)?.opacity = CGFloat((0.04 + deskFocus * 0.36 + event * 0.08).clamped(to: 0.02...0.48))
        compositionFocusNode.childNode(withName: "compositionBoardCenterGlow", recursively: true)?.opacity = CGFloat((0.04 + boardFocus * 0.44 + event * 0.1).clamped(to: 0.02...0.56))
        compositionFocusNode.childNode(withName: "compositionRearLeftTunnel", recursively: true)?.opacity = CGFloat((0.06 + rearFocus * 0.36 + event * 0.12).clamped(to: 0.04...0.52))
        compositionFocusNode.childNode(withName: "compositionRearRightTunnel", recursively: true)?.opacity = CGFloat((0.06 + rearFocus * 0.36 + event * 0.12).clamped(to: 0.04...0.52))
        for index in 0..<4 {
            compositionFocusNode.childNode(withName: "compositionAisleDepthGlint\(index)", recursively: true)?.opacity = CGFloat((0.04 + rearFocus * 0.24 + lowLight * 0.12).clamped(to: 0.02...0.36))
        }
        compositionFocusNode.eulerAngles.z = Float(event * 0.025 - stress * 0.014)
        compositionFocusNode.scale = SCNVector3(1 + CGFloat(event) * 0.035, 1 + CGFloat(stress) * 0.025, 1)
        cinematicForegroundDepthNode.opacity = CGFloat((0.04 + deskFocus * 0.18 + rearFocus * 0.08 + stress * 0.12 + event * 0.2 + teacherNear * 0.22 + lowLight * 0.08).clamped(to: 0.02...0.72) * studentView)
        cinematicForegroundDepthNode.eulerAngles.z = Float(event * 0.026 + stress * 0.012 - rearFocus * 0.008)
        cinematicForegroundDepthNode.scale = SCNVector3(1 + CGFloat(event) * 0.035 + CGFloat(teacherNear) * 0.025, 1 + CGFloat(stress) * 0.02 + CGFloat(deskFocus) * 0.018, 1)
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthTopMatte", recursively: true)?.opacity = CGFloat((0.06 + event * 0.16 + teacherNear * 0.12 + rearFocus * 0.08).clamped(to: 0.03...0.38))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthDeskEdgeMatte", recursively: true)?.opacity = CGFloat((0.08 + deskFocus * 0.46 + stress * 0.12 + teacherNear * 0.1).clamped(to: 0.04...0.72))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthDeskEdgeMatte", recursively: true)?.position.y = Float(-0.056 + deskFocus * -0.004 + event * 0.002)
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthLeftCurtain", recursively: true)?.opacity = CGFloat((0.06 + stress * 0.12 + event * 0.16 + teacherNear * 0.08).clamped(to: 0.03...0.4))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthRightCurtain", recursively: true)?.opacity = CGFloat((0.06 + stress * 0.1 + event * 0.18 + teacherNear * 0.16).clamped(to: 0.03...0.46))
        for index in 0..<4 {
            let slice = cinematicForegroundDepthNode.childNode(withName: "foregroundDepthWindowFrameSlice\(index)", recursively: true)
            slice?.opacity = CGFloat((0.02 + lowLight * 0.12 + rearFocus * 0.12 + event * 0.08 - Double(index) * 0.006).clamped(to: 0.01...0.28))
            slice?.eulerAngles.z = CGFloat(-0.42 + Double(index) * 0.08 + event * 0.05)
        }
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthPaperLanding", recursively: true)?.opacity = CGFloat((0.02 + deskFocus * 0.32 + event * 0.06).clamped(to: 0.01...0.42))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthShoulderMass", recursively: true)?.opacity = CGFloat((0.04 + stress * 0.2 + event * 0.12 + teacherNear * 0.12).clamped(to: 0.02...0.42))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthTeacherNearGate", recursively: true)?.opacity = CGFloat((0.01 + teacherNear * 0.42 + event * 0.12).clamped(to: 0...0.56))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthTeacherNearGate", recursively: true)?.position.x = Float(0.052 + (teacherNode.position.x * 0.004).clamped(to: -0.016...0.016))
        cinematicForegroundDepthNode.childNode(withName: "foregroundDepthRearTunnelCap", recursively: true)?.opacity = CGFloat((0.03 + rearFocus * 0.3 + lowLight * 0.08 + event * 0.08).clamped(to: 0.01...0.36))
        for index in 0..<5 {
            let dust = cinematicForegroundDepthNode.childNode(withName: "foregroundDepthFocusDust\(index)", recursively: true)
            dust?.opacity = CGFloat((0.015 + deskFocus * 0.08 + lowLight * 0.08 + event * 0.08 - Double(index) * 0.004).clamped(to: 0.005...0.2))
            dust?.position.y = Float(-0.026 + Double(index % 3) * 0.018 + event * 0.003)
        }
        cinematicFocusRackNode.opacity = CGFloat((0.04 + deskFocus * 0.18 + boardFocus * 0.14 + rearFocus * 0.08 + event * 0.2 + teacherNear * 0.18 + lowLight * 0.08).clamped(to: 0.03...0.62) * studentView)
        cinematicFocusRackNode.eulerAngles.z = Float(event * 0.035 - teacherNear * 0.018 + stress * 0.012)
        cinematicFocusRackNode.scale = SCNVector3(1 + CGFloat(event) * 0.05 + CGFloat(teacherNear) * 0.035, 1 + CGFloat(stress) * 0.035, 1)
        cinematicFocusRackNode.childNode(withName: "focusRackCenterBreath", recursively: true)?.opacity = CGFloat((0.08 + event * 0.14 + teacherNear * 0.18).clamped(to: 0.04...0.42))
        cinematicFocusRackNode.childNode(withName: "focusRackDeskPlane", recursively: true)?.opacity = CGFloat((0.04 + deskFocus * 0.44 + stress * 0.08).clamped(to: 0.02...0.56))
        cinematicFocusRackNode.childNode(withName: "focusRackBoardPlane", recursively: true)?.opacity = CGFloat((0.04 + boardFocus * 0.42 + lowLight * 0.1).clamped(to: 0.02...0.54))
        cinematicFocusRackNode.childNode(withName: "focusRackTeacherPressure", recursively: true)?.opacity = CGFloat((0.02 + teacherNear * 0.48 + event * 0.16).clamped(to: 0.01...0.62))
        cinematicFocusRackNode.childNode(withName: "focusRackLeftFalloff", recursively: true)?.opacity = CGFloat((0.08 + stress * 0.14 + event * 0.18 + teacherNear * 0.16).clamped(to: 0.04...0.5))
        cinematicFocusRackNode.childNode(withName: "focusRackRightFalloff", recursively: true)?.opacity = CGFloat((0.08 + stress * 0.12 + event * 0.2 + teacherNear * 0.18).clamped(to: 0.04...0.52))
        for index in 0..<7 {
            cinematicFocusRackNode.childNode(withName: "focusRackMicroBokeh\(index)", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.16 + event * 0.18 + rearFocus * 0.08 + Double(index % 3) * 0.012).clamped(to: 0.02...0.34))
        }
        let teacherPulse = game.teacher.isNearPlayer ? 0.12 : 0.0
        filmGrainNode.opacity = CGFloat((0.04 + lowLight * 0.2 + stress * 0.12 + event * 0.16).clamped(to: 0.03...0.44) * studentView)
        filmGrainNode.eulerAngles.z = Float(game.currentTurn % 11) * 0.004 - Float(event) * 0.012
        filmGrainNode.scale = SCNVector3(1 + CGFloat(event) * 0.018, 1 + CGFloat(stress) * 0.012, 1)
        for index in 0..<44 {
            let jitter = Double((game.currentTurn + index) % 5) * 0.012
            filmGrainNode.childNode(withName: "filmGrainSpeck\(index)", recursively: true)?.opacity = CGFloat((0.035 + lowLight * 0.14 + event * 0.12 + jitter).clamped(to: 0.02...0.32))
        }
        for index in 0..<9 {
            filmGrainNode.childNode(withName: "filmGateScanline\(index)", recursively: true)?.opacity = CGFloat((0.025 + lowLight * 0.08 + event * 0.08).clamped(to: 0.02...0.2))
        }
        filmGrainNode.childNode(withName: "filmGateTopPressure", recursively: true)?.opacity = CGFloat((0.06 + event * 0.16 + stress * 0.08).clamped(to: 0.04...0.32))
        filmGrainNode.childNode(withName: "filmGateBottomPressure", recursively: true)?.opacity = CGFloat((0.05 + event * 0.14 + stress * 0.1).clamped(to: 0.04...0.32))

        chromaticEdgeNode.opacity = CGFloat((0.02 + event * 0.26 + stress * 0.08 + teacherPulse).clamped(to: 0.02...0.5) * studentView)
        chromaticEdgeNode.eulerAngles.z = Float(event * 0.012 - stress * 0.008)
        chromaticEdgeNode.scale = SCNVector3(1 + CGFloat(event) * 0.025, 1 + CGFloat(stress) * 0.018, 1)
        chromaticEdgeNode.childNode(withName: "chromaticLeftRed", recursively: true)?.position.x = Float(-0.075 - event * 0.004)
        chromaticEdgeNode.childNode(withName: "chromaticRightCyan", recursively: true)?.position.x = Float(0.075 + event * 0.004)
        chromaticEdgeNode.childNode(withName: "chromaticTopCyan", recursively: true)?.opacity = CGFloat((0.05 + event * 0.22 + lowLight * 0.06).clamped(to: 0.03...0.34))
        chromaticEdgeNode.childNode(withName: "chromaticBottomRed", recursively: true)?.opacity = CGFloat((0.05 + event * 0.2 + stress * 0.08).clamped(to: 0.03...0.34))
        for index in 0..<6 {
            chromaticEdgeNode.childNode(withName: "chromaticCornerSplit\(index)", recursively: true)?.opacity = CGFloat((0.04 + event * 0.22 + teacherPulse * 0.6).clamped(to: 0.02...0.38))
        }

        exposureBreathNode.opacity = CGFloat((0.04 + lowLight * 0.12 + event * 0.18 + boardFocus * 0.08 + teacherPulse * 0.42).clamped(to: 0.02...0.48) * studentView)
        exposureBreathNode.eulerAngles.z = Float(stress * -0.006 + event * 0.012)
        exposureBreathNode.childNode(withName: "exposureWarmBreath", recursively: true)?.opacity = CGFloat((0.05 + game.classroomLightLevel * 0.12 + event * 0.1 + teacherPulse * 0.32).clamped(to: 0.03...0.34))
        exposureBreathNode.childNode(withName: "exposureCoolRecovery", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.2 + event * 0.1).clamped(to: 0.02...0.34))
        exposureBreathNode.childNode(withName: "exposureTopRolloff", recursively: true)?.opacity = CGFloat((0.08 + stress * 0.12 + event * 0.14).clamped(to: 0.06...0.36))
        exposureBreathNode.childNode(withName: "exposureBottomRolloff", recursively: true)?.opacity = CGFloat((0.08 + deskFocus * 0.18 + stress * 0.1 + event * 0.12).clamped(to: 0.06...0.38))
        for index in 0..<5 {
            exposureBreathNode.childNode(withName: "exposureIrisGhost\(index)", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.12 + event * 0.16 + Double(index) * 0.012).clamped(to: 0.02...0.32))
        }

        cinematicGradeNode.opacity = CGFloat((0.05 + lowLight * 0.16 + event * 0.22 + stress * 0.08 + teacherPulse * 0.62).clamped(to: 0.03...0.58) * studentView)
        cinematicGradeNode.eulerAngles.z = Float(event * 0.01 - stress * 0.006)
        cinematicGradeNode.scale = SCNVector3(1 + CGFloat(event) * 0.018, 1 + CGFloat(lowLight) * 0.012, 1)
        cinematicGradeNode.childNode(withName: "gradeWarmHighlightRolloff", recursively: true)?.opacity = CGFloat((0.04 + game.classroomLightLevel * 0.1 + event * 0.08).clamped(to: 0.03...0.24))
        cinematicGradeNode.childNode(withName: "gradeCoolShadowLift", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.26 + stress * 0.08).clamped(to: 0.03...0.34))
        cinematicGradeNode.childNode(withName: "gradeTopLetterboxPressure", recursively: true)?.opacity = CGFloat((0.08 + event * 0.18 + stress * 0.08 + teacherPulse * 0.42).clamped(to: 0.06...0.38))
        cinematicGradeNode.childNode(withName: "gradeBottomLetterboxPressure", recursively: true)?.opacity = CGFloat((0.08 + deskFocus * 0.14 + event * 0.16 + stress * 0.1).clamped(to: 0.06...0.4))
        cinematicGradeNode.childNode(withName: "gradeSkinToneProtect", recursively: true)?.opacity = CGFloat((0.05 + teacherNear * 0.08 + stress * 0.08 + event * 0.06).clamped(to: 0.03...0.28))
        cinematicGradeNode.childNode(withName: "gradeBoardGreenBias", recursively: true)?.opacity = CGFloat((0.03 + boardFocus * 0.22 + lowLight * 0.08).clamped(to: 0.02...0.28))
        for index in 0..<4 {
            cinematicGradeNode.childNode(withName: "gradeEventHeatStreak\(index)", recursively: true)?.opacity = CGFloat((0.02 + event * 0.28 + teacherNear * 0.08 + Double(index) * 0.014).clamped(to: 0.01...0.34))
        }
        for index in 0..<8 {
            cinematicGradeNode.childNode(withName: "gradeLowLightBlueNoise\(index)", recursively: true)?.opacity = CGFloat((0.02 + lowLight * 0.16 + event * 0.08 + Double((game.currentTurn + index) % 3) * 0.014).clamped(to: 0.01...0.26))
        }

        let timeProgress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let rainFeeling = (timeProgress > 0.46 || game.classroomLightLevel < 0.6) ? 1.0 : 0.0
        let ceilingPulse = Double(game.currentTurn % 4) * 0.012
        cinematicLightUnificationNode.opacity = CGFloat((0.04 + lowLight * 0.18 + event * 0.2 + stress * 0.08 + teacherNear * 0.16 + deskFocus * 0.06 + boardFocus * 0.04).clamped(to: 0.025...0.52) * studentView)
        cinematicLightUnificationNode.eulerAngles.z = Float(event * 0.012 - stress * 0.007 + teacherNear * 0.004)
        cinematicLightUnificationNode.scale = SCNVector3(1 + CGFloat(event) * 0.024 + CGFloat(teacherNear) * 0.012, 1 + CGFloat(lowLight) * 0.02 + CGFloat(deskFocus) * 0.01, 1)
        cinematicLightUnificationNode.childNode(withName: "globalWindowCoolWash", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.26 + rainFeeling * 0.16 + rearFocus * 0.06).clamped(to: 0.02...0.42))
        cinematicLightUnificationNode.childNode(withName: "globalBoardChalkLift", recursively: true)?.opacity = CGFloat((0.03 + boardFocus * 0.38 + lowLight * 0.08 + event * 0.06).clamped(to: 0.02...0.46))
        cinematicLightUnificationNode.childNode(withName: "globalTeacherWarmPressureBloom", recursively: true)?.opacity = CGFloat((0.025 + teacherNear * 0.42 + event * 0.18 + teacherPulse * 0.68).clamped(to: 0.015...0.58))
        cinematicLightUnificationNode.childNode(withName: "globalDeskAmberReturn", recursively: true)?.opacity = CGFloat((0.035 + deskFocus * 0.38 + stress * 0.1 + event * 0.06).clamped(to: 0.02...0.48))
        cinematicLightUnificationNode.childNode(withName: "globalLowLightShoulderFalloff", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.24 + stress * 0.12 + teacherNear * 0.16 + event * 0.12).clamped(to: 0.05...0.46))
        cinematicLightUnificationNode.childNode(withName: "globalEventPeripheralHeat", recursively: true)?.opacity = CGFloat((0.02 + event * 0.36 + teacherNear * 0.08).clamped(to: 0.01...0.42))
        cinematicLightUnificationNode.childNode(withName: "globalRainBlueVeil", recursively: true)?.opacity = CGFloat((0.02 + rainFeeling * 0.18 + lowLight * 0.12 + event * 0.04).clamped(to: 0.01...0.32))
        cinematicLightUnificationNode.childNode(withName: "globalSkinToneMidlineProtect", recursively: true)?.opacity = CGFloat((0.025 + teacherNear * 0.16 + stress * 0.1 + event * 0.08).clamped(to: 0.015...0.32))
        for index in 0..<3 {
            cinematicLightUnificationNode.childNode(withName: "globalCeilingTubeBand\(index)", recursively: true)?.opacity = CGFloat((0.035 + lowLight * 0.12 + ceilingPulse + Double(index) * 0.01).clamped(to: 0.02...0.26))
        }
        for index in 0..<5 {
            cinematicLightUnificationNode.childNode(withName: "globalHalationBridge\(index)", recursively: true)?.opacity = CGFloat((0.025 + event * 0.12 + teacherNear * 0.08 + deskFocus * 0.06 + Double((game.currentTurn + index) % 3) * 0.014).clamped(to: 0.015...0.28))
        }
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorShadowSpine", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.18 + stress * 0.1 + teacherNear * 0.18 + event * 0.12).clamped(to: 0.02...0.42))
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorShadowSpine", recursively: true)?.eulerAngles.z = Float(-0.018 + event * 0.03 - stress * 0.015)
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorDeskBoardBridge", recursively: true)?.opacity = CGFloat((0.025 + deskFocus * 0.24 + boardFocus * 0.18 + event * 0.08 + teacherNear * 0.06).clamped(to: 0.012...0.36))
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorDeskBoardBridge", recursively: true)?.position.y = Float(-0.027 + deskFocus * 0.006 - boardFocus * 0.004)
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorTeacherSpill", recursively: true)?.opacity = CGFloat((0.018 + teacherNear * 0.38 + event * 0.16 + stress * 0.08).clamped(to: 0.01...0.5))
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorTeacherSpill", recursively: true)?.scale = SCNVector3(2.4 + CGFloat(teacherNear) * 0.5, 1.1 + CGFloat(event) * 0.2, 0.08)
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorWindowSpecularTrace", recursively: true)?.opacity = CGFloat((0.018 + rainFeeling * 0.18 + rearFocus * 0.08 + lowLight * 0.1 + event * 0.04).clamped(to: 0.01...0.3))
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorWindowSpecularTrace", recursively: true)?.eulerAngles.z = Float(-0.07 + (timeProgress - 0.5) * 0.04)
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorRainMixer", recursively: true)?.opacity = CGFloat((0.012 + rainFeeling * 0.22 + lowLight * 0.12 + event * 0.08).clamped(to: 0.008...0.34))
        cinematicLightUnificationNode.childNode(withName: "globalLightDirectorRainMixer", recursively: true)?.scale = SCNVector3(1 + CGFloat(rainFeeling) * 0.06, 1 + CGFloat(lowLight) * 0.04, 1)
        for index in 0..<6 {
            let equalizer = cinematicLightUnificationNode.childNode(withName: "globalLightDirectorSkinEqualizer\(index)", recursively: true)
            equalizer?.opacity = CGFloat((0.018 + teacherNear * 0.1 + stress * 0.08 + event * 0.06 + Double(index % 2) * 0.012).clamped(to: 0.01...0.24))
            equalizer?.position.y = Float(-0.002 + Double(index % 2) * 0.022 + event * 0.003)
        }
        let selectedTarget = game.teacher.focusMode == .selectedStudent ? 1.0 : 0.0
        let teacherView = game.viewMode == .teacher ? 1.0 : 0.0
        let dangerWeight = (event * 0.42 + teacherNear * 0.34 + selectedTarget * 0.2 + stress * 0.12).clamped(to: 0...1)
        narrativeLensCueNode.opacity = CGFloat((0.025 + dangerWeight * 0.34 + lowLight * 0.08 + rearFocus * 0.05).clamped(to: 0.015...0.52) * studentView + teacherView * 0.05)
        narrativeLensCueNode.eulerAngles.z = Float(event * 0.018 - stress * 0.01 + teacherNear * 0.008)
        narrativeLensCueNode.scale = SCNVector3(1 + CGFloat(dangerWeight) * 0.03, 1 + CGFloat(event) * 0.026, 1)
        narrativeLensCueNode.childNode(withName: "narrativeTeacherNearBloom", recursively: true)?.opacity = CGFloat((0.02 + teacherNear * 0.42 + selectedTarget * 0.12 + event * 0.12).clamped(to: 0.01...0.58))
        narrativeLensCueNode.childNode(withName: "narrativeTeacherNearBloom", recursively: true)?.position.x = Float(0.036 + (teacherNode.position.x * 0.004).clamped(to: -0.018...0.018))
        narrativeLensCueNode.childNode(withName: "narrativeTargetNeedle", recursively: true)?.opacity = CGFloat((selectedTarget * (0.18 + teacherNear * 0.28 + event * 0.12)).clamped(to: 0...0.62))
        narrativeLensCueNode.childNode(withName: "narrativeTargetNeedle", recursively: true)?.eulerAngles.z = Float(-0.08 + teacherNode.position.x * 0.018)
        narrativeLensCueNode.childNode(withName: "narrativeDeskAttentionPlate", recursively: true)?.opacity = CGFloat((0.02 + deskFocus * 0.38 + stress * 0.08 + event * 0.06).clamped(to: 0.01...0.46))
        narrativeLensCueNode.childNode(withName: "narrativeBoardAnchorGlow", recursively: true)?.opacity = CGFloat((0.02 + boardFocus * 0.42 + lowLight * 0.08 + event * 0.06).clamped(to: 0.01...0.5))
        narrativeLensCueNode.childNode(withName: "narrativeRearTunnelFrame", recursively: true)?.opacity = CGFloat((0.02 + rearFocus * 0.34 + event * 0.1 + lowLight * 0.06).clamped(to: 0.01...0.42))
        narrativeLensCueNode.childNode(withName: "narrativeRearAisleGuide", recursively: true)?.opacity = CGFloat((0.015 + rearFocus * 0.32 + selectedTarget * 0.08 + lowLight * 0.08).clamped(to: 0.01...0.38))
        narrativeLensCueNode.childNode(withName: "narrativePanicTopClamp", recursively: true)?.opacity = CGFloat((0.04 + dangerWeight * 0.22 + event * 0.1).clamped(to: 0.03...0.38))
        narrativeLensCueNode.childNode(withName: "narrativePanicBottomClamp", recursively: true)?.opacity = CGFloat((0.04 + dangerWeight * 0.24 + deskFocus * 0.08 + event * 0.08).clamped(to: 0.03...0.42))
        for index in 0..<4 {
            let pulse = narrativeLensCueNode.childNode(withName: "narrativeDangerPulse\(index)", recursively: true)
            pulse?.opacity = CGFloat((0.01 + dangerWeight * 0.2 + Double((game.currentTurn + index) % 3) * 0.015 - Double(index) * 0.012).clamped(to: 0.005...0.3))
            pulse?.scale = SCNVector3(1.8 + CGFloat(dangerWeight) * 0.5, 0.5 + CGFloat(event) * 0.2, 0.08)
        }
        for index in 0..<5 {
            let mote = narrativeLensCueNode.childNode(withName: "narrativeFocusMote\(index)", recursively: true)
            mote?.opacity = CGFloat((0.008 + lowLight * 0.08 + rearFocus * 0.08 + boardFocus * 0.04 + Double((game.currentTurn + index) % 4) * 0.008).clamped(to: 0.004...0.18))
            mote?.position.y = Float(-0.018 + Double(index % 3) * 0.018 + event * 0.002)
        }
        lensFlareNode.eulerAngles.z = Float(game.currentTurn % 8) * 0.015 - 0.05
    }

    private func updateGlobalCinematicDepth(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let progress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let lowLight = max(0, 0.68 - game.classroomLightLevel)
        let event = eventIntensity.vignette.clamped(to: 0...1)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let boardFocus = game.cameraPose == .board ? 1.0 : 0.0
        let deskFocus = game.cameraPose == .desk ? 1.0 : 0.0
        let rearFocus = game.cameraPose == .rear ? 1.0 : 0.0
        let mood = (progress * 0.32 + lowLight * 0.42 + event * 0.34 + teacherPressure * 0.18).clamped(to: 0...1)
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)

        classroomDepthCueNode.opacity = CGFloat((0.16 + mood * 0.48).clamped(to: 0.12...0.72))
        classroomDepthCueNode.position.y = Float(event * 0.012)
        classroomDepthCueNode.eulerAngles.y = Float((progress - 0.5) * 0.018 + event * 0.012)
        for index in 0..<8 {
            classroomDepthCueNode.childNode(withName: "cinematicDepthVeil\(index)", recursively: true)?.opacity = CGFloat((0.12 + mood * 0.34 + Double(index % 3) * 0.025).clamped(to: 0.1...0.62))
        }
        for row in 0..<5 {
            classroomDepthCueNode.childNode(withName: "cinematicRowSeparation\(row)", recursively: true)?.opacity = CGFloat((0.12 + teacherPressure * 0.18 + event * 0.22).clamped(to: 0.08...0.48))
        }
        for index in 0..<12 {
            classroomDepthCueNode.childNode(withName: "rearDepthBokeh\(index)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.28 + progress * 0.16).clamped(to: 0.05...0.46))
        }
        for index in 0..<6 {
            let guide = classroomDepthCueNode.childNode(withName: "worldFocusGuideGlint\(index)", recursively: true)
            guide?.opacity = CGFloat((0.05 + lowLight * 0.18 + event * 0.16 + (game.cameraPose == .board ? 0.12 : 0)).clamped(to: 0.03...0.38))
            guide?.position.y = CGFloat(1.06 + Float(index % 3) * 0.18 + Float(event) * 0.012)
        }

        cinematicLightCorridorNode.opacity = CGFloat((0.08 + mood * 0.36 + boardFocus * 0.12 + deskFocus * 0.08 + teacherNear * 0.12 + rearFocus * 0.08).clamped(to: 0.05...0.76))
        cinematicLightCorridorNode.position.y = Float(event * 0.006 + teacherNear * 0.003)
        cinematicLightCorridorNode.eulerAngles.y = Float((progress - 0.5) * 0.01 + event * 0.008)
        cinematicLightCorridorNode.scale = SCNVector3(1 + CGFloat(event) * 0.01, 1 + CGFloat(lowLight) * 0.012, 1)
        for index in 0..<6 {
            let corridor = cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorBoardDepth\(index)", recursively: true)
            corridor?.opacity = CGFloat((0.035 + boardFocus * 0.22 + progress * 0.08 + event * 0.08 + teacherPressure * 0.06 - Double(index) * 0.008).clamped(to: 0.015...0.42))
            corridor?.position.y = Float(1.52 + Double(index % 2) * 0.12 + event * 0.006)
            corridor?.eulerAngles.y = Float(-0.08 + Double(index) * 0.028 + event * 0.035)
        }
        for index in 0..<7 {
            let beam = cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorWindowCrossBeam\(index)", recursively: true)
            beam?.opacity = CGFloat((0.025 + lowLight * 0.18 + rearFocus * 0.08 + event * 0.08 + Double(index % 2) * 0.014).clamped(to: 0.01...0.36))
            beam?.position.x = Float(2.55 - Double(index % 3) * 0.08 - event * 0.035)
            beam?.scale = SCNVector3(1 + CGFloat(lowLight) * 0.08, 1 + CGFloat(event) * 0.04, 1 + CGFloat(progress) * 0.04)
        }
        for row in 0..<5 {
            let rowWeight = (0.05 + teacherPressure * 0.12 + event * 0.12 + lowLight * 0.08 + (row == 0 && boardFocus > 0 ? 0.08 : 0)).clamped(to: 0.02...0.44)
            let matte = cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorDeskNegativeFill\(row)", recursively: true)
            matte?.opacity = CGFloat(rowWeight)
            matte?.position.y = Float(0.87 + rowWeight * 0.01)
            let rim = cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorStudentRowRim\(row)", recursively: true)
            rim?.opacity = CGFloat((0.025 + lowLight * 0.1 + teacherPressure * 0.08 + event * 0.08 - Double(row) * 0.004).clamped(to: 0.01...0.3))
            rim?.eulerAngles.y = Float((row % 2 == 0 ? 0.024 : -0.022) + event * 0.025)
        }
        for index in 0..<4 {
            let curtain = cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorRearFalloffCurtain\(index)", recursively: true)
            curtain?.opacity = CGFloat((0.03 + lowLight * 0.16 + rearFocus * 0.12 + event * 0.08 + progress * 0.06 - Double(index) * 0.012).clamped(to: 0.01...0.34))
            curtain?.position.y = Float(1.5 + Double(index % 2) * 0.16 + event * 0.008)
        }
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorTeacherSilhouetteGate", recursively: true)?.opacity = CGFloat((0.03 + teacherNear * 0.24 + teacherPressure * 0.14 + event * 0.1).clamped(to: 0.01...0.48))
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorTeacherSilhouetteGate", recursively: true)?.position.x = teacherNode.position.x * 0.38
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorTeacherSilhouetteGate", recursively: true)?.position.z = (teacherNode.position.z - 0.3).clamped(to: -4.6...1.4)
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorBlackboardHalation", recursively: true)?.opacity = CGFloat((0.04 + boardFocus * 0.2 + lowLight * 0.08 + event * 0.08).clamped(to: 0.02...0.38))
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorPlayerForegroundMatte", recursively: true)?.opacity = CGFloat((0.03 + deskFocus * 0.18 + teacherNear * 0.12 + event * 0.08).clamped(to: 0.01...0.38))
        cinematicLightCorridorNode.childNode(withName: "cinematicLightCorridorAisleSightline", recursively: true)?.opacity = CGFloat((0.02 + lowLight * 0.12 + teacherPressure * 0.08 + rearFocus * 0.1 + event * 0.08).clamped(to: 0.01...0.32))

        classroomVolumetricCompositionNode.opacity = CGFloat((0.06 + mood * 0.36 + lowLight * 0.18 + event * 0.18 + teacherNear * 0.12 + boardFocus * 0.08).clamped(to: 0.04...0.78))
        classroomVolumetricCompositionNode.position.y = Float(event * 0.005 + teacherNear * 0.003)
        classroomVolumetricCompositionNode.eulerAngles = SCNVector3(0, Float((progress - 0.5) * 0.006 + event * 0.008), Float(event * 0.004 - teacherNear * 0.003))
        classroomVolumetricCompositionNode.scale = SCNVector3(1 + CGFloat(event) * 0.012, 1 + CGFloat(lowLight) * 0.016, 1)
        for index in 0..<7 {
            let shaft = classroomVolumetricCompositionNode.childNode(withName: "volumetricWindowShaft\(index)", recursively: true)
            shaft?.opacity = CGFloat((0.025 + lowLight * 0.22 + progress * 0.08 + rearFocus * 0.06 + event * 0.06 - Double(index) * 0.004).clamped(to: 0.01...0.36))
            shaft?.position.x = Float(2.45 - Double(index % 2) * 0.22 - event * 0.03 + teacherNear * 0.02)
            shaft?.eulerAngles.y = Float(-0.5 + Double(index) * 0.018 + lowLight * 0.04 + event * 0.025)
            shaft?.scale = SCNVector3(1 + CGFloat(lowLight) * 0.08, 1 + CGFloat(event) * 0.04, 1 + CGFloat(progress) * 0.04)
            let floorHit = classroomVolumetricCompositionNode.childNode(withName: "volumetricWindowFloorHit\(index)", recursively: true)
            floorHit?.opacity = CGFloat((0.025 + lowLight * 0.18 + event * 0.08 + rearFocus * 0.04 - Double(index) * 0.003).clamped(to: 0.01...0.32))
            floorHit?.position.y = Float(0.058 + lowLight * 0.004)
        }
        for row in 0..<5 {
            let rowMates = game.classmates.filter { $0.seat.row == row }
            let rowStress = rowMates.map { ($0.stress / 100).clamped(to: 0...1) }.max() ?? 0
            let rowPhone = rowMates.contains { $0.state == .usingPhone } ? 1.0 : 0.0
            let rowCry = rowMates.contains { $0.state == .crying } ? 1.0 : 0.0
            let rowSleep = rowMates.contains { $0.state == .sleeping } ? 1.0 : 0.0
            let rowTarget = game.selectedTeacherTarget?.seat.row == row && game.teacher.focusMode == .selectedStudent ? 1.0 : 0.0
            let rowEvent = rowMates.contains { $0.id == eventMateID } ? 1.0 : 0.0
            let rowPressure = (teacherPressure * 0.12 + event * 0.12 + lowLight * 0.1 + rowStress * 0.12 + rowTarget * 0.14 + rowEvent * 0.12 + (row == 0 && boardFocus > 0 ? 0.08 : 0) + (row == 4 && rearFocus > 0 ? 0.08 : 0)).clamped(to: 0...0.62)
            let rowVolume = classroomVolumetricCompositionNode.childNode(withName: "volumetricDeskRowAirShelf\(row)", recursively: true)
            rowVolume?.opacity = CGFloat((0.02 + rowPressure + Double(row) * 0.01).clamped(to: 0.01...0.34))
            rowVolume?.position.y = Float(1.02 + rowPressure * 0.018)
            let negative = classroomVolumetricCompositionNode.childNode(withName: "volumetricDeskRowNegativeFill\(row)", recursively: true)
            negative?.opacity = CGFloat((0.03 + rowPressure * 0.7 + teacherNear * 0.05).clamped(to: 0.015...0.42))
            negative?.position.y = Float(0.845 + rowPressure * 0.01)
            let shoulderFog = classroomVolumetricCompositionNode.childNode(withName: "volumetricStudentShoulderFog\(row)", recursively: true)
            shoulderFog?.opacity = CGFloat((0.02 + lowLight * 0.14 + rowPressure * 0.36 + event * 0.06).clamped(to: 0.01...0.28))
            let bodyCut = classroomVolumetricCompositionNode.childNode(withName: "volumetricRowBodyOcclusionCut\(row)", recursively: true)
            bodyCut?.opacity = CGFloat((0.03 + rowPressure * 0.42 + rowCry * 0.1 + rowSleep * 0.08 + teacherNear * 0.05).clamped(to: 0.015...0.46))
            bodyCut?.position.y = Float(0.74 - rowCry * 0.012 - rowSleep * 0.01 + rowPressure * 0.006)
            bodyCut?.scale = SCNVector3(1 + CGFloat(rowTarget + rowEvent) * 0.04, 1 + CGFloat(rowPressure) * 0.04, 1)
            let deskBounce = classroomVolumetricCompositionNode.childNode(withName: "volumetricRowDeskBounceReturn\(row)", recursively: true)
            deskBounce?.opacity = CGFloat((0.018 + lowLight * 0.1 + rowPhone * 0.12 + rowStress * 0.1 + event * 0.05).clamped(to: 0.006...0.32))
            deskBounce?.position.y = Float(0.875 + rowPhone * 0.004 + rowPressure * 0.003)
            let seatBreak = classroomVolumetricCompositionNode.childNode(withName: "volumetricRowSeatBackSilhouetteBreak\(row)", recursively: true)
            seatBreak?.opacity = CGFloat((0.02 + rowPressure * 0.28 + rowSleep * 0.1 + rowCry * 0.08 + lowLight * 0.08).clamped(to: 0.01...0.34))
            seatBreak?.position.y = Float(0.98 - rowSleep * 0.014 - rowCry * 0.01)
            let rim = classroomVolumetricCompositionNode.childNode(withName: "volumetricRowWindowRimOnBodies\(row)", recursively: true)
            rim?.opacity = CGFloat((0.012 + lowLight * 0.18 + rowPhone * 0.06 + rowTarget * 0.08 + rowEvent * 0.06 + rearFocus * 0.04).clamped(to: 0.004...0.32))
            rim?.eulerAngles.y = Float(-0.32 + lowLight * 0.04 + event * 0.025)
        }
        for classmate in game.classmates {
            let seatPocket = classroomVolumetricCompositionNode.childNode(withName: "volumetricSeatBodyPocket_\(classmate.seat.row)_\(classmate.seat.column)", recursively: true)
            let classmateStress = (classmate.stress / 100).clamped(to: 0...1)
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stateWeight: Double
            switch classmate.state {
            case .crying:
                stateWeight = 0.34
            case .sleeping:
                stateWeight = 0.28
            case .covering, .anxious:
                stateWeight = 0.24
            case .usingPhone:
                stateWeight = 0.2
            case .offeringHelp, .lookingAtPlayer:
                stateWeight = 0.16
            default:
                stateWeight = 0.08
            }
            let pocketRead = (0.025 + classmateStress * 0.16 + stateWeight + (isTarget ? 0.18 : 0) + (isEventMate ? 0.16 : 0) + lowLight * 0.08 + event * 0.06).clamped(to: 0.01...0.58)
            seatPocket?.opacity = CGFloat(pocketRead)
            seatPocket?.position.y = Float(0.72 - (classmate.state == .crying || classmate.state == .sleeping ? 0.018 : 0) + pocketRead * 0.006)
            seatPocket?.scale = SCNVector3(1.55 + CGFloat(pocketRead) * 0.22, 0.62 + CGFloat(isTarget ? 0.08 : 0), 0.28 + CGFloat(isEventMate ? 0.08 : 0))
        }
        for index in 0..<8 {
            let mote = classroomVolumetricCompositionNode.childNode(withName: "volumetricClassroomDustMote\(index)", recursively: true)
            mote?.opacity = CGFloat((0.015 + lowLight * 0.12 + event * 0.08 + boardFocus * 0.04 + Double((game.currentTurn + index) % 3) * 0.008 - Double(index) * 0.002).clamped(to: 0.004...0.22))
            mote?.position.y = Float(1.08 + Double(index % 4) * 0.16 + lowLight * 0.012 + event * 0.006)
        }
        for index in 0..<5 {
            let bloom = classroomVolumetricCompositionNode.childNode(withName: "volumetricBlackboardChalkBloom\(index)", recursively: true)
            bloom?.opacity = CGFloat((0.025 + boardFocus * 0.22 + lowLight * 0.08 + event * 0.06 + teacherPressure * 0.04 - Double(index) * 0.006).clamped(to: 0.01...0.36))
            bloom?.position.y = Float(1.72 + Double(index % 2) * 0.12 + event * 0.006)
        }
        let volumeTeacherGate = classroomVolumetricCompositionNode.childNode(withName: "volumetricTeacherMovingShadowGate", recursively: true)
        volumeTeacherGate?.opacity = CGFloat((0.025 + teacherNear * 0.3 + teacherPressure * 0.18 + event * 0.12).clamped(to: 0.01...0.56))
        volumeTeacherGate?.position.x = teacherNode.position.x * 0.42
        volumeTeacherGate?.position.z = (teacherNode.position.z - 0.24).clamped(to: -4.8...1.2)
        volumeTeacherGate?.scale = SCNVector3(1 + CGFloat(teacherNear) * 0.08 + CGFloat(event) * 0.04, 1 + CGFloat(teacherPressure) * 0.05, 1)
        let pressureBloom = classroomVolumetricCompositionNode.childNode(withName: "volumetricTeacherPressureBloom", recursively: true)
        pressureBloom?.opacity = CGFloat((0.02 + teacherNear * 0.26 + teacherPressure * 0.16 + event * 0.16).clamped(to: 0.01...0.44))
        pressureBloom?.position.x = teacherNode.position.x * 0.28
        pressureBloom?.position.z = (teacherNode.position.z + 0.42).clamped(to: -4.6...1.6)
        classroomVolumetricCompositionNode.childNode(withName: "volumetricPlayerForegroundCompression", recursively: true)?.opacity = CGFloat((0.025 + deskFocus * 0.2 + teacherNear * 0.16 + event * 0.1 + lowLight * 0.06).clamped(to: 0.01...0.42))
        classroomVolumetricCompositionNode.childNode(withName: "volumetricAisleSightVolume", recursively: true)?.opacity = CGFloat((0.02 + lowLight * 0.12 + teacherPressure * 0.08 + rearFocus * 0.1 + event * 0.08).clamped(to: 0.01...0.34))
    }

    private func updateEventCinematicLayer(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        guard case .event(let event) = game.gameState else {
            eventCinematicOverlayNode.removeAction(forKey: "event_overlay_pulse")
            eventWorldRippleNode.removeAction(forKey: "event_world_pulse")
            eventCinematicOverlayNode.opacity = 0
            eventWorldRippleNode.opacity = 0
            return
        }

        let intensity = CGFloat((0.18 + eventIntensity.vignette * 0.62).clamped(to: 0.18...0.92))
        eventCinematicOverlayNode.opacity = intensity
        eventWorldRippleNode.opacity = CGFloat((0.16 + eventIntensity.vignette * 0.5).clamped(to: 0.12...0.72))

        let palette: (warm: NSColor, cool: NSColor, shadow: CGFloat, memory: CGFloat)
        switch event.kind {
        case .playerBreakdown:
            palette = (NSColor(calibratedRed: 1.0, green: 0.18, blue: 0.08, alpha: 0.22), NSColor(calibratedRed: 0.18, green: 0.22, blue: 0.36, alpha: 0.12), 0.72, 0.08)
        case .loneliness:
            palette = (NSColor(calibratedRed: 0.28, green: 0.44, blue: 0.9, alpha: 0.12), NSColor(calibratedRed: 0.3, green: 0.62, blue: 1.0, alpha: 0.22), 0.44, 0.34)
        case .powerOutage:
            palette = (NSColor(calibratedRed: 0.08, green: 0.12, blue: 0.22, alpha: 0.28), NSColor(calibratedRed: 0.12, green: 0.34, blue: 0.62, alpha: 0.18), 0.86, 0.12)
        case .memoryTrust:
            palette = (NSColor(calibratedRed: 0.42, green: 1.0, blue: 0.72, alpha: 0.16), NSColor(calibratedRed: 0.56, green: 0.92, blue: 1.0, alpha: 0.2), 0.26, 0.76)
        case .memorySuspicion:
            palette = (NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.18, alpha: 0.18), NSColor(calibratedRed: 0.55, green: 0.28, blue: 1.0, alpha: 0.18), 0.62, 0.58)
        case .classmateCrying:
            palette = (NSColor(calibratedRed: 0.32, green: 0.52, blue: 1.0, alpha: 0.16), NSColor(calibratedRed: 0.58, green: 0.78, blue: 1.0, alpha: 0.22), 0.5, 0.44)
        case .classmateHelpRequest, .supportOffer, .teacherConcern:
            palette = (NSColor(calibratedRed: 0.38, green: 1.0, blue: 0.72, alpha: 0.14), NSColor(calibratedRed: 0.72, green: 0.94, blue: 1.0, alpha: 0.12), 0.3, 0.52)
        default:
            palette = (NSColor(calibratedRed: 1.0, green: 0.48, blue: 0.18, alpha: 0.16), NSColor(calibratedRed: 0.38, green: 0.62, blue: 1.0, alpha: 0.12), 0.42, 0.22)
        }

        eventCinematicOverlayNode.childNode(withName: "eventWarmCut", recursively: true)?.geometry?.firstMaterial?.diffuse.contents = palette.warm
        eventCinematicOverlayNode.childNode(withName: "eventWarmCut", recursively: true)?.geometry?.firstMaterial?.emission.contents = palette.warm
        eventCinematicOverlayNode.childNode(withName: "eventCoolCut", recursively: true)?.geometry?.firstMaterial?.diffuse.contents = palette.cool
        eventCinematicOverlayNode.childNode(withName: "eventCoolCut", recursively: true)?.geometry?.firstMaterial?.emission.contents = palette.cool
        eventWorldRippleNode.childNode(withName: "eventDeskPressureShadow", recursively: true)?.opacity = palette.shadow
        for index in 0..<6 {
            eventWorldRippleNode.childNode(withName: "eventMemoryThread\(index)", recursively: true)?.opacity = palette.memory
        }

        if eventCinematicOverlayNode.action(forKey: "event_overlay_pulse") == nil {
            eventCinematicOverlayNode.runAction(.repeatForever(.sequence([
                .scale(to: 1.035, duration: 0.42),
                .scale(to: 1.0, duration: 0.58)
            ])), forKey: "event_overlay_pulse")
        }
        if eventWorldRippleNode.action(forKey: "event_world_pulse") == nil {
            eventWorldRippleNode.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: CGFloat((0.24 + eventIntensity.vignette * 0.56).clamped(to: 0.18...0.82)), duration: 0.5),
                .fadeOpacity(to: CGFloat((0.12 + eventIntensity.vignette * 0.32).clamped(to: 0.1...0.54)), duration: 0.72)
            ])), forKey: "event_world_pulse")
        }
    }

    private func cameraTurnDuration(game: GameManager) -> Double {
        guard game.viewMode == .student else { return 0.35 }
        let stressDelay = game.player.stress / 180
        let attentionDelay = max(0, 45 - game.player.visualAttention) / 90
        let teacherDelay = game.teacher.isNearPlayer ? 0.22 : 0
        return (0.28 + stressDelay + attentionDelay + teacherDelay).clamped(to: 0.28...1.15)
    }

    private func teacherEulerAngles(from: SCNVector3, to: SCNVector3) -> SCNVector3 {
        let dx = to.x - from.x
        let dy = to.y - from.y
        let dz = to.z - from.z
        let yaw = atan2(dx, dz)
        let distance = sqrt(dx * dx + dz * dz)
        let pitch = -atan2(dy, distance)
        return SCNVector3(pitch, yaw, 0)
    }

    private func teacherCameraTarget(game: GameManager) -> SCNVector3 {
        switch game.teacher.focusMode {
        case .wholeClass:
            return SCNVector3(0, 0.88, 0.15)
        case .selectedStudent:
            if let target = game.selectedTeacherTarget {
                return classmateHeadPosition(seat: target.seat)
            }
            return SCNVector3(0, 0.88, 0.15)
        case .blackboard:
            return SCNVector3(0, 1.88, -5.7)
        case .rearDoor:
            return SCNVector3(-3.9, 1.25, 4.25)
        }
    }

    private func handleMouseDragged(_ event: NSEvent) {
        currentGame?.rotateStudentView(deltaX: event.deltaX, deltaY: event.deltaY)
    }

    private func handleKey(_ event: NSEvent, isDown: Bool) {
        let character: Character
        if event.keyCode == 49 {
            character = " "
        } else if let first = event.charactersIgnoringModifiers?.lowercased().first {
            character = first
        } else {
            return
        }
        guard character == " " else { return }
        if isDown {
            pressedKeys.insert(character)
        } else {
            pressedKeys.remove(character)
        }
    }

    private func handleModifier(_ event: NSEvent) {
        currentGame?.setFreeRoamSideways(event.modifierFlags.contains(.shift))
    }

    private func tickMovement() {
        guard let game = currentGame, game.freeRoam.isActive else {
            lastMovementTick = Date()
            return
        }
        let now = Date()
        let delta = min(0.05, now.timeIntervalSince(lastMovementTick))
        lastMovementTick = now

        var forward = 0.0
        if pressedKeys.contains(" ") { forward = 1 }
        if forward != 0 {
            game.moveStudentFreeRoam(forward: forward, strafe: 0, deltaTime: delta)
        }
    }

    private func classmateHeadPosition(seat: (row: Int, column: Int)) -> SCNVector3 {
        let x = Float(seat.column) * 1.2 - 2.4
        let z = Float(seat.row) * 1.45 - 2.0
        return SCNVector3(x, 1.22, z)
    }

    private func makeEnvironment() -> SCNNode {
        let root = SCNNode()
        root.addChildNode(box(width: 8, height: 0.04, length: 12, color: NSColor(calibratedRed: 0.48, green: 0.38, blue: 0.28, alpha: 1), position: SCNVector3(0, -0.02, 0)))
        root.addChildNode(makeFloorFinishLayer())
        floorMicroDetailNode.addChildNode(makeFloorMicroDetailLayer())
        floorMicroDetailNode.opacity = 0.26
        root.addChildNode(floorMicroDetailNode)
        floorSpecularWearNode.addChildNode(makeFloorSpecularWearLayer())
        floorSpecularWearNode.opacity = 0.18
        root.addChildNode(floorSpecularWearNode)
        floorReflectionSweepNode.addChildNode(makeFloorReflectionSweepLayer())
        floorReflectionSweepNode.opacity = 0.16
        root.addChildNode(floorReflectionSweepNode)
        environmentLightTransportNode.addChildNode(makeEnvironmentLightTransportLayer())
        environmentLightTransportNode.opacity = 0.18
        root.addChildNode(environmentLightTransportNode)
        root.addChildNode(box(width: 8, height: 3.5, length: 0.06, color: wallColor, position: SCNVector3(0, 1.75, -6)))
        root.addChildNode(box(width: 8, height: 3.5, length: 0.06, color: wallColor, position: SCNVector3(0, 1.75, 6)))
        root.addChildNode(box(width: 0.06, height: 3.5, length: 12, color: wallColor, position: SCNVector3(-4, 1.75, 0)))
        root.addChildNode(box(width: 0.06, height: 3.5, length: 0.88, color: wallColor, position: SCNVector3(4, 1.75, -5.56)))
        root.addChildNode(box(width: 0.06, height: 3.5, length: 1.68, color: wallColor, position: SCNVector3(4, 1.75, -3.34)))
        root.addChildNode(box(width: 0.06, height: 3.5, length: 1.45, color: wallColor, position: SCNVector3(4, 1.75, -1.775)))
        root.addChildNode(box(width: 0.06, height: 3.5, length: 2.05, color: wallColor, position: SCNVector3(4, 1.75, 3.025)))
