    private func makeFloorFinishLayer() -> SCNNode {
        let root = SCNNode()
        let varnish = NSColor(calibratedRed: 0.72, green: 0.58, blue: 0.38, alpha: 0.16)
        for z in stride(from: -5.4, through: 5.4, by: 0.42) {
            root.addChildNode(box(width: 7.7, height: 0.004, length: 0.018, color: varnish, position: SCNVector3(0, 0.012, Float(z))))
        }

        let aisleWear = NSColor(calibratedRed: 0.12, green: 0.1, blue: 0.08, alpha: 0.18)
        for x in [-1.8, -0.6, 0.6, 1.8] {
            root.addChildNode(box(width: 0.42, height: 0.005, length: 10.6, color: aisleWear, position: SCNVector3(Float(x), 0.014, 0.1)))
        }

        let contact = NSColor(calibratedWhite: 0.02, alpha: 0.18)
        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                root.addChildNode(box(width: 0.94, height: 0.004, length: 0.82, color: contact, position: SCNVector3(x, 0.016, z + 0.2)))
            }
        }

        for index in 0..<16 {
            let x = Float((index * 37) % 72) / 10 - 3.6
            let z = Float((index * 53) % 104) / 10 - 5.2
            let scuff = box(width: 0.32 + CGFloat(index % 3) * 0.08, height: 0.005, length: 0.026, color: NSColor(calibratedWhite: 0.92, alpha: 0.08), position: SCNVector3(x, 0.018, z))
            scuff.eulerAngles.y = Float(index % 7) * 0.18
            root.addChildNode(scuff)
        }
        return root
    }

