            let wallPane = box(width: 0.008, height: 0.62 + CGFloat(index % 2) * 0.24, length: 0.7 + CGFloat(index % 3) * 0.18, color: rainCool, position: SCNVector3(3.965, 1.42 + Float(index % 2) * 0.24, z))
