            shoulderWash.eulerAngles.y = row % 2 == 0 ? 0.022 : -0.018
            root.addChildNode(shoulderWash)
        }

        let teacherCast = box(width: 1.35, height: 0.006, length: 0.42, color: shadowInk.withAlphaComponent(0.18), position: SCNVector3(0, 0.072, -3.6))
        teacherCast.name = "shadowDirectorTeacherMovingCast"
        teacherCast.eulerAngles.y = -0.2
        root.addChildNode(teacherCast)

        let teacherWallCut = box(width: 1.1, height: 0.76, length: 0.008, color: shadowInk.withAlphaComponent(0.09), position: SCNVector3(0, 1.36, -5.965))
        teacherWallCut.name = "shadowDirectorTeacherWallCut"
        root.addChildNode(teacherWallCut)

        let projectorCone = box(width: 2.5, height: 0.48, length: 0.012, color: chalkAir, position: SCNVector3(0.42, 1.82, -5.62))
        projectorCone.name = "shadowDirectorProjectorAirCut"
