    private func makeWallLayeredPaintLayer() -> SCNNode {
        let root = SCNNode()
        let repairPaint = NSColor(calibratedRed: 0.78, green: 0.79, blue: 0.72, alpha: 0.16)
        let oldGlue = NSColor(calibratedRed: 0.42, green: 0.34, blue: 0.18, alpha: 0.16)
        let tape = NSColor(calibratedRed: 0.94, green: 0.82, blue: 0.44, alpha: 0.26)
        let paper = NSColor(calibratedWhite: 0.96, alpha: 0.22)

        for index in 0..<12 {
            let x = -3.45 + Float((index * 59) % 690) / 100
            let y = 0.92 + Float((index * 43) % 210) / 100
            let front = index % 2 == 0
            let patch = box(
                width: 0.34 + CGFloat(index % 4) * 0.1,
                height: 0.18 + CGFloat(index % 3) * 0.08,
                length: 0.005,
                color: index % 3 == 0 ? repairPaint : oldGlue,
                position: SCNVector3(x, y, Float(front ? -5.928 : 5.928))
            )
            patch.name = "wallLayeredPaintPatch\(index)"
            patch.eulerAngles.z = CGFloat((index % 7) - 3) * 0.025
            root.addChildNode(patch)
        }

        for index in 0..<7 {
            let z = -4.75 + Float(index) * 1.38
            let sidePatch = box(
                width: 0.005,
                height: 0.22 + CGFloat(index % 3) * 0.07,
                length: 0.28 + CGFloat(index % 2) * 0.12,
                color: index % 2 == 0 ? repairPaint : oldGlue,
                position: SCNVector3(-3.928, 1.05 + Float(index % 4) * 0.42, z)
            )
            sidePatch.name = "sideWallLayeredPaintPatch\(index)"
            root.addChildNode(sidePatch)
        }

        for (index, x) in [-2.9, -1.75, 1.65, 2.85].enumerated() {
            let note = box(
                width: 0.26,
                height: 0.2,
                length: 0.004,
                color: paper,
                position: SCNVector3(Float(x), 2.48 - Float(index % 2) * 0.36, -5.925)
            )
            note.name = "frontWallHalfRemovedPaper\(index)"
            note.eulerAngles.z = CGFloat(index - 1) * 0.035
            root.addChildNode(note)
            let tapeTop = box(
                width: 0.11,
                height: 0.016,
                length: 0.005,
                color: tape,
                position: SCNVector3(Float(x) - 0.04, 2.59 - Float(index % 2) * 0.36, -5.921)
            )
            tapeTop.eulerAngles.z = CGFloat(index % 3 - 1) * 0.08
            root.addChildNode(tapeTop)
        }

        for index in 0..<10 {
            let x = -3.25 + Float(index) * 0.72
            let drip = box(
                width: 0.018,
                height: 0.18 + CGFloat(index % 4) * 0.05,
                length: 0.004,
                color: NSColor(calibratedRed: 0.16, green: 0.14, blue: 0.1, alpha: 0.1),
                position: SCNVector3(x, 2.92 - Float(index % 3) * 0.12, Float(index % 2 == 0 ? -5.924 : 5.924))
            )
            drip.name = "wallRainOldDrip\(index)"
            root.addChildNode(drip)
        }
        return root
    }

    private func makeWallAgingOverlayLayer() -> SCNNode {
        let root = SCNNode()
        let stain = NSColor(calibratedRed: 0.18, green: 0.16, blue: 0.12, alpha: 0.13)
        let chalk = NSColor(calibratedWhite: 0.92, alpha: 0.08)
        for index in 0..<14 {
            let x = -3.35 + Float((index * 53) % 670) / 100
            let y = 0.82 + Float((index * 31) % 190) / 100
            let z: Float = index % 2 == 0 ? -5.972 : 5.972
            let mark = box(width: 0.28 + CGFloat(index % 4) * 0.12, height: 0.08 + CGFloat(index % 3) * 0.05, length: 0.006, color: index % 3 == 0 ? chalk : stain, position: SCNVector3(x, y, z))
