        }
        return root
    }

    private func makeCorridorCinematicLayer() -> SCNNode {
        let root = SCNNode()
        let floorReflection = NSColor(calibratedRed: 0.78, green: 0.9, blue: 1.0, alpha: 0.08)
        let warmDoor = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.28, alpha: 0.1)
        let silhouette = NSColor(calibratedWhite: 0.02, alpha: 0.14)
        let deepVignette = NSColor(calibratedWhite: 0.0, alpha: 0.12)

        for index in 0..<7 {
            let z = -8.6 + Float(index) * 2.25
            let strip = box(width: 2.08 - CGFloat(index % 2) * 0.24, height: 0.005, length: 0.12, color: index % 2 == 0 ? floorReflection : warmDoor, position: SCNVector3(5.14, 0.028, z))
            strip.name = "corridorFloorReflectionStrip\(index)"
            strip.eulerAngles.y = -0.05 + Float(index % 3) * 0.04
            root.addChildNode(strip)
        }

        for index in 0..<4 {
            let z = [-9.7, -6.4, 4.9, 7.7][index]
            let body = box(width: 0.08, height: 0.58, length: 0.16, color: silhouette, position: SCNVector3(4.32 + Float(index % 2) * 0.22, 0.72, Float(z)))
            body.name = "corridorDistantStudentBody\(index)"
            root.addChildNode(body)
            let head = sphere(radius: 0.055, color: silhouette.withAlphaComponent(0.18), position: SCNVector3(4.32 + Float(index % 2) * 0.22, 1.08, Float(z)), scale: SCNVector3(0.72, 1, 0.72))
            head.name = "corridorDistantStudentHead\(index)"
            root.addChildNode(head)
        }

        for index in 0..<5 {
            let z = -10.2 + Float(index) * 4.4
            let vignette = box(width: 0.08, height: 2.2, length: 0.68, color: deepVignette, position: SCNVector3(4.2, 1.42, z))
            vignette.name = "corridorDepthVignette\(index)"
            root.addChildNode(vignette)
        }
        return root
    }

    private func makeCorridorDoor(label: String, z: Float) -> SCNNode {
        let root = SCNNode()
        root.addChildNode(box(width: 0.05, height: 1.7, length: 0.78, color: NSColor(calibratedRed: 0.42, green: 0.28, blue: 0.16, alpha: 1), position: SCNVector3(4.11, 0.92, z)))
