    private func makeWindowLayer() -> SCNNode {
        let root = SCNNode()
        for z in [-2.9, 1.2] {
            root.addChildNode(glassPane(width: 0.035, height: 1.05, length: 1.4, position: SCNVector3(-3.955, 1.7, Float(z))))
            root.addChildNode(windowFrame(at: SCNVector3(-3.97, 1.7, Float(z))))
        }
        for z in [-0.85, 1.2, 2.75] {
            root.addChildNode(glassPane(width: 0.035, height: 1.32, length: 1.15, position: SCNVector3(3.955, 1.78, Float(z))))
            root.addChildNode(windowFrame(at: SCNVector3(3.97, 1.78, Float(z)), height: 1.38, length: 1.21))
        }
        root.addChildNode(makeWindowReflectionLayer())
        windowInteriorReflectionNode.addChildNode(makeWindowInteriorReflectionLayer())
        windowInteriorReflectionNode.opacity = 0.18
        root.addChildNode(windowInteriorReflectionNode)
        windowCinematicDetailNode.addChildNode(makeWindowCinematicDetailLayer())
        windowCinematicDetailNode.opacity = 0.18
        root.addChildNode(windowCinematicDetailNode)
        windowExteriorCinematicNode.addChildNode(makeWindowExteriorCinematicLayer())
        windowExteriorCinematicNode.opacity = 0.16
        root.addChildNode(windowExteriorCinematicNode)
        root.addChildNode(makeWindowFabricAndBlinds())
        windowRainStreakNode.addChildNode(makeWindowRainStreaks())
        windowRainStreakNode.opacity = 0
        root.addChildNode(windowRainStreakNode)
        windowCondensationNode.addChildNode(makeWindowCondensationLayer())
        windowCondensationNode.opacity = 0.12
        root.addChildNode(windowCondensationNode)

        outsideSkyNode.addChildNode(box(width: 0.03, height: 1.5, length: 6.4, color: NSColor(calibratedRed: 0.45, green: 0.72, blue: 0.96, alpha: 1), position: SCNVector3(0, 0, 0)))
        outsideSkyNode.addChildNode(box(width: 0.035, height: 0.42, length: 0.7, color: NSColor(calibratedRed: 0.18, green: 0.22, blue: 0.28, alpha: 1), position: SCNVector3(-0.008, -0.38, -2.1)))
        outsideSkyNode.addChildNode(box(width: 0.035, height: 0.62, length: 0.85, color: NSColor(calibratedRed: 0.16, green: 0.2, blue: 0.26, alpha: 1), position: SCNVector3(-0.008, -0.28, -0.9)))
        outsideSkyNode.addChildNode(box(width: 0.035, height: 0.52, length: 0.72, color: NSColor(calibratedRed: 0.14, green: 0.18, blue: 0.24, alpha: 1), position: SCNVector3(-0.008, -0.33, 0.55)))
        outsideSkyNode.addChildNode(box(width: 0.035, height: 0.68, length: 0.9, color: NSColor(calibratedRed: 0.13, green: 0.17, blue: 0.22, alpha: 1), position: SCNVector3(-0.008, -0.24, 1.85)))
        outsideSkyNode.addChildNode(makeOutsideNightDetails())
        outsideSkyNode.position = SCNVector3(-4.08, 1.75, -0.85)
        root.addChildNode(outsideSkyNode)
        outsideParallaxDepthNode.addChildNode(makeOutsideParallaxDepthLayer())
        outsideParallaxDepthNode.position = SCNVector3(-4.12, 1.73, -0.85)
        outsideParallaxDepthNode.opacity = 0.24
        root.addChildNode(outsideParallaxDepthNode)

        outsideCloudNode.addChildNode(box(width: 0.032, height: 0.16, length: 0.9, color: NSColor(calibratedWhite: 0.95, alpha: 0.72), position: SCNVector3(0, 0.28, -1.7)))
        outsideCloudNode.addChildNode(box(width: 0.032, height: 0.12, length: 1.15, color: NSColor(calibratedWhite: 0.9, alpha: 0.66), position: SCNVector3(0, 0.1, 1.1)))
        outsideCloudNode.position = SCNVector3(-4.115, 1.78, -0.85)
        root.addChildNode(outsideCloudNode)

        outsideSunNode.addChildNode(sphere(radius: 0.13, color: NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.28, alpha: 1), position: SCNVector3(0, 0, 0)))
        outsideSunNode.position = SCNVector3(-4.13, 2.13, -2.2)
        root.addChildNode(outsideSunNode)

        outsideMoonNode.addChildNode(sphere(radius: 0.1, color: NSColor(calibratedRed: 0.88, green: 0.92, blue: 1.0, alpha: 1), position: SCNVector3(0, 0, 0)))
        outsideMoonNode.position = SCNVector3(-4.13, 2.22, 1.7)
        outsideMoonNode.opacity = 0
        root.addChildNode(outsideMoonNode)

        for z in stride(from: -2.9, through: 2.5, by: 0.45) {
            let rain = box(width: 0.018, height: 0.32, length: 0.012, color: NSColor(calibratedRed: 0.68, green: 0.82, blue: 1.0, alpha: 0.58), position: SCNVector3(0, 0, Float(z)))
            rain.eulerAngles.x = -0.22
            outsideRainNode.addChildNode(rain)
        }
        outsideRainNode.position = SCNVector3(-4.14, 1.78, -0.15)
        outsideRainNode.opacity = 0
        root.addChildNode(outsideRainNode)

        outsideLampNode.addChildNode(box(width: 0.022, height: 0.72, length: 0.08, color: NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.28, alpha: 1), position: SCNVector3(0, 0, 0)))
        outsideLampNode.addChildNode(box(width: 0.024, height: 0.18, length: 0.9, color: NSColor(calibratedRed: 1.0, green: 0.62, blue: 0.18, alpha: 1), position: SCNVector3(0, 0.28, 0)))
        outsideLampNode.position = SCNVector3(-4.14, 1.42, 2.45)
        outsideLampNode.opacity = 0.18
        root.addChildNode(outsideLampNode)
        return root
    }

    private func makeWindowRainStreaks() -> SCNNode {
        let root = SCNNode()
        let colors = [
            NSColor(calibratedRed: 0.72, green: 0.86, blue: 1.0, alpha: 0.42),
            NSColor(calibratedRed: 0.5, green: 0.72, blue: 1.0, alpha: 0.28),
            NSColor(calibratedWhite: 0.92, alpha: 0.2)
        ]
        let leftWindowZ: [Float] = [-2.9, 1.2]
        for (windowIndex, z) in leftWindowZ.enumerated() {
            for index in 0..<12 {
                let localZ = z - 0.56 + Float((index * 19 + windowIndex * 7) % 112) / 100
                let y = 2.18 - Float((index * 23) % 95) / 100
                let streak = capsule(radius: 0.0045, height: 0.22 + CGFloat(index % 4) * 0.035, color: colors[index % colors.count], position: SCNVector3(-3.922, y, localZ), rotation: SCNVector4(0, 0, 1, -0.08))
                streak.eulerAngles.x = -0.06
                root.addChildNode(streak)
            }
        }
        for z in [-0.85, 1.2, 2.75] {
            for index in 0..<9 {
                let localZ = Float(z) - 0.45 + Float((index * 17) % 92) / 100
                let y = 2.34 - Float((index * 29) % 105) / 100
                let streak = capsule(radius: 0.004, height: 0.2 + CGFloat(index % 3) * 0.04, color: colors[(index + 1) % colors.count], position: SCNVector3(3.922, y, localZ), rotation: SCNVector4(0, 0, 1, 0.06))
                streak.eulerAngles.x = 0.06
                root.addChildNode(streak)
            }
        }
        return root
    }

    private func makeWindowCondensationLayer() -> SCNNode {
        let root = SCNNode()
        for (index, z) in [-2.9, 1.2, -0.85, 2.75].enumerated() {
            let leftSide = index < 2
            let haze = box(width: 0.014, height: 0.22 + CGFloat(index % 2) * 0.08, length: 0.82, color: NSColor(calibratedWhite: 0.94, alpha: 0.08), position: SCNVector3(leftSide ? -3.918 : 3.918, 1.32 + Float(index % 2) * 0.16, Float(z)))
            haze.eulerAngles.z = leftSide ? -0.04 : 0.04
            root.addChildNode(haze)
        }
        return root
    }

    private func makeWindowReflectionLayer() -> SCNNode {
        let root = SCNNode()
        let reflection = NSColor(calibratedRed: 0.86, green: 0.94, blue: 1.0, alpha: 0.18)
        let grime = NSColor(calibratedWhite: 0.88, alpha: 0.11)
        for z in [-2.9, 1.2] {
            for index in 0..<3 {
                let streak = box(width: 0.012, height: 0.62 - CGFloat(index) * 0.08, length: 0.035, color: reflection, position: SCNVector3(-3.93, 1.56 + Float(index) * 0.08, Float(z) - 0.36 + Float(index) * 0.34))
                streak.eulerAngles.z = -0.36
                root.addChildNode(streak)
            }
            root.addChildNode(box(width: 0.014, height: 0.018, length: 1.08, color: grime, position: SCNVector3(-3.928, 1.18, Float(z))))
        }
        for z in [-0.85, 1.2, 2.75] {
            for index in 0..<2 {
                let streak = box(width: 0.012, height: 0.74 - CGFloat(index) * 0.12, length: 0.035, color: reflection, position: SCNVector3(3.93, 1.62 + Float(index) * 0.13, Float(z) - 0.25 + Float(index) * 0.38))
                streak.eulerAngles.z = 0.34
                root.addChildNode(streak)
            }
            root.addChildNode(box(width: 0.014, height: 0.016, length: 0.92, color: grime, position: SCNVector3(3.928, 1.24, Float(z))))
        }
        return root
    }

    private func makeWindowInteriorReflectionLayer() -> SCNNode {
        let root = SCNNode()
        let tubeReflection = NSColor(calibratedRed: 0.9, green: 0.96, blue: 1.0, alpha: 0.12)
        let warmLamp = NSColor(calibratedRed: 1.0, green: 0.62, blue: 0.22, alpha: 0.12)
        let darkFigure = NSColor(calibratedWhite: 0.02, alpha: 0.13)
        let scratch = NSColor(calibratedWhite: 0.94, alpha: 0.1)

        for (sideIndex, x) in [-3.916, 3.916].enumerated() {
            let side: Float = sideIndex == 0 ? -1 : 1
            let windows: [Float] = sideIndex == 0 ? [-2.9, 1.2] : [-0.85, 1.2, 2.75]
            for (windowIndex, z) in windows.enumerated() {
                let tube = box(width: 0.01, height: 0.035, length: 0.86, color: tubeReflection, position: SCNVector3(Float(x), 2.08 - Float(windowIndex % 2) * 0.08, z))
                tube.name = "windowCeilingTubeReflection_\(sideIndex)_\(windowIndex)"
                tube.eulerAngles.z = CGFloat(side) * 0.08
                root.addChildNode(tube)

                let rowGhost = box(width: 0.01, height: 0.3, length: 0.12, color: darkFigure, position: SCNVector3(Float(x), 1.45, z - 0.28))
                rowGhost.name = "windowStudentGhostReflection_\(sideIndex)_\(windowIndex)"
                rowGhost.eulerAngles.z = CGFloat(side) * -0.04
                root.addChildNode(rowGhost)
                let headGhost = sphere(radius: 0.035, color: darkFigure.withAlphaComponent(0.16), position: SCNVector3(Float(x), 1.66, z - 0.29), scale: SCNVector3(0.28, 1, 1))
                headGhost.name = "windowStudentHeadReflection_\(sideIndex)_\(windowIndex)"
                root.addChildNode(headGhost)

                let lampBleed = box(width: 0.01, height: 0.22, length: 0.54, color: warmLamp, position: SCNVector3(Float(x), 1.82, z + 0.32))
                lampBleed.name = "windowRainNightLampBleed_\(sideIndex)_\(windowIndex)"
                lampBleed.eulerAngles.z = CGFloat(side) * 0.12
                root.addChildNode(lampBleed)

                for index in 0..<4 {
                    let localZ = z - 0.46 + Float((index * 29 + windowIndex * 11) % 92) / 100
                    let y = 2.16 - Float((index * 19) % 78) / 100
                    let hairline = box(width: 0.008, height: 0.16 + CGFloat(index % 2) * 0.06, length: 0.006, color: scratch, position: SCNVector3(Float(x), y, localZ))
                    hairline.name = "windowMicroScratch_\(sideIndex)_\(windowIndex)_\(index)"
                    hairline.eulerAngles.z = CGFloat(side) * (0.28 + CGFloat(index) * 0.06)
                    root.addChildNode(hairline)
                }
            }
        }
        return root
    }

    private func makeWindowCinematicDetailLayer() -> SCNNode {
        let root = SCNNode()
        let droplet = NSColor(calibratedRed: 0.72, green: 0.88, blue: 1.0, alpha: 0.2)
        let warmReflection = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.24, alpha: 0.1)
        let cyanSplit = NSColor(calibratedRed: 0.28, green: 0.78, blue: 1.0, alpha: 0.11)
        let redSplit = NSColor(calibratedRed: 1.0, green: 0.22, blue: 0.12, alpha: 0.08)
        let dust = NSColor(calibratedWhite: 0.92, alpha: 0.12)

        for (sideIndex, x) in [-3.913, 3.913].enumerated() {
            let side: Float = sideIndex == 0 ? -1 : 1
            let windows: [Float] = sideIndex == 0 ? [-2.9, 1.2] : [-0.85, 1.2, 2.75]
            for (windowIndex, z) in windows.enumerated() {
                let verticalEdge = capsule(radius: 0.003, height: 1.04, color: sideIndex == 0 ? cyanSplit : redSplit, position: SCNVector3(Float(x), 1.78, z - 0.56), rotation: SCNVector4(0, 0, 1, 0))
                verticalEdge.name = "windowChromaticVerticalEdge_\(sideIndex)_\(windowIndex)"
                root.addChildNode(verticalEdge)
                let oppositeEdge = capsule(radius: 0.003, height: 1.04, color: sideIndex == 0 ? redSplit : cyanSplit, position: SCNVector3(Float(x), 1.78, z + 0.56), rotation: SCNVector4(0, 0, 1, 0))
                oppositeEdge.name = "windowChromaticOppositeEdge_\(sideIndex)_\(windowIndex)"
                root.addChildNode(oppositeEdge)

                for index in 0..<8 {
                    let localZ = z - 0.48 + Float((index * 17 + windowIndex * 13) % 96) / 100
                    let y = 2.24 - Float((index * 31 + sideIndex * 11) % 112) / 100
                    let bead = sphere(radius: 0.009 + CGFloat(index % 3) * 0.0025, color: droplet, position: SCNVector3(Float(x), y, localZ), scale: SCNVector3(0.26, 1.0, 0.72))
                    bead.name = "windowRaisedRainBead_\(sideIndex)_\(windowIndex)_\(index)"
                    bead.geometry?.firstMaterial?.emission.contents = droplet.withAlphaComponent(0.09)
                    root.addChildNode(bead)
                }

                for index in 0..<3 {
                    let runnel = capsule(radius: 0.0035, height: 0.38 + CGFloat(index) * 0.05, color: droplet.withAlphaComponent(0.18), position: SCNVector3(Float(x), 2.08 - Float(index) * 0.28, z - 0.28 + Float(index) * 0.26), rotation: SCNVector4(0, 0, 1, side * 0.04))
                    runnel.name = "windowLongWaterRunnel_\(sideIndex)_\(windowIndex)_\(index)"
                    root.addChildNode(runnel)
                }

                let lampRibbon = box(width: 0.009, height: 0.028, length: 0.96, color: warmReflection, position: SCNVector3(Float(x), 2.18 - Float(windowIndex % 2) * 0.12, z))
                lampRibbon.name = "windowInteriorLightRibbon_\(sideIndex)_\(windowIndex)"
                lampRibbon.eulerAngles.z = CGFloat(side) * 0.055
                root.addChildNode(lampRibbon)

                let frameDust = box(width: 0.01, height: 0.018, length: 1.0, color: dust, position: SCNVector3(Float(x), 1.16, z))
                frameDust.name = "windowFrameDustShelf_\(sideIndex)_\(windowIndex)"
                root.addChildNode(frameDust)
            }
        }
        return root
    }

    private func makeWindowExteriorCinematicLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "windowExteriorCinematicLayer"
        let coolGlass = NSColor(calibratedRed: 0.46, green: 0.72, blue: 1.0, alpha: 0.1)
        let deepOutside = NSColor(calibratedRed: 0.02, green: 0.04, blue: 0.1, alpha: 0.18)
        let lampWarm = NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.24, alpha: 0.15)
        let rainBlue = NSColor(calibratedRed: 0.34, green: 0.58, blue: 1.0, alpha: 0.12)
        let indoorWarm = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: 0.09)
        let frameShadow = NSColor(calibratedWhite: 0.0, alpha: 0.14)

        for (sideIndex, x) in [-3.905, 3.905].enumerated() {
            let side: Float = sideIndex == 0 ? -1 : 1
            let windows: [Float] = sideIndex == 0 ? [-2.9, 1.2] : [-0.85, 1.2, 2.75]
            for (windowIndex, z) in windows.enumerated() {
                let depthWash = box(width: 0.012, height: 0.9, length: 1.02, color: deepOutside, position: SCNVector3(Float(x), 1.78, z))
                depthWash.name = "windowExteriorDepthWash_\(sideIndex)_\(windowIndex)"
                depthWash.eulerAngles.z = CGFloat(side) * 0.018
                root.addChildNode(depthWash)

                let glassSkin = box(width: 0.009, height: 0.96, length: 0.96, color: coolGlass, position: SCNVector3(Float(x), 1.8, z))
                glassSkin.name = "windowExteriorGlassSkin_\(sideIndex)_\(windowIndex)"
                glassSkin.geometry?.firstMaterial?.emission.contents = coolGlass.withAlphaComponent(0.05)
                root.addChildNode(glassSkin)

                let indoorStripe = box(width: 0.008, height: 0.022, length: 0.92, color: indoorWarm, position: SCNVector3(Float(x), 2.06 - Float(windowIndex % 2) * 0.1, z))
                indoorStripe.name = "windowExteriorIndoorLightStripe_\(sideIndex)_\(windowIndex)"
                indoorStripe.eulerAngles.z = CGFloat(side) * 0.05
                root.addChildNode(indoorStripe)

                let sillPool = box(width: 0.011, height: 0.014, length: 0.96, color: rainBlue.withAlphaComponent(0.12), position: SCNVector3(Float(x), 1.16, z))
                sillPool.name = "windowExteriorWetSillPool_\(sideIndex)_\(windowIndex)"
                root.addChildNode(sillPool)

                let verticalShadow = box(width: 0.011, height: 0.86, length: 0.026, color: frameShadow, position: SCNVector3(Float(x), 1.74, z - 0.54))
                verticalShadow.name = "windowExteriorFrameDepthShadow_\(sideIndex)_\(windowIndex)"
                root.addChildNode(verticalShadow)

                for index in 0..<4 {
                    let lamp = sphere(
                        radius: 0.018 + CGFloat(index % 2) * 0.006,
                        color: lampWarm,
                        position: SCNVector3(Float(x) + side * 0.006, 1.56 + Float(index % 2) * 0.22, z - 0.42 + Float(index) * 0.28),
                        scale: SCNVector3(0.28, 1.0, 1.8)
                    )
                    lamp.name = "windowExteriorFarLampBokeh_\(sideIndex)_\(windowIndex)_\(index)"
                    lamp.geometry?.firstMaterial?.emission.contents = lampWarm.withAlphaComponent(0.16)
                    root.addChildNode(lamp)
                }

                for index in 0..<5 {
                    let parallax = box(
                        width: 0.007,
                        height: 0.12 + CGFloat(index % 3) * 0.05,
                        length: 0.05 + CGFloat(index % 2) * 0.02,
                        color: deepOutside.withAlphaComponent(0.12),
                        position: SCNVector3(Float(x) + side * 0.008, 1.42 + Float(index % 3) * 0.17, z - 0.45 + Float(index) * 0.22)
                    )
                    parallax.name = "windowExteriorParallaxBlock_\(sideIndex)_\(windowIndex)_\(index)"
                    root.addChildNode(parallax)
                }

                for index in 0..<4 {
                    let dropletGlow = sphere(
                        radius: 0.006 + CGFloat(index % 2) * 0.0018,
                        color: rainBlue.withAlphaComponent(0.16),
                        position: SCNVector3(Float(x), 2.18 - Float(index) * 0.22, z - 0.34 + Float(index % 3) * 0.25),
                        scale: SCNVector3(0.22, 1.15, 0.75)
                    )
                    dropletGlow.name = "windowExteriorDropletLens_\(sideIndex)_\(windowIndex)_\(index)"
                    dropletGlow.geometry?.firstMaterial?.emission.contents = rainBlue.withAlphaComponent(0.055)
                    root.addChildNode(dropletGlow)
                }
            }
        }

        root.opacity = 0.16
        return root
    }

    private func makeWindowFabricAndBlinds() -> SCNNode {
        let root = SCNNode()
        let fabric = NSColor(calibratedRed: 0.35, green: 0.56, blue: 0.72, alpha: 0.78)
        let fabricShadow = NSColor(calibratedRed: 0.12, green: 0.2, blue: 0.28, alpha: 0.46)
        let railColor = NSColor(calibratedWhite: 0.72, alpha: 1)
        let slatColor = NSColor(calibratedWhite: 0.9, alpha: 0.62)

        for z in [-2.9, 1.2] {
            root.addChildNode(capsule(radius: 0.018, height: 1.68, color: railColor, position: SCNVector3(-3.88, 2.31, Float(z)), rotation: SCNVector4(1, 0, 0, Float.pi / 2)))
            for (sideIndex, side) in [-1.0, 1.0].enumerated() {
                let baseZ = Float(z) + Float(side) * 0.73
                let curtain = roundedBox(width: 0.045, height: 1.2, length: 0.18, chamfer: 0.02, color: fabric, position: SCNVector3(-3.89, 1.7, baseZ))
                curtain.runAction(.repeatForever(.sequence([
                    .rotateBy(x: 0, y: CGFloat(side) * 0.018, z: CGFloat(side) * 0.012, duration: 2.0 + Double(sideIndex) * 0.35),
                    .rotateBy(x: 0, y: -CGFloat(side) * 0.018, z: -CGFloat(side) * 0.012, duration: 2.4 + Double(sideIndex) * 0.28)
                ])), forKey: "curtain_air_sway")
                root.addChildNode(curtain)

                let innerShadow = box(width: 0.022, height: 1.06, length: 0.024, color: fabricShadow, position: SCNVector3(-3.86, 1.66, baseZ - Float(side) * 0.04))
                innerShadow.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: 0.34, duration: 1.8 + Double(sideIndex) * 0.24),
                    .fadeOpacity(to: 0.58, duration: 2.2 + Double(sideIndex) * 0.18)
                ])), forKey: "curtain_shadow_breathe")
                root.addChildNode(innerShadow)
                for fold in 0..<3 {
                    let foldZ = baseZ + Float(fold - 1) * 0.045
                    let foldNode = capsule(radius: 0.006, height: 1.1, color: fabricShadow, position: SCNVector3(-3.852, 1.67, foldZ))
                    foldNode.runAction(.repeatForever(.sequence([
                        .moveBy(x: 0, y: 0, z: CGFloat(side) * 0.012, duration: 1.7 + Double(fold) * 0.22),
                        .moveBy(x: 0, y: 0, z: -CGFloat(side) * 0.012, duration: 2.0 + Double(fold) * 0.18)
                    ])), forKey: "fold_sway")
                    root.addChildNode(foldNode)
                }
            }
        }

        for z in [-0.85, 1.2, 2.75] {
            root.addChildNode(capsule(radius: 0.016, height: 1.38, color: railColor, position: SCNVector3(3.89, 2.48, Float(z)), rotation: SCNVector4(1, 0, 0, Float.pi / 2)))
            for index in 0..<9 {
                let y = 2.3 - Float(index) * 0.13
                let slat = box(width: 0.02, height: 0.012, length: 1.02, color: slatColor, position: SCNVector3(3.895, y, Float(z)))
                slat.eulerAngles.z = index % 2 == 0 ? 0.08 : -0.05
                slat.runAction(.repeatForever(.sequence([
                    .rotateBy(x: 0, y: 0, z: index % 2 == 0 ? 0.018 : -0.014, duration: 1.8 + Double(index % 3) * 0.22),
                    .rotateBy(x: 0, y: 0, z: index % 2 == 0 ? -0.018 : 0.014, duration: 2.2 + Double(index % 4) * 0.2)
                ])), forKey: "blind_slat_waver")
                root.addChildNode(slat)
            }
            let cord = capsule(radius: 0.006, height: 0.78, color: NSColor(calibratedWhite: 0.82, alpha: 0.86), position: SCNVector3(3.84, 1.74, Float(z) + 0.54))
            cord.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: 0.025, duration: 1.4),
                .rotateBy(x: 0, y: 0, z: -0.025, duration: 1.8)
            ])), forKey: "cord_sway")
            root.addChildNode(cord)
            let bead = sphere(radius: 0.018, color: NSColor(calibratedWhite: 0.78, alpha: 0.88), position: SCNVector3(3.84, 1.32, Float(z) + 0.54), scale: SCNVector3(0.65, 1, 0.65))
            bead.runAction(.repeatForever(.sequence([
                .moveBy(x: 0.006, y: 0, z: 0, duration: 1.4),
                .moveBy(x: -0.006, y: 0, z: 0, duration: 1.8)
            ])), forKey: "bead_sway")
            root.addChildNode(bead)
        }
        return root
    }

    private func makeOutsideNightDetails() -> SCNNode {
        let root = SCNNode()
        let lightColors = [
            NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.32, alpha: 0.92),
            NSColor(calibratedRed: 0.58, green: 0.76, blue: 1.0, alpha: 0.76),
            NSColor(calibratedRed: 0.9, green: 0.95, blue: 1.0, alpha: 0.58)
        ]

        for index in 0..<34 {
            let z = -2.85 + Float((index * 37) % 580) / 100
            let y = 0.12 + Float((index * 19) % 120) / 100
            let light = box(width: 0.038, height: 0.026, length: 0.026, color: lightColors[index % lightColors.count], position: SCNVector3(-0.032, y, z))
            light.geometry?.firstMaterial?.emission.contents = lightColors[index % lightColors.count]
            root.addChildNode(light)
        }

        for index in 0..<18 {
            let z = -3.0 + Float((index * 41) % 620) / 100
            let y = 0.52 + Float((index * 29) % 84) / 100
            let star = sphere(radius: 0.012 + CGFloat(index % 3) * 0.003, color: NSColor(calibratedWhite: 0.96, alpha: 0.72), position: SCNVector3(-0.038, y, z), scale: SCNVector3(1, 0.7, 1))
            star.geometry?.firstMaterial?.emission.contents = NSColor(calibratedWhite: 0.84, alpha: 0.46)
            root.addChildNode(star)
        }

        let farRoadGlow = box(width: 0.026, height: 0.055, length: 5.2, color: NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.18, alpha: 0.14), position: SCNVector3(-0.036, -0.53, -0.15))
        root.addChildNode(farRoadGlow)
        return root
    }

    private func makeOutsideParallaxDepthLayer() -> SCNNode {
        let root = SCNNode()
        let farBuilding = NSColor(calibratedRed: 0.08, green: 0.12, blue: 0.18, alpha: 0.46)
        let midBuilding = NSColor(calibratedRed: 0.12, green: 0.16, blue: 0.22, alpha: 0.52)
        let closeTree = NSColor(calibratedRed: 0.04, green: 0.16, blue: 0.08, alpha: 0.42)
        let rainMist = NSColor(calibratedRed: 0.62, green: 0.76, blue: 1.0, alpha: 0.08)
        let litWindow = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.3, alpha: 0.24)

        for index in 0..<5 {
            let z = -2.75 + Float(index) * 1.36
            let building = box(width: 0.018, height: 0.72 + CGFloat(index % 3) * 0.18, length: 0.56 + CGFloat(index % 2) * 0.18, color: index % 2 == 0 ? farBuilding : midBuilding, position: SCNVector3(-0.018, -0.18 + Float(index % 2) * 0.08, z))
            building.name = "outsideParallaxBuilding\(index)"
            root.addChildNode(building)
            for lightIndex in 0..<3 {
                let window = box(width: 0.006, height: 0.034, length: 0.045, color: litWindow, position: SCNVector3(-0.032, 0.02 + Float(lightIndex) * 0.14, z - 0.18 + Float((index + lightIndex) % 4) * 0.11))
                window.name = "outsideParallaxWindowLight\(index)_\(lightIndex)"
                window.geometry?.firstMaterial?.emission.contents = litWindow
                root.addChildNode(window)
            }
        }

        for index in 0..<6 {
            let z = -3.0 + Float(index) * 1.15
            let tree = sphere(radius: 0.16 + CGFloat(index % 2) * 0.04, color: closeTree, position: SCNVector3(-0.04, -0.42 + Float(index % 3) * 0.08, z), scale: SCNVector3(0.22, 1.0, 0.86))
            tree.name = "outsideNearTreeSilhouette\(index)"
            root.addChildNode(tree)
        }

        for index in 0..<7 {
            let z = -2.95 + Float(index) * 0.96
            let mist = box(width: 0.01, height: 0.36 + CGFloat(index % 2) * 0.12, length: 0.62, color: rainMist, position: SCNVector3(-0.052, 0.18 + Float(index % 3) * 0.16, z))
            mist.name = "outsideRainMistVeil\(index)"
            mist.eulerAngles.z = -0.06 + CGFloat(index % 4) * 0.03
            root.addChildNode(mist)
        }
        return root
    }

    private func glassPane(width: CGFloat, height: CGFloat, length: CGFloat, position: SCNVector3) -> SCNNode {
        let geometry = SCNBox(width: width, height: height, length: length, chamferRadius: 0.004)
        let glass = SCNMaterial()
        glass.diffuse.contents = NSColor(calibratedRed: 0.68, green: 0.88, blue: 1.0, alpha: 0.2)
        glass.specular.contents = NSColor.white
        glass.emission.contents = NSColor(calibratedRed: 0.18, green: 0.36, blue: 0.5, alpha: 0.05)
        glass.transparency = 0.28
        glass.blendMode = .alpha
        glass.isDoubleSided = true
        geometry.firstMaterial = glass
        let node = SCNNode(geometry: geometry)
        node.position = position
        return node
    }

    private func windowFrame(at position: SCNVector3, height: CGFloat = 1.12, length: CGFloat = 1.46) -> SCNNode {
        let root = SCNNode()
        root.position = position
        let frameColor = NSColor(calibratedRed: 0.72, green: 0.74, blue: 0.72, alpha: 1)
        root.addChildNode(box(width: 0.055, height: height, length: 0.04, color: frameColor, position: SCNVector3(0, 0, -Float(length / 2))))
        root.addChildNode(box(width: 0.055, height: height, length: 0.04, color: frameColor, position: SCNVector3(0, 0, Float(length / 2))))
        root.addChildNode(box(width: 0.055, height: 0.04, length: length, color: frameColor, position: SCNVector3(0, Float(height / 2), 0)))
        root.addChildNode(box(width: 0.055, height: 0.04, length: length, color: frameColor, position: SCNVector3(0, -Float(height / 2), 0)))
        root.addChildNode(box(width: 0.058, height: height - 0.06, length: 0.025, color: frameColor, position: SCNVector3(0, 0, 0)))
        return root
    }

    private func makeDoors() -> SCNNode {
        let root = SCNNode()
        let doorColor = NSColor(calibratedRed: 0.38, green: 0.25, blue: 0.15, alpha: 1)
        let trimColor = NSColor(calibratedRed: 0.18, green: 0.12, blue: 0.08, alpha: 1)
        let knobColor = NSColor(calibratedRed: 0.86, green: 0.68, blue: 0.28, alpha: 1)

        addDoorFrame(to: root, centerZ: -4.65, color: trimColor)
        frontDoorLightSpillNode.addChildNode(makeDoorLightSpill(centerZ: -4.65, isRear: false))
        frontDoorGapLightNode.addChildNode(makeDoorGapLight(centerZ: -4.65))
        root.addChildNode(frontDoorLightSpillNode)
        root.addChildNode(frontDoorGapLightNode)
        configureDoorLeaf(frontDoorLeftNode, doorColor: doorColor, knobColor: knobColor, knobOffsetZ: 0.13)
        configureDoorLeaf(frontDoorRightNode, doorColor: doorColor, knobColor: knobColor, knobOffsetZ: -0.13)
        root.addChildNode(frontDoorLeftNode)
        root.addChildNode(frontDoorRightNode)

        addDoorFrame(to: root, centerZ: 4.65, color: trimColor)
        rearDoorLightSpillNode.addChildNode(makeDoorLightSpill(centerZ: 4.65, isRear: true))
        rearDoorGapLightNode.addChildNode(makeDoorGapLight(centerZ: 4.65))
        root.addChildNode(rearDoorLightSpillNode)
        root.addChildNode(rearDoorGapLightNode)
        configureDoorLeaf(rearDoorLeftNode, doorColor: doorColor, knobColor: knobColor, knobOffsetZ: 0.13)
        configureDoorLeaf(rearDoorRightNode, doorColor: doorColor, knobColor: knobColor, knobOffsetZ: -0.13)
        root.addChildNode(rearDoorLeftNode)
        root.addChildNode(rearDoorRightNode)
        updateDoors(frontOpen: false, rearOpen: false)
        return root
    }

    private func makeDoorLightSpill(centerZ: Float, isRear: Bool) -> SCNNode {
        let root = SCNNode()
        let warm = NSColor(calibratedRed: 1.0, green: 0.84, blue: 0.48, alpha: 0.16)
        let pale = NSColor(calibratedRed: 0.92, green: 0.96, blue: 1.0, alpha: 0.11)
        let amberEdge = NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.22, alpha: 0.34)
        let contactShadow = NSColor(calibratedWhite: 0.02, alpha: 0.28)
        let angle: Float = isRear ? -0.07 : 0.07

        let mainPool = box(width: 1.55, height: 0.007, length: 0.86, color: warm, position: SCNVector3(3.22, 0.022, centerZ))
        mainPool.eulerAngles.y = angle
        root.addChildNode(mainPool)

        let longPool = box(width: 2.35, height: 0.006, length: 0.34, color: pale, position: SCNVector3(2.75, 0.024, centerZ + (isRear ? -0.07 : 0.07)))
        longPool.eulerAngles.y = angle * 1.6
        root.addChildNode(longPool)

        let thresholdGlow = box(width: 0.06, height: 0.01, length: 0.93, color: amberEdge, position: SCNVector3(3.94, 0.036, centerZ))
        root.addChildNode(thresholdGlow)
        let thresholdShadow = box(width: 0.18, height: 0.008, length: 0.96, color: contactShadow, position: SCNVector3(4.02, 0.028, centerZ))
        root.addChildNode(thresholdShadow)

        for offset in [-0.45, 0.45] {
            let sideRim = box(width: 0.018, height: 1.92, length: 0.04, color: amberEdge, position: SCNVector3(3.95, 1.05, centerZ + Float(offset)))
            root.addChildNode(sideRim)
            let frameShadow = box(width: 0.018, height: 1.9, length: 0.075, color: contactShadow, position: SCNVector3(4.035, 1.04, centerZ + Float(offset)))
            root.addChildNode(frameShadow)
        }

        let topGlow = box(width: 0.02, height: 0.035, length: 0.84, color: NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.36, alpha: 0.24), position: SCNVector3(3.955, 2.08, centerZ))
        root.addChildNode(topGlow)

        let light = SCNLight()
        light.type = .omni
        light.intensity = 0
        light.color = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.42, alpha: 1)
        light.attenuationStartDistance = 0.2
        light.attenuationEndDistance = 3.2
        let lightNode = SCNNode()
        lightNode.name = "doorSpillLight"
        lightNode.light = light
        lightNode.position = SCNVector3(3.45, 1.05, centerZ)
        root.addChildNode(lightNode)

        return root
    }

    private func makeDoorGapLight(centerZ: Float) -> SCNNode {
        let root = SCNNode()
        let seamLight = NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.42, alpha: 0.5)
        let lowLight = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.24, alpha: 0.32)
        root.addChildNode(box(width: 0.014, height: 1.82, length: 0.018, color: seamLight, position: SCNVector3(3.965, 1.02, centerZ)))
        root.addChildNode(box(width: 0.014, height: 0.028, length: 0.72, color: lowLight, position: SCNVector3(3.965, 0.09, centerZ)))
        root.addChildNode(box(width: 0.016, height: 0.018, length: 0.36, color: NSColor(calibratedWhite: 0.02, alpha: 0.36), position: SCNVector3(3.995, 0.07, centerZ)))
        return root
    }

    private func configureDoorLeaf(_ node: SCNNode, doorColor: NSColor, knobColor: NSColor, knobOffsetZ: Float) {
        node.addChildNode(box(width: 0.08, height: 2.0, length: 0.37, color: doorColor, position: SCNVector3Zero))
        node.addChildNode(sphere(radius: 0.028, color: knobColor, position: SCNVector3(-0.055, 0.02, knobOffsetZ)))
    }

    private func addDoorFrame(to root: SCNNode, centerZ: Float, color: NSColor) {
        root.addChildNode(box(width: 0.1, height: 2.14, length: 0.06, color: color, position: SCNVector3(4.0, 1.07, centerZ - 0.45)))
        root.addChildNode(box(width: 0.1, height: 2.14, length: 0.06, color: color, position: SCNVector3(4.0, 1.07, centerZ + 0.45)))
        root.addChildNode(box(width: 0.1, height: 0.08, length: 0.96, color: color, position: SCNVector3(4.0, 2.12, centerZ)))
    }

    private func updateDoors(game: GameManager) {
        updateDoors(frontOpen: game.frontDoorOpen, rearOpen: game.rearDoorOpen)
    }

    private func updateDoors(frontOpen: Bool, rearOpen: Bool) {
        updateDoorLeaves(leftNode: frontDoorLeftNode, rightNode: frontDoorRightNode, isOpen: frontOpen, centerZ: Float(StudentDoor.front.centerZ))
        updateDoorLeaves(leftNode: rearDoorLeftNode, rightNode: rearDoorRightNode, isOpen: rearOpen, centerZ: Float(StudentDoor.rear.centerZ))
        updateDoorLightEffects(frontOpen: frontOpen, rearOpen: rearOpen)
    }

    private func updateDoorLightEffects(frontOpen: Bool, rearOpen: Bool) {
        applyDoorLightState(spillNode: frontDoorLightSpillNode, gapNode: frontDoorGapLightNode, isOpen: frontOpen, openIntensity: 185)
        applyDoorLightState(spillNode: rearDoorLightSpillNode, gapNode: rearDoorGapLightNode, isOpen: rearOpen, openIntensity: 145)
    }

    private func applyDoorLightState(spillNode: SCNNode, gapNode: SCNNode, isOpen: Bool, openIntensity: CGFloat) {
        let pulseKey = "doorLightPulse"
        let targetSpillOpacity: CGFloat = isOpen ? 0.88 : 0.13
        let targetGapOpacity: CGFloat = isOpen ? 0.95 : 0.28
        gapNode.opacity = targetGapOpacity

        if let spillLight = spillNode.childNode(withName: "doorSpillLight", recursively: true)?.light {
            spillLight.intensity = isOpen ? openIntensity : 18
        }

        if isOpen {
            if spillNode.action(forKey: pulseKey) == nil {
                spillNode.opacity = targetSpillOpacity
                let brighten = SCNAction.fadeOpacity(to: targetSpillOpacity, duration: 1.1)
                brighten.timingMode = .easeInEaseOut
                let soften = SCNAction.fadeOpacity(to: 0.66, duration: 1.35)
                soften.timingMode = .easeInEaseOut
                spillNode.runAction(.repeatForever(.sequence([soften, brighten])), forKey: pulseKey)
            }
        } else {
            spillNode.removeAction(forKey: pulseKey)
            spillNode.opacity = targetSpillOpacity
        }
    }

    private func updateDoorLeaves(leftNode: SCNNode, rightNode: SCNNode, isOpen: Bool, centerZ: Float) {
        if isOpen {
            leftNode.position = SCNVector3(4.31, 1.0, centerZ - 0.43)
            leftNode.eulerAngles = SCNVector3(0, Float.pi / 2, 0)
            rightNode.position = SCNVector3(4.31, 1.0, centerZ + 0.43)
            rightNode.eulerAngles = SCNVector3(0, -Float.pi / 2, 0)
        } else {
            leftNode.position = SCNVector3(4.02, 1.0, centerZ - 0.19)
            leftNode.eulerAngles = SCNVector3Zero
            rightNode.position = SCNVector3(4.02, 1.0, centerZ + 0.19)
            rightNode.eulerAngles = SCNVector3Zero
        }
    }

    private func updatePlayerLocker(game: GameManager) {
        updatePlayerLocker(isOpen: game.playerLockerOpen)
    }

    private func updatePlayerLocker(isOpen: Bool) {
        if isOpen {
            playerLockerDoorNode.position = SCNVector3(6.19, 0.63, -3.76)
            playerLockerDoorNode.eulerAngles = SCNVector3(0, -Float.pi / 2, 0)
        } else {
            playerLockerDoorNode.position = SCNVector3(6.3, 0.63, -3.9)
            playerLockerDoorNode.eulerAngles = SCNVector3Zero
        }
    }

    private func makeFurniture() -> SCNNode {
        let root = SCNNode()
        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                root.addChildNode(makeDesk(at: SCNVector3(x, 0, z), isPlayer: row == 2 && column == 1))
                root.addChildNode(makeChair(at: SCNVector3(x, 0, z + 0.55)))
            }
        }
        deskSpecularNetworkNode.addChildNode(makeDeskSpecularNetworkLayer())
        deskSpecularNetworkNode.opacity = 0.24
        root.addChildNode(deskSpecularNetworkNode)
        deskRowDepthDetailNode.addChildNode(makeDeskRowDepthDetailLayer())
        deskRowDepthDetailNode.opacity = 0.2
        root.addChildNode(deskRowDepthDetailNode)
        smallPropCinematicNode.addChildNode(makeSmallPropCinematicLayer())
        smallPropCinematicNode.opacity = 0.2
        root.addChildNode(smallPropCinematicNode)
        furnitureMaterialDetailNode.addChildNode(makeFurnitureMaterialDetailLayer())
        furnitureMaterialDetailNode.opacity = 0.22
        root.addChildNode(furnitureMaterialDetailNode)
        furnitureCinematicContactNode.addChildNode(makeFurnitureCinematicContactLayer())
        furnitureCinematicContactNode.opacity = 0.2
        root.addChildNode(furnitureCinematicContactNode)
        furnitureMicroGeometryNode.addChildNode(makeFurnitureMicroGeometryLayer())
        furnitureMicroGeometryNode.opacity = 0.18
        root.addChildNode(furnitureMicroGeometryNode)
        studentDeskStoryPropNode.addChildNode(makeStudentDeskStoryPropLayer())
        studentDeskStoryPropNode.opacity = 0.18
        root.addChildNode(studentDeskStoryPropNode)
        classroomLifeClutterNode.addChildNode(makeClassroomLifeClutterLayer())
        classroomLifeClutterNode.opacity = 0.2
        root.addChildNode(classroomLifeClutterNode)
        return root
    }

    private func makeInteriorDetails() -> SCNNode {
        let root = SCNNode()
        let seamColor = NSColor(calibratedRed: 0.34, green: 0.28, blue: 0.22, alpha: 1)
        for x in stride(from: -3.0, through: 3.0, by: 1.0) {
            root.addChildNode(box(width: 0.012, height: 0.006, length: 11.4, color: seamColor, position: SCNVector3(Float(x), 0.006, 0)))
        }
        for z in stride(from: -5.0, through: 5.0, by: 1.0) {
            root.addChildNode(box(width: 7.4, height: 0.006, length: 0.012, color: seamColor, position: SCNVector3(0, 0.007, Float(z))))
        }

        let baseboard = NSColor(calibratedRed: 0.42, green: 0.33, blue: 0.24, alpha: 1)
        root.addChildNode(box(width: 7.8, height: 0.12, length: 0.035, color: baseboard, position: SCNVector3(0, 0.08, -5.96)))
        root.addChildNode(box(width: 7.8, height: 0.12, length: 0.035, color: baseboard, position: SCNVector3(0, 0.08, 5.96)))
        root.addChildNode(box(width: 0.035, height: 0.12, length: 11.8, color: baseboard, position: SCNVector3(-3.96, 0.08, 0)))

        root.addChildNode(makeNoticeBoard())
        root.addChildNode(makeCleaningCorner())
        root.addChildNode(makeCeilingLights())
        root.addChildNode(makeCeilingInfrastructure())
        ceilingMoodShadowNode.addChildNode(makeCeilingMoodShadowLayer())
        ceilingMoodShadowNode.opacity = 0.18
        root.addChildNode(ceilingMoodShadowNode)
        ceilingCinematicLayerNode.addChildNode(makeCeilingCinematicLayer())
        ceilingCinematicLayerNode.opacity = 0.22
        root.addChildNode(ceilingCinematicLayerNode)
        ceilingFixtureDetailNode.addChildNode(makeCeilingFixtureDetailLayer())
        ceilingFixtureDetailNode.opacity = 0.18
        root.addChildNode(ceilingFixtureDetailNode)
        ceilingLightRigCinematicNode.addChildNode(makeCeilingLightRigCinematicLayer())
        ceilingLightRigCinematicNode.opacity = 0.16
        root.addChildNode(ceilingLightRigCinematicNode)
        root.addChildNode(makeAirDustLayer())
        atmosphericMediumNode.addChildNode(makeAtmosphericMediumLayer())
        atmosphericMediumNode.opacity = 0.16
        root.addChildNode(atmosphericMediumNode)
        nearFieldAtmosphereNode.addChildNode(makeNearFieldAtmosphereLayer())
        nearFieldAtmosphereNode.opacity = 0.14
        root.addChildNode(nearFieldAtmosphereNode)
        volumetricLightVolumeNode.addChildNode(makeVolumetricLightVolumeLayer())
        volumetricLightVolumeNode.opacity = 0.18
        root.addChildNode(volumetricLightVolumeNode)
        classroomOccludedLightShaftNode.addChildNode(makeClassroomOccludedLightShaftLayer())
        classroomOccludedLightShaftNode.opacity = 0.14
        root.addChildNode(classroomOccludedLightShaftNode)
        classroomAirContinuityNode.addChildNode(makeClassroomAirContinuityLayer())
        classroomAirContinuityNode.opacity = 0.16
        root.addChildNode(classroomAirContinuityNode)
        classroomAmbientMotionRhythmNode.addChildNode(makeClassroomAmbientMotionRhythmLayer())
        classroomAmbientMotionRhythmNode.opacity = 0.14
        root.addChildNode(classroomAmbientMotionRhythmNode)
        root.addChildNode(makeAnimatedLightPatches())
        root.addChildNode(makeDepthAtmosphereLayer())
        root.addChildNode(makeRightStorageCabinet())
        root.addChildNode(makeRearNewspaperWall())
        root.addChildNode(makeAirConditioningDetails())
        root.addChildNode(makeWallEquipmentDetails())
        environmentStoryDetailNode.addChildNode(makeEnvironmentStoryDetailLayer())
        environmentStoryDetailNode.opacity = 0.22
        root.addChildNode(environmentStoryDetailNode)
        return root
    }

    private func makeEnvironmentStoryDetailLayer() -> SCNNode {
        let root = SCNNode()
        let oldTape = NSColor(calibratedRed: 0.88, green: 0.78, blue: 0.45, alpha: 0.2)
        let paperGhost = NSColor(calibratedWhite: 0.96, alpha: 0.16)
        let dirt = NSColor(calibratedRed: 0.14, green: 0.1, blue: 0.065, alpha: 0.2)
        let chalk = NSColor(calibratedWhite: 0.9, alpha: 0.13)
        let shoeRub = NSColor(calibratedWhite: 0.02, alpha: 0.16)

        for index in 0..<8 {
            let x = -1.82 + Float(index % 4) * 1.18
            let y: Float = index < 4 ? 2.62 : 1.28
            let tape = box(width: 0.18 + CGFloat(index % 2) * 0.05, height: 0.014, length: 0.006, color: oldTape, position: SCNVector3(x, y, -5.972))
            tape.name = "storyBlackboardTapeGhost\(index)"
            tape.eulerAngles.z = CGFloat((index % 3) - 1) * 0.08
            root.addChildNode(tape)
        }

        for index in 0..<5 {
            let smear = box(width: 0.42 + CGFloat(index % 2) * 0.16, height: 0.018, length: 0.006, color: chalk, position: SCNVector3(-1.9 + Float(index) * 0.95, 1.33 + Float(index % 2) * 0.18, -5.974))
            smear.name = "storyBlackboardHandSmear\(index)"
            smear.eulerAngles.z = CGFloat(index - 2) * 0.035
            root.addChildNode(smear)
        }

        for index in 0..<6 {
            let poster = box(width: 0.34 + CGFloat(index % 2) * 0.08, height: 0.11 + CGFloat(index % 3) * 0.035, length: 0.006, color: paperGhost, position: SCNVector3(-3.2 + Float(index) * 1.26, 1.58 + Float(index % 3) * 0.22, 5.974))
            poster.name = "storyRearPosterGhost\(index)"
            poster.eulerAngles.z = CGFloat((index % 5) - 2) * 0.035
            root.addChildNode(poster)
            let curl = box(width: 0.09, height: 0.018, length: 0.008, color: NSColor(calibratedWhite: 1.0, alpha: 0.18), position: SCNVector3(-3.05 + Float(index) * 1.26, 1.64 + Float(index % 3) * 0.22, 5.966))
            curl.name = "storyRearPosterCurl\(index)"
            curl.eulerAngles.z = -0.18 + CGFloat(index % 3) * 0.09
            root.addChildNode(curl)
        }

        for index in 0..<10 {
            let z = -4.9 + Float(index) * 1.08
            let scuff = box(width: 0.006, height: 0.09 + CGFloat(index % 3) * 0.04, length: 0.18 + CGFloat(index % 2) * 0.08, color: dirt, position: SCNVector3(-3.974, 0.42 + Float(index % 4) * 0.18, z))
            scuff.name = "storySideWallDeskScuff\(index)"
            scuff.eulerAngles.x = CGFloat((index % 5) - 2) * 0.02
            root.addChildNode(scuff)
        }

        for index in 0..<8 {
            let x = -3.2 + Float(index) * 0.92
            let frontChip = box(width: 0.22 + CGFloat(index % 2) * 0.07, height: 0.018, length: 0.008, color: dirt.withAlphaComponent(0.22), position: SCNVector3(x, 0.145, -5.982))
            frontChip.name = "storyBaseboardChipFront\(index)"
            root.addChildNode(frontChip)
            let rearChip = box(width: 0.2 + CGFloat(index % 3) * 0.05, height: 0.016, length: 0.008, color: dirt.withAlphaComponent(0.2), position: SCNVector3(x + 0.18, 0.132, 5.982))
            rearChip.name = "storyBaseboardChipRear\(index)"
            root.addChildNode(rearChip)
        }

        for index in 0..<9 {
            let z = -5.0 + Float(index) * 1.25
            let kick = box(width: 0.006, height: 0.12 + CGFloat(index % 3) * 0.035, length: 0.24 + CGFloat(index % 2) * 0.06, color: shoeRub, position: SCNVector3(3.972, 0.36 + Float(index % 2) * 0.12, z))
            kick.name = "storyDoorSideKickMark\(index)"
            kick.eulerAngles.x = CGFloat((index % 4) - 1) * 0.045
            root.addChildNode(kick)
        }

        for index in 0..<12 {
            let x = -3.4 + Float((index * 47) % 680) / 100
            let z = -5.1 + Float((index * 61) % 1020) / 100
            let gum = sphere(radius: 0.018 + CGFloat(index % 3) * 0.004, color: NSColor(calibratedWhite: 0.08, alpha: 0.16), position: SCNVector3(x, 0.048, z), scale: SCNVector3(1.8, 0.18, 1.0))
            gum.name = "storyFloorGumShadow\(index)"
            root.addChildNode(gum)
        }

        for index in 0..<14 {
            let trace = box(width: 0.18 + CGFloat(index % 4) * 0.06, height: 0.003, length: 0.018, color: shoeRub.withAlphaComponent(0.11), position: SCNVector3(-3.25 + Float((index * 37) % 650) / 100, 0.052, -5.25 + Float((index * 43) % 1050) / 100))
            trace.name = "storyFloorHeelTrace\(index)"
            trace.eulerAngles.y = -0.55 + Float(index % 9) * 0.13
            root.addChildNode(trace)
        }
        return root
    }

    private func makeDeskSpecularNetworkLayer() -> SCNNode {
        let root = SCNNode()
        let warmEdge = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.42, alpha: 0.12)
        let coolRim = NSColor(calibratedRed: 0.42, green: 0.68, blue: 1.0, alpha: 0.08)
        let contact = NSColor(calibratedWhite: 0.02, alpha: 0.1)

        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let topWash = box(width: 0.68, height: 0.004, length: 0.052, color: (row + column) % 2 == 0 ? warmEdge : coolRim, position: SCNVector3(x - 0.02, 0.808, z - 0.22))
                topWash.name = "deskTopCinematicRim_\(row)_\(column)"
                topWash.eulerAngles.y = Float(column - 1) * 0.035
                topWash.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: 0.08, duration: 1.8 + Double(row) * 0.16),
                    .fadeOpacity(to: 0.3, duration: 2.4 + Double(column) * 0.14)
                ])), forKey: "desk_rim_breathe")
                root.addChildNode(topWash)

                let nearLip = box(width: 0.82, height: 0.005, length: 0.018, color: contact, position: SCNVector3(x, 0.814, z + 0.305))
                nearLip.name = "deskNearLipOcclusion_\(row)_\(column)"
                root.addChildNode(nearLip)
            }
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 1.92
            let rowRibbon = box(width: 5.8, height: 0.003, length: 0.06, color: NSColor(calibratedRed: 0.9, green: 0.92, blue: 0.78, alpha: 0.055), position: SCNVector3(0, 0.822, z))
            rowRibbon.name = "deskRowSoftReflection\(row)"
            rowRibbon.eulerAngles.y = row % 2 == 0 ? 0.025 : -0.025
            root.addChildNode(rowRibbon)
        }
        return root
    }

