                let personalGap = box(width: 0.46, height: 0.003, length: 0.08, color: NSColor(calibratedWhite: 0.0, alpha: 0.09), position: SCNVector3(x - 0.06, 0.814, z - 0.34))
                personalGap.name = "deskRowPersonalSpaceOcclusion_\(row)_\(column)"
                root.addChildNode(personalGap)
            }
        }
        return root
    }

