    private func makeClassroomLifeClutterLayer() -> SCNNode {
        let root = SCNNode()
        let pencilCaseColors = [
            NSColor(calibratedRed: 0.12, green: 0.18, blue: 0.36, alpha: 1),
            NSColor(calibratedRed: 0.42, green: 0.12, blue: 0.18, alpha: 1),
            NSColor(calibratedRed: 0.12, green: 0.32, blue: 0.22, alpha: 1),
            NSColor(calibratedRed: 0.62, green: 0.42, blue: 0.16, alpha: 1)
        ]
        let stickyColors = [
            NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.32, alpha: 0.82),
            NSColor(calibratedRed: 0.58, green: 0.9, blue: 0.78, alpha: 0.78),
            NSColor(calibratedRed: 0.8, green: 0.72, blue: 1.0, alpha: 0.74)
        ]
        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let seed = row * 13 + column * 17

                let pencilCase = roundedBox(
                    width: 0.22 + CGFloat(seed % 2) * 0.04,
                    height: 0.034,
                    length: 0.105,
                    chamfer: 0.022,
                    color: pencilCaseColors[seed % pencilCaseColors.count],
                    position: SCNVector3(x + 0.19, 0.855, z - 0.12)
                )
                pencilCase.name = "lifePencilCase_\(row)_\(column)"
                pencilCase.eulerAngles.y = -0.18 + Float(seed % 5) * 0.08
                root.addChildNode(pencilCase)
                let zipperLine = box(width: 0.18, height: 0.004, length: 0.006, color: NSColor(calibratedWhite: 0.95, alpha: 0.3), position: SCNVector3(x + 0.19, 0.878, z - 0.12))
                zipperLine.name = "lifePencilCaseZipper_\(row)_\(column)"
                zipperLine.eulerAngles.y = pencilCase.eulerAngles.y
                root.addChildNode(zipperLine)

                if (row + column) % 2 == 0 {
                    let ruler = box(width: 0.34, height: 0.006, length: 0.032, color: NSColor(calibratedWhite: 0.92, alpha: 0.36), position: SCNVector3(x - 0.18, 0.858, z + 0.05))
                    ruler.name = "lifeTranslucentRuler_\(row)_\(column)"
                    ruler.eulerAngles.y = 0.34 - Float(seed % 4) * 0.08
                    root.addChildNode(ruler)
                    for tick in 0..<5 {
                        let mark = box(width: 0.006, height: 0.003, length: 0.02, color: NSColor(calibratedWhite: 0.08, alpha: 0.22), position: SCNVector3(x - 0.32 + Float(tick) * 0.06, 0.864, z + 0.05))
                        mark.name = "lifeRulerTick_\(row)_\(column)_\(tick)"
                        mark.eulerAngles.y = ruler.eulerAngles.y
                        root.addChildNode(mark)
                    }
                }

                let sticky = box(width: 0.12, height: 0.005, length: 0.08, color: stickyColors[seed % stickyColors.count], position: SCNVector3(x - 0.28, 0.862, z + 0.2))
                sticky.name = "lifeStickyNote_\(row)_\(column)"
                sticky.eulerAngles.y = -0.12 + Float(seed % 6) * 0.04
                root.addChildNode(sticky)
                let stickyShadow = box(width: 0.13, height: 0.003, length: 0.085, color: NSColor(calibratedWhite: 0.02, alpha: 0.08), position: SCNVector3(x - 0.28, 0.856, z + 0.2))
                stickyShadow.name = "lifeStickyNoteContact_\(row)_\(column)"
                stickyShadow.eulerAngles.y = sticky.eulerAngles.y
                root.addChildNode(stickyShadow)

                if seed % 3 == 0 {
                    let tissue = roundedBox(width: 0.18, height: 0.046, length: 0.12, chamfer: 0.012, color: NSColor(calibratedWhite: 0.96, alpha: 0.86), position: SCNVector3(x + 0.02, 0.865, z + 0.25))
                    tissue.name = "lifeTissuePack_\(row)_\(column)"
                    tissue.eulerAngles.y = 0.1
                    root.addChildNode(tissue)
                    let tissuePull = box(width: 0.1, height: 0.006, length: 0.035, color: NSColor(calibratedWhite: 1.0, alpha: 0.58), position: SCNVector3(x + 0.02, 0.895, z + 0.25))
                    tissuePull.name = "lifeTissuePull_\(row)_\(column)"
                    tissuePull.eulerAngles.z = -0.18
                    root.addChildNode(tissuePull)
                }

                let danglingStrap = capsule(radius: 0.004, height: 0.28, color: NSColor(calibratedWhite: 0.02, alpha: 0.82), position: SCNVector3(x + (seed % 2 == 0 ? -0.42 : 0.42), 0.68, z + 0.24), rotation: SCNVector4(0, 0, 1, seed % 2 == 0 ? -0.2 : 0.2))
                danglingStrap.name = "lifeDeskDanglingStrap_\(row)_\(column)"
                root.addChildNode(danglingStrap)
            }
        }
        return root
    }

    private func makeFurnitureMaterialDetailLayer() -> SCNNode {
        let root = SCNNode()
        let varnishWarm = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.38, alpha: 0.12)
        let oldWoodCut = NSColor(calibratedRed: 0.18, green: 0.09, blue: 0.035, alpha: 0.22)
        let paperEdge = NSColor(calibratedWhite: 0.96, alpha: 0.18)
        let chairMetal = NSColor(calibratedRed: 0.82, green: 0.84, blue: 0.76, alpha: 0.12)
        let contactDark = NSColor(calibratedWhite: 0.0, alpha: 0.14)

        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let seed = row * 7 + column * 11

                let frontVarnish = box(width: 0.58 + CGFloat(seed % 3) * 0.08, height: 0.004, length: 0.01, color: varnishWarm, position: SCNVector3(x - 0.04, 0.832, z + 0.302))
                frontVarnish.name = "furnitureDeskVarnishEdge_\(row)_\(column)"
                frontVarnish.eulerAngles.y = Float(seed % 5) * 0.018 - 0.036
                root.addChildNode(frontVarnish)

                for corner in 0..<2 {
                    let side: Float = corner == 0 ? -1 : 1
                    let chip = box(width: 0.09 + CGFloat((seed + corner) % 2) * 0.04, height: 0.005, length: 0.018, color: oldWoodCut, position: SCNVector3(x + side * 0.36, 0.836, z + (corner == 0 ? -0.25 : 0.25)))
                    chip.name = "furnitureDeskCornerChip_\(row)_\(column)_\(corner)"
                    chip.eulerAngles.y = side * (0.16 + Float(seed % 4) * 0.035)
                    root.addChildNode(chip)
                }

                for scratch in 0..<4 {
                    let mark = box(
                        width: 0.16 + CGFloat((scratch + seed) % 3) * 0.028,
                        height: 0.003,
                        length: 0.0045,
                        color: scratch % 2 == 0 ? oldWoodCut.withAlphaComponent(0.18) : varnishWarm.withAlphaComponent(0.1),
                        position: SCNVector3(x - 0.26 + Float((scratch * 19 + seed) % 52) / 100, 0.839, z - 0.2 + Float((scratch * 23 + seed) % 40) / 100)
                    )
                    mark.name = "furnitureDeskMicroScratch_\(row)_\(column)_\(scratch)"
                    mark.eulerAngles.y = -0.42 + Float((scratch + seed) % 9) * 0.09
                    root.addChildNode(mark)
                }

                let pageStack = box(width: 0.24, height: 0.006, length: 0.07, color: paperEdge, position: SCNVector3(x - 0.2, 0.848, z - 0.322))
                pageStack.name = "furniturePaperLayerEdge_\(row)_\(column)"
                pageStack.eulerAngles.y = -0.08 + Float((row + column) % 4) * 0.045
                root.addChildNode(pageStack)

                for layer in 0..<3 {
                    let pageLine = box(width: 0.2 - CGFloat(layer) * 0.025, height: 0.0025, length: 0.006, color: NSColor(calibratedWhite: 1.0, alpha: 0.12), position: SCNVector3(x - 0.2 + Float(layer) * 0.014, 0.852 + Float(layer) * 0.003, z - 0.34 + Float(layer) * 0.012))
                    pageLine.name = "furniturePageSheetSplit_\(row)_\(column)_\(layer)"
                    pageLine.eulerAngles.y = pageStack.eulerAngles.y
                    root.addChildNode(pageLine)
                }

                let chairSeatPolish = box(width: 0.38, height: 0.004, length: 0.035, color: varnishWarm.withAlphaComponent(0.09), position: SCNVector3(x, 0.506, z + 0.55 - 0.06))
                chairSeatPolish.name = "furnitureChairSeatPolish_\(row)_\(column)"
                chairSeatPolish.eulerAngles.y = Float(column - 1) * 0.04
                root.addChildNode(chairSeatPolish)

                let chairBackRim = box(width: 0.42, height: 0.004, length: 0.012, color: varnishWarm.withAlphaComponent(0.1), position: SCNVector3(x, 0.902, z + 0.55 + 0.18))
                chairBackRim.name = "furnitureChairBackRim_\(row)_\(column)"
                root.addChildNode(chairBackRim)

                for leg in 0..<2 {
                    let side: Float = leg == 0 ? -1 : 1
                    let legGlint = capsule(radius: 0.0032, height: 0.34, color: chairMetal, position: SCNVector3(x + side * 0.235, 0.255, z + 0.55 + 0.17), rotation: SCNVector4(1, 0, 0, side * 0.08))
                    legGlint.name = "furnitureChairLegGlint_\(row)_\(column)_\(leg)"
                    root.addChildNode(legGlint)
                }

                let deskFootBlend = box(width: 0.74, height: 0.004, length: 0.22, color: contactDark, position: SCNVector3(x, 0.024, z + 0.12))
                deskFootBlend.name = "furnitureDeskFloorBlend_\(row)_\(column)"
                deskFootBlend.eulerAngles.y = Float(seed % 5) * 0.04 - 0.08
                root.addChildNode(deskFootBlend)

                let bagFloorWeight = box(width: 0.32, height: 0.004, length: 0.22, color: contactDark.withAlphaComponent(0.18), position: SCNVector3(x + (seed % 2 == 0 ? -0.48 : 0.48), 0.034, z + 0.16 + Float(seed % 3) * 0.035))
                bagFloorWeight.name = "furnitureBackpackFloorWeight_\(row)_\(column)"
                bagFloorWeight.eulerAngles.y = seed % 2 == 0 ? -0.12 : 0.12
                root.addChildNode(bagFloorWeight)
            }
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let aislePolish = box(width: 5.3, height: 0.003, length: 0.052, color: NSColor(calibratedRed: 0.76, green: 0.88, blue: 1.0, alpha: 0.045), position: SCNVector3(0, 0.032, z + 0.67))
            aislePolish.name = "furnitureAisleFloorPolish_\(row)"
            aislePolish.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.018
            root.addChildNode(aislePolish)
        }
        return root
    }

    private func makeFurnitureCinematicContactLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "furnitureCinematicContactLayer"

        let deepContact = NSColor(calibratedWhite: 0.0, alpha: 0.16)
        let warmEdge = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.38, alpha: 0.11)
        let coolMetal = NSColor(calibratedRed: 0.72, green: 0.86, blue: 1.0, alpha: 0.09)
        let skid = NSColor(calibratedWhite: 0.02, alpha: 0.12)
        let dust = NSColor(calibratedRed: 0.58, green: 0.55, blue: 0.48, alpha: 0.08)

        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let seed = row * 19 + column * 23

                let deskMass = box(width: 0.9, height: 0.003, length: 0.54, color: deepContact, position: SCNVector3(x, 0.044, z + 0.08))
                deskMass.name = "furnitureDeskMassContact_\(row)_\(column)"
                deskMass.eulerAngles.y = -0.08 + Float(seed % 5) * 0.04
                root.addChildNode(deskMass)

                let chairMass = box(width: 0.62, height: 0.003, length: 0.48, color: deepContact.withAlphaComponent(0.13), position: SCNVector3(x, 0.04, z + 0.59))
                chairMass.name = "furnitureChairMassContact_\(row)_\(column)"
                chairMass.eulerAngles.y = 0.06 - Float(seed % 4) * 0.035
                root.addChildNode(chairMass)

                for legIndex in 0..<4 {
                    let legX: Float = legIndex < 2 ? -0.34 : 0.34
                    let legZ: Float = legIndex % 2 == 0 ? -0.2 : 0.2
                    let weld = capsule(
                        radius: 0.0035,
                        height: 0.092,
                        color: coolMetal,
                        position: SCNVector3(x + legX, 0.61, z + legZ),
                        rotation: SCNVector4(0, 0, 1, Float.pi / 2)
                    )
                    weld.name = "furnitureDeskLegWeldCatch_\(row)_\(column)_\(legIndex)"
                    weld.eulerAngles.y = Float(legIndex - 1) * 0.08
                    root.addChildNode(weld)

                    let footDust = box(width: 0.18, height: 0.003, length: 0.12, color: dust, position: SCNVector3(x + legX, 0.034, z + legZ))
                    footDust.name = "furnitureDeskFootDustHalo_\(row)_\(column)_\(legIndex)"
                    footDust.eulerAngles.y = -0.24 + Float((seed + legIndex) % 7) * 0.08
                    root.addChildNode(footDust)
                }

                for side in [-1.0, 1.0] {
                    let sideF = Float(side)
                    let chairLegCatch = capsule(
                        radius: 0.003,
                        height: 0.31,
                        color: coolMetal.withAlphaComponent(0.12),
                        position: SCNVector3(x + sideF * 0.22, 0.27, z + 0.72),
                        rotation: SCNVector4(1, 0, 0, sideF * 0.08)
                    )
                    chairLegCatch.name = side < 0 ? "furnitureLeftChairRearLegCatch_\(row)_\(column)" : "furnitureRightChairRearLegCatch_\(row)_\(column)"
                    root.addChildNode(chairLegCatch)

                    let skidMark = box(width: 0.42, height: 0.003, length: 0.024, color: skid, position: SCNVector3(x + sideF * 0.13, 0.031, z + 0.78 + Float(seed % 3) * 0.018))
                    skidMark.name = side < 0 ? "furnitureLeftChairSkidMark_\(row)_\(column)" : "furnitureRightChairSkidMark_\(row)_\(column)"
                    skidMark.eulerAngles.y = sideF * (0.12 + Float(seed % 4) * 0.035)
                    root.addChildNode(skidMark)
                }

                let undersideBounce = box(width: 0.74, height: 0.004, length: 0.026, color: warmEdge, position: SCNVector3(x, 0.654, z + 0.275))
                undersideBounce.name = "furnitureDeskUndersideBounce_\(row)_\(column)"
                undersideBounce.eulerAngles.y = Float(column - 1) * 0.025
                root.addChildNode(undersideBounce)

                let backCut = box(width: 0.52, height: 0.004, length: 0.018, color: warmEdge.withAlphaComponent(0.08), position: SCNVector3(x, 0.89, z + 0.75))
                backCut.name = "furnitureChairBackTopCatch_\(row)_\(column)"
                backCut.eulerAngles.y = -0.04 + Float(row % 3) * 0.03
                root.addChildNode(backCut)
            }
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowContact = box(width: 5.55, height: 0.003, length: 0.16, color: deepContact.withAlphaComponent(0.12), position: SCNVector3(-0.02, 0.038, z + 0.48))
            rowContact.name = "furnitureRowContactGradient\(row)"
            rowContact.eulerAngles.y = row % 2 == 0 ? -0.012 : 0.014
            root.addChildNode(rowContact)

            let rowGlint = box(width: 5.25, height: 0.003, length: 0.018, color: warmEdge.withAlphaComponent(0.075), position: SCNVector3(0.04, 0.833, z + 0.31))
            rowGlint.name = "furnitureRowEdgeSpecularGlint\(row)"
            rowGlint.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.018
            root.addChildNode(rowGlint)
        }

        for column in 0..<4 {
            let x = Float(column) * 1.2 - 2.4
            let aisleDust = box(width: 0.18, height: 0.003, length: 6.65, color: dust.withAlphaComponent(0.07), position: SCNVector3(x + 0.47, 0.029, 0.78))
            aisleDust.name = "furnitureAisleDustDepth\(column)"
            aisleDust.eulerAngles.y = column % 2 == 0 ? 0.008 : -0.01
            root.addChildNode(aisleDust)
        }

        return root
    }

    private func makeFurnitureMicroGeometryLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "furnitureMicroGeometryLayer"

        let varnishGlint = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.38, alpha: 0.09)
        let darkGroove = NSColor(calibratedRed: 0.08, green: 0.04, blue: 0.018, alpha: 0.2)
        let wornWood = NSColor(calibratedRed: 0.72, green: 0.48, blue: 0.24, alpha: 0.18)
        let coldMetal = NSColor(calibratedRed: 0.64, green: 0.78, blue: 0.92, alpha: 0.12)
        let rubber = NSColor(calibratedWhite: 0.02, alpha: 0.2)
        let seatPressure = NSColor(calibratedWhite: 0.0, alpha: 0.14)

        for row in 0..<5 {
            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let seed = row * 37 + column * 41

                let frontLamination = box(width: 0.84, height: 0.008, length: 0.018, color: wornWood, position: SCNVector3(x, 0.842, z + 0.315))
                frontLamination.name = "furnitureMicroDeskFrontLamination_\(row)_\(column)"
                frontLamination.eulerAngles.y = -0.018 + Float(seed % 5) * 0.009
                root.addChildNode(frontLamination)

                let frontShadowGroove = box(width: 0.8, height: 0.004, length: 0.01, color: darkGroove, position: SCNVector3(x + 0.01, 0.823, z + 0.326))
                frontShadowGroove.name = "furnitureMicroDeskFrontGroove_\(row)_\(column)"
                root.addChildNode(frontShadowGroove)

                let underCavity = box(width: 0.72, height: 0.006, length: 0.12, color: darkGroove.withAlphaComponent(0.18), position: SCNVector3(x, 0.646, z + 0.18))
                underCavity.name = "furnitureMicroDeskUnderCavityShadow_\(row)_\(column)"
                underCavity.eulerAngles.y = Float(column - 1) * 0.02
                root.addChildNode(underCavity)

                let stickerResidue = roundedBox(width: 0.16, height: 0.004, length: 0.09, chamfer: 0.01, color: varnishGlint.withAlphaComponent(0.09), position: SCNVector3(x - 0.18 + Float(seed % 5) * 0.018, 0.852, z - 0.12 + Float(seed % 3) * 0.05))
                stickerResidue.name = "furnitureMicroDeskStickerResidue_\(row)_\(column)"
                stickerResidue.eulerAngles.y = -0.22 + Float(seed % 7) * 0.06
                root.addChildNode(stickerResidue)

                let gumGhost = sphere(radius: 0.026, color: NSColor(calibratedWhite: 0.92, alpha: 0.08), position: SCNVector3(x + 0.25 - Float(seed % 4) * 0.03, 0.853, z + 0.08), scale: SCNVector3(1.6, 0.12, 0.8))
                gumGhost.name = "furnitureMicroDeskGumGhost_\(row)_\(column)"
                root.addChildNode(gumGhost)

                for dentIndex in 0..<3 {
                    let dent = box(
                        width: 0.07 + CGFloat((seed + dentIndex) % 3) * 0.018,
                        height: 0.003,
                        length: 0.006,
                        color: darkGroove.withAlphaComponent(0.13),
                        position: SCNVector3(x - 0.24 + Float(dentIndex) * 0.22, 0.854, z - 0.18 + Float((seed + dentIndex * 13) % 38) / 100)
                    )
                    dent.name = "furnitureMicroDeskPencilDent_\(row)_\(column)_\(dentIndex)"
                    dent.eulerAngles.y = -0.5 + Float((seed + dentIndex) % 9) * 0.1
                    root.addChildNode(dent)
                }

                for sideIndex in 0..<2 {
                    let side: Float = sideIndex == 0 ? -1 : 1
                    let sideName = sideIndex == 0 ? "Left" : "Right"
                    let cornerCap = roundedBox(width: 0.078, height: 0.016, length: 0.056, chamfer: 0.012, color: wornWood.withAlphaComponent(0.22), position: SCNVector3(x + side * 0.41, 0.843, z + 0.29))
                    cornerCap.name = "furnitureMicroDesk\(sideName)CornerCap_\(row)_\(column)"
                    cornerCap.eulerAngles.y = side * 0.12
                    root.addChildNode(cornerCap)

                    let edgeSplinter = capsule(radius: 0.0025, height: 0.18, color: wornWood.withAlphaComponent(0.2), position: SCNVector3(x + side * 0.404, 0.858, z - 0.08), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                    edgeSplinter.name = "furnitureMicroDesk\(sideName)EdgeSplinter_\(row)_\(column)"
                    edgeSplinter.eulerAngles.y = side * (0.18 + Float(seed % 4) * 0.035)
                    root.addChildNode(edgeSplinter)

                    let sideLayer = box(width: 0.024, height: 0.006, length: 0.47, color: darkGroove.withAlphaComponent(0.18), position: SCNVector3(x + side * 0.414, 0.818, z + 0.02))
                    sideLayer.name = "furnitureMicroDesk\(sideName)SideLaminateLine_\(row)_\(column)"
                    sideLayer.eulerAngles.y = side * 0.018
                    root.addChildNode(sideLayer)

                    let chairBackSideWear = box(width: 0.056, height: 0.18, length: 0.008, color: varnishGlint.withAlphaComponent(0.1), position: SCNVector3(x + side * 0.245, 0.915, z + 0.73))
                    chairBackSideWear.name = "furnitureMicroChair\(sideName)BackEdgeWear_\(row)_\(column)"
                    chairBackSideWear.eulerAngles.z = side * 0.025
                    root.addChildNode(chairBackSideWear)
                }

                for grainIndex in 0..<6 {
                    let grain = box(
                        width: 0.12 + CGFloat((seed + grainIndex) % 3) * 0.04,
                        height: 0.003,
                        length: 0.004,
                        color: grainIndex % 2 == 0 ? darkGroove.withAlphaComponent(0.12) : varnishGlint.withAlphaComponent(0.1),
                        position: SCNVector3(x - 0.32 + Float(grainIndex) * 0.128, 0.848, z - 0.24 + Float((seed + grainIndex * 11) % 42) / 100)
                    )
                    grain.name = "furnitureMicroDeskWoodGrain_\(row)_\(column)_\(grainIndex)"
                    grain.eulerAngles.y = -0.42 + Float((seed + grainIndex) % 9) * 0.09
                    root.addChildNode(grain)
                }

                let seatDepression = sphere(radius: 0.13, color: seatPressure, position: SCNVector3(x, 0.515, z + 0.5), scale: SCNVector3(1.9, 0.12, 0.9))
                seatDepression.name = "furnitureMicroChairSeatDepression_\(row)_\(column)"
                seatDepression.eulerAngles.y = Float(seed % 5) * 0.028 - 0.056
                root.addChildNode(seatDepression)

                let seatFrontCrack = box(width: 0.38, height: 0.004, length: 0.008, color: darkGroove.withAlphaComponent(0.16), position: SCNVector3(x - 0.02, 0.526, z + 0.27))
                seatFrontCrack.name = "furnitureMicroChairSeatFrontCrack_\(row)_\(column)"
                seatFrontCrack.eulerAngles.y = -0.08 + Float(seed % 5) * 0.035
                root.addChildNode(seatFrontCrack)

                for screwIndex in 0..<4 {
                    let sx: Float = screwIndex < 2 ? -0.23 : 0.23
                    let sz: Float = screwIndex % 2 == 0 ? 0.34 : 0.64
                    let screw = sphere(radius: 0.011, color: coldMetal, position: SCNVector3(x + sx, 0.532, z + sz), scale: SCNVector3(1.0, 0.22, 1.0))
                    screw.name = "furnitureMicroChairSeatScrew_\(row)_\(column)_\(screwIndex)"
                    screw.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.24)
                    root.addChildNode(screw)

                    let rustHalo = sphere(radius: 0.022, color: NSColor(calibratedRed: 0.42, green: 0.18, blue: 0.08, alpha: 0.12), position: SCNVector3(x + sx, 0.531, z + sz), scale: SCNVector3(1.4, 0.08, 1.0))
                    rustHalo.name = "furnitureMicroChairScrewRustHalo_\(row)_\(column)_\(screwIndex)"
                    root.addChildNode(rustHalo)
                }

                for legIndex in 0..<4 {
                    let lx: Float = legIndex < 2 ? -0.34 : 0.34
                    let lz: Float = legIndex % 2 == 0 ? -0.2 : 0.2
                    let weldRing = capsule(radius: 0.004, height: 0.09, color: coldMetal, position: SCNVector3(x + lx, 0.595, z + lz), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                    weldRing.name = "furnitureMicroDeskLegWeldRing_\(row)_\(column)_\(legIndex)"
                    weldRing.eulerAngles.y = Float(legIndex - 1) * 0.08
                    root.addChildNode(weldRing)

                    let rubberFoot = sphere(radius: 0.026, color: rubber, position: SCNVector3(x + lx, 0.052, z + lz), scale: SCNVector3(1.4, 0.2, 1.0))
                    rubberFoot.name = "furnitureMicroDeskRubberFoot_\(row)_\(column)_\(legIndex)"
                    root.addChildNode(rubberFoot)

                    let chromeKiss = box(width: 0.12, height: 0.003, length: 0.018, color: coldMetal.withAlphaComponent(0.1), position: SCNVector3(x + lx, 0.054, z + lz + 0.05))
                    chromeKiss.name = "furnitureMicroChairFootChromeKiss_\(row)_\(column)_\(legIndex)"
                    chromeKiss.eulerAngles.y = -0.2 + Float((seed + legIndex) % 6) * 0.08
                    root.addChildNode(chromeKiss)
                }
            }
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowEdge = box(width: 5.55, height: 0.004, length: 0.016, color: varnishGlint.withAlphaComponent(0.08), position: SCNVector3(0, 0.846, z + 0.315))
            rowEdge.name = "furnitureMicroRowUnifiedDeskEdge\(row)"
            rowEdge.eulerAngles.y = row % 2 == 0 ? 0.012 : -0.014
            root.addChildNode(rowEdge)

            let chairBackHands = box(width: 5.18, height: 0.006, length: 0.022, color: varnishGlint.withAlphaComponent(0.08), position: SCNVector3(0, 0.974, z + 0.735))
            chairBackHands.name = "furnitureMicroRowChairBackHandOil\(row)"
            chairBackHands.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.016
            root.addChildNode(chairBackHands)

            let scuffArc = box(width: 5.35, height: 0.003, length: 0.032, color: darkGroove.withAlphaComponent(0.1), position: SCNVector3(0.02, 0.036, z + 0.78))
            scuffArc.name = "furnitureMicroRowSharedScuffArc\(row)"
            scuffArc.eulerAngles.y = row % 2 == 0 ? -0.026 : 0.024
            root.addChildNode(scuffArc)
        }

        root.opacity = 0.18
        return root
    }

    private func makeStudentDeskStoryPropLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "studentDeskStoryPropLayer"

        let page = NSColor(calibratedRed: 0.9, green: 0.86, blue: 0.72, alpha: 0.32)
        let pageEdge = NSColor(calibratedRed: 0.72, green: 0.62, blue: 0.42, alpha: 0.22)
        let graphite = NSColor(calibratedWhite: 0.05, alpha: 0.34)
        let pencilWood = NSColor(calibratedRed: 0.88, green: 0.48, blue: 0.22, alpha: 0.55)
        let eraserPink = NSColor(calibratedRed: 0.95, green: 0.42, blue: 0.46, alpha: 0.46)
        let plasticBlue = NSColor(calibratedRed: 0.25, green: 0.48, blue: 0.82, alpha: 0.42)
        let plasticGreen = NSColor(calibratedRed: 0.26, green: 0.6, blue: 0.42, alpha: 0.36)
        let waterGlass = NSColor(calibratedRed: 0.55, green: 0.82, blue: 1.0, alpha: 0.24)
        let phoneBlack = NSColor(calibratedWhite: 0.015, alpha: 0.42)
        let phoneGlow = NSColor(calibratedRed: 0.36, green: 0.78, blue: 1.0, alpha: 0.16)
        let inkBlue = NSColor(calibratedRed: 0.1, green: 0.2, blue: 0.55, alpha: 0.18)
        let dust = NSColor(calibratedWhite: 0.94, alpha: 0.12)
        let contact = NSColor(calibratedWhite: 0.0, alpha: 0.12)
        let warning = NSColor(calibratedRed: 1.0, green: 0.22, blue: 0.12, alpha: 0.12)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowPaperLine = box(width: 5.15, height: 0.003, length: 0.01, color: pageEdge.withAlphaComponent(0.08), position: SCNVector3(0.02, 0.858, z + 0.165))
            rowPaperLine.name = "studentDeskStoryRowPaperLine\(row)"
            rowPaperLine.eulerAngles.y = row % 2 == 0 ? -0.01 : 0.012
            root.addChildNode(rowPaperLine)

            let rowDust = box(width: 5.25, height: 0.002, length: 0.13, color: dust.withAlphaComponent(0.055), position: SCNVector3(-0.02, 0.859, z - 0.05))
            rowDust.name = "studentDeskStoryRowStillnessDust\(row)"
            rowDust.eulerAngles.y = row % 2 == 0 ? 0.015 : -0.013
            root.addChildNode(rowDust)

            for column in 0..<4 {
                if row == 2 && column == 1 { continue }

                let x = Float(column) * 1.2 - 2.4
                let seed = row * 53 + column * 29
                let slant = -0.18 + Float(seed % 7) * 0.06
                let localX = -0.16 + Float(seed % 5) * 0.075
                let localZ = -0.17 + Float((seed / 3) % 6) * 0.055
                let accent = seed % 3 == 0 ? plasticBlue : (seed % 3 == 1 ? plasticGreen : eraserPink)

                let notebook = roundedBox(
                    width: 0.34 + CGFloat(seed % 3) * 0.035,
                    height: 0.01,
                    length: 0.24 + CGFloat(seed % 2) * 0.035,
                    chamfer: 0.012,
                    color: page.withAlphaComponent(0.28),
                    position: SCNVector3(x + localX, 0.858, z + localZ)
                )
                notebook.name = "studentDeskStoryNotebook_\(row)_\(column)"
                notebook.eulerAngles.y = slant
                root.addChildNode(notebook)

                let coverBand = box(width: 0.3, height: 0.003, length: 0.018, color: accent.withAlphaComponent(0.22), position: SCNVector3(x + localX, 0.866, z + localZ - 0.095))
                coverBand.name = "studentDeskStoryNotebookCoverBand_\(row)_\(column)"
                coverBand.eulerAngles.y = slant
                root.addChildNode(coverBand)

                for edgeIndex in 0..<3 {
                    let edge = box(width: 0.26 + CGFloat(edgeIndex) * 0.025, height: 0.0025, length: 0.004, color: pageEdge, position: SCNVector3(x + localX - 0.018 + Float(edgeIndex) * 0.02, 0.868 + Float(edgeIndex) * 0.001, z + localZ + 0.085 + Float(edgeIndex) * 0.012))
                    edge.name = "studentDeskStoryPageEdge_\(row)_\(column)_\(edgeIndex)"
                    edge.eulerAngles.y = slant + Float(edgeIndex - 1) * 0.035
                    root.addChildNode(edge)
                }

                let examCorner = roundedBox(width: 0.16, height: 0.004, length: 0.1, chamfer: 0.01, color: page.withAlphaComponent(0.22), position: SCNVector3(x + 0.18 - Float(seed % 4) * 0.04, 0.871, z + 0.09 + Float(seed % 3) * 0.045))
                examCorner.name = "studentDeskStoryExamCorner_\(row)_\(column)"
                examCorner.eulerAngles.y = -slant * 0.7
                examCorner.eulerAngles.x = 0.03 + Float(seed % 4) * 0.01
                root.addChildNode(examCorner)

                let foldedNote = roundedBox(width: 0.12, height: 0.005, length: 0.075, chamfer: 0.009, color: page.withAlphaComponent(seed % 2 == 0 ? 0.24 : 0.16), position: SCNVector3(x - 0.28 + Float(seed % 3) * 0.05, 0.872, z + 0.18 - Float(seed % 5) * 0.035))
                foldedNote.name = "studentDeskStoryFoldedNote_\(row)_\(column)"
                foldedNote.eulerAngles.y = 0.22 - Float(seed % 5) * 0.08
                root.addChildNode(foldedNote)

                let pencil = capsule(radius: 0.006, height: 0.32, color: pencilWood, position: SCNVector3(x + 0.15 - Float(seed % 3) * 0.07, 0.879, z - 0.11 + Float(seed % 4) * 0.05), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                pencil.name = "studentDeskStoryPencil_\(row)_\(column)"
                pencil.eulerAngles.y = 0.7 - Float(seed % 6) * 0.16
                root.addChildNode(pencil)

                let pencilTip = sphere(radius: 0.01, color: graphite, position: SCNVector3(x + 0.29 - Float(seed % 3) * 0.07, 0.879, z - 0.02 + Float(seed % 4) * 0.035), scale: SCNVector3(1.0, 0.35, 1.0))
                pencilTip.name = "studentDeskStoryPencilGraphite_\(row)_\(column)"
                root.addChildNode(pencilTip)

                let eraser = roundedBox(width: 0.07, height: 0.026, length: 0.042, chamfer: 0.007, color: eraserPink, position: SCNVector3(x - 0.05 + Float(seed % 4) * 0.045, 0.875, z + 0.23 - Float(seed % 3) * 0.04))
                eraser.name = "studentDeskStoryEraser_\(row)_\(column)"
                eraser.eulerAngles.y = -0.18 + Float(seed % 5) * 0.09
                root.addChildNode(eraser)

                let ruler = box(width: 0.32, height: 0.004, length: 0.026, color: NSColor(calibratedRed: 0.95, green: 0.82, blue: 0.32, alpha: 0.18), position: SCNVector3(x + 0.08, 0.873, z - 0.245 + Float(seed % 4) * 0.04))
                ruler.name = "studentDeskStoryRuler_\(row)_\(column)"
                ruler.eulerAngles.y = -0.38 + Float(seed % 6) * 0.12
                root.addChildNode(ruler)

                for markIndex in 0..<5 {
                    let mark = box(width: 0.004, height: 0.002, length: 0.018, color: graphite.withAlphaComponent(0.14), position: SCNVector3(x - 0.05 + Float(markIndex) * 0.035, 0.877, z - 0.25 + Float(seed % 4) * 0.04))
                    mark.name = "studentDeskStoryRulerMark_\(row)_\(column)_\(markIndex)"
                    mark.eulerAngles.y = ruler.eulerAngles.y
                    root.addChildNode(mark)
                }

                let bottle = capsule(radius: 0.035, height: 0.19, color: waterGlass, position: SCNVector3(x + 0.32 - Float(seed % 2) * 0.08, 0.94, z + 0.2 - Float(seed % 3) * 0.06))
                bottle.name = "studentDeskStoryWaterBottle_\(row)_\(column)"
                bottle.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.34)
                root.addChildNode(bottle)

                let bottleCap = capsule(radius: 0.022, height: 0.026, color: accent.withAlphaComponent(0.34), position: SCNVector3(bottle.position.x, 1.045, bottle.position.z))
                bottleCap.name = "studentDeskStoryWaterBottleCap_\(row)_\(column)"
                root.addChildNode(bottleCap)

                let phone = roundedBox(width: 0.15, height: 0.009, length: 0.25, chamfer: 0.018, color: phoneBlack, position: SCNVector3(x - 0.27 + Float(seed % 4) * 0.04, 0.867, z - 0.23 + Float(seed % 3) * 0.04))
                phone.name = "studentDeskStoryHiddenPhone_\(row)_\(column)"
                phone.eulerAngles.y = 0.28 - Float(seed % 6) * 0.09
                root.addChildNode(phone)

                let glow = box(width: 0.12, height: 0.003, length: 0.19, color: phoneGlow, position: SCNVector3(phone.position.x, 0.873, phone.position.z))
                glow.name = "studentDeskStoryPhoneGlow_\(row)_\(column)"
                glow.eulerAngles.y = phone.eulerAngles.y
                root.addChildNode(glow)

                for inkIndex in 0..<3 {
                    let line = box(width: 0.11 + CGFloat(inkIndex) * 0.035, height: 0.002, length: 0.004, color: inkBlue, position: SCNVector3(x + localX - 0.05, 0.874 + Float(inkIndex) * 0.001, z + localZ - 0.02 + Float(inkIndex) * 0.035))
                    line.name = "studentDeskStoryInkLine_\(row)_\(column)_\(inkIndex)"
                    line.eulerAngles.y = slant + Float(inkIndex) * 0.015
                    root.addChildNode(line)
                }

                for crumbIndex in 0..<4 {
                    let crumb = sphere(radius: 0.004 + CGFloat((crumbIndex + seed) % 3) * 0.0015, color: dust.withAlphaComponent(0.16), position: SCNVector3(x - 0.33 + Float((seed + crumbIndex * 7) % 66) / 100, 0.873, z - 0.25 + Float((seed + crumbIndex * 11) % 52) / 100), scale: SCNVector3(1.3, 0.28, 0.8))
                    crumb.name = "studentDeskStoryCrumb_\(row)_\(column)_\(crumbIndex)"
                    root.addChildNode(crumb)
                }

                let teacherShadowTag = box(width: 0.74, height: 0.003, length: 0.16, color: warning, position: SCNVector3(x, 0.878, z - 0.02))
                teacherShadowTag.name = "studentDeskStoryTeacherShadowTag_\(row)_\(column)"
                teacherShadowTag.eulerAngles.y = slant * 0.35
                root.addChildNode(teacherShadowTag)

                let contactPool = sphere(radius: 0.22, color: contact, position: SCNVector3(x + 0.04, 0.852, z + 0.02), scale: SCNVector3(1.8, 0.045, 0.8))
                contactPool.name = "studentDeskStoryPropContactPool_\(row)_\(column)"
                contactPool.eulerAngles.y = slant
                root.addChildNode(contactPool)
            }
        }

        root.opacity = 0.18
        return root
    }

    private func makeCeilingInfrastructure() -> SCNNode {
        let root = SCNNode()
        let conduit = NSColor(calibratedRed: 0.58, green: 0.6, blue: 0.58, alpha: 1)
        let shadow = NSColor(calibratedWhite: 0.04, alpha: 0.22)
        for x in [-3.2, -1.1, 1.1, 3.2] {
            root.addChildNode(capsule(radius: 0.012, height: 11.4, color: conduit, position: SCNVector3(Float(x), 3.465, 0), rotation: SCNVector4(1, 0, 0, Float.pi / 2)))
            root.addChildNode(box(width: 0.05, height: 0.006, length: 11.2, color: shadow, position: SCNVector3(Float(x) + 0.035, 3.438, 0)))
        }
        for z in [-4.6, -2.2, 0.2, 2.6, 4.7] {
            let junction = roundedBox(width: 0.28, height: 0.035, length: 0.18, chamfer: 0.018, color: NSColor(calibratedWhite: 0.74, alpha: 1), position: SCNVector3(3.25, 3.43, Float(z)))
            root.addChildNode(junction)
            root.addChildNode(box(width: 0.22, height: 0.006, length: 0.12, color: shadow, position: SCNVector3(3.27, 3.405, Float(z) + 0.03)))
        }
        return root
    }

    private func makeCeilingMoodShadowLayer() -> SCNNode {
        let root = SCNNode()
        for (index, z) in [-4.6, -2.6, -0.55, 1.65, 3.9].enumerated() {
            let band = box(width: 7.4 - CGFloat(index % 2) * 0.42, height: 0.006, length: 0.34 + CGFloat(index % 3) * 0.08, color: NSColor(calibratedWhite: 0.02, alpha: 0.16), position: SCNVector3(0, 3.486, Float(z)))
            band.name = "ceilingMoodBand\(index)"
            band.eulerAngles.y = Float(index - 2) * 0.018
            band.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.08, duration: 2.4 + Double(index) * 0.18),
                .fadeOpacity(to: 0.24, duration: 2.9 + Double(index) * 0.16)
            ])), forKey: "ceiling_mood_breathe")
            root.addChildNode(band)
        }

        for index in 0..<6 {
            let leak = box(width: 0.22 + CGFloat(index % 3) * 0.08, height: 0.005, length: 0.055, color: NSColor(calibratedRed: 0.34, green: 0.3, blue: 0.22, alpha: 0.12), position: SCNVector3(-2.8 + Float(index) * 1.1, 3.49, -4.8 + Float(index % 4) * 2.0))
            leak.name = "ceilingOldLeak\(index)"
            leak.eulerAngles.y = Float(index % 5) * 0.15
            root.addChildNode(leak)
        }
        return root
    }

    private func makeCeilingCinematicLayer() -> SCNNode {
        let root = SCNNode()
        let lampBloom = NSColor(calibratedRed: 1.0, green: 0.92, blue: 0.68, alpha: 0.08)
        let coolTube = NSColor(calibratedRed: 0.72, green: 0.86, blue: 1.0, alpha: 0.08)
        let contact = NSColor(calibratedWhite: 0.0, alpha: 0.12)
        let fanShadow = NSColor(calibratedWhite: 0.0, alpha: 0.1)
        let airShear = NSColor(calibratedRed: 0.82, green: 0.9, blue: 1.0, alpha: 0.045)

        for (index, z) in [-3.2, 0.0, 3.2].enumerated() {
            let bloom = box(width: 1.9, height: 0.006, length: 0.54, color: lampBloom, position: SCNVector3(0, 3.432, Float(z)))
            bloom.name = "ceilingLampBloomHalo\(index)"
            bloom.eulerAngles.y = index % 2 == 0 ? 0.018 : -0.018
            root.addChildNode(bloom)

            for side in [-1.0, 1.0] {
                let glare = box(width: 1.42, height: 0.004, length: 0.018, color: coolTube, position: SCNVector3(0, 3.414, Float(z) + Float(side) * 0.17))
                glare.name = "ceilingTubeGlare\(index)_\(side < 0 ? 0 : 1)"
                glare.eulerAngles.y = Float(side) * 0.012
                root.addChildNode(glare)
            }
        }

        for (index, x) in [-3.86, 3.86].enumerated() {
            let strip = box(width: 0.05, height: 0.006, length: 11.6, color: contact, position: SCNVector3(Float(x), 3.428, 0))
            strip.name = "ceilingSideContactShadow\(index)"
            root.addChildNode(strip)
        }
        for (index, z) in [-5.86, 5.86].enumerated() {
            let strip = box(width: 7.7, height: 0.006, length: 0.052, color: contact, position: SCNVector3(0, 3.427, Float(z)))
            strip.name = "ceilingFrontRearContactShadow\(index)"
            root.addChildNode(strip)
        }

        for (fanIndex, z) in [-1.8, 2.1].enumerated() {
            let sweepRoot = SCNNode()
            sweepRoot.name = "fanSweepShadowRoot\(fanIndex)"
            sweepRoot.position = SCNVector3(0, 0.062, Float(z))
            for bladeIndex in 0..<3 {
                let blade = box(width: 1.85, height: 0.004, length: 0.055, color: fanShadow, position: SCNVector3(0.55, 0, 0))
                blade.name = "fanSweepBlade\(fanIndex)_\(bladeIndex)"
                let bladeRoot = SCNNode()
                bladeRoot.eulerAngles.y = CGFloat(bladeIndex) * CGFloat.pi * 2 / 3
                bladeRoot.addChildNode(blade)
                sweepRoot.addChildNode(bladeRoot)
            }
            root.addChildNode(sweepRoot)

            let shear = box(width: 2.45, height: 0.58, length: 0.018, color: airShear, position: SCNVector3(0, 2.82, Float(z)))
            shear.name = "fanAirShearVeil\(fanIndex)"
            shear.eulerAngles.y = fanIndex == 0 ? 0.05 : -0.05
            root.addChildNode(shear)
        }
        return root
    }

    private func makeCeilingFixtureDetailLayer() -> SCNNode {
        let root = SCNNode()
        let metal = NSColor(calibratedRed: 0.56, green: 0.57, blue: 0.54, alpha: 0.86)
        let dark = NSColor(calibratedWhite: 0.02, alpha: 0.22)
        let tubeCore = NSColor(calibratedRed: 0.92, green: 0.96, blue: 1.0, alpha: 0.32)
        let warmFlicker = NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.46, alpha: 0.12)
        let dust = NSColor(calibratedRed: 0.72, green: 0.68, blue: 0.58, alpha: 0.14)

        for (fixtureIndex, z) in [-3.2, 0.0, 3.2].enumerated() {
            let zf = Float(z)
            let backPlate = roundedBox(width: 1.58, height: 0.018, length: 0.34, chamfer: 0.018, color: metal, position: SCNVector3(0, 3.444, zf))
            backPlate.name = "ceilingFixtureBackPlate\(fixtureIndex)"
            root.addChildNode(backPlate)

            for sideIndex in 0..<2 {
                let side: Float = sideIndex == 0 ? -1 : 1
                let tube = capsule(radius: 0.018, height: 1.28, color: tubeCore, position: SCNVector3(0, 3.418, zf + side * 0.105), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                tube.name = "ceilingFixtureTubeCore\(fixtureIndex)_\(sideIndex)"
                tube.geometry?.firstMaterial?.emission.contents = tubeCore
                root.addChildNode(tube)

                let flickerGhost = box(width: 1.36, height: 0.004, length: 0.026, color: warmFlicker, position: SCNVector3(0, 3.404, zf + side * 0.105))
                flickerGhost.name = "ceilingFixtureFlickerGhost\(fixtureIndex)_\(sideIndex)"
                root.addChildNode(flickerGhost)

                for end in [-1.0, 1.0] {
                    let cap = roundedBox(width: 0.06, height: 0.03, length: 0.066, chamfer: 0.012, color: metal.blended(withFraction: 0.24, of: .black) ?? metal, position: SCNVector3(Float(end) * 0.69, 3.416, zf + side * 0.105))
                    cap.name = "ceilingFixtureEndCap\(fixtureIndex)_\(sideIndex)_\(end < 0 ? 0 : 1)"
                    root.addChildNode(cap)
                }
            }

            for screwIndex in 0..<4 {
                let sx: Float = screwIndex < 2 ? -0.64 : 0.64
                let sz: Float = screwIndex % 2 == 0 ? -0.14 : 0.14
                let screw = sphere(radius: 0.011, color: dark.withAlphaComponent(0.48), position: SCNVector3(sx, 3.43, zf + sz), scale: SCNVector3(1, 0.24, 1))
                screw.name = "ceilingFixtureScrewHead\(fixtureIndex)_\(screwIndex)"
                root.addChildNode(screw)
            }

            let ballastShadow = box(width: 1.62, height: 0.005, length: 0.38, color: dark, position: SCNVector3(0.04, 3.392, zf + 0.018))
            ballastShadow.name = "ceilingFixtureBallastShadow\(fixtureIndex)"
            root.addChildNode(ballastShadow)

            for dustIndex in 0..<5 {
                let dx = -0.62 + Float(dustIndex) * 0.31
                let dustLine = box(width: 0.16 + CGFloat(dustIndex % 2) * 0.05, height: 0.004, length: 0.012, color: dust, position: SCNVector3(dx, 3.433, zf - 0.18 + Float(dustIndex % 3) * 0.09))
                dustLine.name = "ceilingFixtureDustLip\(fixtureIndex)_\(dustIndex)"
                dustLine.eulerAngles.y = -0.12 + Float(dustIndex) * 0.05
                root.addChildNode(dustLine)
            }
        }

        for conduitIndex in 0..<4 {
            let x = [-3.2, -1.1, 1.1, 3.2][conduitIndex]
            let cableShadow = box(width: 0.09, height: 0.004, length: 11.35, color: dark.withAlphaComponent(0.16), position: SCNVector3(Float(x) + 0.055, 3.414, 0))
            cableShadow.name = "ceilingFixtureConduitCastShadow\(conduitIndex)"
            root.addChildNode(cableShadow)
        }
        return root
    }

    private func makeCeilingLightRigCinematicLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "ceilingLightRigCinematicLayer"

        let diffuser = NSColor(calibratedRed: 0.96, green: 0.98, blue: 1.0, alpha: 0.12)
        let tubeHot = NSColor(calibratedRed: 1.0, green: 0.95, blue: 0.78, alpha: 0.18)
        let metalEdge = NSColor(calibratedRed: 0.62, green: 0.63, blue: 0.58, alpha: 0.22)
        let oilShadow = NSColor(calibratedWhite: 0.02, alpha: 0.18)
        let dust = NSColor(calibratedRed: 0.58, green: 0.54, blue: 0.44, alpha: 0.16)
        let insect = NSColor(calibratedWhite: 0.02, alpha: 0.2)
        let warmFlicker = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.34, alpha: 0.12)
        let coolGrid = NSColor(calibratedRed: 0.52, green: 0.72, blue: 1.0, alpha: 0.07)

        for (fixtureIndex, z) in [-3.2, 0.0, 3.2].enumerated() {
            let zf = Float(z)
            let diffuserGlow = roundedBox(width: 1.74, height: 0.018, length: 0.42, chamfer: 0.04, color: diffuser, position: SCNVector3(0, 3.392, zf))
            diffuserGlow.name = "ceilingLightRigDiffuserGlow\(fixtureIndex)"
            diffuserGlow.geometry?.firstMaterial?.emission.contents = diffuser
            root.addChildNode(diffuserGlow)

            let frameTop = box(width: 1.82, height: 0.008, length: 0.026, color: metalEdge, position: SCNVector3(0, 3.414, zf - 0.24))
            frameTop.name = "ceilingLightRigFrameLipFront\(fixtureIndex)"
            root.addChildNode(frameTop)

            let frameBottom = box(width: 1.82, height: 0.008, length: 0.026, color: metalEdge, position: SCNVector3(0, 3.414, zf + 0.24))
            frameBottom.name = "ceilingLightRigFrameLipRear\(fixtureIndex)"
            root.addChildNode(frameBottom)

            for sideIndex in 0..<2 {
                let side: Float = sideIndex == 0 ? -1 : 1
                let tube = capsule(radius: 0.012, height: 1.46, color: tubeHot, position: SCNVector3(0, 3.386, zf + side * 0.12), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                tube.name = "ceilingLightRigTubeHotCore\(fixtureIndex)_\(sideIndex)"
                tube.geometry?.firstMaterial?.emission.contents = tubeHot
                root.addChildNode(tube)

                let afterimage = box(width: 1.62, height: 0.004, length: 0.05, color: warmFlicker, position: SCNVector3(0, 3.376, zf + side * 0.12))
                afterimage.name = "ceilingLightRigFlickerAfterimage\(fixtureIndex)_\(sideIndex)"
                root.addChildNode(afterimage)
            }

            let ballast = roundedBox(width: 0.5, height: 0.016, length: 0.16, chamfer: 0.018, color: oilShadow, position: SCNVector3(0.38, 3.37, zf + 0.025))
            ballast.name = "ceilingLightRigBallastOilShadow\(fixtureIndex)"
            root.addChildNode(ballast)

            let gridShadow = box(width: 1.96, height: 0.004, length: 0.62, color: coolGrid, position: SCNVector3(0, 3.366, zf))
            gridShadow.name = "ceilingLightRigGridShadow\(fixtureIndex)"
            gridShadow.eulerAngles.y = fixtureIndex % 2 == 0 ? 0.012 : -0.012
            root.addChildNode(gridShadow)

            for dustIndex in 0..<7 {
                let x = -0.76 + Float(dustIndex) * 0.255
                let zOffset = -0.225 + Float((dustIndex * 2) % 5) * 0.105
                let dustLine = box(width: 0.12 + CGFloat(dustIndex % 3) * 0.035, height: 0.004, length: 0.01, color: dust, position: SCNVector3(x, 3.407, zf + zOffset))
                dustLine.name = "ceilingLightRigDustEdge\(fixtureIndex)_\(dustIndex)"
                dustLine.eulerAngles.y = -0.18 + Float(dustIndex) * 0.055
                root.addChildNode(dustLine)
            }

            for speckIndex in 0..<8 {
                let seed = fixtureIndex * 31 + speckIndex * 17
                let speck = sphere(
                    radius: 0.006 + CGFloat(speckIndex % 3) * 0.0015,
                    color: insect,
                    position: SCNVector3(-0.68 + Float(seed % 136) / 100, 3.382, zf - 0.2 + Float((seed * 3) % 40) / 100),
                    scale: SCNVector3(1.3, 0.2, 0.8)
                )
                speck.name = "ceilingLightRigDeadInsectSpeck\(fixtureIndex)_\(speckIndex)"
                root.addChildNode(speck)
            }
        }

        for index in 0..<4 {
            let x = [-2.9, -0.95, 0.95, 2.9][index]
            let sag = capsule(radius: 0.005, height: 10.6, color: NSColor(calibratedWhite: 0.03, alpha: 0.2), position: SCNVector3(Float(x), 3.388 - Float(index % 2) * 0.012, 0), rotation: SCNVector4(1, 0, 0, Float.pi / 2))
            sag.name = "ceilingLightRigWireSag\(index)"
            root.addChildNode(sag)
        }

        for index in 0..<5 {
            let pressure = box(width: 6.8 - CGFloat(index % 2) * 0.28, height: 0.004, length: 0.11 + CGFloat(index % 3) * 0.03, color: NSColor(calibratedWhite: 0.0, alpha: 0.08), position: SCNVector3(0, 3.374, -4.6 + Float(index) * 2.25))
            pressure.name = "ceilingLightRigRoomPressureBand\(index)"
            pressure.eulerAngles.y = -0.018 + Float(index) * 0.008
            root.addChildNode(pressure)
        }

        let teacherPulse = box(width: 2.2, height: 0.005, length: 0.38, color: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.46, alpha: 0.1), position: SCNVector3(0, 3.36, -3.8))
        teacherPulse.name = "ceilingLightRigTeacherStepCeilingPulse"
        root.addChildNode(teacherPulse)

        return root
    }

    private func makeAirDustLayer() -> SCNNode {
        let root = SCNNode()
        let colors = [
            NSColor(calibratedWhite: 0.96, alpha: 0.28),
            NSColor(calibratedRed: 0.72, green: 0.82, blue: 1.0, alpha: 0.18),
            NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.56, alpha: 0.16)
        ]
        for index in 0..<42 {
            let x = -3.35 + Float((index * 47) % 670) / 100
            let y = 1.05 + Float((index * 31) % 165) / 100
            let z = -5.1 + Float((index * 59) % 1020) / 100
            let mote = sphere(radius: 0.008 + CGFloat(index % 3) * 0.002, color: colors[index % colors.count], position: SCNVector3(x, y, z), scale: SCNVector3(1, 0.75, 1))
            mote.geometry?.firstMaterial?.emission.contents = colors[index % colors.count]
            let drift = SCNAction.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.018, y: 0.035 + CGFloat(index % 4) * 0.01, z: CGFloat((index % 7) - 3) * 0.012, duration: 2.6 + Double(index % 5) * 0.42),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.018, y: -0.035 - CGFloat(index % 4) * 0.01, z: -CGFloat((index % 7) - 3) * 0.012, duration: 2.9 + Double(index % 4) * 0.38)
            ])
            mote.runAction(.repeatForever(drift), forKey: "dust_drift")
            root.addChildNode(mote)
        }
        return root
    }

    private func makeAtmosphericMediumLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "atmosphericMediumLayer"
        let coolHumidity = NSColor(calibratedRed: 0.56, green: 0.72, blue: 1.0, alpha: 0.055)
        let warmBreath = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.52, alpha: 0.045)
        let chalkHaze = NSColor(calibratedRed: 0.82, green: 0.95, blue: 0.76, alpha: 0.05)
        let projectorDust = NSColor(calibratedRed: 0.68, green: 0.86, blue: 1.0, alpha: 0.06)
        let softShadow = NSColor(calibratedWhite: 0.0, alpha: 0.045)

        for row in 0..<5 {
            let z = -4.7 + Float(row) * 2.15
            let strata = box(width: 7.2, height: 0.42 + CGFloat(row % 2) * 0.08, length: 0.018, color: row % 2 == 0 ? coolHumidity : warmBreath, position: SCNVector3(0, 1.34 + Float(row % 3) * 0.18, z))
            strata.name = "atmosphericRowStrata\(row)"
            strata.eulerAngles.y = -0.06 + Float(row) * 0.025
            root.addChildNode(strata)
        }

        for index in 0..<4 {
            let windowMist = box(width: 0.018, height: 1.42, length: 1.36, color: coolHumidity.withAlphaComponent(0.07), position: SCNVector3(-3.76, 1.78, -3.0 + Float(index) * 2.0))
            windowMist.name = "atmosphericWindowHumidityVeil\(index)"
            windowMist.eulerAngles.z = -0.025 + Float(index) * 0.012
            root.addChildNode(windowMist)
        }

        for index in 0..<5 {
            let boardHaze = box(width: 0.72 + CGFloat(index % 2) * 0.18, height: 0.24, length: 0.012, color: chalkHaze, position: SCNVector3(-1.6 + Float(index) * 0.78, 1.62 + Float(index % 2) * 0.18, -5.72))
            boardHaze.name = "atmosphericBlackboardChalkHaze\(index)"
            boardHaze.eulerAngles.z = -0.04 + Float(index) * 0.018
            root.addChildNode(boardHaze)
        }

        for index in 0..<18 {
            let x = -0.62 + Float((index * 37) % 128) / 100
            let y = 1.18 + Float((index * 23) % 116) / 100
            let z = -4.18 + Float((index * 29) % 86) / 100
            let speck = sphere(radius: 0.006 + CGFloat(index % 3) * 0.0015, color: projectorDust, position: SCNVector3(x, y, z), scale: SCNVector3(1.3, 0.62, 1.0))
            speck.name = "atmosphericProjectorDust\(index)"
            speck.geometry?.firstMaterial?.emission.contents = projectorDust
            speck.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.01, y: 0.026 + CGFloat(index % 3) * 0.006, z: CGFloat((index % 4) - 1) * 0.008, duration: 1.6 + Double(index % 5) * 0.16),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.01, y: -0.026 - CGFloat(index % 3) * 0.006, z: -CGFloat((index % 4) - 1) * 0.008, duration: 1.9 + Double(index % 4) * 0.18)
            ])), forKey: "projector_dust_swim")
            root.addChildNode(speck)
        }

        for row in 0..<5 {
            let breath = box(width: 5.8, height: 0.2, length: 0.012, color: warmBreath, position: SCNVector3(0, 1.02, -2.15 + Float(row) * 1.45))
            breath.name = "atmosphericClassBreathWarmth\(row)"
            breath.eulerAngles.y = row % 2 == 0 ? 0.02 : -0.025
            root.addChildNode(breath)
        }

        for index in 0..<6 {
            let shadowLift = box(width: 6.6, height: 0.12, length: 0.012, color: softShadow, position: SCNVector3(0, 0.72 + Float(index % 3) * 0.34, -4.85 + Float(index) * 1.85))
            shadowLift.name = "atmosphericShadowStratification\(index)"
            shadowLift.eulerAngles.y = -0.035 + Float(index) * 0.014
            root.addChildNode(shadowLift)
        }

        root.opacity = 0.16
        return root
    }

    private func makeClassroomSpatialHierarchyLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomSpatialHierarchyLayer"

        let coolAir = NSColor(calibratedRed: 0.46, green: 0.66, blue: 1.0, alpha: 0.055)
        let warmAir = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: 0.045)
        let shadowInk = NSColor(calibratedWhite: 0.0, alpha: 0.11)
        let chalkDepth = NSColor(calibratedRed: 0.74, green: 0.92, blue: 0.78, alpha: 0.06)
        let rainCool = NSColor(calibratedRed: 0.62, green: 0.8, blue: 1.0, alpha: 0.07)

        for row in 0..<5 {
            let z = -2.0 + Float(row) * 1.45
            let rowSlice = box(width: 6.85 - CGFloat(row % 2) * 0.22, height: 0.36, length: 0.018, color: row % 2 == 0 ? coolAir : warmAir, position: SCNVector3(0, 1.08 + Float(row % 3) * 0.16, z + 0.42))
            rowSlice.name = "spatialHierarchyRowAirSlice\(row)"
            rowSlice.eulerAngles.y = -0.045 + Float(row) * 0.018
            root.addChildNode(rowSlice)

            let deskOcclusion = box(width: 6.6, height: 0.005, length: 0.24, color: shadowInk.withAlphaComponent(0.14), position: SCNVector3(0, 0.872, z + 0.12))
            deskOcclusion.name = "spatialHierarchyDeskRowOcclusion\(row)"
            deskOcclusion.eulerAngles.y = Float(row % 3 - 1) * 0.02
            root.addChildNode(deskOcclusion)

            let shoulderBand = box(width: 5.8, height: 0.2, length: 0.012, color: shadowInk.withAlphaComponent(0.08), position: SCNVector3(0, 1.04, z + 0.52))
            shoulderBand.name = "spatialHierarchyStudentShoulderNegative\(row)"
            shoulderBand.eulerAngles.y = Float(row % 2 == 0 ? 0.018 : -0.018)
            root.addChildNode(shoulderBand)

            let floorPool = box(width: 6.3, height: 0.004, length: 0.42, color: shadowInk.withAlphaComponent(0.1), position: SCNVector3(0, 0.056, z + 0.46))
            floorPool.name = "spatialHierarchyFloorDepthPool\(row)"
            floorPool.eulerAngles.y = Float(row % 5 - 2) * 0.014
            root.addChildNode(floorPool)
        }

        for index in 0..<4 {
            let z = -3.35 + Float(index) * 1.82
            let windowRib = box(width: 0.024, height: 1.72, length: 1.2, color: rainCool, position: SCNVector3(-3.58, 1.68, z))
            windowRib.name = "spatialHierarchyWindowVolumeRib\(index)"
            windowRib.eulerAngles.z = -0.022 + Float(index) * 0.01
            root.addChildNode(windowRib)

            let windowFloor = box(width: 2.4 + CGFloat(index % 2) * 0.34, height: 0.004, length: 0.2, color: rainCool.withAlphaComponent(0.08), position: SCNVector3(-2.2 + Float(index % 2) * 0.22, 0.072, z + 0.3))
            windowFloor.name = "spatialHierarchyWindowFloorReturn\(index)"
            windowFloor.eulerAngles.y = -0.18 + Float(index) * 0.045
            root.addChildNode(windowFloor)
        }

        for index in 0..<5 {
            let boardFog = box(width: 1.0 + CGFloat(index % 2) * 0.22, height: 0.26, length: 0.012, color: chalkDepth, position: SCNVector3(-1.8 + Float(index) * 0.9, 1.55 + Float(index % 2) * 0.16, -5.66))
            boardFog.name = "spatialHierarchyBlackboardDepthFog\(index)"
            boardFog.eulerAngles.z = -0.03 + Float(index) * 0.015
            root.addChildNode(boardFog)
        }

        for index in 0..<6 {
            let aisleGate = box(width: 0.16 + CGFloat(index % 3) * 0.04, height: 1.1, length: 0.012, color: shadowInk.withAlphaComponent(0.09), position: SCNVector3(-2.85 + Float(index) * 1.14, 1.06, -4.75 + Float(index % 3) * 2.0))
            aisleGate.name = "spatialHierarchyVerticalAisleGate\(index)"
            aisleGate.eulerAngles.z = Float(index % 2 == 0 ? 0.012 : -0.012)
            root.addChildNode(aisleGate)
        }

        let foregroundMatte = box(width: 4.8, height: 0.42, length: 0.02, color: shadowInk.withAlphaComponent(0.12), position: SCNVector3(-0.6, 0.86, 1.82))
        foregroundMatte.name = "spatialHierarchyPlayerForegroundMatte"
        foregroundMatte.eulerAngles.y = -0.018
        root.addChildNode(foregroundMatte)

        let teacherBodyCut = box(width: 0.76, height: 1.45, length: 0.018, color: shadowInk.withAlphaComponent(0.16), position: SCNVector3(0, 1.14, -3.9))
        teacherBodyCut.name = "spatialHierarchyTeacherBodyOcclusion"
        root.addChildNode(teacherBodyCut)

        let teacherFloorDrag = box(width: 1.25, height: 0.005, length: 0.6, color: shadowInk.withAlphaComponent(0.15), position: SCNVector3(0, 0.064, -3.58))
        teacherFloorDrag.name = "spatialHierarchyTeacherFloorDrag"
        teacherFloorDrag.eulerAngles.y = -0.06
        root.addChildNode(teacherFloorDrag)

        let boardToDeskBridge = box(width: 5.9, height: 0.2, length: 0.014, color: chalkDepth.withAlphaComponent(0.075), position: SCNVector3(0, 1.22, -3.9))
        boardToDeskBridge.name = "spatialHierarchyBoardDeskDepthBridge"
        boardToDeskBridge.eulerAngles.y = 0.025
        root.addChildNode(boardToDeskBridge)

        let rearCompression = box(width: 6.8, height: 1.35, length: 0.012, color: shadowInk.withAlphaComponent(0.08), position: SCNVector3(0, 1.38, 5.45))
        rearCompression.name = "spatialHierarchyRearWallCompression"
        root.addChildNode(rearCompression)

        for index in 0..<12 {
            let mote = sphere(
                radius: 0.005 + CGFloat(index % 3) * 0.0012,
                color: index % 2 == 0 ? coolAir.withAlphaComponent(0.14) : warmAir.withAlphaComponent(0.12),
                position: SCNVector3(-2.9 + Float((index * 43) % 580) / 100, 0.9 + Float((index * 29) % 125) / 100, -4.5 + Float((index * 53) % 940) / 100),
                scale: SCNVector3(1.4, 0.48, 1.0)
            )
            mote.name = "spatialHierarchyDepthMote\(index)"
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.01, y: 0.024 + CGFloat(index % 3) * 0.005, z: CGFloat((index % 7) - 3) * 0.009, duration: 1.7 + Double(index % 4) * 0.18),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.01, y: -0.024 - CGFloat(index % 3) * 0.005, z: -CGFloat((index % 7) - 3) * 0.009, duration: 2.0 + Double(index % 5) * 0.16)
            ])), forKey: "spatial_hierarchy_depth_mote")
            root.addChildNode(mote)
        }

        root.opacity = 0.12
        return root
    }

    private func makeNearFieldAtmosphereLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "nearFieldAtmosphereLayer"
        let warmLensDust = NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.52, alpha: 0.12)
        let coolLensDust = NSColor(calibratedRed: 0.62, green: 0.78, blue: 1.0, alpha: 0.1)
        let deskAir = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.38, alpha: 0.045)
        let coolRowFog = NSColor(calibratedRed: 0.48, green: 0.64, blue: 0.9, alpha: 0.05)
        let rainMist = NSColor(calibratedRed: 0.68, green: 0.82, blue: 1.0, alpha: 0.07)
        let halation = NSColor(calibratedRed: 1.0, green: 0.88, blue: 0.58, alpha: 0.08)

        for index in 0..<28 {
            let x = -2.9 + Float((index * 41) % 590) / 100
            let y = 0.72 + Float((index * 29) % 132) / 100
            let z = -1.15 + Float((index * 53) % 560) / 100
            let color = index % 2 == 0 ? warmLensDust : coolLensDust
            let mote = sphere(
                radius: 0.0045 + CGFloat(index % 4) * 0.0014,
                color: color,
                position: SCNVector3(x, y, z),
                scale: SCNVector3(1.4 + CGFloat(index % 3) * 0.28, 0.6, 1.0)
            )
            mote.name = "nearFieldAirMote\(index)"
            mote.geometry?.firstMaterial?.emission.contents = color
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.014, y: 0.018 + CGFloat(index % 3) * 0.006, z: CGFloat((index % 7) - 3) * 0.01, duration: 1.8 + Double(index % 5) * 0.2),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.014, y: -0.018 - CGFloat(index % 3) * 0.006, z: -CGFloat((index % 7) - 3) * 0.01, duration: 2.1 + Double(index % 4) * 0.22)
            ])), forKey: "near_field_air_mote")
            root.addChildNode(mote)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.18
            let rowFog = box(width: 5.9, height: 0.34, length: 0.014, color: coolRowFog, position: SCNVector3(0, 1.12 + Float(row % 2) * 0.1, z + 0.42))
            rowFog.name = "nearFieldRowFogVeil\(row)"
            rowFog.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.02
            root.addChildNode(rowFog)

            let deskShimmer = box(width: 5.45, height: 0.16, length: 0.012, color: deskAir, position: SCNVector3(0.02, 0.88, z + 0.16))
            deskShimmer.name = "nearFieldDeskHeatShimmer\(row)"
            deskShimmer.eulerAngles.y = row % 2 == 0 ? -0.014 : 0.018
            root.addChildNode(deskShimmer)
        }

        for column in 0..<4 {
            let x = Float(column) * 1.2 - 1.93
            let aisleFog = box(width: 0.24, height: 0.42, length: 6.5, color: coolRowFog.withAlphaComponent(0.045), position: SCNVector3(x, 0.98, 0.72))
            aisleFog.name = "nearFieldAisleAtmosphere\(column)"
            aisleFog.eulerAngles.y = column % 2 == 0 ? 0.01 : -0.012
            root.addChildNode(aisleFog)
        }

        let rainBreath = box(width: 6.8, height: 1.12, length: 0.016, color: rainMist, position: SCNVector3(0.18, 1.34, 1.28))
        rainBreath.name = "nearFieldRainInteriorBreath"
        rainBreath.eulerAngles.y = -0.03
        root.addChildNode(rainBreath)

        for index in 0..<7 {
            let lampHalo = sphere(
                radius: 0.05 + CGFloat(index % 3) * 0.012,
                color: halation,
                position: SCNVector3(-2.7 + Float(index) * 0.9, 2.12 + Float(index % 2) * 0.16, -0.68 + Float(index % 3) * 1.1),
                scale: SCNVector3(2.4, 0.32, 0.42)
            )
            lampHalo.name = "nearFieldLowLightHalation\(index)"
            lampHalo.geometry?.firstMaterial?.emission.contents = halation
            root.addChildNode(lampHalo)
        }

        let foregroundBloom = box(width: 4.2, height: 0.28, length: 0.012, color: warmLensDust.withAlphaComponent(0.08), position: SCNVector3(-0.18, 0.92, 1.64))
        foregroundBloom.name = "nearFieldForegroundDeskBloom"
        foregroundBloom.eulerAngles.y = 0.025
        root.addChildNode(foregroundBloom)

        return root
    }

    private func makeVolumetricLightVolumeLayer() -> SCNNode {
        let root = SCNNode()
        let windowBeam = NSColor(calibratedRed: 0.58, green: 0.76, blue: 1.0, alpha: 0.08)
        let chalkHaze = NSColor(calibratedRed: 0.86, green: 0.96, blue: 0.78, alpha: 0.055)
        let ceilingGlow = NSColor(calibratedRed: 1.0, green: 0.84, blue: 0.52, alpha: 0.045)

        for (index, z) in [-2.45, -1.04, 0.42, 1.86, 3.28].enumerated() {
            let beam = box(
                width: 0.16,
                height: 1.82 - CGFloat(index % 2) * 0.24,
                length: 1.18,
                color: windowBeam,
                position: SCNVector3(2.48 - Float(index % 2) * 0.18, 1.62, Float(z))
            )
            beam.name = "windowVolumetricBeam\(index)"
            beam.eulerAngles = SCNVector3(-0.05, -0.38 + Float(index) * 0.025, -0.09)
            beam.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.22, duration: 2.2 + Double(index % 3) * 0.35),
                .fadeOpacity(to: 0.48, duration: 3.0 + Double(index % 4) * 0.28)
            ])), forKey: "window_volume_breathe")
            root.addChildNode(beam)
        }

        for (index, x) in [-1.8, -0.82, 0.12, 1.05, 1.9].enumerated() {
            let haze = box(
                width: 0.52 + CGFloat(index % 2) * 0.12,
                height: 0.92,
                length: 0.018,
                color: chalkHaze,
                position: SCNVector3(Float(x), 1.78 + Float(index % 2) * 0.14, -5.86)
            )
            haze.name = "blackboardChalkVolume\(index)"
            haze.eulerAngles.z = CGFloat(index - 2) * 0.025
            root.addChildNode(haze)
        }

        for row in 0..<3 {
            let z = -3.2 + Float(row) * 3.2
            let glow = box(
                width: 2.1,
                height: 0.42,
                length: 0.8,
                color: ceilingGlow,
                position: SCNVector3(0, 2.78, z)
            )
            glow.name = "ceilingLampAirGlow\(row)"
            glow.eulerAngles.y = row % 2 == 0 ? 0.04 : -0.04
            glow.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.18, duration: 1.6 + Double(row) * 0.22),
                .fadeOpacity(to: 0.36, duration: 2.1 + Double(row) * 0.18)
            ])), forKey: "ceiling_air_glow")
            root.addChildNode(glow)
        }
        return root
    }

    private func makeClassroomOccludedLightShaftLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomOccludedLightShaftLayer"

        let windowSlice = NSColor(calibratedRed: 0.55, green: 0.74, blue: 1.0, alpha: 0.07)
        let warmDust = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: 0.055)
        let shadowCut = NSColor(calibratedWhite: 0.0, alpha: 0.075)
        let rainBlue = NSColor(calibratedRed: 0.26, green: 0.44, blue: 0.82, alpha: 0.055)
        let chalkSilver = NSColor(calibratedRed: 0.78, green: 0.9, blue: 1.0, alpha: 0.055)

        for index in 0..<5 {
            let z = -2.65 + Float(index) * 1.42
            let shaft = box(
                width: 0.1 + CGFloat(index % 2) * 0.035,
                height: 1.78 - CGFloat(index % 3) * 0.14,
                length: 1.14,
                color: windowSlice,
                position: SCNVector3(2.34 - Float(index % 2) * 0.12, 1.54 + Float(index % 2) * 0.08, z)
            )
            shaft.name = "occludedLightWindowBlade\(index)"
            shaft.eulerAngles = SCNVector3(-0.08, -0.46 + Float(index) * 0.022, -0.13)
            root.addChildNode(shaft)

            let mullionCut = box(width: 0.055, height: 1.62, length: 0.78, color: shadowCut, position: SCNVector3(2.28, 1.5, z + 0.1))
            mullionCut.name = "occludedLightMullionShadowCut\(index)"
            mullionCut.eulerAngles = SCNVector3(-0.08, -0.45 + Float(index) * 0.018, -0.13)
            root.addChildNode(mullionCut)

            let rainVeil = box(width: 0.08, height: 1.28, length: 1.02, color: rainBlue, position: SCNVector3(2.18, 1.38, z - 0.06))
            rainVeil.name = "occludedLightRainVeil\(index)"
            rainVeil.eulerAngles = SCNVector3(-0.06, -0.4 + Float(index) * 0.02, -0.1)
            root.addChildNode(rainVeil)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let deskOcclusion = box(width: 5.65, height: 0.004, length: 0.18, color: shadowCut.withAlphaComponent(0.1), position: SCNVector3(0.05, 0.872, z + 0.08))
            deskOcclusion.name = "occludedLightDeskRowOcclusion\(row)"
            deskOcclusion.eulerAngles.y = row % 2 == 0 ? -0.025 : 0.024
            root.addChildNode(deskOcclusion)

            let shoulderRim = box(width: 5.45, height: 0.18, length: 0.012, color: warmDust, position: SCNVector3(0.02, 1.08, z + 0.16))
            shoulderRim.name = "occludedLightStudentShoulderRim\(row)"
            shoulderRim.eulerAngles.y = row % 2 == 0 ? 0.02 : -0.018
            root.addChildNode(shoulderRim)

            let aisleHaze = box(width: 0.24, height: 0.5, length: 1.25, color: chalkSilver, position: SCNVector3(-0.02, 1.12, z + 0.42))
            aisleHaze.name = "occludedLightRowAisleSuspension\(row)"
            aisleHaze.eulerAngles.y = row % 2 == 0 ? -0.04 : 0.04
            root.addChildNode(aisleHaze)
        }

        for column in 0..<4 {
            let x = Float(column) * 1.2 - 2.4
            let verticalCut = box(width: 0.04, height: 1.2, length: 5.9, color: shadowCut.withAlphaComponent(0.055), position: SCNVector3(x + 0.42, 1.2, 0.7))
            verticalCut.name = "occludedLightAisleVerticalCut\(column)"
            verticalCut.eulerAngles.y = -0.035 + Float(column) * 0.018
            root.addChildNode(verticalCut)
        }

        let teacherCut = box(width: 0.72, height: 1.35, length: 0.04, color: shadowCut.withAlphaComponent(0.12), position: SCNVector3(0, 1.36, -3.55))
        teacherCut.name = "occludedLightTeacherMovingBodyCut"
        teacherCut.eulerAngles.y = -0.16
        root.addChildNode(teacherCut)

        let teacherFloor = box(width: 1.12, height: 0.004, length: 0.52, color: shadowCut.withAlphaComponent(0.12), position: SCNVector3(0, 0.076, -3.25))
        teacherFloor.name = "occludedLightTeacherFloorOcclusion"
        teacherFloor.eulerAngles.y = -0.22
        root.addChildNode(teacherFloor)

        let boardHaze = box(width: 2.4, height: 0.58, length: 0.014, color: chalkSilver, position: SCNVector3(0.35, 1.78, -5.64))
        boardHaze.name = "occludedLightBlackboardChalkCone"
        boardHaze.eulerAngles.x = -0.12
        root.addChildNode(boardHaze)

        for index in 0..<10 {
            let mote = sphere(
                radius: 0.004 + CGFloat(index % 3) * 0.0012,
                color: index % 2 == 0 ? chalkSilver.withAlphaComponent(0.12) : warmDust.withAlphaComponent(0.1),
                position: SCNVector3(-1.4 + Float((index * 37) % 280) / 100, 1.05 + Float((index * 23) % 95) / 100, -4.9 + Float((index * 29) % 210) / 100),
                scale: SCNVector3(1.5, 0.48, 0.9)
            )
            mote.name = "occludedLightFloatingDust\(index)"
            mote.geometry?.firstMaterial?.emission.contents = chalkSilver.withAlphaComponent(0.045)
            root.addChildNode(mote)
        }

        root.opacity = 0.14
        return root
    }

    private func makeClassroomAirContinuityLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomAirContinuityLayer"
        let chalkSuspension = NSColor(calibratedRed: 0.86, green: 0.96, blue: 0.78, alpha: 0.06)
        let rainHumidity = NSColor(calibratedRed: 0.52, green: 0.72, blue: 1.0, alpha: 0.06)
        let projectorSilver = NSColor(calibratedRed: 0.68, green: 0.86, blue: 1.0, alpha: 0.07)
        let warmDeskAir = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.42, alpha: 0.05)
        let pressureShadow = NSColor(calibratedWhite: 0.0, alpha: 0.055)

        for index in 0..<5 {
            let chalk = box(
                width: 0.84 + CGFloat(index % 2) * 0.18,
                height: 0.32,
                length: 0.014,
                color: chalkSuspension,
                position: SCNVector3(-1.8 + Float(index) * 0.9, 1.48 + Float(index % 2) * 0.2, -5.42)
            )
            chalk.name = "airContinuityChalkSuspension\(index)"
            chalk.eulerAngles.z = -0.035 + Float(index) * 0.018
            root.addChildNode(chalk)
        }

        for index in 0..<4 {
            let bridge = box(
                width: 0.026,
                height: 1.24,
                length: 1.45,
                color: rainHumidity,
                position: SCNVector3(3.66, 1.48 + Float(index % 2) * 0.12, -3.18 + Float(index) * 2.04)
            )
            bridge.name = "airContinuityWindowHumidityBridge\(index)"
            bridge.eulerAngles.z = -0.018 + Float(index) * 0.009
            root.addChildNode(bridge)
        }

        for index in 0..<14 {
            let x = -0.7 + Float((index * 31) % 140) / 100
            let y = 1.05 + Float((index * 17) % 88) / 100
            let z = -4.34 + Float((index * 23) % 96) / 100
            let mote = sphere(
                radius: 0.0045 + CGFloat(index % 3) * 0.001,
                color: projectorSilver,
                position: SCNVector3(x, y, z),
                scale: SCNVector3(1.5, 0.42, 0.8)
            )
            mote.name = "airContinuityProjectorMote\(index)"
            mote.geometry?.firstMaterial?.emission.contents = projectorSilver
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.01, y: 0.018 + CGFloat(index % 3) * 0.006, z: CGFloat((index % 4) - 1) * 0.008, duration: 1.5 + Double(index % 4) * 0.18),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.01, y: -0.018 - CGFloat(index % 3) * 0.006, z: -CGFloat((index % 4) - 1) * 0.008, duration: 1.9 + Double(index % 5) * 0.16)
            ])), forKey: "air_continuity_mote")
            root.addChildNode(mote)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let deskAir = box(width: 5.75, height: 0.18, length: 0.014, color: warmDeskAir, position: SCNVector3(0, 0.96, z + 0.22))
            deskAir.name = "airContinuityDeskThermalLayer\(row)"
            deskAir.eulerAngles.y = row % 2 == 0 ? -0.016 : 0.018
            root.addChildNode(deskAir)

            let stillness = box(width: 5.9, height: 0.09, length: 0.014, color: pressureShadow, position: SCNVector3(0, 0.72, z + 0.52))
            stillness.name = "airContinuityRowStillnessShadow\(row)"
            stillness.eulerAngles.y = row % 2 == 0 ? 0.012 : -0.014
            root.addChildNode(stillness)
        }

        let teacherWake = sphere(radius: 0.18, color: pressureShadow.withAlphaComponent(0.08), position: SCNVector3(0, 0.84, -2.8), scale: SCNVector3(3.0, 0.18, 1.4))
        teacherWake.name = "airContinuityTeacherWakePressure"
        root.addChildNode(teacherWake)

        let foregroundHaze = box(width: 4.5, height: 0.24, length: 0.014, color: warmDeskAir.withAlphaComponent(0.07), position: SCNVector3(-0.25, 0.92, 1.62))
        foregroundHaze.name = "airContinuityForegroundHaze"
        foregroundHaze.eulerAngles.y = 0.022
        root.addChildNode(foregroundHaze)

        root.opacity = 0.16
        return root
    }

    private func makeClassroomAmbientMotionRhythmLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomAmbientMotionRhythmLayer"

        let fanShadow = NSColor(calibratedWhite: 0.0, alpha: 0.075)
        let tubeAfterglow = NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.58, alpha: 0.07)
        let paperLift = NSColor(calibratedWhite: 0.98, alpha: 0.13)
        let rainCaustic = NSColor(calibratedRed: 0.42, green: 0.62, blue: 1.0, alpha: 0.075)
        let chalkAir = NSColor(calibratedRed: 0.82, green: 0.96, blue: 0.78, alpha: 0.07)
        let pressureShadow = NSColor(calibratedWhite: 0.0, alpha: 0.09)

        for index in 0..<7 {
            let blade = box(
                width: 2.1 + CGFloat(index % 2) * 0.32,
                height: 0.003,
                length: 0.055,
                color: fanShadow,
                position: SCNVector3(-2.8 + Float(index) * 0.92, 0.031, -4.7 + Float((index * 19) % 92) / 10)
            )
            blade.name = "ambientRhythmFanBladeShadow\(index)"
            blade.eulerAngles.y = -0.7 + Float(index) * 0.31
            blade.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0.18 + CGFloat(index % 3) * 0.04, z: 0, duration: 1.2 + Double(index % 3) * 0.18),
                .rotateBy(x: 0, y: -0.18 - CGFloat(index % 3) * 0.04, z: 0, duration: 1.35 + Double(index % 4) * 0.16)
            ])), forKey: "ambient_fan_shadow_sweep")
            root.addChildNode(blade)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowPulse = box(width: 5.9, height: 0.006, length: 0.16, color: tubeAfterglow, position: SCNVector3(0, 0.884, z + 0.04))
            rowPulse.name = "ambientRhythmDeskTubePulse\(row)"
            rowPulse.eulerAngles.y = row % 2 == 0 ? -0.02 : 0.024
            root.addChildNode(rowPulse)

            let rowStillness = box(width: 5.7, height: 0.004, length: 0.11, color: pressureShadow, position: SCNVector3(0.06, 0.212, z - 0.08))
            rowStillness.name = "ambientRhythmRowStillnessPool\(row)"
            rowStillness.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.02
            root.addChildNode(rowStillness)
        }

        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25
                let page = box(
                    width: 0.34 + CGFloat((row + column) % 2) * 0.04,
                    height: 0.004,
                    length: 0.018,
                    color: paperLift,
                    position: SCNVector3(x - 0.11 + Float(column % 2) * 0.04, 0.238, z - 0.28)
                )
                page.name = "ambientRhythmPageFlutter\(row)_\(column)"
                page.eulerAngles.y = -0.18 + Float((row + column) % 5) * 0.07
                page.runAction(.repeatForever(.sequence([
                    .rotateBy(x: 0.035 + CGFloat((row + column) % 3) * 0.01, y: 0, z: 0, duration: 1.6 + Double((row + column) % 4) * 0.18),
                    .rotateBy(x: -0.035 - CGFloat((row + column) % 3) * 0.01, y: 0, z: 0, duration: 1.9 + Double((row + column) % 5) * 0.16)
                ])), forKey: "ambient_page_flutter")
                root.addChildNode(page)
            }
        }

        for index in 0..<5 {
            let z = -3.2 + Float(index) * 1.7
            let caustic = box(width: 0.12, height: 0.62, length: 0.92, color: rainCaustic, position: SCNVector3(3.38, 1.24 + Float(index % 2) * 0.14, z))
            caustic.name = "ambientRhythmWindowRainCaustic\(index)"
            caustic.eulerAngles = SCNVector3(-0.03, -0.42 + Float(index) * 0.025, -0.08)
            root.addChildNode(caustic)
        }

        for index in 0..<8 {
            let chalk = sphere(
                radius: 0.006 + CGFloat(index % 3) * 0.0015,
                color: chalkAir,
                position: SCNVector3(-1.65 + Float(index) * 0.44, 1.46 + Float(index % 3) * 0.13, -5.18 + Float(index % 2) * 0.16),
                scale: SCNVector3(1.7, 0.42, 0.9)
            )
            chalk.name = "ambientRhythmChalkPulseMote\(index)"
            chalk.geometry?.firstMaterial?.emission.contents = chalkAir
            chalk.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.012, y: 0.026 + CGFloat(index % 2) * 0.008, z: CGFloat((index % 4) - 1) * 0.01, duration: 1.8 + Double(index % 4) * 0.14),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.012, y: -0.026 - CGFloat(index % 2) * 0.008, z: -CGFloat((index % 4) - 1) * 0.01, duration: 2.0 + Double(index % 5) * 0.12)
            ])), forKey: "ambient_chalk_pulse")
            root.addChildNode(chalk)
        }

        let teacherWake = box(width: 0.74, height: 0.006, length: 1.28, color: pressureShadow.withAlphaComponent(0.14), position: SCNVector3(0, 0.082, -3.2))
        teacherWake.name = "ambientRhythmTeacherWakeShadow"
        teacherWake.eulerAngles.y = -0.2
        root.addChildNode(teacherWake)

        let frontBoardFlicker = box(width: 3.4, height: 0.18, length: 0.012, color: tubeAfterglow.withAlphaComponent(0.06), position: SCNVector3(0.2, 1.48, -5.86))
        frontBoardFlicker.name = "ambientRhythmBlackboardLightBreath"
        root.addChildNode(frontBoardFlicker)

        root.opacity = 0.14
        return root
    }

    private func makeAnimatedLightPatches() -> SCNNode {
        let root = SCNNode()
        let coolWindow = NSColor(calibratedRed: 0.48, green: 0.68, blue: 1.0, alpha: 0.12)
        let warmCeiling = NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.46, alpha: 0.1)
        let boardBounce = NSColor(calibratedRed: 0.08, green: 0.32, blue: 0.18, alpha: 0.12)

        for (index, z) in [-2.75, -1.28, 0.35, 1.9, 3.22].enumerated() {
            let patch = box(width: 1.75 - CGFloat(index % 2) * 0.18, height: 0.004, length: 0.36, color: coolWindow, position: SCNVector3(2.15 - Float(index % 2) * 0.28, 0.024, Float(z)))
            patch.eulerAngles.y = -0.24 + Float(index) * 0.035
            patch.opacity = 0.46 + CGFloat(index % 3) * 0.08
            patch.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.28 + CGFloat(index % 2) * 0.08, duration: 2.1 + Double(index) * 0.18),
                .fadeOpacity(to: 0.58 + CGFloat(index % 3) * 0.08, duration: 2.8 + Double(index) * 0.14)
            ])), forKey: "window_light_breathe")
            root.addChildNode(patch)
        }

        for (index, x) in [-2.4, 0.0, 2.4].enumerated() {
            for z in [-3.2, 0.0, 3.2] {
                let pool = box(width: 1.18, height: 0.003, length: 0.64, color: warmCeiling, position: SCNVector3(Float(x), 0.026, Float(z)))
                pool.opacity = 0.34
                pool.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: index == 1 ? 0.5 : 0.42, duration: 1.4 + Double(index) * 0.2),
                    .fadeOpacity(to: 0.26, duration: 1.7 + Double(index) * 0.17)
                ])), forKey: "ceiling_pool_breathe")
                root.addChildNode(pool)
            }
        }

        for x in [-1.8, -0.9, 0.05, 0.95, 1.85] {
            let chalkBounce = box(width: 0.54, height: 0.006, length: 0.08, color: boardBounce, position: SCNVector3(Float(x), 1.28, -5.91))
            chalkBounce.opacity = 0.38
            chalkBounce.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.18, duration: 2.6),
                .fadeOpacity(to: 0.46, duration: 3.1)
            ])), forKey: "board_bounce")
            root.addChildNode(chalkBounce)
        }

        for index in 0..<10 {
            let x = -3.1 + Float((index * 61) % 620) / 100
            let z = -4.8 + Float((index * 43) % 960) / 100
            let shadow = box(width: 0.42 + CGFloat(index % 3) * 0.1, height: 0.003, length: 0.045, color: NSColor(calibratedWhite: 0.02, alpha: 0.1), position: SCNVector3(x, 0.028, z))
            shadow.eulerAngles.y = Float(index) * 0.19
            shadow.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.16, duration: 1.2 + Double(index % 3) * 0.25),
                .fadeOpacity(to: 0.06, duration: 1.6 + Double(index % 4) * 0.22)
            ])), forKey: "human_shadow_breathe")
            root.addChildNode(shadow)
        }
        return root
    }

    private func makeDepthAtmosphereLayer() -> SCNNode {
        let root = SCNNode()
        let coolAir = NSColor(calibratedRed: 0.42, green: 0.58, blue: 0.78, alpha: 0.055)
        let warmAir = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.36, alpha: 0.042)
        for (index, z) in [-4.85, -3.5, -2.1, -0.7, 0.8, 2.25, 3.65].enumerated() {
            let veil = box(width: 7.2 - CGFloat(index % 3) * 0.32, height: 1.25 + CGFloat(index % 2) * 0.2, length: 0.012, color: index % 2 == 0 ? coolAir : warmAir, position: SCNVector3(0, 1.35 + Float(index % 2) * 0.18, Float(z)))
            veil.eulerAngles.y = Float(index - 3) * 0.018
            veil.opacity = 0.38
            veil.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.22, duration: 2.8 + Double(index % 3) * 0.4),
                .fadeOpacity(to: 0.46, duration: 3.4 + Double(index % 4) * 0.35)
            ])), forKey: "depth_air")
            root.addChildNode(veil)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.05
            let aisleShadow = box(width: 5.9, height: 0.005, length: 0.24, color: NSColor(calibratedWhite: 0.02, alpha: 0.07), position: SCNVector3(0, 0.034, z + 0.45))
            aisleShadow.eulerAngles.y = row % 2 == 0 ? 0.03 : -0.025
            root.addChildNode(aisleShadow)
        }
        return root
    }

