    private func makeCeilingLights() -> SCNNode {
        let root = SCNNode()
        for (index, z) in [-3.2, 0.0, 3.2].enumerated() {
            let lightPanel = box(width: 1.35, height: 0.025, length: 0.22, color: NSColor(calibratedWhite: 0.96, alpha: 1), position: SCNVector3(0, 3.47, Float(z)))
            lightPanel.geometry?.firstMaterial?.emission.contents = NSColor(calibratedWhite: 0.72, alpha: 1)
            lightPanel.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.86, duration: 0.08 + Double(index) * 0.02),
                .fadeOpacity(to: 1.0, duration: 0.12),
                .wait(duration: 1.7 + Double(index) * 0.42),
                .fadeOpacity(to: 0.92, duration: 0.06),
                .fadeOpacity(to: 1.0, duration: 0.08),
                .wait(duration: 2.5 + Double(index) * 0.35)
            ])), forKey: "panel_micro_flicker")
            root.addChildNode(lightPanel)
            let nearTrim = box(width: 1.46, height: 0.018, length: 0.03, color: NSColor(calibratedWhite: 0.62, alpha: 1), position: SCNVector3(0, 3.45, Float(z) - 0.14))
            let farTrim = box(width: 1.46, height: 0.018, length: 0.03, color: NSColor(calibratedWhite: 0.62, alpha: 1), position: SCNVector3(0, 3.45, Float(z) + 0.14))
            root.addChildNode(nearTrim)
            root.addChildNode(farTrim)
        }
        return root
    }

