            root.addChildNode(box(width: 0.085, height: 0.02, length: 0.26, color: NSColor(calibratedWhite: 0.72, alpha: 0.36), position: SCNVector3(-3.875, 2.52, Float(z))))
            root.addChildNode(box(width: 0.086, height: 0.02, length: 0.2, color: NSColor(calibratedWhite: 0.72, alpha: 0.22), position: SCNVector3(-3.875, 2.45, Float(z))))
        }

        root.addChildNode(roundedBox(width: 0.42, height: 0.09, length: 0.28, chamfer: 0.025, color: NSColor(calibratedWhite: 0.78, alpha: 1), position: SCNVector3(0, 3.28, -5.82)))
        root.addChildNode(box(width: 0.18, height: 0.018, length: 0.16, color: NSColor(calibratedRed: 0.22, green: 0.28, blue: 0.32, alpha: 1), position: SCNVector3(0, 3.22, -5.76)))
        root.addChildNode(capsule(radius: 0.012, height: 0.58, color: cable, position: SCNVector3(0.28, 3.34, -5.86), rotation: SCNVector4(1, 0, 0, Float.pi / 2)))
        root.addChildNode(capsule(radius: 0.009, height: 1.08, color: cable, position: SCNVector3(0.78, 3.41, -5.86), rotation: SCNVector4(0, 0, 1, Float.pi / 2)))

        for x in [-3.2, 3.2] {
            let sign = box(width: 0.38, height: 0.12, length: 0.035, color: NSColor(calibratedRed: 0.12, green: 0.46, blue: 0.34, alpha: 1), position: SCNVector3(Float(x), 2.62, 5.95))
            sign.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.02, green: 0.18, blue: 0.09, alpha: 0.45)
