        }
        return root
    }

    private func makeDesk(at position: SCNVector3, isPlayer: Bool) -> SCNNode {
        let root = SCNNode()
        root.position = position
        let topColor = isPlayer ? NSColor(calibratedRed: 0.74, green: 0.62, blue: 0.46, alpha: 1) : NSColor(calibratedRed: 0.62, green: 0.48, blue: 0.34, alpha: 1)
        let underside = NSColor(calibratedRed: 0.28, green: 0.2, blue: 0.13, alpha: 1)
        let metal = NSColor(calibratedRed: 0.13, green: 0.15, blue: 0.16, alpha: 1)
        root.addChildNode(roundedBox(width: 0.86, height: 0.065, length: 0.58, chamfer: 0.025, color: topColor, position: SCNVector3(0, 0.735, 0)))
        root.addChildNode(box(width: 0.82, height: 0.012, length: 0.54, color: NSColor(calibratedRed: 0.92, green: 0.78, blue: 0.54, alpha: 0.1), position: SCNVector3(0, 0.775, 0)))
        root.addChildNode(box(width: 0.78, height: 0.045, length: 0.06, color: underside, position: SCNVector3(0, 0.66, -0.26)))
        root.addChildNode(box(width: 0.78, height: 0.028, length: 0.05, color: underside, position: SCNVector3(0, 0.66, 0.26)))
        root.addChildNode(box(width: 0.055, height: 0.028, length: 0.5, color: underside, position: SCNVector3(-0.39, 0.66, 0)))
        root.addChildNode(box(width: 0.055, height: 0.028, length: 0.5, color: underside, position: SCNVector3(0.39, 0.66, 0)))
        let deskSeed = Int((position.x + 4) * 10 + (position.z + 6) * 7)
        if isPlayer == false {
            root.addChildNode(makeDeskSupplies(seed: deskSeed))
        }
        root.addChildNode(makeDeskLifeDetails(seed: deskSeed, isPlayer: isPlayer))
        root.addChildNode(makeDeskIdentityDetails(seed: deskSeed, isPlayer: isPlayer))
        root.addChildNode(makeDeskSurfaceMicroDetails(seed: deskSeed, isPlayer: isPlayer))
        root.addChildNode(makeDeskStructuralDetails(seed: deskSeed, isPlayer: isPlayer, topColor: topColor, underside: underside, metal: metal))
        for x in [-0.34, 0.34] {
            for z in [-0.2, 0.2] {
                root.addChildNode(capsule(radius: 0.025, height: 0.68, color: metal, position: SCNVector3(Float(x), 0.36, Float(z))))
                root.addChildNode(box(width: 0.11, height: 0.018, length: 0.09, color: NSColor(calibratedWhite: 0.035, alpha: 1), position: SCNVector3(Float(x), 0.02, Float(z))))
            }
        }
        root.addChildNode(box(width: 0.7, height: 0.018, length: 0.035, color: metal, position: SCNVector3(0, 0.34, -0.2)))
        root.addChildNode(box(width: 0.7, height: 0.018, length: 0.035, color: metal, position: SCNVector3(0, 0.34, 0.2)))
        return root
    }

    private func makeDeskSupplies(seed: Int) -> SCNNode {
        let root = SCNNode()
        let bookColors = [
            NSColor(calibratedRed: 0.18, green: 0.32, blue: 0.66, alpha: 1),
            NSColor(calibratedRed: 0.6, green: 0.2, blue: 0.18, alpha: 1),
            NSColor(calibratedRed: 0.22, green: 0.46, blue: 0.28, alpha: 1)
        ]
        let stackCount = 1 + seed % 3
        for index in 0..<stackCount {
            let book = box(width: 0.3, height: 0.026, length: 0.15, color: bookColors[(seed + index) % bookColors.count], position: SCNVector3(-0.18 + Float(index) * 0.03, 0.61 + Float(index) * 0.026, -0.25))
            root.addChildNode(book)
            let pageEdge = box(width: 0.26, height: 0.006, length: 0.012, color: NSColor(calibratedWhite: 0.92, alpha: 0.82), position: SCNVector3(-0.18 + Float(index) * 0.03, 0.626 + Float(index) * 0.026, -0.322))
            pageEdge.name = "bookPageEdge\(seed)_\(index)"
            root.addChildNode(pageEdge)
            let spineGroove = box(width: 0.012, height: 0.018, length: 0.13, color: NSColor(calibratedWhite: 0.04, alpha: 0.18), position: SCNVector3(-0.332 + Float(index) * 0.03, 0.618 + Float(index) * 0.026, -0.25))
            spineGroove.name = "bookSpineGroove\(seed)_\(index)"
            root.addChildNode(spineGroove)
        }
        if seed % 2 == 0 {
            root.addChildNode(box(width: 0.26, height: 0.012, length: 0.035, color: NSColor(calibratedRed: 0.1, green: 0.14, blue: 0.32, alpha: 1), position: SCNVector3(0.16, 0.615, -0.18)))
        } else {
            root.addChildNode(box(width: 0.22, height: 0.04, length: 0.11, color: NSColor(calibratedRed: 0.78, green: 0.68, blue: 0.42, alpha: 1), position: SCNVector3(0.18, 0.615, -0.18)))
        }
        let notebook = box(width: 0.32, height: 0.008, length: 0.24, color: NSColor(calibratedWhite: 0.92, alpha: 0.92), position: SCNVector3(-0.02, 0.619, 0.02))
        notebook.eulerAngles.y = Float(seed % 5) * 0.05 - 0.1
        root.addChildNode(notebook)
        for index in 0..<3 {
            root.addChildNode(box(width: 0.18 + CGFloat(index) * 0.03, height: 0.004, length: 0.008, color: NSColor(calibratedRed: 0.32, green: 0.36, blue: 0.44, alpha: 0.48), position: SCNVector3(-0.05 + Float(index) * 0.04, 0.626, -0.04 + Float(index) * 0.045)))
        }
        let pencil = capsule(radius: 0.006, height: 0.26, color: seed % 2 == 0 ? NSColor(calibratedRed: 0.86, green: 0.58, blue: 0.18, alpha: 1) : NSColor(calibratedRed: 0.08, green: 0.14, blue: 0.34, alpha: 1), position: SCNVector3(0.22, 0.632, 0.06), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        pencil.eulerAngles.y = -0.35 + Float(seed % 4) * 0.12
        root.addChildNode(pencil)
        return root
    }

    private func makeDeskLifeDetails(seed: Int, isPlayer: Bool) -> SCNNode {
        let root = SCNNode()
        let bagColors = [
            NSColor(calibratedRed: 0.08, green: 0.12, blue: 0.2, alpha: 1),
            NSColor(calibratedRed: 0.14, green: 0.22, blue: 0.16, alpha: 1),
            NSColor(calibratedRed: 0.28, green: 0.1, blue: 0.12, alpha: 1),
            NSColor(calibratedRed: 0.18, green: 0.16, blue: 0.3, alpha: 1)
        ]
        let bagColor = isPlayer ? NSColor(calibratedRed: 0.12, green: 0.18, blue: 0.28, alpha: 1) : bagColors[seed % bagColors.count]
        let bagX = seed % 2 == 0 ? -0.48 : 0.48
        let bagZ = 0.1 + Float(seed % 3) * 0.045
        let bag = roundedBox(width: 0.22, height: 0.36, length: 0.28, chamfer: 0.045, color: bagColor, position: SCNVector3(Float(bagX), 0.24, bagZ))
        bag.eulerAngles.z = seed % 2 == 0 ? -0.12 : 0.12
        root.addChildNode(bag)
        root.addChildNode(makeBackpackFabricDetails(seed: seed, bagX: Float(bagX), bagZ: bagZ, color: bagColor))
        root.addChildNode(roundedBox(width: 0.18, height: 0.12, length: 0.22, chamfer: 0.025, color: NSColor(calibratedWhite: 0.05, alpha: 0.6), position: SCNVector3(Float(bagX), 0.31, bagZ - 0.04)))
        root.addChildNode(capsule(radius: 0.009, height: 0.28, color: NSColor(calibratedWhite: 0.02, alpha: 1), position: SCNVector3(Float(bagX) - 0.09, 0.28, bagZ + 0.11), rotation: SCNVector4(1, 0, 0, 0.42)))
        root.addChildNode(capsule(radius: 0.009, height: 0.28, color: NSColor(calibratedWhite: 0.02, alpha: 1), position: SCNVector3(Float(bagX) + 0.09, 0.28, bagZ + 0.11), rotation: SCNVector4(1, 0, 0, -0.42)))

        if seed % 3 != 1 || isPlayer {
            let bottle = makeWaterBottle(seed: seed, position: SCNVector3(0.34, 0.84, 0.18 - Float(seed % 3) * 0.06))
            root.addChildNode(bottle)
        }

        if seed % 4 == 0 || isPlayer {
            let paperBall = sphere(radius: 0.045, color: NSColor(calibratedWhite: 0.84, alpha: 1), position: SCNVector3(-0.12, 0.065, 0.42), scale: SCNVector3(1.0, 0.72, 0.84))
            paperBall.eulerAngles = SCNVector3(0.2, 0.4, -0.16)
            root.addChildNode(paperBall)
        }

        if seed % 5 == 0 {
            let strap = capsule(radius: 0.008, height: 0.44, color: NSColor(calibratedWhite: 0.03, alpha: 1), position: SCNVector3(-0.06, 0.12, 0.34), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            strap.eulerAngles.y = 0.2
            root.addChildNode(strap)
        }

        root.addChildNode(box(width: 0.92, height: 0.004, length: 0.72, color: NSColor(calibratedWhite: 0.02, alpha: 0.12), position: SCNVector3(0, 0.018, 0.1)))
        return root
    }

    private func makeBackpackFabricDetails(seed: Int, bagX: Float, bagZ: Float, color: NSColor) -> SCNNode {
        let root = SCNNode()
        let seam = color.blended(withFraction: 0.34, of: .black) ?? color
        let thread = color.blended(withFraction: 0.28, of: .white) ?? color
        for index in 0..<5 {
            let y = 0.13 + Float(index) * 0.055
            let stitch = capsule(radius: 0.0028, height: 0.18 + CGFloat(index % 2) * 0.035, color: index % 2 == 0 ? seam.withAlphaComponent(0.72) : thread.withAlphaComponent(0.42), position: SCNVector3(bagX, y, bagZ - 0.145), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            stitch.name = "backpackFabricStitch\(seed)_\(index)"
            stitch.eulerAngles.y = -0.05 + Float(index % 3) * 0.05
            root.addChildNode(stitch)
        }
        let zipper = capsule(radius: 0.004, height: 0.24, color: NSColor(calibratedWhite: 0.04, alpha: 1), position: SCNVector3(bagX, 0.33, bagZ - 0.145), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        zipper.name = "backpackFrontZipper\(seed)"
        root.addChildNode(zipper)
        let zipperPull = roundedBox(width: 0.026, height: 0.014, length: 0.012, chamfer: 0.004, color: NSColor(calibratedWhite: 0.78, alpha: 1), position: SCNVector3(bagX + 0.085, 0.323, bagZ - 0.158))
        zipperPull.name = "backpackZipperPull\(seed)"
        root.addChildNode(zipperPull)
        return root
    }

    private func makeDeskIdentityDetails(seed: Int, isPlayer: Bool) -> SCNNode {
        let root = SCNNode()
        let plateBase = roundedBox(width: 0.24, height: 0.028, length: 0.075, chamfer: 0.012, color: isPlayer ? NSColor(calibratedRed: 0.18, green: 0.3, blue: 0.46, alpha: 1) : NSColor(calibratedRed: 0.22, green: 0.24, blue: 0.26, alpha: 1), position: SCNVector3(-0.28, 0.815, 0.25))
        plateBase.eulerAngles.y = -0.08
        root.addChildNode(plateBase)
        let plateFace = box(width: 0.18, height: 0.006, length: 0.052, color: NSColor(calibratedWhite: 0.9, alpha: 0.88), position: SCNVector3(-0.28, 0.834, 0.25))
        plateFace.eulerAngles.y = -0.08
        root.addChildNode(plateFace)
        root.addChildNode(box(width: 0.1, height: 0.004, length: 0.006, color: NSColor(calibratedRed: 0.16, green: 0.18, blue: 0.24, alpha: 0.6), position: SCNVector3(-0.285, 0.84, 0.25)))
        root.addChildNode(box(width: 0.055, height: 0.004, length: 0.006, color: NSColor(calibratedRed: 0.42, green: 0.08, blue: 0.1, alpha: 0.62), position: SCNVector3(-0.245, 0.842, 0.27)))

        let page = box(width: 0.22, height: 0.006, length: 0.16, color: NSColor(calibratedWhite: 0.96, alpha: 0.9), position: SCNVector3(0.06, 0.812, 0.22))
        page.eulerAngles.y = Float(seed % 5) * 0.04 - 0.08
        root.addChildNode(page)
        let curl = box(width: 0.07, height: 0.006, length: 0.03, color: NSColor(calibratedWhite: 1.0, alpha: 0.82), position: SCNVector3(0.14, 0.822, 0.285))
        curl.eulerAngles.z = -0.18
        curl.runAction(.repeatForever(.sequence([
            .rotateBy(x: 0, y: 0, z: 0.05, duration: 1.8 + Double(seed % 3) * 0.2),
            .rotateBy(x: 0, y: 0, z: -0.05, duration: 2.2 + Double(seed % 4) * 0.16)
        ])), forKey: "page_curl")
        root.addChildNode(curl)
        for index in 0..<3 {
            root.addChildNode(box(width: 0.12 + CGFloat(index) * 0.025, height: 0.004, length: 0.006, color: NSColor(calibratedRed: 0.18, green: 0.22, blue: 0.3, alpha: 0.44), position: SCNVector3(0.02 + Float(index) * 0.025, 0.82, 0.16 + Float(index) * 0.04)))
        }

        if seed % 4 == 1 || isPlayer {
            let noteColor = isPlayer ? NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.26, alpha: 1) : NSColor(calibratedRed: 0.72, green: 0.92, blue: 0.86, alpha: 1)
            let note = box(width: 0.11, height: 0.006, length: 0.085, color: noteColor, position: SCNVector3(0.28, 0.818, -0.02))
            note.eulerAngles.y = 0.16
            root.addChildNode(note)
            root.addChildNode(box(width: 0.07, height: 0.004, length: 0.006, color: NSColor(calibratedWhite: 0.18, alpha: 0.52), position: SCNVector3(0.28, 0.824, -0.02)))
        }

        let shadow = box(width: 0.62, height: 0.004, length: 0.28, color: NSColor(calibratedWhite: 0.02, alpha: 0.12), position: SCNVector3(0.0, 0.807, 0.17))
        root.addChildNode(shadow)
        return root
    }

    private func makeDeskSurfaceMicroDetails(seed: Int, isPlayer: Bool) -> SCNNode {
        let root = SCNNode()
        let edgeWear = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: isPlayer ? 0.28 : 0.16)
        let cutMark = NSColor(calibratedRed: 0.18, green: 0.11, blue: 0.06, alpha: 0.22)
        let graphite = NSColor(calibratedWhite: 0.04, alpha: 0.22)
        let tape = NSColor(calibratedRed: 0.95, green: 0.82, blue: 0.42, alpha: 0.24)

        let frontEdge = box(width: 0.78, height: 0.005, length: 0.012, color: edgeWear, position: SCNVector3(0, 0.812, 0.29))
        frontEdge.name = isPlayer ? "playerDeskFrontEdgeWear" : "deskFrontEdgeWear"
        root.addChildNode(frontEdge)

        let leftCorner = box(width: 0.12, height: 0.006, length: 0.018, color: edgeWear, position: SCNVector3(-0.36, 0.814, -0.26))
        leftCorner.eulerAngles.y = -0.14
        root.addChildNode(leftCorner)
        let rightCorner = box(width: 0.1, height: 0.006, length: 0.018, color: edgeWear, position: SCNVector3(0.36, 0.814, 0.25))
        rightCorner.eulerAngles.y = 0.12
        root.addChildNode(rightCorner)

        for index in 0..<7 {
            let x = -0.31 + Float((seed + index * 17) % 62) / 100
            let z = -0.21 + Float((seed + index * 23) % 44) / 100
            let mark = box(
                width: 0.09 + CGFloat(index % 3) * 0.035,
                height: 0.004,
                length: 0.006,
                color: index % 2 == 0 ? cutMark : graphite,
                position: SCNVector3(x, 0.819, z)
            )
            mark.name = "deskSurfaceCutMark\(index)"
            mark.eulerAngles.y = -0.45 + Float((seed + index) % 9) * 0.11
            root.addChildNode(mark)
        }

        if seed % 2 == 0 || isPlayer {
            let tapeStrip = box(width: 0.18, height: 0.005, length: 0.028, color: tape, position: SCNVector3(-0.18, 0.824, 0.16))
            tapeStrip.name = isPlayer ? "playerDeskOldTapeStrip" : "deskOldTapeStrip"
            tapeStrip.eulerAngles.y = 0.18 - Float(seed % 5) * 0.035
            root.addChildNode(tapeStrip)
        }

        if seed % 3 == 0 {
            let sticker = roundedBox(width: 0.12, height: 0.006, length: 0.075, chamfer: 0.008, color: NSColor(calibratedRed: 0.12, green: 0.34, blue: 0.58, alpha: 0.42), position: SCNVector3(0.24, 0.825, -0.18))
            sticker.name = "deskHalfPeeledSticker"
            sticker.eulerAngles.y = -0.22
            root.addChildNode(sticker)
            let liftedCorner = box(width: 0.04, height: 0.006, length: 0.022, color: NSColor(calibratedWhite: 0.96, alpha: 0.32), position: SCNVector3(0.29, 0.833, -0.15))
            liftedCorner.eulerAngles.z = -0.24
            root.addChildNode(liftedCorner)
        }

        let underShadow = box(width: 0.72, height: 0.006, length: 0.05, color: NSColor(calibratedWhite: 0.015, alpha: 0.18), position: SCNVector3(0, 0.64, 0.29))
        underShadow.name = "deskLipContactShadow"
        root.addChildNode(underShadow)
        return root
    }

    private func makeDeskStructuralDetails(seed: Int, isPlayer: Bool, topColor: NSColor, underside: NSColor, metal: NSColor) -> SCNNode {
        let root = SCNNode()
        let edgeDark = topColor.blended(withFraction: 0.36, of: .black) ?? topColor
        let edgeLight = topColor.blended(withFraction: 0.26, of: .white) ?? topColor
        let drawerColor = underside.blended(withFraction: 0.08, of: .white) ?? underside
        let wornMetal = metal.blended(withFraction: 0.44, of: .white) ?? metal

        let frontLayer = roundedBox(width: 0.84, height: 0.036, length: 0.03, chamfer: 0.01, color: edgeDark, position: SCNVector3(0, 0.698, 0.305))
        frontLayer.name = isPlayer ? "playerDeskLaminatedFrontLayer" : "deskLaminatedFrontLayer"
        root.addChildNode(frontLayer)
        let frontHighlight = box(width: 0.74, height: 0.006, length: 0.012, color: edgeLight.withAlphaComponent(isPlayer ? 0.34 : 0.22), position: SCNVector3(0.02, 0.724, 0.326))
        frontHighlight.name = isPlayer ? "playerDeskPressedEdgeHighlight" : "deskPressedEdgeHighlight"
        root.addChildNode(frontHighlight)

        let drawerPanel = roundedBox(width: 0.46, height: 0.095, length: 0.025, chamfer: 0.008, color: drawerColor, position: SCNVector3(-0.08, 0.603, 0.292))
        drawerPanel.name = isPlayer ? "playerDeskDrawerPanel" : "deskDrawerPanel"
        root.addChildNode(drawerPanel)
        let drawerGap = box(width: 0.5, height: 0.005, length: 0.01, color: NSColor(calibratedWhite: 0.01, alpha: 0.3), position: SCNVector3(-0.08, 0.656, 0.31))
        drawerGap.name = isPlayer ? "playerDeskDrawerGap" : "deskDrawerGap"
        root.addChildNode(drawerGap)
        let handle = capsule(radius: 0.006, height: 0.22, color: wornMetal.withAlphaComponent(0.62), position: SCNVector3(-0.08, 0.61, 0.319), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        handle.name = isPlayer ? "playerDeskDrawerHandle" : "deskDrawerHandle"
        root.addChildNode(handle)

        for index in 0..<3 {
            let rib = box(width: 0.062, height: 0.035, length: 0.5, color: underside.withAlphaComponent(0.82), position: SCNVector3(-0.26 + Float(index) * 0.26, 0.622, -0.002))
            rib.name = "deskUndersideRib\(index)"
            root.addChildNode(rib)
        }
        for side in [-1.0, 1.0] {
            let sideF = Float(side)
            let bracket = roundedBox(width: 0.055, height: 0.065, length: 0.07, chamfer: 0.01, color: wornMetal.withAlphaComponent(0.58), position: SCNVector3(sideF * 0.34, 0.626, 0.22))
            bracket.name = side < 0 ? "deskLeftLegBracket" : "deskRightLegBracket"
            root.addChildNode(bracket)
            let screw = sphere(radius: 0.012, color: NSColor(calibratedWhite: 0.03, alpha: 0.86), position: SCNVector3(sideF * 0.34, 0.642, 0.256), scale: SCNVector3(1, 0.3, 1))
            screw.name = side < 0 ? "deskLeftBracketScrew" : "deskRightBracketScrew"
            root.addChildNode(screw)
        }

        for index in 0..<4 {
            let x: Float = index < 2 ? -0.34 : 0.34
            let z: Float = index % 2 == 0 ? -0.2 : 0.2
            let ferrule = roundedBox(width: 0.075, height: 0.055, length: 0.075, chamfer: 0.012, color: NSColor(calibratedWhite: 0.02, alpha: 0.92), position: SCNVector3(x, 0.062, z))
            ferrule.name = "deskRubberFootFerrule\(index)"
            root.addChildNode(ferrule)
            let floorPress = box(width: 0.16, height: 0.003, length: 0.12, color: NSColor(calibratedWhite: 0.0, alpha: 0.13), position: SCNVector3(x, 0.024, z))
            floorPress.name = "deskFootFloorPressure\(index)"
            root.addChildNode(floorPress)
        }

        if seed % 2 == 0 || isPlayer {
            let gum = roundedBox(width: 0.055, height: 0.018, length: 0.034, chamfer: 0.01, color: NSColor(calibratedRed: 0.82, green: 0.76, blue: 0.68, alpha: 0.38), position: SCNVector3(0.18, 0.626, -0.18))
            gum.name = isPlayer ? "playerDeskUndersideOldGum" : "deskUndersideOldGum"
            root.addChildNode(gum)
        }
        return root
    }

    private func makeWaterBottle(seed: Int, position: SCNVector3) -> SCNNode {
        let root = SCNNode()
        root.position = position
        let bodyGeometry = SCNCylinder(radius: 0.045, height: 0.18)
        bodyGeometry.radialSegmentCount = 16
        bodyGeometry.firstMaterial = material(NSColor(calibratedRed: 0.58, green: 0.78, blue: 0.92, alpha: 0.58))
        let body = SCNNode(geometry: bodyGeometry)
        body.position = SCNVector3(0, 0, 0)
        root.addChildNode(body)

        let labelColor = seed % 2 == 0
            ? NSColor(calibratedRed: 0.1, green: 0.3, blue: 0.62, alpha: 1)
            : NSColor(calibratedRed: 0.72, green: 0.18, blue: 0.22, alpha: 1)
        root.addChildNode(box(width: 0.092, height: 0.038, length: 0.012, color: labelColor, position: SCNVector3(0, -0.015, 0.04)))
        root.addChildNode(capsule(radius: 0.026, height: 0.045, color: NSColor(calibratedWhite: 0.86, alpha: 1), position: SCNVector3(0, 0.112, 0)))
        root.addChildNode(makeBottleSurfaceDetails(seed: seed))
        return root
    }

    private func makeBottleSurfaceDetails(seed: Int) -> SCNNode {
        let root = SCNNode()
        let waterLine = capsule(radius: 0.004, height: 0.078, color: NSColor(calibratedRed: 0.84, green: 0.96, blue: 1.0, alpha: 0.36), position: SCNVector3(0, -0.044, 0.044), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        waterLine.name = "bottleWaterLine\(seed)"
        root.addChildNode(waterLine)
        let verticalGlint = capsule(radius: 0.0025, height: 0.14, color: NSColor(calibratedWhite: 1.0, alpha: 0.22), position: SCNVector3(0.028, 0.006, 0.043), rotation: SCNVector4(1, 0, 0, 0.02))
        verticalGlint.name = "bottleVerticalGlint\(seed)"
        root.addChildNode(verticalGlint)
        let capRidge = capsule(radius: 0.0025, height: 0.044, color: NSColor(calibratedWhite: 0.58, alpha: 0.44), position: SCNVector3(0, 0.136, 0), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        capRidge.name = "bottleCapRidge\(seed)"
        root.addChildNode(capRidge)
        return root
    }

    private func makeChair(at position: SCNVector3) -> SCNNode {
        let root = SCNNode()
        root.position = position
        let seat = NSColor(calibratedRed: 0.28, green: 0.24, blue: 0.22, alpha: 1)
        let seatHighlight = NSColor(calibratedRed: 0.42, green: 0.34, blue: 0.28, alpha: 0.18)
        let metal = NSColor(calibratedRed: 0.12, green: 0.13, blue: 0.14, alpha: 1)
        root.addChildNode(roundedBox(width: 0.54, height: 0.065, length: 0.48, chamfer: 0.03, color: seat, position: SCNVector3(0, 0.45, 0)))
        root.addChildNode(box(width: 0.46, height: 0.006, length: 0.38, color: seatHighlight, position: SCNVector3(0, 0.487, -0.01)))
        root.addChildNode(roundedBox(width: 0.56, height: 0.48, length: 0.065, chamfer: 0.018, color: NSColor(calibratedRed: 0.25, green: 0.21, blue: 0.19, alpha: 1), position: SCNVector3(0, 0.75, 0.22)))
        root.addChildNode(box(width: 0.46, height: 0.028, length: 0.032, color: seatHighlight, position: SCNVector3(0, 0.87, 0.185)))
        root.addChildNode(makeChairWearDetails())
        root.addChildNode(makeChairStructuralDetails(seat: seat, metal: metal))
        for x in [-0.22, 0.22] {
            for z in [-0.16, 0.18] {
                let leg = capsule(radius: 0.018, height: 0.42, color: metal, position: SCNVector3(Float(x), 0.24, Float(z)))
                leg.eulerAngles.x = z > 0 ? -0.06 : 0.06
                root.addChildNode(leg)
            }
        }
        root.addChildNode(capsule(radius: 0.012, height: 0.58, color: metal, position: SCNVector3(0, 0.35, -0.02), rotation: SCNVector4(0, 0, 1, Float.pi / 2)))
        root.addChildNode(box(width: 0.6, height: 0.005, length: 0.52, color: NSColor(calibratedWhite: 0.02, alpha: 0.16), position: SCNVector3(0, 0.012, 0.04)))
        return root
    }

    private func makeChairWearDetails() -> SCNNode {
        let root = SCNNode()
        let edge = NSColor(calibratedRed: 0.1, green: 0.085, blue: 0.075, alpha: 1)
        let worn = NSColor(calibratedRed: 0.68, green: 0.54, blue: 0.4, alpha: 0.18)
        root.addChildNode(box(width: 0.52, height: 0.01, length: 0.026, color: edge, position: SCNVector3(0, 0.494, -0.24)))
        root.addChildNode(box(width: 0.52, height: 0.01, length: 0.026, color: edge, position: SCNVector3(0, 0.494, 0.24)))
        root.addChildNode(box(width: 0.026, height: 0.01, length: 0.42, color: edge, position: SCNVector3(-0.27, 0.494, 0)))
        root.addChildNode(box(width: 0.026, height: 0.01, length: 0.42, color: edge, position: SCNVector3(0.27, 0.494, 0)))

        for index in 0..<5 {
            let scratch = box(width: 0.12 + CGFloat(index % 2) * 0.04, height: 0.005, length: 0.008, color: worn, position: SCNVector3(-0.18 + Float(index) * 0.09, 0.502, -0.12 + Float(index % 3) * 0.08))
            scratch.eulerAngles.y = Float(index) * 0.18
            root.addChildNode(scratch)
        }

        for x in [-0.19, 0.19] {
            for y in [0.63, 0.86] {
                root.addChildNode(sphere(radius: 0.014, color: NSColor(calibratedWhite: 0.08, alpha: 1), position: SCNVector3(Float(x), Float(y), 0.18), scale: SCNVector3(1, 0.55, 1)))
            }
        }
        root.addChildNode(makeChairHardwareDetails())
        return root
    }

    private func makeChairStructuralDetails(seat: NSColor, metal: NSColor) -> SCNNode {
        let root = SCNNode()
        let seatDark = seat.blended(withFraction: 0.42, of: .black) ?? seat
        let seatLight = seat.blended(withFraction: 0.28, of: .white) ?? seat
        let wornMetal = metal.blended(withFraction: 0.48, of: .white) ?? metal

        let seatCompression = sphere(radius: 0.16, color: seatDark.withAlphaComponent(0.32), position: SCNVector3(0.01, 0.492, -0.025), scale: SCNVector3(1.55, 0.16, 1.1))
        seatCompression.name = "chairSeatWeightCompression"
        root.addChildNode(seatCompression)
        let frontRoll = capsule(radius: 0.012, height: 0.48, color: seatLight.withAlphaComponent(0.2), position: SCNVector3(0, 0.5, -0.245), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        frontRoll.name = "chairSeatFrontRoundedWear"
        root.addChildNode(frontRoll)

        for index in 0..<3 {
            let slot = roundedBox(width: 0.1, height: 0.115, length: 0.012, chamfer: 0.018, color: NSColor(calibratedWhite: 0.015, alpha: 0.52), position: SCNVector3(-0.16 + Float(index) * 0.16, 0.76, 0.178))
            slot.name = "chairBackVentCutout\(index)"
            root.addChildNode(slot)
            let innerRim = box(width: 0.07, height: 0.006, length: 0.01, color: seatLight.withAlphaComponent(0.16), position: SCNVector3(-0.16 + Float(index) * 0.16, 0.817, 0.168))
            innerRim.name = "chairBackVentInnerRim\(index)"
            root.addChildNode(innerRim)
        }

        let lowerBrace = capsule(radius: 0.011, height: 0.54, color: wornMetal.withAlphaComponent(0.48), position: SCNVector3(0, 0.58, 0.18), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        lowerBrace.name = "chairBackLowerMetalBrace"
        root.addChildNode(lowerBrace)
        let floorSkid = box(width: 0.58, height: 0.004, length: 0.11, color: NSColor(calibratedWhite: 0.0, alpha: 0.14), position: SCNVector3(0, 0.024, -0.04))
        floorSkid.name = "chairFloorSkidShadow"
        root.addChildNode(floorSkid)

        for side in [-1.0, 1.0] {
            let sideF = Float(side)
            let sideBrace = capsule(radius: 0.008, height: 0.44, color: wornMetal.withAlphaComponent(0.44), position: SCNVector3(sideF * 0.22, 0.38, 0.06), rotation: SCNVector4(1, 0, 0, 0.36))
            sideBrace.name = side < 0 ? "chairLeftSideBrace" : "chairRightSideBrace"
            root.addChildNode(sideBrace)
        }
        return root
    }

    private func makeChairHardwareDetails() -> SCNNode {
        let root = SCNNode()
        let screw = NSColor(calibratedWhite: 0.04, alpha: 0.86)
        let wornMetal = NSColor(calibratedRed: 0.78, green: 0.74, blue: 0.62, alpha: 0.22)
        for x in [-0.19, 0.19] {
            for z in [-0.17, 0.17] {
                let screwHead = sphere(radius: 0.012, color: screw, position: SCNVector3(Float(x), 0.49, Float(z)), scale: SCNVector3(1, 0.26, 1))
                screwHead.name = "chairSeatScrew"
                root.addChildNode(screwHead)
                let rim = box(width: 0.06, height: 0.004, length: 0.008, color: wornMetal, position: SCNVector3(Float(x), 0.506, Float(z)))
                rim.eulerAngles.y = Float(x) * 0.45
                root.addChildNode(rim)
            }
        }
        for index in 0..<3 {
            let scuff = box(width: 0.12 + CGFloat(index) * 0.035, height: 0.004, length: 0.01, color: wornMetal, position: SCNVector3(-0.18 + Float(index) * 0.18, 0.88, 0.178))
            scuff.name = "chairBackEdgePolish\(index)"
            scuff.eulerAngles.y = -0.06 + Float(index) * 0.06
            root.addChildNode(scuff)
        }
        return root
    }

    private func addClassmates(classmates: [Classmate]) {
        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.0
                let profile = classmates.first(where: { $0.id == id })?.profile
                let node = makeStudent(seed: id, profile: profile)
                node.position = SCNVector3(x, 0.5, z)
                classmateNodes[id] = node
                classmateBaseScales[id] = node.scale
                scene.rootNode.addChildNode(node)
                applyCinematicMaterialPass(to: node)
                startClassmateIdleAnimation(node, seed: id, state: nil)
                id += 1
            }
        }
    }

    private func rebuildClassmates(with classmates: [Classmate]) {
        classmateNodes.values.forEach { $0.removeFromParentNode() }
        classmateNodes.removeAll()
        classmateStates.removeAll()
        classmateBaseScales.removeAll()
        addClassmates(classmates: classmates)
    }

    private func profileSignature(for classmates: [Classmate]) -> String {
        classmates
            .map { mate in
                "\(mate.id):\(Int(mate.profile.cooperation))-\(Int(mate.profile.orderliness))-\(Int(mate.profile.rebelliousness))-\(Int(mate.profile.empathy))-\(Int(mate.profile.anxiety))-\(Int(mate.profile.maskStrength))"
            }
            .joined(separator: "|")
    }

    private func makeStudent(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "student_\(seed)"
        root.eulerAngles.y = Float((seed % 5) - 2) * 0.018
        let shirtColors = [
            NSColor(calibratedRed: 0.18, green: 0.28, blue: 0.62, alpha: 1),
            NSColor(calibratedRed: 0.88, green: 0.9, blue: 0.92, alpha: 1),
            NSColor(calibratedRed: 0.32, green: 0.48, blue: 0.35, alpha: 1),
            NSColor(calibratedRed: 0.55, green: 0.18, blue: 0.22, alpha: 1)
        ]
        let uniformColor = studentUniformColor(seed: seed, profile: profile, fallback: shirtColors[seed % shirtColors.count])
        let bodyRoot = makeStudentBody(uniformColor: uniformColor, seed: seed, profile: profile)
        bodyRoot.name = "bodyRoot"
        root.addChildNode(bodyRoot)

        let head = sphere(radius: 0.15, color: skinColor(seed), position: SCNVector3(0, 0.88, 0))
        head.name = "head"
        head.addChildNode(makeStudentFaceVolumeDetails(seed: seed, profile: profile))
        head.addChildNode(makeStudentFace(seed: seed, profile: profile))
        head.addChildNode(makeStudentEmotionalFaceLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentCloseupFaceDetailLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentFacialCinematicFidelityLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentSkinEyeMicroMaterialLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentHeadAccessories(seed: seed, profile: profile))
        head.addChildNode(makeStudentHeadSilhouetteDetailLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentHeadMotionFidelityLayer(seed: seed, profile: profile))
        head.addChildNode(makeStudentHairCinematicMaterialLayer(seed: seed, profile: profile))
        if profile?.orderliness ?? 0 > 72 {
            head.addChildNode(makeFaceGlasses())
        }
        root.addChildNode(head)

        let hair = sphere(radius: 0.152, color: NSColor(calibratedWhite: 0.04 + CGFloat(seed % 3) * 0.04, alpha: 1), position: SCNVector3(0, 0.98, 0.02), scale: hairScale(seed: seed, profile: profile))
        hair.name = "hair"
        root.addChildNode(hair)
        root.addChildNode(makeHairDetail(seed: seed, profile: profile))

        if profile?.anxiety ?? 0 > 68 {
            let tensionNote = box(width: 0.18, height: 0.01, length: 0.08, color: NSColor(calibratedRed: 0.94, green: 0.86, blue: 0.3, alpha: 1), position: SCNVector3(-0.24, 0.2, -0.16))
            tensionNote.name = "tensionNote"
            root.addChildNode(tensionNote)
        }

        let phone = box(width: 0.12, height: 0.012, length: 0.2, color: NSColor(calibratedRed: 0.04, green: 0.18, blue: 0.55, alpha: 1), position: SCNVector3(0.18, 0.2, -0.18))
        phone.name = "phone"
        phone.opacity = (profile?.rebelliousness ?? 0) > 72 ? 0.28 : 0
        root.addChildNode(phone)
        let phoneGlow = makeClassmateStatusGlow(name: "phoneGlow", color: NSColor(calibratedRed: 0.18, green: 0.36, blue: 1.0, alpha: 0.38), position: SCNVector3(0.18, 0.205, -0.18), width: 0.28, length: 0.34)
        root.addChildNode(phoneGlow)
        let phoneLight = SCNLight()
        phoneLight.type = .omni
        phoneLight.intensity = 0
        phoneLight.color = NSColor(calibratedRed: 0.22, green: 0.42, blue: 1.0, alpha: 1)
        phoneLight.attenuationStartDistance = 0.05
        phoneLight.attenuationEndDistance = 1.1
        let phoneLightNode = SCNNode()
        phoneLightNode.name = "phoneLight"
        phoneLightNode.light = phoneLight
        phoneLightNode.position = SCNVector3(0.18, 0.38, -0.16)
        root.addChildNode(phoneLightNode)

        let paper = box(width: 0.22, height: 0.006, length: 0.16, color: NSColor(calibratedWhite: 0.92, alpha: 1), position: SCNVector3(-0.12, 0.18, -0.2))
        paper.name = "paper"
        paper.opacity = (profile?.orderliness ?? 50) > 70 ? 0.82 : 0.55
        root.addChildNode(paper)
        root.addChildNode(makeClassmateStatusGlow(name: "paperGlow", color: NSColor(calibratedRed: 0.98, green: 0.9, blue: 0.62, alpha: 0.18), position: SCNVector3(-0.12, 0.184, -0.2), width: 0.32, length: 0.24))
        root.addChildNode(makeClassmateStatusGlow(name: "cryingDeskGlow", color: NSColor(calibratedRed: 0.38, green: 0.62, blue: 1.0, alpha: 0.24), position: SCNVector3(-0.05, 0.186, -0.08), width: 0.38, length: 0.28))
        let coverShadow = makeClassmateStatusGlow(name: "coverShadow", color: NSColor(calibratedWhite: 0.02, alpha: 0.26), position: SCNVector3(-0.04, 0.188, -0.18), width: 0.34, length: 0.22)
        coverShadow.eulerAngles.y = -0.12
        root.addChildNode(coverShadow)

        if profile?.empathy ?? 0 > 72 {
            let supportNote = box(width: 0.08, height: 0.012, length: 0.12, color: NSColor(calibratedRed: 0.88, green: 0.94, blue: 1.0, alpha: 1), position: SCNVector3(-0.22, 0.21, 0.02))
            supportNote.name = "supportNote"
            supportNote.opacity = 0.35
            root.addChildNode(supportNote)
        }
        root.addChildNode(makeClassmateStatusGlow(name: "supportGlow", color: NSColor(calibratedRed: 0.48, green: 1.0, blue: 0.78, alpha: 0.22), position: SCNVector3(-0.22, 0.206, 0.02), width: 0.22, length: 0.26))
        root.addChildNode(makeStudentHandContactLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentHandPerformanceLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentGroundingDetails(seed: seed, profile: profile))
        root.addChildNode(makeStudentLowerBodyContactFidelityLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentMaterialIntegrationLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentClothMicroSurfaceLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentBodySilhouetteLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentUniformTailoringLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentCinematicRimLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentMicroMotionLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentGestureAnatomyLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentGroupPerformanceLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentMotionInertiaLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentSeatedKineticSilhouetteLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentPlayableMicroExpressionLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentStateReadabilityLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentActionSilhouetteLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentActingContinuityLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentPerformanceDirectorLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentSeatDeskContactLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentDeskInteractionFidelityLayer(seed: seed, profile: profile))
        root.addChildNode(makeStudentAnatomyVolumeLODLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentHeroFocusLODLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentIdentityPropLayer(seed: seed, profile: profile, uniformColor: uniformColor))
        root.addChildNode(makeStudentLocalLightTransportLayer(seed: seed, profile: profile, uniformColor: uniformColor))

        root.scale = SCNVector3(1, Float(0.94 + (profile?.cooperation ?? 50) / 900), 1)
        return root
    }

    private func makeClassmateStatusGlow(name: String, color: NSColor, position: SCNVector3, width: CGFloat, length: CGFloat) -> SCNNode {
        let glow = box(width: width, height: 0.004, length: length, color: color, position: position)
        glow.name = name
        glow.opacity = 0
        glow.geometry?.firstMaterial?.emission.contents = color
        return glow
    }

    private func makeStudentHandContactLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentHandContactLayer"
        let contactColor = NSColor(calibratedWhite: 0.01, alpha: 0.18)
        let warmSkin = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.52, alpha: 0.12)
        let phoneBlue = NSColor(calibratedRed: 0.24, green: 0.44, blue: 1.0, alpha: 0.16)

        let leftPressure = box(width: 0.18, height: 0.004, length: 0.052, color: contactColor, position: SCNVector3(-0.14, 0.213, -0.18))
        leftPressure.name = "leftHandPaperPressure"
        leftPressure.eulerAngles.y = -0.16
        root.addChildNode(leftPressure)
        let rightPressure = box(width: 0.18, height: 0.004, length: 0.052, color: contactColor, position: SCNVector3(0.13, 0.213, -0.17))
        rightPressure.name = "rightHandPaperPressure"
        rightPressure.eulerAngles.y = 0.16
        root.addChildNode(rightPressure)

        for index in 0..<4 {
            let side: Float = index < 2 ? -1 : 1
            let local = Float(index % 2) * 0.028
            let shadow = box(
                width: 0.07 + CGFloat(index % 2) * 0.018,
                height: 0.004,
                length: 0.012,
                color: contactColor,
                position: SCNVector3(side * (0.08 + local), 0.218, -0.225 + local)
            )
            shadow.name = "studentFingerContactShadow\(index)"
            shadow.eulerAngles.y = side * (0.18 + Float(index % 2) * 0.08)
            root.addChildNode(shadow)
        }

        let skinReflection = box(width: 0.34, height: 0.004, length: 0.08, color: warmSkin, position: SCNVector3(-0.02, 0.224, -0.14))
        skinReflection.name = "handSkinDeskReflection"
        skinReflection.eulerAngles.y = Float(seed % 5) * 0.025 - 0.05
        root.addChildNode(skinReflection)

        let thumbGlow = box(width: 0.18, height: 0.004, length: 0.1, color: phoneBlue, position: SCNVector3(0.18, 0.226, -0.18))
        thumbGlow.name = "phoneThumbGlow"
        thumbGlow.opacity = (profile?.rebelliousness ?? 0) > 72 ? 0.12 : 0
        root.addChildNode(thumbGlow)
        return root
    }

    private func makeStudentHandPerformanceLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentHandPerformanceLayer"
        root.opacity = 0.18

        let baseSkin = skinColor(seed)
        let skinWarm = baseSkin.blended(withFraction: 0.16, of: .white) ?? baseSkin
        let nailCatch = NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.74, alpha: 0.32)
        let shadow = NSColor(calibratedWhite: 0.02, alpha: 0.18)
        let cuffShadow = NSColor(calibratedRed: 0.04, green: 0.07, blue: 0.12, alpha: 0.22)
        let bluePhone = NSColor(calibratedRed: 0.25, green: 0.45, blue: 1.0, alpha: 0.2)
        let nervousness = Double(profile?.anxiety ?? 50) / 100.0
        let neatness = Double(profile?.orderliness ?? 50) / 100.0

        for sideName in ["Left", "Right"] {
            let side: Float = sideName == "Left" ? -1 : 1
            let baseX = side * 0.13
            for index in 0..<3 {
                let ridge = capsule(
                    radius: 0.006,
                    height: 0.068 - CGFloat(index) * 0.006,
                    color: skinWarm.blended(withFraction: 0.22, of: .black) ?? skinWarm,
                    position: SCNVector3(baseX + side * Float(index) * 0.024, 0.247 + Float(index) * 0.004, -0.208 + Float(index) * 0.018)
                )
                ridge.name = "student\(sideName)KnuckleRidge\(index)"
                ridge.eulerAngles.x = Float.pi / 2
                ridge.eulerAngles.z = side * (0.52 + Float(index) * 0.08)
                ridge.opacity = CGFloat(0.12 + nervousness * 0.08)
                root.addChildNode(ridge)
            }

            for index in 0..<4 {
                let nail = roundedBox(
                    width: 0.018,
                    height: 0.003,
                    length: 0.008,
                    chamfer: 0.003,
                    color: nailCatch,
                    position: SCNVector3(baseX + side * (-0.028 + Float(index) * 0.019), 0.265, -0.245 + Float(index % 2) * 0.018)
                )
                nail.name = "student\(sideName)FingernailCatch\(index)"
                nail.eulerAngles.y = side * (0.18 + Float(index) * 0.025)
                nail.opacity = CGFloat(0.06 + neatness * 0.1)
                nail.geometry?.firstMaterial?.emission.contents = nailCatch
                root.addChildNode(nail)
            }

            let palm = box(width: 0.11, height: 0.004, length: 0.052, color: shadow, position: SCNVector3(baseX, 0.226, -0.182))
            palm.name = "student\(sideName)PalmCompression"
            palm.eulerAngles.y = side * 0.16
            palm.opacity = 0.18
            root.addChildNode(palm)

            let pulse = box(width: 0.065, height: 0.004, length: 0.018, color: shadow, position: SCNVector3(side * 0.205, 0.234, -0.116))
            pulse.name = "student\(sideName)WristPulseShadow"
            pulse.eulerAngles.y = side * 0.28
            pulse.opacity = 0.14
            root.addChildNode(pulse)

            let cuffFold = box(width: 0.105, height: 0.006, length: 0.018, color: cuffShadow, position: SCNVector3(side * 0.222, 0.255, -0.086))
            cuffFold.name = "student\(sideName)SleeveCuffFold"
            cuffFold.eulerAngles.y = side * 0.18
            cuffFold.opacity = 0.16
            root.addChildNode(cuffFold)
        }

        let phoneThumb = roundedBox(width: 0.052, height: 0.005, length: 0.018, chamfer: 0.006, color: bluePhone, position: SCNVector3(0.19, 0.284, -0.204))
        phoneThumb.name = "studentPhoneThumbJointHighlight"
        phoneThumb.eulerAngles.y = 0.24
        phoneThumb.opacity = 0
        phoneThumb.geometry?.firstMaterial?.emission.contents = bluePhone
        root.addChildNode(phoneThumb)

        let pencilGrip = capsule(radius: 0.007, height: 0.078, color: NSColor(calibratedRed: 0.82, green: 0.62, blue: 0.32, alpha: 0.38), position: SCNVector3(-0.105, 0.282, -0.232))
        pencilGrip.name = "studentPencilGripPressure"
        pencilGrip.eulerAngles.x = Float.pi / 2
        pencilGrip.eulerAngles.z = -0.7
        pencilGrip.opacity = 0
        root.addChildNode(pencilGrip)

        let coverVeil = box(width: 0.31, height: 0.004, length: 0.12, color: NSColor(calibratedWhite: 0.03, alpha: 0.2), position: SCNVector3(-0.02, 0.332, -0.16))
        coverVeil.name = "studentCoveringHandVeil"
        coverVeil.eulerAngles.x = -0.14
        coverVeil.opacity = 0
        root.addChildNode(coverVeil)

        let tearWipe = box(width: 0.17, height: 0.004, length: 0.026, color: NSColor(calibratedRed: 0.42, green: 0.64, blue: 1.0, alpha: 0.18), position: SCNVector3(-0.11, 0.356, -0.118))
        tearWipe.name = "studentTearWipeFingerGhost"
        tearWipe.eulerAngles.z = -0.28
        tearWipe.opacity = 0
        tearWipe.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.3, green: 0.48, blue: 0.92, alpha: 0.12)
        root.addChildNode(tearWipe)

        return root
    }

    private func makeStudentGroundingDetails(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let floorShadow = box(width: 0.64, height: 0.004, length: 0.5, color: NSColor(calibratedWhite: 0.015, alpha: 0.22), position: SCNVector3(0, -0.488, 0.08))
        floorShadow.name = "studentFloorShadow"
        floorShadow.eulerAngles.y = Float(seed % 5) * 0.035 - 0.07
        root.addChildNode(floorShadow)

        let footContact = box(width: 0.46, height: 0.005, length: 0.18, color: NSColor(calibratedWhite: 0.01, alpha: 0.24), position: SCNVector3(0.01, -0.472, -0.18))
        footContact.name = "studentFootContact"
        root.addChildNode(footContact)

        let deskOcclusion = box(width: 0.54, height: 0.004, length: 0.24, color: NSColor(calibratedWhite: 0.02, alpha: 0.2), position: SCNVector3(0, 0.176, -0.12))
        deskOcclusion.name = "studentDeskOcclusion"
        deskOcclusion.eulerAngles.y = -0.08
        root.addChildNode(deskOcclusion)

        let rimColor = (profile?.rebelliousness ?? 0) > 72
            ? NSColor(calibratedRed: 1.0, green: 0.48, blue: 0.24, alpha: 0.16)
            : NSColor(calibratedRed: 0.62, green: 0.78, blue: 1.0, alpha: 0.12)
        let leftRim = capsule(radius: 0.005, height: 0.48, color: rimColor, position: SCNVector3(-0.19, 0.54, -0.115), rotation: SCNVector4(0, 0, 1, 0.08))
        leftRim.name = "studentLeftRimLight"
        let rightRim = capsule(radius: 0.005, height: 0.48, color: rimColor, position: SCNVector3(0.19, 0.54, -0.115), rotation: SCNVector4(0, 0, 1, -0.08))
        rightRim.name = "studentRightRimLight"
        let headRim = capsule(radius: 0.004, height: 0.2, color: rimColor.withAlphaComponent(0.14), position: SCNVector3(0.0, 0.97, -0.14), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        headRim.name = "studentHeadRimLight"
        root.addChildNode(leftRim)
        root.addChildNode(rightRim)
        root.addChildNode(headRim)
        return root
    }

    private func makeStudentLowerBodyContactFidelityLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentLowerBodyContactFidelityLayer"

        let anxious = (profile?.anxiety ?? 0) > 68
        let contact = NSColor(calibratedWhite: 0.0, alpha: 0.14)
        let dust = NSColor(calibratedWhite: 0.88, alpha: anxious ? 0.13 : 0.08)
