    private func makeStudentUniformTailoringLayer(seed: Int, profile: ClassmateProfile?, uniformColor: NSColor) -> SCNNode {
        let root = SCNNode()
        root.name = "studentUniformTailoringLayer"

        let tidy = (profile?.orderliness ?? 0) > 72
        let anxious = (profile?.anxiety ?? 0) > 68
        let clothShadow = uniformColor.blended(withFraction: anxious ? 0.58 : 0.46, of: .black) ?? uniformColor
        let clothCatch = uniformColor.blended(withFraction: tidy ? 0.52 : 0.34, of: .white) ?? uniformColor
        let thread = NSColor(calibratedWhite: tidy ? 0.92 : 0.72, alpha: tidy ? 0.22 : 0.16)
        let buttonColor = NSColor(calibratedWhite: tidy ? 0.92 : 0.78, alpha: 0.9)
        let nameTag = NSColor(calibratedRed: 0.92, green: 0.95, blue: 1.0, alpha: tidy ? 0.8 : 0.58)
