        rightCollar.name = "studentUniformRightCollarPlane"
        rightCollar.eulerAngles.z = 0.28
        root.addChildNode(rightCollar)

        let collarGap = capsule(radius: 0.003, height: 0.11, color: clothShadow.withAlphaComponent(0.3), position: SCNVector3(0, 0.642, -0.174), rotation: SCNVector4(1, 0, 0, 0.08))
