        let placketCatch = box(width: 0.011, height: 0.29, length: 0.012, color: clothCatch.withAlphaComponent(0.2), position: SCNVector3(-0.014, 0.495, -0.178))
        placketCatch.name = "studentUniformPlacketEdgeCatch"
        root.addChildNode(placketCatch)

        for index in 0..<4 {
            let button = sphere(
                radius: 0.012,
                color: buttonColor.withAlphaComponent(0.86),
                position: SCNVector3(0.017, 0.61 - Float(index) * 0.068, -0.186),
                scale: SCNVector3(0.92, 0.92, 0.22)
            )
            button.name = "studentUniformButton\(index)"
            button.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.22)
