            let buttonHole = box(width: 0.03, height: 0.004, length: 0.004, color: clothShadow.withAlphaComponent(0.28), position: SCNVector3(-0.016, 0.61 - Float(index) * 0.068, -0.187))
            buttonHole.name = "studentUniformButtonHole\(index)"
            root.addChildNode(buttonHole)
        }

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
