    private func makeStudentCinematicRimLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentCinematicRimLayer"
        let empathy = profile?.empathy ?? 0
        let anxiety = profile?.anxiety ?? 0
        let rebellious = profile?.rebelliousness ?? 0
        let baseWarm = rebellious > 72
            ? NSColor(calibratedRed: 1.0, green: 0.36, blue: 0.18, alpha: 0.22)
            : NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.34, alpha: 0.18)
        let baseCool = empathy > 72
            ? NSColor(calibratedRed: 0.42, green: 1.0, blue: 0.74, alpha: 0.18)
            : NSColor(calibratedRed: 0.42, green: 0.68, blue: 1.0, alpha: 0.17)
        let anxietyColor = NSColor(calibratedRed: 1.0, green: 0.28, blue: 0.16, alpha: anxiety > 68 ? 0.2 : 0.09)

        let leftRim = capsule(radius: 0.0048, height: 0.62, color: baseWarm, position: SCNVector3(-0.235, 0.58, -0.132), rotation: SCNVector4(0, 0, 1, 0.06))
        leftRim.name = "studentCinematicLeftRim"
        root.addChildNode(leftRim)
        let rightRim = capsule(radius: 0.0048, height: 0.62, color: baseCool, position: SCNVector3(0.235, 0.58, -0.132), rotation: SCNVector4(0, 0, 1, -0.06))
        rightRim.name = "studentCinematicRightRim"
        root.addChildNode(rightRim)
        let headHalo = capsule(radius: 0.004, height: 0.2, color: baseCool.withAlphaComponent(0.2), position: SCNVector3(0, 1.0, -0.15), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        headHalo.name = "studentCinematicHeadHalo"
        root.addChildNode(headHalo)

        let deskReflection = box(width: 0.58, height: 0.004, length: 0.16, color: baseCool.withAlphaComponent(0.09), position: SCNVector3(0, 0.19, -0.18))
        deskReflection.name = "studentDeskSkinReflection"
        deskReflection.eulerAngles.y = Float(seed % 5) * 0.035 - 0.07
        root.addChildNode(deskReflection)
        let emotionalWash = box(width: 0.42, height: 0.004, length: 0.22, color: anxietyColor, position: SCNVector3(0, 0.205, 0.02))
        emotionalWash.name = "studentEmotionalColorWash"
        emotionalWash.opacity = 0.18
        root.addChildNode(emotionalWash)
        let silhouetteCut = box(width: 0.5, height: 0.01, length: 0.028, color: NSColor(calibratedWhite: 0.01, alpha: 0.14), position: SCNVector3(0, 0.73, -0.14))
        silhouetteCut.name = "studentShoulderSilhouetteCut"
        root.addChildNode(silhouetteCut)

        for index in 0..<5 {
            let mote = sphere(radius: 0.005 + CGFloat(index % 2) * 0.0015, color: NSColor(calibratedWhite: 0.92, alpha: 0.16), position: SCNVector3(-0.18 + Float(index) * 0.09, 0.28 + Float(index % 2) * 0.09, -0.18 + Float(index % 3) * 0.08), scale: SCNVector3(1, 0.65, 1))
            mote.name = "studentHandDustMote\(index)"
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.006, y: 0.022, z: 0.004, duration: 1.4 + Double(index) * 0.12),
                .fadeOpacity(to: 0.05, duration: 0.18),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.006, y: -0.022, z: -0.004, duration: 0.01),
                .fadeOpacity(to: 0.24, duration: 0.18)
            ])), forKey: "student_hand_dust")
            root.addChildNode(mote)
        }
        return root
    }

    private func makeStudentMicroMotionLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentMicroMotionLayer"
        let anxiety = profile?.anxiety ?? 0
        let rebellious = profile?.rebelliousness ?? 0
        let empathy = profile?.empathy ?? 0
        let warmSkinBounce = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.5, alpha: 0.13)
        let tensionRed = NSColor(calibratedRed: 1.0, green: 0.28, blue: 0.16, alpha: anxiety > 68 ? 0.22 : 0.1)
        let phoneBlue = NSColor(calibratedRed: 0.24, green: 0.48, blue: 1.0, alpha: rebellious > 72 ? 0.26 : 0.1)
        let helpGreen = NSColor(calibratedRed: 0.48, green: 1.0, blue: 0.72, alpha: empathy > 72 ? 0.18 : 0.08)
        let contactShadow = NSColor(calibratedWhite: 0.02, alpha: 0.18)

        let leftShoulder = capsule(radius: 0.004, height: 0.2, color: tensionRed, position: SCNVector3(-0.18, 0.76, -0.128), rotation: SCNVector4(0, 0, 1, 1.42))
        leftShoulder.name = "studentLeftShoulderTensionLine"
        root.addChildNode(leftShoulder)
        let rightShoulder = capsule(radius: 0.004, height: 0.2, color: tensionRed, position: SCNVector3(0.18, 0.76, -0.128), rotation: SCNVector4(0, 0, 1, -1.42))
        rightShoulder.name = "studentRightShoulderTensionLine"
        root.addChildNode(rightShoulder)

        let throatShadow = box(width: 0.09, height: 0.006, length: 0.018, color: contactShadow.withAlphaComponent(0.16), position: SCNVector3(0, 0.73, -0.146))
        throatShadow.name = "studentThroatSwallowShadow"
        root.addChildNode(throatShadow)

        let breathBand = box(width: 0.28, height: 0.006, length: 0.036, color: warmSkinBounce, position: SCNVector3(0, 0.58, -0.142))
        breathBand.name = "studentBreathMotionBand"
        breathBand.runAction(.repeatForever(.sequence([
            .scale(to: 1.06, duration: 1.15 + Double(seed % 4) * 0.16),
            .scale(to: 0.96, duration: 1.35 + Double(seed % 5) * 0.14)
        ])), forKey: "student_breath_band")
        root.addChildNode(breathBand)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            for index in 0..<3 {
                let ripple = sphere(radius: 0.016 + CGFloat(index) * 0.004, color: contactShadow.withAlphaComponent(0.1), position: SCNVector3(side * (0.11 + Float(index) * 0.035), 0.188, -0.23 + Float(index) * 0.025), scale: SCNVector3(1.8, 0.18, 1.0))
                ripple.name = sideIndex == 0 ? "studentLeftFingerTapRipple\(index)" : "studentRightFingerTapRipple\(index)"
                ripple.runAction(.repeatForever(.sequence([
                    .scale(to: 1.18 + CGFloat(index) * 0.08, duration: 0.18 + Double(index) * 0.04),
                    .scale(to: 0.82, duration: 0.22 + Double(seed % 3) * 0.04),
                    .wait(duration: 0.58 + Double((seed + index) % 5) * 0.09)
                ])), forKey: "finger_tap_ripple")
                root.addChildNode(ripple)
            }
        }

        let penTrail = box(width: 0.2, height: 0.003, length: 0.018, color: NSColor(calibratedWhite: 0.08, alpha: 0.15), position: SCNVector3(-0.12, 0.192, -0.26))
        penTrail.name = "studentPenTipMotionTrail"
        penTrail.eulerAngles.y = -0.18 + Float(seed % 4) * 0.06
        penTrail.runAction(.repeatForever(.sequence([
            .moveBy(x: 0.018, y: 0, z: -0.004, duration: 0.2),
            .moveBy(x: -0.018, y: 0, z: 0.004, duration: 0.16),
            .wait(duration: 0.42 + Double(seed % 4) * 0.08)
        ])), forKey: "pen_tip_scrub")
        root.addChildNode(penTrail)

        let phoneThumbArc = capsule(radius: 0.004, height: 0.18, color: phoneBlue, position: SCNVector3(0.2, 0.226, -0.16), rotation: SCNVector4(0, 0, 1, 0.78))
        phoneThumbArc.name = "studentPhoneThumbMotionArc"
        phoneThumbArc.runAction(.repeatForever(.sequence([
            .rotateBy(x: 0, y: 0, z: 0.18, duration: 0.22),
            .rotateBy(x: 0, y: 0, z: -0.18, duration: 0.26),
            .wait(duration: 0.44 + Double(seed % 5) * 0.07)
        ])), forKey: "phone_thumb_arc")
        root.addChildNode(phoneThumbArc)

        let phoneJawLight = box(width: 0.18, height: 0.004, length: 0.06, color: phoneBlue.withAlphaComponent(0.16), position: SCNVector3(0.02, 0.78, -0.154))
        phoneJawLight.name = "studentPhoneJawLightPulse"
        phoneJawLight.runAction(.repeatForever(.sequence([
            .scale(to: 1.12, duration: 0.32),
            .scale(to: 0.88, duration: 0.4),
            .wait(duration: 0.36 + Double(seed % 3) * 0.09)
        ])), forKey: "phone_jaw_light")
        root.addChildNode(phoneJawLight)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let kneeGhost = box(width: 0.11, height: 0.004, length: 0.06, color: contactShadow.withAlphaComponent(0.12), position: SCNVector3(side * 0.12, 0.245, 0.09))
            kneeGhost.name = sideIndex == 0 ? "studentLeftKneeBounceGhost" : "studentRightKneeBounceGhost"
            kneeGhost.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.018 + CGFloat(seed % 3) * 0.002, z: 0, duration: 0.16),
                .moveBy(x: 0, y: -0.018 - CGFloat(seed % 3) * 0.002, z: 0, duration: 0.18),
                .wait(duration: 0.28 + Double((seed + sideIndex) % 4) * 0.08)
            ])), forKey: "knee_bounce_ghost")
            root.addChildNode(kneeGhost)
        }

        let helpReachGhost = box(width: 0.24, height: 0.004, length: 0.08, color: helpGreen, position: SCNVector3(-0.28, 0.22, 0.02))
        helpReachGhost.name = "studentHelpReachGhost"
        helpReachGhost.eulerAngles.y = -0.18
        root.addChildNode(helpReachGhost)

        root.opacity = 0.18
        return root
    }

