    private func makeStudentGroupPerformanceLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentGroupPerformanceLayer"
        let anxiety = profile?.anxiety ?? 0
        let empathy = profile?.empathy ?? 0
        let attentionWarm = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.42, alpha: 0.11)
        let pressureCool = NSColor(calibratedRed: 0.42, green: 0.58, blue: 1.0, alpha: 0.09)
        let deepShadow = NSColor(calibratedWhite: 0.0, alpha: 0.14)
        let nervousRed = NSColor(calibratedRed: 1.0, green: 0.24, blue: 0.14, alpha: anxiety > 68 ? 0.18 : 0.08)
        let supportGreen = NSColor(calibratedRed: 0.42, green: 1.0, blue: 0.68, alpha: empathy > 70 ? 0.16 : 0.07)

        let breathEnvelope = box(width: 0.34, height: 0.16, length: 0.014, color: attentionWarm.withAlphaComponent(0.07), position: SCNVector3(0, 0.57, -0.158))
        breathEnvelope.name = "studentGroupBreathEnvelope"
        breathEnvelope.eulerAngles.z = Float(seed % 5 - 2) * 0.012
        breathEnvelope.runAction(.repeatForever(.sequence([
            .scale(to: 1.04 + CGFloat(seed % 3) * 0.018, duration: 1.4 + Double(seed % 4) * 0.17),
            .scale(to: 0.97, duration: 1.7 + Double(seed % 5) * 0.13)
        ])), forKey: "group_breath_envelope")
        root.addChildNode(breathEnvelope)

        let attentionTurn = box(width: 0.26, height: 0.004, length: 0.07, color: pressureCool, position: SCNVector3(0.02, 0.91, -0.182))
        attentionTurn.name = "studentGroupAttentionTurnEcho"
        attentionTurn.eulerAngles.y = -0.08 + Float(seed % 4) * 0.05
        root.addChildNode(attentionTurn)

        let teacherSweep = box(width: 0.42, height: 0.006, length: 0.13, color: deepShadow.withAlphaComponent(0.18), position: SCNVector3(0, 0.205, -0.18))
        teacherSweep.name = "studentTeacherSweepCompression"
        teacherSweep.eulerAngles.y = Float(seed % 5 - 2) * 0.035
        root.addChildNode(teacherSweep)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"

            let shoulderWave = capsule(
                radius: 0.0038,
                height: 0.21,
                color: nervousRed,
                position: SCNVector3(side * 0.17, 0.69, -0.152),
                rotation: SCNVector4(0, 0, 1, side * 1.35)
            )
            shoulderWave.name = "studentGroup\(sideName)ShoulderWave"
            root.addChildNode(shoulderWave)

            let elbowDelay = sphere(
                radius: 0.014,
                color: deepShadow.withAlphaComponent(0.12),
                position: SCNVector3(side * 0.2, 0.43, -0.15),
                scale: SCNVector3(1.45, 0.22, 0.72)
            )
            elbowDelay.name = "studentGroup\(sideName)ElbowDelayShadow"
            root.addChildNode(elbowDelay)
        }

        for index in 0..<4 {
            let syncBreak = box(
                width: 0.11 + CGFloat(index % 2) * 0.035,
                height: 0.003,
                length: 0.018,
                color: index % 2 == 0 ? attentionWarm : pressureCool,
                position: SCNVector3(-0.2 + Float(index) * 0.13, 0.816 + Float(index % 2) * 0.012, -0.186)
            )
            syncBreak.name = "studentGroupSyncBreakLine\(index)"
            syncBreak.eulerAngles.y = -0.18 + Float((seed + index) % 7) * 0.06
            root.addChildNode(syncBreak)
        }

        let helpPulse = box(width: 0.36, height: 0.004, length: 0.09, color: supportGreen, position: SCNVector3(-0.18, 0.245, 0.02))
        helpPulse.name = "studentGroupHelpPulse"
        helpPulse.eulerAngles.y = -0.14
        root.addChildNode(helpPulse)

        let targetStillness = box(width: 0.36, height: 0.004, length: 0.16, color: deepShadow.withAlphaComponent(0.14), position: SCNVector3(0, 0.055, 0.12))
        targetStillness.name = "studentGroupTargetStillnessPool"
        targetStillness.eulerAngles.y = Float(seed % 6 - 3) * 0.03
        root.addChildNode(targetStillness)

        root.opacity = 0.12
        return root
    }

