            wristAfter.name = "studentInertia\(sideName)WristAfterimage"
            wristAfter.eulerAngles.y = side * 0.22
            root.addChildNode(wristAfter)

            let kneeTrace = box(width: 0.14, height: 0.004, length: 0.055, color: pressureRed.withAlphaComponent(0.12), position: SCNVector3(side * 0.12, 0.205, 0.06))
            kneeTrace.name = "studentInertia\(sideName)KneeJitterTrace"
            kneeTrace.eulerAngles.y = side * 0.14
            kneeTrace.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.012 + CGFloat(seed % 3) * 0.002, z: 0, duration: 0.16),
                .moveBy(x: 0, y: -0.012 - CGFloat(seed % 3) * 0.002, z: 0, duration: 0.18),
                .wait(duration: 0.42 + Double((seed + sideIndex) % 4) * 0.08)
            ])), forKey: "inertia_knee_trace")
            root.addChildNode(kneeTrace)
        }

        let deskSlide = box(width: 0.44, height: 0.004, length: 0.13, color: shadow.withAlphaComponent(0.17), position: SCNVector3(0.02, 0.186, -0.23))
        deskSlide.name = "studentInertiaDeskWeightSlide"
        deskSlide.eulerAngles.y = Float(seed % 5 - 2) * 0.025
        root.addChildNode(deskSlide)

        let teacherStartle = box(width: 0.42, height: 0.006, length: 0.18, color: shadow.withAlphaComponent(0.2), position: SCNVector3(0, 0.09, 0.1))
        teacherStartle.name = "studentInertiaTeacherStartleShadow"
        teacherStartle.eulerAngles.y = Float(seed % 7 - 3) * 0.025
        root.addChildNode(teacherStartle)

        let seatShift = box(width: 0.34, height: 0.005, length: 0.14, color: shadow.withAlphaComponent(0.14), position: SCNVector3(0, 0.03, 0.18))
        seatShift.name = "studentInertiaSeatShiftSmear"
        seatShift.eulerAngles.y = Float(seed % 6 - 3) * 0.026
        root.addChildNode(seatShift)

        let backpackLag = box(width: 0.24, height: 0.08, length: 0.012, color: shadow.withAlphaComponent(0.1), position: SCNVector3(0.08, 0.45, 0.19))
        backpackLag.name = "studentInertiaBackpackLagShadow"
        backpackLag.eulerAngles.z = -0.08
        root.addChildNode(backpackLag)

        let pencilLag = box(width: 0.26, height: 0.003, length: 0.018, color: NSColor(calibratedWhite: 0.05, alpha: 0.16), position: SCNVector3(-0.12, 0.194, -0.268))
        pencilLag.name = "studentInertiaPencilStrokeLag"
        pencilLag.eulerAngles.y = -0.22 + Float(seed % 4) * 0.05
        pencilLag.runAction(.repeatForever(.sequence([
            .moveBy(x: 0.018, y: 0, z: -0.006, duration: 0.16),
            .moveBy(x: -0.018, y: 0, z: 0.006, duration: 0.2),
            .wait(duration: 0.46 + Double(seed % 5) * 0.08)
        ])), forKey: "inertia_pencil_lag")
        root.addChildNode(pencilLag)

        let phoneLag = box(width: 0.22, height: 0.004, length: 0.12, color: phoneBlue, position: SCNVector3(0.18, 0.235, -0.164))
        phoneLag.name = "studentInertiaPhoneScreenLag"
        phoneLag.eulerAngles.y = 0.16
        phoneLag.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 0.24),
            .fadeOpacity(to: 0.32, duration: 0.18),
            .wait(duration: 0.42 + Double(seed % 3) * 0.08)
        ])), forKey: "inertia_phone_lag")
        root.addChildNode(phoneLag)

        let helpAfter = capsule(radius: 0.004, height: 0.36, color: helpGreen, position: SCNVector3(-0.27, 0.31, -0.014), rotation: SCNVector4(0, 0, 1, -0.9))
        helpAfter.name = "studentInertiaHelpReachAfterimage"
        root.addChildNode(helpAfter)

        let coverSnap = box(width: 0.36, height: 0.006, length: 0.18, color: shadow.withAlphaComponent(0.18), position: SCNVector3(0, 0.58, -0.19))
        coverSnap.name = "studentInertiaCoverSnapPlane"
        coverSnap.eulerAngles.y = -0.18
        root.addChildNode(coverSnap)

        let groupFreeze = box(width: 0.38, height: 0.12, length: 0.009, color: NSColor(calibratedRed: 0.76, green: 0.86, blue: 1.0, alpha: 0.08), position: SCNVector3(0, 0.54, -0.188))
        groupFreeze.name = "studentInertiaGroupFreezeOutline"
        groupFreeze.eulerAngles.z = Float(seed % 5 - 2) * 0.015
        root.addChildNode(groupFreeze)

        root.opacity = 0.12
        return root
    }

    private func makeStudentSeatedKineticSilhouetteLayer(seed: Int, profile: ClassmateProfile?, uniformColor: NSColor) -> SCNNode {
        let root = SCNNode()
        root.name = "studentSeatedKineticSilhouetteLayer"

        let anxiety = profile?.anxiety ?? 0
        let rebellious = profile?.rebelliousness ?? 0
        let empathy = profile?.empathy ?? 0
        let pressureInk = NSColor(calibratedWhite: 0.0, alpha: anxiety > 66 ? 0.2 : 0.13)
        let rimCool = NSColor(calibratedRed: 0.48, green: 0.68, blue: 1.0, alpha: 0.1)
        let bodyWarm = uniformColor.blended(withFraction: 0.24, of: .white)?.withAlphaComponent(0.13) ?? NSColor(calibratedWhite: 0.9, alpha: 0.13)
        let skinHeat = NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.45, alpha: 0.12)
        let phoneBlue = NSColor(calibratedRed: 0.18, green: 0.42, blue: 1.0, alpha: rebellious > 68 ? 0.18 : 0.09)
        let helpGreen = NSColor(calibratedRed: 0.42, green: 1.0, blue: 0.7, alpha: empathy > 68 ? 0.16 : 0.07)

        let torsoLead = box(width: 0.42, height: 0.26, length: 0.012, color: bodyWarm, position: SCNVector3(0, 0.52, -0.202))
        torsoLead.name = "studentKineticTorsoLeadPlane"
        torsoLead.eulerAngles.z = Float(seed % 5 - 2) * 0.012
        root.addChildNode(torsoLead)

        let headPocket = box(width: 0.3, height: 0.12, length: 0.01, color: rimCool, position: SCNVector3(0, 0.89, -0.205))
        headPocket.name = "studentKineticHeadPocketRim"
        headPocket.eulerAngles.y = Float(seed % 5 - 2) * 0.018
        root.addChildNode(headPocket)

        let chinDrop = box(width: 0.22, height: 0.018, length: 0.012, color: pressureInk.withAlphaComponent(0.16), position: SCNVector3(0, 0.765, -0.198))
        chinDrop.name = "studentKineticChinDropCut"
        root.addChildNode(chinDrop)

        let ribBreath = box(width: 0.36, height: 0.014, length: 0.04, color: skinHeat.withAlphaComponent(0.12), position: SCNVector3(0, 0.59, -0.208))
        ribBreath.name = "studentKineticRibBreathBand"
        ribBreath.runAction(.repeatForever(.sequence([
            .scale(to: 1.04 + CGFloat(seed % 3) * 0.015, duration: 1.05 + Double(seed % 4) * 0.14),
            .scale(to: 0.96, duration: 1.3 + Double(seed % 5) * 0.11)
        ])), forKey: "kinetic_rib_breath")
        root.addChildNode(ribBreath)

        let deskSeal = box(width: 0.52, height: 0.006, length: 0.16, color: pressureInk.withAlphaComponent(0.15), position: SCNVector3(0, 0.184, -0.24))
        deskSeal.name = "studentKineticDeskEdgeSeal"
        deskSeal.eulerAngles.y = Float(seed % 7 - 3) * 0.018
        root.addChildNode(deskSeal)

        let seatBack = box(width: 0.46, height: 0.15, length: 0.01, color: pressureInk.withAlphaComponent(0.1), position: SCNVector3(0, 0.43, 0.17))
        seatBack.name = "studentKineticSeatBackRubShadow"
        root.addChildNode(seatBack)

        let hipWeight = box(width: 0.44, height: 0.006, length: 0.15, color: pressureInk.withAlphaComponent(0.14), position: SCNVector3(0, 0.044, 0.15))
        hipWeight.name = "studentKineticHipWeightPool"
        hipWeight.eulerAngles.y = Float(seed % 5 - 2) * 0.02
        root.addChildNode(hipWeight)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"

            let shoulder = box(width: 0.18, height: 0.036, length: 0.012, color: bodyWarm.withAlphaComponent(0.14), position: SCNVector3(side * 0.18, 0.7, -0.206))
            shoulder.name = "studentKinetic\(sideName)ShoulderLead"
            shoulder.eulerAngles.z = side * (0.14 + Float(seed % 4) * 0.018)
            root.addChildNode(shoulder)

            let sleeveBrake = capsule(radius: 0.0038, height: 0.24, color: pressureInk.withAlphaComponent(0.13), position: SCNVector3(side * 0.205, 0.47, -0.204), rotation: SCNVector4(0, 0, 1, side * 0.58))
            sleeveBrake.name = "studentKinetic\(sideName)SleeveBrakeLine"
            root.addChildNode(sleeveBrake)

            let wristPlant = box(width: 0.17, height: 0.005, length: 0.032, color: pressureInk.withAlphaComponent(0.15), position: SCNVector3(side * 0.15, 0.224, -0.275))
            wristPlant.name = "studentKinetic\(sideName)WristPlantShadow"
            wristPlant.eulerAngles.y = side * 0.18
            root.addChildNode(wristPlant)

            let footSlide = box(width: 0.2, height: 0.004, length: 0.055, color: pressureInk.withAlphaComponent(0.12), position: SCNVector3(side * 0.12, 0.052, 0.085 + Float(sideIndex) * 0.035))
            footSlide.name = "studentKinetic\(sideName)FootSlideTrace"
            footSlide.eulerAngles.y = side * 0.08
            root.addChildNode(footSlide)
        }

        let writingDrag = box(width: 0.34, height: 0.0035, length: 0.018, color: pressureInk.withAlphaComponent(0.16), position: SCNVector3(-0.13, 0.206, -0.286))
        writingDrag.name = "studentKineticWritingDragRead"
        writingDrag.eulerAngles.y = -0.24 + Float(seed % 4) * 0.04
        root.addChildNode(writingDrag)

        let phonePocket = box(width: 0.34, height: 0.006, length: 0.18, color: phoneBlue, position: SCNVector3(0.16, 0.236, -0.19))
        phonePocket.name = "studentKineticPhonePocketColdRim"
        phonePocket.eulerAngles.y = 0.16
        root.addChildNode(phonePocket)

        let coverMass = box(width: 0.4, height: 0.14, length: 0.01, color: pressureInk.withAlphaComponent(0.16), position: SCNVector3(-0.02, 0.58, -0.208))
        coverMass.name = "studentKineticCoverMassBlock"
        coverMass.eulerAngles.y = -0.14
        root.addChildNode(coverMass)

        let helpCounter = capsule(radius: 0.004, height: 0.4, color: helpGreen, position: SCNVector3(-0.3, 0.32, -0.05), rotation: SCNVector4(0, 0, 1, -0.88))
        helpCounter.name = "studentKineticHelpReachCounterline"
        root.addChildNode(helpCounter)

        let freezePlate = box(width: 0.58, height: 0.24, length: 0.009, color: rimCool.withAlphaComponent(0.1), position: SCNVector3(0, 0.54, -0.214))
        freezePlate.name = "studentKineticTeacherFreezePlate"
        freezePlate.eulerAngles.z = Float(seed % 5 - 2) * 0.014
        root.addChildNode(freezePlate)

        for index in 0..<4 {
            let shoulderRipple = box(width: 0.42 - CGFloat(index) * 0.05, height: 0.005, length: 0.014, color: rimCool.withAlphaComponent(0.08), position: SCNVector3(0, 0.72 - Float(index) * 0.06, -0.214))
            shoulderRipple.name = "studentKineticShoulderRipple\(index)"
            shoulderRipple.eulerAngles.z = Float(index - 1) * 0.018
            root.addChildNode(shoulderRipple)
        }

        root.opacity = 0.1
        return root
    }

