        paperLift.eulerAngles.x = 0.035
        paperLift.eulerAngles.y = -0.1 + Float(seed % 5) * 0.035
        root.addChildNode(paperLift)

        for index in 0..<4 {
            let curl = box(width: 0.13 - CGFloat(index) * 0.014, height: 0.003, length: 0.012, color: paperWarm.withAlphaComponent(0.16), position: SCNVector3(-0.26 + Float(index) * 0.085, 0.214 + Float(index % 2) * 0.003, -0.142 - Float(index % 2) * 0.035))
