        }

        let pencilTrail = box(width: 0.42, height: 0.003, length: 0.014, color: graphite, position: SCNVector3(-0.12, 0.218, -0.286))
        pencilTrail.name = "studentDeskInteractionPencilTrail"
        pencilTrail.eulerAngles.y = -0.28 + Float(seed % 4) * 0.05
        root.addChildNode(pencilTrail)

        for index in 0..<5 {
            let scratch = box(width: 0.06 + CGFloat(index % 3) * 0.025, height: 0.0025, length: 0.004, color: graphite.withAlphaComponent(0.12), position: SCNVector3(-0.28 + Float(index) * 0.08, 0.222, -0.304 + Float(index % 2) * 0.02))
            scratch.name = "studentDeskInteractionGraphiteScratch\(index)"
            scratch.eulerAngles.y = -0.34 + Float(index) * 0.12
            root.addChildNode(scratch)
        }

        let phoneLeak = roundedBox(width: 0.24, height: 0.004, length: 0.18, chamfer: 0.016, color: phoneBlue, position: SCNVector3(0.18, 0.224, -0.19))
        phoneLeak.name = "studentDeskInteractionPhoneEdgeLeak"
        phoneLeak.eulerAngles.y = 0.16
        root.addChildNode(phoneLeak)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"

            let wristBridge = box(width: 0.24, height: 0.004, length: 0.06, color: pressureInk, position: SCNVector3(side * 0.12, 0.211, -0.19))
            wristBridge.name = "studentDeskInteraction\(sideName)WristShadowBridge"
            wristBridge.eulerAngles.y = side * 0.16
            root.addChildNode(wristBridge)

            let palmOil = sphere(radius: 0.04, color: skinOil, position: SCNVector3(side * 0.12, 0.224, -0.216), scale: SCNVector3(1.8, 0.08, 0.72))
            palmOil.name = "studentDeskInteraction\(sideName)PalmOilPrint"
            palmOil.eulerAngles.y = side * 0.22
            root.addChildNode(palmOil)

            let sleeveDrag = box(width: 0.25, height: 0.003, length: 0.035, color: sleeveDust, position: SCNVector3(side * 0.15, 0.219, -0.252))
            sleeveDrag.name = "studentDeskInteraction\(sideName)SleeveDragDust"
            sleeveDrag.eulerAngles.y = side * (0.34 + Float(seed % 4) * 0.03)
            root.addChildNode(sleeveDrag)

            for fingerIndex in 0..<3 {
                let fingerSmear = box(width: 0.07, height: 0.0025, length: 0.012, color: pressureInk.withAlphaComponent(0.11), position: SCNVector3(side * (0.06 + Float(fingerIndex) * 0.035), 0.226, -0.278 + Float(fingerIndex % 2) * 0.026))
                fingerSmear.name = "studentDeskInteraction\(sideName)FingerSmear\(fingerIndex)"
                fingerSmear.eulerAngles.y = side * (0.22 + Float(fingerIndex) * 0.08)
                root.addChildNode(fingerSmear)
            }
        }

        let tearDrop = sphere(radius: 0.012, color: tearCool, position: SCNVector3(-0.07, 0.226, -0.126), scale: SCNVector3(1.0, 0.18, 1.35))
        tearDrop.name = "studentDeskInteractionTearDrop"
        tearDrop.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.28)
        root.addChildNode(tearDrop)

        let breathFog = box(width: 0.32, height: 0.04, length: 0.014, color: NSColor(calibratedRed: 0.72, green: 0.84, blue: 1.0, alpha: 0.06), position: SCNVector3(0.0, 0.49, -0.194))
        breathFog.name = "studentDeskInteractionBreathDeskFog"
