        teacherFreezeCut.eulerAngles.y = Float(seed % 5 - 2) * 0.02
        root.addChildNode(teacherFreezeCut)

        root.opacity = 0.1
        return root
    }

    private func makeStudentHeroFocusLODLayer(seed: Int, profile: ClassmateProfile?, uniformColor: NSColor) -> SCNNode {
        let root = SCNNode()
