        let anxiety = (profile?.anxiety ?? 50) / 100
        let empathy = (profile?.empathy ?? 50) / 100
        let rebellious = (profile?.rebelliousness ?? 50) / 100
        let orderliness = (profile?.orderliness ?? 50) / 100
        let clothCatch = uniformColor.blended(withFraction: 0.38, of: .white) ?? uniformColor
        let clothShadow = uniformColor.blended(withFraction: 0.48, of: .black) ?? uniformColor
        let skinWarm = skinColor(seed).blended(withFraction: 0.18, of: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.58, alpha: 1)) ?? skinColor(seed)

        let bodySilhouette = box(width: 0.54, height: 0.62, length: 0.018, color: NSColor(calibratedWhite: 0.0, alpha: 0.16), position: SCNVector3(0.0, 0.5, 0.155))
