            let lowerLid = box(width: 0.064, height: 0.006, length: 0.004, color: NSColor(calibratedRed: 0.95, green: 0.74, blue: 0.62, alpha: CGFloat(0.18 + anxiety * 0.08)), position: SCNVector3(side * 0.052, 0.89, -0.176))
