            let cheekPlane = box(width: 0.07, height: 0.045, length: 0.004, color: NSColor(calibratedRed: 1.0, green: 0.46, blue: 0.42, alpha: CGFloat(0.08 + anxiety * 0.08)), position: SCNVector3(side * 0.076, 0.842, -0.17))
            cheekPlane.name = "studentHeroFocus\(sideName)CheekVolume"
