            let collarEdge = box(width: 0.15, height: 0.01, length: 0.008, color: clothCatch.withAlphaComponent(0.26), position: SCNVector3(side * 0.084, 0.702, -0.156))
            collarEdge.name = "studentHeroFocus\(sideName)CollarEdge"
            collarEdge.eulerAngles.z = side * -0.34
            root.addChildNode(collarEdge)

            let sleeveCrest = box(width: 0.22, height: 0.012, length: 0.01, color: clothCatch.withAlphaComponent(0.2), position: SCNVector3(side * 0.245, 0.47, -0.13))
            sleeveCrest.name = "studentHeroFocus\(sideName)SleeveCrest"
            sleeveCrest.eulerAngles.z = side * -0.28
            root.addChildNode(sleeveCrest)

            let wristSeal = box(width: 0.18, height: 0.006, length: 0.026, color: NSColor(calibratedWhite: 0.0, alpha: 0.16), position: SCNVector3(side * 0.135, 0.226, -0.206))
