            wristSeal.eulerAngles.y = side * 0.12
            root.addChildNode(wristSeal)
        }

        let throatShadow = box(width: 0.11, height: 0.034, length: 0.006, color: NSColor(calibratedWhite: 0.0, alpha: CGFloat(0.15 + anxiety * 0.08)), position: SCNVector3(0, 0.735, -0.16))
        throatShadow.name = "studentHeroFocusThroatTension"
        root.addChildNode(throatShadow)

        let chestPlane = roundedBox(width: 0.28, height: 0.17, length: 0.012, chamfer: 0.018, color: clothShadow.withAlphaComponent(0.2), position: SCNVector3(0, 0.575, -0.145))
