            ? NSColor(calibratedRed: 0.42, green: 1.0, blue: 0.76, alpha: 0.16)
            : NSColor(calibratedRed: 0.68, green: 0.82, blue: 1.0, alpha: 0.14)
        let gazeThread = box(width: 0.34, height: 0.006, length: 0.004, color: gazeThreadColor, position: SCNVector3(0.0, 0.908, -0.182))
        gazeThread.name = "studentHeroFocusGazeThread"
        gazeThread.geometry?.firstMaterial?.emission.contents = gazeThreadColor
