        let phonePocketGlow = roundedBox(width: 0.18, height: 0.034, length: 0.006, chamfer: 0.012, color: NSColor(calibratedRed: 0.2, green: 0.42, blue: 1.0, alpha: CGFloat(0.1 + rebellious * 0.08)), position: SCNVector3(0.13, 0.42, -0.152))
