        neatEdge.name = "studentHeroFocusUniformPressLine"
        root.addChildNode(neatEdge)

        for index in 0..<7 {
            let hairFiber = box(width: 0.006, height: 0.12 - CGFloat(index % 3) * 0.014, length: 0.004, color: NSColor(calibratedWhite: 0.9, alpha: 0.08), position: SCNVector3(-0.102 + Float(index) * 0.034, 0.985 - Float(index % 2) * 0.018, -0.135))
            hairFiber.name = "studentHeroFocusHairFiber\(index)"
            hairFiber.eulerAngles.z = -0.28 + Float(index) * 0.09
            root.addChildNode(hairFiber)
        }

        for index in 0..<6 {
            let microCatch = box(width: 0.055 + CGFloat(index % 3) * 0.018, height: 0.004, length: 0.004, color: clothCatch.withAlphaComponent(0.14), position: SCNVector3(-0.22 + Float(index) * 0.088, 0.518 - Float(index % 2) * 0.052, -0.166))
            microCatch.name = "studentHeroFocusUniformMicroCatch\(index)"
            microCatch.eulerAngles.z = -0.18 + Float(index) * 0.075
            root.addChildNode(microCatch)
        }

        for index in 0..<4 {
            let dust = sphere(radius: 0.006 + CGFloat(index % 2) * 0.002, color: NSColor(calibratedRed: 0.95, green: 0.9, blue: 0.78, alpha: 0.1), position: SCNVector3(-0.14 + Float(index) * 0.095, 0.78 + Float(index % 2) * 0.065, -0.19), scale: SCNVector3(1.0, 0.4, 0.16))
            dust.name = "studentHeroFocusBreathDust\(index)"
            root.addChildNode(dust)
        }

        root.opacity = 0.08
        return root
    }

