            let wristTendon = capsule(radius: 0.0045, height: 0.13, color: boneCatch.withAlphaComponent(0.12), position: SCNVector3(side * 0.126, 0.252, -0.188), rotation: SCNVector4(0, 0, 1, CGFloat(side) * 1.32))
            wristTendon.name = "studentAnatomy\(sideName)WristTendonLine"
