            palmHeel.name = "studentAnatomy\(sideName)PalmHeelDeskSeal"
            root.addChildNode(palmHeel)

            let hipPocket = sphere(radius: 0.08, color: clothDark, position: SCNVector3(side * 0.12, 0.405, 0.02), scale: SCNVector3(1.1, 0.42, 0.72))
