            let kneeCap = sphere(radius: 0.05, color: clothLight.withAlphaComponent(0.16), position: SCNVector3(side * 0.12, 0.18, -0.035), scale: SCNVector3(1.12, 0.5, 0.92))
            kneeCap.name = "studentAnatomy\(sideName)KneeCapPlane"
            root.addChildNode(kneeCap)

            let ankleSeal = box(width: 0.11, height: 0.006, length: 0.035, color: deskSeal.withAlphaComponent(0.12), position: SCNVector3(side * 0.13, 0.066, -0.075))
            ankleSeal.name = "studentAnatomy\(sideName)AnkleFloorSeal"
