        }

        root.opacity = 0.1
        return root
    }

    private func makeStudentIdentityPropLayer(seed: Int, profile: ClassmateProfile?, uniformColor: NSColor) -> SCNNode {
        let root = SCNNode()
        root.name = "studentIdentityPropLayer"
        let rebellious = profile?.rebelliousness ?? 0
        let orderliness = profile?.orderliness ?? 0
        let empathy = profile?.empathy ?? 0
        let anxiety = profile?.anxiety ?? 0
        let bagColor: NSColor
        if rebellious > 72 {
            bagColor = NSColor(calibratedRed: 0.32, green: 0.06, blue: 0.11, alpha: 1)
        } else if empathy > 72 {
            bagColor = NSColor(calibratedRed: 0.08, green: 0.28, blue: 0.24, alpha: 1)
        } else if orderliness > 72 {
            bagColor = NSColor(calibratedRed: 0.08, green: 0.1, blue: 0.24, alpha: 1)
        } else {
            bagColor = NSColor(calibratedRed: 0.12 + CGFloat(seed % 3) * 0.04, green: 0.12, blue: 0.16 + CGFloat(seed % 2) * 0.05, alpha: 1)
        }
        let bagHighlight = bagColor.blended(withFraction: 0.28, of: .white) ?? bagColor
        let bagShadow = bagColor.blended(withFraction: 0.38, of: .black) ?? bagColor
        let strapColor = uniformColor.blended(withFraction: 0.52, of: .black) ?? uniformColor

        let backpack = roundedBox(width: 0.34, height: 0.34, length: 0.14, chamfer: 0.045, color: bagColor, position: SCNVector3(0.0, 0.54, 0.18))
        backpack.name = "studentBackpackBody"
        backpack.eulerAngles.x = -0.05
        root.addChildNode(backpack)
        let bagPocket = roundedBox(width: 0.22, height: 0.12, length: 0.028, chamfer: 0.018, color: bagShadow.withAlphaComponent(0.92), position: SCNVector3(0.0, 0.47, 0.25))
        bagPocket.name = "studentBackpackPocket"
        root.addChildNode(bagPocket)
        let bagCatch = box(width: 0.24, height: 0.012, length: 0.018, color: bagHighlight.withAlphaComponent(0.42), position: SCNVector3(-0.025, 0.68, 0.255))
        bagCatch.name = "studentBackpackTopCatch"
        bagCatch.eulerAngles.z = -0.08
        root.addChildNode(bagCatch)

        let leftStrap = capsule(radius: 0.006, height: 0.48, color: strapColor, position: SCNVector3(-0.13, 0.55, -0.118), rotation: SCNVector4(0, 0, 1, -0.08))
        leftStrap.name = "studentLeftShoulderBagStrap"
        root.addChildNode(leftStrap)
        let rightStrap = capsule(radius: 0.006, height: 0.48, color: strapColor, position: SCNVector3(0.13, 0.55, -0.118), rotation: SCNVector4(0, 0, 1, 0.08))
        rightStrap.name = "studentRightShoulderBagStrap"
        root.addChildNode(rightStrap)

        let zipper = box(width: 0.18, height: 0.006, length: 0.012, color: NSColor(calibratedWhite: 0.86, alpha: 0.58), position: SCNVector3(0.02, 0.49, 0.274))
        zipper.name = "studentBackpackZipperCatch"
        zipper.eulerAngles.z = -0.08 + Float(seed % 4) * 0.04
        root.addChildNode(zipper)

        if seed % 3 != 1 || empathy > 72 {
            let bottleColor = empathy > 72
                ? NSColor(calibratedRed: 0.34, green: 0.82, blue: 0.72, alpha: 0.76)
                : NSColor(calibratedRed: 0.42, green: 0.62, blue: 1.0, alpha: 0.68)
            let bottle = capsule(radius: 0.024, height: 0.18, color: bottleColor, position: SCNVector3(0.24, 0.43, 0.14), rotation: SCNVector4(1, 0, 0, 0.08))
            bottle.name = "studentSideBottle"
            root.addChildNode(bottle)
            let cap = box(width: 0.042, height: 0.022, length: 0.032, color: NSColor(calibratedWhite: 0.9, alpha: 0.82), position: SCNVector3(0.24, 0.52, 0.14))
            cap.name = "studentBottleCap"
            root.addChildNode(cap)
        }

        if rebellious > 72 || seed % 4 == 0 {
            let charmColor = rebellious > 72
                ? NSColor(calibratedRed: 1.0, green: 0.2, blue: 0.32, alpha: 0.82)
                : NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.22, alpha: 0.82)
            let charmCord = capsule(radius: 0.003, height: 0.13, color: NSColor(calibratedWhite: 0.08, alpha: 0.8), position: SCNVector3(-0.18, 0.42, 0.24))
            charmCord.name = "studentBagCharmCord"
            root.addChildNode(charmCord)
            let charm = sphere(radius: 0.026, color: charmColor, position: SCNVector3(-0.18, 0.34, 0.24), scale: SCNVector3(0.9, 1.0, 0.6))
            charm.name = "studentBagCharm"
            charm.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: 0.18, duration: 0.7 + Double(seed % 3) * 0.12),
                .rotateBy(x: 0, y: 0, z: -0.18, duration: 0.9 + Double(seed % 4) * 0.1)
            ])), forKey: "student_bag_charm_sway")
            root.addChildNode(charm)
        }

        let watchBand = capsule(radius: 0.004, height: 0.06, color: NSColor(calibratedWhite: 0.04, alpha: 0.82), position: SCNVector3(-0.224, 0.27, -0.08), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        watchBand.name = "studentWatchBand"
        watchBand.opacity = orderliness > 68 || seed % 5 == 0 ? 0.82 : 0.22
        root.addChildNode(watchBand)
        let watchFace = sphere(radius: 0.014, color: NSColor(calibratedWhite: 0.92, alpha: 0.68), position: SCNVector3(-0.224, 0.272, -0.108), scale: SCNVector3(1.0, 0.55, 0.22))
        watchFace.name = "studentWatchFaceGlint"
        watchFace.opacity = watchBand.opacity
        root.addChildNode(watchFace)

        let leftLace = box(width: 0.085, height: 0.004, length: 0.01, color: NSColor(calibratedWhite: 0.9, alpha: 0.54), position: SCNVector3(-0.088, -0.43, -0.166))
        leftLace.name = "studentLeftShoeLace"
        leftLace.eulerAngles.y = -0.16
        root.addChildNode(leftLace)
        let rightLace = box(width: 0.085, height: 0.004, length: 0.01, color: NSColor(calibratedWhite: 0.9, alpha: 0.54), position: SCNVector3(0.088, -0.43, -0.166))
        rightLace.name = "studentRightShoeLace"
        rightLace.eulerAngles.y = 0.16
        root.addChildNode(rightLace)

        if anxiety > 68 {
            let foldedTissue = roundedBox(width: 0.09, height: 0.028, length: 0.065, chamfer: 0.009, color: NSColor(calibratedWhite: 0.96, alpha: 0.86), position: SCNVector3(-0.24, 0.232, -0.1))
            foldedTissue.name = "studentPocketTissue"
            foldedTissue.eulerAngles.y = -0.1
            root.addChildNode(foldedTissue)
        }

        if seed % 2 == 0 || rebellious > 72 {
            let clipColor = rebellious > 72
                ? NSColor(calibratedRed: 1.0, green: 0.22, blue: 0.36, alpha: 0.92)
                : NSColor(calibratedRed: 0.84, green: 0.88, blue: 1.0, alpha: 0.78)
            let sideClip = box(width: 0.058, height: 0.01, length: 0.014, color: clipColor, position: SCNVector3(-0.132, 0.965, -0.118))
            sideClip.name = "studentSideHairClip"
            sideClip.eulerAngles.z = -0.24
            root.addChildNode(sideClip)
        }

        root.opacity = 0.86
        return root
    }

    private func makeStudentLocalLightTransportLayer(seed: Int, profile: ClassmateProfile?, uniformColor: NSColor) -> SCNNode {
        let root = SCNNode()
        root.name = "studentLocalLightTransportLayer"
        let windowBlue = NSColor(calibratedRed: 0.48, green: 0.68, blue: 1.0, alpha: 0.12)
        let deskAmber = NSColor(calibratedRed: 1.0, green: 0.7, blue: 0.34, alpha: 0.1)
        let phoneBlue = NSColor(calibratedRed: 0.12, green: 0.34, blue: 1.0, alpha: 0.16)
        let warmSkin = skinColor(seed).withAlphaComponent(0.14)
        let pressureRed = NSColor(calibratedRed: 1.0, green: 0.28, blue: 0.12, alpha: 0.12)
        let contactInk = NSColor(calibratedWhite: 0.0, alpha: 0.14)
        let clothLift = uniformColor.blended(withFraction: 0.26, of: .white) ?? uniformColor

        let windowShoulder = capsule(radius: 0.005, height: 0.62, color: windowBlue, position: SCNVector3(-0.24, 0.62, -0.142), rotation: SCNVector4(0, 0, 1, 0.08))
        windowShoulder.name = "studentLocalWindowShoulderWrap"
        root.addChildNode(windowShoulder)

        let headRim = capsule(radius: 0.004, height: 0.28, color: windowBlue.withAlphaComponent(0.16), position: SCNVector3(-0.108, 0.91, -0.132), rotation: SCNVector4(0, 0, 1, 0.18))
        headRim.name = "studentLocalHeadWindowRim"
        root.addChildNode(headRim)

        let deskBounce = box(width: 0.48, height: 0.006, length: 0.092, color: deskAmber, position: SCNVector3(0.0, 0.236, -0.164))
        deskBounce.name = "studentLocalDeskBounceUnderHands"
        deskBounce.eulerAngles.y = -0.04 + Float(seed % 5) * 0.018
        root.addChildNode(deskBounce)

        let skinBounce = sphere(radius: 0.052, color: warmSkin, position: SCNVector3(-0.02, 0.266, -0.16), scale: SCNVector3(2.8, 0.16, 0.82))
        skinBounce.name = "studentLocalSkinDeskBounce"
        root.addChildNode(skinBounce)

        let phonePocket = box(width: 0.32, height: 0.006, length: 0.17, color: phoneBlue, position: SCNVector3(0.17, 0.246, -0.18))
        phonePocket.name = "studentLocalPhoneLightPocket"
        phonePocket.eulerAngles.y = 0.1
        root.addChildNode(phonePocket)

        let facePhoneCast = box(width: 0.18, height: 0.038, length: 0.006, color: phoneBlue.withAlphaComponent(0.12), position: SCNVector3(0.04, 0.82, -0.16))
        facePhoneCast.name = "studentLocalPhoneFaceCast"
        root.addChildNode(facePhoneCast)

        let teacherTargetShadow = box(width: 0.52, height: 0.008, length: 0.18, color: pressureRed, position: SCNVector3(0.02, 0.154, -0.25))
        teacherTargetShadow.name = "studentLocalTeacherTargetPressure"
        teacherTargetShadow.eulerAngles.y = -0.12
        root.addChildNode(teacherTargetShadow)

        let deskContactBridge = box(width: 0.6, height: 0.005, length: 0.13, color: contactInk, position: SCNVector3(0.0, 0.188, -0.236))
        deskContactBridge.name = "studentLocalDeskContactBridge"
        root.addChildNode(deskContactBridge)

        let chairOcclusion = box(width: 0.48, height: 0.22, length: 0.012, color: contactInk.withAlphaComponent(0.12), position: SCNVector3(0.0, 0.48, 0.17))
        chairOcclusion.name = "studentLocalChairBackOcclusion"
        root.addChildNode(chairOcclusion)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let sleeveCatch = capsule(radius: 0.004, height: 0.28, color: clothLift.withAlphaComponent(0.16), position: SCNVector3(side * 0.18, 0.42, -0.15), rotation: SCNVector4(0, 0, 1, side * 0.46))
            sleeveCatch.name = "studentLocal\(sideName)SleeveLightCatch"
            root.addChildNode(sleeveCatch)

            let handPool = sphere(radius: 0.034, color: warmSkin.withAlphaComponent(0.12), position: SCNVector3(side * 0.13, 0.236, -0.2), scale: SCNVector3(1.6, 0.22, 0.72))
            handPool.name = "studentLocal\(sideName)HandBouncePool"
            root.addChildNode(handPool)

            let footDark = sphere(radius: 0.05, color: contactInk.withAlphaComponent(0.16), position: SCNVector3(side * 0.13, -0.42, -0.14), scale: SCNVector3(1.6, 0.12, 0.72))
            footDark.name = "studentLocal\(sideName)FootGroundSeal"
            root.addChildNode(footDark)
        }

        for index in 0..<5 {
            let dust = sphere(radius: 0.004 + CGFloat(index % 2) * 0.001, color: deskAmber.withAlphaComponent(0.12), position: SCNVector3(-0.18 + Float(index) * 0.09, 0.284 + Float(index % 2) * 0.018, -0.245), scale: SCNVector3(1.3, 0.42, 0.7))
            dust.name = "studentLocalDeskDustMote\(index)"
            dust.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.004, y: 0.016, z: 0.004, duration: 0.9 + Double(index) * 0.08),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.004, y: -0.016, z: -0.004, duration: 1.1 + Double(index) * 0.08)
            ])), forKey: "student_local_desk_dust")
            root.addChildNode(dust)
        }

        if profile?.rebelliousness ?? 0 > 72 {
            phonePocket.opacity = 0.22
            facePhoneCast.opacity = 0.16
        }

        root.opacity = 0.12
        return root
    }

    private func makeHairDetail(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let hairColor = NSColor(calibratedWhite: 0.025 + CGFloat(seed % 4) * 0.025, alpha: 1)
        let highlightColor = hairColor.blended(withFraction: 0.28, of: .white) ?? hairColor
        let shadowColor = hairColor.blended(withFraction: 0.34, of: .black) ?? hairColor
        let bangCount = 2 + seed % 3
        for index in 0..<bangCount {
            let bang = capsule(radius: 0.014, height: 0.13 + CGFloat(index % 2) * 0.035, color: hairColor, position: SCNVector3(-0.07 + Float(index) * 0.055, 0.91, -0.12), rotation: SCNVector4(1, 0, 0, 0.55))
            bang.eulerAngles.z = CGFloat(index - 1) * 0.12
            root.addChildNode(bang)
        }
        for index in 0..<5 {
            let side: Float = index % 2 == 0 ? -1.0 : 1.0
            let strand = capsule(
                radius: 0.007 + CGFloat(index % 2) * 0.002,
                height: 0.16 + CGFloat(index % 3) * 0.035,
                color: index == 2 ? highlightColor : shadowColor,
                position: SCNVector3(side * (0.118 + Float(index % 3) * 0.012), 0.895 - Float(index) * 0.018, -0.055 + Float(index % 2) * 0.06),
                rotation: SCNVector4(1, 0, 0, 0.22 + Float(index) * 0.03)
            )
            strand.name = "studentHairSideStrand\(index)"
            strand.eulerAngles.z = CGFloat(side) * (0.24 + CGFloat(index) * 0.035)
            strand.opacity = 0.88
            root.addChildNode(strand)
        }
        for index in 0..<4 {
            let crown = capsule(radius: 0.0045, height: 0.18 + CGFloat(index) * 0.018, color: highlightColor.withAlphaComponent(0.56), position: SCNVector3(-0.065 + Float(index) * 0.045, 1.045, -0.04 + Float(index % 2) * 0.035), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            crown.name = "studentHairCrownHighlight\(index)"
            crown.eulerAngles.y = -0.18 + Float(index) * 0.1
            root.addChildNode(crown)
        }
        let napeShadow = capsule(radius: 0.018, height: 0.18, color: shadowColor.withAlphaComponent(0.72), position: SCNVector3(0, 0.84, 0.112), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        napeShadow.name = "studentHairNapeShadow"
        root.addChildNode(napeShadow)

        if profile?.empathy ?? 0 > 72 || seed % 5 == 0 {
            let tie = capsule(radius: 0.022, height: 0.22, color: hairColor, position: SCNVector3(0.13, 0.82, 0.08), rotation: SCNVector4(1, 0, 0, 0.12))
            tie.eulerAngles.z = -0.18
            root.addChildNode(tie)
            root.addChildNode(sphere(radius: 0.032, color: NSColor(calibratedRed: 0.28, green: 0.08, blue: 0.12, alpha: 1), position: SCNVector3(0.12, 0.9, 0.075), scale: SCNVector3(1, 0.55, 1)))
        }

        if profile?.rebelliousness ?? 0 > 72 {
            let clip = box(width: 0.08, height: 0.012, length: 0.018, color: NSColor(calibratedRed: 0.86, green: 0.18, blue: 0.28, alpha: 1), position: SCNVector3(-0.11, 0.98, -0.12))
            clip.eulerAngles.z = -0.3
            root.addChildNode(clip)
        }
        return root
    }

    private func makeStudentFaceVolumeDetails(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let skin = skinColor(seed)
        let warm = NSColor(calibratedRed: 0.95, green: 0.55, blue: 0.42, alpha: 1)
        let coolShadow = NSColor(calibratedRed: 0.18, green: 0.1, blue: 0.12, alpha: 1)
        let anxious = (profile?.anxiety ?? 0) > 68
        let faceHighlight = skin.blended(withFraction: 0.18, of: .white) ?? skin
        let faceShadow = skin.blended(withFraction: anxious ? 0.2 : 0.12, of: coolShadow) ?? skin

        let forehead = sphere(radius: 0.048, color: faceHighlight.withAlphaComponent(0.5), position: SCNVector3(0, 0.07, -0.126), scale: SCNVector3(1.25, 0.38, 0.18))
        forehead.name = "studentForeheadSoftHighlight"
        root.addChildNode(forehead)
        let noseBridge = capsule(radius: 0.004, height: 0.052, color: faceHighlight.withAlphaComponent(0.68), position: SCNVector3(0.008, 0.018, -0.166))
        noseBridge.name = "studentNoseBridgeHighlight"
        root.addChildNode(noseBridge)
        let jawShadow = capsule(radius: 0.006, height: 0.14, color: faceShadow.withAlphaComponent(0.38), position: SCNVector3(0, -0.095, -0.126), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        jawShadow.name = "studentJawAmbientShadow"
        root.addChildNode(jawShadow)
        let leftEyeSocket = capsule(radius: 0.004, height: 0.07, color: faceShadow.withAlphaComponent(anxious ? 0.62 : 0.32), position: SCNVector3(-0.052, 0.018, -0.161), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        let rightEyeSocket = capsule(radius: 0.004, height: 0.07, color: faceShadow.withAlphaComponent(anxious ? 0.62 : 0.32), position: SCNVector3(0.052, 0.018, -0.161), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        leftEyeSocket.name = "leftEyeSocketShadow"
        rightEyeSocket.name = "rightEyeSocketShadow"
        root.addChildNode(leftEyeSocket)
        root.addChildNode(rightEyeSocket)
        root.addChildNode(sphere(radius: 0.018, color: skin.blended(withFraction: 0.12, of: warm)?.withAlphaComponent(0.42) ?? skin, position: SCNVector3(-0.088, -0.014, -0.151), scale: SCNVector3(1.35, 0.48, 0.16)))
        root.addChildNode(sphere(radius: 0.018, color: skin.blended(withFraction: 0.12, of: warm)?.withAlphaComponent(0.42) ?? skin, position: SCNVector3(0.088, -0.014, -0.151), scale: SCNVector3(1.35, 0.48, 0.16)))
        return root
    }

