        let root = SCNNode()
        root.name = "studentEmotionalFaceLayer"
        let wet = NSColor(calibratedRed: 0.78, green: 0.9, blue: 1.0, alpha: 0.24)
        let tear = NSColor(calibratedRed: 0.7, green: 0.86, blue: 1.0, alpha: 0.22)
