        let phoneBlue = NSColor(calibratedRed: 0.24, green: 0.44, blue: 1.0, alpha: 0.18)
        let tension = NSColor(calibratedRed: 0.2, green: 0.08, blue: 0.08, alpha: 0.18)
        let sweat = NSColor(calibratedRed: 0.74, green: 0.9, blue: 1.0, alpha: 0.2)

        let leftWet = capsule(radius: 0.0028, height: 0.07, color: wet, position: SCNVector3(-0.052, 0.016, -0.171), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        leftWet.name = "leftEyeWetLine"
        root.addChildNode(leftWet)
        let rightWet = capsule(radius: 0.0028, height: 0.07, color: wet, position: SCNVector3(0.052, 0.016, -0.171), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        rightWet.name = "rightEyeWetLine"
        root.addChildNode(rightWet)

        let leftTear = capsule(radius: 0.0025, height: 0.088, color: tear, position: SCNVector3(-0.064, -0.032, -0.17), rotation: SCNVector4(1, 0, 0, 0.08))
        leftTear.name = "leftTearTrack"
        root.addChildNode(leftTear)
        let rightTear = capsule(radius: 0.0025, height: 0.078, color: tear, position: SCNVector3(0.06, -0.03, -0.17), rotation: SCNVector4(1, 0, 0, -0.08))
        rightTear.name = "rightTearTrack"
        root.addChildNode(rightTear)

        let leftBlush = sphere(radius: 0.018, color: blush, position: SCNVector3(-0.09, -0.018, -0.166), scale: SCNVector3(1.5, 0.45, 0.16))
        leftBlush.name = "leftCheekStressFlush"
        root.addChildNode(leftBlush)
        let rightBlush = sphere(radius: 0.018, color: blush, position: SCNVector3(0.09, -0.018, -0.166), scale: SCNVector3(1.5, 0.45, 0.16))
        rightBlush.name = "rightCheekStressFlush"
        root.addChildNode(rightBlush)

        let phoneReflection = box(width: 0.12, height: 0.026, length: 0.004, color: phoneBlue, position: SCNVector3(0.028, -0.012, -0.176))
        phoneReflection.name = "phoneFaceReflection"
        phoneReflection.eulerAngles.z = -0.08
        root.addChildNode(phoneReflection)

        let lowerLip = capsule(radius: 0.0026, height: 0.07, color: tension, position: SCNVector3(0, -0.074, -0.171), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        lowerLip.name = "lowerLipTensionLine"
        root.addChildNode(lowerLip)

        for index in 0..<3 {
            let bead = sphere(
                radius: 0.004 + CGFloat(index % 2) * 0.001,
                color: sweat,
                position: SCNVector3(0.074 + Float(index) * 0.018, 0.058 - Float(index % 2) * 0.032, -0.168),
                scale: SCNVector3(0.75, 1.25, 0.2)
            )
            bead.name = "anxietySweatBead\(index)"
            bead.opacity = (profile?.anxiety ?? 0) > 68 ? 0.18 : 0.04
            root.addChildNode(bead)
        }

        for child in root.childNodes where child.name != nil {
            child.opacity = 0
        }
        return root
    }

