    private func makeStudentFacialCinematicFidelityLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentFacialCinematicFidelityLayer"

        let skin = skinColor(seed)
        let anxiety = profile?.anxiety ?? 0
        let empathy = profile?.empathy ?? 50
        let subsurface = skin.blended(withFraction: 0.22, of: NSColor(calibratedRed: 1.0, green: 0.42, blue: 0.3, alpha: 1)) ?? skin
        let pore = skin.blended(withFraction: 0.18, of: .white) ?? skin
        let shadow = skin.blended(withFraction: anxiety > 66 ? 0.28 : 0.18, of: NSColor(calibratedRed: 0.08, green: 0.035, blue: 0.035, alpha: 1)) ?? skin
        let wet = NSColor(calibratedRed: 0.82, green: 0.92, blue: 1.0, alpha: 0.22)
        let lip = NSColor(calibratedRed: 0.64, green: 0.18, blue: 0.16, alpha: 0.2)

        for (sideName, side) in [("Left", -1.0), ("Right", 1.0)] {
            let sideF = Float(side)
            let cheek = sphere(
                radius: 0.026,
                color: subsurface.withAlphaComponent(0.18),
                position: SCNVector3(sideF * 0.082, -0.018, -0.181),
                scale: SCNVector3(1.55, 0.55, 0.1)
            )
            cheek.name = "student\(sideName)SkinSubsurfaceBloom"
            root.addChildNode(cheek)

            let cornea = sphere(
                radius: 0.014,
                color: wet.withAlphaComponent(0.16),
                position: SCNVector3(sideF * 0.052, 0.031, -0.184),
                scale: SCNVector3(1.35, 0.78, 0.08)
            )
            cornea.name = "student\(sideName)CorneaGlassCatch"
