    }

    private func makeStudentSkinEyeMicroMaterialLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentSkinEyeMicroMaterialLayer"

        let skin = skinColor(seed)
        let anxiety = profile?.anxiety ?? 0
        let rebellious = profile?.rebelliousness ?? 0
        let warmSkin = skin.blended(withFraction: 0.18, of: NSColor(calibratedRed: 1.0, green: 0.46, blue: 0.32, alpha: 1)) ?? skin
        let poreLight = skin.blended(withFraction: 0.28, of: .white) ?? skin
        let poreShadow = skin.blended(withFraction: 0.32, of: NSColor(calibratedRed: 0.08, green: 0.035, blue: 0.028, alpha: 1)) ?? skin
        let wet = NSColor(calibratedRed: 0.82, green: 0.94, blue: 1.0, alpha: 0.2)
        let phoneBlue = NSColor(calibratedRed: 0.22, green: 0.48, blue: 1.0, alpha: rebellious > 68 ? 0.16 : 0.08)
        let lipDry = NSColor(calibratedRed: 0.44, green: 0.12, blue: 0.1, alpha: 0.18)
        let tendonShadow = NSColor(calibratedRed: 0.08, green: 0.035, blue: 0.03, alpha: anxiety > 66 ? 0.18 : 0.1)

        for (sideName, side) in [("Left", -1.0), ("Right", 1.0)] {
            let sideF = Float(side)

            let tearFilm = capsule(radius: 0.002, height: 0.074, color: wet.withAlphaComponent(0.22), position: SCNVector3(sideF * 0.052, 0.026, -0.19), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            tearFilm.name = "student\(sideName)TearFilmMeniscus"
            tearFilm.geometry?.firstMaterial?.emission.contents = wet.withAlphaComponent(0.05)
            root.addChildNode(tearFilm)

            let scleraWet = sphere(radius: 0.011, color: wet.withAlphaComponent(0.12), position: SCNVector3(sideF * 0.052, 0.031, -0.191), scale: SCNVector3(1.55, 0.52, 0.055))
            scleraWet.name = "student\(sideName)ScleraWetGlaze"
            scleraWet.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.2)
            root.addChildNode(scleraWet)

            let lowerWater = capsule(radius: 0.0018, height: 0.052, color: wet.withAlphaComponent(0.16), position: SCNVector3(sideF * 0.05, 0.006, -0.19), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            lowerWater.name = "student\(sideName)LowerLidWaterline"
            root.addChildNode(lowerWater)

            let cheekPoreCluster = sphere(radius: 0.013, color: warmSkin.withAlphaComponent(0.08), position: SCNVector3(sideF * 0.09, -0.026, -0.189), scale: SCNVector3(2.0, 0.48, 0.055))
            cheekPoreCluster.name = "student\(sideName)CheekPoreCluster"
            root.addChildNode(cheekPoreCluster)

            let cheekSalt = box(width: 0.05, height: 0.003, length: 0.003, color: wet.withAlphaComponent(0.1), position: SCNVector3(sideF * 0.088, -0.052, -0.191))
            cheekSalt.name = "student\(sideName)CheekTearSaltTrace"
            cheekSalt.eulerAngles.z = sideF * -0.24
            root.addChildNode(cheekSalt)

            let earBack = sphere(radius: 0.015, color: warmSkin.withAlphaComponent(0.1), position: SCNVector3(sideF * 0.153, -0.016, -0.006), scale: SCNVector3(0.45, 1.1, 0.12))
            earBack.name = "student\(sideName)EarBackTranslucency"
            root.addChildNode(earBack)
        }

        for index in 0..<12 {
            let x = -0.06 + Float((index * 19 + seed * 7) % 120) / 1000
            let y = 0.07 - Float((index * 11) % 72) / 1000
            let color = index % 2 == 0 ? poreLight.withAlphaComponent(0.12) : poreShadow.withAlphaComponent(0.08)
            let pore = sphere(radius: 0.0018 + CGFloat(index % 3) * 0.00045, color: color, position: SCNVector3(x, y, -0.191), scale: SCNVector3(1.35, 0.58, 0.04))
            pore.name = "studentSkinMicroPore\(index)"
            root.addChildNode(pore)
        }

        let noseOil = sphere(radius: 0.012, color: poreLight.withAlphaComponent(0.16), position: SCNVector3(0.006, -0.024, -0.193), scale: SCNVector3(0.78, 1.0, 0.06))
        noseOil.name = "studentNoseWingOilSpecular"
        noseOil.geometry?.firstMaterial?.specular.contents = NSColor(calibratedWhite: 1.0, alpha: 0.28)
        root.addChildNode(noseOil)

        let philtrumShadow = capsule(radius: 0.0018, height: 0.035, color: tendonShadow.withAlphaComponent(0.16), position: SCNVector3(0.004, -0.057, -0.192), rotation: SCNVector4(1, 0, 0, 0.08))
        philtrumShadow.name = "studentPhiltrumMicroShadow"
        root.addChildNode(philtrumShadow)

        for index in 0..<3 {
            let crack = box(width: 0.022 + CGFloat(index) * 0.012, height: 0.002, length: 0.003, color: lipDry.withAlphaComponent(0.16), position: SCNVector3(-0.026 + Float(index) * 0.026, -0.082, -0.193))
            crack.name = "studentLipDryCrack\(index)"
            crack.eulerAngles.z = -0.12 + Float(index) * 0.12
            root.addChildNode(crack)
        }

        let phoneUnderGlow = box(width: 0.15, height: 0.035, length: 0.003, color: phoneBlue, position: SCNVector3(0.02, -0.008, -0.194))
        phoneUnderGlow.name = "studentPhoneBlueSkinBounce"
        phoneUnderGlow.eulerAngles.z = -0.08
        root.addChildNode(phoneUnderGlow)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let tendon = capsule(radius: 0.002, height: 0.08, color: tendonShadow, position: SCNVector3(side * 0.026, -0.166, -0.118), rotation: SCNVector4(0, 0, 1, side * 0.12))
            tendon.name = "student\(sideName)NeckTendonMicroShadow"
            root.addChildNode(tendon)
        }

        root.opacity = 0.08
        return root
    }

    private func makeStudentHeadAccessories(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let skin = skinColor(seed)
        let earWarmth = NSColor(calibratedRed: 0.9, green: 0.36, blue: 0.32, alpha: 1)
        let earShadow = NSColor(calibratedWhite: 0.06, alpha: 1)
        root.addChildNode(sphere(radius: 0.026, color: skin.blended(withFraction: 0.04, of: earWarmth) ?? skin, position: SCNVector3(-0.148, -0.004, -0.005), scale: SCNVector3(0.46, 0.8, 0.28)))
        root.addChildNode(sphere(radius: 0.026, color: skin.blended(withFraction: 0.04, of: earWarmth) ?? skin, position: SCNVector3(0.148, -0.004, -0.005), scale: SCNVector3(0.46, 0.8, 0.28)))
        root.addChildNode(sphere(radius: 0.012, color: skin.blended(withFraction: 0.12, of: earShadow) ?? skin, position: SCNVector3(-0.152, -0.006, -0.012), scale: SCNVector3(0.35, 0.6, 0.18)))
        root.addChildNode(sphere(radius: 0.012, color: skin.blended(withFraction: 0.12, of: earShadow) ?? skin, position: SCNVector3(0.152, -0.006, -0.012), scale: SCNVector3(0.35, 0.6, 0.18)))

        if profile?.maskStrength ?? 50 > 70 || seed % 7 == 0 {
            root.addChildNode(makeStudentFaceMask(seed: seed))
        }

        if profile?.orderliness ?? 0 > 76 || seed % 6 == 2 {
            let hairPinColor = profile?.orderliness ?? 0 > 76
                ? NSColor(calibratedRed: 0.82, green: 0.9, blue: 1.0, alpha: 1)
                : NSColor(calibratedRed: 0.92, green: 0.68, blue: 0.22, alpha: 1)
            let pin = box(width: 0.07, height: 0.012, length: 0.018, color: hairPinColor, position: SCNVector3(-0.09, 0.085, -0.125))
            pin.eulerAngles.z = -0.32
            root.addChildNode(pin)
        }

        if profile?.rebelliousness ?? 0 > 76 {
            root.addChildNode(sphere(radius: 0.01, color: NSColor(calibratedRed: 0.92, green: 0.72, blue: 0.22, alpha: 1), position: SCNVector3(0.154, -0.034, -0.016), scale: SCNVector3(0.6, 1.0, 0.6)))
        }
        return root
    }

    private func makeStudentHeadSilhouetteDetailLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentHeadSilhouetteDetailLayer"
        let hairBase = NSColor(calibratedWhite: 0.025 + CGFloat(seed % 4) * 0.025, alpha: 1)
        let hairCatch = hairBase.blended(withFraction: 0.38, of: .white) ?? hairBase
