        let anxious = (profile?.anxiety ?? 0) > 68

        let hairline = capsule(radius: 0.0048, height: 0.2, color: hairShadow.withAlphaComponent(0.78), position: SCNVector3(0, 0.09, -0.158), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
