            let bangShadow = capsule(radius: 0.0036 + CGFloat(index % 2) * 0.001, height: 0.09 + CGFloat(index % 3) * 0.018, color: index == 2 ? hairCatch.withAlphaComponent(0.46) : hairShadow.withAlphaComponent(0.72), position: SCNVector3(x, 0.075 - Float(index % 2) * 0.012, -0.164), rotation: SCNVector4(1, 0, 0, 0.48))
            bangShadow.name = "studentBangCastStrand\(index)"
            bangShadow.eulerAngles.z = -0.18 + Float(index) * 0.09
            root.addChildNode(bangShadow)
        }

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let temple = capsule(radius: 0.004, height: 0.118, color: hairShadow.withAlphaComponent(0.68), position: SCNVector3(side * 0.128, 0.04, -0.112), rotation: SCNVector4(1, 0, 0, 0.22))
            temple.name = "student\(sideName)TempleFlyaway"
            temple.eulerAngles.z = side * (0.28 + Float(seed % 3) * 0.035)
            root.addChildNode(temple)

            let earRim = capsule(radius: 0.0032, height: 0.052, color: earWarm.withAlphaComponent(0.52), position: SCNVector3(side * 0.153, -0.004, -0.018), rotation: SCNVector4(1, 0, 0, 0.1))
            earRim.name = "student\(sideName)EarWarmRim"
            earRim.eulerAngles.z = side * 0.16
            root.addChildNode(earRim)

            let earOcclusion = sphere(radius: 0.013, color: hairShadow.withAlphaComponent(anxious ? 0.34 : 0.22), position: SCNVector3(side * 0.142, 0.018, -0.02), scale: SCNVector3(0.38, 0.8, 0.16))
            earOcclusion.name = "student\(sideName)EarHairOcclusion"
            root.addChildNode(earOcclusion)
        }

        let neckShadow = capsule(radius: 0.006, height: 0.145, color: hairShadow.withAlphaComponent(0.34), position: SCNVector3(0, -0.15, 0.052), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        neckShadow.name = "studentNeckHairCastShadow"
        root.addChildNode(neckShadow)

        let crownRim = box(width: 0.16, height: 0.006, length: 0.018, color: hairCatch.withAlphaComponent(0.32), position: SCNVector3(0.012, 0.145, -0.04))
        crownRim.name = "studentCrownRimCatch"
        crownRim.eulerAngles.z = -0.08 + Float(seed % 5) * 0.03
        root.addChildNode(crownRim)

        root.opacity = 0.18
        return root
    }

