    private func makeStudentHairCinematicMaterialLayer(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentHairCinematicMaterialLayer"

        let hairBase = NSColor(calibratedWhite: 0.018 + CGFloat(seed % 4) * 0.022, alpha: 1)
        let hairCatch = hairBase.blended(withFraction: 0.46, of: .white) ?? hairBase
        let hairWarm = hairBase.blended(withFraction: 0.22, of: NSColor(calibratedRed: 0.72, green: 0.42, blue: 0.18, alpha: 1)) ?? hairBase
        let hairShadow = hairBase.blended(withFraction: 0.56, of: .black) ?? hairBase
        let oilGlint = NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.52, alpha: (profile?.orderliness ?? 50) > 70 ? 0.13 : 0.08)
        let coolRim = NSColor(calibratedRed: 0.48, green: 0.68, blue: 1.0, alpha: 0.09)

        let partLine = capsule(radius: 0.0024, height: 0.18, color: hairShadow.withAlphaComponent(0.58), position: SCNVector3(-0.018 + Float(seed % 3) * 0.012, 0.128, -0.12), rotation: SCNVector4(0, 0, 1, 0.12))
        partLine.name = "studentHairCinematicPartLine"
