        let crownOil = sphere(radius: 0.042, color: oilGlint, position: SCNVector3(0.018, 0.142, -0.074), scale: SCNVector3(1.8, 0.3, 0.16))
        crownOil.name = "studentHairCinematicCrownOilSheen"
