            strand.eulerAngles.z = -0.24 + Float(index) * 0.07
            root.addChildNode(strand)
        }

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            for index in 0..<4 {
                let flyaway = capsule(
                    radius: 0.0016 + CGFloat(index % 2) * 0.0005,
                    height: 0.088 + CGFloat(index) * 0.012,
                    color: (index % 2 == 0 ? hairCatch : hairShadow).withAlphaComponent(0.38),
                    position: SCNVector3(side * (0.112 + Float(index) * 0.01), 0.058 - Float(index) * 0.018, -0.1 + Float(index % 2) * 0.018),
                    rotation: SCNVector4(1, 0, 0, 0.22)
