                flyaway.eulerAngles.z = side * (0.32 + Float(index) * 0.08)
                root.addChildNode(flyaway)
            }

            let templeOil = box(width: 0.034, height: 0.12, length: 0.004, color: oilGlint.withAlphaComponent(0.08), position: SCNVector3(side * 0.124, 0.028, -0.134))
            templeOil.name = "studentHairCinematic\(sideName)TempleOilCatch"
            templeOil.eulerAngles.z = side * 0.18
            root.addChildNode(templeOil)

            let earCast = sphere(radius: 0.018, color: hairShadow.withAlphaComponent(0.24), position: SCNVector3(side * 0.14, -0.006, -0.036), scale: SCNVector3(0.34, 0.92, 0.12))
            earCast.name = "studentHairCinematic\(sideName)EarCastShadow"
            root.addChildNode(earCast)
        }

        let napeSoftMass = capsule(radius: 0.012, height: 0.16, color: hairShadow.withAlphaComponent(0.42), position: SCNVector3(0, -0.052, 0.084), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        napeSoftMass.name = "studentHairCinematicNapeSoftMass"
        root.addChildNode(napeSoftMass)

        let rearCoolEdge = capsule(radius: 0.003, height: 0.18, color: coolRim, position: SCNVector3(0.02, 0.012, 0.112), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        rearCoolEdge.name = "studentHairCinematicRearCoolRim"
        root.addChildNode(rearCoolEdge)

        root.opacity = 0.1
        return root
    }

    private func makeStudentFaceMask(seed: Int) -> SCNNode {
        let root = SCNNode()
        let maskColor = seed % 2 == 0
            ? NSColor(calibratedRed: 0.82, green: 0.9, blue: 0.96, alpha: 1)
            : NSColor(calibratedWhite: 0.92, alpha: 1)
        let mask = roundedBox(width: 0.18, height: 0.07, length: 0.018, chamfer: 0.018, color: maskColor, position: SCNVector3(0, -0.04, -0.154))
        mask.name = "studentMask"
        root.addChildNode(mask)
        for y in [-0.058, -0.04, -0.022] {
            root.addChildNode(box(width: 0.15, height: 0.004, length: 0.008, color: NSColor(calibratedWhite: 0.72, alpha: 0.5), position: SCNVector3(0, Float(y), -0.166)))
        }
        root.addChildNode(capsule(radius: 0.0035, height: 0.12, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(-0.122, -0.038, -0.08), rotation: SCNVector4(0, 0, 1, 0.55)))
        root.addChildNode(capsule(radius: 0.0035, height: 0.12, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(0.122, -0.038, -0.08), rotation: SCNVector4(0, 0, 1, -0.55)))
        return root
    }

    private func makeTeacherGeometry() -> SCNNode {
        let root = SCNNode()
        root.addChildNode(makeTeacherGroundingDetails())
        let body = makeTeacherBody()
        body.name = "teacherBodyRoot"
        root.addChildNode(body)
        let head = sphere(radius: 0.15, color: NSColor(calibratedRed: 0.9, green: 0.78, blue: 0.66, alpha: 1), position: SCNVector3(0, 1.28, 0))
        head.name = "teacherHead"
        head.addChildNode(makeTeacherFaceVolumeDetails())
        head.addChildNode(makeTeacherFace())
        root.addChildNode(head)
        let hair = sphere(radius: 0.153, color: NSColor(calibratedWhite: 0.035, alpha: 1), position: SCNVector3(0, 1.37, 0.025), scale: SCNVector3(1.0, 0.36, 0.92))
        hair.name = "teacherHair"
        root.addChildNode(hair)
        root.addChildNode(makeTeacherHairDetails())
        teacherGazeNode.addChildNode(gazeCone())
        teacherGazeNode.position = SCNVector3(0, 1.22, -0.32)
        teacherGazeNode.eulerAngles.x = -.pi / 2
        teacherGazeNode.opacity = 0.12
        root.addChildNode(teacherGazeNode)

        let pressureLight = SCNLight()
        pressureLight.type = .omni
        pressureLight.color = NSColor(calibratedRed: 1.0, green: 0.48, blue: 0.24, alpha: 1)
        pressureLight.intensity = 0
        teacherPressureLightNode.light = pressureLight
        teacherPressureLightNode.position = SCNVector3(0, 1.2, -0.12)
        root.addChildNode(teacherPressureLightNode)
        root.addChildNode(makeTeacherPerformanceLayer())
        root.addChildNode(makeTeacherDirectorPerformanceLayer())
        root.addChildNode(makeTeacherAuthorityActionLayer())
        root.addChildNode(makeTeacherCloseupFidelityLayer())
        root.addChildNode(makeTeacherMaterialFidelityLayer())
        root.addChildNode(makeTeacherHandPropCinematicLayer())
        root.addChildNode(makeTeacherNearPresenceLayer())
        root.addChildNode(makeTeacherPatrolAuthorityLayer())
        return root
    }

    private func makeTeacherCinematicRimLayer() -> SCNNode {
        let root = SCNNode()
        let warm = NSColor(calibratedRed: 1.0, green: 0.62, blue: 0.24, alpha: 0.22)
        let cool = NSColor(calibratedRed: 0.42, green: 0.68, blue: 1.0, alpha: 0.18)
        let dark = NSColor(calibratedWhite: 0.01, alpha: 0.18)

        let leftBodyRim = capsule(radius: 0.006, height: 0.72, color: warm, position: SCNVector3(-0.235, 0.88, -0.126), rotation: SCNVector4(0, 0, 1, 0.04))
        leftBodyRim.name = "teacherCinematicLeftBodyRim"
        root.addChildNode(leftBodyRim)
        let rightBodyRim = capsule(radius: 0.006, height: 0.72, color: cool, position: SCNVector3(0.235, 0.88, -0.126), rotation: SCNVector4(0, 0, 1, -0.04))
        rightBodyRim.name = "teacherCinematicRightBodyRim"
        root.addChildNode(rightBodyRim)
        let headHalo = capsule(radius: 0.005, height: 0.26, color: warm.withAlphaComponent(0.28), position: SCNVector3(0.0, 1.39, -0.15), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        headHalo.name = "teacherCinematicHeadHalo"
        root.addChildNode(headHalo)
        let shoulderShadow = box(width: 0.58, height: 0.018, length: 0.035, color: dark, position: SCNVector3(0, 1.05, -0.132))
        shoulderShadow.name = "teacherCinematicShoulderCut"
        root.addChildNode(shoulderShadow)

        for index in 0..<4 {
            let chalkDust = sphere(radius: 0.008 + CGFloat(index) * 0.0015, color: NSColor(calibratedWhite: 0.94, alpha: 0.18), position: SCNVector3(0.28 + Float(index) * 0.035, 0.72 + Float(index % 2) * 0.08, -0.16), scale: SCNVector3(1, 0.65, 1))
            chalkDust.name = "teacherHandChalkBokeh\(index)"
            chalkDust.runAction(.repeatForever(.sequence([
                .moveBy(x: 0.01, y: 0.03, z: 0, duration: 1.2 + Double(index) * 0.12),
                .fadeOpacity(to: 0.04, duration: 0.22),
                .moveBy(x: -0.01, y: -0.03, z: 0, duration: 0.01),
                .fadeOpacity(to: 0.28, duration: 0.18)
            ])), forKey: "teacher_chalk_bokeh")
            root.addChildNode(chalkDust)
        }
        return root
