    private func makeTeacherPerformanceLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "teacherPerformanceLayer"
        let chalkWhite = NSColor(calibratedWhite: 0.96, alpha: 0.28)
        let glassBlue = NSColor(calibratedRed: 0.48, green: 0.72, blue: 1.0, alpha: 0.22)
        let warningWarm = NSColor(calibratedRed: 1.0, green: 0.42, blue: 0.16, alpha: 0.18)
        let paperGlow = NSColor(calibratedWhite: 1.0, alpha: 0.18)
        let contact = NSColor(calibratedWhite: 0.01, alpha: 0.22)

        let leftGlare = box(width: 0.062, height: 0.006, length: 0.006, color: glassBlue, position: SCNVector3(-0.055, 1.315, -0.18))
        leftGlare.name = "teacherLeftGlassesGlare"
        root.addChildNode(leftGlare)
        let rightGlare = box(width: 0.062, height: 0.006, length: 0.006, color: glassBlue, position: SCNVector3(0.055, 1.315, -0.18))
        rightGlare.name = "teacherRightGlassesGlare"
        root.addChildNode(rightGlare)

        let gazePin = box(width: 0.2, height: 0.004, length: 0.012, color: warningWarm, position: SCNVector3(0, 1.25, -0.2))
        gazePin.name = "teacherGazePinLine"
        gazePin.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 0.42),
            .fadeOpacity(to: 0.36, duration: 0.52)
        ])), forKey: "teacher_gaze_pin")
        root.addChildNode(gazePin)

        for index in 0..<4 {
            let stroke = box(width: 0.18 + CGFloat(index) * 0.045, height: 0.005, length: 0.006, color: chalkWhite.withAlphaComponent(0.16 + CGFloat(index) * 0.03), position: SCNVector3(0.32 + Float(index) * 0.026, 0.58 + Float(index % 2) * 0.035, -0.17))
            stroke.name = "teacherChalkMotionTrail\(index)"
            stroke.eulerAngles.z = -0.22 + CGFloat(index) * 0.08
            stroke.runAction(.repeatForever(.sequence([
                .moveBy(x: 0.018, y: 0.01, z: 0, duration: 0.16 + Double(index) * 0.03),
                .fadeOpacity(to: 0.04, duration: 0.14),
                .moveBy(x: -0.018, y: -0.01, z: 0, duration: 0.01),
                .fadeOpacity(to: 0.26, duration: 0.16),
                .wait(duration: 0.34 + Double(index) * 0.06)
            ])), forKey: "teacher_chalk_trail")
            root.addChildNode(stroke)
        }

        for index in 0..<5 {
            let dust = sphere(radius: 0.005 + CGFloat(index % 2) * 0.0015, color: chalkWhite, position: SCNVector3(0.28 + Float(index) * 0.035, 0.66 + Float(index % 3) * 0.045, -0.18), scale: SCNVector3(1, 0.6, 1))
            dust.name = "teacherChalkFingerDust\(index)"
            dust.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.006, y: 0.026, z: 0.002, duration: 1.0 + Double(index) * 0.12),
                .fadeOpacity(to: 0.04, duration: 0.18),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.006, y: -0.026, z: -0.002, duration: 0.01),
                .fadeOpacity(to: 0.26, duration: 0.16)
            ])), forKey: "teacher_chalk_finger_dust")
            root.addChildNode(dust)
        }

        let notebookEdge = box(width: 0.2, height: 0.004, length: 0.03, color: paperGlow, position: SCNVector3(-0.36, 0.674, -0.16))
        notebookEdge.name = "teacherNotebookPageEdge"
        notebookEdge.eulerAngles.z = -0.28
        notebookEdge.runAction(.repeatForever(.sequence([
            .rotateBy(x: 0, y: 0.06, z: 0.02, duration: 0.38),
            .rotateBy(x: 0, y: -0.06, z: -0.02, duration: 0.48),
            .wait(duration: 1.2)
        ])), forKey: "teacher_notebook_page")
        root.addChildNode(notebookEdge)

        let leftCuffCrease = box(width: 0.09, height: 0.004, length: 0.012, color: contact.withAlphaComponent(0.18), position: SCNVector3(-0.31, 0.48, -0.065))
        leftCuffCrease.name = "teacherLeftCuffPressureCrease"
        root.addChildNode(leftCuffCrease)
        let rightCuffCrease = box(width: 0.09, height: 0.004, length: 0.012, color: contact.withAlphaComponent(0.18), position: SCNVector3(0.31, 0.48, -0.065))
        rightCuffCrease.name = "teacherRightCuffPressureCrease"
        root.addChildNode(rightCuffCrease)

        for index in 0..<4 {
            let hem = capsule(radius: 0.0038, height: 0.18 + CGFloat(index % 2) * 0.04, color: contact.withAlphaComponent(0.14), position: SCNVector3(-0.15 + Float(index) * 0.1, 0.57, -0.13), rotation: SCNVector4(0, 0, 1, -0.08 + Float(index) * 0.05))
            hem.name = "teacherCoatHemMotion\(index)"
            hem.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: CGFloat(index % 2 == 0 ? 0.035 : -0.03), duration: 0.9 + Double(index) * 0.08),
                .rotateBy(x: 0, y: 0, z: CGFloat(index % 2 == 0 ? -0.035 : 0.03), duration: 1.1 + Double(index) * 0.1)
            ])), forKey: "teacher_coat_hem")
            root.addChildNode(hem)
        }

        let inspectPoint = sphere(radius: 0.028, color: warningWarm.withAlphaComponent(0.2), position: SCNVector3(0.34, 0.42, -0.2), scale: SCNVector3(1.8, 0.2, 1.0))
        inspectPoint.name = "teacherInspectionPointShadow"
        root.addChildNode(inspectPoint)

        let leftStep = sphere(radius: 0.07, color: contact.withAlphaComponent(0.16), position: SCNVector3(-0.1, -0.02, -0.085), scale: SCNVector3(1.5, 0.08, 1.0))
        leftStep.name = "teacherLeftStepPressureRing"
        root.addChildNode(leftStep)
        let rightStep = sphere(radius: 0.07, color: contact.withAlphaComponent(0.16), position: SCNVector3(0.1, -0.02, -0.085), scale: SCNVector3(1.5, 0.08, 1.0))
        rightStep.name = "teacherRightStepPressureRing"
        root.addChildNode(rightStep)

        root.opacity = 0.24
        return root
    }

