            let cheekCut = sphere(radius: 0.017, color: skinCatch.withAlphaComponent(0.12), position: SCNVector3(side * 0.088, 1.255, -0.18), scale: SCNVector3(1.55, 0.32, 0.12))
            cheekCut.name = "teacherCloseup\(sideName)CheekAuthoritySheen"
            root.addChildNode(cheekCut)

            let cuffFiber = box(width: 0.12, height: 0.004, length: 0.018, color: suitFiber, position: SCNVector3(side * 0.31, 0.55, -0.176))
            cuffFiber.name = "teacherCloseup\(sideName)CuffFiberCatch"
