        let nasolabial = capsule(radius: 0.003, height: 0.112, color: fatigueShadow.withAlphaComponent(0.24), position: SCNVector3(0, 1.235, -0.19), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        nasolabial.name = "teacherCloseupMouthAuthorityCrease"
        root.addChildNode(nasolabial)

        let chalkThumb = box(width: 0.12, height: 0.004, length: 0.024, color: chalkWhite, position: SCNVector3(0.34, 0.5, -0.202))
        chalkThumb.name = "teacherCloseupChalkThumbDust"
        chalkThumb.eulerAngles.z = -0.18
        root.addChildNode(chalkThumb)

        let chalkFingerPressure = sphere(radius: 0.018, color: pressureWarm.withAlphaComponent(0.18), position: SCNVector3(0.37, 0.485, -0.2), scale: SCNVector3(1.4, 0.24, 0.72))
        chalkFingerPressure.name = "teacherCloseupFingerPressurePad"
        root.addChildNode(chalkFingerPressure)

        let suitChestFiber = box(width: 0.36, height: 0.006, length: 0.018, color: suitFiber, position: SCNVector3(0, 0.91, -0.154))
        suitChestFiber.name = "teacherCloseupSuitChestFiber"
        root.addChildNode(suitChestFiber)

        let collarOil = box(width: 0.26, height: 0.006, length: 0.014, color: fatigueShadow.withAlphaComponent(0.18), position: SCNVector3(0, 1.08, -0.154))
        collarOil.name = "teacherCloseupCollarOilShadow"
        root.addChildNode(collarOil)

        for index in 0..<5 {
            let dust = sphere(
                radius: 0.004 + CGFloat(index % 2) * 0.001,
                color: chalkWhite,
                position: SCNVector3(0.29 + Float(index) * 0.034, 0.56 + Float(index % 2) * 0.028, -0.214),
                scale: SCNVector3(1.4, 0.34, 0.7)
            )
