    private func makeTeacherHandPropCinematicLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "teacherHandPropCinematicLayer"

        let skinRidge = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.5, alpha: 0.16)
        let skinShadow = NSColor(calibratedRed: 0.2, green: 0.075, blue: 0.045, alpha: 0.18)
        let chalkWhite = NSColor(calibratedWhite: 0.98, alpha: 0.22)
        let paperWhite = NSColor(calibratedWhite: 0.95, alpha: 0.2)
        let inkBlue = NSColor(calibratedRed: 0.08, green: 0.14, blue: 0.23, alpha: 0.24)
        let suitThread = NSColor(calibratedRed: 0.52, green: 0.6, blue: 0.72, alpha: 0.14)
        let cuffButton = NSColor(calibratedRed: 0.12, green: 0.13, blue: 0.15, alpha: 0.26)
        let contactShadow = NSColor(calibratedWhite: 0.0, alpha: 0.2)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let wristX = side * 0.315
            let palmX = side * 0.345

            let tendonA = capsule(radius: 0.0024, height: 0.076, color: skinShadow, position: SCNVector3(wristX + side * 0.006, 0.505, -0.214), rotation: SCNVector4(0, 0, 1, side * 0.16))
            tendonA.name = "teacherHandProp\(sideName)WristTendonA"
            root.addChildNode(tendonA)

            let tendonB = capsule(radius: 0.002, height: 0.064, color: skinRidge, position: SCNVector3(wristX + side * 0.018, 0.492, -0.217), rotation: SCNVector4(0, 0, 1, side * -0.08))
            tendonB.name = "teacherHandProp\(sideName)WristTendonB"
            root.addChildNode(tendonB)

            let cuffSeam = box(width: 0.096, height: 0.004, length: 0.014, color: suitThread, position: SCNVector3(wristX, 0.557, -0.198))
            cuffSeam.name = "teacherHandProp\(sideName)CuffSeam"
            cuffSeam.eulerAngles.z = side * 0.18
            root.addChildNode(cuffSeam)

            let cuffFold = box(width: 0.088, height: 0.005, length: 0.02, color: contactShadow.withAlphaComponent(0.12), position: SCNVector3(wristX + side * 0.006, 0.544, -0.212))
            cuffFold.name = "teacherHandProp\(sideName)CuffFoldShadow"
            cuffFold.eulerAngles.z = side * 0.22
            root.addChildNode(cuffFold)

            let button = sphere(radius: 0.01, color: cuffButton, position: SCNVector3(wristX - side * 0.035, 0.552, -0.222), scale: SCNVector3(1.2, 0.34, 0.82))
            button.name = "teacherHandProp\(sideName)CuffButton"
            root.addChildNode(button)

            for fingerIndex in 0..<4 {
                let offset = Float(fingerIndex) * 0.018
                let knuckle = sphere(
                    radius: 0.011 - CGFloat(fingerIndex % 2) * 0.001,
                    color: fingerIndex % 2 == 0 ? skinRidge : skinShadow.withAlphaComponent(0.14),
                    position: SCNVector3(palmX + side * offset, 0.48 - Float(fingerIndex % 2) * 0.01, -0.226),
                    scale: SCNVector3(1.32, 0.28, 0.74)
                )
                knuckle.name = "teacherHandProp\(sideName)KnuckleRidge\(fingerIndex)"
                root.addChildNode(knuckle)

                let nail = box(width: 0.014, height: 0.0025, length: 0.008, color: paperWhite.withAlphaComponent(0.16), position: SCNVector3(palmX + side * (offset + 0.006), 0.464 - Float(fingerIndex % 2) * 0.006, -0.236))
                nail.name = "teacherHandProp\(sideName)NailGlint\(fingerIndex)"
                nail.eulerAngles.z = side * 0.18
                root.addChildNode(nail)
            }

            for lintIndex in 0..<3 {
                let lint = capsule(
                    radius: 0.0018,
                    height: 0.07 + CGFloat(lintIndex) * 0.012,
                    color: suitThread.withAlphaComponent(0.12),
                    position: SCNVector3(wristX - side * 0.022 + side * Float(lintIndex) * 0.016, 0.586 + Float(lintIndex % 2) * 0.016, -0.202),
                    rotation: SCNVector4(0, 0, 1, side * (0.48 + Float(lintIndex) * 0.1))
                )
                lint.name = "teacherHandProp\(sideName)SleeveLint\(lintIndex)"
                root.addChildNode(lint)
            }
        }

        let chalkTipContact = sphere(radius: 0.018, color: chalkWhite, position: SCNVector3(0.405, 0.486, -0.247), scale: SCNVector3(1.4, 0.26, 0.72))
        chalkTipContact.name = "teacherHandPropRightChalkTipContact"
        chalkTipContact.geometry?.firstMaterial?.emission.contents = chalkWhite.withAlphaComponent(0.12)
        root.addChildNode(chalkTipContact)

        let chalkDustBloom = sphere(radius: 0.042, color: chalkWhite.withAlphaComponent(0.12), position: SCNVector3(0.422, 0.505, -0.252), scale: SCNVector3(1.8, 0.44, 1.0))
        chalkDustBloom.name = "teacherHandPropRightChalkDustBloom"
        chalkDustBloom.geometry?.firstMaterial?.emission.contents = chalkWhite.withAlphaComponent(0.06)
        root.addChildNode(chalkDustBloom)

        for index in 0..<5 {
            let flake = sphere(
                radius: 0.0035 + CGFloat(index % 2) * 0.001,
                color: chalkWhite,
                position: SCNVector3(0.372 + Float(index) * 0.018, 0.455 + Float(index % 3) * 0.018, -0.258),
                scale: SCNVector3(1.4, 0.46, 0.8)
            )
            flake.name = "teacherHandPropChalkPowderFlake\(index)"
            root.addChildNode(flake)
        }

        let notebookCorner = box(width: 0.085, height: 0.004, length: 0.05, color: paperWhite, position: SCNVector3(-0.45, 0.685, -0.205))
        notebookCorner.name = "teacherHandPropLeftNotebookCornerBend"
        notebookCorner.eulerAngles.z = -0.42
        notebookCorner.eulerAngles.y = 0.16
        root.addChildNode(notebookCorner)

        let notebookThumbShadow = sphere(radius: 0.024, color: skinShadow.withAlphaComponent(0.18), position: SCNVector3(-0.318, 0.633, -0.224), scale: SCNVector3(1.5, 0.24, 0.72))
        notebookThumbShadow.name = "teacherHandPropLeftNotebookThumbPressure"
        root.addChildNode(notebookThumbShadow)

        for index in 0..<4 {
            let paperLine = box(width: 0.18 - CGFloat(index) * 0.018, height: 0.0025, length: 0.006, color: inkBlue.withAlphaComponent(0.16), position: SCNVector3(-0.37, 0.682 - Float(index) * 0.012, -0.232))
            paperLine.name = "teacherHandPropNotebookInkLine\(index)"
            paperLine.eulerAngles.z = -0.24
            root.addChildNode(paperLine)
        }

        let inspectionNail = box(width: 0.02, height: 0.0025, length: 0.01, color: paperWhite.withAlphaComponent(0.24), position: SCNVector3(0.455, 0.443, -0.244))
        inspectionNail.name = "teacherHandPropInspectionFingerNail"
        inspectionNail.eulerAngles.z = -0.48
        root.addChildNode(inspectionNail)

        let inspectionDeskCast = box(width: 0.28, height: 0.004, length: 0.058, color: contactShadow.withAlphaComponent(0.18), position: SCNVector3(0.34, 0.06, -0.218))
        inspectionDeskCast.name = "teacherHandPropInspectionDeskCast"
        inspectionDeskCast.eulerAngles.y = -0.1
        root.addChildNode(inspectionDeskCast)

        root.opacity = 0.12
        return root
    }

    private func makeTeacherNearPresenceLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "teacherNearPresenceLayer"
        let pressureShadow = NSColor(calibratedWhite: 0.0, alpha: 0.2)
        let warmAuthority = NSColor(calibratedRed: 1.0, green: 0.42, blue: 0.16, alpha: 0.16)
        let glassKnife = NSColor(calibratedRed: 0.72, green: 0.9, blue: 1.0, alpha: 0.22)
        let chalkWhite = NSColor(calibratedWhite: 0.96, alpha: 0.18)
        let suitFiber = NSColor(calibratedRed: 0.52, green: 0.6, blue: 0.72, alpha: 0.12)
        let skinPressure = NSColor(calibratedRed: 1.0, green: 0.7, blue: 0.52, alpha: 0.14)

        let deskKnife = box(width: 0.9, height: 0.005, length: 0.1, color: pressureShadow.withAlphaComponent(0.22), position: SCNVector3(0.12, 0.076, -0.22))
        deskKnife.name = "teacherNearPresenceDeskKnifeShadow"
        deskKnife.eulerAngles.y = -0.24
        root.addChildNode(deskKnife)

        let bodyOcclusion = box(width: 0.54, height: 0.72, length: 0.018, color: pressureShadow.withAlphaComponent(0.13), position: SCNVector3(0.02, 0.82, -0.19))
        bodyOcclusion.name = "teacherNearPresenceBodyOcclusionMass"
        bodyOcclusion.eulerAngles.z = -0.015
        root.addChildNode(bodyOcclusion)

        let headDrop = box(width: 0.28, height: 0.07, length: 0.008, color: warmAuthority.withAlphaComponent(0.11), position: SCNVector3(0.01, 1.27, -0.218))
        headDrop.name = "teacherNearPresenceHeadDropPressure"
        root.addChildNode(headDrop)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"

            let stepBlade = sphere(radius: 0.086, color: pressureShadow.withAlphaComponent(0.18), position: SCNVector3(side * 0.11, -0.018, -0.1), scale: SCNVector3(2.2, 0.06, 1.2))
            stepBlade.name = "teacherNearPresence\(sideName)StepBlade"
            stepBlade.eulerAngles.y = side * 0.12
            root.addChildNode(stepBlade)

            let trouserPull = capsule(radius: 0.0045, height: 0.34, color: suitFiber, position: SCNVector3(side * 0.13, 0.38, -0.176), rotation: SCNVector4(0, 0, 1, side * 0.09))
            trouserPull.name = "teacherNearPresence\(sideName)TrouserPullLine"
            root.addChildNode(trouserPull)

            let sleeveSweep = box(width: 0.2, height: 0.006, length: 0.034, color: pressureShadow.withAlphaComponent(0.14), position: SCNVector3(side * 0.31, 0.54, -0.21))
            sleeveSweep.name = "teacherNearPresence\(sideName)SleeveSweep"
            sleeveSweep.eulerAngles.z = side * 0.2
            root.addChildNode(sleeveSweep)

            let lensSlice = box(width: 0.096, height: 0.004, length: 0.006, color: glassKnife, position: SCNVector3(side * 0.056, 1.323, -0.218))
            lensSlice.name = "teacherNearPresence\(sideName)LensSlice"
            lensSlice.eulerAngles.z = side * 0.08
            lensSlice.geometry?.firstMaterial?.emission.contents = glassKnife
            root.addChildNode(lensSlice)
        }

        for index in 0..<5 {
            let hem = box(width: 0.12 + CGFloat(index % 2) * 0.03, height: 0.008, length: 0.032, color: suitFiber.withAlphaComponent(0.12), position: SCNVector3(-0.2 + Float(index) * 0.1, 0.56 - Float(index % 2) * 0.02, -0.205))
            hem.name = "teacherNearPresenceCoatHemDrag\(index)"
            hem.eulerAngles.z = -0.1 + Float(index) * 0.05
            root.addChildNode(hem)
        }

        let handPressure = sphere(radius: 0.026, color: skinPressure, position: SCNVector3(0.36, 0.47, -0.226), scale: SCNVector3(1.5, 0.25, 0.72))
        handPressure.name = "teacherNearPresenceFingerPressure"
        root.addChildNode(handPressure)

        let fingerShadow = capsule(radius: 0.004, height: 0.22, color: pressureShadow.withAlphaComponent(0.2), position: SCNVector3(0.38, 0.46, -0.236), rotation: SCNVector4(0, 0, 1, -0.78))
        fingerShadow.name = "teacherNearPresenceFingerCast"
        root.addChildNode(fingerShadow)

        let notebookWall = box(width: 0.3, height: 0.12, length: 0.012, color: pressureShadow.withAlphaComponent(0.14), position: SCNVector3(-0.34, 0.64, -0.218))
        notebookWall.name = "teacherNearPresenceNotebookOcclusion"
        notebookWall.eulerAngles.z = -0.24
        root.addChildNode(notebookWall)

        let chalkClose = box(width: 0.18, height: 0.004, length: 0.026, color: chalkWhite, position: SCNVector3(0.33, 0.53, -0.242))
        chalkClose.name = "teacherNearPresenceChalkCloseSmear"
        chalkClose.eulerAngles.z = -0.22
        root.addChildNode(chalkClose)

        for index in 0..<8 {
            let mote = sphere(
                radius: 0.004 + CGFloat(index % 3) * 0.0012,
                color: chalkWhite.withAlphaComponent(0.14),
                position: SCNVector3(0.2 + Float(index) * 0.035, 0.54 + Float(index % 3) * 0.036, -0.25),
                scale: SCNVector3(1.2, 0.42, 0.7)
            )
            mote.name = "teacherNearPresenceChalkBreathMote\(index)"
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.006, y: 0.024, z: 0.004, duration: 0.8 + Double(index) * 0.08),
                .fadeOpacity(to: 0.035, duration: 0.16),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.006, y: -0.024, z: -0.004, duration: 0.01),
                .fadeOpacity(to: 0.22, duration: 0.18)
            ])), forKey: "teacher_near_chalk_mote")
            root.addChildNode(mote)
        }

        let airPush = box(width: 0.72, height: 0.1, length: 0.012, color: warmAuthority.withAlphaComponent(0.08), position: SCNVector3(0, 0.34, -0.26))
        airPush.name = "teacherNearPresenceAirPush"
        airPush.eulerAngles.y = -0.1
        root.addChildNode(airPush)

        root.opacity = 0.1
        return root
    }

    private func makeTeacherPatrolAuthorityLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "teacherPatrolAuthorityLayer"
        let floorInk = NSColor(calibratedWhite: 0.0, alpha: 0.16)
        let warmAuthority = NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.12, alpha: 0.14)
        let coolAuthority = NSColor(calibratedRed: 0.42, green: 0.68, blue: 1.0, alpha: 0.12)
        let chalkWhite = NSColor(calibratedWhite: 0.96, alpha: 0.18)
        let suitEdge = NSColor(calibratedRed: 0.62, green: 0.72, blue: 0.82, alpha: 0.12)
        let skinWarm = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.54, alpha: 0.12)

        let patrolWake = box(width: 0.82, height: 0.004, length: 0.22, color: floorInk, position: SCNVector3(0, 0.046, 0.18))
        patrolWake.name = "teacherPatrolAuthorityFloorWake"
        patrolWake.eulerAngles.y = -0.08
        root.addChildNode(patrolWake)

        let leftStep = sphere(radius: 0.085, color: floorInk.withAlphaComponent(0.18), position: SCNVector3(-0.12, 0.046, -0.04), scale: SCNVector3(1.8, 0.08, 1.0))
        leftStep.name = "teacherPatrolAuthorityLeftStepPress"
        root.addChildNode(leftStep)
        let rightStep = sphere(radius: 0.085, color: floorInk.withAlphaComponent(0.18), position: SCNVector3(0.12, 0.046, -0.04), scale: SCNVector3(1.8, 0.08, 1.0))
        rightStep.name = "teacherPatrolAuthorityRightStepPress"
        root.addChildNode(rightStep)

        let coatWake = box(width: 0.54, height: 0.46, length: 0.014, color: floorInk.withAlphaComponent(0.1), position: SCNVector3(0, 0.78, -0.18))
        coatWake.name = "teacherPatrolAuthorityCoatWakePlane"
        root.addChildNode(coatWake)

        for index in 0..<5 {
            let hem = capsule(radius: 0.004, height: 0.2 + CGFloat(index % 2) * 0.035, color: suitEdge, position: SCNVector3(-0.18 + Float(index) * 0.09, 0.56, -0.17), rotation: SCNVector4(0, 0, 1, -0.16 + Float(index) * 0.08))
            hem.name = "teacherPatrolAuthorityHemLag\(index)"
            root.addChildNode(hem)
        }

        let gazeSweep = box(width: 0.42, height: 0.008, length: 0.024, color: warmAuthority, position: SCNVector3(0, 1.24, -0.24))
        gazeSweep.name = "teacherPatrolAuthorityGazeSweep"
        gazeSweep.geometry?.firstMaterial?.emission.contents = warmAuthority.withAlphaComponent(0.06)
        root.addChildNode(gazeSweep)

        let targetLock = box(width: 0.56, height: 0.005, length: 0.055, color: warmAuthority.withAlphaComponent(0.16), position: SCNVector3(0.18, 0.49, -0.24))
        targetLock.name = "teacherPatrolAuthorityTargetDeskLock"
        targetLock.eulerAngles.y = -0.2
        root.addChildNode(targetLock)

        let boardWrist = capsule(radius: 0.004, height: 0.36, color: chalkWhite, position: SCNVector3(0.34, 0.56, -0.22), rotation: SCNVector4(0, 0, 1, -0.72))
        boardWrist.name = "teacherPatrolAuthorityBoardWristArc"
        root.addChildNode(boardWrist)

        for index in 0..<6 {
            let chalk = sphere(radius: 0.0045 + CGFloat(index % 3) * 0.001, color: chalkWhite.withAlphaComponent(0.16), position: SCNVector3(0.24 + Float(index) * 0.036, 0.56 + Float(index % 3) * 0.03, -0.238), scale: SCNVector3(1.3, 0.42, 0.7))
            chalk.name = "teacherPatrolAuthorityChalkScatter\(index)"
            root.addChildNode(chalk)
        }

        let nearPlayerBlade = box(width: 0.88, height: 0.006, length: 0.11, color: warmAuthority.withAlphaComponent(0.14), position: SCNVector3(0.08, 0.06, -0.2))
        nearPlayerBlade.name = "teacherPatrolAuthorityNearPlayerBlade"
        nearPlayerBlade.eulerAngles.y = -0.22
        root.addChildNode(nearPlayerBlade)

        let rearDoorCut = capsule(radius: 0.005, height: 0.62, color: coolAuthority, position: SCNVector3(0.24, 0.98, -0.18), rotation: SCNVector4(0, 0, 1, -0.08))
        rearDoorCut.name = "teacherPatrolAuthorityRearDoorCoolCut"
        root.addChildNode(rearDoorCut)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let sleeve = capsule(radius: 0.004, height: 0.28, color: sideIndex == 0 ? suitEdge : warmAuthority, position: SCNVector3(side * 0.3, 0.6, -0.2), rotation: SCNVector4(0, 0, 1, side * 0.72))
            sleeve.name = "teacherPatrolAuthority\(sideName)SleeveVector"
            root.addChildNode(sleeve)
            let finger = box(width: 0.11, height: 0.004, length: 0.022, color: skinWarm, position: SCNVector3(side * 0.34, 0.48, -0.226))
            finger.name = "teacherPatrolAuthority\(sideName)FingerCommand"
            finger.eulerAngles.z = side * 0.18
            root.addChildNode(finger)
        }

        for index in 0..<4 {
            let airSlice = box(width: 0.68 - CGFloat(index) * 0.08, height: 0.004, length: 0.018, color: warmAuthority.withAlphaComponent(0.08), position: SCNVector3(0, 0.88 + Float(index) * 0.055, -0.236))
            airSlice.name = "teacherPatrolAuthorityAirStillnessSlice\(index)"
            root.addChildNode(airSlice)
        }

        root.opacity = 0.12
        return root
    }

    private func updateTeacherAttention(game: GameManager, teacherPosition: SCNVector3) {
        let pressure = game.teacher.institutionalPressure / 100
        let attention = max(pressure, game.teacher.isNearPlayer ? 0.88 : 0.22)
        let rearDoor = game.teacher.positionIndex == 8
        let color = rearDoor
            ? NSColor(calibratedRed: 0.35, green: 0.62, blue: 1.0, alpha: 1)
            : NSColor(calibratedRed: 1.0, green: 0.46, blue: 0.22, alpha: 1)

        teacherGazeNode.opacity = CGFloat(0.08 + attention * 0.32)
        teacherPressureLightNode.light?.intensity = 18 + 120 * attention
        teacherPressureLightNode.light?.color = color
        teacherGazeNode.childNodes.first?.geometry?.firstMaterial?.diffuse.contents = color.withAlphaComponent(0.18)
        teacherGazeNode.childNodes.first?.geometry?.firstMaterial?.emission.contents = color.withAlphaComponent(0.12)
        teacherNode.childNode(withName: "teacherFloorShadow", recursively: true)?.opacity = CGFloat(0.28 + attention * 0.24)
        teacherNode.childNode(withName: "teacherPressureShadow", recursively: true)?.opacity = CGFloat(0.12 + attention * 0.44)
        teacherNode.childNode(withName: "teacherLeftRimLight", recursively: true)?.opacity = CGFloat(0.18 + attention * 0.42)
        teacherNode.childNode(withName: "teacherRightRimLight", recursively: true)?.opacity = CGFloat(0.18 + attention * 0.42)
        teacherNode.childNode(withName: "teacherHeadRimLight", recursively: true)?.opacity = CGFloat(0.14 + attention * 0.36)
        teacherCinematicRimNode.opacity = CGFloat((0.22 + attention * 0.46 + (game.teacher.isNearPlayer ? 0.18 : 0)).clamped(to: 0.18...0.86))
        teacherCinematicRimNode.childNode(withName: "teacherCinematicLeftBodyRim", recursively: true)?.opacity = CGFloat(0.34 + attention * 0.42)
        teacherCinematicRimNode.childNode(withName: "teacherCinematicRightBodyRim", recursively: true)?.opacity = rearDoor ? CGFloat(0.72) : CGFloat(0.24 + attention * 0.34)
        teacherCinematicRimNode.childNode(withName: "teacherCinematicHeadHalo", recursively: true)?.opacity = CGFloat(0.18 + attention * 0.36)
        teacherCinematicRimNode.childNode(withName: "teacherCinematicShoulderCut", recursively: true)?.opacity = CGFloat(0.18 + pressure * 0.28)
        teacherNode.childNode(withName: "teacherPerformanceLayer", recursively: true)?.opacity = CGFloat((0.16 + attention * 0.34 + (game.teacher.isNearPlayer ? 0.16 : 0)).clamped(to: 0.12...0.74))
        teacherNode.childNode(withName: "teacherLeftGlassesGlare", recursively: true)?.opacity = CGFloat((0.14 + pressure * 0.28 + (rearDoor ? 0.18 : 0)).clamped(to: 0.1...0.68))
        teacherNode.childNode(withName: "teacherRightGlassesGlare", recursively: true)?.opacity = CGFloat((0.12 + attention * 0.34).clamped(to: 0.08...0.7))
        teacherNode.childNode(withName: "teacherGazePinLine", recursively: true)?.opacity = CGFloat((game.teacher.focusMode == .selectedStudent ? 0.36 : 0.08) + attention * 0.18)
        teacherNode.childNode(withName: "teacherInspectionPointShadow", recursively: true)?.opacity = CGFloat((game.teacher.isNearPlayer ? 0.42 : 0.16) + pressure * 0.18)
        teacherNode.childNode(withName: "teacherNotebookPageEdge", recursively: true)?.opacity = CGFloat((0.18 + attention * 0.14).clamped(to: 0.12...0.46))

        let playerPosition = SCNVector3(-0.6, game.player.posture == .standing ? 1.58 : 1.18, 1.5)
        teacherNode.eulerAngles = teacherEulerAngles(from: teacherPosition, to: playerPosition)
        updateTeacherPose(game: game)
    }

    private func updateTeacherSpatialPressure(game: GameManager, teacherIndex: Int) {
        let pressure = CGFloat((game.teacher.institutionalPressure / 100).clamped(to: 0...1))
        teacherPathShadowNode.opacity = CGFloat(game.teacher.isNearPlayer ? 0.46 : 0.24) + pressure * 0.18
        for index in 0..<9 {
            let activeDistance = abs(index - teacherIndex)
            let pool = teacherPathShadowNode.childNode(withName: "teacherPathPool\(index)", recursively: true)
            pool?.opacity = activeDistance == 0 ? CGFloat(0.62 + pressure * 0.22) : (activeDistance == 1 ? 0.28 : 0.12)
            pool?.scale = activeDistance == 0 ? SCNVector3(1.18, 1, 1.08) : SCNVector3(1, 1, 1)
        }
        for index in 0..<8 {
            teacherPathShadowNode.childNode(withName: "teacherPathStreak\(index)", recursively: true)?.opacity = index == max(0, teacherIndex - 1) ? CGFloat(0.3 + pressure * 0.2) : 0.1
        }

        if let target = game.selectedTeacherTarget, game.teacher.focusMode == .selectedStudent {
            let x = Float(target.seat.column) * 1.2 - 2.4
            let z = Float(target.seat.row) * 1.45 - 2.25
            teacherTargetSeatFocusNode.position = SCNVector3(x, 0.048, z + 0.15)
            teacherTargetSeatFocusNode.opacity = CGFloat(game.teacher.isNearPlayer ? 0.72 : 0.42) + pressure * 0.18
        } else {
            teacherTargetSeatFocusNode.opacity = 0
        }
    }

    private func updateClassroomSeatPressure(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let eventMateID = activeEventClassmateID(game: game)
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let teacherPressure = CGFloat((game.teacher.institutionalPressure / 100).clamped(to: 0...1))
        let eventPressure = CGFloat(eventIntensity.vignette.clamped(to: 0...1))
        classroomSeatPressureNode.opacity = CGFloat(0.18 + teacherPressure * 0.18 + eventPressure * 0.28)

        for classmate in game.classmates {
            let pool = classroomSeatPressureNode.childNode(withName: "seatPressurePool\(classmate.id)", recursively: true)
            let line = classroomSeatPressureNode.childNode(withName: "seatTargetLine\(classmate.id)", recursively: true)
            let thread = classroomSeatPressureNode.childNode(withName: "seatRelationshipThread\(classmate.id)", recursively: true)
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stateBoost: CGFloat
            switch classmate.state {
            case .crying:
                stateBoost = 0.46
            case .anxious, .covering:
                stateBoost = 0.34
            case .usingPhone:
                stateBoost = 0.28
            case .offeringHelp, .lookingAtPlayer:
                stateBoost = 0.24
            default:
                stateBoost = 0.08
            }

            pool?.opacity = (0.12 + stateBoost + (isTarget ? 0.28 : 0) + (isEventMate ? 0.34 : 0)).clamped(to: 0.1...0.86)
            pool?.scale = isTarget || isEventMate ? SCNVector3(1.18, 1, 1.12) : SCNVector3(1, 1, 1)
            line?.opacity = isTarget ? CGFloat(0.62 + teacherPressure * 0.24) : (isEventMate ? 0.5 : 0)
            thread?.opacity = classmate.state == .offeringHelp || isEventMate ? 0.56 : (classmate.state == .lookingAtPlayer ? 0.34 : 0)
            if classmate.state == .usingPhone {
                pool?.geometry?.firstMaterial?.diffuse.contents = NSColor(calibratedRed: 0.05, green: 0.22, blue: 0.62, alpha: 0.22)
                pool?.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.02, green: 0.08, blue: 0.22, alpha: 0.12)
            } else if classmate.state == .crying {
                pool?.geometry?.firstMaterial?.diffuse.contents = NSColor(calibratedRed: 0.18, green: 0.32, blue: 0.8, alpha: 0.2)
                pool?.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.06, green: 0.12, blue: 0.28, alpha: 0.12)
            } else {
                pool?.geometry?.firstMaterial?.diffuse.contents = NSColor(calibratedWhite: 0.01, alpha: 0.18)
                pool?.geometry?.firstMaterial?.emission.contents = NSColor.black
            }
        }
    }

    private func updateClassroomSurfaceRelief(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let event = eventIntensity.vignette.clamped(to: 0...1)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let deskFocus = game.cameraPose == .desk ? 1.0 : 0.0
        let boardFocus = game.cameraPose == .board ? 1.0 : 0.0
        let timeProgress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let rainMood = (timeProgress > 0.46 || game.classroomLightLevel < 0.6) ? 1.0 : 0.0

        classroomSurfaceReliefNode.opacity = CGFloat((0.16 + lowLight * 0.22 + event * 0.18 + teacherPressure * 0.1 + deskFocus * 0.12).clamped(to: 0.12...0.62))
        classroomSurfaceReliefNode.eulerAngles.y = Float(event * 0.004 - teacherNear * 0.003)
        classroomSurfaceReliefNode.childNode(withName: "surfaceFloorVarnishFilm", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.18 + deskFocus * 0.16 + event * 0.08).clamped(to: 0.04...0.36))
        classroomSurfaceReliefNode.childNode(withName: "surfaceWallHumidityVeil", recursively: true)?.opacity = CGFloat((0.06 + rainMood * 0.24 + lowLight * 0.08 + boardFocus * 0.06).clamped(to: 0.03...0.36))
        classroomSurfaceReliefNode.childNode(withName: "surfaceBlackboardChalkFallout", recursively: true)?.opacity = CGFloat((0.05 + boardFocus * 0.24 + event * 0.08).clamped(to: 0.02...0.34))
        classroomSurfaceReliefNode.childNode(withName: "surfaceTeacherPathPolish", recursively: true)?.opacity = CGFloat((0.06 + teacherNear * 0.24 + teacherPressure * 0.16 + event * 0.1).clamped(to: 0.03...0.42))
        for row in 0..<5 {
            classroomSurfaceReliefNode.childNode(withName: "surfaceDeskEdgeScratchRow\(row)", recursively: true)?.opacity = CGFloat((0.06 + deskFocus * 0.14 + lowLight * 0.08 + event * 0.06 + Double(row) * 0.012).clamped(to: 0.03...0.32))
            classroomSurfaceReliefNode.childNode(withName: "surfaceChairBackHandPolishRow\(row)", recursively: true)?.opacity = CGFloat((0.05 + teacherPressure * 0.08 + lowLight * 0.08 + Double((game.currentTurn + row) % 3) * 0.014).clamped(to: 0.03...0.28))
            classroomSurfaceReliefNode.childNode(withName: "surfaceAisleDustSettlingRow\(row)", recursively: true)?.opacity = CGFloat((0.04 + rainMood * 0.08 + lowLight * 0.1 + event * 0.08).clamped(to: 0.02...0.26))
        }
        for index in 0..<9 {
            let glint = classroomSurfaceReliefNode.childNode(withName: "surfaceMicroGlint\(index)", recursively: true)
            glint?.opacity = CGFloat((0.025 + lowLight * 0.08 + event * 0.08 + deskFocus * 0.06 + Double((game.currentTurn + index) % 4) * 0.01).clamped(to: 0.01...0.22))
            glint?.eulerAngles.y = Float(-0.08 + Double(index % 5) * 0.04 + event * 0.02)
        }
        updateCinematicMaterialUnification(
            game: game,
            lowLight: lowLight,
            event: event,
            teacherPressure: teacherPressure,
            teacherNear: teacherNear,
            deskFocus: deskFocus,
            boardFocus: boardFocus,
            rainMood: rainMood
        )
    }

    private func updateCinematicMaterialUnification(
        game: GameManager,
        lowLight: Double,
        event: Double,
        teacherPressure: Double,
        teacherNear: Double,
        deskFocus: Double,
        boardFocus: Double,
        rainMood: Double
    ) {
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)
        let progress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let rearFocus = game.cameraPose == .rear ? 1.0 : 0.0

        cinematicMaterialUnificationNode.opacity = CGFloat((0.06 + lowLight * 0.22 + event * 0.18 + teacherPressure * 0.1 + deskFocus * 0.1 + boardFocus * 0.08 + rainMood * 0.12).clamped(to: 0.04...0.74))
        cinematicMaterialUnificationNode.position.y = Float(event * 0.004 + teacherNear * 0.003)
        cinematicMaterialUnificationNode.eulerAngles.y = Float((progress - 0.5) * 0.006 + event * 0.008)
        cinematicMaterialUnificationNode.scale = SCNVector3(1 + CGFloat(event) * 0.01, 1 + CGFloat(lowLight) * 0.012, 1)

        for index in 0..<7 {
            let floor = cinematicMaterialUnificationNode.childNode(withName: "materialUnityFloorWetSheen\(index)", recursively: true)
            floor?.opacity = CGFloat((0.025 + lowLight * 0.14 + rainMood * 0.18 + event * 0.08 + progress * 0.04 - Double(index) * 0.004).clamped(to: 0.01...0.38))
            floor?.position.y = Float(0.071 + rainMood * 0.004 + event * 0.002)
            floor?.eulerAngles.y = Float(-0.04 + Double(index) * 0.014 + event * 0.025)
        }

        for row in 0..<5 {
            let rowBoost = (0.04 + lowLight * 0.08 + teacherPressure * 0.08 + event * 0.08 + (row == 0 ? boardFocus * 0.08 : 0)).clamped(to: 0.02...0.34)
            let varnish = cinematicMaterialUnificationNode.childNode(withName: "materialUnityDeskVarnishRow\(row)", recursively: true)
            varnish?.opacity = CGFloat(rowBoost + deskFocus * 0.08)
            varnish?.position.y = Float(0.842 + deskFocus * 0.004 + event * 0.002)

            let underside = cinematicMaterialUnificationNode.childNode(withName: "materialUnityDeskUndersideOcclusionRow\(row)", recursively: true)
            underside?.opacity = CGFloat((0.03 + teacherPressure * 0.1 + event * 0.1 + lowLight * 0.08).clamped(to: 0.02...0.32))

            let uniform = cinematicMaterialUnificationNode.childNode(withName: "materialUnityUniformRimRow\(row)", recursively: true)
            uniform?.opacity = CGFloat((0.025 + lowLight * 0.08 + teacherPressure * 0.1 + event * 0.08 - Double(row) * 0.004).clamped(to: 0.01...0.28))
            uniform?.eulerAngles.y = Float((row % 2 == 0 ? 0.02 : -0.024) + event * 0.025)
        }

        for classmate in game.classmates {
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stress = (classmate.stress / 100).clamped(to: 0...1)
            let stateMaterial: Double
            switch classmate.state {
            case .usingPhone:
                stateMaterial = 0.2
            case .crying:
                stateMaterial = 0.22 + event * 0.08
            case .anxious, .covering:
                stateMaterial = 0.16 + stress * 0.12
            case .sleeping:
                stateMaterial = 0.1 + lowLight * 0.06
            case .offeringHelp, .lookingAtPlayer:
                stateMaterial = 0.12
            case .studying:
                stateMaterial = 0.14
            }
            let pressure = (0.04 + stateMaterial + (isTarget ? 0.18 : 0) + (isEventMate ? 0.18 : 0) + teacherPressure * 0.08 + event * 0.06).clamped(to: 0.02...0.56)

            let paper = cinematicMaterialUnificationNode.childNode(withName: "materialUnitySeatPaperCatch\(classmate.id)", recursively: true)
            paper?.opacity = CGFloat((0.025 + pressure * 0.5 + deskFocus * 0.08).clamped(to: 0.01...0.38))
            paper?.position.y = Float(0.862 + pressure * 0.006)

            let oil = cinematicMaterialUnificationNode.childNode(withName: "materialUnitySeatHandOilBloom\(classmate.id)", recursively: true)
            oil?.opacity = CGFloat((0.02 + pressure * 0.38 + lowLight * 0.04).clamped(to: 0.01...0.32))
            oil?.scale = SCNVector3(2.0 + CGFloat(pressure) * 0.22, 0.16, 0.75 + CGFloat(event) * 0.06)

            let mirror = cinematicMaterialUnificationNode.childNode(withName: "materialUnitySeatShoeMirror\(classmate.id)", recursively: true)
            mirror?.opacity = CGFloat((0.018 + rainMood * 0.12 + lowLight * 0.08 + pressure * 0.12).clamped(to: 0.008...0.28))
        }

        for index in 0..<6 {
            let chalk = cinematicMaterialUnificationNode.childNode(withName: "materialUnityBlackboardChalkOil\(index)", recursively: true)
            chalk?.opacity = CGFloat((0.03 + boardFocus * 0.22 + lowLight * 0.08 + event * 0.08 - Double(index) * 0.006).clamped(to: 0.01...0.36))
            chalk?.position.y = Float(1.48 + Double(index % 3) * 0.16 + event * 0.004)
        }

        for index in 0..<5 {
            let glass = cinematicMaterialUnificationNode.childNode(withName: "materialUnityWindowFresnel\(index)", recursively: true)
            glass?.opacity = CGFloat((0.025 + lowLight * 0.16 + rainMood * 0.14 + rearFocus * 0.08 + event * 0.06 - Double(index) * 0.004).clamped(to: 0.01...0.34))
            glass?.eulerAngles.z = Float(-0.02 + Double(index) * 0.01 + event * 0.018)
        }

        for row in 0..<5 {
            let rowStress = game.classmates.filter { $0.seat.row == row }.map { ($0.stress / 100).clamped(to: 0...1) }.max() ?? 0
            let rowPhoneGlow = game.classmates.contains { $0.seat.row == row && $0.state == .usingPhone } ? 1.0 : 0.0
            let rowStudyLoad = game.classmates.contains { $0.seat.row == row && $0.state == .studying } ? 1.0 : 0.0

            let wood = cinematicMaterialUnificationNode.childNode(withName: "materialUnityWoodEndgrainResponse\(row)", recursively: true)
            wood?.opacity = CGFloat((0.03 + deskFocus * 0.12 + lowLight * 0.1 + rowStress * 0.08 + teacherPressure * 0.06 + event * 0.08).clamped(to: 0.01...0.36))
            wood?.position.y = Float(0.858 + deskFocus * 0.004 + event * 0.002)

            let cloth = cinematicMaterialUnificationNode.childNode(withName: "materialUnityClothThreadSheen\(row)", recursively: true)
            cloth?.opacity = CGFloat((0.02 + lowLight * 0.14 + rowStress * 0.1 + event * 0.08 + rowPhoneGlow * 0.06).clamped(to: 0.01...0.32))
            cloth?.scale = SCNVector3(1 + CGFloat(rowStress) * 0.04, 1 + CGFloat(event) * 0.03, 1)

            let metal = cinematicMaterialUnificationNode.childNode(withName: "materialUnityMetalColdGlintRow\(row)", recursively: true)
            metal?.opacity = CGFloat((0.015 + lowLight * 0.16 + rainMood * 0.12 + rowPhoneGlow * 0.08 + event * 0.06 + Double(row) * 0.006).clamped(to: 0.005...0.34))
            metal?.eulerAngles.y = Float(Double(row % 3 - 1) * 0.025 + progress * 0.018 + event * 0.018)

            if rowStudyLoad > 0 {
                wood?.scale = SCNVector3(1 + CGFloat(rowStudyLoad) * 0.03, 1, 1 + CGFloat(deskFocus) * 0.02)
            }
        }

        for index in 0..<8 {
            let fiber = cinematicMaterialUnificationNode.childNode(withName: "materialUnityPaperFiberResponse\(index)", recursively: true)
            let rowStudy = game.classmates.contains { $0.state == .studying && ($0.id + index) % 4 == 0 } ? 1.0 : 0.0
            fiber?.opacity = CGFloat((0.02 + rowStudy * 0.18 + deskFocus * 0.08 + lowLight * 0.08 + event * 0.06 - Double(index) * 0.002).clamped(to: 0.005...0.34))
            fiber?.position.y = Float(0.872 + rowStudy * 0.004 + event * 0.002)
        }

        for index in 0..<7 {
            let skin = cinematicMaterialUnificationNode.childNode(withName: "materialUnitySkinSweatRim\(index)", recursively: true)
            let activeStress = game.classmates.contains { $0.stress > 72 && ($0.id + index) % 3 == 0 } ? 1.0 : 0.0
            skin?.opacity = CGFloat((0.015 + activeStress * 0.18 + teacherPressure * 0.1 + event * 0.08 + lowLight * 0.05).clamped(to: 0.005...0.34))
            skin?.position.y = Float(1.08 + Double(index % 3) * 0.09 + activeStress * 0.006 + event * 0.002)
        }

        for index in 0..<6 {
            let boardSpec = cinematicMaterialUnificationNode.childNode(withName: "materialUnityBlackboardGhostSpecular\(index)", recursively: true)
            boardSpec?.opacity = CGFloat((0.015 + boardFocus * 0.22 + lowLight * 0.08 + event * 0.08 - Double(index) * 0.004).clamped(to: 0.005...0.34))
            boardSpec?.position.y = Float(1.72 + Double(index % 2) * 0.16 + boardFocus * 0.008 + event * 0.003)
        }

        for index in 0..<6 {
            let bead = cinematicMaterialUnificationNode.childNode(withName: "materialUnityGlassRainBeadResponse\(index)", recursively: true)
            bead?.opacity = CGFloat((rainMood * (0.1 + progress * 0.08 + lowLight * 0.08 - Double(index) * 0.006) + event * 0.03).clamped(to: 0...0.32))
            bead?.position.y = Float(1.0 + Double(index % 3) * 0.35 - progress * 0.012 + event * 0.004)
            bead?.scale = SCNVector3(0.34 + CGFloat(rainMood) * 0.08, 1.2 + CGFloat(progress) * 0.08, 0.78)
        }

        let teacherReflection = cinematicMaterialUnificationNode.childNode(withName: "materialUnityTeacherFloorReflection", recursively: true)
        teacherReflection?.opacity = CGFloat((0.025 + teacherNear * 0.26 + teacherPressure * 0.12 + rainMood * 0.08 + event * 0.08).clamped(to: 0.01...0.48))
        teacherReflection?.position.x = teacherNode.position.x * 0.46
        teacherReflection?.position.z = (teacherNode.position.z + 0.12).clamped(to: -4.2...1.6)
        teacherReflection?.scale = SCNVector3(3.2 + CGFloat(teacherNear) * 0.42, 0.08, 1.2 + CGFloat(event) * 0.16)

        let playerBridge = cinematicMaterialUnificationNode.childNode(withName: "materialUnityPlayerDeskBridge", recursively: true)
        playerBridge?.opacity = CGFloat((0.025 + deskFocus * 0.22 + teacherNear * 0.08 + event * 0.08 + lowLight * 0.06).clamped(to: 0.01...0.38))
        playerBridge?.position.y = Float(0.856 + deskFocus * 0.004 + event * 0.002)

        updateEnvironmentReflectionCatcher(
            game: game,
            lowLight: lowLight,
            event: event,
            teacherPressure: teacherPressure,
            teacherNear: teacherNear,
            deskFocus: deskFocus,
            boardFocus: boardFocus,
            rainMood: rainMood,
            targetID: targetID,
            eventMateID: eventMateID
        )
    }

    private func updateEnvironmentReflectionCatcher(
        game: GameManager,
        lowLight: Double,
        event: Double,
        teacherPressure: Double,
        teacherNear: Double,
        deskFocus: Double,
        boardFocus: Double,
        rainMood: Double,
        targetID: Int?,
        eventMateID: Int?
    ) {
        environmentReflectionCatcherNode.opacity = CGFloat((0.06 + lowLight * 0.2 + rainMood * 0.22 + event * 0.16 + teacherPressure * 0.08 + deskFocus * 0.08).clamped(to: 0.04...0.76))
        environmentReflectionCatcherNode.position.y = Float(rainMood * 0.003 + event * 0.002)
        environmentReflectionCatcherNode.eulerAngles.y = Float(event * 0.006 + (Double(game.currentTurn % 5) - 2) * 0.001)

        for row in 0..<5 {
            let rowMates = game.classmates.filter { $0.seat.row == row }
            let phoneLoad = Double(rowMates.filter { $0.state == .usingPhone }.count)
            let pressureLoad = Double(rowMates.filter { $0.state == .anxious || $0.state == .crying || $0.state == .covering }.count)
            let rowTarget = rowMates.contains { $0.id == targetID } ? 1.0 : 0.0
            let rowEvent = rowMates.contains { $0.id == eventMateID } ? 1.0 : 0.0
            let rowDepth = Double(row) / 4.0
            let rowRead = (phoneLoad * 0.05 + pressureLoad * 0.06 + rowTarget * 0.12 + rowEvent * 0.14 + lowLight * 0.08 + rainMood * 0.1 + event * 0.08).clamped(to: 0...0.48)

            let floorWash = environmentReflectionCatcherNode.childNode(withName: "reflectionRowFloorWash\(row)", recursively: true)
            floorWash?.opacity = CGFloat((0.025 + rowRead + rowDepth * 0.025).clamped(to: 0.01...0.48))
            floorWash?.scale = SCNVector3(1 + CGFloat(rowRead) * 0.12, 1, 1 + CGFloat(rainMood + event) * 0.06)

            let deskSheen = environmentReflectionCatcherNode.childNode(withName: "reflectionRowDeskSheen\(row)", recursively: true)
            deskSheen?.opacity = CGFloat((0.025 + deskFocus * 0.08 + rowRead * 0.76 + teacherPressure * 0.04).clamped(to: 0.01...0.4))
            deskSheen?.position.y = Float(0.874 + rowRead * 0.004 + event * 0.002)
        }

        for classmate in game.classmates {
            let statePressure: Double
            switch classmate.state {
            case .usingPhone:
                statePressure = 0.28 + lowLight * 0.12
            case .crying:
                statePressure = 0.32 + event * 0.12
            case .anxious, .covering:
                statePressure = 0.24 + (classmate.stress / 100).clamped(to: 0...1) * 0.14
            case .sleeping:
                statePressure = 0.16 + lowLight * 0.08
            case .studying:
                statePressure = 0.18 + deskFocus * 0.08
            case .offeringHelp, .lookingAtPlayer:
                statePressure = 0.2
            }
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let seatX = Float(classmate.seat.column) * 1.2 - 2.4
            let seatZ = Float(classmate.seat.row) * 1.45 - 2.25
            let pressure = (0.04 + statePressure + (isTarget ? 0.18 : 0) + (isEventMate ? 0.2 : 0) + teacherPressure * 0.06 + rainMood * 0.08 + event * 0.06).clamped(to: 0.02...0.68)

            let floorBody = environmentReflectionCatcherNode.childNode(withName: "reflectionSeatFloorBody\(classmate.id)", recursively: true)
            floorBody?.opacity = CGFloat((0.02 + pressure * 0.42 + rainMood * 0.1).clamped(to: 0.01...0.42))
            floorBody?.position = SCNVector3(seatX, Float(0.071 + rainMood * 0.004 + event * 0.002), seatZ + 0.58)
            floorBody?.scale = SCNVector3(2.4 + CGFloat(pressure) * 0.3, 0.08, 0.82 + CGFloat(event) * 0.08)

            let deskBody = environmentReflectionCatcherNode.childNode(withName: "reflectionSeatDeskBody\(classmate.id)", recursively: true)
            deskBody?.opacity = CGFloat((0.018 + pressure * 0.36 + deskFocus * 0.08).clamped(to: 0.01...0.38))
            deskBody?.position = SCNVector3(seatX, Float(0.876 + pressure * 0.004), seatZ + 0.22)

            let windowGhost = environmentReflectionCatcherNode.childNode(withName: "reflectionSeatWindowGhost\(classmate.id)", recursively: true)
            windowGhost?.opacity = CGFloat((0.015 + lowLight * 0.12 + rainMood * 0.12 + pressure * 0.18 + (classmate.state == .lookingAtPlayer ? 0.08 : 0)).clamped(to: 0.005...0.34))
            windowGhost?.position = SCNVector3(3.91, Float(1.08 + pressure * 0.018), seatZ + 0.08)

            let phonePool = environmentReflectionCatcherNode.childNode(withName: "reflectionSeatPhonePool\(classmate.id)", recursively: true)
            phonePool?.opacity = classmate.state == .usingPhone ? CGFloat((0.18 + lowLight * 0.28 + rainMood * 0.12 + event * 0.08).clamped(to: 0.08...0.62)) : CGFloat((0.005 + pressure * 0.04).clamped(to: 0...0.08))
            phonePool?.position = SCNVector3(seatX + 0.15, Float(0.878 + lowLight * 0.004), seatZ + 0.12)

            let pressureEdge = environmentReflectionCatcherNode.childNode(withName: "reflectionSeatPressureEdge\(classmate.id)", recursively: true)
            pressureEdge?.opacity = CGFloat(((isTarget ? 0.18 : 0.02) + (isEventMate ? 0.2 : 0) + event * 0.08 + (classmate.state == .anxious || classmate.state == .covering ? 0.12 : 0)).clamped(to: 0...0.46))
            pressureEdge?.position = SCNVector3(seatX, Float(0.882 + pressure * 0.003), seatZ + 0.02)
        }

        let teacherFloor = environmentReflectionCatcherNode.childNode(withName: "reflectionTeacherFloorGhost", recursively: true)
        teacherFloor?.opacity = CGFloat((0.025 + teacherNear * 0.26 + teacherPressure * 0.12 + rainMood * 0.12 + event * 0.1).clamped(to: 0.01...0.52))
        teacherFloor?.position = SCNVector3(teacherNode.position.x * 0.46, Float(0.072 + rainMood * 0.004), (teacherNode.position.z + 0.12).clamped(to: -4.4...1.6))
        teacherFloor?.scale = SCNVector3(3.0 + CGFloat(teacherNear) * 0.42, 0.08, 1.05 + CGFloat(event) * 0.18)

        environmentReflectionCatcherNode.childNode(withName: "reflectionBlackboardFloorGhost", recursively: true)?.opacity = CGFloat((0.02 + boardFocus * 0.24 + lowLight * 0.1 + rainMood * 0.08 + event * 0.08).clamped(to: 0.01...0.38))
        environmentReflectionCatcherNode.childNode(withName: "reflectionPlayerDeskCatch", recursively: true)?.opacity = CGFloat((0.025 + deskFocus * 0.26 + teacherNear * 0.08 + event * 0.08 + lowLight * 0.06).clamped(to: 0.01...0.44))
        environmentReflectionCatcherNode.childNode(withName: "reflectionPlayerFloorContact", recursively: true)?.opacity = CGFloat((0.025 + deskFocus * 0.18 + teacherNear * 0.1 + rainMood * 0.08 + event * 0.08).clamped(to: 0.01...0.36))
    }

    private func updateClassroomMotionEcho(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let eventPressure = eventIntensity.vignette.clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let teacherIndex = game.teacher.positionIndex
        let pulse = Double(game.currentTurn % 6) / 6.0

        classroomMotionEchoNode.opacity = CGFloat((0.12 + teacherPressure * 0.22 + eventPressure * 0.24 + lowLight * 0.08 + teacherNear * 0.18).clamped(to: 0.08...0.72))
        classroomMotionEchoNode.childNode(withName: "motionTeacherStepAirPush", recursively: true)?.opacity = CGFloat((0.06 + teacherNear * 0.32 + teacherPressure * 0.14 + eventPressure * 0.08).clamped(to: 0.02...0.48))
        classroomMotionEchoNode.childNode(withName: "motionTeacherStepAirPush", recursively: true)?.position.x = teacherNode.position.x * 0.42
        classroomMotionEchoNode.childNode(withName: "motionEventStillnessField", recursively: true)?.opacity = CGFloat((0.04 + eventPressure * 0.38 + teacherPressure * 0.1).clamped(to: 0.02...0.5))
        classroomMotionEchoNode.childNode(withName: "motionPlayerDeskPulse", recursively: true)?.opacity = CGFloat((0.04 + teacherNear * 0.28 + eventPressure * 0.16).clamped(to: 0.02...0.42))

        for row in 0..<5 {
            let activeRow = abs(row - max(0, min(4, teacherIndex / 2)))
            let rowWeight = (0.05 + teacherPressure * 0.08 + eventPressure * 0.08 + (activeRow == 0 ? 0.22 : activeRow == 1 ? 0.1 : 0) + pulse * 0.035).clamped(to: 0.03...0.42)
            let wake = classroomMotionEchoNode.childNode(withName: "motionRowAttentionWake\(row)", recursively: true)
            wake?.opacity = CGFloat(rowWeight)
            wake?.position.y = Float(0.88 + rowWeight * 0.028)
            wake?.eulerAngles.y = Float(-0.025 + Double(row % 3) * 0.018 + eventPressure * 0.012)
            classroomMotionEchoNode.childNode(withName: "motionFloorBreathRow\(row)", recursively: true)?.opacity = CGFloat((0.04 + rowWeight * 0.55 + lowLight * 0.04).clamped(to: 0.02...0.3))
        }

        for classmate in game.classmates {
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stress = (classmate.stress / 100).clamped(to: 0...1)
            let stateShock: Double
            switch classmate.state {
            case .anxious, .covering:
                stateShock = 0.2
            case .crying:
                stateShock = 0.28
            case .usingPhone:
                stateShock = 0.18
            case .sleeping:
                stateShock = -0.04
            default:
                stateShock = 0.06
            }
            let attention = (0.04 + stress * 0.12 + teacherPressure * 0.08 + eventPressure * 0.12 + stateShock + (isTarget ? 0.34 : 0) + (isEventMate ? 0.28 : 0)).clamped(to: 0...0.72)
            let deskJolt = classroomMotionEchoNode.childNode(withName: "motionStudentDeskJolt\(classmate.id)", recursively: true)
            deskJolt?.opacity = CGFloat(attention)
            deskJolt?.position.y = Float(0.842 + attention * 0.018 + pulse * 0.004)
            deskJolt?.eulerAngles.y = Float(-0.035 + Double(classmate.id % 5) * 0.018 + attention * 0.03)
            let shoulder = classroomMotionEchoNode.childNode(withName: "motionStudentShoulderEcho\(classmate.id)", recursively: true)
            shoulder?.opacity = CGFloat((attention * 0.72 + (isTarget ? 0.12 : 0)).clamped(to: 0...0.58))
            shoulder?.position.y = Float(0.99 + attention * 0.02)
            shoulder?.eulerAngles.z = Float(-0.03 + Double(classmate.id % 4) * 0.02 + (isTarget ? 0.035 : 0))
        }
    }

    private func updateTeacherStudentPressureField(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let eventPressure = eventIntensity.vignette.clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let teacherRow = max(0, min(4, Int(round((Double(teacherNode.position.z) + 2.25) / 1.45))))
        let targetMode = targetID == nil ? 0.0 : 1.0
        let rearView = game.cameraPose == .rear ? 1.0 : 0.0

        teacherStudentPressureFieldNode.opacity = CGFloat((0.06 + teacherPressure * 0.24 + eventPressure * 0.18 + lowLight * 0.1 + teacherNear * 0.16 + targetMode * 0.1 + rearView * 0.08).clamped(to: 0.04...0.72))
        teacherStudentPressureFieldNode.position.y = Float(eventPressure * 0.004 + teacherNear * 0.003)
        teacherStudentPressureFieldNode.eulerAngles.y = Float((Double(game.teacher.positionIndex % 5) - 2) * 0.002 + eventPressure * 0.006)

        if let sweep = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldTeacherGazeSweep", recursively: true) {
            sweep.position.x = teacherNode.position.x * 0.46
            sweep.position.z = teacherNode.position.z + 0.72
            sweep.opacity = CGFloat((0.04 + teacherPressure * 0.22 + teacherNear * 0.2 + eventPressure * 0.1).clamped(to: 0.02...0.52))
            sweep.eulerAngles.y = Float(-0.18 + Double(teacherNode.position.x) * -0.04 + targetMode * 0.08)
            sweep.scale = SCNVector3(1 + CGFloat(teacherNear) * 0.18 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(teacherPressure) * 0.12)
        }
        if let wake = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldTeacherWakePool", recursively: true) {
            wake.position.x = teacherNode.position.x
            wake.position.z = teacherNode.position.z + 0.18
            wake.opacity = CGFloat((0.04 + teacherNear * 0.24 + teacherPressure * 0.12 + eventPressure * 0.08).clamped(to: 0.02...0.44))
            wake.scale = SCNVector3(2.8 + CGFloat(teacherNear) * 0.5, 0.08, 1.4 + CGFloat(eventPressure) * 0.18)
        }
        if let target = game.selectedTeacherTarget, game.teacher.focusMode == .selectedStudent {
            let x = Float(target.seat.column) * 1.2 - 2.4
            let z = Float(target.seat.row) * 1.45 - 2.25
            let deltaX = Double(x - teacherNode.position.x)
            let deltaZ = Double(z - teacherNode.position.z)
            let distance = sqrt(deltaX * deltaX + deltaZ * deltaZ)
            let beam = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldTargetBeam", recursively: true)
            beam?.position = SCNVector3((teacherNode.position.x + x) * 0.5, 0.094, (teacherNode.position.z + z) * 0.5 + 0.08)
            beam?.opacity = CGFloat((0.16 + teacherPressure * 0.32 + teacherNear * 0.18 + eventPressure * 0.1).clamped(to: 0.08...0.72))
            beam?.eulerAngles.y = Float(atan2(deltaX, deltaZ))
            beam?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.08, 1, max(0.45, CGFloat(distance) / 4.6))
        } else {
            teacherStudentPressureFieldNode.childNode(withName: "pressureFieldTargetBeam", recursively: true)?.opacity = 0
        }

        teacherStudentPressureFieldNode.childNode(withName: "pressureFieldPlayerThreatPool", recursively: true)?.opacity = CGFloat((0.03 + teacherNear * 0.28 + eventPressure * 0.14 + (game.viewMode == .student ? 0.08 : 0)).clamped(to: 0.01...0.5))
        for row in 0..<5 {
            let rowDistance = Double(abs(row - teacherRow))
            let rowTarget = game.selectedTeacherTarget?.seat.row == row && game.teacher.focusMode == .selectedStudent ? 1.0 : 0.0
            let rowWeight = (0.04 + max(0, 0.24 - rowDistance * 0.08) + teacherPressure * 0.12 + eventPressure * 0.08 + rowTarget * 0.22 + rearView * 0.04).clamped(to: 0.02...0.58)
            let sweep = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldRowSweep\(row)", recursively: true)
            sweep?.opacity = CGFloat(rowWeight)
            sweep?.position.y = Float(0.076 + rowWeight * 0.015)
            sweep?.scale = SCNVector3(1 + CGFloat(rowTarget) * 0.08, 1, 1 + CGFloat(eventPressure) * 0.05)
            teacherStudentPressureFieldNode.childNode(withName: "pressureFieldRowShoulderFreeze\(row)", recursively: true)?.opacity = CGFloat((0.02 + rowWeight * 0.44 + eventPressure * 0.06).clamped(to: 0.01...0.34))
            teacherStudentPressureFieldNode.childNode(withName: "pressureFieldRowDeskLipTension\(row)", recursively: true)?.opacity = CGFloat((0.03 + rowWeight * 0.5 + lowLight * 0.04).clamped(to: 0.02...0.36))
        }

        for classmate in game.classmates {
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stress = (classmate.stress / 100).clamped(to: 0...1)
            let suspicion = (classmate.suspicionOfPlayer / 100).clamped(to: 0...1)
            let rowDistance = Double(abs(classmate.seat.row - teacherRow))
            let sweepPressure = max(0, 0.18 - rowDistance * 0.055)
            let stateWeight: Double
            switch classmate.state {
            case .usingPhone:
                stateWeight = 0.2 + suspicion * 0.18
            case .anxious, .covering:
                stateWeight = 0.22 + stress * 0.16
            case .crying:
                stateWeight = 0.26 + eventPressure * 0.08
            case .sleeping:
                stateWeight = 0.18 + teacherPressure * 0.08
            case .offeringHelp, .lookingAtPlayer:
                stateWeight = 0.14
            case .studying:
                stateWeight = 0.1
            }
            let personalPressure = (0.03 + sweepPressure + stateWeight + (isTarget ? 0.32 : 0) + (isEventMate ? 0.24 : 0) + eventPressure * 0.08).clamped(to: 0.01...0.78)
            let seatPin = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldStudentSeatPin\(classmate.id)", recursively: true)
            seatPin?.opacity = CGFloat(personalPressure)
            seatPin?.scale = SCNVector3(1.8 + CGFloat(personalPressure) * 0.28, 0.08, 1.2 + CGFloat(isTarget ? 0.22 : 0))
            let gazeCut = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldStudentGazeCut\(classmate.id)", recursively: true)
            gazeCut?.opacity = CGFloat((personalPressure * 0.42 + (isTarget ? 0.22 : 0)).clamped(to: 0.01...0.52))
            gazeCut?.position.y = Float(0.994 + personalPressure * 0.018)
            gazeCut?.eulerAngles.y = Float(((teacherNode.position.x - (Float(classmate.seat.column) * 1.2 - 2.4)) * 0.035).clamped(to: -0.12...0.12))
            let deskLock = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldStudentDeskLock\(classmate.id)", recursively: true)
            deskLock?.opacity = CGFloat((personalPressure * 0.48 + lowLight * 0.04).clamped(to: 0.02...0.42))
            deskLock?.scale = SCNVector3(1 + CGFloat(isTarget ? 0.12 : 0), 1, 1 + CGFloat(eventPressure) * 0.05)
        }

        for index in 0..<6 {
            let slice = teacherStudentPressureFieldNode.childNode(withName: "pressureFieldAirStillnessSlice\(index)", recursively: true)
            slice?.opacity = CGFloat((0.015 + eventPressure * 0.12 + teacherPressure * 0.06 + lowLight * 0.05 - Double(index) * 0.006).clamped(to: 0.005...0.22))
            slice?.position.y = Float(1.08 + Double(index % 3) * 0.18 + eventPressure * 0.006)
        }
    }

    private func updateStudentEnvironmentIntegration(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let eventPressure = eventIntensity.vignette.clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let teacherRow = max(0, min(4, Int(round((Double(teacherNode.position.z) + 2.25) / 1.45))))
        let boardView = game.cameraPose == .board ? 1.0 : 0.0
        let rearView = game.cameraPose == .rear ? 1.0 : 0.0

        studentEnvironmentIntegrationNode.opacity = CGFloat((0.08 + teacherPressure * 0.2 + eventPressure * 0.18 + lowLight * 0.16 + teacherNear * 0.12 + boardView * 0.06 + rearView * 0.08).clamped(to: 0.05...0.78))
        studentEnvironmentIntegrationNode.position.y = Float(eventPressure * 0.003 + teacherNear * 0.003)
        studentEnvironmentIntegrationNode.eulerAngles.y = Float(eventPressure * 0.004 + (Double(game.currentTurn % 5) - 2) * 0.001)
        studentEnvironmentIntegrationNode.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.01, 1 + CGFloat(lowLight) * 0.014, 1)

        for row in 0..<5 {
            let rowDistance = Double(abs(row - teacherRow))
            let rowTarget = game.selectedTeacherTarget?.seat.row == row && game.teacher.focusMode == .selectedStudent ? 1.0 : 0.0
            let rowEvent: Double
            if let eventMateID = eventMateID, game.classmates.contains(where: { $0.seat.row == row && $0.id == eventMateID }) {
                rowEvent = 1.0
            } else {
                rowEvent = 0.0
            }
            let rowPressure = (0.04 + max(0, 0.22 - rowDistance * 0.065) + rowTarget * 0.24 + rowEvent * 0.18 + teacherPressure * 0.12 + eventPressure * 0.1 + lowLight * 0.08).clamped(to: 0.02...0.72)

            let shoulder = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowShoulderOcclusion\(row)", recursively: true)
            shoulder?.opacity = CGFloat((0.04 + rowPressure * 0.52 + eventPressure * 0.06).clamped(to: 0.02...0.48))
            shoulder?.position.y = Float(1.015 + rowPressure * 0.014)
            shoulder?.scale = SCNVector3(1 + CGFloat(rowTarget) * 0.04 + CGFloat(eventPressure) * 0.03, 1, 1)

            let deskLip = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowDeskLipOcclusion\(row)", recursively: true)
            deskLip?.opacity = CGFloat((0.04 + rowPressure * 0.5 + lowLight * 0.08).clamped(to: 0.02...0.44))
            deskLip?.position.y = Float(0.858 + rowPressure * 0.008)

            let window = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowWindowLightAbsorb\(row)", recursively: true)
            window?.opacity = CGFloat((0.035 + lowLight * 0.16 + rowPressure * 0.16 + boardView * 0.04).clamped(to: 0.02...0.36))
            window?.eulerAngles.y = Float((row % 2 == 0 ? -0.035 : 0.025) + eventPressure * 0.035)

            let breath = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowBreathVeil\(row)", recursively: true)
            breath?.opacity = CGFloat((0.03 + lowLight * 0.12 + rowPressure * 0.12 + eventPressure * 0.08 - Double(row) * 0.006).clamped(to: 0.01...0.3))
            breath?.position.y = Float(1.02 + lowLight * 0.012 + eventPressure * 0.008)

            let floor = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowFloorBounce\(row)", recursively: true)
            floor?.opacity = CGFloat((0.035 + lowLight * 0.12 + rowPressure * 0.14 + teacherNear * 0.04).clamped(to: 0.02...0.3))
            floor?.scale = SCNVector3(1 + CGFloat(rowPressure) * 0.08, 1, 1 + CGFloat(eventPressure) * 0.06)

            let windowRake = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowWindowRakeWrap\(row)", recursively: true)
            windowRake?.opacity = CGFloat((0.025 + lowLight * 0.2 + rowPressure * 0.16 + rowTarget * 0.08 + rearView * 0.04).clamped(to: 0.01...0.38))
            windowRake?.eulerAngles.y = Float((row % 2 == 0 ? -0.055 : 0.045) + lowLight * 0.025 + eventPressure * 0.02)

            let rowCast = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowUnifiedCastShadow\(row)", recursively: true)
            rowCast?.opacity = CGFloat((0.03 + rowPressure * 0.32 + teacherPressure * 0.08 + eventPressure * 0.08).clamped(to: 0.015...0.42))
            rowCast?.position.y = Float(0.064 - rowPressure * 0.002)
            rowCast?.scale = SCNVector3(1 + CGFloat(rowPressure) * 0.08, 1, 1 + CGFloat(eventPressure) * 0.06)

            let deskReflection = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvRowDeskReflectionWrap\(row)", recursively: true)
            deskReflection?.opacity = CGFloat((0.025 + game.classroomLightLevel * 0.08 + lowLight * 0.08 + rowPressure * 0.12 + teacherNear * 0.04).clamped(to: 0.01...0.32))
            deskReflection?.position.y = Float(0.874 + rowPressure * 0.004)
        }

        for classmate in game.classmates {
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stress = (classmate.stress / 100).clamped(to: 0...1)
            let suspicion = (classmate.suspicionOfPlayer / 100).clamped(to: 0...1)
            let rowDistance = Double(abs(classmate.seat.row - teacherRow))
            let rowSweep = max(0, 0.2 - rowDistance * 0.055)
            let stateWeight: Double
            switch classmate.state {
            case .usingPhone:
                stateWeight = 0.24 + suspicion * 0.18
            case .anxious, .covering:
                stateWeight = 0.22 + stress * 0.18
            case .crying:
                stateWeight = 0.28 + eventPressure * 0.1
            case .sleeping:
                stateWeight = 0.2 + lowLight * 0.08
            case .offeringHelp, .lookingAtPlayer:
                stateWeight = 0.14 + teacherPressure * 0.04
            case .studying:
                stateWeight = 0.1
            }
            let personal = (0.03 + rowSweep + stateWeight + (isTarget ? 0.3 : 0) + (isEventMate ? 0.24 : 0) + eventPressure * 0.08 + teacherPressure * 0.08).clamped(to: 0.01...0.82)

            let contact = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatBodyContact\(classmate.id)", recursively: true)
            contact?.opacity = CGFloat((0.04 + personal * 0.44 + lowLight * 0.05).clamped(to: 0.02...0.46))
            contact?.scale = SCNVector3(2.6 + CGFloat(personal) * 0.28, 0.08, 1.3 + CGFloat(isTarget ? 0.18 : 0))

            let desk = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatDeskOcclusion\(classmate.id)", recursively: true)
            desk?.opacity = CGFloat((0.04 + personal * 0.46 + lowLight * 0.08).clamped(to: 0.02...0.5))
            desk?.position.y = Float(0.868 + personal * 0.008)

            let rim = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatWindowRim\(classmate.id)", recursively: true)
            rim?.opacity = CGFloat((0.02 + lowLight * 0.08 + personal * 0.2 + (isTarget ? 0.1 : 0)).clamped(to: 0.01...0.38))
            rim?.eulerAngles.y = Float(-0.06 + Double(classmate.seat.row + classmate.seat.column) * 0.012 + eventPressure * 0.04)

            let halo = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatStressHalo\(classmate.id)", recursively: true)
            halo?.opacity = CGFloat((personal * 0.42 + (isEventMate ? 0.16 : 0) + eventPressure * 0.08).clamped(to: 0.02...0.58))
            halo?.position.y = Float(0.982 + personal * 0.012)
            halo?.scale = SCNVector3(1.9 + CGFloat(personal) * 0.22, 0.22, 0.75 + CGFloat(isTarget ? 0.14 : 0))

            let dust = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatPaperDust\(classmate.id)", recursively: true)
            dust?.opacity = CGFloat((0.02 + lowLight * 0.08 + eventPressure * 0.08 + personal * 0.06).clamped(to: 0.01...0.22))
            dust?.position.y = Float(0.892 + lowLight * 0.012 + eventPressure * 0.01)

            let shoulderWrap = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatShoulderLightWrap\(classmate.id)", recursively: true)
            shoulderWrap?.opacity = CGFloat((0.025 + lowLight * 0.16 + personal * 0.18 + (classmate.state == .lookingAtPlayer ? 0.08 : 0) + (isTarget ? 0.1 : 0)).clamped(to: 0.01...0.42))
            shoulderWrap?.position.y = Float(1.04 + personal * 0.01)
            shoulderWrap?.eulerAngles.y = Float(-0.08 + Double(classmate.seat.column) * 0.018 + lowLight * 0.035)

            let deskSkinBounce = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatDeskSkinBounce\(classmate.id)", recursively: true)
            let deskAction: Double
            switch classmate.state {
            case .studying:
                deskAction = 0.2
            case .usingPhone:
                deskAction = 0.16 + suspicion * 0.08
            case .crying, .sleeping:
                deskAction = 0.24
            case .covering, .anxious:
                deskAction = 0.18
            case .offeringHelp, .lookingAtPlayer:
                deskAction = 0.1
            }
            deskSkinBounce?.opacity = CGFloat((0.02 + deskAction + personal * 0.14 + lowLight * 0.06).clamped(to: 0.01...0.42))
            deskSkinBounce?.scale = SCNVector3(2.4 + CGFloat(personal) * 0.16, 0.12, 0.8 + CGFloat(deskAction) * 0.12)

            let floorEcho = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatFloorLightEcho\(classmate.id)", recursively: true)
            floorEcho?.opacity = CGFloat((0.015 + lowLight * 0.12 + personal * 0.12 + eventPressure * 0.08 + (isEventMate ? 0.08 : 0)).clamped(to: 0.005...0.32))
            floorEcho?.scale = SCNVector3(2.4 + CGFloat(personal) * 0.18, 0.06, 0.95 + CGFloat(lowLight) * 0.08)

            let silhouette = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvSeatSilhouetteGrounding\(classmate.id)", recursively: true)
            silhouette?.opacity = CGFloat((0.035 + personal * 0.3 + teacherPressure * 0.08 + eventPressure * 0.08 + (classmate.state == .sleeping || classmate.state == .crying ? 0.12 : 0)).clamped(to: 0.02...0.5))
            silhouette?.eulerAngles.y = Float(Double(classmate.seat.column - 1) * 0.025 + eventPressure * 0.018)
            silhouette?.scale = SCNVector3(1 + CGFloat(personal) * 0.1, 1, 1 + CGFloat(isTarget ? 0.12 : 0))
        }

        let bridge = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvTeacherOcclusionBridge", recursively: true)
        bridge?.opacity = CGFloat((0.03 + teacherNear * 0.26 + teacherPressure * 0.14 + eventPressure * 0.12).clamped(to: 0.01...0.52))
        bridge?.position.x = teacherNode.position.x * 0.26
        bridge?.position.z = Float((Double(teacherNode.position.z) * 0.48 - 0.2).clamped(to: -2.8...1.2))
        bridge?.scale = SCNVector3(1 + CGFloat(teacherNear) * 0.18 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(teacherPressure) * 0.12)

        let spine = studentEnvironmentIntegrationNode.childNode(withName: "studentEnvWindowRowLightSpine", recursively: true)
        spine?.opacity = CGFloat((0.025 + lowLight * 0.18 + eventPressure * 0.08 + rearView * 0.06).clamped(to: 0.01...0.34))
        spine?.position.x = Float(-3.05 + eventPressure * 0.04)
    }

    private func updateClassroomContactShadows(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let targetID = game.teacher.focusMode == .selectedStudent ? game.selectedTeacherTarget?.id : nil
        let eventMateID = activeEventClassmateID(game: game)
        let teacherPressure = CGFloat((game.teacher.institutionalPressure / 100).clamped(to: 0...1))
        let eventPressure = CGFloat(eventIntensity.vignette.clamped(to: 0...1))
        let lowLight = CGFloat((1 - game.classroomLightLevel).clamped(to: 0...1))
        classroomContactShadowNode.opacity = CGFloat((0.22 + teacherPressure * 0.14 + eventPressure * 0.16 + lowLight * 0.18).clamped(to: 0.18...0.64))

        for classmate in game.classmates {
            let isTarget = classmate.id == targetID
            let isEventMate = classmate.id == eventMateID
            let stress = CGFloat((classmate.stress / 100).clamped(to: 0...1))
            let suspicion = CGFloat((classmate.suspicionOfPlayer / 100).clamped(to: 0...1))
            let pressure = CGFloat((Double(stress) * 0.4 + Double(teacherPressure) * 0.24 + Double(eventPressure) * 0.18 + (isTarget ? 0.24 : 0) + (isEventMate ? 0.22 : 0)).clamped(to: 0...1))

            let seatCore = classroomContactShadowNode.childNode(withName: "seatContactCore\(classmate.id)", recursively: true)
            let bodyDesk = classroomContactShadowNode.childNode(withName: "bodyDeskContact\(classmate.id)", recursively: true)
            let deskOcclusion = classroomContactShadowNode.childNode(withName: "deskFrontOcclusionBand\(classmate.id)", recursively: true)
            let chairBack = classroomContactShadowNode.childNode(withName: "chairBackOcclusion\(classmate.id)", recursively: true)
            let floorStretch = classroomContactShadowNode.childNode(withName: "studentFloorStretchShadow\(classmate.id)", recursively: true)

            let stateContact: CGFloat
            switch classmate.state {
            case .sleeping:
                stateContact = 0.36
            case .crying:
                stateContact = 0.42
            case .anxious, .covering:
                stateContact = 0.28
            case .usingPhone:
                stateContact = 0.24
            case .offeringHelp, .lookingAtPlayer:
                stateContact = 0.18
            case .studying:
                stateContact = 0.22
            }

            seatCore?.opacity = CGFloat((0.18 + pressure * 0.22 + stateContact * 0.4).clamped(to: 0.14...0.62))
            seatCore?.scale = SCNVector3(1 + pressure * 0.1, 1, 1 + pressure * 0.06)
            bodyDesk?.opacity = CGFloat((0.08 + stateContact + (classmate.state == .sleeping ? 0.2 : 0) + (classmate.state == .crying ? 0.16 : 0)).clamped(to: 0.06...0.72))
            deskOcclusion?.opacity = CGFloat((0.12 + pressure * 0.18 + suspicion * 0.12 + (isTarget ? 0.16 : 0)).clamped(to: 0.08...0.54))
            chairBack?.opacity = CGFloat((0.12 + pressure * 0.16 + (classmate.state == .covering ? 0.22 : 0)).clamped(to: 0.08...0.48))
            floorStretch?.opacity = CGFloat((0.1 + lowLight * 0.18 + eventPressure * 0.14 + (isTarget ? 0.16 : 0)).clamped(to: 0.08...0.5))
            floorStretch?.eulerAngles.y = Float((classmate.id % 5) - 2) * 0.018 + Float(eventPressure) * 0.02

            for legIndex in 0..<4 {
                let legShadow = classroomContactShadowNode.childNode(withName: "deskLegContactShadow\(classmate.id)_\(legIndex)", recursively: true)
                legShadow?.opacity = CGFloat((0.12 + lowLight * 0.16 + pressure * 0.08).clamped(to: 0.08...0.34))
            }
        }

        for row in 0..<5 {
            let rowNode = classroomContactShadowNode.childNode(withName: "rowDepthContactVeil\(row)", recursively: true)
            rowNode?.opacity = CGFloat((0.06 + CGFloat(row) * 0.018 + eventPressure * 0.07 + lowLight * 0.08).clamped(to: 0.04...0.24))
        }
        classroomContactShadowNode.childNode(withName: "playerSeatContactShadow", recursively: true)?.opacity = CGFloat((0.22 + lowLight * 0.18 + eventPressure * 0.1).clamped(to: 0.18...0.46))
    }

    private func activeEventClassmateID(game: GameManager) -> Int? {
        guard case .event(let event) = game.gameState else { return nil }
        switch event.kind {
        case .classmateCrying(let classmateID),
             .classmateHelpRequest(let classmateID),
             .classmateReport(let classmateID),
             .memoryTrust(let classmateID),
             .memorySuspicion(let classmateID):
            return classmateID
        default:
            return nil
        }
    }

    private func updateTeacherPose(game: GameManager) {
        let body = teacherNode.childNode(withName: "teacherBodyRoot", recursively: true)
        let head = teacherNode.childNode(withName: "teacherHead", recursively: true)
        let hair = teacherNode.childNode(withName: "teacherHair", recursively: true)
        let leftArm = teacherNode.childNode(withName: "teacherLeftArm", recursively: true)
        let rightArm = teacherNode.childNode(withName: "teacherRightArm", recursively: true)
        let leftForearm = teacherNode.childNode(withName: "teacherLeftForearm", recursively: true)
        let rightForearm = teacherNode.childNode(withName: "teacherRightForearm", recursively: true)
        let leftHand = teacherNode.childNode(withName: "teacherLeftHand", recursively: true)
        let rightHand = teacherNode.childNode(withName: "teacherRightHand", recursively: true)
        let leftFoot = teacherNode.childNode(withName: "teacherLeftFoot", recursively: true)
        let rightFoot = teacherNode.childNode(withName: "teacherRightFoot", recursively: true)
        let notebook = teacherNode.childNode(withName: "teacherNotebook", recursively: true)
        let chalk = teacherNode.childNode(withName: "teacherChalk", recursively: true)
        let displayLocation = teacherDisplayLocation(game: game)
        let pressure = Float((game.teacher.institutionalPressure / 100).clamped(to: 0...1))
        let fatigue = Float((game.teacher.fatigue / 100).clamped(to: 0...1))
        let stepPhase = Float((game.currentTurn + game.teacher.positionIndex) % 5 - 2) * 0.018
        let eventPressure = Float(eventVisualIntensity(game: game).vignette.clamped(to: 0...1))
        let lowLight = Float((1 - game.classroomLightLevel).clamped(to: 0...1))

        body?.eulerAngles = SCNVector3(0, 0, 0)
        head?.eulerAngles = SCNVector3(0, 0, 0)
        hair?.eulerAngles = SCNVector3(0, 0, 0)
        leftArm?.eulerAngles.z = 0.1
        rightArm?.eulerAngles.z = -0.1
        leftForearm?.eulerAngles = SCNVector3(0.12, 0, 0.08)
        rightForearm?.eulerAngles = SCNVector3(0.12, 0, -0.08)
        leftHand?.eulerAngles = SCNVector3(0, 0, 0)
        rightHand?.eulerAngles = SCNVector3(0, 0, 0)
        leftFoot?.eulerAngles.x = 0
        rightFoot?.eulerAngles.x = 0
        notebook?.opacity = 0.75
        chalk?.opacity = displayLocation == .podium ? 1.0 : 0.28

        switch displayLocation {
        case .podium:
            head?.eulerAngles.x = -0.05
            rightArm?.eulerAngles.z = -0.34
            rightForearm?.eulerAngles = SCNVector3(0.38, 0, -0.2)
            rightHand?.eulerAngles.z = -0.18
            leftForearm?.eulerAngles = SCNVector3(0.16, 0, 0.18)
            notebook?.opacity = game.teacher.focusMode == .blackboard ? 1.0 : 0.68
            if game.teacher.focusMode == .blackboard && rightHand?.action(forKey: "chalk_write") == nil {
                rightHand?.runAction(.repeatForever(.sequence([
                    .rotateBy(x: 0.03, y: 0, z: -0.05, duration: 0.18),
                    .rotateBy(x: -0.03, y: 0, z: 0.05, duration: 0.22),
                    .wait(duration: 0.32)
                ])), forKey: "chalk_write")
            }
        case .leftAisle, .rightAisle:
            body?.eulerAngles.z = displayLocation == .leftAisle ? -0.04 : 0.04
            head?.eulerAngles.y = displayLocation == .leftAisle ? 0.16 : -0.16
            leftArm?.eulerAngles.z = 0.18
            rightArm?.eulerAngles.z = -0.22
            leftForearm?.eulerAngles = SCNVector3(0.2, 0, 0.14)
            rightForearm?.eulerAngles = SCNVector3(0.28, 0, -0.18)
            leftFoot?.eulerAngles.x = displayLocation == .leftAisle ? 0.08 : 0
            rightFoot?.eulerAngles.x = displayLocation == .rightAisle ? 0.08 : 0
        case .rearDoor:
            body?.eulerAngles.z = 0.06
            head?.eulerAngles.y = -0.28
            head?.eulerAngles.x = -0.06
            leftArm?.eulerAngles.z = 0.26
            rightArm?.eulerAngles.z = -0.06
            leftForearm?.eulerAngles = SCNVector3(0.34, 0, 0.22)
            notebook?.opacity = 0.34
        case .targetDesk:
            body?.eulerAngles.x = -0.1
            head?.eulerAngles.x = -0.14
            leftArm?.eulerAngles.z = -0.08
            rightArm?.eulerAngles.z = -0.36
            leftForearm?.eulerAngles = SCNVector3(0.2, 0, -0.1)
            rightForearm?.eulerAngles = SCNVector3(0.52, 0, -0.28)
            rightHand?.eulerAngles.z = -0.24
            leftFoot?.eulerAngles.x = -0.04
            notebook?.opacity = 0.95
        }

        let isPatrolling = displayLocation == .leftAisle || displayLocation == .rightAisle || displayLocation == .rearDoor
        let isInspecting = displayLocation == .targetDesk || game.teacher.focusMode == .selectedStudent && game.teacher.isNearPlayer
        let boardFocus = game.teacher.focusMode == .blackboard || displayLocation == .podium
        let performanceLayer = teacherNode.childNode(withName: "teacherPerformanceLayer", recursively: true)
        performanceLayer?.opacity = CGFloat((0.16 + Double(pressure) * 0.32 + (isInspecting ? 0.22 : 0) + (isPatrolling ? 0.1 : 0)).clamped(to: 0.12...0.76))
        performanceLayer?.eulerAngles.z = CGFloat(stepPhase * 0.7 + (isInspecting ? -0.018 * pressure : 0))
        performanceLayer?.position.y = CGFloat((boardFocus ? 0.006 : 0.0) + Double(pressure) * 0.004)

        let closeupLayer = teacherNode.childNode(withName: "teacherCloseupFidelityLayer", recursively: true)
        closeupLayer?.opacity = CGFloat((0.1 + Double(pressure) * 0.32 + Double(fatigue) * 0.12 + (game.teacher.isNearPlayer ? 0.22 : 0) + (isInspecting ? 0.18 : 0) + (boardFocus ? 0.08 : 0)).clamped(to: 0.08...0.82))
        closeupLayer?.eulerAngles.z = Float(stepPhase * 0.42 + (isInspecting ? -pressure * 0.018 : 0))
        closeupLayer?.position.y = Float(Double(pressure) * 0.004 + (boardFocus ? 0.004 : 0))
        teacherNode.childNode(withName: "teacherCloseupBrowPressurePlane", recursively: true)?.opacity = CGFloat((0.08 + Double(pressure) * 0.24 + Double(fatigue) * 0.14 + (isInspecting ? 0.12 : 0)).clamped(to: 0.04...0.52))
        teacherNode.childNode(withName: "teacherCloseupNoseBridgeAuthorityCatch", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.14 + (game.teacher.isNearPlayer ? 0.1 : 0)).clamped(to: 0.03...0.34))
        teacherNode.childNode(withName: "teacherCloseupMouthAuthorityCrease", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.22 + Double(fatigue) * 0.12 + (isInspecting ? 0.12 : 0)).clamped(to: 0.03...0.48))
        teacherNode.childNode(withName: "teacherCloseupChalkThumbDust", recursively: true)?.opacity = boardFocus ? CGFloat((0.22 + Double(pressure) * 0.14).clamped(to: 0.16...0.5)) : 0.04
        teacherNode.childNode(withName: "teacherCloseupFingerPressurePad", recursively: true)?.opacity = boardFocus || isInspecting ? CGFloat((0.18 + Double(pressure) * 0.16).clamped(to: 0.12...0.46)) : 0.04
        teacherNode.childNode(withName: "teacherCloseupSuitChestFiber", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.12 + Double(fatigue) * 0.08 + (isPatrolling ? 0.08 : 0)).clamped(to: 0.03...0.32))
        teacherNode.childNode(withName: "teacherCloseupCollarOilShadow", recursively: true)?.opacity = CGFloat((0.08 + Double(fatigue) * 0.18 + Double(pressure) * 0.08).clamped(to: 0.04...0.36))
        for sideName in ["Left", "Right"] {
            let sideBias = sideName == "Left" ? 0.94 : 1.0
            teacherNode.childNode(withName: "teacherCloseup\(sideName)LensEdgeGlint", recursively: true)?.opacity = CGFloat((0.08 + Double(pressure) * 0.24 + (game.teacher.isNearPlayer ? 0.18 : 0) + (sideName == "Right" && boardFocus ? 0.08 : 0)).clamped(to: 0.04...0.58) * sideBias)
            teacherNode.childNode(withName: "teacherCloseup\(sideName)UnderEyeFatigue", recursively: true)?.opacity = CGFloat((0.06 + Double(fatigue) * 0.22 + Double(pressure) * 0.12 + (isInspecting ? 0.08 : 0)).clamped(to: 0.03...0.42) * sideBias)
            teacherNode.childNode(withName: "teacherCloseup\(sideName)CheekAuthoritySheen", recursively: true)?.opacity = CGFloat((0.04 + Double(pressure) * 0.12 + (game.teacher.isNearPlayer ? 0.08 : 0)).clamped(to: 0.02...0.28) * sideBias)
            teacherNode.childNode(withName: "teacherCloseup\(sideName)CuffFiberCatch", recursively: true)?.opacity = CGFloat((0.05 + Double(fatigue) * 0.08 + (isPatrolling ? 0.12 : 0) + (isInspecting ? 0.12 : 0) + (boardFocus && sideName == "Right" ? 0.14 : 0)).clamped(to: 0.02...0.4) * sideBias)
        }
        for index in 0..<5 {
            let particle = teacherNode.childNode(withName: "teacherCloseupChalkParticle\(index)", recursively: true)
