        teacherNode.childNode(withName: "teacherLeftLensKnifeGlint", recursively: true)?.opacity = CGFloat((0.1 + Double(pressure) * 0.28 + (game.teacher.isNearPlayer ? 0.18 : 0)).clamped(to: 0.06...0.68))
        teacherNode.childNode(withName: "teacherRightLensKnifeGlint", recursively: true)?.opacity = CGFloat((0.08 + Double(pressure) * 0.22 + (isPatrolling ? 0.12 : 0)).clamped(to: 0.05...0.56))
        teacherNode.childNode(withName: "teacherMouthTensionCut", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.28 + Double(fatigue) * 0.12 + (isInspecting ? 0.12 : 0)).clamped(to: 0.03...0.52))
        teacherNode.childNode(withName: "teacherCollarPressureShadow", recursively: true)?.opacity = CGFloat((0.08 + Double(pressure) * 0.2 + Double(fatigue) * 0.1).clamped(to: 0.04...0.42))
        teacherNode.childNode(withName: "teacherShoulderCommandLine", recursively: true)?.opacity = CGFloat((0.08 + Double(pressure) * 0.24 + (isInspecting ? 0.12 : 0)).clamped(to: 0.04...0.46))
        teacherNode.childNode(withName: "teacherCoatCenterTension", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.2 + (isPatrolling ? 0.12 : 0)).clamped(to: 0.03...0.4))
        teacherNode.childNode(withName: "teacherLeftGesturePressureArc", recursively: true)?.opacity = CGFloat((0.05 + (isPatrolling ? 0.18 : 0) + (isInspecting ? 0.12 : 0) + Double(pressure) * 0.12).clamped(to: 0.02...0.44))
        teacherNode.childNode(withName: "teacherRightGesturePressureArc", recursively: true)?.opacity = CGFloat((0.05 + (boardFocus ? 0.24 : 0) + (isInspecting ? 0.2 : 0) + Double(pressure) * 0.14).clamped(to: 0.02...0.54))
        teacherNode.childNode(withName: "teacherLeftWristAuthorityCut", recursively: true)?.opacity = CGFloat((0.06 + (isPatrolling ? 0.14 : 0) + Double(fatigue) * 0.08).clamped(to: 0.03...0.34))
        teacherNode.childNode(withName: "teacherRightWristAuthorityCut", recursively: true)?.opacity = CGFloat((0.06 + (boardFocus || isInspecting ? 0.22 : 0) + Double(pressure) * 0.12).clamped(to: 0.03...0.46))
        for index in 0..<4 {
            let burst = teacherNode.childNode(withName: "teacherChalkAirBurst\(index)", recursively: true)
            burst?.opacity = CGFloat((boardFocus ? 0.16 + Double(pressure) * 0.14 - Double(index) * 0.02 : 0.02).clamped(to: 0.01...0.42))
            burst?.position.y = CGFloat(0.6 + Float(index % 2) * 0.034 + stepPhase * 0.4)
        }
        teacherNode.childNode(withName: "teacherInspectionLeaningShadow", recursively: true)?.opacity = CGFloat((isInspecting ? 0.28 + Double(pressure) * 0.22 : 0.06).clamped(to: 0.03...0.62))
        teacherNode.childNode(withName: "teacherInspectionLeaningShadow", recursively: true)?.position.x = CGFloat(0.2 + stepPhase * 0.9)
        teacherNode.childNode(withName: "teacherPatrolMotionFloorTrail", recursively: true)?.opacity = CGFloat((isPatrolling ? 0.18 + abs(Double(stepPhase)) * 4.0 + Double(pressure) * 0.08 : 0.04).clamped(to: 0.02...0.48))
        teacherNode.childNode(withName: "teacherPatrolMotionFloorTrail", recursively: true)?.eulerAngles.y = CGFloat(stepPhase * 1.6)
        teacherNode.childNode(withName: "teacherPatrolMotionFloorTrail", recursively: true)?.scale = SCNVector3(1 + CGFloat(abs(stepPhase)) * 5.0, 1, 1 + CGFloat(isPatrolling ? 0.2 : 0))

        let authorityLayer = teacherNode.childNode(withName: "teacherAuthorityActionLayer", recursively: true)
        authorityLayer?.opacity = CGFloat((0.1 + Double(pressure) * 0.34 + (isInspecting ? 0.2 : 0) + (isPatrolling ? 0.12 : 0) + (boardFocus ? 0.16 : 0) + (game.teacher.isNearPlayer ? 0.12 : 0)).clamped(to: 0.08...0.84))
        authorityLayer?.eulerAngles.z = CGFloat(stepPhase * 0.5 + (isInspecting ? -pressure * 0.025 : 0))
        authorityLayer?.position.y = CGFloat(Double(pressure) * 0.004 + (boardFocus ? 0.006 : 0))
        teacherNode.childNode(withName: "teacherRightKnuckleChalkPressure", recursively: true)?.opacity = CGFloat((boardFocus ? 0.28 + Double(pressure) * 0.18 : 0.06).clamped(to: 0.03...0.58))
        teacherNode.childNode(withName: "teacherRightKnuckleChalkPressure", recursively: true)?.eulerAngles.z = CGFloat(-0.18 + stepPhase * 1.2)
        teacherNode.childNode(withName: "teacherLeftNotebookGripPressure", recursively: true)?.opacity = CGFloat((0.08 + (isInspecting ? 0.24 : 0) + (isPatrolling ? 0.14 : 0) + Double(fatigue) * 0.12).clamped(to: 0.04...0.5))
        teacherNode.childNode(withName: "teacherLeftNotebookGripPressure", recursively: true)?.eulerAngles.z = CGFloat(-0.28 + stepPhase * 0.9)
        for index in 0..<5 {
            let crumb = teacherNode.childNode(withName: "teacherChalkTipCrumb\(index)", recursively: true)
            crumb?.opacity = CGFloat((boardFocus ? 0.16 + Double(pressure) * 0.12 - Double(index) * 0.018 : 0.02).clamped(to: 0.01...0.4))
            crumb?.position.y = CGFloat(0.56 + Float(index % 2) * 0.026 + stepPhase * 0.24)
            crumb?.position.x = Float(0.29 + Double(index) * 0.034 + Double(stepPhase) * 0.36)
        }
        teacherNode.childNode(withName: "teacherLeftSleeveSnapLine", recursively: true)?.opacity = CGFloat((0.06 + (isPatrolling ? 0.18 : 0) + (isInspecting ? 0.1 : 0) + Double(fatigue) * 0.08).clamped(to: 0.03...0.38))
        teacherNode.childNode(withName: "teacherRightSleeveSnapLine", recursively: true)?.opacity = CGFloat((0.06 + (boardFocus ? 0.2 : 0) + (isInspecting ? 0.18 : 0) + Double(pressure) * 0.12).clamped(to: 0.03...0.48))
        teacherNode.childNode(withName: "teacherCoatAuthoritySilhouette", recursively: true)?.opacity = CGFloat((0.06 + Double(pressure) * 0.18 + (isPatrolling ? 0.14 : 0) + (game.teacher.isNearPlayer ? 0.12 : 0)).clamped(to: 0.03...0.46))
        teacherNode.childNode(withName: "teacherInspectionFingerPoint", recursively: true)?.opacity = CGFloat((isInspecting ? 0.34 + Double(pressure) * 0.18 : 0.03).clamped(to: 0.02...0.64))
        teacherNode.childNode(withName: "teacherInspectionFingerPoint", recursively: true)?.eulerAngles.z = CGFloat(-0.78 - pressure * 0.12)
        teacherNode.childNode(withName: "teacherPatrolCoatWake", recursively: true)?.opacity = CGFloat((isPatrolling ? 0.18 + abs(Double(stepPhase)) * 3.4 + Double(fatigue) * 0.08 : 0.03).clamped(to: 0.02...0.48))
        teacherNode.childNode(withName: "teacherPatrolCoatWake", recursively: true)?.eulerAngles.y = CGFloat(-0.08 + stepPhase * 1.4)
        teacherNode.childNode(withName: "teacherPatrolCoatWake", recursively: true)?.scale = SCNVector3(1 + CGFloat(abs(stepPhase)) * 4.4, 1, 1 + CGFloat(fatigue) * 0.08)
        teacherNode.childNode(withName: "teacherBoardWristGhost", recursively: true)?.opacity = CGFloat((boardFocus ? 0.22 + Double(pressure) * 0.16 : 0.02).clamped(to: 0.01...0.52))
        teacherNode.childNode(withName: "teacherBoardWristGhost", recursively: true)?.eulerAngles.z = CGFloat(-0.24 + stepPhase * 1.6)
        teacherNode.childNode(withName: "teacherNearDeskShadowBlade", recursively: true)?.opacity = CGFloat((isInspecting || game.teacher.isNearPlayer ? 0.22 + Double(pressure) * 0.18 : 0.04).clamped(to: 0.02...0.54))
        teacherNode.childNode(withName: "teacherRearDoorCoolAuthorityRim", recursively: true)?.opacity = CGFloat((displayLocation == .rearDoor ? 0.36 + Double(pressure) * 0.12 : 0.06).clamped(to: 0.03...0.58))

        let nearPresence = game.teacher.isNearPlayer ? 1.0 : 0.0
        let inspectPresence = isInspecting ? 1.0 : 0.0
        let patrolPresence = isPatrolling ? 1.0 : 0.0
        let nearLayer = teacherNode.childNode(withName: "teacherNearPresenceLayer", recursively: true)
        nearLayer?.opacity = CGFloat((0.05 + Double(nearPresence) * 0.34 + Double(inspectPresence) * 0.22 + Double(patrolPresence) * 0.08 + Double(pressure) * 0.18 + Double(eventPressure) * 0.14 + Double(lowLight) * 0.08).clamped(to: 0.03...0.86))
        nearLayer?.eulerAngles.z = CGFloat(stepPhase * 0.72 - pressure * 0.014)
        nearLayer?.position.y = Float(Double(nearPresence) * 0.006 + Double(eventPressure) * 0.004)
        nearLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.018, 1 + CGFloat(nearPresence) * 0.025, 1)
        teacherNode.childNode(withName: "teacherNearPresenceDeskKnifeShadow", recursively: true)?.opacity = CGFloat((0.06 + Double(nearPresence) * 0.34 + Double(inspectPresence) * 0.26 + Double(pressure) * 0.16 + Double(lowLight) * 0.12).clamped(to: 0.03...0.62))
        teacherNode.childNode(withName: "teacherNearPresenceDeskKnifeShadow", recursively: true)?.position.x = Float(0.12 + Double(stepPhase) * 1.4)
        teacherNode.childNode(withName: "teacherNearPresenceDeskKnifeShadow", recursively: true)?.scale = SCNVector3(1 + CGFloat(nearPresence) * 0.18 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(inspectPresence) * 0.12)
        teacherNode.childNode(withName: "teacherNearPresenceBodyOcclusionMass", recursively: true)?.opacity = CGFloat((0.04 + Double(nearPresence) * 0.24 + Double(inspectPresence) * 0.16 + Double(pressure) * 0.1 + Double(lowLight) * 0.08).clamped(to: 0.02...0.46))
        teacherNode.childNode(withName: "teacherNearPresenceBodyOcclusionMass", recursively: true)?.eulerAngles.z = CGFloat(-0.015 + stepPhase * 0.7)
        teacherNode.childNode(withName: "teacherNearPresenceHeadDropPressure", recursively: true)?.opacity = CGFloat((0.04 + Double(nearPresence) * 0.18 + Double(inspectPresence) * 0.22 + Double(pressure) * 0.18 + Double(fatigue) * 0.08).clamped(to: 0.02...0.48))
        teacherNode.childNode(withName: "teacherNearPresenceFingerPressure", recursively: true)?.opacity = CGFloat((0.04 + Double(inspectPresence) * 0.32 + (boardFocus ? 0.12 : 0) + Double(pressure) * 0.18).clamped(to: 0.02...0.58))
        teacherNode.childNode(withName: "teacherNearPresenceFingerPressure", recursively: true)?.position.x = Float(0.36 + Double(stepPhase) * 0.55)
        teacherNode.childNode(withName: "teacherNearPresenceFingerCast", recursively: true)?.opacity = CGFloat((0.03 + Double(inspectPresence) * 0.3 + Double(nearPresence) * 0.12 + Double(pressure) * 0.14).clamped(to: 0.01...0.52))
        teacherNode.childNode(withName: "teacherNearPresenceFingerCast", recursively: true)?.eulerAngles.z = CGFloat(-0.78 - pressure * 0.12 + stepPhase * 0.8)
        teacherNode.childNode(withName: "teacherNearPresenceNotebookOcclusion", recursively: true)?.opacity = CGFloat((0.04 + Double(inspectPresence) * 0.18 + Double(patrolPresence) * 0.14 + Double(fatigue) * 0.12 + Double(lowLight) * 0.08).clamped(to: 0.02...0.44))
        teacherNode.childNode(withName: "teacherNearPresenceNotebookOcclusion", recursively: true)?.eulerAngles.z = CGFloat(-0.24 + stepPhase * 1.1)
        teacherNode.childNode(withName: "teacherNearPresenceChalkCloseSmear", recursively: true)?.opacity = CGFloat(((boardFocus ? 0.22 : 0.03) + Double(inspectPresence) * 0.1 + Double(pressure) * 0.12).clamped(to: 0.01...0.48))
        teacherNode.childNode(withName: "teacherNearPresenceAirPush", recursively: true)?.opacity = CGFloat((0.03 + Double(nearPresence) * 0.2 + Double(patrolPresence) * 0.14 + Double(eventPressure) * 0.12 + Double(pressure) * 0.08).clamped(to: 0.01...0.42))
        teacherNode.childNode(withName: "teacherNearPresenceAirPush", recursively: true)?.position.x = Float(Double(stepPhase) * 1.6)
        teacherNode.childNode(withName: "teacherNearPresenceAirPush", recursively: true)?.scale = SCNVector3(1 + CGFloat(abs(stepPhase)) * 4.0 + CGFloat(eventPressure) * 0.08, 1 + CGFloat(nearPresence) * 0.08, 1)
        for sideName in ["Left", "Right"] {
            let sideBias = sideName == "Left" ? 0.94 : 1.0
            let stepWeight = sideName == "Left" ? max(0, Double(stepPhase)) * 4.4 : max(0, Double(-stepPhase)) * 4.4
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)StepBlade", recursively: true)?.opacity = CGFloat((0.04 + stepWeight + Double(nearPresence) * 0.18 + Double(inspectPresence) * 0.08 + Double(lowLight) * 0.08).clamped(to: 0.02...0.58) * sideBias)
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)StepBlade", recursively: true)?.scale = SCNVector3(2.2 + CGFloat(stepWeight) * 1.8, 0.06, 1.2 + CGFloat(nearPresence) * 0.22)
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)TrouserPullLine", recursively: true)?.opacity = CGFloat((0.04 + Double(patrolPresence) * 0.18 + Double(nearPresence) * 0.1 + Double(pressure) * 0.1).clamped(to: 0.02...0.36) * sideBias)
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)TrouserPullLine", recursively: true)?.eulerAngles.z = CGFloat((sideName == "Left" ? 0.09 : -0.09) + stepPhase * (sideName == "Left" ? 1.2 : -1.1))
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)SleeveSweep", recursively: true)?.opacity = CGFloat((0.04 + Double(inspectPresence) * 0.2 + Double(patrolPresence) * 0.12 + Double(fatigue) * 0.08 + (sideName == "Right" && boardFocus ? 0.12 : 0)).clamped(to: 0.02...0.42) * sideBias)
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)SleeveSweep", recursively: true)?.eulerAngles.z = CGFloat((sideName == "Left" ? 0.2 : -0.2) + stepPhase * (sideName == "Left" ? 1.0 : -1.15))
            teacherNode.childNode(withName: "teacherNearPresence\(sideName)LensSlice", recursively: true)?.opacity = CGFloat((0.06 + Double(nearPresence) * 0.22 + Double(pressure) * 0.2 + Double(lowLight) * 0.12 + Double(eventPressure) * 0.08).clamped(to: 0.03...0.58) * sideBias)
        }
        for index in 0..<5 {
            let drag = teacherNode.childNode(withName: "teacherNearPresenceCoatHemDrag\(index)", recursively: true)
            drag?.opacity = CGFloat((0.03 + Double(patrolPresence) * 0.18 + Double(nearPresence) * 0.12 + Double(fatigue) * 0.08 + Double(index % 2) * 0.02).clamped(to: 0.01...0.38))
            drag?.position.x = Float(-0.2 + Double(index) * 0.1 + Double(stepPhase) * (patrolPresence > 0 ? 1.2 : 0.4))
            drag?.eulerAngles.z = Float(-0.1 + Double(index) * 0.05 + Double(stepPhase) * 1.4)
        }
        for index in 0..<8 {
            let mote = teacherNode.childNode(withName: "teacherNearPresenceChalkBreathMote\(index)", recursively: true)
            mote?.opacity = CGFloat(((boardFocus || isInspecting ? 0.12 : 0.02) + Double(eventPressure) * 0.08 + Double(pressure) * 0.06 - Double(index) * 0.008).clamped(to: 0.01...0.34))
            mote?.position.x = Float(0.2 + Double(index) * 0.035 + Double(stepPhase) * 0.28)
        }

        let patrolLayer = teacherNode.childNode(withName: "teacherPatrolAuthorityLayer", recursively: true)
        let patrolRead = Double(patrolPresence)
        let inspectRead = Double(inspectPresence)
        let nearRead = Double(nearPresence)
        let boardRead = boardFocus ? 1.0 : 0.0
        let stepMagnitude = abs(Double(stepPhase))
        patrolLayer?.opacity = CGFloat((0.05 + patrolRead * 0.24 + inspectRead * 0.22 + boardRead * 0.16 + nearRead * 0.18 + Double(pressure) * 0.22 + Double(eventPressure) * 0.12 + Double(lowLight) * 0.08).clamped(to: 0.03...0.86))
        patrolLayer?.position.y = Float(Double(eventPressure) * 0.004 + nearRead * 0.003)
        patrolLayer?.eulerAngles.z = CGFloat(Double(stepPhase) * 0.7 - inspectRead * Double(pressure) * 0.018)
        patrolLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.014 + CGFloat(nearRead) * 0.016, 1 + CGFloat(max(patrolRead, inspectRead)) * 0.014, 1)

        let floorWake = teacherNode.childNode(withName: "teacherPatrolAuthorityFloorWake", recursively: true)
        floorWake?.opacity = CGFloat((0.04 + patrolRead * 0.24 + nearRead * 0.14 + Double(pressure) * 0.1 + stepMagnitude * 3.0).clamped(to: 0.02...0.52))
        floorWake?.eulerAngles.y = CGFloat(-0.08 + Double(stepPhase) * 1.5)
        floorWake?.scale = SCNVector3(1 + CGFloat(stepMagnitude) * 4.5, 1, 1 + CGFloat(patrolRead) * 0.18)

        let leftStepWeight = max(0, Double(stepPhase)) * 5.0
        let rightStepWeight = max(0, Double(-stepPhase)) * 5.0
        teacherNode.childNode(withName: "teacherPatrolAuthorityLeftStepPress", recursively: true)?.opacity = CGFloat((0.03 + patrolRead * leftStepWeight + nearRead * 0.08).clamped(to: 0.02...0.5))
        teacherNode.childNode(withName: "teacherPatrolAuthorityRightStepPress", recursively: true)?.opacity = CGFloat((0.03 + patrolRead * rightStepWeight + nearRead * 0.08).clamped(to: 0.02...0.5))

        let coatWake = teacherNode.childNode(withName: "teacherPatrolAuthorityCoatWakePlane", recursively: true)
        coatWake?.opacity = CGFloat((0.03 + patrolRead * 0.18 + nearRead * 0.12 + Double(fatigue) * 0.08 + Double(pressure) * 0.08).clamped(to: 0.01...0.42))
        coatWake?.eulerAngles.z = CGFloat(Double(stepPhase) * 0.8)

        for index in 0..<5 {
            let hem = teacherNode.childNode(withName: "teacherPatrolAuthorityHemLag\(index)", recursively: true)
            hem?.opacity = CGFloat((0.02 + patrolRead * 0.18 + nearRead * 0.08 + Double(index % 2) * 0.02 + Double(fatigue) * 0.04).clamped(to: 0.01...0.38))
            hem?.position.x = Float(-0.18 + Double(index) * 0.09 + Double(stepPhase) * (patrolRead > 0 ? 1.1 : 0.35))
            hem?.eulerAngles.z = Float(-0.16 + Double(index) * 0.08 + Double(stepPhase) * 1.4)
        }

        let gazeSweep = teacherNode.childNode(withName: "teacherPatrolAuthorityGazeSweep", recursively: true)
        gazeSweep?.opacity = CGFloat((0.04 + Double(pressure) * 0.22 + inspectRead * 0.2 + patrolRead * 0.12 + nearRead * 0.16).clamped(to: 0.02...0.54))
        gazeSweep?.position.x = Float(Double(stepPhase) * -1.8)
        gazeSweep?.scale = SCNVector3(1 + CGFloat(inspectRead) * 0.22 + CGFloat(pressure) * 0.08, 1, 1)

        let targetLock = teacherNode.childNode(withName: "teacherPatrolAuthorityTargetDeskLock", recursively: true)
        targetLock?.opacity = CGFloat((inspectRead * (0.3 + Double(pressure) * 0.22) + nearRead * 0.08).clamped(to: 0...0.62))
        targetLock?.position.x = Float(0.18 + Double(stepPhase) * 0.8)
        targetLock?.eulerAngles.y = CGFloat(-0.2 + Double(stepPhase) * 1.1)

        let boardWrist = teacherNode.childNode(withName: "teacherPatrolAuthorityBoardWristArc", recursively: true)
        boardWrist?.opacity = CGFloat((boardRead * (0.24 + Double(pressure) * 0.18)).clamped(to: 0...0.58))
        boardWrist?.eulerAngles.z = CGFloat(-0.72 + Double(stepPhase) * 1.6)
        boardWrist?.position.x = Float(0.34 + Double(stepPhase) * 0.38)

        for index in 0..<6 {
            let chalkScatter = teacherNode.childNode(withName: "teacherPatrolAuthorityChalkScatter\(index)", recursively: true)
            chalkScatter?.opacity = CGFloat(((boardFocus ? 0.14 : 0.02) + boardRead * Double(pressure) * 0.12 + Double(eventPressure) * 0.04 - Double(index) * 0.012).clamped(to: 0.01...0.36))
            chalkScatter?.position.x = Float(0.24 + Double(index) * 0.036 + Double(stepPhase) * 0.34)
            chalkScatter?.position.y = Float(0.56 + Double(index % 3) * 0.03 + Double(stepPhase) * 0.12)
        }

        let nearPlayerBlade = teacherNode.childNode(withName: "teacherPatrolAuthorityNearPlayerBlade", recursively: true)
        nearPlayerBlade?.opacity = CGFloat((nearRead * 0.28 + inspectRead * 0.18 + Double(eventPressure) * 0.12 + Double(pressure) * 0.1).clamped(to: 0.02...0.58))
        nearPlayerBlade?.position.x = Float(0.08 + Double(stepPhase) * 1.2)
        nearPlayerBlade?.scale = SCNVector3(1 + CGFloat(nearRead) * 0.2 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(inspectRead) * 0.12)

        let rearDoorCut = teacherNode.childNode(withName: "teacherPatrolAuthorityRearDoorCoolCut", recursively: true)
        rearDoorCut?.opacity = CGFloat((displayLocation == .rearDoor ? 0.34 + Double(pressure) * 0.12 : 0.04).clamped(to: 0.02...0.56))
        rearDoorCut?.eulerAngles.z = CGFloat(-0.08 + Double(stepPhase) * 0.7)

        for sideName in ["Left", "Right"] {
            let sideSign: Double = sideName == "Left" ? -1 : 1
            let sideBias = sideName == "Left" ? 0.94 : 1.0
            let sideStep = sideName == "Left" ? leftStepWeight : rightStepWeight
            let sleeve = teacherNode.childNode(withName: "teacherPatrolAuthority\(sideName)SleeveVector", recursively: true)
            sleeve?.opacity = CGFloat((0.04 + patrolRead * 0.14 + inspectRead * 0.12 + boardRead * (sideName == "Right" ? 0.16 : 0.04) + Double(fatigue) * 0.06).clamped(to: 0.02...0.42) * sideBias)
            sleeve?.eulerAngles.z = CGFloat(sideSign * 0.72 + Double(stepPhase) * sideSign * 1.1)
            let finger = teacherNode.childNode(withName: "teacherPatrolAuthority\(sideName)FingerCommand", recursively: true)
            finger?.opacity = CGFloat((0.03 + inspectRead * 0.22 + boardRead * (sideName == "Right" ? 0.18 : 0.02) + sideStep * 0.02 + Double(pressure) * 0.08).clamped(to: 0.02...0.44) * sideBias)
            finger?.eulerAngles.z = CGFloat(sideSign * 0.18 + Double(stepPhase) * sideSign * 0.9)
        }

        for index in 0..<4 {
            let airSlice = teacherNode.childNode(withName: "teacherPatrolAuthorityAirStillnessSlice\(index)", recursively: true)
            airSlice?.opacity = CGFloat((0.02 + inspectRead * 0.08 + patrolRead * 0.05 + nearRead * 0.06 + Double(pressure) * 0.05 - Double(index) * 0.008).clamped(to: 0.01...0.24))
            airSlice?.position.x = Float(Double(stepPhase) * (0.8 + Double(index) * 0.22))
            airSlice?.scale = SCNVector3(1 + CGFloat(nearRead) * 0.08 + CGFloat(stepMagnitude) * 2.0, 1, 1)
        }
    }

    private func teacherDisplayLocation(game: GameManager) -> TeacherLocation {
        if game.teacher.positionIndex == TeacherLocation.rearDoor.positionIndex {
            return .rearDoor
        }
        if [3, 4].contains(game.teacher.positionIndex) || game.teacher.focusMode == .selectedStudent && game.teacher.isNearPlayer {
            return .targetDesk
        }
        if game.teacher.positionIndex >= 5 {
            return .leftAisle
        }
        if [1, 2].contains(game.teacher.positionIndex) {
            return .rightAisle
        }
        return game.teacher.location
    }

    private func makePlayerDeskProps() -> SCNNode {
        let root = SCNNode()
        root.addChildNode(makePlayerDeskSurfaceDetails())
        playerDeskFocusGlowNode.addChildNode(makePlayerDeskFocusGlow())
        playerDeskFocusGlowNode.opacity = 0.16
        root.addChildNode(playerDeskFocusGlowNode)
        playerHandShadowNode.addChildNode(makePlayerHandShadowLayer())
        playerHandShadowNode.opacity = 0.28
        root.addChildNode(playerHandShadowNode)

