    private func makePlayerDeskSurfaceDetails() -> SCNNode {
        let root = SCNNode()
        let woodEdge = NSColor(calibratedRed: 0.42, green: 0.29, blue: 0.17, alpha: 1)
        let softShadow = NSColor(calibratedWhite: 0.02, alpha: 0.18)
        root.addChildNode(box(width: 0.94, height: 0.028, length: 0.035, color: woodEdge, position: SCNVector3(-0.6, 0.762, 1.98)))
        root.addChildNode(box(width: 0.94, height: 0.008, length: 0.55, color: NSColor(calibratedRed: 0.88, green: 0.72, blue: 0.48, alpha: 0.08), position: SCNVector3(-0.6, 0.807, 1.44)))
        root.addChildNode(box(width: 0.62, height: 0.006, length: 0.5, color: softShadow, position: SCNVector3(-0.62, 0.806, 1.48)))

        for index in 0..<9 {
            let x = -0.96 + Float(index) * 0.09
            let z = 1.2 + Float((index * 17) % 48) / 100
            let scratch = box(width: 0.13 + CGFloat(index % 3) * 0.04, height: 0.004, length: 0.008, color: NSColor(calibratedWhite: 0.94, alpha: 0.14), position: SCNVector3(x, 0.812, z))
            scratch.eulerAngles.y = Float(index % 5) * 0.12
            root.addChildNode(scratch)
        }

        let eraser = box(width: 0.12, height: 0.035, length: 0.06, color: NSColor(calibratedRed: 0.88, green: 0.82, blue: 0.92, alpha: 1), position: SCNVector3(-0.94, 0.835, 1.25))
        eraser.eulerAngles.y = -0.24
        root.addChildNode(eraser)
        root.addChildNode(box(width: 0.126, height: 0.006, length: 0.063, color: softShadow, position: SCNVector3(-0.94, 0.813, 1.25)))

        let sticky = box(width: 0.14, height: 0.006, length: 0.12, color: NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.28, alpha: 1), position: SCNVector3(-0.28, 0.818, 1.18))
        sticky.eulerAngles.y = 0.2
        root.addChildNode(sticky)
        root.addChildNode(box(width: 0.1, height: 0.004, length: 0.01, color: NSColor(calibratedRed: 0.58, green: 0.44, blue: 0.12, alpha: 0.65), position: SCNVector3(-0.285, 0.824, 1.18)))

        let ruler = box(width: 0.036, height: 0.012, length: 0.46, color: NSColor(calibratedRed: 0.78, green: 0.9, blue: 1.0, alpha: 0.46), position: SCNVector3(-1.02, 0.824, 1.54))
        ruler.eulerAngles.y = -0.04
        root.addChildNode(ruler)
        root.addChildNode(makePlayerDeskCloseupDetails())
        return root
    }

