    private func makePlayerBodyPresenceLayer() -> SCNNode {
        let root = SCNNode()
        let uniform = NSColor(calibratedRed: 0.08, green: 0.13, blue: 0.28, alpha: 0.68)
        let uniformLight = NSColor(calibratedRed: 0.28, green: 0.38, blue: 0.72, alpha: 0.18)
        let deepShadow = NSColor(calibratedWhite: 0.0, alpha: 0.22)
        let skinBounce = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.48, alpha: 0.1)

