        let rightSleeve = roundedBox(width: 0.16, height: 0.04, length: 0.2, chamfer: 0.025, color: uniform, position: SCNVector3(-0.34, 0.805, 1.58))
        rightSleeve.name = "playerRightSleeveCuff"
        rightSleeve.eulerAngles = SCNVector3(0.02, 0.24, -0.08)
