        let leftCuffShadow = box(width: 0.18, height: 0.005, length: 0.04, color: deepShadow, position: SCNVector3(-0.91, 0.815, 1.5))
        leftCuffShadow.name = "playerLeftCuffDeskContact"
        leftCuffShadow.eulerAngles.y = -0.28
        root.addChildNode(leftCuffShadow)
        let rightCuffShadow = box(width: 0.18, height: 0.005, length: 0.04, color: deepShadow, position: SCNVector3(-0.34, 0.815, 1.48))
