    private func makePlayerFirstPersonTactileLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "playerFirstPersonTactileLayer"
        let skinSheen = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.56, alpha: 0.14)
        let pressureShadow = NSColor(calibratedWhite: 0.0, alpha: 0.16)
        let cuffBlue = NSColor(calibratedRed: 0.18, green: 0.28, blue: 0.58, alpha: 0.18)
        let phoneBlue = NSColor(calibratedRed: 0.26, green: 0.48, blue: 1.0, alpha: 0.18)
        let paperWhite = NSColor(calibratedWhite: 1.0, alpha: 0.16)
        let snackOil = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.22, alpha: 0.12)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let baseX: Float = sideIndex == 0 ? -0.84 : -0.43
            let baseZ: Float = sideIndex == 0 ? 1.51 : 1.44

            let palmPressure = box(width: 0.24, height: 0.004, length: 0.09, color: pressureShadow, position: SCNVector3(baseX, 0.832, baseZ))
            palmPressure.name = "player\(sideName)PalmTactilePressure"
            palmPressure.eulerAngles.y = side * -0.18
            root.addChildNode(palmPressure)

            let wristPull = box(width: 0.2, height: 0.005, length: 0.035, color: cuffBlue, position: SCNVector3(baseX + side * 0.05, 0.846, baseZ + 0.18))
            wristPull.name = "player\(sideName)SleevePullTactile"
            wristPull.eulerAngles.y = side * -0.2
            root.addChildNode(wristPull)

            for index in 0..<4 {
                let fingerX = baseX + side * (-0.045 + Float(index) * 0.026)
                let finger = box(width: 0.052, height: 0.003, length: 0.01, color: pressureShadow.withAlphaComponent(0.14), position: SCNVector3(fingerX, 0.84, baseZ - 0.105 + Float(index % 2) * 0.032))
                finger.name = "player\(sideName)FingerPadPressure\(index)"
                finger.eulerAngles.y = side * (0.16 + Float(index) * 0.035)
                root.addChildNode(finger)

                let nail = roundedBox(width: 0.018, height: 0.003, length: 0.007, chamfer: 0.003, color: skinSheen, position: SCNVector3(fingerX, 0.856, baseZ - 0.136 + Float(index % 2) * 0.028))
                nail.name = "player\(sideName)FingernailCatch\(index)"
                nail.eulerAngles.y = side * 0.18
                nail.geometry?.firstMaterial?.emission.contents = skinSheen
                root.addChildNode(nail)
            }
        }

        let deskEdgeFriction = box(width: 0.92, height: 0.004, length: 0.018, color: pressureShadow.withAlphaComponent(0.18), position: SCNVector3(-0.61, 0.842, 1.92))
        deskEdgeFriction.name = "playerDeskEdgeSkinFriction"
        root.addChildNode(deskEdgeFriction)

        let paperWriteBuzz = box(width: 0.42, height: 0.004, length: 0.05, color: paperWhite, position: SCNVector3(-0.56, 0.856, 1.38))
        paperWriteBuzz.name = "playerPaperWriteTactileBuzz"
        paperWriteBuzz.eulerAngles.y = -0.08
        root.addChildNode(paperWriteBuzz)

        let phoneThumbWash = box(width: 0.26, height: 0.004, length: 0.16, color: phoneBlue, position: SCNVector3(-0.25, 0.852, 1.54))
        phoneThumbWash.name = "playerPhoneThumbBlueTactile"
        phoneThumbWash.eulerAngles.y = 0.18
        phoneThumbWash.geometry?.firstMaterial?.emission.contents = phoneBlue
        root.addChildNode(phoneThumbWash)

        let snackGrease = box(width: 0.18, height: 0.004, length: 0.08, color: snackOil, position: SCNVector3(-0.04, 0.836, 1.33))
        snackGrease.name = "playerSnackGreaseFingerSheen"
        snackGrease.eulerAngles.y = 0.36
        root.addChildNode(snackGrease)

