    private func makePlayerHandAnatomyFidelityLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "playerHandAnatomyFidelityLayer"
        let skinCatch = NSColor(calibratedRed: 1.0, green: 0.76, blue: 0.58, alpha: 0.16)
        let skinShadow = NSColor(calibratedRed: 0.16, green: 0.055, blue: 0.038, alpha: 0.16)
        let nailCatch = NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.8, alpha: 0.14)
        let cuffShadow = NSColor(calibratedRed: 0.04, green: 0.07, blue: 0.16, alpha: 0.2)
        let paperPressure = NSColor(calibratedWhite: 1.0, alpha: 0.13)
        let phoneBlue = NSColor(calibratedRed: 0.22, green: 0.46, blue: 1.0, alpha: 0.16)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"
            let baseX: Float = sideIndex == 0 ? -0.84 : -0.43
            let baseZ: Float = sideIndex == 0 ? 1.51 : 1.44

            let palmCrease = box(width: 0.19, height: 0.004, length: 0.018, color: skinShadow, position: SCNVector3(baseX + side * 0.028, 0.858, baseZ - 0.038))
            palmCrease.name = "player\(sideName)PalmLifeLine"
            palmCrease.eulerAngles.y = side * -0.22
            root.addChildNode(palmCrease)

            let wristTendon = capsule(radius: 0.0034, height: 0.16, color: skinCatch.withAlphaComponent(0.22), position: SCNVector3(baseX - side * 0.058, 0.866, baseZ + 0.088), rotation: SCNVector4(0, 0, 1, side * 0.62))
            wristTendon.name = "player\(sideName)WristTendonCatch"
            root.addChildNode(wristTendon)

            let cuffDrag = box(width: 0.19, height: 0.006, length: 0.04, color: cuffShadow, position: SCNVector3(baseX - side * 0.07, 0.848, baseZ + 0.16))
            cuffDrag.name = "player\(sideName)CuffDragShadow"
            cuffDrag.eulerAngles.y = side * -0.24
            root.addChildNode(cuffDrag)

            for index in 0..<4 {
                let fingerX = baseX + side * (-0.045 + Float(index) * 0.026)
                let ridge = box(width: 0.05, height: 0.004, length: 0.009, color: skinCatch, position: SCNVector3(fingerX, 0.864, baseZ - 0.09 + Float(index % 2) * 0.03))
                ridge.name = "player\(sideName)KnuckleAnatomyRidge\(index)"
                ridge.eulerAngles.y = side * (0.18 + Float(index) * 0.035)
                root.addChildNode(ridge)

                let pad = sphere(radius: 0.014, color: skinShadow.withAlphaComponent(0.12), position: SCNVector3(fingerX + side * 0.006, 0.842, baseZ - 0.122 + Float(index % 2) * 0.028), scale: SCNVector3(1.5, 0.18, 0.55))
                pad.name = "player\(sideName)FingerPadAnatomyPress\(index)"
                pad.eulerAngles.y = side * 0.18
                root.addChildNode(pad)

                let nail = box(width: 0.018, height: 0.003, length: 0.006, color: nailCatch, position: SCNVector3(fingerX + side * 0.018, 0.867, baseZ - 0.148 + Float(index % 2) * 0.024))
                nail.name = "player\(sideName)NailEdgeAnatomyCatch\(index)"
                nail.eulerAngles.y = side * 0.2
                nail.geometry?.firstMaterial?.emission.contents = nailCatch
                root.addChildNode(nail)
            }
        }

        let paperGrip = box(width: 0.38, height: 0.004, length: 0.042, color: paperPressure, position: SCNVector3(-0.55, 0.861, 1.36))
        paperGrip.name = "playerRightHandPaperGripPressure"
        paperGrip.eulerAngles.y = -0.08
        root.addChildNode(paperGrip)

        let penPivot = sphere(radius: 0.018, color: skinCatch.withAlphaComponent(0.18), position: SCNVector3(-0.43, 0.868, 1.39), scale: SCNVector3(1.2, 0.28, 0.85))
        penPivot.name = "playerPenGripJointPivot"
        root.addChildNode(penPivot)

        let phoneThumb = box(width: 0.22, height: 0.004, length: 0.08, color: phoneBlue, position: SCNVector3(-0.25, 0.862, 1.54))
        phoneThumb.name = "playerLeftThumbPhoneAnatomyGlow"
        phoneThumb.eulerAngles.y = 0.2
        phoneThumb.geometry?.firstMaterial?.emission.contents = phoneBlue
        root.addChildNode(phoneThumb)

        let snackOil = box(width: 0.18, height: 0.004, length: 0.05, color: NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.3, alpha: 0.11), position: SCNVector3(-0.06, 0.848, 1.32))
        snackOil.name = "playerSnackOilCuticleSheen"
        snackOil.eulerAngles.y = 0.36
        root.addChildNode(snackOil)

        root.opacity = 0.18
        return root
    }

