                position: SCNVector3(-0.9 + Float(index % 3) * 0.05, 0.849, 1.48 + Float(index / 3) * 0.045),
                scale: SCNVector3(1.4, 0.18, 0.72)
            )
            print.name = "playerDeskMaterialLeftHandOilPrint\(index)"
            root.addChildNode(print)
        }

        for index in 0..<6 {
            let print = sphere(
                radius: 0.009 + CGFloat(index % 2) * 0.0015,
                color: skinOil.withAlphaComponent(0.12),
                position: SCNVector3(-0.46 + Float(index % 3) * 0.045, 0.85, 1.4 + Float(index / 3) * 0.04),
                scale: SCNVector3(1.35, 0.18, 0.7)
            )
            print.name = "playerDeskMaterialRightHandOilPrint\(index)"
            root.addChildNode(print)
        }

        let phoneGlass = box(width: 0.32, height: 0.004, length: 0.22, color: pressureBlue.withAlphaComponent(0.12), position: SCNVector3(-0.22, 0.834, 1.55))
        phoneGlass.name = "playerDeskMaterialPhoneGlassReflection"
        phoneGlass.eulerAngles.y = 0.14
        root.addChildNode(phoneGlass)

        let phoneEdgeShadow = box(width: 0.22, height: 0.003, length: 0.032, color: deepScratch.withAlphaComponent(0.16), position: SCNVector3(-0.22, 0.827, 1.705))
        phoneEdgeShadow.name = "playerDeskMaterialPhoneEdgeOcclusion"
        phoneEdgeShadow.eulerAngles.y = 0.14
        root.addChildNode(phoneEdgeShadow)

        let teacherDrop = box(width: 1.05, height: 0.005, length: 0.22, color: teacherShadow, position: SCNVector3(-0.58, 0.858, 1.74))
        teacherDrop.name = "playerDeskMaterialTeacherShadowDrop"
        teacherDrop.eulerAngles.y = -0.04
        root.addChildNode(teacherDrop)

        let deskFrontPolish = box(width: 0.92, height: 0.004, length: 0.04, color: varnish.withAlphaComponent(0.12), position: SCNVector3(-0.6, 0.84, 1.96))
        deskFrontPolish.name = "playerDeskMaterialFrontEdgePolish"
        root.addChildNode(deskFrontPolish)

        for index in 0..<10 {
            let mote = sphere(
                radius: 0.0035 + CGFloat(index % 3) * 0.0008,
                color: paperFiber.withAlphaComponent(0.12),
