                .moveBy(x: CGFloat((index % 3) - 1) * 0.004, y: 0.012, z: 0.006, duration: 1.1 + Double(index % 4) * 0.12),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.004, y: -0.012, z: -0.006, duration: 1.3 + Double(index % 5) * 0.1)
            ])), forKey: "player_desk_close_dust")
            root.addChildNode(mote)
        }

        root.opacity = 0.16
        return root
    }

