            edge.eulerAngles.y = 0.025 + Float(index) * 0.012
            root.addChildNode(edge)
        }
        for index in 0..<6 {
            let indent = box(width: 0.08 + CGFloat(index % 3) * 0.035, height: 0.003, length: 0.004, color: NSColor(calibratedRed: 0.12, green: 0.16, blue: 0.24, alpha: 0.18), position: SCNVector3(-0.75 + Float(index) * 0.07, 0.835, 1.38 + Float(index % 3) * 0.055))
