        let wornPalmSpot = box(width: 0.26, height: 0.004, length: 0.16, color: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.5, alpha: 0.08), position: SCNVector3(-0.78, 0.834, 1.58))
