    private func addHandDetails(to handNode: SCNNode, mirrored: Bool) {
        let side: Float = mirrored ? -1 : 1
        let palm = sphere(radius: 0.038, color: skinTone, position: SCNVector3(side * 0.12, -0.003, -0.015), scale: SCNVector3(1.05, 0.62, 0.85))
        palm.name = mirrored ? "leftPlayerPalm" : "rightPlayerPalm"
        handNode.addChildNode(palm)
        let cuffColor = NSColor(calibratedRed: 0.13, green: 0.18, blue: 0.34, alpha: 1)
        let cuff = roundedBox(width: 0.14, height: 0.036, length: 0.09, chamfer: 0.018, color: cuffColor, position: SCNVector3(side * -0.045, 0.003, 0.07))
        cuff.name = mirrored ? "leftPlayerCuff" : "rightPlayerCuff"
        cuff.eulerAngles.z = CGFloat(side) * -0.12
        handNode.addChildNode(cuff)
        handNode.addChildNode(box(width: 0.12, height: 0.006, length: 0.012, color: NSColor(calibratedWhite: 0.86, alpha: 0.7), position: SCNVector3(side * -0.045, 0.022, 0.038)))
        for index in 0..<4 {
            let offset = -0.035 + Float(index) * 0.022
            let finger = capsule(radius: 0.0075, height: 0.092 - CGFloat(index % 2) * 0.012, color: skinTone, position: SCNVector3(side * (0.15 + Float(index) * 0.006), offset, -0.055), rotation: SCNVector4(1, 0, 0, Float.pi / 2))
            finger.name = mirrored ? "leftPlayerFinger\(index)" : "rightPlayerFinger\(index)"
            finger.eulerAngles.z = CGFloat(side) * (0.12 + CGFloat(index) * 0.025)
            handNode.addChildNode(finger)
            let nail = box(width: 0.018, height: 0.004, length: 0.01, color: NSColor(calibratedRed: 0.96, green: 0.78, blue: 0.72, alpha: 0.76), position: SCNVector3(side * (0.19 + Float(index) * 0.007), offset, -0.09))
            nail.name = mirrored ? "leftPlayerNail\(index)" : "rightPlayerNail\(index)"
            nail.eulerAngles.z = CGFloat(side) * 0.16
            handNode.addChildNode(nail)
            let knuckle = sphere(radius: 0.008, color: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.72, alpha: 0.32), position: SCNVector3(side * (0.13 + Float(index) * 0.006), offset, -0.03), scale: SCNVector3(1.2, 0.45, 0.7))
            knuckle.name = mirrored ? "leftPlayerKnuckle\(index)" : "rightPlayerKnuckle\(index)"
            handNode.addChildNode(knuckle)
        }
        let thumb = capsule(radius: 0.009, height: 0.095, color: skinTone, position: SCNVector3(side * 0.08, 0.035, -0.035), rotation: SCNVector4(0, 0, 1, CGFloat(side) * 0.72))
        thumb.name = mirrored ? "leftPlayerThumb" : "rightPlayerThumb"
        handNode.addChildNode(thumb)
        let palmHighlight = box(width: 0.08, height: 0.005, length: 0.012, color: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.66, alpha: 0.22), position: SCNVector3(side * 0.11, 0.022, -0.05))
        palmHighlight.name = mirrored ? "leftPlayerPalmHighlight" : "rightPlayerPalmHighlight"
        palmHighlight.eulerAngles.z = CGFloat(side) * 0.18
        handNode.addChildNode(palmHighlight)
    }

    private func makeBlackboardDetails() -> SCNNode {
        let root = SCNNode()
        root.addChildNode(makeText("55-SEAT CLASSROOM", size: 0.075, color: NSColor(calibratedWhite: 0.82, alpha: 1), position: SCNVector3(-0.72, 2.43, -5.9)))
        root.addChildNode(makeText("晚自习", size: 0.22, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(-1.75, 2.24, -5.9)))
        root.addChildNode(makeText("今日目标：完成作业  管理压力  允许求助", size: 0.075, color: NSColor(calibratedWhite: 0.82, alpha: 1), position: SCNVector3(-1.78, 1.98, -5.9)))
        root.addChildNode(makeText("抬头会暴露，低头会失去信息。", size: 0.068, color: NSColor(calibratedRed: 0.78, green: 0.92, blue: 0.78, alpha: 1), position: SCNVector3(-1.78, 1.8, -5.9)))
        blackboardStatusNode.position = SCNVector3(-1.78, 1.62, -5.9)
        root.addChildNode(blackboardStatusNode)
        root.addChildNode(makeBlackboardChalkDetails())
        root.addChildNode(makeBlackboardDustVeil())
        blackboardSurfaceDetailNode.addChildNode(makeBlackboardSurfaceDetailLayer())
        blackboardSurfaceDetailNode.opacity = 0.24
        root.addChildNode(blackboardSurfaceDetailNode)
        blackboardPatinaNode.addChildNode(makeBlackboardPatinaLayer())
        blackboardPatinaNode.opacity = 0.22
        root.addChildNode(blackboardPatinaNode)
        blackboardLiveWritingNode.addChildNode(makeBlackboardLiveWritingLayer())
        blackboardLiveWritingNode.opacity = 0.34
        root.addChildNode(blackboardLiveWritingNode)
        blackboardFormulaDetailNode.addChildNode(makeBlackboardFormulaDetailLayer())
        blackboardFormulaDetailNode.opacity = 0.22
        root.addChildNode(blackboardFormulaDetailNode)
        blackboardReliefCinematicNode.addChildNode(makeBlackboardReliefCinematicLayer())
        blackboardReliefCinematicNode.opacity = 0.2
        root.addChildNode(blackboardReliefCinematicNode)
        blackboardChalkDustNode.addChildNode(makeChalkDustBurstLayer())
        blackboardChalkDustNode.opacity = 0.18
        root.addChildNode(blackboardChalkDustNode)
        frontTeachingCinematicNode.addChildNode(makeFrontTeachingCinematicLayer())
        frontTeachingCinematicNode.opacity = 0.18
        root.addChildNode(frontTeachingCinematicNode)
        frontTeachingDepthStageNode.addChildNode(makeFrontTeachingDepthStageLayer())
        frontTeachingDepthStageNode.opacity = 0.14
        root.addChildNode(frontTeachingDepthStageNode)
        return root
    }

    private func makeBlackboardLiveWritingLayer() -> SCNNode {
        let root = SCNNode()
        let bright = NSColor(calibratedWhite: 0.94, alpha: 0.76)
        let soft = NSColor(calibratedWhite: 0.78, alpha: 0.34)
        let accent = NSColor(calibratedRed: 0.76, green: 0.92, blue: 0.72, alpha: 0.48)

        for row in 0..<4 {
            for stroke in 0..<5 {
                let width = 0.16 + CGFloat((row + stroke) % 3) * 0.06
                let x = -0.78 + Float(stroke) * 0.36 + Float(row % 2) * 0.06
                let y = 2.22 - Float(row) * 0.16
                let mark = box(width: width, height: 0.01, length: 0.006, color: (stroke + row) % 4 == 0 ? accent : bright, position: SCNVector3(x, y, -5.874))
                mark.eulerAngles.z = CGFloat((stroke % 3) - 1) * 0.05
                mark.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: 0.44, duration: 1.4 + Double(stroke) * 0.08),
                    .fadeOpacity(to: 0.82, duration: 1.7 + Double(row) * 0.1)
                ])), forKey: "fresh_chalk_breathe")
                root.addChildNode(mark)
            }
        }

        for index in 0..<6 {
            let underline = box(width: 0.42 - CGFloat(index % 2) * 0.1, height: 0.008, length: 0.006, color: soft, position: SCNVector3(0.68 + Float(index % 3) * 0.42, 2.22 - Float(index / 3) * 0.28, -5.872))
            underline.eulerAngles.z = -0.05 + CGFloat(index) * 0.018
            root.addChildNode(underline)
        }

        let focusBox = box(width: 0.72, height: 0.36, length: 0.006, color: NSColor(calibratedRed: 0.88, green: 0.94, blue: 0.78, alpha: 0.08), position: SCNVector3(1.15, 1.84, -5.876))
        focusBox.name = "blackboardFocusWash"
        focusBox.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 1.2),
            .fadeOpacity(to: 0.24, duration: 1.8)
        ])), forKey: "focus_wash")
        root.addChildNode(focusBox)
        return root
    }

