        let rightFalloff = box(width: 0.16, height: 1.08, length: 0.006, color: boardShadow.withAlphaComponent(0.14), position: SCNVector3(2.18, 1.96, -5.832))
        rightFalloff.name = "frontTeachingBoardRightVignette"
        root.addChildNode(rightFalloff)

        for index in 0..<8 {
            let x = -1.9 + Float(index) * 0.54
            let ridge = box(width: 0.28 + CGFloat(index % 3) * 0.08, height: 0.01, length: 0.004, color: index % 2 == 0 ? chalkHot : boardGreen, position: SCNVector3(x, 1.58 + Float(index % 3) * 0.19, -5.828))
