        let projectorCut = box(width: 1.72, height: 0.18, length: 0.008, color: projectorBlue, position: SCNVector3(0.18, 1.18, -5.05))
        projectorCut.name = "frontTeachingProjectorCutThrough"
        projectorCut.eulerAngles.x = -0.08
        root.addChildNode(projectorCut)
        let podiumTopBounce = box(width: 1.18, height: 0.006, length: 0.36, color: warmPodium, position: SCNVector3(0, 1.055, -4.54))
        podiumTopBounce.name = "frontTeachingPodiumTopBounce"
        root.addChildNode(podiumTopBounce)
        let podiumFrontOcclusion = box(width: 1.12, height: 0.12, length: 0.006, color: boardShadow.withAlphaComponent(0.13), position: SCNVector3(0, 0.79, -4.49))
        podiumFrontOcclusion.name = "frontTeachingPodiumFrontOcclusion"
        root.addChildNode(podiumFrontOcclusion)

        for index in 0..<5 {
            let dust = sphere(radius: 0.006 + CGFloat(index % 3) * 0.0015, color: chalkHot.withAlphaComponent(0.16), position: SCNVector3(0.16 + Float(index) * 0.16, 1.42 + Float(index % 2) * 0.18, -5.62), scale: SCNVector3(1.6, 0.55, 0.7))
            dust.name = "frontTeachingChalkLensMote\(index)"
            dust.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.01, y: 0.024, z: 0.004, duration: 1.2 + Double(index) * 0.12),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.01, y: -0.024, z: -0.004, duration: 1.5 + Double(index) * 0.1)
            ])), forKey: "front_chalk_mote")
            root.addChildNode(dust)
        }

        root.opacity = 0.18
