        boardLowerGate.name = "frontStageBoardLowerGateShadow"
        root.addChildNode(boardLowerGate)

        for index in 0..<6 {
            let x = -1.85 + Float(index) * 0.74
            let chalkDepth = box(width: 0.38 + CGFloat(index % 3) * 0.09, height: 0.016, length: 0.012, color: chalkWhite, position: SCNVector3(x, 2.28 - Float(index % 3) * 0.19, -5.785))
            chalkDepth.name = "frontStageRaisedChalkDepth\(index)"
