        teacherRim.eulerAngles.y = -0.12
        root.addChildNode(teacherRim)

        let chalkCone = box(width: 1.42, height: 0.42, length: 0.012, color: chalkWhite.withAlphaComponent(0.08), position: SCNVector3(0.54, 1.62, -5.12))
        chalkCone.name = "frontStageChalkConeThroughAir"
        chalkCone.eulerAngles = SCNVector3(-0.06, -0.18, -0.04)
