            mote.geometry?.firstMaterial?.emission.contents = chalkWhite.withAlphaComponent(0.05)
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.01, y: 0.02 + CGFloat(index % 2) * 0.006, z: CGFloat((index % 4) - 1) * 0.008, duration: 1.4 + Double(index % 5) * 0.12),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.01, y: -0.02 - CGFloat(index % 2) * 0.006, z: -CGFloat((index % 4) - 1) * 0.008, duration: 1.7 + Double(index % 4) * 0.14)
