        let leftSideOcclusion = box(width: 0.05, height: 1.28, length: 0.024, color: pressureShadow.withAlphaComponent(0.16), position: SCNVector3(-2.22, 1.93, -5.73))
        leftSideOcclusion.name = "frontStageBlackboardSideOcclusionLeft"
        root.addChildNode(leftSideOcclusion)
        let rightSideOcclusion = box(width: 0.046, height: 1.22, length: 0.024, color: pressureShadow.withAlphaComponent(0.12), position: SCNVector3(2.22, 1.94, -5.735))
        rightSideOcclusion.name = "frontStageBlackboardSideOcclusionRight"
        root.addChildNode(rightSideOcclusion)

        let trayCastShelf = box(width: 4.05, height: 0.018, length: 0.18, color: pressureShadow.withAlphaComponent(0.13), position: SCNVector3(0.05, 1.315, -5.57))
        trayCastShelf.name = "frontStageTrayCastShelf"
        trayCastShelf.eulerAngles.x = -0.035
        root.addChildNode(trayCastShelf)

        let podiumFootOcclusion = box(width: 1.46, height: 0.005, length: 0.48, color: pressureShadow.withAlphaComponent(0.18), position: SCNVector3(0, 0.088, -4.18))
        podiumFootOcclusion.name = "frontStagePodiumFootOcclusion"
        podiumFootOcclusion.eulerAngles.y = -0.08
        root.addChildNode(podiumFootOcclusion)

        for index in 0..<6 {
            let parallax = box(
                width: 0.28 + CGFloat(index % 3) * 0.09,
                height: 0.01,
                length: 0.01,
                color: chalkWhite.withAlphaComponent(0.1),
                position: SCNVector3(-1.54 + Float(index) * 0.58, 2.12 - Float(index % 3) * 0.22, -5.745 + Float(index % 2) * 0.012)
            )
            parallax.name = "frontStageFormulaParallaxLayer\(index)"
            parallax.eulerAngles = SCNVector3(-0.012, -0.045 + Float(index % 3) * 0.025, -0.05 + Float(index % 5) * 0.026)
            root.addChildNode(parallax)
        }

        let reachVolume = box(width: 0.78, height: 0.28, length: 0.016, color: teacherAmber.withAlphaComponent(0.09), position: SCNVector3(0.72, 1.86, -5.02))
        reachVolume.name = "frontStageTeacherChalkReachVolume"
        reachVolume.eulerAngles = SCNVector3(-0.04, -0.22, -0.08)
        root.addChildNode(reachVolume)

        root.opacity = 0.14
        return root
