    private func makeBlackboardPatinaLayer() -> SCNNode {
        let root = SCNNode()
        let greenGhost = NSColor(calibratedRed: 0.52, green: 0.72, blue: 0.52, alpha: 0.08)
        let chalkGhost = NSColor(calibratedWhite: 0.86, alpha: 0.11)
        let edgeCool = NSColor(calibratedRed: 0.38, green: 0.58, blue: 0.84, alpha: 0.1)
        let edgeWarm = NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.42, alpha: 0.09)

        for index in 0..<18 {
            let x = -1.92 + Float((index * 43) % 390) / 100
            let y = 1.48 + Float((index * 31) % 96) / 100
            let smear = box(width: 0.34 + CGFloat(index % 4) * 0.1, height: 0.018 + CGFloat(index % 3) * 0.006, length: 0.005, color: index % 3 == 0 ? greenGhost : chalkGhost, position: SCNVector3(x, y, -5.868))
            smear.name = "blackboardPatinaSmear\(index)"
            smear.eulerAngles.z = CGFloat((index % 7) - 3) * 0.025
            root.addChildNode(smear)
        }

        let topBloom = box(width: 4.1, height: 0.045, length: 0.006, color: edgeCool, position: SCNVector3(0, 2.55, -5.866))
        topBloom.name = "blackboardTopCoolBloom"
        root.addChildNode(topBloom)
        let leftBloom = box(width: 0.055, height: 1.1, length: 0.006, color: edgeWarm, position: SCNVector3(-2.05, 1.94, -5.866))
        leftBloom.name = "blackboardLeftWarmRim"
        root.addChildNode(leftBloom)
        let trayShadow = box(width: 4.0, height: 0.035, length: 0.006, color: NSColor(calibratedWhite: 0.01, alpha: 0.18), position: SCNVector3(0, 1.34, -5.864))
        trayShadow.name = "blackboardTrayAmbientOcclusion"
