        for index in 0..<7 {
            let vertical = box(width: 0.018, height: 0.68 + CGFloat(index % 3) * 0.12, length: 0.005, color: chalkGhost.withAlphaComponent(0.07), position: SCNVector3(-1.75 + Float(index) * 0.58, 1.88, -5.862))
            vertical.name = "blackboardVerticalWipe\(index)"
            vertical.eulerAngles.z = CGFloat((index % 3) - 1) * 0.025
            root.addChildNode(vertical)
