    private func makeBlackboardSurfaceDetailLayer() -> SCNNode {
        let root = SCNNode()
        let erasedChalk = NSColor(calibratedWhite: 0.78, alpha: 0.09)
        let freshEdge = NSColor(calibratedWhite: 0.95, alpha: 0.2)
        let greenSheen = NSColor(calibratedRed: 0.32, green: 0.58, blue: 0.36, alpha: 0.08)
        let frameOil = NSColor(calibratedRed: 0.9, green: 0.72, blue: 0.38, alpha: 0.09)

        for index in 0..<22 {
            let x = -1.94 + Float((index * 41) % 390) / 100
            let y = 1.48 + Float((index * 23) % 96) / 100
            let wipe = box(
                width: 0.28 + CGFloat(index % 5) * 0.06,
                height: 0.008,
                length: 0.004,
                color: index % 4 == 0 ? greenSheen : erasedChalk,
                position: SCNVector3(x, y, -5.858)
            )
            wipe.name = "blackboardDirectionalErase\(index)"
            wipe.eulerAngles.z = CGFloat((index % 9) - 4) * 0.018
            root.addChildNode(wipe)
        }

        for index in 0..<12 {
            let x = -1.75 + Float(index) * 0.32
            let edge = box(
                width: 0.12 + CGFloat(index % 3) * 0.04,
                height: 0.006,
                length: 0.004,
                color: freshEdge,
                position: SCNVector3(x, 2.3 - Float(index % 4) * 0.18, -5.854)
            )
            edge.name = "freshChalkPowderEdge\(index)"
            edge.eulerAngles.z = -0.04 + CGFloat(index % 4) * 0.026
            root.addChildNode(edge)
        }

        let topOil = box(width: 4.18, height: 0.018, length: 0.005, color: frameOil, position: SCNVector3(0, 2.535, -5.852))
        topOil.name = "blackboardFrameTopOilHighlight"
        root.addChildNode(topOil)
        let lowerDustLip = box(width: 3.95, height: 0.02, length: 0.005, color: NSColor(calibratedWhite: 0.86, alpha: 0.14), position: SCNVector3(0.08, 1.392, -5.852))
        lowerDustLip.name = "blackboardLowerDustLip"
        root.addChildNode(lowerDustLip)

        for index in 0..<5 {
            let ghostCircle = SCNTorus(ringRadius: 0.12 + CGFloat(index % 2) * 0.025, pipeRadius: 0.0025)
            ghostCircle.firstMaterial = material(NSColor(calibratedRed: 0.82, green: 0.92, blue: 0.72, alpha: 0.11))
            let node = SCNNode(geometry: ghostCircle)
            node.name = "blackboardFormulaGhostCircle\(index)"
            node.position = SCNVector3(0.8 + Float(index) * 0.28, 1.72 + Float(index % 2) * 0.16, -5.85)
            node.eulerAngles.x = CGFloat.pi / 2
            root.addChildNode(node)
        }

        for index in 0..<8 {
            let drip = box(width: 0.012, height: 0.16 + CGFloat(index % 3) * 0.035, length: 0.004, color: NSColor(calibratedWhite: 0.7, alpha: 0.07), position: SCNVector3(-1.92 + Float(index) * 0.55, 2.38 - Float(index % 3) * 0.08, -5.848))
            drip.name = "blackboardDampChalkDrip\(index)"
            root.addChildNode(drip)
        }
        return root
    }

    private func makeBlackboardFormulaDetailLayer() -> SCNNode {
        let root = SCNNode()
        let freshChalk = NSColor(calibratedWhite: 0.96, alpha: 0.38)
        let ghostChalk = NSColor(calibratedWhite: 0.82, alpha: 0.16)
        let correction = NSColor(calibratedRed: 0.92, green: 0.98, blue: 0.72, alpha: 0.28)
        let dust = NSColor(calibratedWhite: 0.9, alpha: 0.18)

        for row in 0..<5 {
            let y = 2.35 - Float(row) * 0.18
            for segment in 0..<5 {
                let width = 0.08 + CGFloat((row + segment) % 3) * 0.034
                let x = -1.72 + Float(segment) * 0.2 + Float(row % 2) * 0.04
                let mark = box(width: width, height: 0.007, length: 0.004, color: (segment + row) % 3 == 0 ? freshChalk : ghostChalk, position: SCNVector3(x, y, -5.846))
                mark.name = "blackboardFormulaStroke\(row)_\(segment)"
                mark.eulerAngles.z = CGFloat((segment % 3) - 1) * 0.06
                root.addChildNode(mark)

                if segment % 2 == 0 {
                    let divider = box(width: 0.006, height: 0.035, length: 0.004, color: ghostChalk, position: SCNVector3(x + 0.075, y - 0.018, -5.845))
                    divider.name = "blackboardFormulaDivider\(row)_\(segment)"
                    divider.eulerAngles.z = CGFloat((row % 3) - 1) * 0.04
                    root.addChildNode(divider)
                }
            }
        }

        for index in 0..<7 {
            let underline = box(width: 0.34 + CGFloat(index % 3) * 0.05, height: 0.006, length: 0.004, color: correction, position: SCNVector3(-1.46 + Float(index % 4) * 0.48, 1.56 + Float(index / 4) * 0.18, -5.844))
            underline.name = "blackboardFormulaCorrectionUnderline\(index)"
            underline.eulerAngles.z = -0.07 + CGFloat(index % 5) * 0.03
            root.addChildNode(underline)
        }

        for index in 0..<4 {
            let circle = SCNTorus(ringRadius: 0.095 + CGFloat(index % 2) * 0.028, pipeRadius: 0.0025)
            circle.firstMaterial = material(correction)
            let node = SCNNode(geometry: circle)
            node.name = "blackboardFormulaCorrectionCircle\(index)"
            node.position = SCNVector3(0.62 + Float(index) * 0.36, 2.22 - Float(index % 2) * 0.18, -5.843)
            node.eulerAngles.x = CGFloat.pi / 2
            node.eulerAngles.z = CGFloat(index) * 0.08
            root.addChildNode(node)
        }

        for index in 0..<8 {
            let tail = box(width: 0.46 + CGFloat(index % 4) * 0.08, height: 0.009, length: 0.004, color: ghostChalk.withAlphaComponent(0.1), position: SCNVector3(0.05 + Float(index % 4) * 0.5, 1.68 + Float(index / 4) * 0.16, -5.842))
            tail.name = "blackboardEraserDragTail\(index)"
            tail.eulerAngles.z = CGFloat((index % 5) - 2) * 0.018
            root.addChildNode(tail)
        }

        for index in 0..<12 {
            let crumb = sphere(radius: 0.004 + CGFloat(index % 3) * 0.0015, color: dust, position: SCNVector3(-1.7 + Float(index) * 0.31, 1.405 + Float(index % 2) * 0.012, -5.84), scale: SCNVector3(1.5, 0.55, 0.7))
            crumb.name = "blackboardTrayChalkResidue\(index)"
            root.addChildNode(crumb)
        }

        let teacherSweep = box(width: 0.72, height: 0.018, length: 0.004, color: NSColor(calibratedRed: 0.95, green: 0.86, blue: 0.58, alpha: 0.11), position: SCNVector3(0.82, 2.02, -5.841))
        teacherSweep.name = "blackboardTeacherFreshSweep"
        teacherSweep.runAction(.repeatForever(.sequence([
