    private func makeChalkDustBurstLayer() -> SCNNode {
        let root = SCNNode()
        for index in 0..<28 {
            let x = -0.5 + Float((index * 31) % 210) / 100
            let y = 1.72 + Float((index * 17) % 64) / 100
            let dust = sphere(radius: 0.005 + CGFloat(index % 4) * 0.0015, color: NSColor(calibratedWhite: 0.9, alpha: 0.2), position: SCNVector3(x, y, -5.84), scale: SCNVector3(1, 0.7, 1))
            dust.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 5) - 2) * 0.01, y: 0.04 + CGFloat(index % 3) * 0.006, z: 0.006, duration: 1.2 + Double(index % 4) * 0.16),
                .fadeOpacity(to: 0.08, duration: 0.2),
                .moveBy(x: -CGFloat((index % 5) - 2) * 0.01, y: -0.04 - CGFloat(index % 3) * 0.006, z: -0.006, duration: 0.02),
                .fadeOpacity(to: 0.44, duration: 0.18),
                .wait(duration: 0.55 + Double(index % 5) * 0.12)
            ])), forKey: "chalk_burst_float")
            root.addChildNode(dust)
        }

        let chalkCloud = box(width: 1.2, height: 0.36, length: 0.008, color: NSColor(calibratedWhite: 0.82, alpha: 0.12), position: SCNVector3(0.42, 1.86, -5.866))
        chalkCloud.name = "chalkCloudWash"
        chalkCloud.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 0.7),
            .fadeOpacity(to: 0.26, duration: 0.5),
            .wait(duration: 1.0)
        ])), forKey: "chalk_cloud")
        root.addChildNode(chalkCloud)
        return root
    }

    private func makeBlackboardChalkDetails() -> SCNNode {
        let root = SCNNode()
        let chalk = NSColor(calibratedWhite: 0.86, alpha: 0.74)
        let faint = NSColor(calibratedWhite: 0.72, alpha: 0.32)
        for index in 0..<18 {
            let x = -1.55 + Float(index % 6) * 0.56
            let y = 2.35 - Float(index / 6) * 0.28
            let mark = box(width: 0.18 + CGFloat(index % 3) * 0.08, height: 0.012, length: 0.006, color: index % 4 == 0 ? faint : chalk, position: SCNVector3(x, y, -5.885))
            mark.eulerAngles.z = CGFloat((index % 5) - 2) * 0.05
            root.addChildNode(mark)
        }

        for index in 0..<5 {
            let circle = SCNTorus(ringRadius: 0.085 + CGFloat(index) * 0.012, pipeRadius: 0.003)
            circle.firstMaterial = material(NSColor(calibratedRed: 0.86, green: 0.92, blue: 0.76, alpha: 0.36))
            let node = SCNNode(geometry: circle)
            node.position = SCNVector3(1.05 + Float(index) * 0.22, 2.1 - Float(index % 2) * 0.14, -5.884)
            node.eulerAngles.x = CGFloat.pi / 2
            root.addChildNode(node)
        }

        let eraserDust = box(width: 1.1, height: 0.018, length: 0.008, color: NSColor(calibratedWhite: 0.78, alpha: 0.2), position: SCNVector3(0.88, 1.42, -5.88))
        root.addChildNode(eraserDust)
        root.addChildNode(box(width: 0.42, height: 0.055, length: 0.04, color: NSColor(calibratedRed: 0.14, green: 0.12, blue: 0.1, alpha: 1), position: SCNVector3(1.88, 1.39, -5.86)))
        root.addChildNode(box(width: 0.24, height: 0.018, length: 0.026, color: NSColor(calibratedWhite: 0.88, alpha: 1), position: SCNVector3(1.52, 1.41, -5.85)))
        return root
    }

    private func makeBlackboardDustVeil() -> SCNNode {
