            let y = 1.55 + Float((index * 29) % 88) / 100
            let smear = box(width: 0.24 + CGFloat(index % 4) * 0.06, height: 0.01, length: 0.005, color: NSColor(calibratedWhite: 0.78, alpha: 0.1 + CGFloat(index % 3) * 0.035), position: SCNVector3(x, y, -5.878))
