            root.addChildNode(smear)
        }
        for index in 0..<10 {
            let dust = sphere(radius: 0.006 + CGFloat(index % 3) * 0.002, color: NSColor(calibratedWhite: 0.88, alpha: 0.22), position: SCNVector3(-0.8 + Float(index) * 0.18, 1.46 + Float(index % 2) * 0.025, -5.845), scale: SCNVector3(1.0, 0.65, 1.0))
            dust.runAction(.repeatForever(.sequence([
