                .moveBy(x: -CGFloat((index % 3) - 1) * 0.008, y: -0.018, z: 0, duration: 2.1 + Double(index % 5) * 0.18)
            ])), forKey: "chalk_dust_float")
            root.addChildNode(dust)
        }
        return root
