    private func makePodiumSurfaceProps() -> SCNNode {
        let root = SCNNode()
        let paper = NSColor(calibratedWhite: 0.93, alpha: 1)
        for index in 0..<3 {
            let sheet = box(width: 0.34, height: 0.006, length: 0.22, color: paper, position: SCNVector3(-0.22 + Float(index) * 0.12, 1.035 + Float(index) * 0.006, -4.48 + Float(index) * 0.025))
            sheet.eulerAngles.y = -0.18 + Float(index) * 0.12
            root.addChildNode(sheet)
            root.addChildNode(box(width: 0.23, height: 0.004, length: 0.012, color: NSColor(calibratedRed: 0.16, green: 0.2, blue: 0.28, alpha: 0.42), position: SCNVector3(-0.25 + Float(index) * 0.12, 1.044 + Float(index) * 0.006, -4.5 + Float(index) * 0.025)))
        }

        let chalkBox = roundedBox(width: 0.22, height: 0.06, length: 0.12, chamfer: 0.018, color: NSColor(calibratedRed: 0.72, green: 0.16, blue: 0.12, alpha: 1), position: SCNVector3(0.42, 1.045, -4.48))
        root.addChildNode(chalkBox)
        for offset in [-0.055, 0, 0.055] {
            root.addChildNode(box(width: 0.012, height: 0.014, length: 0.11, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(0.42 + Float(offset), 1.085, -4.48)))
        }

        let cupBody = SCNCylinder(radius: 0.055, height: 0.16)
        cupBody.radialSegmentCount = 18
        cupBody.firstMaterial = material(NSColor(calibratedRed: 0.42, green: 0.72, blue: 0.92, alpha: 0.62))
        let cup = SCNNode(geometry: cupBody)
        cup.position = SCNVector3(-0.48, 1.1, -4.47)
        root.addChildNode(cup)
        root.addChildNode(capsule(radius: 0.012, height: 0.13, color: NSColor(calibratedWhite: 0.92, alpha: 0.72), position: SCNVector3(-0.42, 1.12, -4.47), rotation: SCNVector4(0, 0, 1, 0.7)))

        for index in 0..<8 {
            let nick = box(width: 0.16 + CGFloat(index % 3) * 0.04, height: 0.005, length: 0.01, color: NSColor(calibratedWhite: 0.96, alpha: 0.12), position: SCNVector3(-0.7 + Float(index) * 0.2, 1.023, -4.84 + Float(index % 2) * 0.05))
            nick.eulerAngles.y = Float(index % 5) * 0.1
            root.addChildNode(nick)
        }

        let screenReflection = box(width: 0.38, height: 0.008, length: 0.055, color: NSColor(calibratedRed: 0.35, green: 0.78, blue: 1.0, alpha: 0.18), position: SCNVector3(0, 1.02, -4.31))
        screenReflection.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 2.2),
            .fadeOpacity(to: 0.28, duration: 2.7)
        ])), forKey: "podium_screen_reflect")
        root.addChildNode(screenReflection)

        let topSheen = box(width: 1.02, height: 0.006, length: 0.42, color: NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.58, alpha: 0.13), position: SCNVector3(0, 1.018, -4.62))
        topSheen.eulerAngles.x = -0.03
        root.addChildNode(topSheen)
        root.addChildNode(box(width: 0.72, height: 0.005, length: 0.03, color: NSColor(calibratedWhite: 0.82, alpha: 0.22), position: SCNVector3(0.08, 1.026, -4.35)))
        for index in 0..<4 {
            let chalk = capsule(radius: 0.01, height: 0.14 - CGFloat(index % 2) * 0.035, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(-0.12 + Float(index) * 0.09, 1.04, -4.345), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            chalk.eulerAngles.y = Float(index) * 0.13
            root.addChildNode(chalk)
        }
        return root
    }

    private func makePodiumMaterialDetailLayer() -> SCNNode {
        let root = SCNNode()
        let wornWood = NSColor(calibratedRed: 1.0, green: 0.84, blue: 0.56, alpha: 0.16)
        let fingerDust = NSColor(calibratedWhite: 0.9, alpha: 0.16)
        let shadow = NSColor(calibratedWhite: 0.02, alpha: 0.28)
        let projectorBlue = NSColor(calibratedRed: 0.64, green: 0.86, blue: 1.0, alpha: 0.22)

        let frontHandPolish = box(width: 1.04, height: 0.006, length: 0.048, color: wornWood, position: SCNVector3(0, 1.029, -4.86))
        frontHandPolish.name = "podiumFrontEdgeHandPolish"
        root.addChildNode(frontHandPolish)

        for index in 0..<10 {
            let grain = box(width: 0.18 + CGFloat(index % 4) * 0.05, height: 0.004, length: 0.008, color: NSColor(calibratedRed: 0.34, green: 0.2, blue: 0.11, alpha: 0.18), position: SCNVector3(-0.48 + Float(index % 5) * 0.24, 1.032, -4.77 + Float(index / 5) * 0.18))
            grain.name = "podiumWoodGrainScar\(index)"
            grain.eulerAngles.y = -0.16 + Float(index % 4) * 0.1
            root.addChildNode(grain)
        }

        for index in 0..<6 {
            let smear = box(width: 0.12 + CGFloat(index % 3) * 0.04, height: 0.004, length: 0.014, color: fingerDust, position: SCNVector3(0.34 + Float(index % 3) * 0.07, 1.09, -4.4 + Float(index / 3) * 0.05))
            smear.name = "podiumChalkFingerSmear\(index)"
            smear.eulerAngles.y = -0.18 + Float(index) * 0.07
            root.addChildNode(smear)
        }

        let paperStackShadow = box(width: 0.48, height: 0.004, length: 0.28, color: shadow, position: SCNVector3(-0.11, 1.027, -4.455))
        paperStackShadow.name = "podiumPaperStackShadow"
        root.addChildNode(paperStackShadow)

        let cupRing = SCNTorus(ringRadius: 0.068, pipeRadius: 0.0028)
        cupRing.firstMaterial = material(NSColor(calibratedWhite: 1.0, alpha: 0.18))
        let cupRingNode = SCNNode(geometry: cupRing)
        cupRingNode.name = "podiumCupWaterRing"
        cupRingNode.position = SCNVector3(-0.48, 1.032, -4.47)
        cupRingNode.eulerAngles.x = CGFloat.pi / 2
        root.addChildNode(cupRingNode)

        for index in 0..<11 {
            let dust = sphere(radius: 0.0035 + CGFloat(index % 3) * 0.0012, color: projectorBlue, position: SCNVector3(-0.42 + Float((index * 29) % 86) / 100, 1.08 + Float(index % 4) * 0.018, -4.37 - Float(index % 3) * 0.04), scale: SCNVector3(1, 0.65, 1))
            dust.name = "podiumProjectorDustSpeck\(index)"
            dust.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.006, y: 0.014, z: CGFloat((index % 2) == 0 ? 0.004 : -0.004), duration: 1.5 + Double(index % 4) * 0.18),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.006, y: -0.014, z: CGFloat((index % 2) == 0 ? -0.004 : 0.004), duration: 1.7 + Double(index % 5) * 0.14)
            ])), forKey: "podium_dust_float")
            root.addChildNode(dust)
        }

        for index in 0..<3 {
            let cableShadow = box(width: 0.5 - CGFloat(index) * 0.08, height: 0.005, length: 0.018, color: shadow.withAlphaComponent(0.18), position: SCNVector3(-0.38 + Float(index) * 0.34, 0.985, -4.22 - Float(index) * 0.12))
            cableShadow.name = "podiumCableShadow\(index)"
            cableShadow.eulerAngles.y = 0.26 - Float(index) * 0.18
            root.addChildNode(cableShadow)
        }

        let projectorEdgeCatch = box(width: 0.52, height: 0.006, length: 0.018, color: projectorBlue, position: SCNVector3(0, 0.99, -4.535))
        projectorEdgeCatch.name = "podiumProjectorEdgeCatch"
        projectorEdgeCatch.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.1, duration: 1.6),
            .fadeOpacity(to: 0.34, duration: 1.3)
        ])), forKey: "projector_edge_catch")
        root.addChildNode(projectorEdgeCatch)
        return root
    }

    private func makePodiumProjectorGlow() -> SCNNode {
        let root = SCNNode()
        let glow = box(width: 1.28, height: 0.42, length: 0.012, color: NSColor(calibratedRed: 0.5, green: 0.78, blue: 1.0, alpha: 0.12), position: SCNVector3(0, 1.06, -4.48))
        glow.name = "podiumProjectorGlowWash"
        glow.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.08, duration: 1.6),
            .fadeOpacity(to: 0.24, duration: 2.1)
        ])), forKey: "projector_glow_breathe")
        root.addChildNode(glow)
        for index in 0..<5 {
            let stripe = box(width: 0.92 - CGFloat(index) * 0.1, height: 0.012, length: 0.008, color: NSColor(calibratedRed: 0.78, green: 0.92, blue: 1.0, alpha: 0.12), position: SCNVector3(0, 0.92 + Float(index) * 0.08, -4.47))
            root.addChildNode(stripe)
        }
        return root
    }

    private func makeTouchPanel(x: Float, title: String) -> SCNNode {
        let root = SCNNode()
        root.addChildNode(box(width: 0.82, height: 0.94, length: 0.055, color: NSColor(calibratedRed: 0.02, green: 0.08, blue: 0.12, alpha: 1), position: SCNVector3(x, 1.9, -5.91)))
        root.childNodes.last?.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.0, green: 0.18, blue: 0.26, alpha: 1)
        root.addChildNode(makeText(title, size: 0.065, color: NSColor(calibratedRed: 0.72, green: 0.92, blue: 1.0, alpha: 1), position: SCNVector3(x - 0.32, 2.24, -5.86)))
        for index in 0..<4 {
            root.addChildNode(box(width: 0.46 - CGFloat(index) * 0.05, height: 0.035, length: 0.025, color: NSColor(calibratedRed: 0.1 + CGFloat(index) * 0.08, green: 0.45, blue: 0.62, alpha: 1), position: SCNVector3(x - 0.12, 2.08 - Float(index) * 0.13, -5.85)))
        }
        return root
    }

    private func makeWallClock() -> SCNNode {
        let root = SCNNode()
        let face = SCNCylinder(radius: 0.28, height: 0.035)
        face.radialSegmentCount = 32
        face.firstMaterial = material(NSColor(calibratedWhite: 0.92, alpha: 1))
        let faceNode = SCNNode(geometry: face)
        faceNode.position = SCNVector3(2.85, 2.62, -5.88)
        faceNode.eulerAngles.x = CGFloat.pi / 2
        root.addChildNode(faceNode)

        root.addChildNode(makeText("12", size: 0.052, color: .black, position: SCNVector3(2.81, 2.79, -5.83)))
        root.addChildNode(makeText("6", size: 0.052, color: .black, position: SCNVector3(2.84, 2.39, -5.83)))
        root.addChildNode(makeText("3", size: 0.052, color: .black, position: SCNVector3(3.03, 2.58, -5.83)))
        root.addChildNode(makeText("9", size: 0.052, color: .black, position: SCNVector3(2.63, 2.58, -5.83)))

        clockHourHandNode.position = SCNVector3(2.85, 2.62, -5.82)
        clockHourHandNode.addChildNode(box(width: 0.026, height: 0.13, length: 0.012, color: .black, position: SCNVector3(0, 0.065, 0)))
        root.addChildNode(clockHourHandNode)

        clockMinuteHandNode.position = SCNVector3(2.85, 2.62, -5.81)
        clockMinuteHandNode.addChildNode(box(width: 0.018, height: 0.2, length: 0.012, color: NSColor(calibratedRed: 0.2, green: 0.2, blue: 0.22, alpha: 1), position: SCNVector3(0, 0.1, 0)))
        root.addChildNode(clockMinuteHandNode)
        root.addChildNode(sphere(radius: 0.025, color: NSColor(calibratedWhite: 0.08, alpha: 1), position: SCNVector3(2.85, 2.62, -5.8)))
        return root
    }

    private func updateClock(game: GameManager) {
        let startMinutes = 18 * 60 + 30
        let totalMinutes = Double(startMinutes + game.elapsedMinutes)
        let minuteAngle = -CGFloat((totalMinutes / 60) * 2 * Double.pi)
        let hourAngle = -CGFloat((totalMinutes / 720) * 2 * Double.pi)
        clockMinuteHandNode.eulerAngles.z = minuteAngle
        clockHourHandNode.eulerAngles.z = hourAngle
    }

    private func updateBlackboard(game: GameManager) {
        blackboardStatusNode.childNodes.forEach { $0.removeFromParentNode() }
        let status = "时间 \(game.clockText)   作业 \(Int(game.player.homework))%   压力 \(Int(game.player.stress))"
        blackboardStatusNode.addChildNode(makeText(status, size: 0.07, color: NSColor(calibratedRed: 0.94, green: 0.88, blue: 0.62, alpha: 1), position: SCNVector3Zero))
        let chalkFocus = game.teacher.focusMode == .blackboard || game.teacher.location == .podium
        let pressure = (game.player.stress / 160).clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let eventPressure = eventVisualIntensity(game: game).vignette.clamped(to: 0...1)
        blackboardLiveWritingNode.opacity = chalkFocus ? CGFloat(0.54 + pressure * 0.22) : 0.28
        blackboardChalkDustNode.opacity = chalkFocus ? CGFloat(0.42 + pressure * 0.2) : 0.12
        blackboardPatinaNode.opacity = CGFloat((0.2 + pressure * 0.18 + (chalkFocus ? 0.12 : 0)).clamped(to: 0.18...0.54))
        blackboardSurfaceDetailNode.opacity = CGFloat((0.2 + pressure * 0.22 + (chalkFocus ? 0.18 : 0)).clamped(to: 0.18...0.68))
        blackboardSurfaceDetailNode.position.y = Float(pressure * 0.006)
        blackboardSurfaceDetailNode.childNode(withName: "blackboardLowerDustLip", recursively: true)?.opacity = chalkFocus ? CGFloat(0.46 + pressure * 0.18) : 0.22
        blackboardSurfaceDetailNode.childNode(withName: "blackboardFrameTopOilHighlight", recursively: true)?.opacity = game.classroomLightLevel < 0.65 ? 0.38 : 0.22
        blackboardFormulaDetailNode.opacity = CGFloat((0.16 + pressure * 0.18 + (chalkFocus ? 0.24 : 0) + eventPressure * 0.12).clamped(to: 0.12...0.74))
        blackboardFormulaDetailNode.position.y = Float(pressure * 0.006 + eventPressure * 0.004)
        forEachDescendant(of: blackboardFormulaDetailNode) { child in
            guard let name = child.name else { return }
            if name.contains("CorrectionCircle") || name.contains("CorrectionUnderline") {
                child.opacity = CGFloat((0.34 + pressure * 0.32 + (chalkFocus ? 0.22 : 0)).clamped(to: 0.28...0.9))
            } else if name.contains("TrayChalkResidue") {
                child.opacity = CGFloat((0.26 + lowLight * 0.18 + eventPressure * 0.12).clamped(to: 0.18...0.64))
            } else if name.contains("EraserDragTail") {
                child.opacity = CGFloat((0.22 + pressure * 0.18).clamped(to: 0.16...0.52))
            }
        }
        blackboardReliefCinematicNode.opacity = CGFloat((0.14 + pressure * 0.2 + lowLight * 0.16 + eventPressure * 0.14 + (chalkFocus ? 0.22 : 0)).clamped(to: 0.1...0.82))
        blackboardReliefCinematicNode.position.y = Float(pressure * 0.005 + eventPressure * 0.006)
        blackboardReliefCinematicNode.eulerAngles.z = Float(eventPressure * 0.005 - pressure * 0.003)
        forEachDescendant(of: blackboardReliefCinematicNode) { child in
            guard let name = child.name else { return }
            if name.contains("ChalkThickness") || name.contains("ChalkUnderShadow") {
                child.opacity = CGFloat((0.12 + pressure * 0.2 + (chalkFocus ? 0.26 : 0.06) + eventPressure * 0.08).clamped(to: 0.08...0.68))
            } else if name.contains("WetWipeStain") || name.contains("EraserRidge") {
                child.opacity = CGFloat((0.1 + lowLight * 0.16 + pressure * 0.16 + eventPressure * 0.12).clamped(to: 0.06...0.5))
            } else if name.contains("LowerTrayDustPile") || name.contains("TrayChalkStick") {
                child.opacity = CGFloat((0.2 + (chalkFocus ? 0.18 : 0.04) + pressure * 0.12 + lowLight * 0.08).clamped(to: 0.14...0.62))
            } else if name.contains("FrameOilRim") {
                child.opacity = CGFloat((0.12 + lowLight * 0.22 + eventPressure * 0.08).clamped(to: 0.08...0.46))
            } else if name.contains("BoardCoreThickness") || name.contains("BoardFrameSeamShadow") {
                child.opacity = CGFloat((0.1 + lowLight * 0.2 + pressure * 0.08 + eventPressure * 0.08 + (chalkFocus ? 0.06 : 0)).clamped(to: 0.06...0.44))
            } else if name.contains("OldEraseGhost") || name.contains("CornerHumidityBloom") {
                child.opacity = CGFloat((0.08 + lowLight * 0.16 + pressure * 0.12 + eventPressure * 0.08).clamped(to: 0.04...0.38))
            } else if name.contains("FormulaPressureRidge") {
                child.opacity = CGFloat((0.08 + (chalkFocus ? 0.3 : 0.06) + pressure * 0.14 + eventPressure * 0.08).clamped(to: 0.04...0.62))
            } else if name.contains("TrayPowderShelf") || name.contains("ChalkCrumbShadow") {
                child.opacity = CGFloat((0.14 + (chalkFocus ? 0.16 : 0.04) + lowLight * 0.12 + pressure * 0.08).clamped(to: 0.08...0.48))
            } else if name.contains("TeacherSleeveEraseArc") {
                child.opacity = CGFloat(((chalkFocus ? 0.2 : 0.02) + pressure * 0.1 + eventPressure * 0.08).clamped(to: 0.02...0.4))
            } else if name.contains("ProjectorSkim") {
                child.opacity = CGFloat((0.08 + lowLight * 0.24 + eventPressure * 0.14 + (game.currentPeriod == .third ? 0.16 : 0)).clamped(to: 0.04...0.56))
            } else if name.contains("TeacherHandGhost") || name.contains("TeacherFingerGhost") {
                child.opacity = CGFloat(((chalkFocus ? 0.18 : 0.02) + pressure * 0.08 + eventPressure * 0.08).clamped(to: 0.02...0.36))
            } else if name.contains("PodiumEdgeOcclusion") {
                child.opacity = CGFloat((0.12 + lowLight * 0.18 + pressure * 0.1 + eventPressure * 0.1).clamped(to: 0.08...0.42))
            } else if name.contains("PodiumEdgeCatch") || name.contains("PodiumEdgeNick") || name.contains("PodiumChalkFleck") {
                child.opacity = CGFloat((0.12 + lowLight * 0.12 + (chalkFocus ? 0.12 : 0) + eventPressure * 0.06).clamped(to: 0.06...0.42))
            }
        }
        frontTeachingCinematicNode.opacity = CGFloat((0.14 + pressure * 0.18 + lowLight * 0.16 + eventPressure * 0.14 + (chalkFocus ? 0.22 : 0)).clamped(to: 0.1...0.78))
        frontTeachingCinematicNode.position.y = Float(pressure * 0.004 + eventPressure * 0.006)
        frontTeachingCinematicNode.eulerAngles.z = Float(eventPressure * 0.006 - pressure * 0.004)
        forEachDescendant(of: frontTeachingCinematicNode) { child in
            guard let name = child.name else { return }
            if name.contains("FreshChalkRidge") || name.contains("ChalkLensMote") {
                child.opacity = CGFloat((0.08 + (chalkFocus ? 0.28 : 0.06) + pressure * 0.14 + eventPressure * 0.08).clamped(to: 0.05...0.56))
            } else if name.contains("ErasedFormulaBloom") {
                child.opacity = CGFloat((0.08 + lowLight * 0.12 + pressure * 0.12 + (chalkFocus ? 0.08 : 0)).clamped(to: 0.04...0.34))
            } else if name.contains("ProjectorCutThrough") {
                child.opacity = CGFloat((0.08 + lowLight * 0.22 + eventPressure * 0.16 + (game.currentPeriod == .third ? 0.18 : 0)).clamped(to: 0.05...0.52))
            } else if name.contains("PodiumTopBounce") {
                child.opacity = CGFloat((0.08 + lowLight * 0.14 + (chalkFocus ? 0.12 : 0) + eventPressure * 0.08).clamped(to: 0.05...0.38))
            } else if name.contains("Falloff") || name.contains("Vignette") || name.contains("Occlusion") {
                child.opacity = CGFloat((0.1 + lowLight * 0.18 + pressure * 0.12 + eventPressure * 0.1).clamped(to: 0.06...0.46))
            }
        }
        let teacherFrontPresence = (1 - abs(Double(teacherNode.position.z + 4.25)) / 3.6).clamped(to: 0...1)
        let teacherLateral = Double(teacherNode.position.x).clamped(to: -2.6...2.6)
        frontTeachingDepthStageNode.opacity = CGFloat((0.1 + lowLight * 0.16 + pressure * 0.16 + eventPressure * 0.16 + teacherFrontPresence * 0.18 + (chalkFocus ? 0.2 : 0)).clamped(to: 0.06...0.82))
        frontTeachingDepthStageNode.position.y = Float(pressure * 0.004 + eventPressure * 0.006)
        frontTeachingDepthStageNode.eulerAngles.z = Float(eventPressure * 0.005 - pressure * 0.003)
        forEachDescendant(of: frontTeachingDepthStageNode) { child in
            guard let name = child.name else { return }
            if name.contains("BoardCoolVolume") {
                child.opacity = CGFloat((0.06 + lowLight * 0.18 + eventPressure * 0.08 + (chalkFocus ? 0.12 : 0)).clamped(to: 0.03...0.36))
            } else if name.contains("BlackboardSideOcclusion") {
                child.opacity = CGFloat((0.08 + lowLight * 0.18 + pressure * 0.1 + eventPressure * 0.08).clamped(to: 0.04...0.42))
            } else if name.contains("BoardLowerGate") || name.contains("FirstRowDeskCut") {
                child.opacity = CGFloat((0.08 + pressure * 0.18 + lowLight * 0.12 + eventPressure * 0.1 + teacherFrontPresence * 0.08).clamped(to: 0.04...0.46))
            } else if name.contains("RaisedChalkDepth") || name.contains("ChalkCastShadow") {
                child.opacity = CGFloat((0.07 + (chalkFocus ? 0.3 : 0.06) + pressure * 0.14 + eventPressure * 0.08).clamped(to: 0.03...0.58))
            } else if name.contains("FormulaParallaxLayer") {
                child.opacity = CGFloat((0.05 + (chalkFocus ? 0.24 : 0.05) + pressure * 0.12 + eventPressure * 0.08).clamped(to: 0.02...0.46))
            } else if name.contains("TrayCastShelf") {
                child.opacity = CGFloat((0.08 + pressure * 0.16 + lowLight * 0.14 + (chalkFocus ? 0.08 : 0)).clamped(to: 0.04...0.42))
            } else if name.contains("PodiumReflectionStep") {
                child.opacity = CGFloat((0.06 + lowLight * 0.16 + teacherFrontPresence * 0.12 + eventPressure * 0.08 + (chalkFocus ? 0.1 : 0)).clamped(to: 0.03...0.42))
                child.position.y = Float(1.038 + eventPressure * 0.004 + teacherFrontPresence * 0.003)
            } else if name.contains("PodiumFootOcclusion") {
                child.opacity = CGFloat((0.08 + teacherFrontPresence * 0.22 + lowLight * 0.16 + eventPressure * 0.1).clamped(to: 0.04...0.48))
                child.scale = SCNVector3(1 + CGFloat(teacherFrontPresence) * 0.14, 1, 1 + CGFloat(lowLight) * 0.08)
            } else if name.contains("TeacherBodyGate") {
                child.position.x = Float(teacherLateral * 0.18)
                child.opacity = CGFloat((0.02 + teacherFrontPresence * 0.36 + eventPressure * 0.16 + pressure * 0.08).clamped(to: 0.01...0.54))
                child.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.08, 1 + CGFloat(teacherFrontPresence) * 0.04, 1)
            } else if name.contains("TeacherFloorCast") {
                child.position.x = Float(teacherLateral * 0.28)
                child.opacity = CGFloat((0.04 + teacherFrontPresence * 0.34 + lowLight * 0.12 + eventPressure * 0.12).clamped(to: 0.02...0.56))
                child.scale = SCNVector3(1 + CGFloat(teacherFrontPresence) * 0.16 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(lowLight) * 0.08)
            } else if name.contains("TeacherWarmRimColumn") {
                child.position.x = Float(0.24 + teacherLateral * 0.2)
                child.opacity = CGFloat((0.04 + teacherFrontPresence * 0.26 + lowLight * 0.12 + (chalkFocus ? 0.12 : 0)).clamped(to: 0.02...0.46))
            } else if name.contains("TeacherChalkReachVolume") {
                child.position.x = Float(0.72 + teacherLateral * 0.16)
                child.opacity = CGFloat(((chalkFocus ? 0.16 : 0.02) + teacherFrontPresence * 0.18 + eventPressure * 0.08).clamped(to: 0.01...0.38))
            } else if name.contains("ChalkConeThroughAir") {
                child.opacity = CGFloat((0.04 + (chalkFocus ? 0.24 : 0.06) + lowLight * 0.1 + eventPressure * 0.08).clamped(to: 0.02...0.4))
            } else if name.contains("FloatingChalkDepthMote") {
                child.opacity = CGFloat((0.03 + (chalkFocus ? 0.18 : 0.04) + lowLight * 0.1 + eventPressure * 0.08).clamped(to: 0.01...0.32))
            } else if name.contains("BoardSideDepthGlow") {
                child.opacity = CGFloat((0.04 + lowLight * 0.16 + eventPressure * 0.08).clamped(to: 0.02...0.3))
            }
        }
        podiumMaterialDetailNode.opacity = CGFloat((0.12 + lowLight * 0.16 + (chalkFocus ? 0.16 : 0) + eventPressure * 0.08).clamped(to: 0.1...0.58))
        podiumMaterialDetailNode.position.y = Float(eventPressure * 0.003)
        forEachDescendant(of: podiumMaterialDetailNode) { child in
            guard let name = child.name else { return }
            if name.contains("ProjectorDustSpeck") {
                child.opacity = CGFloat((0.18 + lowLight * 0.3 + eventPressure * 0.18 + (chalkFocus ? 0.08 : 0)).clamped(to: 0.12...0.76))
            } else if name.contains("HandPolish") || name.contains("EdgeCatch") {
                child.opacity = CGFloat((0.2 + lowLight * 0.16 + (chalkFocus ? 0.12 : 0)).clamped(to: 0.16...0.56))
            } else if name.contains("ChalkFingerSmear") || name.contains("CupWaterRing") {
                child.opacity = CGFloat((0.18 + pressure * 0.14 + lowLight * 0.08).clamped(to: 0.12...0.48))
            }
        }
        if chalkFocus && blackboardLiveWritingNode.action(forKey: "live_board_scratch") == nil {
            blackboardLiveWritingNode.runAction(.repeatForever(.sequence([
                .moveBy(x: 0.012, y: 0.002, z: 0, duration: 0.12),
                .moveBy(x: -0.012, y: -0.002, z: 0, duration: 0.16),
                .wait(duration: 0.56)
            ])), forKey: "live_board_scratch")
        } else if !chalkFocus {
            blackboardLiveWritingNode.removeAction(forKey: "live_board_scratch")
        }
    }

    private func updateTimeAtmosphere(game: GameManager) {
        let lightLevel = game.classroomLightLevel
        let period = game.currentPeriod
        let progress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let eventPressure = eventVisualIntensity(game: game).vignette.clamped(to: 0...1)
        let skyColor: NSColor
        let ambientColor: NSColor
        let lampOpacity: CGFloat

        switch period {
        case .first:
            skyColor = NSColor(calibratedRed: 0.58, green: 0.78, blue: 0.96, alpha: 1)
