        for row in 0..<5 {
            let rowDepth = Double(row) / 4
            classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmDeskTubePulse\(row)", recursively: true)?.opacity = CGFloat((0.04 + lightLevel * 0.08 + (1 - lightLevel) * 0.16 + eventPressure * 0.08 + (period == .third ? 0.12 : 0) + rowDepth * 0.025).clamped(to: 0.02...0.38))
            classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmRowStillnessPool\(row)", recursively: true)?.opacity = CGFloat((0.04 + (1 - lightLevel) * 0.16 + eventPressure * 0.14 + teacherNearAir * 0.08 + rowDepth * 0.02).clamped(to: 0.02...0.4))
            classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmRowStillnessPool\(row)", recursively: true)?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(teacherNearAir) * 0.05)
        }
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let page = classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmPageFlutter\(row)_\(column)", recursively: true)
                let studyPulse = game.classmates.first(where: { $0.seat.row == row && $0.seat.column == column })?.state == .studying ? 0.14 : 0.0
                let pressurePulse = game.classmates.first(where: { $0.seat.row == row && $0.seat.column == column })?.state == .crying ? 0.18 : 0.0
                page?.opacity = CGFloat((0.05 + lightLevel * 0.08 + (rainy ? 0.08 : 0) + eventPressure * 0.08 + studyPulse + pressurePulse).clamped(to: 0.02...0.42))
                page?.position.y = Float(0.238 + studyPulse * 0.018 + pressurePulse * 0.008 + eventPressure * 0.004)
            }
        }
        for index in 0..<5 {
            let caustic = classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmWindowRainCaustic\(index)", recursively: true)
            caustic?.opacity = rainy ? CGFloat((0.1 + progress * 0.2 + (1 - lightLevel) * 0.12 + eventPressure * 0.08 - Double(index) * 0.01).clamped(to: 0.04...0.44)) : CGFloat((0.02 + (1 - lightLevel) * 0.04).clamped(to: 0.01...0.1))
            caustic?.position.y = Float(1.24 + Double(index % 2) * 0.14 - progress * 0.018 + eventPressure * 0.006)
            caustic?.eulerAngles.z = Float(-0.08 + progress * 0.02 + eventPressure * 0.012)
        }
        for index in 0..<8 {
            let chalk = classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmChalkPulseMote\(index)", recursively: true)
            chalk?.opacity = CGFloat((0.03 + (chalkFocus ? 0.22 : 0.04) + (1 - lightLevel) * 0.1 + eventPressure * 0.08 + Double((game.currentTurn + index) % 4) * 0.01).clamped(to: 0.01...0.34))
            chalk?.position.y = Float(1.46 + Double(index % 3) * 0.13 + eventPressure * 0.008 + (chalkFocus ? 0.012 : 0))
        }
        let ambientTeacherWake = classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmTeacherWakeShadow", recursively: true)
        ambientTeacherWake?.position.x = teacherNode.position.x * 0.38
        ambientTeacherWake?.position.z = teacherNode.position.z + 0.18
        ambientTeacherWake?.opacity = CGFloat((0.02 + teacherNearAir * 0.3 + eventPressure * 0.16 + game.teacher.institutionalPressure / 100 * 0.1 + (1 - lightLevel) * 0.08).clamped(to: 0.01...0.48))
        ambientTeacherWake?.scale = SCNVector3(1 + CGFloat(teacherNearAir) * 0.18 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(progress) * 0.04)
        classroomAmbientMotionRhythmNode.childNode(withName: "ambientRhythmBlackboardLightBreath", recursively: true)?.opacity = CGFloat((0.04 + (chalkFocus ? 0.22 : 0.06) + (1 - lightLevel) * 0.12 + eventPressure * 0.08 + (period == .third ? 0.12 : 0)).clamped(to: 0.02...0.4))
        classroomSpatialHierarchyNode.opacity = CGFloat((0.07 + (1 - lightLevel) * 0.2 + progress * 0.1 + (rainy ? 0.16 : 0) + eventPressure * 0.16 + teacherNearAir * 0.08 + deskPoseAir * 0.06 + rearPoseAir * 0.08).clamped(to: 0.05...0.72))
        classroomSpatialHierarchyNode.position.y = Float(eventPressure * 0.006 + (rainy ? 0.004 : 0) + deskPoseAir * 0.004)
        classroomSpatialHierarchyNode.eulerAngles = SCNVector3(0, Float((progress - 0.5) * 0.004 + eventPressure * 0.006), Float(eventPressure * 0.004 - teacherNearAir * 0.003))
        classroomSpatialHierarchyNode.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.012, 1 + CGFloat(1 - lightLevel) * 0.012, 1)
        for row in 0..<5 {
            let rowDepth = Double(row) / 4.0
            let rowPressure = game.classmates.filter { $0.seat.row == row }.map { ($0.stress / 100).clamped(to: 0...1) }.max() ?? 0
            let rowPhone = game.classmates.contains { $0.seat.row == row && $0.state == .usingPhone } ? 1.0 : 0.0
            let rowCrying = game.classmates.contains { $0.seat.row == row && ($0.state == .crying || $0.state == .sleeping) } ? 1.0 : 0.0
            let teacherRowFocus = game.selectedTeacherTarget?.seat.row == row ? 1.0 : 0.0
            let rowSlice = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyRowAirSlice\(row)", recursively: true)
            rowSlice?.opacity = CGFloat((0.035 + (1 - lightLevel) * 0.14 + rowDepth * 0.035 + rowPressure * 0.08 + eventPressure * 0.08 + (rainy ? 0.08 : 0)).clamped(to: 0.015...0.34))
            rowSlice?.position.y = Float(1.08 + Double(row % 3) * 0.16 + eventPressure * 0.006 + rowPressure * 0.006)
            rowSlice?.eulerAngles.y = Float(-0.045 + Double(row) * 0.018 + progress * 0.012 + eventPressure * 0.01)
            let deskOcc = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyDeskRowOcclusion\(row)", recursively: true)
            deskOcc?.opacity = CGFloat((0.05 + (1 - lightLevel) * 0.16 + rowPressure * 0.12 + teacherRowFocus * 0.18 + eventPressure * 0.1).clamped(to: 0.02...0.46))
            deskOcc?.position.y = Float(0.872 + rowPressure * 0.004 + eventPressure * 0.003)
            let shoulder = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyStudentShoulderNegative\(row)", recursively: true)
            shoulder?.opacity = CGFloat((0.04 + rowPressure * 0.14 + rowPhone * 0.08 + rowCrying * 0.12 + teacherRowFocus * 0.1 + (1 - lightLevel) * 0.08).clamped(to: 0.02...0.42))
            shoulder?.scale = SCNVector3(1 + CGFloat(rowPressure) * 0.04, 1 + CGFloat(rowCrying) * 0.04, 1)
            let floorPool = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyFloorDepthPool\(row)", recursively: true)
            floorPool?.opacity = CGFloat((0.04 + (1 - lightLevel) * 0.14 + eventPressure * 0.12 + teacherRowFocus * 0.1 + rowCrying * 0.08).clamped(to: 0.02...0.4))
            floorPool?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.08 + CGFloat(teacherRowFocus) * 0.08, 1, 1 + CGFloat(rowPressure) * 0.04)
        }
        for index in 0..<4 {
            let rib = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyWindowVolumeRib\(index)", recursively: true)
            rib?.opacity = CGFloat((0.04 + (rainy ? 0.24 : 0.04) + (1 - lightLevel) * 0.14 + eventPressure * 0.08 + Double(index) * 0.012).clamped(to: 0.02...0.46))
            rib?.position.y = Float(1.68 + progress * 0.018 + eventPressure * 0.006)
            let floorReturn = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyWindowFloorReturn\(index)", recursively: true)
            floorReturn?.opacity = rainy ? CGFloat((0.08 + progress * 0.16 + (1 - lightLevel) * 0.1 + eventPressure * 0.08).clamped(to: 0.04...0.38)) : CGFloat((0.02 + (1 - lightLevel) * 0.05).clamped(to: 0.01...0.12))
        }
        for index in 0..<5 {
            let fog = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyBlackboardDepthFog\(index)", recursively: true)
            fog?.opacity = CGFloat((0.03 + (chalkFocus ? 0.24 : 0.06) + (1 - lightLevel) * 0.08 + eventPressure * 0.1 - Double(index) * 0.006).clamped(to: 0.015...0.44))
            fog?.position.y = Float(1.55 + Double(index % 2) * 0.16 + (chalkFocus ? 0.012 : 0) + eventPressure * 0.006)
        }
        for index in 0..<6 {
            let gate = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyVerticalAisleGate\(index)", recursively: true)
            gate?.opacity = CGFloat((0.025 + rearPoseAir * 0.1 + (1 - lightLevel) * 0.12 + eventPressure * 0.1 + teacherNearAir * 0.06 - Double(index % 2) * 0.006).clamped(to: 0.01...0.32))
            gate?.scale = SCNVector3(1, 1 + CGFloat(eventPressure) * 0.04, 1)
        }
        classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyPlayerForegroundMatte", recursively: true)?.opacity = CGFloat((0.03 + deskPoseAir * 0.28 + eventPressure * 0.12 + teacherNearAir * 0.08 + (1 - lightLevel) * 0.06).clamped(to: 0.01...0.48))
        let hierarchyTeacher = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyTeacherBodyOcclusion", recursively: true)
        hierarchyTeacher?.position.x = teacherNode.position.x * 0.5
        hierarchyTeacher?.position.z = teacherNode.position.z + 0.28
        hierarchyTeacher?.opacity = CGFloat((0.03 + teacherNearAir * 0.34 + eventPressure * 0.14 + (1 - lightLevel) * 0.08).clamped(to: 0.01...0.52))
        hierarchyTeacher?.scale = SCNVector3(1 + CGFloat(teacherNearAir) * 0.12, 1 + CGFloat(eventPressure) * 0.08, 1)
        let hierarchyTeacherFloor = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyTeacherFloorDrag", recursively: true)
        hierarchyTeacherFloor?.position.x = teacherNode.position.x * 0.46
        hierarchyTeacherFloor?.position.z = teacherNode.position.z + 0.42
        hierarchyTeacherFloor?.opacity = CGFloat((0.04 + teacherNearAir * 0.3 + eventPressure * 0.16 + (1 - lightLevel) * 0.08).clamped(to: 0.02...0.52))
        hierarchyTeacherFloor?.scale = SCNVector3(1 + CGFloat(teacherNearAir) * 0.18, 1, 1 + CGFloat(eventPressure) * 0.12)
        classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyBoardDeskDepthBridge", recursively: true)?.opacity = CGFloat((0.03 + (chalkFocus ? 0.22 : 0.06) + rearPoseAir * 0.08 + (1 - lightLevel) * 0.08 + eventPressure * 0.1).clamped(to: 0.01...0.4))
        classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyRearWallCompression", recursively: true)?.opacity = CGFloat((0.04 + rearPoseAir * 0.18 + (1 - lightLevel) * 0.14 + progress * 0.08 + eventPressure * 0.08).clamped(to: 0.02...0.4))
        for index in 0..<12 {
            let mote = classroomSpatialHierarchyNode.childNode(withName: "spatialHierarchyDepthMote\(index)", recursively: true)
            mote?.opacity = CGFloat((0.02 + (1 - lightLevel) * 0.12 + (rainy ? 0.08 : 0) + eventPressure * 0.08 + Double((game.currentTurn + index) % 3) * 0.01 - Double(index) * 0.0015).clamped(to: 0.005...0.26))
            mote?.position.y = Float(0.9 + Double((index * 29) % 125) / 100 + eventPressure * 0.006 + (rainy ? 0.006 : 0))
        }
        if rainy && outsideRainNode.action(forKey: "rain_fall") == nil {
            outsideRainNode.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: -0.22, z: 0.04, duration: 0.34),
                .moveBy(x: 0, y: 0.22, z: -0.04, duration: 0)
            ])), forKey: "rain_fall")
            windowRainStreakNode.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: -0.04, z: 0.01, duration: 0.8),
                .moveBy(x: 0, y: 0.04, z: -0.01, duration: 0)
            ])), forKey: "window_rain_slide")
        } else if !rainy {
            outsideRainNode.removeAction(forKey: "rain_fall")
            windowRainStreakNode.removeAction(forKey: "window_rain_slide")
        }
        outsideLampNode.opacity = lightLevel < 0.6 ? 0.95 : lampOpacity
        outsideLampNode.childNodes.forEach {
            $0.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.18, alpha: lightLevel < 0.6 ? 0.85 : 0.38)
        }
    }

    private func updateCeilingCinematicLayer(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let lightLevel = game.classroomLightLevel
        let lowLight = (1 - lightLevel).clamped(to: 0...1)
        let eventPressure = eventIntensity.vignette.clamped(to: 0...1)
        let progress = max(0, min(1, Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))))
        let thirdPeriod = game.currentPeriod == .third
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        ceilingCinematicLayerNode.opacity = CGFloat((0.16 + lowLight * 0.18 + eventPressure * 0.12 + (thirdPeriod ? 0.12 : 0)).clamped(to: 0.12...0.62))
        ceilingFixtureDetailNode.opacity = CGFloat((0.12 + lowLight * 0.2 + eventPressure * 0.1 + (thirdPeriod ? 0.14 : 0)).clamped(to: 0.1...0.68))
        ceilingFixtureDetailNode.position.y = Float(eventPressure * -0.002)
        ceilingFixtureDetailNode.eulerAngles.y = Float(eventPressure * 0.004)
        ceilingLightRigCinematicNode.opacity = CGFloat((0.08 + lowLight * 0.22 + eventPressure * 0.16 + teacherNear * 0.08 + (thirdPeriod ? 0.18 : 0)).clamped(to: 0.06...0.76))
        ceilingLightRigCinematicNode.position.y = Float(-0.003 - eventPressure * 0.006 - teacherNear * 0.002)
        ceilingLightRigCinematicNode.eulerAngles.y = Float(eventPressure * 0.006 + teacherNear * 0.003)

        for index in 0..<3 {
            let lampHalo = ceilingCinematicLayerNode.childNode(withName: "ceilingLampBloomHalo\(index)", recursively: true)
            let flicker = thirdPeriod && index == game.currentTurn % 3
            lampHalo?.opacity = CGFloat((0.18 + lowLight * 0.18 + (flicker ? 0.2 : 0) + eventPressure * 0.08).clamped(to: 0.12...0.58))
            lampHalo?.scale = flicker ? SCNVector3(1.08, 1, 1.05) : SCNVector3(1, 1, 1)
            for side in 0..<2 {
                ceilingCinematicLayerNode.childNode(withName: "ceilingTubeGlare\(index)_\(side)", recursively: true)?.opacity = CGFloat((0.14 + lightLevel * 0.1 + lowLight * 0.18 + (flicker ? 0.16 : 0)).clamped(to: 0.1...0.52))
                ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureTubeCore\(index)_\(side)", recursively: true)?.opacity = CGFloat((0.32 + lightLevel * 0.24 + lowLight * 0.18 + (flicker ? 0.22 : 0)).clamped(to: 0.22...0.86))
                ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureFlickerGhost\(index)_\(side)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.16 + eventPressure * 0.08 + (flicker ? 0.28 : 0)).clamped(to: 0.04...0.52))
                ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigTubeHotCore\(index)_\(side)", recursively: true)?.opacity = CGFloat((0.18 + lightLevel * 0.16 + lowLight * 0.24 + eventPressure * 0.08 + (flicker ? 0.26 : 0)).clamped(to: 0.12...0.72))
                ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigFlickerAfterimage\(index)_\(side)", recursively: true)?.opacity = CGFloat((0.06 + lowLight * 0.16 + eventPressure * 0.1 + (flicker ? 0.34 : 0)).clamped(to: 0.02...0.58))
            }
            ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureBackPlate\(index)", recursively: true)?.opacity = CGFloat((0.28 + lowLight * 0.18 + eventPressure * 0.08).clamped(to: 0.2...0.58))
            ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureBallastShadow\(index)", recursively: true)?.opacity = CGFloat((0.16 + lowLight * 0.2 + eventPressure * 0.08).clamped(to: 0.1...0.46))
            ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigDiffuserGlow\(index)", recursively: true)?.opacity = CGFloat((0.12 + lightLevel * 0.08 + lowLight * 0.2 + eventPressure * 0.08 + (flicker ? 0.18 : 0)).clamped(to: 0.08...0.5))
            ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigFrameLipFront\(index)", recursively: true)?.opacity = CGFloat((0.16 + lowLight * 0.12 + eventPressure * 0.06).clamped(to: 0.1...0.38))
            ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigFrameLipRear\(index)", recursively: true)?.opacity = CGFloat((0.14 + lowLight * 0.12 + eventPressure * 0.06).clamped(to: 0.08...0.36))
            ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigBallastOilShadow\(index)", recursively: true)?.opacity = CGFloat((0.12 + lowLight * 0.22 + eventPressure * 0.1 + teacherNear * 0.06).clamped(to: 0.08...0.52))
            ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigGridShadow\(index)", recursively: true)?.opacity = CGFloat((0.06 + lowLight * 0.16 + eventPressure * 0.12 + (flicker ? 0.1 : 0)).clamped(to: 0.04...0.42))
            for dustIndex in 0..<5 {
                ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureDustLip\(index)_\(dustIndex)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.14 + (thirdPeriod ? 0.08 : 0) + Double(dustIndex % 2) * 0.02).clamped(to: 0.04...0.34))
            }
            for dustIndex in 0..<7 {
                ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigDustEdge\(index)_\(dustIndex)", recursively: true)?.opacity = CGFloat((0.06 + lowLight * 0.18 + eventPressure * 0.06 + Double(dustIndex % 3) * 0.018).clamped(to: 0.03...0.36))
            }
            for speckIndex in 0..<8 {
                ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigDeadInsectSpeck\(index)_\(speckIndex)", recursively: true)?.opacity = CGFloat((0.05 + lowLight * 0.12 + (thirdPeriod ? 0.06 : 0) + Double(speckIndex % 2) * 0.018).clamped(to: 0.02...0.28))
            }
        }

        for fanIndex in 0..<2 {
            let sweep = ceilingCinematicLayerNode.childNode(withName: "fanSweepShadowRoot\(fanIndex)", recursively: true)
            sweep?.opacity = CGFloat((0.12 + lowLight * 0.16 + eventPressure * 0.12 + (thirdPeriod ? 0.14 : 0)).clamped(to: 0.08...0.5))
            sweep?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(progress) * 0.04)
            ceilingCinematicLayerNode.childNode(withName: "fanAirShearVeil\(fanIndex)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.14 + eventPressure * 0.16).clamped(to: 0.04...0.4))
        }

        for index in 0..<2 {
            ceilingCinematicLayerNode.childNode(withName: "ceilingSideContactShadow\(index)", recursively: true)?.opacity = CGFloat((0.16 + lowLight * 0.16).clamped(to: 0.12...0.42))
            ceilingCinematicLayerNode.childNode(withName: "ceilingFrontRearContactShadow\(index)", recursively: true)?.opacity = CGFloat((0.14 + lowLight * 0.14 + eventPressure * 0.06).clamped(to: 0.1...0.38))
        }
        for conduitIndex in 0..<4 {
            ceilingFixtureDetailNode.childNode(withName: "ceilingFixtureConduitCastShadow\(conduitIndex)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.18 + eventPressure * 0.08).clamped(to: 0.04...0.34))
            let sag = ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigWireSag\(conduitIndex)", recursively: true)
            sag?.opacity = CGFloat((0.08 + lowLight * 0.16 + eventPressure * 0.08 + teacherNear * 0.04).clamped(to: 0.04...0.34))
            sag?.position.y = Float(3.388 - Double(conduitIndex % 2) * 0.012 - lowLight * 0.012 - eventPressure * 0.008)
        }
        for index in 0..<5 {
            let band = ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigRoomPressureBand\(index)", recursively: true)
            band?.opacity = CGFloat((0.05 + lowLight * 0.16 + eventPressure * 0.14 + teacherNear * 0.08 + Double(index % 2) * 0.018).clamped(to: 0.03...0.42))
            band?.position.y = Float(3.374 - eventPressure * 0.006 - teacherNear * 0.004)
        }
        if let teacherPulse = ceilingLightRigCinematicNode.childNode(withName: "ceilingLightRigTeacherStepCeilingPulse", recursively: true) {
            teacherPulse.opacity = CGFloat((0.02 + eventPressure * 0.16 + teacherNear * 0.22 + lowLight * 0.08).clamped(to: 0.0...0.48))
            teacherPulse.position.x = teacherNode.position.x * 0.32
            teacherPulse.position.z = (teacherNode.position.z * 0.58).clamped(to: -4.4...2.6)
            teacherPulse.scale = SCNVector3(1 + CGFloat(teacherNear * 0.14 + eventPressure * 0.08), 1, 1 + CGFloat(lowLight * 0.12))
        }
    }

    private func updateDeskState(game: GameManager) {
        let progress = max(0.02, min(1.0, game.player.homework / 100))
        homeworkProgressNode.scale = SCNVector3(Float(progress) * 0.46, 1, 1)
        homeworkProgressNode.opacity = game.cameraPose == .desk ? 1.0 : 0.62
        homeworkSheetNode.opacity = game.cameraPose == .desk || game.audioCues.first?.kind == .paper ? 1.0 : 0.72

        let bladderLoad = max(0.02, min(1.0, game.player.bladder / 100))
        bladderIndicatorNode.scale = SCNVector3(Float(bladderLoad) * 0.34, 1, 1)
        bladderIndicatorNode.opacity = game.player.bladder > 48 || game.cameraPose == .desk ? 0.35 + CGFloat(bladderLoad) * 0.55 : 0.18

        let stressTilt = CGFloat(min(0.22, game.player.stress / 420))
        let bodyTension = CGFloat(max(0, game.player.bladder - 52) / 48)
        let stressTiltValue = Double(stressTilt)
        let bodyTensionValue = Double(bodyTension)
        let phoneActive = game.audioCues.first?.kind == .phone
        let snackActive = game.audioCues.first?.kind == .wrapper
        let paperActive = game.audioCues.first?.kind == .paper
        let eventPressure = eventVisualIntensity(game: game).vignette.clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let closeupStress = (game.player.stress / 140).clamped(to: 0...1)
        let teacherNearDesk = game.teacher.isNearPlayer ? 1.0 : 0.0
        let drawerOpen = game.cameraPose == .desk || phoneActive || snackActive || paperActive
        drawerNode.position.z = drawerOpen ? 1.78 : 1.66
        drawerNode.opacity = drawerOpen ? 0.92 : 0.55
        drawerShadowNode.opacity = drawerOpen ? 0.44 : 0.18
        snackWrapperNode.opacity = snackActive || game.player.hunger < 18 ? 0.95 : 0.32
        penNode.opacity = phoneActive || snackActive ? 0.18 : (game.cameraPose == .desk || paperActive ? 1.0 : 0.52)
        playerDeskFocusGlowNode.opacity = game.cameraPose == .desk ? CGFloat(0.24 + stressTilt * 0.9) : 0.12
        playerDeskFocusGlowNode.childNode(withName: "playerPhoneBlueWash", recursively: true)?.opacity = phoneActive ? 0.82 : 0.16
        playerDeskFocusGlowNode.childNode(withName: "playerDeskWarmFocus", recursively: true)?.opacity = paperActive ? 0.62 : 0.28
        playerDeskFocusGlowNode.childNode(withName: "playerDeskNearVignette", recursively: true)?.opacity = CGFloat(0.18 + stressTilt * 1.2)
        playerHandShadowNode.opacity = game.cameraPose == .desk ? 0.42 : 0.24
        playerHandShadowNode.childNode(withName: "leftPlayerHandShadow", recursively: true)?.opacity = phoneActive ? 0.22 : 0.44
        playerHandShadowNode.childNode(withName: "rightPlayerHandShadow", recursively: true)?.opacity = paperActive ? 0.58 : 0.34
