        playerUltraCloseMicroGeometryNode.childNode(withName: "playerUltraStressSweatLine", recursively: true)?.opacity = CGFloat((0.02 + bodyTensionValue * 0.18 + closeupStress * 0.12 + eventPressure * 0.08 + lowLight * 0.05).clamped(to: 0.01...0.36))
        playerUltraCloseMicroGeometryNode.childNode(withName: "playerUltraStressSweatLine", recursively: true)?.position.x = Float(-0.63 + stressTiltValue * 0.04)
        playerInteractionContinuityNode.opacity = CGFloat((0.06 + deskPose * 0.18 + closeupStress * 0.14 + bodyTensionValue * 0.14 + eventPressure * 0.12 + teacherNearDesk * 0.16 + lowLight * 0.08).clamped(to: 0.04...0.78) * seatedPresence)
        playerInteractionContinuityNode.position.y = Float(eventPressure * 0.004 + teacherNearDesk * 0.003 - bodyTensionValue * 0.003)
        playerInteractionContinuityNode.eulerAngles.z = Float(stressTiltValue * 0.045 + bodyTensionValue * 0.014 + eventPressure * 0.006)
        playerInteractionContinuityNode.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.014 + CGFloat(teacherNearDesk) * 0.018, 1 + CGFloat(closeupStress) * 0.018, 1)
        playerInteractionContinuityNode.childNode(withName: "playerInteractionHomeworkAdvanceWash", recursively: true)?.opacity = CGFloat((0.04 + paperDrive * 0.32 + progress * 0.16 + lowLight * 0.06).clamped(to: 0.02...0.58))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionHomeworkAdvanceWash", recursively: true)?.scale = SCNVector3(0.55 + CGFloat(progress) * 0.55, 1, 1)
        for index in 0..<10 {
            let filled = progress >= Double(index + 1) / 10.0 ? 1.0 : 0.0
            let tick = playerInteractionContinuityNode.childNode(withName: "playerInteractionHomeworkTick\(index)", recursively: true)
            tick?.opacity = CGFloat((0.03 + filled * 0.3 + paperDrive * 0.12 + eventPressure * 0.04).clamped(to: 0.02...0.48))
            tick?.position.y = Float(0.869 + filled * 0.004 + paperDrive * 0.002)
        }
        playerInteractionContinuityNode.childNode(withName: "playerInteractionRightWristDecisionShadow", recursively: true)?.opacity = CGFloat((0.05 + paperDrive * 0.28 + closeupStress * 0.12 + bodyTensionValue * 0.08).clamped(to: 0.02...0.52))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionRightWristDecisionShadow", recursively: true)?.position.z = Float(1.49 - paperDrive * 0.08)
        playerInteractionContinuityNode.childNode(withName: "playerInteractionLeftPhoneDecisionGlow", recursively: true)?.opacity = CGFloat((phoneDrive * (0.32 + lowLight * 0.22 + eventPressure * 0.1) + teacherNearDesk * 0.04).clamped(to: 0...0.68))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionLeftPhoneDecisionGlow", recursively: true)?.scale = SCNVector3(1 + CGFloat(phoneDrive) * 0.18, 1, 1 + CGFloat(lowLight) * 0.08)
        playerInteractionContinuityNode.childNode(withName: "playerInteractionTeacherDeskCompression", recursively: true)?.opacity = CGFloat((0.03 + teacherNearDesk * 0.36 + eventPressure * 0.14 + closeupStress * 0.08).clamped(to: 0.01...0.6))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionTeacherDeskCompression", recursively: true)?.scale = SCNVector3(1 + CGFloat(teacherNearDesk) * 0.18 + CGFloat(eventPressure) * 0.08, 1, 1 + CGFloat(teacherNearDesk) * 0.12)
        playerInteractionContinuityNode.childNode(withName: "playerInteractionDrawerDarkPocket", recursively: true)?.opacity = CGFloat((0.04 + drawerDrive * 0.24 + phoneDrive * 0.08 + snackDrive * 0.08 + lowLight * 0.08).clamped(to: 0.02...0.42))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionProgressCompletionShine", recursively: true)?.opacity = CGFloat((max(0, progress - 0.72) * 1.4 + paperDrive * 0.06).clamped(to: 0...0.46))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionProgressCompletionShine", recursively: true)?.position.x = Float(-0.86 + progress * 0.42)
        for index in 0..<6 {
            let beat = playerInteractionContinuityNode.childNode(withName: "playerInteractionFingerStaccato\(index)", recursively: true)
            beat?.opacity = CGFloat((0.02 + paperDrive * 0.14 + phoneDrive * 0.12 + bodyTensionValue * 0.1 + closeupStress * 0.08 - Double(index) * 0.012).clamped(to: 0.01...0.34))
            beat?.position.y = Float(0.864 + paperDrive * 0.004 + phoneDrive * 0.003 + bodyTensionValue * 0.002) + sin(Float(game.currentTurn + index) * 0.8) * 0.0015
