        playerInteractionContinuityNode.childNode(withName: "playerInteractionDeskEdgePulse", recursively: true)?.opacity = CGFloat((0.04 + bodyTensionValue * 0.18 + closeupStress * 0.12 + teacherNearDesk * 0.08).clamped(to: 0.02...0.36))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionSnackCrinkleResponse", recursively: true)?.opacity = CGFloat((snackDrive * (0.32 + lowLight * 0.12) + (game.player.hunger < 18 ? 0.08 : 0)).clamped(to: 0...0.5))
        playerInteractionContinuityNode.childNode(withName: "playerInteractionPanicStillnessBand", recursively: true)?.opacity = CGFloat((0.02 + eventPressure * 0.26 + teacherNearDesk * 0.18 + closeupStress * 0.08).clamped(to: 0.01...0.46))
        for index in 0..<8 {
            let mote = playerInteractionContinuityNode.childNode(withName: "playerInteractionCloseActionMote\(index)", recursively: true)
            mote?.opacity = CGFloat((0.02 + paperDrive * 0.08 + phoneDrive * 0.06 + eventPressure * 0.08 + lowLight * 0.08 + teacherNearDesk * 0.04 - Double(index) * 0.004).clamped(to: 0.01...0.24))
        }
        let actionCommit = max(max(paperDrive, phoneDrive), max(snackDrive, drawerDrive * 0.55))
        let freezeDrive = max(teacherNearDesk, eventPressure * 0.72)
        playerActionCommitmentNode.opacity = CGFloat((0.04 + deskPose * 0.12 + actionCommit * 0.18 + closeupStress * 0.14 + bodyTensionValue * 0.12 + freezeDrive * 0.2 + lowLight * 0.08).clamped(to: 0.03...0.78) * seatedPresence)
        playerActionCommitmentNode.position.y = Float(eventPressure * 0.004 + teacherNearDesk * 0.004 - bodyTensionValue * 0.002)
        playerActionCommitmentNode.eulerAngles.z = Float(stressTiltValue * 0.05 + bodyTensionValue * 0.018 - freezeDrive * 0.01)
        playerActionCommitmentNode.scale = SCNVector3(1 + CGFloat(freezeDrive) * 0.016 + CGFloat(eventPressure) * 0.01, 1 + CGFloat(actionCommit) * 0.012, 1)
        playerActionCommitmentNode.childNode(withName: "playerActionRightWriteReach", recursively: true)?.opacity = CGFloat((paperDrive * (0.34 + closeupStress * 0.12 + eventPressure * 0.08) + freezeDrive * 0.04).clamped(to: 0...0.58))
        playerActionCommitmentNode.childNode(withName: "playerActionRightWriteReach", recursively: true)?.position.z = Float(1.39 - paperDrive * 0.06 + freezeDrive * 0.02)
        playerActionCommitmentNode.childNode(withName: "playerActionPaperCommitWash", recursively: true)?.opacity = CGFloat((0.03 + paperDrive * 0.28 + progress * 0.12 + lowLight * 0.06).clamped(to: 0.02...0.48))
        playerActionCommitmentNode.childNode(withName: "playerActionPaperCommitWash", recursively: true)?.scale = SCNVector3(0.7 + CGFloat(progress) * 0.4, 1, 1)
        playerActionCommitmentNode.childNode(withName: "playerActionLeftPhoneReach", recursively: true)?.opacity = CGFloat((phoneDrive * (0.34 + lowLight * 0.2 + eventPressure * 0.1) - teacherNearDesk * 0.08).clamped(to: 0...0.62))
        playerActionCommitmentNode.childNode(withName: "playerActionLeftPhoneReach", recursively: true)?.position.z = Float(1.55 + phoneDrive * 0.04 - teacherNearDesk * 0.08)
        playerActionCommitmentNode.childNode(withName: "playerActionPhoneHideUnderDeskCut", recursively: true)?.opacity = CGFloat((phoneDrive * (0.12 + freezeDrive * 0.32 + lowLight * 0.1) + teacherNearDesk * 0.08).clamped(to: 0...0.58))
        playerActionCommitmentNode.childNode(withName: "playerActionSnackWithdrawCrinkle", recursively: true)?.opacity = CGFloat((snackDrive * (0.28 + lowLight * 0.12 + closeupStress * 0.08) + (game.player.hunger < 18 ? 0.06 : 0)).clamped(to: 0...0.48))
        playerActionCommitmentNode.childNode(withName: "playerActionSnackWithdrawCrinkle", recursively: true)?.eulerAngles.y = Float(0.42 + stressTiltValue * 0.7 + snackDrive * 0.08)
        playerActionCommitmentNode.childNode(withName: "playerActionDrawerFingerHook", recursively: true)?.opacity = CGFloat((drawerDrive * (0.12 + phoneDrive * 0.1 + snackDrive * 0.1 + lowLight * 0.08) + teacherNearDesk * 0.04).clamped(to: 0.02...0.42))
        playerActionCommitmentNode.childNode(withName: "playerActionDrawerFingerHook", recursively: true)?.position.z = Float(1.82 + drawerDrive * 0.05 - freezeDrive * 0.03)
        playerActionCommitmentNode.childNode(withName: "playerActionTeacherFreezeHandBrake", recursively: true)?.opacity = CGFloat((0.02 + freezeDrive * 0.36 + closeupStress * 0.08 + bodyTensionValue * 0.06).clamped(to: 0.01...0.62))
        playerActionCommitmentNode.childNode(withName: "playerActionTeacherFreezeHandBrake", recursively: true)?.scale = SCNVector3(1 + CGFloat(freezeDrive) * 0.18, 1, 1 + CGFloat(eventPressure) * 0.12)
        playerActionCommitmentNode.childNode(withName: "playerActionUnderDeskFootLock", recursively: true)?.opacity = CGFloat((0.02 + bodyTensionValue * 0.24 + freezeDrive * 0.18 + eventPressure * 0.06).clamped(to: 0.01...0.46))
        playerActionCommitmentNode.childNode(withName: "playerActionDeskBreathEdge", recursively: true)?.opacity = CGFloat((0.04 + closeupStress * 0.14 + bodyTensionValue * 0.12 + freezeDrive * 0.08 + lowLight * 0.08).clamped(to: 0.02...0.38))
        playerActionCommitmentNode.childNode(withName: "playerActionBodyLeanShadow", recursively: true)?.opacity = CGFloat((0.04 + deskPose * 0.12 + bodyTensionValue * 0.16 + closeupStress * 0.08 + freezeDrive * 0.08).clamped(to: 0.02...0.44))
        playerActionCommitmentNode.childNode(withName: "playerActionBodyLeanShadow", recursively: true)?.position.z = Float(1.86 - bodyTensionValue * 0.04 + freezeDrive * 0.025)
        for index in 0..<7 {
            let stroke = playerActionCommitmentNode.childNode(withName: "playerActionWritingStrokeEcho\(index)", recursively: true)
            stroke?.opacity = CGFloat((paperDrive * (0.12 + closeupStress * 0.1 + eventPressure * 0.08 - Double(index) * 0.01)).clamped(to: 0...0.36))
            stroke?.position.y = Float(0.879 + paperDrive * 0.004) + sin(Float(game.currentTurn + index) * 0.9) * 0.0015
            stroke?.eulerAngles.y = Float(-0.12 + Double(index) * 0.04 + stressTiltValue * 0.45)
        }
        for index in 0..<5 {
            let slice = playerActionCommitmentNode.childNode(withName: "playerActionPhoneBlueDecisionSlice\(index)", recursively: true)
            slice?.opacity = CGFloat((phoneDrive * (0.1 + lowLight * 0.1 + eventPressure * 0.08 - Double(index) * 0.012)).clamped(to: 0...0.32))
            slice?.position.z = Float(1.5 + Double(index % 2) * 0.08 - freezeDrive * 0.04)
        }
        for index in 0..<5 {
            let ripple = playerActionCommitmentNode.childNode(withName: "playerActionTeacherFreezeRipple\(index)", recursively: true)
            ripple?.opacity = CGFloat((freezeDrive * (0.22 + closeupStress * 0.08 - Double(index) * 0.026)).clamped(to: 0...0.46))
            ripple?.scale = SCNVector3(1 + CGFloat(freezeDrive) * (0.08 + CGFloat(index) * 0.025), 1, 1 + CGFloat(eventPressure) * 0.08)
        }
        for index in 0..<4 {
            let beat = playerActionCommitmentNode.childNode(withName: "playerActionDrawerQuietBeat\(index)", recursively: true)
            beat?.opacity = CGFloat((drawerDrive * (0.08 + phoneDrive * 0.08 + snackDrive * 0.08 + lowLight * 0.05 - Double(index) * 0.014)).clamped(to: 0...0.28))
            beat?.position.x = Float(-0.66 + Double(index) * 0.05 + drawerDrive * 0.025 - freezeDrive * 0.014)
        }
        let embodiedRead = (deskPose * 0.16 + actionCommit * 0.18 + closeupStress * 0.16 + bodyTensionValue * 0.14 + freezeDrive * 0.22 + lowLight * 0.08 + eventPressure * 0.08).clamped(to: 0...0.9)
        playerEmbodiedViewNode.opacity = CGFloat((0.04 + embodiedRead).clamped(to: 0.03...0.82) * seatedPresence)
        playerEmbodiedViewNode.position.y = Float(eventPressure * 0.004 + teacherNearDesk * 0.003 - bodyTensionValue * 0.004)
        playerEmbodiedViewNode.eulerAngles.z = Float(stressTiltValue * 0.045 + bodyTensionValue * 0.016 - freezeDrive * 0.012)
        playerEmbodiedViewNode.scale = SCNVector3(1 + CGFloat(freezeDrive) * 0.016 + CGFloat(eventPressure) * 0.012, 1 + CGFloat(embodiedRead) * 0.014, 1)
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedLeftForearmNearMass", recursively: true)?.opacity = CGFloat((0.12 + deskPose * 0.16 + phoneDrive * 0.18 + bodyTensionValue * 0.1 + lowLight * 0.08).clamped(to: 0.08...0.52))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedLeftForearmNearMass", recursively: true)?.position.z = Float(1.72 + phoneDrive * 0.035 - freezeDrive * 0.02)
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedRightForearmNearMass", recursively: true)?.opacity = CGFloat((0.12 + deskPose * 0.16 + paperDrive * 0.2 + snackDrive * 0.12 + bodyTensionValue * 0.1 + lowLight * 0.08).clamped(to: 0.08...0.56))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedRightForearmNearMass", recursively: true)?.position.z = Float(1.68 - paperDrive * 0.04 + snackDrive * 0.035)
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedPeripheralBlurLeft", recursively: true)?.opacity = CGFloat((0.05 + deskPose * 0.1 + phoneDrive * 0.12 + freezeDrive * 0.12 + eventPressure * 0.08).clamped(to: 0.02...0.42))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedPeripheralBlurRight", recursively: true)?.opacity = CGFloat((0.05 + deskPose * 0.1 + paperDrive * 0.12 + snackDrive * 0.08 + freezeDrive * 0.12 + eventPressure * 0.08).clamped(to: 0.02...0.44))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedDeskEdgeOcclusion", recursively: true)?.opacity = CGFloat((0.08 + deskPose * 0.16 + bodyTensionValue * 0.16 + closeupStress * 0.1 + freezeDrive * 0.08).clamped(to: 0.04...0.48))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedBreathOnPaperVeil", recursively: true)?.opacity = CGFloat((0.02 + lowLight * 0.12 + closeupStress * 0.08 + bodyTensionValue * 0.08 + (paperActive ? 0.06 : 0)).clamped(to: 0.01...0.32))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedTeacherProximityShadow", recursively: true)?.opacity = CGFloat((freezeDrive * (0.28 + eventPressure * 0.12) + closeupStress * 0.06).clamped(to: 0...0.62))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedTeacherProximityShadow", recursively: true)?.scale = SCNVector3(1 + CGFloat(freezeDrive) * 0.18, 1, 1 + CGFloat(eventPressure) * 0.1)
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedPanicGripHalo", recursively: true)?.opacity = CGFloat((0.02 + closeupStress * 0.16 + bodyTensionValue * 0.16 + freezeDrive * 0.18 + eventPressure * 0.08).clamped(to: 0.01...0.48))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedPhoneBlueUnderPalm", recursively: true)?.opacity = CGFloat((phoneDrive * (0.34 + lowLight * 0.2 + eventPressure * 0.08) - teacherNearDesk * 0.08).clamped(to: 0...0.66))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedPhoneBlueUnderPalm", recursively: true)?.position.z = Float(1.58 + phoneDrive * 0.035 - freezeDrive * 0.05)
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedWritingCommitLine", recursively: true)?.opacity = CGFloat((paperDrive * (0.3 + closeupStress * 0.14 + eventPressure * 0.08)).clamped(to: 0...0.58))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedWritingCommitLine", recursively: true)?.eulerAngles.y = Float(-0.12 + stressTiltValue * 0.42)
        for index in 0..<10 {
            let filled = progress >= Double(index + 1) / 10.0 ? 1.0 : 0.0
            let indent = playerEmbodiedViewNode.childNode(withName: "playerEmbodiedHomeworkProgressIndent\(index)", recursively: true)
            indent?.opacity = CGFloat((0.02 + filled * 0.26 + paperDrive * 0.1 + closeupStress * 0.04 - Double(index) * 0.004).clamped(to: 0.01...0.42))
            indent?.position.y = Float(0.887 + filled * 0.004 + paperDrive * 0.002)
        }
        for index in 0..<6 {
            let slice = playerEmbodiedViewNode.childNode(withName: "playerEmbodiedFreezeStillnessSlice\(index)", recursively: true)
            slice?.opacity = CGFloat((freezeDrive * (0.22 + closeupStress * 0.08 - Double(index) * 0.024)).clamped(to: 0...0.46))
            slice?.scale = SCNVector3(1 + CGFloat(freezeDrive) * (0.08 + CGFloat(index) * 0.022), 1, 1 + CGFloat(eventPressure) * 0.08)
        }
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedCompletionReliefGlint", recursively: true)?.opacity = CGFloat((max(0, progress - 0.74) * 1.5 + paperDrive * 0.06 + lowLight * 0.04).clamped(to: 0...0.5))
        playerEmbodiedViewNode.childNode(withName: "playerEmbodiedCompletionReliefGlint", recursively: true)?.position.x = Float(-0.84 + progress * 0.46)
        for index in 0..<4 {
            let seal = playerEmbodiedViewNode.childNode(withName: "playerEmbodiedCuffTableSeal\(index)", recursively: true)
            seal?.opacity = CGFloat((0.04 + bodyTensionValue * 0.16 + closeupStress * 0.08 + (index % 2 == 0 ? phoneDrive * 0.12 : paperDrive * 0.14) + freezeDrive * 0.06).clamped(to: 0.02...0.38))
        }
        playerPhoneNode.childNodes.dropFirst().forEach { $0.opacity = phoneActive ? 1.0 : 0.38 }
        if !phoneActive {
            playerPhoneNode.removeAction(forKey: "player_phone_buzz")
        }
        leftHandNode.position = game.cameraPose == .desk
            ? SCNVector3(-0.85, 0.835, 1.52)
            : SCNVector3(-0.86, 0.83, 1.62)
        rightHandNode.position = paperActive
            ? SCNVector3(-0.45, 0.842, 1.38)
            : (game.cameraPose == .desk ? SCNVector3(-0.43, 0.835, 1.48) : SCNVector3(-0.38, 0.83, 1.6))

        if paperActive {
            leftHandNode.eulerAngles.x = 0.04
            leftHandNode.eulerAngles.z = 0.14 + bodyTension * 0.04
            rightHandNode.eulerAngles.x = -0.18
            rightHandNode.eulerAngles.z = -0.24
            if rightHandNode.action(forKey: "write_homework") == nil {
                let stroke = SCNAction.sequence([
                    .moveBy(x: 0.12, y: 0.002, z: -0.012, duration: 0.12),
                    .moveBy(x: -0.1, y: -0.002, z: 0.022, duration: 0.1),
                    .moveBy(x: 0.07, y: 0, z: -0.01, duration: 0.09),
                    .moveBy(x: -0.09, y: 0, z: 0, duration: 0.12)
                ])
                rightHandNode.runAction(.repeat(stroke, count: 5), forKey: "write_homework")
                homeworkSheetNode.runAction(.sequence([
                    .fadeOpacity(to: 1.0, duration: 0.05),
                    .wait(duration: 0.8),
                    .fadeOpacity(to: game.cameraPose == .desk ? 1.0 : 0.72, duration: 0.4)
                ]), forKey: "paper_focus")
            }
            if playerPaperPressureNode.action(forKey: "fresh_pressure") == nil {
                playerPaperPressureNode.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: 0.68, duration: 0.16),
                    .fadeOpacity(to: 0.36, duration: 0.22),
                    .wait(duration: 0.35)
                ])), forKey: "fresh_pressure")
            }
        } else {
            rightHandNode.removeAction(forKey: "write_homework")
            playerPaperPressureNode.removeAction(forKey: "fresh_pressure")
            leftHandNode.eulerAngles.x = phoneActive ? -0.08 : stressTilt + bodyTension * 0.04
            leftHandNode.eulerAngles.z = phoneActive ? -0.2 : stressTilt + bodyTension * 0.05
            rightHandNode.eulerAngles.x = snackActive ? -0.34 : (phoneActive ? -0.2 : -stressTilt - bodyTension * 0.04)
            rightHandNode.eulerAngles.z = snackActive ? 0.34 : (phoneActive ? 0.24 : -stressTilt - bodyTension * 0.05)
            if phoneActive && playerPhoneNode.action(forKey: "player_phone_buzz") == nil {
                playerPhoneNode.runAction(.repeatForever(.sequence([
                    .moveBy(x: 0.004, y: 0, z: -0.004, duration: 0.06),
                    .moveBy(x: -0.004, y: 0, z: 0.004, duration: 0.08),
                    .wait(duration: 0.42)
                ])), forKey: "player_phone_buzz")
            } else if !phoneActive {
                playerPhoneNode.removeAction(forKey: "player_phone_buzz")
            }
        }

        if bodyTension > 0.1 && leftLegNode.action(forKey: "bladder_fidget") == nil {
            let left = SCNAction.rotateBy(x: 0, y: 0, z: 0.08, duration: 0.12)
            let right = SCNAction.rotateBy(x: 0, y: 0, z: -0.16, duration: 0.18)
            let back = SCNAction.rotateBy(x: 0, y: 0, z: 0.08, duration: 0.12)
            leftLegNode.runAction(.repeatForever(.sequence([left, right, back, .wait(duration: 0.35)])), forKey: "bladder_fidget")
            rightLegNode.runAction(.repeatForever(.sequence([right, left, back, .wait(duration: 0.35)])), forKey: "bladder_fidget")
            seatTensionNode.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.22, duration: 0.18),
                .fadeOpacity(to: 0.08, duration: 0.28),
                .wait(duration: 0.35)
            ])), forKey: "seat_tension")
        } else if bodyTension <= 0.1 {
            leftLegNode.removeAction(forKey: "bladder_fidget")
            rightLegNode.removeAction(forKey: "bladder_fidget")
            seatTensionNode.removeAction(forKey: "seat_tension")
            leftLegNode.eulerAngles.z = 0
            rightLegNode.eulerAngles.z = 0
            seatTensionNode.opacity = 0.08
        }
    }

    private func eventVisualIntensity(game: GameManager) -> (blur: Double, vignette: Double, desaturation: Double) {
        guard case .event(let event) = game.gameState else {
            return (0, 0, 0)
        }
        switch event.kind {
        case .playerBreakdown:
            return (5.5, 1.2, 0.46)
        case .loneliness:
            return (3.6, 1.0, 0.38)
        case .powerOutage:
            return (1.8, 0.72, 0.28)
        case .phoneNotification:
            return (1.2, 0.42, 0.12)
        case .broadcast:
            return (1.0, 0.46, 0.18)
        case .knockOnDoor:
            return (1.5, 0.58, 0.16)
        case .discovery:
            return (3.0, 0.9, 0.22)
        case .classmateCrying:
            return (2.4, 0.78, 0.24)
        case .classmateHelpRequest:
            return (1.0, 0.34, 0.1)
        case .classmateReport:
            return (2.0, 0.66, 0.2)
        case .memoryTrust:
            return (0.7, 0.24, 0.06)
        case .memorySuspicion:
            return (2.2, 0.74, 0.22)
        case .teacherConcern, .supportOffer:
            return (0.8, 0.28, 0.08)
        case .leaveSeatRequest:
            return (1.4, 0.48, 0.14)
        }
    }

    private func makeText(_ string: String, size: CGFloat, color: NSColor, position: SCNVector3) -> SCNNode {
        let geometry = SCNText(string: string, extrusionDepth: 0.002)
        geometry.font = NSFont.systemFont(ofSize: size, weight: .semibold)
        geometry.flatness = 0.3
        geometry.firstMaterial = material(color)
        let node = SCNNode(geometry: geometry)
        node.position = position
        node.scale = SCNVector3(1, 1, 1)
        return node
    }

    private func startClassmateIdleAnimation(_ node: SCNNode, seed: Int, state: ClassmateState?) {
        if state != .sleeping && state != .crying {
            let blinkDelay = 1.8 + Double(seed % 7) * 0.28
            let blink = SCNAction.repeatForever(.sequence([
                .wait(duration: blinkDelay),
                .fadeOpacity(to: 0.78, duration: 0.04),
                .fadeOpacity(to: state == .anxious ? 0.44 : 0.12, duration: 0.08),
                .wait(duration: 0.8 + Double(seed % 3) * 0.18),
                .fadeOpacity(to: 0.72, duration: 0.035),
                .fadeOpacity(to: state == .anxious ? 0.44 : 0.12, duration: 0.07)
            ]))
            node.childNode(withName: "leftUpperLid", recursively: true)?.runAction(blink, forKey: "idle_blink")
            node.childNode(withName: "rightUpperLid", recursively: true)?.runAction(blink, forKey: "idle_blink")
        }

        if state != .usingPhone && state != .sleeping && state != .crying && state != .studying && state != .lookingAtPlayer {
            let eyeDrift = SCNAction.repeatForever(.sequence([
                .moveBy(x: CGFloat((seed % 3) - 1) * 0.0018, y: 0.0008, z: 0, duration: 0.38),
                .wait(duration: 0.5 + Double(seed % 4) * 0.12),
                .moveBy(x: -CGFloat((seed % 3) - 1) * 0.0018, y: -0.0008, z: 0, duration: 0.42),
                .wait(duration: 0.7 + Double(seed % 5) * 0.1)
            ]))
            for name in ["leftPupil", "rightPupil", "leftEyeHighlight", "rightEyeHighlight"] {
                node.childNode(withName: name, recursively: true)?.runAction(eyeDrift, forKey: "idle_eye_drift")
            }
        }

        if state == nil || state == .lookingAtPlayer || state == .offeringHelp {
            let shoulderRise = SCNAction.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.004 + CGFloat(seed % 3) * 0.001, z: 0, duration: 1.2 + Double(seed % 4) * 0.16),
                .moveBy(x: 0, y: -0.004 - CGFloat(seed % 3) * 0.001, z: 0, duration: 1.4 + Double(seed % 5) * 0.14)
            ]))
            node.childNode(withName: "bodyRoot", recursively: false)?.runAction(shoulderRise, forKey: "idle_breathing")
        }
    }

    private func updateClassmateStatusEffects(_ state: ClassmateState, on node: SCNNode) {
        if state != .usingPhone {
            node.childNode(withName: "phoneGlow", recursively: true)?.opacity = 0
        }
        node.childNode(withName: "phoneLight", recursively: true)?.light?.intensity = state == .usingPhone ? 95 : 0
        node.childNode(withName: "paperGlow", recursively: true)?.opacity = state == .studying ? 0.38 : 0.08
        node.childNode(withName: "cryingDeskGlow", recursively: true)?.opacity = state == .crying ? 0.68 : 0
        if state != .offeringHelp {
            node.childNode(withName: "supportGlow", recursively: true)?.opacity = 0
        }
        node.childNode(withName: "coverShadow", recursively: true)?.opacity = state == .covering ? 0.72 : 0
        node.childNode(withName: "studentFloorShadow", recursively: true)?.opacity = state == .sleeping ? 0.18 : (state == .crying ? 0.3 : 0.24)
        node.childNode(withName: "studentFootContact", recursively: true)?.opacity = state == .anxious ? 0.34 : 0.24
        node.childNode(withName: "studentDeskOcclusion", recursively: true)?.opacity = state == .sleeping || state == .crying ? 0.46 : (state == .covering ? 0.38 : 0.22)
        let rimOpacity: CGFloat
        switch state {
        case .usingPhone:
            rimOpacity = 0.46
        case .offeringHelp, .lookingAtPlayer:
            rimOpacity = 0.32
        case .crying, .anxious:
            rimOpacity = 0.24
        default:
            rimOpacity = 0.16
        }
        node.childNode(withName: "studentLeftRimLight", recursively: true)?.opacity = rimOpacity
        node.childNode(withName: "studentRightRimLight", recursively: true)?.opacity = rimOpacity
        node.childNode(withName: "studentHeadRimLight", recursively: true)?.opacity = rimOpacity * 0.9
        node.childNode(withName: "studentCinematicRimLayer", recursively: false)?.opacity = CGFloat((0.18 + rimOpacity * 1.15).clamped(to: 0.18...0.82))
        node.childNode(withName: "studentCinematicLeftRim", recursively: true)?.opacity = rimOpacity
        node.childNode(withName: "studentCinematicRightRim", recursively: true)?.opacity = state == .usingPhone ? CGFloat(0.62) : rimOpacity * 0.92
        node.childNode(withName: "studentCinematicHeadHalo", recursively: true)?.opacity = state == .lookingAtPlayer || state == .offeringHelp ? CGFloat(0.48) : rimOpacity * 0.72
        node.childNode(withName: "studentDeskSkinReflection", recursively: true)?.opacity = state == .studying ? CGFloat(0.28) : (state == .sleeping ? CGFloat(0.1) : CGFloat(0.2))
        node.childNode(withName: "studentEmotionalColorWash", recursively: true)?.opacity = state == .crying ? CGFloat(0.64) : (state == .anxious || state == .covering ? CGFloat(0.42) : CGFloat(0.18))
        node.childNode(withName: "studentShoulderSilhouetteCut", recursively: true)?.opacity = state == .sleeping || state == .crying ? CGFloat(0.38) : CGFloat(0.18)
        node.childNode(withName: "studentMicroMotionLayer", recursively: false)?.opacity = state == .sleeping ? CGFloat(0.08) : (state == .anxious || state == .usingPhone || state == .studying ? CGFloat(0.32) : CGFloat(0.2))
        node.childNode(withName: "studentPenTipMotionTrail", recursively: true)?.opacity = state == .studying ? CGFloat(0.5) : CGFloat(0.08)
        node.childNode(withName: "studentPhoneThumbMotionArc", recursively: true)?.opacity = state == .usingPhone ? CGFloat(0.72) : 0
        node.childNode(withName: "studentPhoneJawLightPulse", recursively: true)?.opacity = state == .usingPhone ? CGFloat(0.5) : 0
        node.childNode(withName: "studentLeftShoulderTensionLine", recursively: true)?.opacity = state == .anxious || state == .covering || state == .crying ? CGFloat(0.42) : CGFloat(0.14)
        node.childNode(withName: "studentRightShoulderTensionLine", recursively: true)?.opacity = state == .anxious || state == .covering || state == .crying ? CGFloat(0.42) : CGFloat(0.14)
        node.childNode(withName: "studentThroatSwallowShadow", recursively: true)?.opacity = state == .anxious || state == .covering ? CGFloat(0.34) : CGFloat(0.12)
        node.childNode(withName: "studentHelpReachGhost", recursively: true)?.opacity = state == .offeringHelp ? CGFloat(0.48) : 0
        node.childNode(withName: "studentIdentityPropLayer", recursively: false)?.opacity = state == .sleeping ? CGFloat(0.62) : CGFloat(0.86)
        node.childNode(withName: "studentBackpackTopCatch", recursively: true)?.opacity = state == .usingPhone || state == .lookingAtPlayer ? CGFloat(0.42) : CGFloat(0.24)
        node.childNode(withName: "studentPocketTissue", recursively: true)?.opacity = state == .anxious || state == .crying ? CGFloat(0.92) : CGFloat(0.28)
        node.childNode(withName: "studentBagCharm", recursively: true)?.opacity = state == .covering ? CGFloat(0.36) : CGFloat(0.86)
        node.childNode(withName: "studentSideBottle", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.38) : CGFloat(0.82)
        node.childNode(withName: "studentWatchFaceGlint", recursively: true)?.opacity = state == .studying || state == .usingPhone ? CGFloat(0.72) : CGFloat(0.34)
        node.childNode(withName: "studentMaterialIntegrationLayer", recursively: false)?.opacity = state == .sleeping || state == .crying ? CGFloat(0.48) : (state == .studying || state == .usingPhone ? CGFloat(0.36) : CGFloat(0.24))
        node.childNode(withName: "studentClothMicroSurfaceLayer", recursively: false)?.opacity = state == .sleeping || state == .crying ? CGFloat(0.5) : (state == .anxious || state == .covering ? CGFloat(0.42) : CGFloat(0.26))
        node.childNode(withName: "studentSeatedKineticSilhouetteLayer", recursively: false)?.opacity = state == .sleeping ? CGFloat(0.18) : (state == .anxious || state == .crying || state == .covering ? CGFloat(0.42) : CGFloat(0.26))
        node.childNode(withName: "studentDeskEdgeCompression", recursively: true)?.opacity = state == .studying || state == .crying || state == .sleeping ? CGFloat(0.46) : CGFloat(0.18)
        node.childNode(withName: "studentClothDeskEdgeWrinkleBridge", recursively: true)?.opacity = state == .studying || state == .crying || state == .sleeping ? CGFloat(0.5) : CGFloat(0.16)
        node.childNode(withName: "studentClothCollarOilShadow", recursively: true)?.opacity = state == .anxious || state == .covering || state == .crying ? CGFloat(0.46) : CGFloat(0.14)
        node.childNode(withName: "studentUniformTailoringLayer", recursively: false)?.opacity = state == .sleeping ? CGFloat(0.18) : (state == .anxious || state == .covering || state == .crying ? CGFloat(0.42) : CGFloat(0.26))
        node.childNode(withName: "studentUniformCollarGapShadow", recursively: true)?.opacity = state == .anxious || state == .covering || state == .crying ? CGFloat(0.5) : CGFloat(0.22)
        node.childNode(withName: "studentUniformDeskHemPressure", recursively: true)?.opacity = state == .studying || state == .crying || state == .sleeping ? CGFloat(0.56) : CGFloat(0.18)
        node.childNode(withName: "studentUniformNameTag", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.24) : CGFloat(0.64)
        node.childNode(withName: "leftSleeveTableCrease", recursively: true)?.opacity = state == .studying || state == .crying ? CGFloat(0.42) : CGFloat(0.16)
        node.childNode(withName: "rightSleeveTableCrease", recursively: true)?.opacity = state == .studying || state == .usingPhone ? CGFloat(0.44) : CGFloat(0.16)
        node.childNode(withName: "studentClothLeftElbowTensionMesh", recursively: true)?.opacity = state == .covering || state == .crying ? CGFloat(0.42) : CGFloat(0.18)
        node.childNode(withName: "studentClothRightElbowTensionMesh", recursively: true)?.opacity = state == .usingPhone || state == .studying ? CGFloat(0.42) : CGFloat(0.18)
        node.childNode(withName: "studentSeatBackOcclusion", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.2) : CGFloat(0.34)
        node.childNode(withName: "leftEyeWetLine", recursively: true)?.opacity = state == .crying ? CGFloat(0.72) : (state == .anxious ? CGFloat(0.34) : CGFloat(0.08))
        node.childNode(withName: "rightEyeWetLine", recursively: true)?.opacity = state == .crying ? CGFloat(0.72) : (state == .anxious ? CGFloat(0.34) : CGFloat(0.08))
        node.childNode(withName: "leftTearTrack", recursively: true)?.opacity = state == .crying ? CGFloat(0.62) : 0
        node.childNode(withName: "rightTearTrack", recursively: true)?.opacity = state == .crying ? CGFloat(0.48) : 0
        node.childNode(withName: "phoneFaceReflection", recursively: true)?.opacity = state == .usingPhone ? CGFloat(0.58) : 0
        node.childNode(withName: "leftCheekStressFlush", recursively: true)?.opacity = state == .crying || state == .anxious ? CGFloat(0.28) : 0
        node.childNode(withName: "rightCheekStressFlush", recursively: true)?.opacity = state == .crying || state == .anxious ? CGFloat(0.28) : 0
        node.childNode(withName: "lowerLipTensionLine", recursively: true)?.opacity = state == .crying || state == .covering ? CGFloat(0.42) : (state == .anxious ? CGFloat(0.24) : 0)
        node.childNode(withName: "studentFacialCinematicFidelityLayer", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.18) : (state == .crying || state == .anxious || state == .usingPhone ? CGFloat(0.42) : CGFloat(0.24))
        node.childNode(withName: "studentLeftCorneaGlassCatch", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.06) : (state == .crying || state == .anxious ? CGFloat(0.5) : CGFloat(0.24))
        node.childNode(withName: "studentRightCorneaGlassCatch", recursively: true)?.opacity = state == .sleeping ? CGFloat(0.06) : (state == .crying || state == .usingPhone ? CGFloat(0.48) : CGFloat(0.24))
        node.childNode(withName: "studentUpperLipWetRim", recursively: true)?.opacity = state == .crying || state == .covering ? CGFloat(0.46) : (state == .anxious ? CGFloat(0.3) : CGFloat(0.12))
        node.childNode(withName: "studentLowerLipSoftSpecular", recursively: true)?.opacity = state == .crying || state == .anxious ? CGFloat(0.42) : CGFloat(0.14)
        node.childNode(withName: "studentJawDeskBounceContact", recursively: true)?.opacity = state == .sleeping || state == .crying || state == .studying ? CGFloat(0.42) : CGFloat(0.16)
        for index in 0..<3 {
            node.childNode(withName: "anxietySweatBead\(index)", recursively: true)?.opacity = state == .anxious || state == .covering ? CGFloat(0.3 - Double(index) * 0.04) : 0
        }
        for index in 0..<4 {
            node.childNode(withName: "studentForeheadMicroSweat\(index)", recursively: true)?.opacity = state == .anxious || state == .covering ? CGFloat(0.32 - Double(index) * 0.035) : (state == .crying ? CGFloat(0.18) : CGFloat(0.04))
        }
        node.childNode(withName: "leftHandPaperPressure", recursively: true)?.opacity = state == .studying || state == .crying ? CGFloat(0.46) : (state == .usingPhone ? CGFloat(0.18) : CGFloat(0.12))
        node.childNode(withName: "rightHandPaperPressure", recursively: true)?.opacity = state == .studying || state == .crying ? CGFloat(0.46) : (state == .usingPhone ? CGFloat(0.18) : CGFloat(0.12))
        node.childNode(withName: "handSkinDeskReflection", recursively: true)?.opacity = state == .studying ? CGFloat(0.34) : (state == .usingPhone ? CGFloat(0.24) : CGFloat(0.14))
        node.childNode(withName: "phoneThumbGlow", recursively: true)?.opacity = state == .usingPhone ? CGFloat(0.62) : 0
        for index in 0..<4 {
            node.childNode(withName: "studentFingerContactShadow\(index)", recursively: true)?.opacity = state == .studying || state == .crying ? CGFloat(0.32) : (state == .usingPhone ? CGFloat(0.22) : CGFloat(0.1))
        }
        for index in 0..<6 {
            node.childNode(withName: "studentDynamicTorsoFold\(index)", recursively: true)?.opacity = state == .anxious || state == .crying || state == .covering ? CGFloat(0.42) : CGFloat(0.22)
        }
        for index in 0..<4 {
            node.childNode(withName: "studentUniformLintCatch\(index)", recursively: true)?.opacity = state == .studying || state == .usingPhone ? CGFloat(0.22) : CGFloat(0.12)
        }
        for index in 0..<6 {
            node.childNode(withName: "studentClothSpecularLint\(index)", recursively: true)?.opacity = state == .studying || state == .usingPhone ? CGFloat(0.26) : CGFloat(0.12)
        }

        if state == .usingPhone && node.childNode(withName: "phoneGlow", recursively: true)?.action(forKey: "phone_surface_pulse") == nil {
            node.childNode(withName: "phoneGlow", recursively: true)?.opacity = 0.9
            node.childNode(withName: "phoneGlow", recursively: true)?.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.95, duration: 0.18),
                .fadeOpacity(to: 0.52, duration: 0.32)
            ])), forKey: "phone_surface_pulse")
        } else if state != .usingPhone {
            node.childNode(withName: "phoneGlow", recursively: true)?.removeAction(forKey: "phone_surface_pulse")
        }

        if state == .offeringHelp && node.childNode(withName: "supportGlow", recursively: true)?.action(forKey: "support_surface_pulse") == nil {
            node.childNode(withName: "supportGlow", recursively: true)?.opacity = 0.82
            node.childNode(withName: "supportGlow", recursively: true)?.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.82, duration: 0.42),
                .fadeOpacity(to: 0.35, duration: 0.58)
            ])), forKey: "support_surface_pulse")
        } else if state != .offeringHelp {
            node.childNode(withName: "supportGlow", recursively: true)?.removeAction(forKey: "support_surface_pulse")
        }
    }

    private func updateClassmatePose(_ classmate: Classmate, on node: SCNNode, game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let stress = (classmate.stress / 100).clamped(to: 0...1)
        let relationship = (classmate.relationship / 100).clamped(to: 0...1)
        let suspicion = (classmate.suspicionOfPlayer / 100).clamped(to: 0...1)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let isTeacherTarget = game.teacher.focusMode == .selectedStudent && game.selectedTeacherTarget?.id == classmate.id
        let isEventMate = activeEventClassmateID(game: game) == classmate.id
        let eventPressure = eventIntensity.vignette.clamped(to: 0...1)
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let pressure = (stress * 0.48 + teacherPressure * 0.22 + eventPressure * 0.18 + (isTeacherTarget ? 0.22 : 0) + (isEventMate ? 0.28 : 0)).clamped(to: 0...1)
        let phase = Float((game.currentTurn + classmate.id) % 5 - 2) * 0.006
        let pressureF = Float(pressure)
        let relationshipF = Float(relationship)
        let suspicionF = Float(suspicion)

        let body = node.childNode(withName: "bodyRoot", recursively: false)
        let head = node.childNode(withName: "head", recursively: false)
        let hair = node.childNode(withName: "hair", recursively: false)
        let leftArm = node.childNode(withName: "leftArm", recursively: true)
        let rightArm = node.childNode(withName: "rightArm", recursively: true)
        let leftForearm = node.childNode(withName: "leftForearm", recursively: true)
        let rightForearm = node.childNode(withName: "rightForearm", recursively: true)
        let leftHand = node.childNode(withName: "leftHand", recursively: true)
        let rightHand = node.childNode(withName: "rightHand", recursively: true)
        let leftLeg = node.childNode(withName: "leftLeg", recursively: true)
        let rightLeg = node.childNode(withName: "rightLeg", recursively: true)
        let leftFoot = node.childNode(withName: "leftFoot", recursively: true)
        let rightFoot = node.childNode(withName: "rightFoot", recursively: true)

        var bodyAngles = body?.eulerAngles ?? SCNVector3Zero
        var headAngles = head?.eulerAngles ?? SCNVector3Zero
        var leftArmZ: Float = 0.12
        var rightArmZ: Float = -0.12
        var leftForearmAngles = SCNVector3(0.18, 0, 0.08)
        var rightForearmAngles = SCNVector3(0.18, 0, -0.08)
        var leftHandZ: Float = 0.18
        var rightHandZ: Float = -0.18
        var leftLegAngles = SCNVector3(0.08, 0, 0.035)
        var rightLegAngles = SCNVector3(-0.08, 0, -0.035)
        var leftFootX: Float = 0
        var rightFootX: Float = 0

        bodyAngles = SCNVector3(-0.018 - pressureF * 0.045, 0, phase * 0.8)
        headAngles = SCNVector3(-0.035 - pressureF * 0.06, 0, -phase * 0.7)

        switch classmate.state {
        case .studying:
            bodyAngles.x -= 0.035
            headAngles.x -= 0.075 + pressureF * 0.035
            leftArmZ = 0.17 + pressureF * 0.04
            rightArmZ = -0.21 - pressureF * 0.04
            leftForearmAngles = SCNVector3(0.42 + pressureF * 0.08, 0, 0.12)
            rightForearmAngles = SCNVector3(0.48 + pressureF * 0.1, 0, -0.16 - phase)
            rightHandZ = -0.2 - pressureF * 0.06
        case .usingPhone:
            bodyAngles.x -= 0.18
            headAngles.x -= 0.18
            headAngles.z += phase * 0.9
            leftArmZ = -0.08
            rightArmZ = 0.08
            leftForearmAngles = SCNVector3(0.6, 0, -0.18)
            rightForearmAngles = SCNVector3(0.6, 0, 0.18)
            leftHandZ = -0.18 - pressureF * 0.05
            rightHandZ = 0.18 + pressureF * 0.05
            leftLegAngles.z = -0.08 - pressureF * 0.04
            rightLegAngles.z = 0.08 + pressureF * 0.04
        case .anxious:
            bodyAngles.z = phase * 2.2
            headAngles.x -= 0.08 + pressureF * 0.08
            headAngles.y = phase * 1.5
            leftForearmAngles = SCNVector3(0.52 + pressureF * 0.1, 0, -0.2)
            rightForearmAngles = SCNVector3(0.52 + pressureF * 0.1, 0, 0.2)
            leftHandZ = -0.04 - pressureF * 0.18
            rightHandZ = 0.04 + pressureF * 0.18
            leftLegAngles.z = 0.16 + pressureF * 0.05
            rightLegAngles.z = -0.18 - pressureF * 0.05
            rightFootX = 0.08 + pressureF * 0.08
        case .sleeping:
            bodyAngles.x = -0.5
            bodyAngles.z = phase * 0.55
            headAngles.x = -0.34
            headAngles.z = -0.08 + phase * 0.4
            leftArmZ = 0.28
            rightArmZ = -0.28
            leftForearmAngles = SCNVector3(0.82, 0, 0.14)
            rightForearmAngles = SCNVector3(0.82, 0, -0.14)
            leftLegAngles = SCNVector3(0.2, 0, -0.12)
            rightLegAngles = SCNVector3(0.12, 0, 0.08)
        case .crying:
            bodyAngles.x = -0.68 - pressureF * 0.08
            bodyAngles.z = phase * 1.4
            headAngles.x = -0.45
            headAngles.z = phase
            leftArmZ = -0.2 - pressureF * 0.08
            rightArmZ = 0.2 + pressureF * 0.08
            leftForearmAngles = SCNVector3(0.72, 0, -0.26)
            rightForearmAngles = SCNVector3(0.72, 0, 0.26)
            leftHandZ = -0.26
            rightHandZ = 0.26
            leftLegAngles.z = -0.22
            rightLegAngles.z = 0.22
        case .offeringHelp:
            let reach = 0.08 + relationshipF * 0.1
            bodyAngles.x -= 0.11
            bodyAngles.z = -reach
            headAngles.y = -0.14 - relationshipF * 0.08
            leftArmZ = -0.1 - relationshipF * 0.1
            leftForearmAngles = SCNVector3(0.36, 0, -0.32 - relationshipF * 0.12)
            leftHandZ = -0.34 - relationshipF * 0.1
            leftLegAngles.z = -0.06
        case .lookingAtPlayer:
            bodyAngles.x -= 0.04
            bodyAngles.z = phase * 0.45
            headAngles.y = ((-0.6 - node.position.x) * 0.08).clamped(to: -0.22...0.22)
            headAngles.x -= 0.025
            rightHandZ = -0.04
            rightFootX = 0.08
        case .covering:
            bodyAngles.z = 0.16 + suspicionF * 0.1
            headAngles.x -= 0.08
            headAngles.y = -0.12 - suspicionF * 0.08
            leftArmZ = -0.18
            rightArmZ = -0.26
            leftForearmAngles = SCNVector3(0.58, 0, -0.38)
            rightForearmAngles = SCNVector3(0.58, 0, -0.22 - suspicionF * 0.08)
            leftHandZ = -0.28
            rightHandZ = -0.3
        }

        if isTeacherTarget {
            let teacherGaze = ((teacherNode.position.x - node.position.x) * 0.06).clamped(to: -0.22...0.22)
            bodyAngles.z += teacherGaze * 0.18
            headAngles.y = teacherGaze
            headAngles.x -= 0.04 + pressureF * 0.04
            leftFootX += 0.04 + pressureF * 0.04
            rightFootX += 0.05 + pressureF * 0.06
        }
        if isEventMate {
            bodyAngles.x -= 0.08
            headAngles.z += phase * 1.2
            leftHandZ -= 0.06
            rightHandZ += 0.06
        }

        body?.eulerAngles = bodyAngles
        head?.eulerAngles = headAngles
        hair?.eulerAngles = SCNVector3(headAngles.x * 0.55, headAngles.y * 0.5, headAngles.z * 0.6)
        let silhouetteLayer = node.childNode(withName: "studentHeadSilhouetteDetailLayer", recursively: true)
        silhouetteLayer?.opacity = CGFloat((0.12 + pressure * 0.24 + lowLight * 0.14 + (isTeacherTarget ? 0.12 : 0) + (classmate.state == .lookingAtPlayer ? 0.08 : 0)).clamped(to: 0.08...0.62))
        silhouetteLayer?.eulerAngles = SCNVector3(headAngles.x * 0.22, headAngles.y * 0.18, headAngles.z * 0.24)
        silhouetteLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.018, 1 + CGFloat(pressure) * 0.018, 1)
        node.childNode(withName: "studentForeheadHairlineShadow", recursively: true)?.opacity = CGFloat((0.16 + pressure * 0.22 + (classmate.state == .covering ? 0.12 : 0)).clamped(to: 0.1...0.52))
        node.childNode(withName: "studentCrownRimCatch", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.18 + (classmate.state == .lookingAtPlayer || isEventMate ? 0.14 : 0)).clamped(to: 0.04...0.42))
        node.childNode(withName: "studentNeckHairCastShadow", recursively: true)?.opacity = CGFloat((0.1 + pressure * 0.22 + max(0, Double(-headAngles.x)) * 0.24).clamped(to: 0.06...0.5))
        for index in 0..<5 {
            let strand = node.childNode(withName: "studentBangCastStrand\(index)", recursively: true)
            strand?.opacity = CGFloat((0.12 + pressure * 0.16 + lowLight * 0.08 + Double(index % 2) * 0.025).clamped(to: 0.08...0.42))
            strand?.eulerAngles.z = Float(-0.18 + Double(index) * 0.09 + Double(phase) * (index % 2 == 0 ? 1.2 : -0.9))
        }
        for sideName in ["Left", "Right"] {
            node.childNode(withName: "student\(sideName)TempleFlyaway", recursively: true)?.opacity = CGFloat((0.1 + pressure * 0.18 + eventPressure * 0.08).clamped(to: 0.06...0.38))
            node.childNode(withName: "student\(sideName)EarWarmRim", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.12 + pressure * 0.08 + (classmate.state == .crying ? 0.12 : 0)).clamped(to: 0.04...0.34))
            node.childNode(withName: "student\(sideName)EarHairOcclusion", recursively: true)?.opacity = CGFloat((0.08 + pressure * 0.14 + (isTeacherTarget ? 0.08 : 0)).clamped(to: 0.04...0.36))
        }
        leftArm?.eulerAngles.z = leftArmZ
        rightArm?.eulerAngles.z = rightArmZ
        leftForearm?.eulerAngles = leftForearmAngles
        rightForearm?.eulerAngles = rightForearmAngles
        leftHand?.eulerAngles.z = leftHandZ
        rightHand?.eulerAngles.z = rightHandZ
        leftLeg?.eulerAngles = leftLegAngles
        rightLeg?.eulerAngles = rightLegAngles
        leftFoot?.eulerAngles.x = leftFootX
        rightFoot?.eulerAngles.x = rightFootX

        let playerGaze = ((-0.6 - node.position.x) * 0.012).clamped(to: -0.006...0.006)
        let teacherGaze = ((teacherNode.position.x - node.position.x) * 0.01).clamped(to: -0.007...0.007)
        let gazeX: Float
        if isTeacherTarget {
            gazeX = teacherGaze
        } else if classmate.state == .lookingAtPlayer || classmate.state == .offeringHelp || isEventMate {
            gazeX = playerGaze
        } else if classmate.state == .usingPhone {
            gazeX = phase * 0.18
        } else {
            gazeX = phase * 0.12
        }
        let gazeDrop: Float = classmate.state == .usingPhone || classmate.state == .studying ? -0.004 : (pressureF > 0.65 ? -0.002 : 0)
        node.childNode(withName: "leftPupil", recursively: true)?.position = SCNVector3(-0.052 + gazeX, 0.032 + gazeDrop, -0.157)
        node.childNode(withName: "rightPupil", recursively: true)?.position = SCNVector3(0.052 + gazeX, 0.032 + gazeDrop, -0.157)
        node.childNode(withName: "leftEyeHighlight", recursively: true)?.position = SCNVector3(-0.048 + gazeX * 0.6, 0.037 + gazeDrop * 0.4, -0.164)
        node.childNode(withName: "rightEyeHighlight", recursively: true)?.position = SCNVector3(0.056 + gazeX * 0.6, 0.037 + gazeDrop * 0.4, -0.164)

        let headMotionLayer = node.childNode(withName: "studentHeadMotionFidelityLayer", recursively: true)
        let gazeIntensity = Double(abs(gazeX) * 18).clamped(to: 0...0.28)
        let phoneFace = classmate.state == .usingPhone ? 1.0 : 0.0
        let cryingFace = classmate.state == .crying ? 1.0 : 0.0
        let anxiousFace = classmate.state == .anxious || classmate.state == .covering || isTeacherTarget ? 1.0 : 0.0
        let headDrop = Double(max(0, -headAngles.x)).clamped(to: 0...0.8)
        headMotionLayer?.opacity = CGFloat((0.08 + pressure * 0.24 + eventPressure * 0.12 + lowLight * 0.08 + gazeIntensity + cryingFace * 0.08 + phoneFace * 0.06).clamped(to: 0.05...0.68))
        headMotionLayer?.eulerAngles = SCNVector3(headAngles.x * -0.08, headAngles.y * -0.12 + phase * 0.5, headAngles.z * -0.16)
        headMotionLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.018, 1 + CGFloat(headDrop) * 0.025, 1)
        node.childNode(withName: "studentMotionBrowClampShadow", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.24 + anxiousFace * 0.18 + (isTeacherTarget ? 0.08 : 0)).clamped(to: 0.03...0.54))
        node.childNode(withName: "studentMotionNoseBridgeCatch", recursively: true)?.opacity = CGFloat((0.05 + lowLight * 0.1 + cryingFace * 0.12 + phoneFace * 0.08 + relationship * 0.04).clamped(to: 0.02...0.32))
        node.childNode(withName: "studentMotionChinDropShadow", recursively: true)?.opacity = CGFloat((0.06 + headDrop * 0.32 + pressure * 0.14 + cryingFace * 0.16).clamped(to: 0.03...0.5))
        node.childNode(withName: "studentMotionHeadTurnSmear", recursively: true)?.opacity = CGFloat((0.03 + gazeIntensity * 0.7 + eventPressure * 0.08 + anxiousFace * 0.08).clamped(to: 0.01...0.28))
        node.childNode(withName: "studentMotionHeadTurnSmear", recursively: true)?.position.x = gazeX * -1.8
        for index in 0..<6 {
            let lag = node.childNode(withName: "studentMotionBangLag\(index)", recursively: true)
            lag?.opacity = CGFloat((0.06 + pressure * 0.12 + lowLight * 0.08 + headDrop * 0.12 + Double(index % 2) * 0.02).clamped(to: 0.03...0.34))
            lag?.eulerAngles.z = Float(-0.18 + Double(index) * 0.072 - Double(headAngles.y) * 0.42 + Double(phase) * (index % 2 == 0 ? 1.0 : -0.8))
        }
        for sideName in ["Left", "Right"] {
            let sideFactor = sideName == "Left" ? -1.0 : 1.0
            let temple = node.childNode(withName: "studentMotion\(sideName)TempleLag", recursively: true)
            temple?.opacity = CGFloat((0.06 + pressure * 0.14 + eventPressure * 0.08 + anxiousFace * 0.08).clamped(to: 0.03...0.36))
            temple?.eulerAngles.z = Float(sideFactor * (0.34 + Double(headAngles.y) * 0.3) + Double(phase) * 0.6)
            let scan = node.childNode(withName: "studentMotion\(sideName)EyeMicroScan", recursively: true)
            scan?.opacity = CGFloat((0.03 + gazeIntensity * 0.9 + phoneFace * 0.16 + anxiousFace * 0.12 + lowLight * 0.08).clamped(to: 0.01...0.42))
            scan?.position.x = Float(sideFactor * 0.052) + gazeX * 0.7
            node.childNode(withName: "studentMotion\(sideName)CheekTensionSheen", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.12 + cryingFace * 0.18 + anxiousFace * 0.08).clamped(to: 0.02...0.34))
        }

        let hairMaterialLayer = node.childNode(withName: "studentHairCinematicMaterialLayer", recursively: true)
        let teacherTargetHair = isTeacherTarget ? 1.0 : 0.0
        let hairMotion = (pressure * 0.24 + headDrop * 0.18 + gazeIntensity * 0.5 + eventPressure * 0.12 + (isTeacherTarget ? 0.12 : 0)).clamped(to: 0...0.7)
        hairMaterialLayer?.opacity = CGFloat((0.08 + lowLight * 0.12 + hairMotion + cryingFace * 0.06 + phoneFace * 0.04).clamped(to: 0.05...0.62))
        hairMaterialLayer?.eulerAngles = SCNVector3(headAngles.x * -0.055, headAngles.y * -0.08 + phase * 0.36, headAngles.z * -0.07)
        hairMaterialLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.012, 1 + CGFloat(headDrop) * 0.018, 1)
        node.childNode(withName: "studentHairCinematicPartLine", recursively: true)?.opacity = CGFloat((0.08 + pressure * 0.2 + lowLight * 0.1 + teacherTargetHair * 0.08).clamped(to: 0.04...0.42))
        node.childNode(withName: "studentHairCinematicCrownOilSheen", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.16 + phoneFace * 0.08 + eventPressure * 0.08 + (classmate.state == .studying ? 0.06 : 0)).clamped(to: 0.02...0.32))
        for index in 0..<8 {
            let fiber = node.childNode(withName: "studentHairCinematicFrontFiber\(index)", recursively: true)
            fiber?.opacity = CGFloat((0.04 + lowLight * 0.1 + pressure * 0.1 + headDrop * 0.12 + Double(index % 3) * 0.014).clamped(to: 0.02...0.34))
            fiber?.eulerAngles.z = Float(-0.24 + Double(index) * 0.07 - Double(headAngles.y) * 0.34 + Double(phase) * (index % 2 == 0 ? 1.1 : -0.85))
        }
        for sideName in ["Left", "Right"] {
            let sideFactor = sideName == "Left" ? -1.0 : 1.0
            for index in 0..<4 {
                let flyaway = node.childNode(withName: "studentHairCinematic\(sideName)Flyaway\(index)", recursively: true)
                flyaway?.opacity = CGFloat((0.04 + pressure * 0.12 + eventPressure * 0.08 + lowLight * 0.08 + Double(index % 2) * 0.018).clamped(to: 0.02...0.32))
                flyaway?.eulerAngles.z = Float(sideFactor * (0.32 + Double(index) * 0.08 + Double(headAngles.y) * 0.28) + Double(phase) * 0.7)
            }
            node.childNode(withName: "studentHairCinematic\(sideName)TempleOilCatch", recursively: true)?.opacity = CGFloat((0.03 + lowLight * 0.12 + phoneFace * 0.08 + pressure * 0.08).clamped(to: 0.01...0.26))
            node.childNode(withName: "studentHairCinematic\(sideName)EarCastShadow", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.16 + headDrop * 0.08 + teacherTargetHair * 0.08).clamped(to: 0.03...0.38))
        }
        node.childNode(withName: "studentHairCinematicNapeSoftMass", recursively: true)?.opacity = CGFloat((0.08 + headDrop * 0.22 + pressure * 0.12 + lowLight * 0.08).clamped(to: 0.04...0.42))
        node.childNode(withName: "studentHairCinematicRearCoolRim", recursively: true)?.opacity = CGFloat((0.03 + lowLight * 0.18 + eventPressure * 0.08 + (classmate.state == .lookingAtPlayer ? 0.08 : 0)).clamped(to: 0.01...0.3))

        let lidOpacity: CGFloat
        switch classmate.state {
        case .sleeping:
            lidOpacity = 0.78
        case .crying:
            lidOpacity = 0.52
        case .anxious:
            lidOpacity = CGFloat((0.34 + pressure * 0.24).clamped(to: 0.34...0.72))
        case .usingPhone:
            lidOpacity = 0.35
        default:
            lidOpacity = CGFloat((0.12 + pressure * 0.18).clamped(to: 0.12...0.42))
        }
        node.childNode(withName: "leftUpperLid", recursively: true)?.opacity = lidOpacity
        node.childNode(withName: "rightUpperLid", recursively: true)?.opacity = lidOpacity

        let browPressure = CGFloat(pressure * 0.18 + suspicion * 0.08)
        node.childNode(withName: "leftBrow", recursively: true)?.eulerAngles.z = CGFloat.pi / 2 - browPressure
        node.childNode(withName: "rightBrow", recursively: true)?.eulerAngles.z = CGFloat.pi / 2 + browPressure

        let blinkPulse = Double((game.currentTurn + classmate.id) % 7 == 0 ? 1.0 : 0.0)
        let faceDetailLayer = node.childNode(withName: "studentCloseupFaceDetailLayer", recursively: true)
        faceDetailLayer?.opacity = CGFloat((0.1 + pressure * 0.24 + lowLight * 0.1 + (isTeacherTarget ? 0.12 : 0) + (classmate.state == .crying ? 0.16 : 0)).clamped(to: 0.06...0.64))
        faceDetailLayer?.eulerAngles.z = CGFloat(phase * 0.45)
        let blinkOpacity = (0.02 + blinkPulse * 0.62 + (classmate.state == .sleeping ? 0.72 : 0) + (classmate.state == .crying ? 0.1 : 0)).clamped(to: 0...0.82)
        node.childNode(withName: "studentLeftBlinkCurtain", recursively: true)?.opacity = CGFloat(blinkOpacity)
        node.childNode(withName: "studentRightBlinkCurtain", recursively: true)?.opacity = CGFloat((blinkOpacity + (classmate.state == .anxious ? 0.04 : 0)).clamped(to: 0...0.86))
        node.childNode(withName: "studentLeftBlinkCurtain", recursively: true)?.position.y = Float(0.034 - blinkOpacity * 0.012)
        node.childNode(withName: "studentRightBlinkCurtain", recursively: true)?.position.y = Float(0.034 - blinkOpacity * 0.012)
        node.childNode(withName: "studentLeftLowerLidCrease", recursively: true)?.opacity = CGFloat((0.08 + pressure * 0.22 + (classmate.state == .crying ? 0.18 : 0) + (isTeacherTarget ? 0.1 : 0)).clamped(to: 0.04...0.5))
        node.childNode(withName: "studentRightLowerLidCrease", recursively: true)?.opacity = CGFloat((0.08 + pressure * 0.2 + (classmate.state == .crying ? 0.16 : 0) + (classmate.state == .usingPhone ? 0.08 : 0)).clamped(to: 0.04...0.48))
        node.childNode(withName: "studentNoseTipSpecular", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.12 + relationship * 0.06 + (classmate.state == .crying ? 0.12 : 0)).clamped(to: 0.04...0.36))
        node.childNode(withName: "studentLeftCheekMicroSheen", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.16 + (classmate.state == .crying || classmate.state == .anxious ? 0.16 : 0)).clamped(to: 0.03...0.42))
        node.childNode(withName: "studentRightCheekMicroSheen", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.14 + (classmate.state == .crying ? 0.14 : 0)).clamped(to: 0.03...0.38))
        node.childNode(withName: "studentLeftMouthCornerTwitch", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.22 + (classmate.state == .covering || classmate.state == .crying ? 0.18 : 0)).clamped(to: 0.03...0.5))
        node.childNode(withName: "studentRightMouthCornerTwitch", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.2 + (classmate.state == .anxious || isTeacherTarget ? 0.16 : 0)).clamped(to: 0.03...0.48))
        node.childNode(withName: "studentPhoneEyeCatchPlane", recursively: true)?.opacity = CGFloat((classmate.state == .usingPhone ? 0.32 + lowLight * 0.22 + pressure * 0.08 : 0).clamped(to: 0...0.62))
        node.childNode(withName: "studentChinTensionContact", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.18 + (classmate.state == .studying || classmate.state == .crying ? 0.12 : 0)).clamped(to: 0.03...0.42))
        let facialLayer = node.childNode(withName: "studentFacialCinematicFidelityLayer", recursively: true)
        facialLayer?.opacity = CGFloat((0.1 + pressure * 0.28 + lowLight * 0.12 + phoneFace * 0.12 + cryingFace * 0.2 + anxiousFace * 0.12 + (isEventMate ? 0.1 : 0)).clamped(to: 0.06...0.72))
        facialLayer?.eulerAngles = SCNVector3(headAngles.x * -0.04, headAngles.y * -0.06 + phase * 0.28, headAngles.z * -0.05)
        for sideName in ["Left", "Right"] {
            let sideMultiplier = sideName == "Left" ? -1.0 : 1.0
            node.childNode(withName: "student\(sideName)SkinSubsurfaceBloom", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.12 + cryingFace * 0.16 + anxiousFace * 0.08 + relationship * 0.08).clamped(to: 0.03...0.42))
            node.childNode(withName: "student\(sideName)CorneaGlassCatch", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.16 + cryingFace * 0.32 + phoneFace * 0.18 + gazeIntensity * 0.5 + (classmate.state == .sleeping ? -0.08 : 0)).clamped(to: 0.02...0.68))
            node.childNode(withName: "student\(sideName)CorneaGlassCatch", recursively: true)?.position.x = Float(sideMultiplier * 0.052) + gazeX * 0.55
            node.childNode(withName: "student\(sideName)InnerEyeWetCorner", recursively: true)?.opacity = CGFloat((0.06 + pressure * 0.18 + cryingFace * 0.42 + anxiousFace * 0.12).clamped(to: 0.02...0.7))
            node.childNode(withName: "student\(sideName)UnderEyeFatiguePlane", recursively: true)?.opacity = CGFloat((0.08 + pressure * 0.2 + lowLight * 0.1 + cryingFace * 0.18 + (isTeacherTarget ? 0.12 : 0)).clamped(to: 0.04...0.54))
            node.childNode(withName: "student\(sideName)NostrilOcclusion", recursively: true)?.opacity = CGFloat((0.08 + headDrop * 0.18 + pressure * 0.12 + anxiousFace * 0.08).clamped(to: 0.04...0.38))
            node.childNode(withName: "student\(sideName)EarSubsurfacePulse", recursively: true)?.opacity = CGFloat((0.05 + pressure * 0.14 + cryingFace * 0.12 + lowLight * 0.08).clamped(to: 0.02...0.34))
        }
        for index in 0..<7 {
            node.childNode(withName: "studentForeheadPoreCatch\(index)", recursively: true)?.opacity = CGFloat((0.035 + lowLight * 0.08 + pressure * 0.08 + Double(index % 3) * 0.012).clamped(to: 0.015...0.26))
        }
        for index in 0..<4 {
            let sweat = node.childNode(withName: "studentForeheadMicroSweat\(index)", recursively: true)
            sweat?.opacity = CGFloat((pressure * 0.18 + anxiousFace * 0.2 + cryingFace * 0.1 + eventPressure * 0.08 - Double(index) * 0.035).clamped(to: 0...0.48))
            sweat?.position.y = Float(0.052 - Double(index % 2) * 0.018 - pressure * 0.006)
        }
        node.childNode(withName: "studentUpperLipWetRim", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.18 + cryingFace * 0.24 + anxiousFace * 0.14 + (classmate.state == .covering ? 0.16 : 0)).clamped(to: 0.02...0.54))
        node.childNode(withName: "studentLowerLipSoftSpecular", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.16 + cryingFace * 0.22 + phoneFace * 0.08).clamped(to: 0.02...0.48))
        node.childNode(withName: "studentJawDeskBounceContact", recursively: true)?.opacity = CGFloat((0.06 + headDrop * 0.28 + pressure * 0.12 + cryingFace * 0.14 + (classmate.state == .studying ? 0.1 : 0)).clamped(to: 0.03...0.48))
        node.childNode(withName: "studentThroatBreathShadowCinematic", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.16 + headDrop * 0.12 + (classmate.state == .sleeping ? 0.12 : 0)).clamped(to: 0.02...0.36))
        node.childNode(withName: "studentMouthSoftnessColorShift", recursively: true)?.opacity = CGFloat((0.04 + relationship * 0.16 + cryingFace * 0.12 + (classmate.state == .offeringHelp ? 0.18 : 0)).clamped(to: 0.02...0.42))
        let skinEyeLayer = node.childNode(withName: "studentSkinEyeMicroMaterialLayer", recursively: true)
        skinEyeLayer?.opacity = CGFloat((0.06 + pressure * 0.22 + lowLight * 0.1 + cryingFace * 0.2 + phoneFace * 0.1 + anxiousFace * 0.08 + gazeIntensity * 0.28).clamped(to: 0.04...0.66))
        skinEyeLayer?.eulerAngles = SCNVector3(headAngles.x * -0.035, headAngles.y * -0.045 + phase * 0.2, headAngles.z * -0.04)
        for sideName in ["Left", "Right"] {
            let sideMultiplier = sideName == "Left" ? -1.0 : 1.0
            node.childNode(withName: "student\(sideName)TearFilmMeniscus", recursively: true)?.opacity = CGFloat((0.05 + pressure * 0.14 + cryingFace * 0.38 + lowLight * 0.08 + gazeIntensity * 0.18).clamped(to: 0.02...0.62))
            node.childNode(withName: "student\(sideName)TearFilmMeniscus", recursively: true)?.position.x = Float(sideMultiplier * 0.052) + gazeX * 0.42
            node.childNode(withName: "student\(sideName)ScleraWetGlaze", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.12 + cryingFace * 0.24 + phoneFace * 0.16 + gazeIntensity * 0.22 + (classmate.state == .sleeping ? -0.06 : 0)).clamped(to: 0.01...0.48))
            node.childNode(withName: "student\(sideName)ScleraWetGlaze", recursively: true)?.position.x = Float(sideMultiplier * 0.052) + gazeX * 0.58
            node.childNode(withName: "student\(sideName)LowerLidWaterline", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.16 + cryingFace * 0.34 + anxiousFace * 0.08).clamped(to: 0.01...0.52))
            node.childNode(withName: "student\(sideName)CheekPoreCluster", recursively: true)?.opacity = CGFloat((0.035 + pressure * 0.1 + lowLight * 0.06 + cryingFace * 0.12).clamped(to: 0.015...0.28))
            node.childNode(withName: "student\(sideName)CheekTearSaltTrace", recursively: true)?.opacity = CGFloat((cryingFace * (0.18 + pressure * 0.18 + lowLight * 0.08)).clamped(to: 0...0.44))
            node.childNode(withName: "student\(sideName)EarBackTranslucency", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.1 + pressure * 0.1 + teacherFreezeRead * 0.08).clamped(to: 0.02...0.3))
            node.childNode(withName: "student\(sideName)NeckTendonMicroShadow", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.2 + anxiousFace * 0.14 + teacherFreezeRead * 0.18 + headDrop * 0.12).clamped(to: 0.02...0.48))
        }
        for index in 0..<12 {
            node.childNode(withName: "studentSkinMicroPore\(index)", recursively: true)?.opacity = CGFloat((0.02 + lowLight * 0.05 + pressure * 0.06 + Double(index % 3) * 0.008).clamped(to: 0.01...0.18))
        }
        node.childNode(withName: "studentNoseWingOilSpecular", recursively: true)?.opacity = CGFloat((0.04 + lowLight * 0.14 + cryingFace * 0.12 + phoneFace * 0.1 + pressure * 0.08).clamped(to: 0.02...0.36))
        node.childNode(withName: "studentPhiltrumMicroShadow", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.18 + anxiousFace * 0.1 + cryingFace * 0.08).clamped(to: 0.02...0.34))
        for index in 0..<3 {
            node.childNode(withName: "studentLipDryCrack\(index)", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.12 + anxiousFace * 0.12 + cryingFace * 0.1 - Double(index) * 0.015).clamped(to: 0.01...0.32))
        }
        node.childNode(withName: "studentPhoneBlueSkinBounce", recursively: true)?.opacity = CGFloat((phoneFace * (0.18 + lowLight * 0.24 + suspicion * 0.1 + pressure * 0.08)).clamped(to: 0...0.5))
        node.childNode(withName: "studentIdCard", recursively: true)?.eulerAngles.z = CGFloat(phase * 1.8)
