            fiber?.eulerAngles.z = Float(-0.28 + Double(index) * 0.09 - Double(headAngles.y) * 0.28 + Double(phase) * (index % 2 == 0 ? 0.9 : -0.7))
        }
        for index in 0..<6 {
            let catchNode = node.childNode(withName: "studentHeroFocusUniformMicroCatch\(index)", recursively: true)
            catchNode?.opacity = CGFloat((0.03 + studyHand * 0.12 + phoneHand * 0.08 + lowLight * 0.08 + directFocus * 0.08 + Double(index % 3) * 0.012).clamped(to: 0.01...0.28))
            catchNode?.position.y = Float(0.518 - Double(index % 2) * 0.052 + pressure * 0.004)
        }
        for index in 0..<4 {
            let dust = node.childNode(withName: "studentHeroFocusBreathDust\(index)", recursively: true)
            dust?.opacity = CGFloat((0.02 + lowLight * 0.12 + sleepingHand * 0.1 + cryingHand * 0.08 + directFocus * 0.06 - Double(index) * 0.012).clamped(to: 0.005...0.22))
            dust?.position.y = Float(0.78 + Double(index % 2) * 0.065 + lowLight * 0.012) + sin(phase * 6.0 + Float(index)) * 0.004
        }

        let performanceLayer = node.childNode(withName: "studentPerformanceDirectorLayer", recursively: false)
        let performanceRead = (readableFocus * 0.44 + deskActionRead * 0.22 + teacherFreezeRead * 0.28 + directFocus * 0.22 + pressure * 0.18 + lowLight * 0.06).clamped(to: 0...0.96)
        let performanceBreath = (0.12 + pressure * 0.22 + sleepingHand * 0.18 + cryingHand * 0.16 + anxiousRead * 0.18 + teacherFreezeRead * 0.14).clamped(to: 0.08...0.72)
        performanceLayer?.opacity = CGFloat((0.07 + performanceRead + eventPressure * 0.06).clamped(to: 0.05...0.92))
        performanceLayer?.position.y = Float(pressure * 0.004 + directFocus * 0.005 - sleepingHand * 0.006)
        performanceLayer?.eulerAngles = SCNVector3(headAngles.x * -0.012, headAngles.y * -0.035 + phase * 0.32, headAngles.z * -0.04)
        performanceLayer?.scale = SCNVector3(1 + CGFloat(directFocus) * 0.018, 1 + CGFloat(performanceBreath) * 0.024, 1)
        node.childNode(withName: "studentPerformanceSpineLoadLine", recursively: true)?.opacity = CGFloat((0.06 + forwardLean * 0.28 + pressure * 0.18 + teacherFreezeRead * 0.14).clamped(to: 0.03...0.5))
        node.childNode(withName: "studentPerformanceSpineLoadLine", recursively: true)?.eulerAngles.z = CGFloat(Double(bodyAngles.z) * -0.42 + Double(phase) * 1.2)
        node.childNode(withName: "studentPerformanceBreathVolume", recursively: true)?.opacity = CGFloat((0.04 + performanceBreath * 0.34 + lowLight * 0.06).clamped(to: 0.02...0.42))
        node.childNode(withName: "studentPerformanceBreathVolume", recursively: true)?.position.y = Float(0.58 + performanceBreath * 0.012 - sleepingHand * 0.008)
        node.childNode(withName: "studentPerformanceThroatLock", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.22 + anxiousRead * 0.16 + teacherFreezeRead * 0.18 + cryingHand * 0.08).clamped(to: 0.02...0.48))
        node.childNode(withName: "studentPerformanceGazeAnchor", recursively: true)?.opacity = CGFloat((0.02 + gazeMotion * 0.24 + directFocus * 0.22 + teacherFreezeRead * 0.18 + phoneHand * 0.06).clamped(to: 0...0.52))
        node.childNode(withName: "studentPerformanceGazeAnchor", recursively: true)?.position.x = gazeX * 1.35
        node.childNode(withName: "studentPerformanceTeacherFreezePlane", recursively: true)?.opacity = CGFloat((0.02 + teacherFreezeRead * 0.36 + eventPressure * 0.08 + pressure * 0.08).clamped(to: 0.01...0.54))
        node.childNode(withName: "studentPerformanceTeacherFreezePlane", recursively: true)?.scale = SCNVector3(1 + CGFloat(teacherFreezeRead) * 0.08, 1 + CGFloat(pressure) * 0.05, 1)
        node.childNode(withName: "studentPerformanceStudyWristTrace", recursively: true)?.opacity = CGFloat((studyHand * (0.2 + pressure * 0.22 + eventPressure * 0.08)).clamped(to: 0...0.56))
        node.childNode(withName: "studentPerformanceStudyWristTrace", recursively: true)?.eulerAngles.y = CGFloat(-0.2 + Double(phase) * 3.1)
        node.childNode(withName: "studentPerformancePhoneGuardGlow", recursively: true)?.opacity = CGFloat((phoneHand * (0.26 + lowLight * 0.24 + suspicion * 0.18 + teacherFreezeRead * 0.14)).clamped(to: 0...0.7))
        node.childNode(withName: "studentPerformancePhoneGuardGlow", recursively: true)?.position.y = Float(0.234 + phoneHand * 0.006 + teacherFreezeRead * 0.004)
        node.childNode(withName: "studentPerformanceHelpReachSpace", recursively: true)?.opacity = CGFloat((offerMotion * (0.28 + relationship * 0.32) + eventMateMotion * 0.08).clamped(to: 0...0.62))
        node.childNode(withName: "studentPerformanceHelpReachSpace", recursively: true)?.eulerAngles.z = CGFloat(-0.9 - relationship * 0.14 + Double(phase) * 0.7)
        node.childNode(withName: "studentPerformanceShoulderCollapse", recursively: true)?.opacity = CGFloat(((cryingHand * 0.3 + sleepingHand * 0.16 + pressure * 0.12 + coverHand * 0.08).clamped(to: 0...0.52)))
        node.childNode(withName: "studentPerformanceShoulderCollapse", recursively: true)?.position.y = Float(0.67 - cryingHand * 0.018 - sleepingHand * 0.012)
        node.childNode(withName: "studentPerformanceSleepWeightPool", recursively: true)?.opacity = CGFloat(((sleepingHand * 0.28 + cryingHand * 0.14 + deskCompression * 0.12).clamped(to: 0...0.48)))
        node.childNode(withName: "studentPerformanceSleepWeightPool", recursively: true)?.scale = SCNVector3(1 + CGFloat(sleepingHand + cryingHand) * 0.12, 1, 1 + CGFloat(deskCompression) * 0.06)
        for sideName in ["Left", "Right"] {
            let sideFactor: Float = sideName == "Left" ? -1 : 1
            let sideAction = sideName == "Left" ? coverHand + cryingHand * 0.72 + offerMotion * 0.68 + teacherFreezeRead * 0.22 : studyHand + phoneHand + teacherFreezeRead * 0.48 + anxiousRead * 0.18
            node.childNode(withName: "studentPerformance\(sideName)ShoulderCatch", recursively: true)?.opacity = CGFloat((0.04 + pressure * 0.18 + sideAction * 0.16 + lowLight * 0.08).clamped(to: 0.02...0.46))
            node.childNode(withName: "studentPerformance\(sideName)ShoulderCatch", recursively: true)?.eulerAngles.z = CGFloat(Double(sideFactor) * (0.78 + sideAction * 0.12) + Double(phase) * 0.9)
            node.childNode(withName: "studentPerformance\(sideName)WristIntent", recursively: true)?.opacity = CGFloat((0.03 + sideAction * 0.2 + deskCompression * 0.12 + pressure * 0.06).clamped(to: 0.01...0.42))
            node.childNode(withName: "studentPerformance\(sideName)WristIntent", recursively: true)?.position.y = Float(0.232 + sideAction * 0.004 + eventPressure * 0.002)
            for fingerIndex in 0..<3 {
                let beat = node.childNode(withName: "studentPerformance\(sideName)FingerBeat\(fingerIndex)", recursively: true)
                beat?.opacity = CGFloat((0.02 + sideAction * 0.14 + anxiousRead * 0.1 + pressure * 0.06 - Double(fingerIndex) * 0.015).clamped(to: 0.005...0.34))
                beat?.position.x = sideFactor * Float(0.09 + Double(fingerIndex) * 0.035 + sideAction * 0.006)
                beat?.position.y = Float(0.224 + sideAction * 0.003) + sin(phase * 4.8 + Float(fingerIndex)) * 0.0014
            }
        }
        for index in 0..<4 {
            let stillness = node.childNode(withName: "studentPerformanceStillnessSlice\(index)", recursively: true)
            stillness?.opacity = CGFloat((0.015 + teacherFreezeRead * 0.2 + eventPressure * 0.08 + pressure * 0.06 - Double(index) * 0.012).clamped(to: 0.005...0.28))
            stillness?.eulerAngles.z = CGFloat(Double(index - 1) * 0.018 + Double(phase) * 0.8)
        }

        let actingLayer = node.childNode(withName: "studentActingContinuityLayer", recursively: false)
        let actingRead = (studyHand * 0.22 + phoneHand * 0.22 + coverHand * 0.2 + cryingHand * 0.26 + sleepingHand * 0.14 + offerMotion * 0.22 + gazeMotion * 0.18 + anxiousRead * 0.18 + teacherFreezeRead * 0.24 + directFocus * 0.16).clamped(to: 0...0.96)
        let followThrough = (deskCompression * 0.22 + forwardLean * 0.2 + pressure * 0.18 + actingRead * 0.28 + eventPressure * 0.08).clamped(to: 0...0.92)
        actingLayer?.opacity = CGFloat((0.04 + actingRead + lowLight * 0.06).clamped(to: 0.035...0.88))
        actingLayer?.position.y = Float(pressure * 0.003 + directFocus * 0.004 - sleepingHand * 0.006 - cryingHand * 0.005)
        actingLayer?.eulerAngles = SCNVector3(headAngles.x * -0.012, headAngles.y * -0.032 + phase * 0.28, headAngles.z * -0.036 + Float(teacherFreezeRead * 0.012 - coverHand * 0.01))
        actingLayer?.scale = SCNVector3(1 + CGFloat(eventPressure) * 0.014 + CGFloat(directFocus) * 0.012, 1 + CGFloat(followThrough) * 0.018, 1)

        let rootWeight = node.childNode(withName: "studentActingRootWeightPendulum", recursively: true)
        rootWeight?.opacity = CGFloat((0.035 + seatedWeight * 0.28 + followThrough * 0.2 + anxiousRead * 0.12 + teacherFreezeRead * 0.12).clamped(to: 0.015...0.52))
        rootWeight?.position.x = Float((phoneHand - offerMotion * 0.6 + Double(headAngles.y) * 0.12) * 0.018)
        rootWeight?.position.y = Float(0.128 - seatedWeight * 0.004 - cryingHand * 0.004)
        rootWeight?.eulerAngles.y = CGFloat(Double(phase) * 1.1 + phoneHand * 0.08 - coverHand * 0.06 + teacherFreezeRead * -0.04)

        let deskRecoil = node.childNode(withName: "studentActingDeskContactRecoil", recursively: true)
        deskRecoil?.opacity = CGFloat((0.03 + deskLoad * 0.32 + studyHand * 0.12 + phoneHand * 0.08 + cryingHand * 0.14 + sleepingHand * 0.12).clamped(to: 0.015...0.52))
        deskRecoil?.position.z = Float(-0.292 - forwardLean * 0.018)
        deskRecoil?.scale = SCNVector3(1 + CGFloat(deskLoad) * 0.08, 1, 1 + CGFloat(followThrough) * 0.04)

        node.childNode(withName: "studentActingTorsoFollowThrough", recursively: true)?.opacity = CGFloat((0.03 + forwardLean * 0.26 + pressure * 0.16 + followThrough * 0.12 + teacherFreezeRead * 0.1).clamped(to: 0.015...0.48))
        node.childNode(withName: "studentActingTorsoFollowThrough", recursively: true)?.eulerAngles.z = CGFloat(Double(bodyAngles.z) * -0.36 + Double(phase) * 0.85 + coverHand * 0.06 - phoneHand * 0.04)
        node.childNode(withName: "studentActingHeadLagContour", recursively: true)?.opacity = CGFloat((0.018 + gazeMotion * 0.22 + teacherFreezeRead * 0.22 + eventMateMotion * 0.12 + abs(Double(headAngles.y)) * 0.36).clamped(to: 0.008...0.48))
        node.childNode(withName: "studentActingHeadLagContour", recursively: true)?.position.x = gazeX * 1.2 - headAngles.y * 0.045
        node.childNode(withName: "studentActingTeacherFreezeHold", recursively: true)?.opacity = CGFloat((teacherFreezeRead * (0.3 + pressure * 0.16) + eventMateMotion * 0.08).clamped(to: 0...0.58))
        node.childNode(withName: "studentActingTeacherFreezeHold", recursively: true)?.scale = SCNVector3(1 + CGFloat(teacherFreezeRead) * 0.12, 1 + CGFloat(pressure) * 0.05, 1)

        for sideName in ["Left", "Right"] {
            let sideFactor: Float = sideName == "Left" ? -1 : 1
            let sideBias = sideName == "Left" ? 0.94 : 1.0
            let sideAct = sideName == "Left" ? coverHand + cryingHand * 0.72 + offerMotion * 0.7 + teacherFreezeRead * 0.2 : studyHand + phoneHand + anxiousRead * 0.18 + teacherFreezeRead * 0.42
            node.childNode(withName: "studentActing\(sideName)ShoulderCounterSwing", recursively: true)?.opacity = CGFloat((0.035 + pressure * 0.14 + sideAct * 0.18 + followThrough * 0.08 + lowLight * 0.06).clamped(to: 0.015...0.44) * sideBias)
            node.childNode(withName: "studentActing\(sideName)ShoulderCounterSwing", recursively: true)?.eulerAngles.z = CGFloat(Double(sideFactor) * (0.72 + sideAct * 0.12) + Double(phase) * 0.8)
            node.childNode(withName: "studentActing\(sideName)ElbowArc", recursively: true)?.opacity = CGFloat((0.02 + sideAct * 0.24 + deskCompression * 0.1 + pressure * 0.06).clamped(to: 0.005...0.48) * sideBias)
            node.childNode(withName: "studentActing\(sideName)ElbowArc", recursively: true)?.position.y = Float(0.31 + sideAct * 0.008 - deskCompression * 0.004)
            node.childNode(withName: "studentActing\(sideName)ElbowArc", recursively: true)?.eulerAngles.z = CGFloat(Double(sideFactor) * -0.72 + Double(phase) * 1.1)
            for fingerIndex in 0..<3 {
                let release = node.childNode(withName: "studentActing\(sideName)FingerRelease\(fingerIndex)", recursively: true)
                release?.opacity = CGFloat((0.02 + sideAct * 0.13 + anxiousRead * 0.08 + pressure * 0.06 - Double(fingerIndex) * 0.014).clamped(to: 0.005...0.32) * sideBias)
                release?.position.x = sideFactor * Float(0.09 + Double(fingerIndex) * 0.035 + sideAct * 0.006)
                release?.position.y = Float(0.232 + sideAct * 0.003) + sin(phase * 4.6 + Float(fingerIndex)) * 0.0014
            }
        }

        node.childNode(withName: "studentActingStudyStrokePath", recursively: true)?.opacity = CGFloat((studyHand * (0.24 + pressure * 0.18 + eventPressure * 0.08)).clamped(to: 0...0.58))
        node.childNode(withName: "studentActingStudyStrokePath", recursively: true)?.eulerAngles.z = CGFloat(-0.88 + Double(phase) * 2.7)
        node.childNode(withName: "studentActingPhoneHidePath", recursively: true)?.opacity = CGFloat((phoneHand * (0.28 + lowLight * 0.22 + suspicion * 0.18 + teacherFreezeRead * 0.12)).clamped(to: 0...0.7))
        node.childNode(withName: "studentActingPhoneHidePath", recursively: true)?.position.y = Float(0.232 + phoneHand * 0.006 + teacherFreezeRead * 0.004)
        node.childNode(withName: "studentActingCoverRisePath", recursively: true)?.opacity = CGFloat(((coverHand + cryingHand * 0.55) * (0.28 + pressure * 0.22) + teacherFreezeRead * 0.08).clamped(to: 0...0.66))
        node.childNode(withName: "studentActingCoverRisePath", recursively: true)?.position.y = Float(0.62 + coverHand * 0.018 + cryingHand * 0.012)
        node.childNode(withName: "studentActingCryWeightDropPool", recursively: true)?.opacity = CGFloat((cryingHand * (0.3 + pressure * 0.22 + lowLight * 0.08)).clamped(to: 0...0.62))
        node.childNode(withName: "studentActingCryWeightDropPool", recursively: true)?.scale = SCNVector3(1.85 + CGFloat(cryingHand) * 0.14, 0.1, 0.95 + CGFloat(pressure) * 0.05)
        node.childNode(withName: "studentActingSleepSettleBreath", recursively: true)?.opacity = CGFloat((sleepingHand * (0.22 + lowLight * 0.08) + cryingHand * 0.08).clamped(to: 0...0.42))
        node.childNode(withName: "studentActingSleepSettleBreath", recursively: true)?.scale = SCNVector3(1 + CGFloat(sleepingHand + cryingHand) * 0.1, 1, 1 + CGFloat(deskCompression) * 0.05)
        node.childNode(withName: "studentActingHelpReachArc", recursively: true)?.opacity = CGFloat((offerMotion * (0.3 + relationship * 0.28) + eventMateMotion * 0.08).clamped(to: 0...0.64))
        node.childNode(withName: "studentActingHelpReachArc", recursively: true)?.eulerAngles.z = CGFloat(-0.96 - relationship * 0.1 + Double(phase) * 0.75)
        for index in 0..<3 {
            let rib = node.childNode(withName: "studentActingBreathHoldRib\(index)", recursively: true)
            rib?.opacity = CGFloat((0.02 + sleepingHand * 0.12 + cryingHand * 0.08 + pressure * 0.08 + teacherFreezeRead * 0.08 + lowLight * 0.04 - Double(index) * 0.012).clamped(to: 0.005...0.28))
            rib?.position.y = Float(0.63 - Double(index) * 0.058 + pressure * 0.003) + sin(phase * 4.0 + Float(index)) * 0.0014
        }
    }

    private func applyStateAnimation(_ state: ClassmateState, to node: SCNNode) {
        clearClassmateActions(node)
        node.eulerAngles.x = 0
        node.eulerAngles.z = 0
        node.childNode(withName: "bodyRoot", recursively: false)?.eulerAngles = SCNVector3(0, 0, 0)
        node.childNode(withName: "head", recursively: false)?.eulerAngles = SCNVector3(0, 0, 0)
        node.childNode(withName: "hair", recursively: false)?.eulerAngles = SCNVector3(0, 0, 0)
        node.childNode(withName: "leftArm", recursively: true)?.eulerAngles = SCNVector3(0, 0, 0.12)
        node.childNode(withName: "rightArm", recursively: true)?.eulerAngles = SCNVector3(0, 0, -0.12)
        node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.18, 0, 0.08)
        node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.18, 0, -0.08)
        node.childNode(withName: "leftHand", recursively: true)?.eulerAngles = SCNVector3(0, 0, 0.18)
        node.childNode(withName: "rightHand", recursively: true)?.eulerAngles = SCNVector3(0, 0, -0.18)
        node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles = SCNVector3(0.08, 0, 0.035)
        node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles = SCNVector3(-0.08, 0, -0.035)
        node.childNode(withName: "leftFoot", recursively: true)?.eulerAngles.x = 0
        node.childNode(withName: "rightFoot", recursively: true)?.eulerAngles.x = 0
        node.childNode(withName: "classmatePencil", recursively: true)?.opacity = state == .studying ? 1.0 : 0.28
        node.childNode(withName: "leftUpperLid", recursively: true)?.opacity = state == .sleeping ? 0.78 : (state == .anxious || state == .crying ? 0.44 : 0.12)
        node.childNode(withName: "rightUpperLid", recursively: true)?.opacity = state == .sleeping ? 0.78 : (state == .anxious || state == .crying ? 0.44 : 0.12)
        node.childNode(withName: "leftTear", recursively: true)?.opacity = state == .crying ? 0.88 : 0
        node.childNode(withName: "rightTear", recursively: true)?.opacity = state == .crying ? 0.62 : 0
        node.childNode(withName: "phone", recursively: false)?.opacity = state == .usingPhone ? 1 : 0
        node.childNode(withName: "paper", recursively: false)?.opacity = state == .studying ? 0.78 : 0.35
        node.childNode(withName: "supportNote", recursively: false)?.opacity = state == .offeringHelp ? 1.0 : 0.35
        node.childNode(withName: "tensionNote", recursively: false)?.opacity = state == .anxious || state == .crying ? 0.9 : 0.48

        switch state {
        case .studying:
            node.eulerAngles.x = -0.03
            node.childNode(withName: "head", recursively: false)?.eulerAngles.x = -0.08
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = 0.18
            node.childNode(withName: "rightArm", recursively: true)?.eulerAngles.z = -0.22
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.42, 0, 0.12)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.48, 0, -0.16)
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles = SCNVector3(0.14, 0, 0.02)
            node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles = SCNVector3(-0.05, 0, -0.02)
            let breathing = SCNAction.sequence([
                .moveBy(x: 0, y: 0.006, z: 0, duration: 0.9),
                .moveBy(x: 0, y: -0.006, z: 0, duration: 0.9)
            ])
            node.childNode(withName: "bodyRoot", recursively: false)?.runAction(.repeatForever(breathing), forKey: "breathing")
            node.childNode(withName: "rightHand", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.035, y: 0.018, z: -0.028, duration: 0.16),
                .rotateBy(x: -0.035, y: -0.018, z: 0.028, duration: 0.18),
                .wait(duration: 0.32)
            ])), forKey: "writing")
            node.childNode(withName: "rightForearm", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.018, y: 0, z: -0.012, duration: 0.28),
                .rotateBy(x: -0.018, y: 0, z: 0.012, duration: 0.34),
                .wait(duration: 0.48)
            ])), forKey: "forearm_write")
        case .usingPhone:
            node.eulerAngles.x = -0.22
            node.childNode(withName: "head", recursively: false)?.eulerAngles.x = -0.18
            node.childNode(withName: "leftUpperLid", recursively: true)?.opacity = 0.35
            node.childNode(withName: "rightUpperLid", recursively: true)?.opacity = 0.35
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = -0.08
            node.childNode(withName: "rightArm", recursively: true)?.eulerAngles.z = 0.08
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.6, 0, -0.18)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.6, 0, 0.18)
            node.childNode(withName: "leftHand", recursively: true)?.eulerAngles.z = -0.18
            node.childNode(withName: "rightHand", recursively: true)?.eulerAngles.z = 0.18
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles.z = -0.08
            node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles.z = 0.08
            node.childNode(withName: "phone", recursively: false)?.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.05, green: 0.2, blue: 0.8, alpha: 1)
            node.childNode(withName: "phone", recursively: false)?.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 1.0, duration: 0.18),
                .fadeOpacity(to: 0.72, duration: 0.28)
            ])), forKey: "phone_glow")
        case .anxious:
            let left = SCNAction.moveBy(x: -0.025, y: 0, z: 0, duration: 0.05)
            let right = SCNAction.moveBy(x: 0.05, y: 0, z: 0, duration: 0.08)
            let back = SCNAction.moveBy(x: -0.025, y: 0, z: 0, duration: 0.05)
            node.runAction(.repeatForever(.sequence([left, right, back, .wait(duration: 0.25)])), forKey: "fidget")
            node.childNode(withName: "head", recursively: false)?.eulerAngles.x = -0.08
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.52, 0, -0.2)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.52, 0, 0.2)
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles.z = 0.16
            node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles.z = -0.18
            node.childNode(withName: "rightFoot", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.16, y: 0, z: 0, duration: 0.09),
                .rotateBy(x: -0.16, y: 0, z: 0, duration: 0.12),
                .wait(duration: 0.18)
            ])), forKey: "foot_tap")
            node.childNode(withName: "leftFoot", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.08, y: 0, z: 0, duration: 0.14),
                .rotateBy(x: -0.08, y: 0, z: 0, duration: 0.16),
                .wait(duration: 0.34)
            ])), forKey: "foot_tap")
            node.childNode(withName: "rightHand", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: 0.06, duration: 0.1),
                .rotateBy(x: 0, y: 0, z: -0.06, duration: 0.12),
                .wait(duration: 0.4)
            ])), forKey: "hand_tension")
            node.childNode(withName: "leftHand", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.035, y: 0, z: -0.04, duration: 0.12),
                .rotateBy(x: -0.035, y: 0, z: 0.04, duration: 0.14),
                .wait(duration: 0.36)
            ])), forKey: "hand_tension")
        case .sleeping:
            node.eulerAngles.x = -0.55
            node.childNode(withName: "head", recursively: false)?.eulerAngles.x = -0.34
            node.childNode(withName: "hair", recursively: false)?.eulerAngles.x = -0.34
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = 0.28
            node.childNode(withName: "rightArm", recursively: true)?.eulerAngles.z = -0.28
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.82, 0, 0.14)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.82, 0, -0.14)
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles = SCNVector3(0.2, 0, -0.12)
            node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles = SCNVector3(0.12, 0, 0.08)
        case .crying:
            node.eulerAngles.x = -0.72
            node.childNode(withName: "head", recursively: false)?.eulerAngles.x = -0.45
            node.childNode(withName: "hair", recursively: false)?.eulerAngles.x = -0.45
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = -0.2
            node.childNode(withName: "rightArm", recursively: true)?.eulerAngles.z = 0.2
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.72, 0, -0.26)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.72, 0, 0.26)
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles.z = -0.22
            node.childNode(withName: "rightLeg", recursively: true)?.eulerAngles.z = 0.22
            let tremble = SCNAction.sequence([.moveBy(x: 0, y: 0.012, z: 0, duration: 0.12), .moveBy(x: 0, y: -0.012, z: 0, duration: 0.12)])
            node.runAction(.repeatForever(tremble), forKey: "cry")
        case .offeringHelp:
            node.eulerAngles.x = -0.12
            node.eulerAngles.z = -0.08
            node.childNode(withName: "head", recursively: false)?.eulerAngles.y = -0.16
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = -0.1
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.36, 0, -0.32)
            node.childNode(withName: "leftHand", recursively: true)?.eulerAngles.z = -0.34
            node.childNode(withName: "leftLeg", recursively: true)?.eulerAngles.z = -0.06
            node.childNode(withName: "supportNote", recursively: false)?.runAction(.repeatForever(.sequence([
                .moveBy(x: -0.02, y: 0, z: 0, duration: 0.35),
                .moveBy(x: 0.02, y: 0, z: 0, duration: 0.45),
                .wait(duration: 0.6)
            ])), forKey: "offer_note")
        case .lookingAtPlayer:
            node.eulerAngles.x = -0.04
            node.eulerAngles.z = 0
            node.childNode(withName: "rightHand", recursively: true)?.eulerAngles.z = -0.04
            node.childNode(withName: "rightFoot", recursively: true)?.eulerAngles.x = 0.08
            node.childNode(withName: "leftBrow", recursively: true)?.eulerAngles.z = CGFloat.pi / 2 - 0.06
            node.childNode(withName: "rightBrow", recursively: true)?.eulerAngles.z = CGFloat.pi / 2 + 0.08
            node.childNode(withName: "head", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0.16, z: 0, duration: 0.42),
                .wait(duration: 0.3),
                .rotateBy(x: 0, y: -0.16, z: 0, duration: 0.42),
                .wait(duration: 0.5)
            ])), forKey: "glance")
        case .covering:
            node.eulerAngles.z = 0.16
            node.childNode(withName: "leftArm", recursively: true)?.eulerAngles.z = -0.18
            node.childNode(withName: "rightArm", recursively: true)?.eulerAngles.z = -0.26
            node.childNode(withName: "leftForearm", recursively: true)?.eulerAngles = SCNVector3(0.58, 0, -0.38)
            node.childNode(withName: "rightForearm", recursively: true)?.eulerAngles = SCNVector3(0.58, 0, -0.22)
            node.childNode(withName: "leftHand", recursively: true)?.eulerAngles.z = -0.28
            node.childNode(withName: "rightHand", recursively: true)?.eulerAngles.z = -0.3
            node.childNode(withName: "paper", recursively: false)?.opacity = 0.95
        }
        attachClassmatePerformanceLayer(state, to: node)
        pulseClassmateStateReadability(state, to: node)
    }

    private func pulseClassmateStateReadability(_ state: ClassmateState, to node: SCNNode) {
        let halo = node.childNode(withName: "studentStateReadinessHalo", recursively: true)
        halo?.scale = SCNVector3(1, 1, 1)
        halo?.runAction(.sequence([
            .scale(to: 1.18, duration: 0.1),
            .scale(to: 0.96, duration: 0.12),
            .scale(to: 1.0, duration: 0.16)
        ]), forKey: "state_readiness_pulse")

        let deskAnchor = node.childNode(withName: "studentStateDeskAnchorPulse", recursively: true)
        deskAnchor?.scale = SCNVector3(1, 1, 1)
        deskAnchor?.runAction(.sequence([
            .scale(to: state == .crying || state == .sleeping ? 1.18 : 1.08, duration: 0.12),
            .scale(to: 1.0, duration: 0.22)
        ]), forKey: "state_desk_anchor_pulse")

        switch state {
        case .studying:
            node.childNode(withName: "studentStateStudyStrokeBeat", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.16, duration: 0.12),
                .scale(to: 0.92, duration: 0.12),
                .wait(duration: 0.24)
            ])), forKey: "state_study_tick")
        case .usingPhone:
            node.childNode(withName: "studentStatePhoneScreenBeat", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.12, duration: 0.1),
                .scale(to: 0.96, duration: 0.18),
                .wait(duration: 0.42)
            ])), forKey: "state_phone_tick")
        case .anxious:
            node.childNode(withName: "studentStateActionVector", recursively: true)?.runAction(.repeatForever(.sequence([
                .moveBy(x: -0.012, y: 0, z: 0, duration: 0.06),
                .moveBy(x: 0.024, y: 0, z: 0, duration: 0.08),
                .moveBy(x: -0.012, y: 0, z: 0, duration: 0.06),
                .wait(duration: 0.36)
            ])), forKey: "state_anxious_vector")
        case .sleeping:
            node.childNode(withName: "studentStateSleepBreathPool", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.12, duration: 1.25),
                .scale(to: 0.95, duration: 1.35)
            ])), forKey: "state_sleep_pool")
        case .crying:
            node.childNode(withName: "studentStateCryWeightDrop", recursively: true)?.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: -0.01, z: 0, duration: 0.16),
                .moveBy(x: 0, y: 0.01, z: 0, duration: 0.2),
                .wait(duration: 0.32)
            ])), forKey: "state_cry_weight")
        case .offeringHelp:
            node.childNode(withName: "studentStateHelpReachCue", recursively: true)?.runAction(.repeatForever(.sequence([
                .moveBy(x: -0.016, y: 0.004, z: 0.012, duration: 0.32),
                .moveBy(x: 0.016, y: -0.004, z: -0.012, duration: 0.38),
                .wait(duration: 0.5)
            ])), forKey: "state_help_reach")
        case .lookingAtPlayer:
            node.childNode(withName: "studentStateFaceIntentPlate", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.08, duration: 0.2),
                .scale(to: 0.98, duration: 0.28),
                .wait(duration: 0.7)
            ])), forKey: "state_gaze_plate")
        case .covering:
            node.childNode(withName: "studentStateCoverBlockCue", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.1, duration: 0.18),
                .scale(to: 0.96, duration: 0.28),
                .wait(duration: 0.52)
            ])), forKey: "state_cover_block")
        }
    }

    private func attachClassmatePerformanceLayer(_ state: ClassmateState, to node: SCNNode) {
        switch state {
        case .studying:
            node.childNode(withName: "classmatePencil", recursively: true)?.runAction(.repeatForever(.sequence([
                .moveBy(x: 0.012, y: 0.002, z: -0.018, duration: 0.12),
                .moveBy(x: -0.016, y: -0.001, z: 0.022, duration: 0.14),
                .moveBy(x: 0.004, y: -0.001, z: -0.004, duration: 0.08),
                .wait(duration: 0.22)
            ])), forKey: "pencil_scritch")
            node.childNode(withName: "paper", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0.018, z: 0, duration: 0.5),
                .rotateBy(x: 0, y: -0.018, z: 0, duration: 0.55),
                .wait(duration: 1.0)
            ])), forKey: "paper_shift")
            node.childNode(withName: "leftPupil", recursively: true)?.runAction(makeEyeScanAction(horizontal: 0.004, vertical: -0.001, delay: 0.45), forKey: "read_scan")
            node.childNode(withName: "rightPupil", recursively: true)?.runAction(makeEyeScanAction(horizontal: 0.004, vertical: -0.001, delay: 0.45), forKey: "read_scan")
        case .usingPhone:
            node.childNode(withName: "head", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.025, y: 0, z: 0, duration: 0.18),
                .rotateBy(x: -0.025, y: 0, z: 0, duration: 0.22),
                .wait(duration: 1.1)
            ])), forKey: "screen_nod")
            node.childNode(withName: "rightThumb", recursively: true)?.runAction(makeThumbTapAction(delay: 0.2), forKey: "thumb_tap")
            node.childNode(withName: "leftThumb", recursively: true)?.runAction(makeThumbTapAction(delay: 0.36), forKey: "thumb_tap")
            node.childNode(withName: "phone", recursively: false)?.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.004, z: 0, duration: 0.08),
                .moveBy(x: 0, y: -0.004, z: 0, duration: 0.1),
                .wait(duration: 0.7)
            ])), forKey: "phone_buzz")
        case .anxious:
            node.childNode(withName: "leftBrow", recursively: true)?.runAction(makeBrowTensionAction(direction: -1), forKey: "brow_tension")
            node.childNode(withName: "rightBrow", recursively: true)?.runAction(makeBrowTensionAction(direction: 1), forKey: "brow_tension")
            node.childNode(withName: "tensionNote", recursively: false)?.runAction(.repeatForever(.sequence([
                .moveBy(x: -0.008, y: 0.004, z: 0, duration: 0.07),
                .moveBy(x: 0.016, y: -0.004, z: 0, duration: 0.1),
                .moveBy(x: -0.008, y: 0, z: 0, duration: 0.08),
                .wait(duration: 0.42)
            ])), forKey: "tension_note_shake")
        case .sleeping:
            node.childNode(withName: "bodyRoot", recursively: false)?.runAction(.repeatForever(.sequence([
                .moveBy(x: 0, y: 0.006, z: 0, duration: 1.45),
                .moveBy(x: 0, y: -0.006, z: 0, duration: 1.65)
            ])), forKey: "sleep_breath")
            node.childNode(withName: "head", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: 0.035, duration: 1.3),
                .rotateBy(x: 0, y: 0, z: -0.035, duration: 1.5)
            ])), forKey: "sleep_head_sway")
        case .crying:
            node.childNode(withName: "leftTear", recursively: true)?.runAction(makeTearFallAction(delay: 0.1), forKey: "tear_fall")
            node.childNode(withName: "rightTear", recursively: true)?.runAction(makeTearFallAction(delay: 0.55), forKey: "tear_fall")
            node.childNode(withName: "leftHand", recursively: true)?.runAction(makeHandCoverShakeAction(direction: -1), forKey: "cover_shake")
            node.childNode(withName: "rightHand", recursively: true)?.runAction(makeHandCoverShakeAction(direction: 1), forKey: "cover_shake")
            node.childNode(withName: "mouth", recursively: true)?.runAction(.repeatForever(.sequence([
                .scale(to: 1.16, duration: 0.16),
                .scale(to: 0.92, duration: 0.2),
                .wait(duration: 0.36)
            ])), forKey: "cry_mouth")
        case .offeringHelp:
            node.childNode(withName: "supportNote", recursively: false)?.runAction(.repeatForever(.sequence([
                .moveBy(x: -0.026, y: 0.006, z: 0.018, duration: 0.42),
                .moveBy(x: 0.026, y: -0.006, z: -0.018, duration: 0.5),
                .wait(duration: 0.55)
            ])), forKey: "note_offer_reach")
            node.childNode(withName: "leftHand", recursively: true)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0.04, y: 0, z: -0.035, duration: 0.35),
                .rotateBy(x: -0.04, y: 0, z: 0.035, duration: 0.42),
                .wait(duration: 0.6)
            ])), forKey: "offer_hand")
            node.childNode(withName: "head", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: -0.045, z: 0, duration: 0.5),
                .rotateBy(x: 0, y: 0.045, z: 0, duration: 0.55),
                .wait(duration: 0.7)
            ])), forKey: "help_check")
        case .lookingAtPlayer:
            for name in ["leftPupil", "rightPupil", "leftEyeHighlight", "rightEyeHighlight"] {
                node.childNode(withName: name, recursively: true)?.runAction(.repeatForever(.sequence([
                    .moveBy(x: -0.005, y: 0.001, z: 0, duration: 0.18),
                    .wait(duration: 0.72),
                    .moveBy(x: 0.005, y: -0.001, z: 0, duration: 0.24),
                    .wait(duration: 0.9)
                ])), forKey: "player_eye_lock")
            }
        case .covering:
            node.childNode(withName: "coverShadow", recursively: true)?.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.82, duration: 0.26),
                .fadeOpacity(to: 0.58, duration: 0.42),
                .wait(duration: 0.55)
            ])), forKey: "cover_shadow_pulse")
            node.childNode(withName: "paper", recursively: false)?.runAction(.repeatForever(.sequence([
                .rotateBy(x: 0, y: 0, z: -0.035, duration: 0.4),
                .rotateBy(x: 0, y: 0, z: 0.035, duration: 0.52),
                .wait(duration: 0.6)
            ])), forKey: "cover_paper_guard")
        }
    }

    private func makeEyeScanAction(horizontal: CGFloat, vertical: CGFloat, delay: Double) -> SCNAction {
        .repeatForever(.sequence([
            .moveBy(x: horizontal, y: vertical, z: 0, duration: 0.18),
            .wait(duration: delay),
            .moveBy(x: -horizontal, y: -vertical, z: 0, duration: 0.2),
            .wait(duration: delay + 0.35)
        ]))
    }

    private func makeThumbTapAction(delay: Double) -> SCNAction {
        .repeatForever(.sequence([
            .rotateBy(x: 0.045, y: 0, z: 0.035, duration: 0.08),
            .rotateBy(x: -0.045, y: 0, z: -0.035, duration: 0.1),
            .wait(duration: delay)
        ]))
    }

    private func makeBrowTensionAction(direction: CGFloat) -> SCNAction {
        .repeatForever(.sequence([
            .rotateBy(x: 0, y: 0, z: direction * 0.035, duration: 0.12),
            .rotateBy(x: 0, y: 0, z: -direction * 0.035, duration: 0.16),
            .wait(duration: 0.44)
        ]))
    }

    private func makeTearFallAction(delay: Double) -> SCNAction {
        .repeatForever(.sequence([
            .fadeOpacity(to: 0.95, duration: 0.06),
            .moveBy(x: 0, y: -0.035, z: 0, duration: 0.45),
            .fadeOpacity(to: 0.12, duration: 0.12),
            .moveBy(x: 0, y: 0.035, z: 0, duration: 0.01),
            .wait(duration: delay)
        ]))
    }

    private func makeHandCoverShakeAction(direction: CGFloat) -> SCNAction {
        .repeatForever(.sequence([
            .rotateBy(x: 0.02, y: 0, z: direction * 0.035, duration: 0.09),
            .rotateBy(x: -0.02, y: 0, z: -direction * 0.035, duration: 0.1),
            .wait(duration: 0.32)
        ]))
    }

    private func clearClassmateActions(_ node: SCNNode) {
        node.removeAllActions()
        for child in node.childNodes {
            clearClassmateActions(child)
        }
    }

    private func makeEventWorldRippleLayer() -> SCNNode {
        let root = SCNNode()
        for index in 0..<4 {
            let ring = SCNTorus(ringRadius: 0.55 + CGFloat(index) * 0.34, pipeRadius: 0.006)
            ring.firstMaterial = material(NSColor(calibratedRed: 1.0, green: 0.38, blue: 0.22, alpha: 0.16 - CGFloat(index) * 0.025))
            let ringNode = SCNNode(geometry: ring)
            ringNode.name = "eventStressRing\(index)"
            ringNode.position = SCNVector3(-0.6, 0.038 + Float(index) * 0.002, 1.48)
            ringNode.eulerAngles.x = Float.pi / 2
            ringNode.runAction(.repeatForever(.sequence([
                .scale(to: 1.18 + CGFloat(index) * 0.08, duration: 1.1 + Double(index) * 0.2),
                .scale(to: 0.82, duration: 0.2),
                .wait(duration: 0.35 + Double(index) * 0.12)
            ])), forKey: "event_floor_pulse")
            root.addChildNode(ringNode)
        }

        let deskShadow = box(width: 2.1, height: 0.006, length: 0.72, color: NSColor(calibratedWhite: 0.01, alpha: 0.24), position: SCNVector3(-0.62, 0.041, 1.55))
        deskShadow.name = "eventDeskPressureShadow"
        deskShadow.eulerAngles.y = -0.08
        deskShadow.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.18, duration: 0.5),
            .fadeOpacity(to: 0.46, duration: 0.7)
        ])), forKey: "event_shadow_breathe")
        root.addChildNode(deskShadow)

        for index in 0..<6 {
            let thread = capsule(radius: 0.004, height: 0.82 + CGFloat(index % 3) * 0.16, color: NSColor(calibratedRed: 0.42, green: 0.86, blue: 1.0, alpha: 0.16), position: SCNVector3(-2.2 + Float(index) * 0.64, 1.28 + Float(index % 2) * 0.18, -0.3 + Float(index % 3) * 0.72), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            thread.name = "eventMemoryThread\(index)"
            thread.eulerAngles.y = -0.18 + Float(index) * 0.05
            thread.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.08, duration: 1.1 + Double(index) * 0.08),
                .fadeOpacity(to: 0.34, duration: 1.6 + Double(index) * 0.1)
            ])), forKey: "memory_thread_breathe")
            root.addChildNode(thread)
        }
        return root
    }

    private func makeClassroomDepthCueLayer() -> SCNNode {
        let root = SCNNode()
        let blueAir = NSColor(calibratedRed: 0.35, green: 0.52, blue: 0.84, alpha: 0.065)
        let warmAir = NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.28, alpha: 0.055)
        let rowShadow = NSColor(calibratedWhite: 0.02, alpha: 0.09)

        for (index, z) in [-4.9, -3.55, -2.15, -0.75, 0.78, 2.25, 3.75, 5.05].enumerated() {
            let veil = box(width: 7.55 - CGFloat(index % 3) * 0.28, height: 1.55 + CGFloat(index % 2) * 0.22, length: 0.01, color: index % 2 == 0 ? blueAir : warmAir, position: SCNVector3(0, 1.45 + Float(index % 2) * 0.16, Float(z)))
            veil.name = "cinematicDepthVeil\(index)"
            veil.eulerAngles.y = Float(index - 4) * 0.014
            veil.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.18, duration: 2.6 + Double(index % 4) * 0.22),
                .fadeOpacity(to: 0.46, duration: 3.1 + Double(index % 5) * 0.2)
            ])), forKey: "depth_veil_breathe")
            root.addChildNode(veil)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.0
            let separation = box(width: 6.4, height: 0.006, length: 0.11, color: rowShadow, position: SCNVector3(0, 0.05, z + 0.62))
            separation.name = "cinematicRowSeparation\(row)"
            separation.eulerAngles.y = row % 2 == 0 ? 0.035 : -0.028
            root.addChildNode(separation)
        }

        for index in 0..<12 {
            let z = -5.2 + Float((index * 47) % 1020) / 100
            let x = -3.2 + Float((index * 31) % 640) / 100
            let lampGhost = sphere(radius: 0.035 + CGFloat(index % 4) * 0.006, color: index % 2 == 0 ? warmAir.withAlphaComponent(0.18) : blueAir.withAlphaComponent(0.16), position: SCNVector3(x, 2.12 + Float(index % 3) * 0.18, z), scale: SCNVector3(1.7, 0.6, 0.18))
            lampGhost.name = "rearDepthBokeh\(index)"
            lampGhost.geometry?.firstMaterial?.emission.contents = index % 2 == 0 ? warmAir : blueAir
            root.addChildNode(lampGhost)
        }
        for index in 0..<6 {
            let z = -4.55 + Float(index) * 1.72
            let guide = box(width: 0.42 + CGFloat(index % 3) * 0.18, height: 0.004, length: 0.036, color: NSColor(calibratedRed: 0.82, green: 0.88, blue: 1.0, alpha: 0.055), position: SCNVector3(-2.75 + Float(index % 2) * 5.5, 1.06 + Float(index % 3) * 0.18, z))
            guide.name = "worldFocusGuideGlint\(index)"
            guide.eulerAngles.y = index % 2 == 0 ? -0.08 : 0.08
            root.addChildNode(guide)
        }
        return root
    }

    private func makeClassroomArchitecturalDepthLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomArchitecturalDepthLayer"

        let cornerInk = NSColor(calibratedWhite: 0.0, alpha: 0.15)
        let ceilingDust = NSColor(calibratedRed: 0.74, green: 0.78, blue: 0.82, alpha: 0.08)
        let windowBlue = NSColor(calibratedRed: 0.46, green: 0.66, blue: 1.0, alpha: 0.08)
        let doorAmber = NSColor(calibratedRed: 1.0, green: 0.62, blue: 0.24, alpha: 0.09)
        let floorDepth = NSColor(calibratedWhite: 0.0, alpha: 0.09)
        let rearAir = NSColor(calibratedRed: 0.34, green: 0.46, blue: 0.72, alpha: 0.07)
        let chalkGlow = NSColor(calibratedRed: 0.72, green: 0.92, blue: 0.72, alpha: 0.07)

        for (index, x) in [-3.98, 3.98].enumerated() {
            let sideName = index == 0 ? "Left" : "Right"
            let frontCorner = box(width: 0.014, height: 2.75, length: 0.18, color: cornerInk, position: SCNVector3(Float(x), 1.42, -5.72))
            frontCorner.name = "architectural\(sideName)FrontCornerOcclusion"
            root.addChildNode(frontCorner)

            let rearCorner = box(width: 0.014, height: 2.65, length: 0.22, color: cornerInk.withAlphaComponent(0.13), position: SCNVector3(Float(x), 1.36, 4.98))
            rearCorner.name = "architectural\(sideName)RearCornerOcclusion"
            root.addChildNode(rearCorner)

            let sideWallFalloff = box(width: 0.012, height: 1.8, length: 9.8, color: index == 0 ? cornerInk.withAlphaComponent(0.1) : windowBlue, position: SCNVector3(Float(x), 1.34, -0.32))
            sideWallFalloff.name = "architectural\(sideName)WallVolumeFalloff"
            sideWallFalloff.eulerAngles.y = index == 0 ? 0.012 : -0.012
            root.addChildNode(sideWallFalloff)

            for band in 0..<5 {
                let z = -4.9 + Float(band) * 2.25
                let baseboard = box(width: 0.018, height: 0.045, length: 0.82, color: cornerInk.withAlphaComponent(0.13), position: SCNVector3(Float(x * 0.997), 0.14, z))
                baseboard.name = "architectural\(sideName)BaseboardDepth\(band)"
                baseboard.eulerAngles.y = index == 0 ? 0.03 : -0.03
                root.addChildNode(baseboard)
            }
        }

        for index in 0..<6 {
            let z = -5.18 + Float(index) * 1.96
            let ceilingBeam = box(width: 7.65, height: 0.032, length: 0.045, color: ceilingDust, position: SCNVector3(0, 2.84, z))
            ceilingBeam.name = "architecturalCeilingBeamDepth\(index)"
            ceilingBeam.eulerAngles.y = -0.012 + Float(index) * 0.005
            root.addChildNode(ceilingBeam)

            let beamShadow = box(width: 7.5, height: 0.012, length: 0.18, color: cornerInk.withAlphaComponent(0.09), position: SCNVector3(0, 2.78, z + 0.18))
            beamShadow.name = "architecturalCeilingBeamShadow\(index)"
            beamShadow.eulerAngles.y = 0.01 - Float(index) * 0.004
            root.addChildNode(beamShadow)
        }

        for index in 0..<5 {
            let z = -4.34 + Float(index) * 1.86
            let windowReveal = box(width: 0.13, height: 1.5, length: 1.06, color: windowBlue, position: SCNVector3(3.88, 1.44, z))
            windowReveal.name = "architecturalWindowRevealDepth\(index)"
            windowReveal.eulerAngles = SCNVector3(-0.035, -0.16, -0.018)
            root.addChildNode(windowReveal)

            let innerSill = box(width: 0.44, height: 0.035, length: 0.92, color: cornerInk.withAlphaComponent(0.12), position: SCNVector3(3.62, 0.84, z + 0.06))
            innerSill.name = "architecturalWindowInnerSillShadow\(index)"
            innerSill.eulerAngles.y = -0.08
            root.addChildNode(innerSill)

            let upperPocket = box(width: 0.2, height: 0.16, length: 0.96, color: cornerInk.withAlphaComponent(0.1), position: SCNVector3(3.78, 2.16, z - 0.02))
            upperPocket.name = "architecturalWindowUpperPocket\(index)"
            root.addChildNode(upperPocket)
        }

        for (index, data) in [
            ("Front", SCNVector3(-3.52, 1.18, -5.56), true),
            ("Rear", SCNVector3(-3.52, 1.18, 4.78), false)
        ].enumerated() {
            let doorName = data.0
            let doorPos = data.1
            let doorGap = box(width: 0.034, height: 1.82, length: 0.012, color: doorAmber, position: doorPos)
            doorGap.name = "architectural\(doorName)DoorGapVolume"
            doorGap.geometry?.firstMaterial?.emission.contents = doorAmber.withAlphaComponent(0.05)
            root.addChildNode(doorGap)

            let jambShadow = box(width: 0.18, height: 2.05, length: 0.012, color: cornerInk.withAlphaComponent(0.14), position: SCNVector3(doorPos.x + 0.28, doorPos.y, doorPos.z + (data.2 ? 0.02 : -0.02)))
            jambShadow.name = "architectural\(doorName)DoorJambShadow"
            root.addChildNode(jambShadow)

            let threshold = box(width: 0.92, height: 0.006, length: 0.18, color: floorDepth.withAlphaComponent(0.12), position: SCNVector3(doorPos.x + 0.18, 0.076, doorPos.z + (data.2 ? 0.26 : -0.26)))
            threshold.name = "architectural\(doorName)DoorThresholdWear"
            threshold.eulerAngles.y = index == 0 ? -0.05 : 0.05
            root.addChildNode(threshold)
        }

        for index in 0..<7 {
            let z = -4.9 + Float(index) * 1.56
            let floorBand = box(width: 6.95 - CGFloat(index % 3) * 0.18, height: 0.004, length: 0.14, color: floorDepth, position: SCNVector3(0, 0.062, z))
            floorBand.name = "architecturalFloorPerspectiveBand\(index)"
            floorBand.eulerAngles.y = -0.025 + Float(index) * 0.008
            root.addChildNode(floorBand)

            let airCurtain = box(width: 7.0 - CGFloat(index % 2) * 0.24, height: 0.46 + CGFloat(index % 3) * 0.08, length: 0.012, color: index % 2 == 0 ? rearAir : chalkGlow, position: SCNVector3(0, 1.38 + Float(index % 2) * 0.13, z + 0.42))
            airCurtain.name = "architecturalDepthAirCurtain\(index)"
            airCurtain.eulerAngles.y = -0.025 + Float(index) * 0.007
            root.addChildNode(airCurtain)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.18
            let rowPocket = box(width: 6.18, height: 0.2, length: 0.018, color: cornerInk.withAlphaComponent(0.08), position: SCNVector3(0, 0.78, z + 0.6))
            rowPocket.name = "architecturalDeskRowPocketShadow\(row)"
            rowPocket.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(rowPocket)

            let ceilingToDesk = box(width: 0.032, height: 1.64, length: 0.012, color: rearAir.withAlphaComponent(0.07), position: SCNVector3(-3.08, 1.58, z))
            ceilingToDesk.name = "architecturalRowVerticalDepthMarker\(row)"
            root.addChildNode(ceilingToDesk)
        }

        let blackboardPocket = box(width: 4.88, height: 1.64, length: 0.016, color: chalkGlow, position: SCNVector3(0, 1.74, -5.92))
        blackboardPocket.name = "architecturalBlackboardRecessGlow"
        root.addChildNode(blackboardPocket)

        let rearCompression = box(width: 7.2, height: 1.8, length: 0.018, color: rearAir.withAlphaComponent(0.09), position: SCNVector3(0, 1.42, 4.78))
        rearCompression.name = "architecturalRearWallDistanceCompression"
        root.addChildNode(rearCompression)

        root.opacity = 0.16
        return root
    }

    private func makeCinematicLightCorridorLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "cinematicLightCorridorLayer"

        let chalkGreen = NSColor(calibratedRed: 0.72, green: 0.92, blue: 0.7, alpha: 0.07)
        let windowBlue = NSColor(calibratedRed: 0.48, green: 0.68, blue: 1.0, alpha: 0.075)
        let warmDesk = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.38, alpha: 0.06)
        let negativeFill = NSColor(calibratedWhite: 0.0, alpha: 0.09)
        let amberHalation = NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.24, alpha: 0.06)
        let coolRear = NSColor(calibratedRed: 0.34, green: 0.46, blue: 0.72, alpha: 0.07)

        for index in 0..<6 {
            let corridor = box(
                width: 1.1 + CGFloat(index % 3) * 0.24,
                height: 0.42 + CGFloat(index % 2) * 0.1,
                length: 0.018,
                color: index % 2 == 0 ? chalkGreen : warmDesk,
                position: SCNVector3(-1.9 + Float(index) * 0.76, 1.52 + Float(index % 2) * 0.12, -4.94 + Float(index) * 0.76)
            )
            corridor.name = "cinematicLightCorridorBoardDepth\(index)"
            corridor.eulerAngles = SCNVector3(-0.02, -0.08 + Float(index) * 0.028, -0.035 + Float(index) * 0.012)
            root.addChildNode(corridor)
        }

        for index in 0..<7 {
            let z = -3.85 + Float(index) * 1.18
            let windowCut = box(
                width: 0.12 + CGFloat(index % 2) * 0.04,
                height: 1.38 - CGFloat(index % 3) * 0.12,
                length: 1.22,
                color: windowBlue,
                position: SCNVector3(2.55 - Float(index % 3) * 0.08, 1.46 + Float(index % 2) * 0.08, z)
            )
            windowCut.name = "cinematicLightCorridorWindowCrossBeam\(index)"
            windowCut.eulerAngles = SCNVector3(-0.07, -0.43 + Float(index) * 0.018, -0.12)
            root.addChildNode(windowCut)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.12
            let matte = box(width: 6.15, height: 0.008, length: 0.16, color: negativeFill, position: SCNVector3(0, 0.87, z + 0.32))
            matte.name = "cinematicLightCorridorDeskNegativeFill\(row)"
            matte.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(matte)

            let rim = box(width: 5.75, height: 0.18, length: 0.014, color: warmDesk, position: SCNVector3(0, 1.08, z + 0.12))
            rim.name = "cinematicLightCorridorStudentRowRim\(row)"
            rim.eulerAngles.y = row % 2 == 0 ? 0.024 : -0.022
            root.addChildNode(rim)
        }

        for index in 0..<4 {
            let curtain = box(width: 7.0 - CGFloat(index) * 0.28, height: 1.1 + CGFloat(index % 2) * 0.2, length: 0.014, color: coolRear, position: SCNVector3(0, 1.5 + Float(index % 2) * 0.16, -4.85 + Float(index) * 2.65))
            curtain.name = "cinematicLightCorridorRearFalloffCurtain\(index)"
            curtain.eulerAngles.y = -0.035 + Float(index) * 0.018
            root.addChildNode(curtain)
        }

        let teacherGate = box(width: 0.78, height: 1.42, length: 0.024, color: negativeFill.withAlphaComponent(0.12), position: SCNVector3(0, 1.22, -3.85))
        teacherGate.name = "cinematicLightCorridorTeacherSilhouetteGate"
        root.addChildNode(teacherGate)

        let boardHalation = box(width: 4.1, height: 1.18, length: 0.014, color: amberHalation, position: SCNVector3(0, 1.92, -5.78))
        boardHalation.name = "cinematicLightCorridorBlackboardHalation"
        root.addChildNode(boardHalation)

        let playerMatte = box(width: 3.8, height: 0.18, length: 0.016, color: negativeFill.withAlphaComponent(0.12), position: SCNVector3(-0.48, 0.82, 1.82))
        playerMatte.name = "cinematicLightCorridorPlayerForegroundMatte"
        playerMatte.eulerAngles.y = -0.035
        root.addChildNode(playerMatte)

        let aisleSightline = box(width: 0.12, height: 0.74, length: 6.2, color: windowBlue.withAlphaComponent(0.055), position: SCNVector3(-0.08, 1.16, -0.36))
        aisleSightline.name = "cinematicLightCorridorAisleSightline"
        aisleSightline.eulerAngles.y = -0.018
        root.addChildNode(aisleSightline)

        root.opacity = 0.16
        return root
    }

    private func makeClassroomVolumetricCompositionLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "classroomVolumetricCompositionLayer"
        let windowBlue = NSColor(calibratedRed: 0.42, green: 0.66, blue: 1.0, alpha: 0.075)
        let chalkGreen = NSColor(calibratedRed: 0.58, green: 0.88, blue: 0.62, alpha: 0.065)
        let warmDust = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.34, alpha: 0.06)
        let shadowInk = NSColor(calibratedWhite: 0.0, alpha: 0.1)
        let pressureWarm = NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.16, alpha: 0.07)
        let deskAmber = NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.34, alpha: 0.055)
        let bodyOcclusion = NSColor(calibratedWhite: 0.0, alpha: 0.12)
        let rimBlue = NSColor(calibratedRed: 0.56, green: 0.78, blue: 1.0, alpha: 0.065)

        for index in 0..<7 {
            let z = -4.7 + Float(index) * 1.42
            let shaft = box(
                width: 0.18 + CGFloat(index % 3) * 0.04,
                height: 1.55 - CGFloat(index % 2) * 0.12,
                length: 1.35,
                color: windowBlue,
                position: SCNVector3(2.45 - Float(index % 2) * 0.22, 1.52 + Float(index % 3) * 0.05, z)
            )
            shaft.name = "volumetricWindowShaft\(index)"
            shaft.eulerAngles = SCNVector3(-0.08, -0.5 + Float(index) * 0.018, -0.13)
            root.addChildNode(shaft)

            let floorHit = box(
                width: 1.04 + CGFloat(index % 3) * 0.16,
                height: 0.004,
                length: 0.16,
                color: windowBlue.withAlphaComponent(0.09),
                position: SCNVector3(-1.85 + Float(index % 3) * 0.2, 0.058, z + 0.32)
            )
            floorHit.name = "volumetricWindowFloorHit\(index)"
            floorHit.eulerAngles.y = -0.32 + Float(index) * 0.025
            root.addChildNode(floorHit)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.12
            let rowVolume = box(width: 6.25, height: 0.34, length: 0.014, color: warmDust, position: SCNVector3(0, 1.02, z + 0.12))
            rowVolume.name = "volumetricDeskRowAirShelf\(row)"
            rowVolume.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(rowVolume)

            let rowNegative = box(width: 6.4, height: 0.008, length: 0.19, color: shadowInk, position: SCNVector3(0.02, 0.845, z + 0.34))
            rowNegative.name = "volumetricDeskRowNegativeFill\(row)"
            rowNegative.eulerAngles.y = row % 2 == 0 ? 0.026 : -0.024
            root.addChildNode(rowNegative)

            let shoulderFog = box(width: 5.7, height: 0.12, length: 0.012, color: windowBlue.withAlphaComponent(0.07), position: SCNVector3(-0.14, 1.18, z - 0.04))
            shoulderFog.name = "volumetricStudentShoulderFog\(row)"
            shoulderFog.eulerAngles.y = row % 2 == 0 ? -0.026 : 0.022
            root.addChildNode(shoulderFog)

            let bodyCut = box(width: 5.92, height: 0.2, length: 0.014, color: bodyOcclusion, position: SCNVector3(0.02, 0.74, z + 0.18))
            bodyCut.name = "volumetricRowBodyOcclusionCut\(row)"
            bodyCut.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.016
            root.addChildNode(bodyCut)

            let deskBounce = box(width: 5.64, height: 0.006, length: 0.14, color: deskAmber, position: SCNVector3(0, 0.875, z + 0.28))
            deskBounce.name = "volumetricRowDeskBounceReturn\(row)"
            deskBounce.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(deskBounce)

            let seatBackBreak = box(width: 5.86, height: 0.16, length: 0.012, color: bodyOcclusion.withAlphaComponent(0.1), position: SCNVector3(0, 0.98, z + 0.58))
            seatBackBreak.name = "volumetricRowSeatBackSilhouetteBreak\(row)"
            seatBackBreak.eulerAngles.y = row % 2 == 0 ? -0.02 : 0.02
            root.addChildNode(seatBackBreak)

            let windowRim = box(width: 0.045, height: 0.78, length: 1.12, color: rimBlue, position: SCNVector3(2.82, 1.28, z + 0.12))
            windowRim.name = "volumetricRowWindowRimOnBodies\(row)"
            windowRim.eulerAngles = SCNVector3(-0.04, -0.32, -0.08)
            root.addChildNode(windowRim)
        }

        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.12
                let bodyPocket = sphere(radius: 0.13, color: bodyOcclusion.withAlphaComponent(0.11), position: SCNVector3(x, 0.72, z + 0.24), scale: SCNVector3(1.55, 0.62, 0.28))
                bodyPocket.name = "volumetricSeatBodyPocket_\(row)_\(column)"
                bodyPocket.eulerAngles.y = Float(((row * 4 + column) % 5) - 2) * 0.035
                root.addChildNode(bodyPocket)
            }
        }

        for index in 0..<8 {
            let mote = sphere(
                radius: 0.006 + CGFloat(index % 3) * 0.0015,
                color: warmDust.withAlphaComponent(0.12),
                position: SCNVector3(-2.65 + Float(index) * 0.74, 1.08 + Float(index % 4) * 0.16, -3.95 + Float(index % 3) * 0.62),
                scale: SCNVector3(1.4, 0.55, 0.5)
            )
            mote.name = "volumetricClassroomDustMote\(index)"
            mote.runAction(.repeatForever(.sequence([
                .moveBy(x: CGFloat((index % 3) - 1) * 0.008, y: 0.028, z: 0.012, duration: 1.6 + Double(index % 4) * 0.16),
                .moveBy(x: -CGFloat((index % 3) - 1) * 0.008, y: -0.028, z: -0.012, duration: 1.8 + Double(index % 5) * 0.14)
            ])), forKey: "volumetric_classroom_dust")
            root.addChildNode(mote)
        }

        for index in 0..<5 {
            let boardBloom = box(width: 0.8 + CGFloat(index % 2) * 0.16, height: 0.28, length: 0.012, color: chalkGreen, position: SCNVector3(-1.9 + Float(index) * 0.95, 1.72 + Float(index % 2) * 0.12, -5.72))
            boardBloom.name = "volumetricBlackboardChalkBloom\(index)"
            boardBloom.eulerAngles.y = -0.04 + Float(index) * 0.02
            root.addChildNode(boardBloom)
        }

        let teacherGate = box(width: 0.72, height: 1.45, length: 0.024, color: shadowInk.withAlphaComponent(0.14), position: SCNVector3(0, 1.1, -3.8))
        teacherGate.name = "volumetricTeacherMovingShadowGate"
        root.addChildNode(teacherGate)

        let pressureBloom = box(width: 1.15, height: 0.18, length: 0.018, color: pressureWarm, position: SCNVector3(0, 0.88, -2.9))
        pressureBloom.name = "volumetricTeacherPressureBloom"
        pressureBloom.eulerAngles.y = -0.08
        root.addChildNode(pressureBloom)

        let playerForeground = box(width: 4.4, height: 0.22, length: 0.018, color: shadowInk.withAlphaComponent(0.14), position: SCNVector3(-0.2, 0.78, 1.74))
        playerForeground.name = "volumetricPlayerForegroundCompression"
        playerForeground.eulerAngles.y = -0.04
        root.addChildNode(playerForeground)

        let aisleVolume = box(width: 0.16, height: 0.88, length: 6.8, color: windowBlue.withAlphaComponent(0.055), position: SCNVector3(-0.06, 1.18, -0.54))
        aisleVolume.name = "volumetricAisleSightVolume"
        aisleVolume.eulerAngles.y = -0.02
        root.addChildNode(aisleVolume)

        root.opacity = 0.12
        return root
    }

    private func makeTeacherPathShadowLayer() -> SCNNode {
        let root = SCNNode()
        let path: [SCNVector3] = [
            SCNVector3(-2.7, 0.043, -4.25), SCNVector3(2.6, 0.043, -3.2),
            SCNVector3(2.6, 0.043, -1.2), SCNVector3(1.2, 0.043, 0.45),
            SCNVector3(0.2, 0.043, 1.55), SCNVector3(-2.2, 0.043, 0.4),
            SCNVector3(-2.8, 0.043, -1.4), SCNVector3(0, 0.043, -4.35),
            SCNVector3(-3.45, 0.043, 4.25)
        ]

        for (index, point) in path.enumerated() {
            let shadow = box(width: 0.84, height: 0.005, length: 0.34, color: NSColor(calibratedWhite: 0.01, alpha: 0.22), position: point)
            shadow.name = "teacherPathPool\(index)"
            shadow.eulerAngles.y = Float(index % 5) * 0.16 - 0.28
            shadow.opacity = index == 0 ? 0.5 : 0.18
            root.addChildNode(shadow)
        }

        for index in 0..<(path.count - 1) {
            let start = path[index]
            let end = path[index + 1]
            let dx = end.x - start.x
            let dz = end.z - start.z
            let length = sqrt(dx * dx + dz * dz)
            let mid = SCNVector3((start.x + end.x) / 2, 0.041, (start.z + end.z) / 2)
            let streak = box(width: 0.18, height: 0.004, length: CGFloat(length), color: NSColor(calibratedRed: 0.12, green: 0.04, blue: 0.02, alpha: 0.12), position: mid)
            streak.name = "teacherPathStreak\(index)"
            streak.eulerAngles.y = atan2(dx, dz)
            root.addChildNode(streak)
        }
        return root
    }

    private func makeTeacherTargetSeatFocusLayer() -> SCNNode {
        let root = SCNNode()
        let focus = box(width: 1.1, height: 0.006, length: 0.82, color: NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.16, alpha: 0.2), position: SCNVector3(0, 0, 0))
        focus.name = "teacherTargetFocusWash"
        focus.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.16, duration: 0.42),
            .fadeOpacity(to: 0.46, duration: 0.58),
            .wait(duration: 0.38)
        ])), forKey: "target_focus_breathe")
        root.addChildNode(focus)

        for index in 0..<3 {
            let ring = SCNTorus(ringRadius: 0.34 + CGFloat(index) * 0.14, pipeRadius: 0.004)
            ring.firstMaterial = material(NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.24, alpha: 0.18 - CGFloat(index) * 0.035))
            let node = SCNNode(geometry: ring)
            node.name = "teacherTargetRing\(index)"
            node.position = SCNVector3(0, 0.008 + Float(index) * 0.002, 0)
            node.eulerAngles.x = Float.pi / 2
            node.runAction(.repeatForever(.sequence([
                .scale(to: 1.12 + CGFloat(index) * 0.06, duration: 0.7 + Double(index) * 0.16),
                .scale(to: 0.9, duration: 0.24),
                .wait(duration: 0.34)
            ])), forKey: "target_ring")
            root.addChildNode(node)
        }
        return root
    }

    private func makeClassroomSeatPressureLayer() -> SCNNode {
        let root = SCNNode()
        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25

                let pressure = box(width: 0.92, height: 0.004, length: 0.66, color: NSColor(calibratedWhite: 0.01, alpha: 0.18), position: SCNVector3(x, 0.046, z + 0.2))
                pressure.name = "seatPressurePool\(id)"
                pressure.eulerAngles.y = Float((row + column) % 5) * 0.035 - 0.07
                pressure.opacity = 0.14
                root.addChildNode(pressure)

                let targetLine = box(width: 0.78, height: 0.005, length: 0.045, color: NSColor(calibratedRed: 1.0, green: 0.52, blue: 0.18, alpha: 0.22), position: SCNVector3(x, 0.052, z - 0.18))
                targetLine.name = "seatTargetLine\(id)"
                targetLine.opacity = 0
                root.addChildNode(targetLine)

                let relationship = capsule(radius: 0.004, height: 0.64, color: NSColor(calibratedRed: 0.36, green: 0.88, blue: 1.0, alpha: 0.13), position: SCNVector3(x - 0.18, 0.86, z + 0.08), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                relationship.name = "seatRelationshipThread\(id)"
                relationship.eulerAngles.y = -0.1 + Float((row * 3 + column) % 6) * 0.035
                relationship.opacity = 0
                relationship.runAction(.repeatForever(.sequence([
                    .fadeOpacity(to: 0.08, duration: 0.9 + Double(id % 4) * 0.12),
                    .fadeOpacity(to: 0.32, duration: 1.3 + Double(id % 5) * 0.1)
                ])), forKey: "relationship_thread")
                root.addChildNode(relationship)
                id += 1
            }
        }
        return root
    }

    private func makeClassroomSurfaceReliefLayer() -> SCNNode {
        let root = SCNNode()
        let floorSheen = NSColor(calibratedRed: 0.9, green: 0.88, blue: 0.76, alpha: 0.075)
        let wallDamp = NSColor(calibratedRed: 0.18, green: 0.26, blue: 0.3, alpha: 0.08)
        let chalkDust = NSColor(calibratedWhite: 0.86, alpha: 0.11)
        let deskScratch = NSColor(calibratedRed: 1.0, green: 0.76, blue: 0.42, alpha: 0.085)
        let darkDust = NSColor(calibratedWhite: 0.0, alpha: 0.08)

        let floorFilm = box(width: 6.4, height: 0.004, length: 7.6, color: floorSheen, position: SCNVector3(-0.05, 0.058, 0.72))
        floorFilm.name = "surfaceFloorVarnishFilm"
        floorFilm.eulerAngles.y = -0.018
        root.addChildNode(floorFilm)

        let wallVeil = box(width: 0.008, height: 1.52, length: 4.8, color: wallDamp, position: SCNVector3(3.965, 1.34, 0.64))
        wallVeil.name = "surfaceWallHumidityVeil"
        root.addChildNode(wallVeil)

        let chalkFallout = box(width: 3.05, height: 0.004, length: 0.46, color: chalkDust, position: SCNVector3(0, 0.846, -5.66))
        chalkFallout.name = "surfaceBlackboardChalkFallout"
        chalkFallout.eulerAngles.y = 0.015
        root.addChildNode(chalkFallout)

        let teacherPath = box(width: 1.15, height: 0.005, length: 3.6, color: floorSheen.withAlphaComponent(0.09), position: SCNVector3(0.06, 0.064, -3.58))
        teacherPath.name = "surfaceTeacherPathPolish"
        teacherPath.eulerAngles.y = -0.04
        root.addChildNode(teacherPath)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let deskScratchRow = box(width: 5.25, height: 0.005, length: 0.026, color: deskScratch, position: SCNVector3(0, 0.836, z + 0.295))
            deskScratchRow.name = "surfaceDeskEdgeScratchRow\(row)"
            deskScratchRow.eulerAngles.y = row % 2 == 0 ? -0.012 : 0.018
            root.addChildNode(deskScratchRow)

            let chairPolish = box(width: 5.1, height: 0.005, length: 0.032, color: floorSheen.withAlphaComponent(0.065), position: SCNVector3(0, 0.912, z + 0.735))
            chairPolish.name = "surfaceChairBackHandPolishRow\(row)"
            chairPolish.eulerAngles.y = row % 2 == 0 ? 0.02 : -0.02
            root.addChildNode(chairPolish)

            let aisleDust = box(width: 5.65, height: 0.004, length: 0.18, color: darkDust, position: SCNVector3(0.03, 0.062, z + 0.58))
            aisleDust.name = "surfaceAisleDustSettlingRow\(row)"
            aisleDust.eulerAngles.y = -0.035 + Float(row) * 0.012
            root.addChildNode(aisleDust)
        }

        for index in 0..<9 {
            let glint = box(
                width: 0.34 + CGFloat(index % 3) * 0.08,
                height: 0.004,
                length: 0.012,
                color: floorSheen.withAlphaComponent(0.06),
                position: SCNVector3(-2.75 + Float(index % 3) * 2.18, 0.068, -2.4 + Float(index / 3) * 2.02)
            )
            glint.name = "surfaceMicroGlint\(index)"
            glint.eulerAngles.y = -0.08 + Float(index % 5) * 0.04
            root.addChildNode(glint)
        }

        root.opacity = 0.22
        return root
    }

    private func makeClassroomMotionEchoLayer() -> SCNNode {
        let root = SCNNode()
        let warmJolt = NSColor(calibratedRed: 1.0, green: 0.55, blue: 0.22, alpha: 0.1)
        let coolEcho = NSColor(calibratedRed: 0.36, green: 0.62, blue: 1.0, alpha: 0.09)
        let floorBreath = NSColor(calibratedWhite: 0.0, alpha: 0.09)
        let shoulderCut = NSColor(calibratedWhite: 0.0, alpha: 0.12)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let wake = box(width: 5.9, height: 0.006, length: 0.12, color: coolEcho, position: SCNVector3(0, 0.88, z + 0.22))
            wake.name = "motionRowAttentionWake\(row)"
            wake.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            wake.opacity = 0.08
            root.addChildNode(wake)

            let floor = box(width: 5.75, height: 0.004, length: 0.2, color: floorBreath, position: SCNVector3(0.02, 0.064, z + 0.58))
            floor.name = "motionFloorBreathRow\(row)"
            floor.eulerAngles.y = row % 2 == 0 ? 0.026 : -0.022
            floor.opacity = 0.06
            root.addChildNode(floor)
        }

        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25

                let deskJolt = box(width: 0.78, height: 0.005, length: 0.044, color: warmJolt, position: SCNVector3(x, 0.842, z + 0.22))
                deskJolt.name = "motionStudentDeskJolt\(id)"
                deskJolt.eulerAngles.y = Float((row + column) % 5) * 0.018 - 0.036
                deskJolt.opacity = 0.08
                root.addChildNode(deskJolt)

                let shoulder = box(width: 0.5, height: 0.012, length: 0.028, color: shoulderCut, position: SCNVector3(x, 0.99, z + 0.03))
                shoulder.name = "motionStudentShoulderEcho\(id)"
                shoulder.eulerAngles.y = Float(column - 1) * 0.018
                shoulder.opacity = 0.08
                root.addChildNode(shoulder)
                id += 1
            }
        }

        let teacherPush = sphere(radius: 0.24, color: warmJolt.withAlphaComponent(0.12), position: SCNVector3(0, 0.82, -2.4), scale: SCNVector3(2.2, 0.12, 1.4))
        teacherPush.name = "motionTeacherStepAirPush"
        root.addChildNode(teacherPush)

        let stillness = box(width: 6.2, height: 0.006, length: 6.6, color: NSColor(calibratedWhite: 0.0, alpha: 0.08), position: SCNVector3(0, 0.072, 0.18))
        stillness.name = "motionEventStillnessField"
        stillness.eulerAngles.y = -0.012
        root.addChildNode(stillness)

        let playerPulse = box(width: 1.08, height: 0.006, length: 0.52, color: warmJolt.withAlphaComponent(0.13), position: SCNVector3(-0.6, 0.842, 1.52))
        playerPulse.name = "motionPlayerDeskPulse"
        playerPulse.eulerAngles.y = -0.04
        root.addChildNode(playerPulse)

        root.opacity = 0.18
        return root
    }

    private func makeTeacherStudentPressureFieldLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "teacherStudentPressureFieldLayer"
        let authorityWarm = NSColor(calibratedRed: 1.0, green: 0.48, blue: 0.16, alpha: 0.12)
        let focusBlue = NSColor(calibratedRed: 0.34, green: 0.62, blue: 1.0, alpha: 0.1)
        let pressureInk = NSColor(calibratedWhite: 0.0, alpha: 0.13)
        let stillnessWhite = NSColor(calibratedRed: 0.78, green: 0.88, blue: 1.0, alpha: 0.075)

        let teacherGazeSweep = box(width: 1.05, height: 0.006, length: 5.8, color: authorityWarm, position: SCNVector3(0, 0.082, -1.45))
        teacherGazeSweep.name = "pressureFieldTeacherGazeSweep"
        teacherGazeSweep.eulerAngles.y = -0.18
        root.addChildNode(teacherGazeSweep)

        let teacherWake = sphere(radius: 0.25, color: authorityWarm.withAlphaComponent(0.12), position: SCNVector3(0, 0.088, -2.2), scale: SCNVector3(2.8, 0.08, 1.4))
        teacherWake.name = "pressureFieldTeacherWakePool"
        root.addChildNode(teacherWake)

        let targetBeam = box(width: 0.16, height: 0.007, length: 4.6, color: focusBlue, position: SCNVector3(0, 0.092, -1.6))
        targetBeam.name = "pressureFieldTargetBeam"
        targetBeam.eulerAngles.y = -0.04
        root.addChildNode(targetBeam)

        let playerThreat = box(width: 1.0, height: 0.006, length: 0.42, color: pressureInk.withAlphaComponent(0.16), position: SCNVector3(-0.6, 0.086, 1.48))
        playerThreat.name = "pressureFieldPlayerThreatPool"
        playerThreat.eulerAngles.y = -0.04
        root.addChildNode(playerThreat)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowSweep = box(width: 6.1, height: 0.005, length: 0.12, color: pressureInk.withAlphaComponent(0.1), position: SCNVector3(0, 0.076, z + 0.36))
            rowSweep.name = "pressureFieldRowSweep\(row)"
            rowSweep.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(rowSweep)

            let shoulderLine = box(width: 5.75, height: 0.016, length: 0.022, color: stillnessWhite, position: SCNVector3(0, 0.99, z + 0.04))
            shoulderLine.name = "pressureFieldRowShoulderFreeze\(row)"
            shoulderLine.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.016
            root.addChildNode(shoulderLine)

            let deskLip = box(width: 5.7, height: 0.006, length: 0.026, color: pressureInk.withAlphaComponent(0.12), position: SCNVector3(0, 0.846, z + 0.31))
            deskLip.name = "pressureFieldRowDeskLipTension\(row)"
            deskLip.eulerAngles.y = row % 2 == 0 ? -0.012 : 0.014
            root.addChildNode(deskLip)
        }

        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25

                let seatPin = sphere(radius: 0.055, color: authorityWarm.withAlphaComponent(0.1), position: SCNVector3(x, 0.078, z + 0.18), scale: SCNVector3(1.8, 0.08, 1.2))
                seatPin.name = "pressureFieldStudentSeatPin\(id)"
                seatPin.eulerAngles.y = Float((row + column) % 5) * 0.025 - 0.05
                root.addChildNode(seatPin)

                let gazeCut = box(width: 0.66, height: 0.006, length: 0.036, color: focusBlue.withAlphaComponent(0.11), position: SCNVector3(x, 0.994, z + 0.02))
                gazeCut.name = "pressureFieldStudentGazeCut\(id)"
                gazeCut.eulerAngles.y = Float(column - 1) * 0.02
                root.addChildNode(gazeCut)

                let deskLock = box(width: 0.72, height: 0.006, length: 0.04, color: pressureInk.withAlphaComponent(0.12), position: SCNVector3(x, 0.847, z + 0.26))
                deskLock.name = "pressureFieldStudentDeskLock\(id)"
                deskLock.eulerAngles.y = Float((row * 2 + column) % 5) * 0.018 - 0.036
                root.addChildNode(deskLock)
                id += 1
            }
        }

        for index in 0..<6 {
            let airSlice = box(width: 6.6 - CGFloat(index % 3) * 0.3, height: 0.11, length: 0.012, color: stillnessWhite.withAlphaComponent(0.055), position: SCNVector3(0, 1.08 + Float(index % 3) * 0.18, -4.6 + Float(index) * 1.82))
            airSlice.name = "pressureFieldAirStillnessSlice\(index)"
            airSlice.eulerAngles.y = -0.03 + Float(index) * 0.012
            root.addChildNode(airSlice)
        }

        root.opacity = 0.12
        return root
    }

    private func makeStudentEnvironmentIntegrationLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "studentEnvironmentIntegrationLayer"

        let contactInk = NSColor(calibratedWhite: 0.0, alpha: 0.16)
        let deskAmber = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.36, alpha: 0.1)
        let windowBlue = NSColor(calibratedRed: 0.52, green: 0.72, blue: 1.0, alpha: 0.11)
        let pressureWarm = NSColor(calibratedRed: 1.0, green: 0.28, blue: 0.14, alpha: 0.12)
        let breathCool = NSColor(calibratedRed: 0.68, green: 0.78, blue: 0.92, alpha: 0.06)
        let paperDust = NSColor(calibratedWhite: 0.9, alpha: 0.1)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let shoulderBand = box(width: 5.6, height: 0.012, length: 0.028, color: contactInk.withAlphaComponent(0.14), position: SCNVector3(0, 1.015, z + 0.17))
            shoulderBand.name = "studentEnvRowShoulderOcclusion\(row)"
            shoulderBand.eulerAngles.y = row % 2 == 0 ? -0.018 : 0.018
            root.addChildNode(shoulderBand)

            let deskLip = box(width: 5.8, height: 0.006, length: 0.04, color: contactInk.withAlphaComponent(0.14), position: SCNVector3(0, 0.858, z + 0.34))
            deskLip.name = "studentEnvRowDeskLipOcclusion\(row)"
            deskLip.eulerAngles.y = row % 2 == 0 ? 0.012 : -0.014
            root.addChildNode(deskLip)

            let windowAbsorb = box(width: 5.1, height: 0.16, length: 0.012, color: windowBlue, position: SCNVector3(-0.12, 1.16, z - 0.08))
            windowAbsorb.name = "studentEnvRowWindowLightAbsorb\(row)"
            windowAbsorb.eulerAngles.y = row % 2 == 0 ? -0.035 : 0.025
            root.addChildNode(windowAbsorb)

            let breathVeil = box(width: 5.2, height: 0.11, length: 0.012, color: breathCool, position: SCNVector3(0, 1.02, z + 0.58))
            breathVeil.name = "studentEnvRowBreathVeil\(row)"
            breathVeil.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.022
            breathVeil.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.05, duration: 1.0 + Double(row) * 0.08),
                .fadeOpacity(to: 0.18, duration: 1.35 + Double(row) * 0.1)
            ])), forKey: "student_env_row_breath")
            root.addChildNode(breathVeil)

            let floorUnify = box(width: 5.5, height: 0.004, length: 0.18, color: deskAmber.withAlphaComponent(0.08), position: SCNVector3(0.02, 0.066, z + 0.64))
            floorUnify.name = "studentEnvRowFloorBounce\(row)"
            floorUnify.eulerAngles.y = -0.02 + Float(row) * 0.01
            root.addChildNode(floorUnify)

            let windowRake = box(width: 5.4, height: 0.18, length: 0.012, color: windowBlue.withAlphaComponent(0.08), position: SCNVector3(-0.28, 1.08, z + 0.28))
            windowRake.name = "studentEnvRowWindowRakeWrap\(row)"
            windowRake.eulerAngles.y = row % 2 == 0 ? -0.055 : 0.045
            root.addChildNode(windowRake)

            let rowCast = box(width: 5.65, height: 0.004, length: 0.22, color: contactInk.withAlphaComponent(0.12), position: SCNVector3(0.04, 0.064, z + 0.44))
            rowCast.name = "studentEnvRowUnifiedCastShadow\(row)"
            rowCast.eulerAngles.y = row % 2 == 0 ? -0.022 : 0.018
            root.addChildNode(rowCast)

            let deskReflection = box(width: 5.45, height: 0.004, length: 0.038, color: deskAmber.withAlphaComponent(0.09), position: SCNVector3(0.02, 0.874, z + 0.18))
            deskReflection.name = "studentEnvRowDeskReflectionWrap\(row)"
            deskReflection.eulerAngles.y = row % 2 == 0 ? 0.014 : -0.018
            root.addChildNode(deskReflection)
        }

        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25

                let bodyContact = sphere(radius: 0.16, color: contactInk.withAlphaComponent(0.14), position: SCNVector3(x, 0.082, z + 0.24), scale: SCNVector3(2.6, 0.08, 1.3))
                bodyContact.name = "studentEnvSeatBodyContact\(id)"
                bodyContact.eulerAngles.y = Float((row + column) % 5) * 0.035 - 0.07
                root.addChildNode(bodyContact)

                let deskOcclusion = box(width: 0.74, height: 0.006, length: 0.06, color: contactInk.withAlphaComponent(0.13), position: SCNVector3(x, 0.868, z + 0.2))
                deskOcclusion.name = "studentEnvSeatDeskOcclusion\(id)"
                deskOcclusion.eulerAngles.y = Float(column - 1) * 0.012
                root.addChildNode(deskOcclusion)

                let rim = capsule(radius: 0.0035, height: 0.62, color: windowBlue.withAlphaComponent(0.12), position: SCNVector3(x - 0.18, 1.02, z + 0.05), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
                rim.name = "studentEnvSeatWindowRim\(id)"
                rim.eulerAngles.y = -0.06 + Float(row + column) * 0.012
                root.addChildNode(rim)

                let stressHalo = sphere(radius: 0.13, color: pressureWarm, position: SCNVector3(x, 0.982, z + 0.08), scale: SCNVector3(1.9, 0.22, 0.75))
                stressHalo.name = "studentEnvSeatStressHalo\(id)"
                root.addChildNode(stressHalo)

                let paperMote = sphere(radius: 0.006, color: paperDust, position: SCNVector3(x + 0.16, 0.892, z + 0.28), scale: SCNVector3(1.4, 0.5, 1))
                paperMote.name = "studentEnvSeatPaperDust\(id)"
                paperMote.runAction(.repeatForever(.sequence([
                    .moveBy(x: CGFloat((id % 3) - 1) * 0.004, y: 0.012, z: 0.006, duration: 1.0 + Double(id % 4) * 0.08),
                    .moveBy(x: -CGFloat((id % 3) - 1) * 0.004, y: -0.012, z: -0.006, duration: 1.2 + Double(id % 5) * 0.08)
                ])), forKey: "student_env_paper_mote")
                root.addChildNode(paperMote)

                let shoulderWrap = box(width: 0.58, height: 0.12, length: 0.008, color: windowBlue.withAlphaComponent(0.11), position: SCNVector3(x - 0.08, 1.04, z + 0.02))
                shoulderWrap.name = "studentEnvSeatShoulderLightWrap\(id)"
                shoulderWrap.eulerAngles.y = -0.08 + Float(column) * 0.018
                root.addChildNode(shoulderWrap)

                let deskSkinBounce = sphere(radius: 0.052, color: deskAmber.withAlphaComponent(0.08), position: SCNVector3(x + 0.02, 0.852, z + 0.12), scale: SCNVector3(2.4, 0.12, 0.8))
                deskSkinBounce.name = "studentEnvSeatDeskSkinBounce\(id)"
                deskSkinBounce.eulerAngles.y = Float((row + column) % 5) * 0.025 - 0.05
                root.addChildNode(deskSkinBounce)

                let floorEcho = sphere(radius: 0.09, color: windowBlue.withAlphaComponent(0.065), position: SCNVector3(x - 0.02, 0.066, z + 0.62), scale: SCNVector3(2.4, 0.06, 0.95))
                floorEcho.name = "studentEnvSeatFloorLightEcho\(id)"
                floorEcho.eulerAngles.y = Float((row * 2 + column) % 7) * 0.03 - 0.09
                root.addChildNode(floorEcho)

                let silhouetteGround = box(width: 0.68, height: 0.004, length: 0.28, color: contactInk.withAlphaComponent(0.13), position: SCNVector3(x + 0.04, 0.061, z + 0.42))
                silhouetteGround.name = "studentEnvSeatSilhouetteGrounding\(id)"
                silhouetteGround.eulerAngles.y = Float(column - 1) * 0.025
                root.addChildNode(silhouetteGround)

                id += 1
            }
        }

        let teacherOcclusionBridge = box(width: 5.8, height: 0.006, length: 0.42, color: contactInk.withAlphaComponent(0.16), position: SCNVector3(0, 0.082, -1.1))
        teacherOcclusionBridge.name = "studentEnvTeacherOcclusionBridge"
        teacherOcclusionBridge.eulerAngles.y = -0.018
        root.addChildNode(teacherOcclusionBridge)

        let rowLightSpine = box(width: 0.024, height: 0.82, length: 6.9, color: windowBlue.withAlphaComponent(0.09), position: SCNVector3(-3.05, 1.28, 0.72))
        rowLightSpine.name = "studentEnvWindowRowLightSpine"
        root.addChildNode(rowLightSpine)

        root.opacity = 0.16
        return root
    }

    private func makeCinematicMaterialUnificationLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "cinematicMaterialUnificationLayer"

        let floorWet = NSColor(calibratedRed: 0.62, green: 0.78, blue: 1.0, alpha: 0.07)
        let varnishWarm = NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.34, alpha: 0.08)
        let chalkOil = NSColor(calibratedRed: 0.72, green: 0.88, blue: 0.68, alpha: 0.08)
        let glassBlue = NSColor(calibratedRed: 0.46, green: 0.68, blue: 1.0, alpha: 0.08)
        let uniformRim = NSColor(calibratedRed: 0.45, green: 0.58, blue: 0.92, alpha: 0.075)
        let contactDark = NSColor(calibratedWhite: 0.0, alpha: 0.1)
        let paperWhite = NSColor(calibratedWhite: 1.0, alpha: 0.1)

        for index in 0..<7 {
            let floor = box(
                width: 5.9 - CGFloat(index % 2) * 0.24,
                height: 0.003,
                length: 0.12 + CGFloat(index % 3) * 0.035,
                color: floorWet,
                position: SCNVector3(0.02, 0.071, -4.45 + Float(index) * 1.5)
            )
            floor.name = "materialUnityFloorWetSheen\(index)"
            floor.eulerAngles.y = -0.04 + Float(index) * 0.014
            root.addChildNode(floor)
        }

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let deskVarnish = box(width: 5.72, height: 0.004, length: 0.032, color: varnishWarm, position: SCNVector3(0, 0.842, z + 0.31))
            deskVarnish.name = "materialUnityDeskVarnishRow\(row)"
            deskVarnish.eulerAngles.y = row % 2 == 0 ? -0.016 : 0.018
            root.addChildNode(deskVarnish)

            let underside = box(width: 5.55, height: 0.004, length: 0.11, color: contactDark.withAlphaComponent(0.12), position: SCNVector3(0, 0.665, z + 0.24))
            underside.name = "materialUnityDeskUndersideOcclusionRow\(row)"
            underside.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.018
            root.addChildNode(underside)

            let uniformRowRim = box(width: 5.4, height: 0.12, length: 0.012, color: uniformRim, position: SCNVector3(0, 1.02, z + 0.08))
            uniformRowRim.name = "materialUnityUniformRimRow\(row)"
            uniformRowRim.eulerAngles.y = row % 2 == 0 ? 0.02 : -0.024
            root.addChildNode(uniformRowRim)
        }

        var id = 0
        for row in 0..<5 {
            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4
                let z = Float(row) * 1.45 - 2.25

                let paperCatch = box(width: 0.34, height: 0.004, length: 0.018, color: paperWhite, position: SCNVector3(x - 0.18, 0.862, z - 0.24))
                paperCatch.name = "materialUnitySeatPaperCatch\(id)"
                paperCatch.eulerAngles.y = -0.12 + Float((row + column) % 5) * 0.04
                root.addChildNode(paperCatch)

                let handOil = sphere(radius: 0.03, color: varnishWarm.withAlphaComponent(0.07), position: SCNVector3(x + 0.08, 0.858, z + 0.12), scale: SCNVector3(2.0, 0.16, 0.75))
                handOil.name = "materialUnitySeatHandOilBloom\(id)"
                root.addChildNode(handOil)

                let shoeMirror = box(width: 0.42, height: 0.003, length: 0.08, color: floorWet.withAlphaComponent(0.06), position: SCNVector3(x, 0.064, z + 0.62))
                shoeMirror.name = "materialUnitySeatShoeMirror\(id)"
                shoeMirror.eulerAngles.y = Float((row * 3 + column) % 7) * 0.04 - 0.12
                root.addChildNode(shoeMirror)

                id += 1
            }
        }

        for index in 0..<6 {
            let chalk = box(width: 0.62 + CGFloat(index % 2) * 0.22, height: 0.018, length: 0.006, color: chalkOil, position: SCNVector3(-1.9 + Float(index) * 0.76, 1.48 + Float(index % 3) * 0.16, -5.976))
            chalk.name = "materialUnityBlackboardChalkOil\(index)"
