        }

        for index in 0..<5 {
            let glass = box(width: 0.012, height: 1.24 - CGFloat(index % 2) * 0.16, length: 0.54, color: glassBlue, position: SCNVector3(3.938, 1.44 + Float(index % 2) * 0.14, -3.9 + Float(index) * 1.9))
            glass.name = "materialUnityWindowFresnel\(index)"
            glass.eulerAngles.z = -0.02 + Float(index) * 0.01
            glass.geometry?.firstMaterial?.emission.contents = glassBlue.withAlphaComponent(0.04)
