        let playerDeskMaterialBridge = box(width: 1.15, height: 0.004, length: 0.42, color: varnishWarm.withAlphaComponent(0.09), position: SCNVector3(-0.58, 0.856, 1.54))
        playerDeskMaterialBridge.name = "materialUnityPlayerDeskBridge"
        playerDeskMaterialBridge.eulerAngles.y = -0.04
        root.addChildNode(playerDeskMaterialBridge)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let woodEndgrain = box(width: 5.58, height: 0.006, length: 0.024, color: varnishWarm.withAlphaComponent(0.07), position: SCNVector3(0, 0.858, z + 0.57))
            woodEndgrain.name = "materialUnityWoodEndgrainResponse\(row)"
            woodEndgrain.eulerAngles.y = row % 2 == 0 ? -0.02 : 0.024
            root.addChildNode(woodEndgrain)

            let clothThread = box(width: 5.2, height: 0.1, length: 0.012, color: uniformRim.withAlphaComponent(0.06), position: SCNVector3(0, 1.12, z + 0.1))
            clothThread.name = "materialUnityClothThreadSheen\(row)"
            clothThread.eulerAngles.y = row % 2 == 0 ? 0.025 : -0.02
            root.addChildNode(clothThread)

            let metalCold = box(width: 5.7, height: 0.005, length: 0.018, color: glassBlue.withAlphaComponent(0.06), position: SCNVector3(0, 0.53, z + 0.38))
            metalCold.name = "materialUnityMetalColdGlintRow\(row)"
            metalCold.eulerAngles.y = Float(row % 3 - 1) * 0.025
            root.addChildNode(metalCold)
        }

        for index in 0..<8 {
            let paperFiber = box(width: 0.52 + CGFloat(index % 3) * 0.09, height: 0.0035, length: 0.01, color: paperWhite.withAlphaComponent(0.08), position: SCNVector3(-2.6 + Float(index) * 0.74, 0.872, -1.95 + Float(index % 4) * 1.42))
            paperFiber.name = "materialUnityPaperFiberResponse\(index)"
            paperFiber.eulerAngles.y = -0.12 + Float(index % 6) * 0.045
