        }

        for index in 0..<7 {
            let skinRim = box(width: 0.44 + CGFloat(index % 2) * 0.08, height: 0.035, length: 0.01, color: NSColor(calibratedRed: 1.0, green: 0.66, blue: 0.46, alpha: 0.055), position: SCNVector3(-2.3 + Float(index) * 0.78, 1.08 + Float(index % 3) * 0.09, -1.7 + Float(index % 4) * 1.36))
            skinRim.name = "materialUnitySkinSweatRim\(index)"
            skinRim.eulerAngles.y = -0.08 + Float(index % 5) * 0.04
