    }

    private func makeEnvironmentReflectionCatcherLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "environmentReflectionCatcherLayer"

        let floorCool = NSColor(calibratedRed: 0.52, green: 0.72, blue: 1.0, alpha: 0.08)
        let deskWarm = NSColor(calibratedRed: 1.0, green: 0.68, blue: 0.34, alpha: 0.09)
        let windowGhost = NSColor(calibratedRed: 0.48, green: 0.7, blue: 1.0, alpha: 0.07)
        let phoneBlue = NSColor(calibratedRed: 0.16, green: 0.36, blue: 1.0, alpha: 0.1)
        let pressureWarm = NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.18, alpha: 0.08)
        let contactInk = NSColor(calibratedWhite: 0.0, alpha: 0.12)

        var id = 0
        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let rowFloorWash = box(width: 5.8, height: 0.003, length: 0.16, color: floorCool.withAlphaComponent(0.055), position: SCNVector3(0, 0.069, z + 0.58))
            rowFloorWash.name = "reflectionRowFloorWash\(row)"
            rowFloorWash.eulerAngles.y = row % 2 == 0 ? -0.026 : 0.022
            root.addChildNode(rowFloorWash)

            let rowDeskSheen = box(width: 5.65, height: 0.004, length: 0.032, color: deskWarm.withAlphaComponent(0.07), position: SCNVector3(0, 0.874, z + 0.28))
            rowDeskSheen.name = "reflectionRowDeskSheen\(row)"
            rowDeskSheen.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.016
            root.addChildNode(rowDeskSheen)

            for column in 0..<4 {
                if row == 2 && column == 1 { continue }
                let x = Float(column) * 1.2 - 2.4

                let floorBody = sphere(radius: 0.12, color: floorCool, position: SCNVector3(x, 0.071, z + 0.58), scale: SCNVector3(2.4, 0.08, 0.82))
                floorBody.name = "reflectionSeatFloorBody\(id)"
                floorBody.eulerAngles.y = Float((row + column) % 5) * 0.035 - 0.07
                root.addChildNode(floorBody)

                let deskBody = box(width: 0.56, height: 0.004, length: 0.11, color: deskWarm, position: SCNVector3(x, 0.876, z + 0.22))
                deskBody.name = "reflectionSeatDeskBody\(id)"
                deskBody.eulerAngles.y = Float(column - 1) * 0.018
                root.addChildNode(deskBody)

                let windowBody = box(width: 0.012, height: 0.46, length: 0.18, color: windowGhost, position: SCNVector3(3.91, 1.08, z + 0.08))
                windowBody.name = "reflectionSeatWindowGhost\(id)"
                windowBody.eulerAngles.z = Float(row - 2) * 0.012
                root.addChildNode(windowBody)

                let phonePool = box(width: 0.34, height: 0.004, length: 0.12, color: phoneBlue, position: SCNVector3(x + 0.15, 0.878, z + 0.12))
                phonePool.name = "reflectionSeatPhonePool\(id)"
                phonePool.eulerAngles.y = 0.16
                root.addChildNode(phonePool)

                let pressureEdge = box(width: 0.62, height: 0.004, length: 0.026, color: pressureWarm, position: SCNVector3(x, 0.882, z + 0.02))
                pressureEdge.name = "reflectionSeatPressureEdge\(id)"
                pressureEdge.eulerAngles.y = Float((row * 2 + column) % 5) * 0.018 - 0.036
                root.addChildNode(pressureEdge)

                id += 1
            }
        }

        let teacherFloor = sphere(radius: 0.2, color: pressureWarm.withAlphaComponent(0.1), position: SCNVector3(0, 0.072, -3.25), scale: SCNVector3(3.0, 0.08, 1.05))
        teacherFloor.name = "reflectionTeacherFloorGhost"
        root.addChildNode(teacherFloor)

        let boardFloor = box(width: 3.9, height: 0.003, length: 0.22, color: windowGhost.withAlphaComponent(0.06), position: SCNVector3(0, 0.07, -4.72))
        boardFloor.name = "reflectionBlackboardFloorGhost"
        boardFloor.eulerAngles.y = -0.018
        root.addChildNode(boardFloor)

        let playerDesk = box(width: 1.24, height: 0.004, length: 0.38, color: deskWarm.withAlphaComponent(0.1), position: SCNVector3(-0.6, 0.878, 1.46))
        playerDesk.name = "reflectionPlayerDeskCatch"
        playerDesk.eulerAngles.y = -0.04
        root.addChildNode(playerDesk)

        let playerFloor = sphere(radius: 0.16, color: contactInk.withAlphaComponent(0.13), position: SCNVector3(-0.58, 0.07, 1.62), scale: SCNVector3(2.4, 0.08, 1.0))
        playerFloor.name = "reflectionPlayerFloorContact"
        playerFloor.eulerAngles.y = -0.06
        root.addChildNode(playerFloor)

        root.opacity = 0.12
        return root
    }

    private func makeClassroomContactShadowLayer() -> SCNNode {
        let root = SCNNode()
        var id = 0
        let softContact = NSColor(calibratedWhite: 0.01, alpha: 0.18)
        let deepContact = NSColor(calibratedWhite: 0.0, alpha: 0.24)
        let deskOcclusion = NSColor(calibratedRed: 0.025, green: 0.018, blue: 0.012, alpha: 0.2)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.05
            let rowVeil = box(
                width: 6.1,
                height: 0.004,
                length: 0.28,
                color: NSColor(calibratedWhite: 0.0, alpha: 0.08),
                position: SCNVector3(0, 0.051, z + 0.54)
            )
            rowVeil.name = "rowDepthContactVeil\(row)"
            rowVeil.eulerAngles.y = row % 2 == 0 ? 0.02 : -0.025
            root.addChildNode(rowVeil)

            for column in 0..<4 {
                let x = Float(column) * 1.2 - 2.4
                let deskZ = Float(row) * 1.45 - 2.25
                if row == 2 && column == 1 {
                    let playerShadow = box(width: 1.0, height: 0.004, length: 0.88, color: softContact, position: SCNVector3(x, 0.053, deskZ + 0.38))
                    playerShadow.name = "playerSeatContactShadow"
                    playerShadow.eulerAngles.y = -0.03
                    root.addChildNode(playerShadow)
                    continue
                }

                let seatCore = box(width: 0.88, height: 0.004, length: 0.74, color: softContact, position: SCNVector3(x, 0.054, deskZ + 0.38))
                seatCore.name = "seatContactCore\(id)"
                seatCore.eulerAngles.y = Float((row + column) % 5) * 0.018 - 0.036
                root.addChildNode(seatCore)

                let floorStretch = box(width: 1.05, height: 0.004, length: 0.12, color: NSColor(calibratedWhite: 0.0, alpha: 0.13), position: SCNVector3(x + 0.04, 0.056, deskZ + 0.76))
                floorStretch.name = "studentFloorStretchShadow\(id)"
                floorStretch.eulerAngles.y = -0.08 + Float((row * 2 + column) % 5) * 0.035
                root.addChildNode(floorStretch)

                let bodyDesk = box(width: 0.58, height: 0.006, length: 0.055, color: deepContact, position: SCNVector3(x, 0.835, deskZ + 0.19))
                bodyDesk.name = "bodyDeskContact\(id)"
                bodyDesk.eulerAngles.y = Float(column - 1) * 0.018
                root.addChildNode(bodyDesk)

                let frontBand = box(width: 0.86, height: 0.006, length: 0.032, color: deskOcclusion, position: SCNVector3(x, 0.824, deskZ + 0.31))
                frontBand.name = "deskFrontOcclusionBand\(id)"
                root.addChildNode(frontBand)

                let chairBack = box(width: 0.62, height: 0.28, length: 0.01, color: NSColor(calibratedWhite: 0.0, alpha: 0.1), position: SCNVector3(x, 0.88, deskZ + 0.73))
                chairBack.name = "chairBackOcclusion\(id)"
                root.addChildNode(chairBack)

                for (legIndex, offset) in [(-0.34, -0.2), (0.34, -0.2), (-0.34, 0.2), (0.34, 0.2)].enumerated() {
                    let legShadow = box(
                        width: 0.18,
                        height: 0.004,
                        length: 0.09,
                        color: NSColor(calibratedWhite: 0.0, alpha: 0.14),
                        position: SCNVector3(x + Float(offset.0), 0.055, deskZ + Float(offset.1))
                    )
                    legShadow.name = "deskLegContactShadow\(id)_\(legIndex)"
                    legShadow.eulerAngles.y = Float(legIndex) * 0.13
                    root.addChildNode(legShadow)
                }
                id += 1
            }
        }
        return root
    }

    private func makeLighting() -> SCNNode {
        let root = SCNNode()
        let ambient = SCNLight()
        ambient.type = .ambient
        ambient.intensity = 210
        ambient.color = NSColor(calibratedRed: 0.62, green: 0.67, blue: 0.78, alpha: 1)
        ambientNode.light = ambient
        root.addChildNode(ambientNode)

        let keyLight = SCNLight()
        keyLight.type = .directional
        keyLight.intensity = 620
        keyLight.color = NSColor(calibratedRed: 1.0, green: 0.92, blue: 0.78, alpha: 1)
        configureShadow(for: keyLight, radius: 7, opacity: 0.42)
        keyLightNode.light = keyLight
        keyLightNode.eulerAngles = SCNVector3(-0.92, -0.35, -0.18)
        root.addChildNode(keyLightNode)

        let windowRim = SCNLight()
        windowRim.type = .directional
        windowRim.intensity = 260
        windowRim.color = NSColor(calibratedRed: 0.55, green: 0.72, blue: 1.0, alpha: 1)
        configureShadow(for: windowRim, radius: 9, opacity: 0.28)
        windowRimLightNode.light = windowRim
        windowRimLightNode.eulerAngles = SCNVector3(-0.2, 1.38, 0)
        root.addChildNode(windowRimLightNode)

        let teacherLight = SCNLight()
        teacherLight.type = .spot
        teacherLight.intensity = 0
        teacherLight.spotInnerAngle = 28
        teacherLight.spotOuterAngle = 70
        teacherLight.color = NSColor(calibratedRed: 1.0, green: 0.56, blue: 0.32, alpha: 1)
        configureShadow(for: teacherLight, radius: 5, opacity: 0.34)
        teacherShadowLightNode.light = teacherLight
        teacherShadowLightNode.position = SCNVector3(0, 2.65, -3.2)
        teacherShadowLightNode.eulerAngles = SCNVector3(-0.9, 0, 0)
        root.addChildNode(teacherShadowLightNode)

        let eventLight = SCNLight()
        eventLight.type = .omni
        eventLight.intensity = 0
        eventLight.color = NSColor(calibratedRed: 1.0, green: 0.38, blue: 0.22, alpha: 1)
        eventLight.attenuationStartDistance = 0.2
        eventLight.attenuationEndDistance = 5.2
        eventPulseLightNode.light = eventLight
        eventPulseLightNode.position = SCNVector3(-0.55, 1.35, 1.24)
        root.addChildNode(eventPulseLightNode)

        eventDeskWashNode.addChildNode(makeEventDeskWash())
        eventDeskWashNode.position = SCNVector3(-0.6, 0.824, 1.45)
        eventDeskWashNode.opacity = 0
        root.addChildNode(eventDeskWashNode)

        projectorBeamNode.addChildNode(makeProjectorBeam())
        projectorBeamNode.position = SCNVector3(0, 2.6, -4.0)
        projectorBeamNode.opacity = 0.18
        root.addChildNode(projectorBeamNode)

        characterBounceLightNode.addChildNode(makeCharacterEnvironmentBounceLayer())
        characterBounceLightNode.opacity = 0.18
        root.addChildNode(characterBounceLightNode)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.05

            let deskBounce = SCNLight()
            deskBounce.type = .omni
            deskBounce.intensity = 0
            deskBounce.color = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.42, alpha: 1)
            deskBounce.attenuationStartDistance = 0.15
            deskBounce.attenuationEndDistance = 2.1
            let deskNode = SCNNode()
            deskNode.name = "studentRowWarmPracticalLight\(row)"
            deskNode.light = deskBounce
            deskNode.position = SCNVector3(0, 0.94, z + 0.22)
            studentRowPracticalLightNodes.append(deskNode)
            root.addChildNode(deskNode)

            let windowRim = SCNLight()
            windowRim.type = .omni
            windowRim.intensity = 0
            windowRim.color = NSColor(calibratedRed: 0.42, green: 0.64, blue: 1.0, alpha: 1)
            windowRim.attenuationStartDistance = 0.2
            windowRim.attenuationEndDistance = 2.8
            let rimNode = SCNNode()
            rimNode.name = "studentRowCoolRimPracticalLight\(row)"
            rimNode.light = windowRim
            rimNode.position = SCNVector3(-2.9, 1.25, z + 0.16)
            studentRowPracticalLightNodes.append(rimNode)
            root.addChildNode(rimNode)
        }

        func addEnvironmentPracticalLight(name: String, color: NSColor, position: SCNVector3, attenuation: CGFloat) {
            let light = SCNLight()
            light.type = .omni
            light.intensity = 0
            light.color = color
            light.attenuationStartDistance = 0.15
            light.attenuationEndDistance = attenuation
            let node = SCNNode()
            node.name = name
            node.light = light
            node.position = position
            environmentPracticalLightNodes.append(node)
            root.addChildNode(node)
        }

        addEnvironmentPracticalLight(
            name: "environmentBlackboardChalkPracticalLight",
            color: NSColor(calibratedRed: 0.58, green: 0.88, blue: 0.52, alpha: 1),
            position: SCNVector3(0, 1.72, -5.26),
            attenuation: 4.4
        )
        addEnvironmentPracticalLight(
            name: "environmentBlackboardTrayWarmPracticalLight",
            color: NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.42, alpha: 1),
            position: SCNVector3(0, 0.92, -4.62),
            attenuation: 3.2
        )
        for (index, z) in [-4.0, -1.35, 1.35, 3.85].enumerated() {
            addEnvironmentPracticalLight(
                name: "environmentWindowCoolPracticalLight\(index)",
                color: NSColor(calibratedRed: 0.36, green: 0.58, blue: 1.0, alpha: 1),
                position: SCNVector3(3.1, 1.55, Float(z)),
                attenuation: 3.8
            )
        }
        addEnvironmentPracticalLight(
            name: "environmentFrontDoorAmberPracticalLight",
            color: NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.26, alpha: 1),
            position: SCNVector3(-3.42, 1.1, -5.32),
            attenuation: 3.4
        )
        addEnvironmentPracticalLight(
            name: "environmentRearDoorAmberPracticalLight",
            color: NSColor(calibratedRed: 0.78, green: 0.86, blue: 1.0, alpha: 1),
            position: SCNVector3(-3.42, 1.1, 4.58),
            attenuation: 3.6
        )
        addEnvironmentPracticalLight(
            name: "environmentFloorBouncePracticalLight",
            color: NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: 1),
            position: SCNVector3(0, 0.36, -0.42),
            attenuation: 5.8
        )

        for x in [-2.7, 0, 2.7] {
            for z in [-3.6, -0.4, 2.8] {
                let light = SCNLight()
                light.type = .omni
                light.intensity = 150
                light.color = NSColor(calibratedRed: 1.0, green: 0.95, blue: 0.82, alpha: 1)
                light.attenuationStartDistance = 0.4
                light.attenuationEndDistance = 7.0
                let node = SCNNode()
                node.light = light
                node.position = SCNVector3(Float(x), 3.15, Float(z))
                ceilingLightNodes.append(node)
                root.addChildNode(node)
            }
        }
        for z in [-1.8, 2.1] {
            let fan = makeCeilingFan(at: SCNVector3(0, 3.18, Float(z)))
            fanNodes.append(fan)
            root.addChildNode(fan)
        }
        return root
    }

    private func configureShadow(for light: SCNLight, radius: CGFloat, opacity: CGFloat) {
        light.castsShadow = true
        light.shadowMode = .deferred
        light.shadowRadius = radius
        light.shadowSampleCount = 16
        light.shadowMapSize = CGSize(width: 2048, height: 2048)
        light.shadowColor = NSColor(calibratedWhite: 0, alpha: opacity)
        light.shadowBias = 0.7
    }

    private func updateCinematicLighting(game: GameManager) {
        let lightLevel = game.classroomLightLevel
        let thirdPeriodBoost = game.currentPeriod == .third ? 0.82 : 1.0
        let eventIntensity = eventVisualIntensity(game: game)
        let pulse = min(1.0, eventIntensity.vignette)
        let lowLight = (1 - lightLevel).clamped(to: 0...1)
        let rainyFeeling = Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes)) > 0.46 || lightLevel < 0.6
        keyLightNode.light?.intensity = 430 + 220 * lightLevel
        keyLightNode.light?.color = game.teacher.isNearPlayer || pulse > 0.35
            ? NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.62, alpha: 1)
            : NSColor(calibratedRed: 1.0, green: 0.92, blue: 0.78, alpha: 1)
        windowRimLightNode.light?.intensity = lightLevel < 0.65 ? 420 : 240
        windowRimLightNode.light?.color = rainyFeeling
            ? NSColor(calibratedRed: 0.38, green: 0.58, blue: 1.0, alpha: 1)
            : NSColor(calibratedRed: 0.55, green: 0.72, blue: 1.0, alpha: 1)
        teacherShadowLightNode.light?.intensity = game.teacher.isNearPlayer ? 520 : 120
        teacherShadowLightNode.position = SCNVector3(teacherNode.position.x, 2.65, teacherNode.position.z + 0.65)
        teacherShadowLightNode.eulerAngles = teacherEulerAngles(from: teacherShadowLightNode.position, to: teacherNode.position)
        let warmAlert = game.teacher.isNearPlayer || pulse > 0.45
        let boardFocus = game.teacher.focusMode == .blackboard || game.currentPeriod == .third
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        let frontDoorOpen = game.frontDoorOpen ? 1.0 : 0.0
        let rearDoorOpen = game.rearDoorOpen ? 1.0 : 0.0
        let progress = Double(game.elapsedMinutes) / Double(max(1, game.settings.totalMinutes))

        for (index, node) in ceilingLightNodes.enumerated() {
            let flicker = game.currentPeriod == .third && index % 3 == game.currentTurn % 3 ? 0.72 : 1.0
            node.light?.intensity = 115 + 155 * lightLevel * thirdPeriodBoost * flicker
            node.light?.color = game.currentPeriod == .third
                ? NSColor(calibratedRed: 0.92, green: 0.9, blue: 0.78, alpha: 1)
                : NSColor(calibratedRed: 1.0, green: 0.95, blue: 0.82, alpha: 1)
        }

        for (index, node) in studentRowPracticalLightNodes.enumerated() {
            let row = index / 2
            let isWarmDesk = index % 2 == 0
            let rowDepth = Double(row) / 4.0
            let rowZ = Float(row) * 1.45 - 2.05
            let rowMates = game.classmates.filter { $0.seat.row == row }
            let anxiousLoad = Double(rowMates.filter { $0.state == .anxious || $0.state == .crying || $0.state == .covering }.count)
            let phoneLoad = Double(rowMates.filter { $0.state == .usingPhone }.count)
            let studyLoad = Double(rowMates.filter { $0.state == .studying }.count)
            let targetLoad = rowMates.contains { $0.id == game.selectedTeacherTarget?.id } ? 1.0 : 0.0
            let rowPressure = (anxiousLoad * 0.08 + phoneLoad * 0.05 + targetLoad * 0.14 + pulse * 0.12 + (game.teacher.isNearPlayer ? 0.08 : 0)).clamped(to: 0...0.42)

            if isWarmDesk {
                node.light?.intensity = CGFloat((18 + lightLevel * 34 + studyLoad * 4 + rowPressure * 75 + pulse * 28 + (game.currentPeriod == .third ? 14 : 0)).clamped(to: 8...110))
                node.light?.color = warmAlert
                    ? NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.34, alpha: 1)
                    : NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.42, alpha: 1)
                node.position = SCNVector3(0, Float(0.92 + rowPressure * 0.04), rowZ + 0.22 + Float(pulse * 0.025))
                node.light?.attenuationEndDistance = CGFloat(1.8 + rowDepth * 0.35 + rowPressure * 0.5)
            } else {
                node.light?.intensity = CGFloat((20 + lowLight * 58 + phoneLoad * 5 + rowDepth * 8 + (rainyFeeling ? 24 : 0) + pulse * 22 + targetLoad * 18).clamped(to: 6...130))
                node.light?.color = rainyFeeling
                    ? NSColor(calibratedRed: 0.32, green: 0.52, blue: 1.0, alpha: 1)
                    : NSColor(calibratedRed: 0.42, green: 0.64, blue: 1.0, alpha: 1)
                node.position = SCNVector3(Float(-2.9 + targetLoad * 0.18), Float(1.22 + lowLight * 0.08 + rowPressure * 0.04), rowZ + 0.16)
                node.light?.attenuationEndDistance = CGFloat(2.4 + lowLight * 0.5 + rowPressure * 0.4)
            }
        }

        for node in environmentPracticalLightNodes {
            let name = node.name ?? ""
            if name.contains("BlackboardChalk") {
                node.light?.intensity = CGFloat((18 + (boardFocus ? 150 : 32) + lowLight * 52 + pulse * 42).clamped(to: 12...260))
                node.light?.color = boardFocus
                    ? NSColor(calibratedRed: 0.58, green: 0.9, blue: 0.52, alpha: 1)
                    : NSColor(calibratedRed: 0.42, green: 0.64, blue: 0.42, alpha: 1)
                node.position = SCNVector3(Float(teacherNode.position.x * 0.08), Float(1.72 + pulse * 0.03), -5.26)
                node.light?.attenuationEndDistance = CGFloat(3.7 + lowLight * 0.6 + (boardFocus ? 0.5 : 0))
            } else if name.contains("BlackboardTrayWarm") {
                node.light?.intensity = CGFloat((12 + (boardFocus ? 82 : 22) + teacherNear * 24 + pulse * 34).clamped(to: 6...170))
                node.light?.color = warmAlert
                    ? NSColor(calibratedRed: 1.0, green: 0.56, blue: 0.3, alpha: 1)
                    : NSColor(calibratedRed: 1.0, green: 0.72, blue: 0.42, alpha: 1)
                node.position = SCNVector3(Float(teacherNode.position.x * 0.12), Float(0.92 + pulse * 0.02), -4.62)
                node.light?.attenuationEndDistance = CGFloat(2.8 + pulse * 0.35 + teacherNear * 0.25)
            } else if name.contains("WindowCool") {
                node.light?.intensity = CGFloat((24 + lowLight * 86 + (rainyFeeling ? 64 : 0) + pulse * 26 + progress * 22).clamped(to: 10...190))
                node.light?.color = rainyFeeling
                    ? NSColor(calibratedRed: 0.28, green: 0.5, blue: 1.0, alpha: 1)
                    : NSColor(calibratedRed: 0.42, green: 0.64, blue: 1.0, alpha: 1)
                node.position.x = Float(3.05 - pulse * 0.04)
                node.position.y = Float(1.48 + lowLight * 0.12 + (rainyFeeling ? 0.04 : 0))
                node.light?.attenuationEndDistance = CGFloat(3.3 + lowLight * 0.5 + (rainyFeeling ? 0.4 : 0))
            } else if name.contains("FrontDoorAmber") {
                node.light?.intensity = CGFloat((10 + frontDoorOpen * 145 + lowLight * 36 + pulse * 26 + teacherNear * 18).clamped(to: 0...210))
                node.light?.color = frontDoorOpen > 0
                    ? NSColor(calibratedRed: 1.0, green: 0.58, blue: 0.26, alpha: 1)
                    : NSColor(calibratedRed: 0.9, green: 0.5, blue: 0.28, alpha: 1)
                node.light?.attenuationEndDistance = CGFloat(2.7 + frontDoorOpen * 0.9 + pulse * 0.3)
            } else if name.contains("RearDoorAmber") {
                node.light?.intensity = CGFloat((8 + rearDoorOpen * 120 + lowLight * 34 + pulse * 22).clamped(to: 0...180))
                node.light?.color = rearDoorOpen > 0
                    ? NSColor(calibratedRed: 0.86, green: 0.92, blue: 1.0, alpha: 1)
                    : NSColor(calibratedRed: 0.62, green: 0.72, blue: 1.0, alpha: 1)
                node.light?.attenuationEndDistance = CGFloat(2.6 + rearDoorOpen * 0.9 + lowLight * 0.35)
            } else if name.contains("FloorBounce") {
                node.light?.intensity = CGFloat((28 + lowLight * 44 + (rainyFeeling ? 52 : 0) + teacherNear * 38 + pulse * 46 + (boardFocus ? 18 : 0)).clamped(to: 12...220))
                node.light?.color = rainyFeeling
                    ? NSColor(calibratedRed: 0.56, green: 0.72, blue: 1.0, alpha: 1)
                    : NSColor(calibratedRed: 1.0, green: 0.78, blue: 0.48, alpha: 1)
                node.position = SCNVector3(Float(teacherNode.position.x * 0.18), Float(0.34 + pulse * 0.015), Float(-0.42 + teacherNode.position.z * 0.05))
                node.light?.attenuationEndDistance = CGFloat(4.6 + lowLight * 0.8 + (rainyFeeling ? 0.8 : 0) + teacherNear * 0.4)
            }
        }

        scene.lightingEnvironment.intensity = CGFloat((0.36 + lightLevel * 0.18 - pulse * 0.05 + (game.teacher.isNearPlayer ? -0.035 : 0)).clamped(to: 0.28...0.62))
        scene.fogStartDistance = CGFloat((7.4 - lowLight * 1.6 - pulse * 0.6).clamped(to: 5.2...8.8))
        scene.fogEndDistance = CGFloat((28 - lowLight * 9.0 - pulse * 2.0 - (rainyFeeling ? 2.4 : 0)).clamped(to: 15...30))

        eventPulseLightNode.light?.intensity = CGFloat(40 + 260 * pulse + (game.teacher.isNearPlayer ? 90 : 0))
        eventPulseLightNode.light?.color = warmAlert
            ? NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.18, alpha: 1)
            : NSColor(calibratedRed: 0.32, green: 0.58, blue: 1.0, alpha: 1)
        eventDeskWashNode.opacity = CGFloat(0.08 + pulse * 0.48 + (game.teacher.isNearPlayer ? 0.18 : 0))
        eventDeskWashNode.eulerAngles.y = Float(game.currentTurn % 5) * 0.015 - 0.03
        projectorBeamNode.opacity = boardFocus ? 0.34 : 0.16
        podiumProjectorGlowNode.opacity = boardFocus ? CGFloat(0.24 + pulse * 0.22) : 0.1
    }

    private func makeCharacterEnvironmentBounceLayer() -> SCNNode {
        let root = SCNNode()
        root.name = "characterEnvironmentBounceLayer"
        let skinWarm = NSColor(calibratedRed: 1.0, green: 0.62, blue: 0.38, alpha: 0.09)
        let windowCool = NSColor(calibratedRed: 0.34, green: 0.58, blue: 1.0, alpha: 0.08)
        let chalkGreen = NSColor(calibratedRed: 0.58, green: 0.82, blue: 0.52, alpha: 0.07)
        let deskAmber = NSColor(calibratedRed: 1.0, green: 0.74, blue: 0.38, alpha: 0.08)
        let pressureWarm = NSColor(calibratedRed: 1.0, green: 0.32, blue: 0.14, alpha: 0.1)
        let wallLift = NSColor(calibratedWhite: 0.0, alpha: 0.08)

        for row in 0..<5 {
            let z = Float(row) * 1.45 - 2.25
            let skinBounce = box(width: 5.5, height: 0.004, length: 0.16, color: skinWarm, position: SCNVector3(0, 0.842, z + 0.18))
            skinBounce.name = "characterRowSkinBounce\(row)"
            skinBounce.eulerAngles.y = row % 2 == 0 ? 0.018 : -0.022
            root.addChildNode(skinBounce)

            let deskBounce = box(width: 5.9, height: 0.004, length: 0.09, color: deskAmber, position: SCNVector3(0, 0.818, z - 0.29))
            deskBounce.name = "deskWarmBounceBand\(row)"
            deskBounce.eulerAngles.y = row % 2 == 0 ? -0.012 : 0.016
            root.addChildNode(deskBounce)

            let coolCatch = box(width: 0.026, height: 0.42, length: 4.8, color: windowCool, position: SCNVector3(-3.74, 1.04, z + 0.18))
            coolCatch.name = "windowCoolCharacterCatch\(row)"
            root.addChildNode(coolCatch)

            let rowShadowLift = box(width: 5.7, height: 0.004, length: 0.12, color: wallLift, position: SCNVector3(0, 0.061, z + 0.58))
            rowShadowLift.name = "rowShadowLiftResponse\(row)"
            root.addChildNode(rowShadowLift)
        }

        for column in 0..<4 {
            let x = Float(column) * 1.2 - 2.4
            let boardBounce = box(width: 0.62, height: 0.006, length: 0.12, color: chalkGreen, position: SCNVector3(x, 0.836, -3.1))
            boardBounce.name = "blackboardChalkBounceColumn\(column)"
            boardBounce.eulerAngles.y = -0.03 + Float(column) * 0.018
            root.addChildNode(boardBounce)
        }

        let teacherFloorAura = sphere(radius: 0.42, color: pressureWarm, position: SCNVector3(0, 0.064, -3.2), scale: SCNVector3(1.8, 0.08, 1.1))
        teacherFloorAura.name = "teacherMovingBounceAura"
        root.addChildNode(teacherFloorAura)

        let teacherWallLift = box(width: 1.2, height: 0.72, length: 0.008, color: wallLift.withAlphaComponent(0.12), position: SCNVector3(0, 1.2, -5.955))
        teacherWallLift.name = "teacherWallBounceShadowLift"
        root.addChildNode(teacherWallLift)

        let playerDeskReturn = box(width: 1.05, height: 0.006, length: 0.42, color: deskAmber.withAlphaComponent(0.12), position: SCNVector3(-0.6, 0.83, 1.45))
        playerDeskReturn.name = "playerDeskReturnBounce"
        playerDeskReturn.eulerAngles.y = -0.04
        root.addChildNode(playerDeskReturn)

        for index in 0..<8 {
            let glint = sphere(radius: 0.018 + CGFloat(index % 3) * 0.004, color: NSColor(calibratedRed: 1.0, green: 0.86, blue: 0.58, alpha: 0.08), position: SCNVector3(-2.8 + Float(index) * 0.8, 0.846, -2.9 + Float(index % 4) * 1.12), scale: SCNVector3(1.8, 0.18, 0.8))
            glint.name = "deskEdgeBounceGlint\(index)"
            glint.runAction(.repeatForever(.sequence([
                .fadeOpacity(to: 0.04, duration: 1.2 + Double(index % 3) * 0.18),
                .fadeOpacity(to: 0.22, duration: 1.6 + Double(index % 4) * 0.14)
            ])), forKey: "desk_bounce_glint")
            root.addChildNode(glint)
        }

        root.opacity = 0.18
        return root
    }

    private func updateCharacterEnvironmentBounce(game: GameManager, eventIntensity: (blur: Double, vignette: Double, desaturation: Double)) {
        let lowLight = (1 - game.classroomLightLevel).clamped(to: 0...1)
        let event = eventIntensity.vignette.clamped(to: 0...1)
        let teacherPressure = (game.teacher.institutionalPressure / 100).clamped(to: 0...1)
        let boardFocus = game.teacher.focusMode == .blackboard || game.cameraPose == .board || game.currentPeriod == .third
        let teacherNear = game.teacher.isNearPlayer ? 1.0 : 0.0
        characterBounceLightNode.opacity = CGFloat((0.14 + lowLight * 0.22 + event * 0.18 + teacherPressure * 0.12).clamped(to: 0.1...0.62))
        characterBounceLightNode.position.y = Float(event * 0.006)
        characterBounceLightNode.eulerAngles.y = Float(event * 0.012 + teacherPressure * 0.008)

        for row in 0..<5 {
            let rowDepth = Double(row) / 4.0
            characterBounceLightNode.childNode(withName: "characterRowSkinBounce\(row)", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.18 + teacherPressure * 0.1 + event * 0.12 + rowDepth * 0.035).clamped(to: 0.04...0.46))
            characterBounceLightNode.childNode(withName: "deskWarmBounceBand\(row)", recursively: true)?.opacity = CGFloat((0.07 + game.classroomLightLevel * 0.08 + teacherNear * 0.14 + event * 0.1).clamped(to: 0.04...0.4))
            characterBounceLightNode.childNode(withName: "windowCoolCharacterCatch\(row)", recursively: true)?.opacity = CGFloat((0.05 + lowLight * 0.22 + (game.currentPeriod == .third ? 0.16 : 0) + rowDepth * 0.04).clamped(to: 0.03...0.44))
            characterBounceLightNode.childNode(withName: "rowShadowLiftResponse\(row)", recursively: true)?.opacity = CGFloat((0.06 + event * 0.12 + teacherPressure * 0.08 + lowLight * 0.1).clamped(to: 0.03...0.32))
        }

        for column in 0..<4 {
            let bounce = characterBounceLightNode.childNode(withName: "blackboardChalkBounceColumn\(column)", recursively: true)
            bounce?.opacity = CGFloat((boardFocus ? 0.18 + event * 0.12 + lowLight * 0.08 : 0.04).clamped(to: 0.02...0.42))
            bounce?.position.z = Float(-3.1 + event * 0.03)
        }

        let teacherAura = characterBounceLightNode.childNode(withName: "teacherMovingBounceAura", recursively: true)
        teacherAura?.position = SCNVector3(teacherNode.position.x, 0.064, teacherNode.position.z + 0.1)
        teacherAura?.opacity = CGFloat((0.12 + teacherPressure * 0.24 + teacherNear * 0.22 + event * 0.16).clamped(to: 0.06...0.62))
        teacherAura?.scale = SCNVector3(1.8 + CGFloat(teacherPressure) * 0.28, 0.08, 1.1 + CGFloat(event) * 0.2)

        let wallLift = characterBounceLightNode.childNode(withName: "teacherWallBounceShadowLift", recursively: true)
        wallLift?.position.x = teacherNode.position.x * 0.36
        wallLift?.opacity = CGFloat((0.06 + teacherPressure * 0.16 + (boardFocus ? 0.12 : 0) + event * 0.1).clamped(to: 0.03...0.4))
        wallLift?.scale = SCNVector3(1 + CGFloat(teacherPressure) * 0.18, 1 + CGFloat(event) * 0.16, 1)

        characterBounceLightNode.childNode(withName: "playerDeskReturnBounce", recursively: true)?.opacity = CGFloat((0.08 + lowLight * 0.16 + event * 0.18 + (game.cameraPose == .desk ? 0.22 : 0)).clamped(to: 0.04...0.52))
        for index in 0..<8 {
            characterBounceLightNode.childNode(withName: "deskEdgeBounceGlint\(index)", recursively: true)?.opacity = CGFloat((0.04 + game.classroomLightLevel * 0.08 + lowLight * 0.1 + event * 0.12).clamped(to: 0.02...0.34))
        }
    }

    private func makeEventDeskWash() -> SCNNode {
        let root = SCNNode()
        let wash = box(width: 1.1, height: 0.004, length: 0.58, color: NSColor(calibratedRed: 1.0, green: 0.34, blue: 0.18, alpha: 0.3), position: SCNVector3(0, 0, 0))
        wash.geometry?.firstMaterial?.emission.contents = NSColor(calibratedRed: 0.45, green: 0.08, blue: 0.04, alpha: 0.22)
        root.addChildNode(wash)
        for index in 0..<4 {
            let stripe = box(width: 0.82 - CGFloat(index) * 0.12, height: 0.005, length: 0.018, color: NSColor(calibratedRed: 1.0, green: 0.82, blue: 0.4, alpha: 0.18), position: SCNVector3(0, 0.004, -0.22 + Float(index) * 0.14))
            root.addChildNode(stripe)
        }
        root.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.65, duration: 0.48),
            .fadeOpacity(to: 0.28, duration: 0.7),
            .wait(duration: 0.32)
        ])), forKey: "desk_event_pulse")
        return root
    }

    private func makeProjectorBeam() -> SCNNode {
        let root = SCNNode()
        let beamColor = NSColor(calibratedRed: 0.68, green: 0.86, blue: 1.0, alpha: 0.08)
        for index in 0..<4 {
            let beam = box(width: 0.92 + CGFloat(index) * 0.22, height: 0.42 + CGFloat(index) * 0.04, length: 0.025, color: beamColor, position: SCNVector3(0, -0.1 + Float(index) * 0.02, -0.42 - Float(index) * 0.28))
            beam.eulerAngles.x = -0.24
            beam.eulerAngles.y = Float(index - 1) * 0.025
            root.addChildNode(beam)
        }
        root.runAction(.repeatForever(.sequence([
            .fadeOpacity(to: 0.3, duration: 2.4),
            .fadeOpacity(to: 0.12, duration: 2.8)
        ])), forKey: "projector_air")
        return root
    }

    private func makeCeilingFan(at position: SCNVector3) -> SCNNode {
        let root = SCNNode()
        root.position = position
        root.opacity = 0.28
        root.addChildNode(capsule(radius: 0.018, height: 0.24, color: NSColor(calibratedWhite: 0.42, alpha: 1), position: SCNVector3(0, 0.12, 0)))
        let hub = sphere(radius: 0.055, color: NSColor(calibratedWhite: 0.34, alpha: 1), position: SCNVector3(0, 0, 0))
        root.addChildNode(hub)
        for angle in [0.0, Double.pi * 2 / 3, Double.pi * 4 / 3] {
            let blade = box(width: 0.62, height: 0.012, length: 0.075, color: NSColor(calibratedWhite: 0.5, alpha: 1), position: SCNVector3(0.31, 0, 0))
            let bladeRoot = SCNNode()
            bladeRoot.eulerAngles.y = CGFloat(angle)
            bladeRoot.addChildNode(blade)
            root.addChildNode(bladeRoot)
        }
        let blur = SCNCylinder(radius: 0.52, height: 0.006)
        blur.radialSegmentCount = 48
        blur.firstMaterial = material(NSColor(calibratedWhite: 0.86, alpha: 0.13))
        blur.firstMaterial?.emission.contents = NSColor(calibratedWhite: 0.55, alpha: 0.05)
        let blurNode = SCNNode(geometry: blur)
        blurNode.name = "fanMotionBlur"
        blurNode.eulerAngles.x = CGFloat.pi / 2
        blurNode.opacity = 0.32
        root.addChildNode(blurNode)
        return root
    }

    private func updateFans(game: GameManager) {
        let spinDuration: Double
        switch game.currentPeriod {
        case .first:
            spinDuration = 1.55
        case .breakOne, .breakTwo:
            spinDuration = 1.25
        case .second:
            spinDuration = 0.95
        case .third:
            spinDuration = 0.48
        }
        let adjustedDuration = game.classroomLightLevel < 0.6 ? min(spinDuration, 0.72) : spinDuration
        guard abs(adjustedDuration - lastFanSpinDuration) > 0.02 else {
            for fan in fanNodes {
                fan.opacity = game.currentPeriod == .first ? 0.42 : 0.58
                fan.childNode(withName: "fanMotionBlur", recursively: true)?.opacity = adjustedDuration < 0.8 ? 0.52 : 0.28
            }
            return
        }
        lastFanSpinDuration = adjustedDuration
        for (index, fan) in fanNodes.enumerated() {
            fan.removeAction(forKey: "spin")
            fan.opacity = game.currentPeriod == .first ? 0.42 : 0.58
            fan.childNode(withName: "fanMotionBlur", recursively: true)?.opacity = adjustedDuration < 0.8 ? 0.52 : 0.28
            fan.runAction(.repeatForever(.rotateBy(x: 0, y: CGFloat.pi * 2, z: 0, duration: adjustedDuration)), forKey: "spin")
            let sweep = ceilingCinematicLayerNode.childNode(withName: "fanSweepShadowRoot\(index)", recursively: true)
            sweep?.removeAction(forKey: "fan_shadow_spin")
            sweep?.runAction(.repeatForever(.rotateBy(x: 0, y: CGFloat.pi * 2, z: 0, duration: adjustedDuration * 1.08)), forKey: "fan_shadow_spin")
        }
    }

    private func emissionColor(for state: ClassmateState) -> NSColor {
        switch state {
        case .anxious:
            return NSColor(calibratedRed: 0.18, green: 0.08, blue: 0.02, alpha: 1)
        case .crying:
            return NSColor(calibratedRed: 0.26, green: 0.04, blue: 0.04, alpha: 1)
        case .offeringHelp, .covering, .lookingAtPlayer:
            return NSColor(calibratedRed: 0.02, green: 0.14, blue: 0.12, alpha: 1)
        case .usingPhone:
            return NSColor(calibratedRed: 0.02, green: 0.08, blue: 0.18, alpha: 1)
        default:
            return NSColor.black
        }
    }

    private func box(width: CGFloat, height: CGFloat, length: CGFloat, color: NSColor, position: SCNVector3) -> SCNNode {
        let geometry = SCNBox(width: width, height: height, length: length, chamferRadius: 0.01)
        geometry.firstMaterial = material(color)
        let node = SCNNode(geometry: geometry)
        node.position = position
        return node
    }

    private func roundedBox(width: CGFloat, height: CGFloat, length: CGFloat, chamfer: CGFloat, color: NSColor, position: SCNVector3) -> SCNNode {
        let geometry = SCNBox(width: width, height: height, length: length, chamferRadius: chamfer)
        geometry.firstMaterial = material(color)
        let node = SCNNode(geometry: geometry)
        node.position = position
        return node
    }

    private func capsule(radius: CGFloat, height: CGFloat, color: NSColor, position: SCNVector3, rotation: SCNVector4? = nil) -> SCNNode {
        let geometry = SCNCapsule(capRadius: radius, height: height)
        geometry.firstMaterial = material(color)
        let node = SCNNode(geometry: geometry)
        node.position = position
        if let rotation {
            node.rotation = rotation
        }
        return node
    }

    private func sphere(radius: CGFloat, color: NSColor, position: SCNVector3, scale: SCNVector3 = SCNVector3(1, 1, 1)) -> SCNNode {
        let geometry = SCNSphere(radius: radius)
        geometry.segmentCount = 12
        geometry.firstMaterial = material(color)
        let node = SCNNode(geometry: geometry)
        node.position = position
        node.scale = scale
        return node
    }

    private func forEachDescendant(of node: SCNNode, _ body: (SCNNode) -> Void) {
        for child in node.childNodes {
            body(child)
            forEachDescendant(of: child, body)
        }
    }

    private func gazeCone() -> SCNNode {
        let geometry = SCNCone(topRadius: 0.06, bottomRadius: 0.62, height: 2.7)
        geometry.radialSegmentCount = 24
        geometry.firstMaterial = material(NSColor(calibratedRed: 1.0, green: 0.46, blue: 0.22, alpha: 0.18))
        geometry.firstMaterial?.blendMode = .add
        geometry.firstMaterial?.isDoubleSided = true
        geometry.firstMaterial?.writesToDepthBuffer = false
        let node = SCNNode(geometry: geometry)
        node.position = SCNVector3(0, 0, -1.35)
        return node
    }

    private func makeStudentBody(uniformColor: NSColor, seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let skin = skinColor(seed)
        let shirtLight = uniformColor.blended(withFraction: 0.28, of: .white) ?? uniformColor
        let pantsColor = NSColor(calibratedRed: 0.1, green: 0.13, blue: 0.19, alpha: 1)
        let shoeColor = NSColor(calibratedWhite: 0.045, alpha: 1)

        let neck = capsule(radius: 0.035, height: 0.13, color: skin, position: SCNVector3(0, 0.73, 0))
        neck.name = "neck"
        root.addChildNode(neck)

        let torso = box(width: 0.29, height: 0.43, length: 0.17, color: uniformColor, position: SCNVector3(0, 0.49, 0))
        torso.name = "torso"
        root.addChildNode(torso)
        root.addChildNode(roundedBox(width: 0.36, height: 0.085, length: 0.19, chamfer: 0.035, color: shirtLight, position: SCNVector3(0, 0.68, -0.005)))
        root.addChildNode(box(width: 0.15, height: 0.012, length: 0.024, color: NSColor(calibratedRed: 0.08, green: 0.1, blue: 0.16, alpha: 1), position: SCNVector3(0, 0.705, -0.1)))
        root.addChildNode(box(width: 0.055, height: 0.11, length: 0.018, color: NSColor(calibratedWhite: 0.94, alpha: 1), position: SCNVector3(-0.035, 0.63, -0.091)))
        root.addChildNode(box(width: 0.055, height: 0.11, length: 0.018, color: NSColor(calibratedWhite: 0.94, alpha: 1), position: SCNVector3(0.035, 0.63, -0.091)))
        root.addChildNode(box(width: 0.34, height: 0.012, length: 0.022, color: NSColor(calibratedWhite: 0.04, alpha: 0.26), position: SCNVector3(0, 0.595, -0.096)))
        root.addChildNode(makeUniformDetails(seed: seed, profile: profile))
        root.addChildNode(makeUniformWearDetails(seed: seed, profile: profile))
        root.addChildNode(makeUniformSilhouetteDetails(uniformColor: uniformColor, seed: seed, profile: profile))
        root.addChildNode(makeStudentStructuralAnatomyLayer(uniformColor: uniformColor, skin: skin, pantsColor: pantsColor, seed: seed, profile: profile))

        root.addChildNode(makeStudentArm(side: -1, uniformColor: uniformColor, skin: skin, seed: seed))
        root.addChildNode(makeStudentArm(side: 1, uniformColor: uniformColor, skin: skin, seed: seed))

        root.addChildNode(makeStudentLeg(side: -1, pantsColor: pantsColor, shoeColor: shoeColor, seed: seed))
        root.addChildNode(makeStudentLeg(side: 1, pantsColor: pantsColor, shoeColor: shoeColor, seed: seed))
        root.addChildNode(box(width: 0.46, height: 0.004, length: 0.36, color: NSColor(calibratedWhite: 0.02, alpha: 0.14), position: SCNVector3(0, -0.045, 0.015)))

        if profile?.rebelliousness ?? 0 > 72 {
            root.addChildNode(box(width: 0.2, height: 0.025, length: 0.185, color: NSColor(calibratedRed: 0.72, green: 0.18, blue: 0.2, alpha: 1), position: SCNVector3(0, 0.7, -0.015)))
        }
        return root
    }

    private func makeStudentStructuralAnatomyLayer(uniformColor: NSColor, skin: NSColor, pantsColor: NSColor, seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        root.name = "studentStructuralAnatomyLayer"

        let anxious = (profile?.anxiety ?? 0) > 66
        let uniformCatch = uniformColor.blended(withFraction: 0.28, of: .white)?.withAlphaComponent(0.16) ?? NSColor(calibratedWhite: 0.8, alpha: 0.16)
        let uniformShadow = uniformColor.blended(withFraction: 0.42, of: .black)?.withAlphaComponent(0.24) ?? NSColor(calibratedWhite: 0.02, alpha: 0.22)
        let skinShadow = skin.blended(withFraction: 0.42, of: .black)?.withAlphaComponent(anxious ? 0.28 : 0.18) ?? NSColor(calibratedWhite: 0.08, alpha: 0.18)
        let skinCatch = skin.blended(withFraction: 0.18, of: .white)?.withAlphaComponent(0.18) ?? NSColor(calibratedWhite: 1.0, alpha: 0.16)
        let clothDark = NSColor(calibratedWhite: 0.0, alpha: 0.15)
        let pantsCatch = pantsColor.blended(withFraction: 0.22, of: .white)?.withAlphaComponent(0.18) ?? NSColor(calibratedWhite: 0.2, alpha: 0.18)

        let neckColumnBack = capsule(radius: 0.012, height: 0.17, color: skinShadow, position: SCNVector3(0, 0.724, 0.066), rotation: SCNVector4(0, 0, 1, 0))
        neckColumnBack.name = "studentStructuralNeckBackColumn"
        root.addChildNode(neckColumnBack)

        let throatPlane = box(width: 0.082, height: 0.048, length: 0.012, color: skinShadow.withAlphaComponent(0.16), position: SCNVector3(0, 0.706, -0.112))
        throatPlane.name = "studentStructuralThroatUnderPlane"
        root.addChildNode(throatPlane)

        let jawCast = capsule(radius: 0.0045, height: 0.16, color: skinShadow.withAlphaComponent(0.2), position: SCNVector3(0, 0.752, -0.124), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        jawCast.name = "studentStructuralJawCastShadow"
        root.addChildNode(jawCast)

        let ribVolume = roundedBox(width: 0.34, height: 0.22, length: 0.038, chamfer: 0.03, color: uniformCatch, position: SCNVector3(0, 0.535, -0.112))
        ribVolume.name = "studentStructuralRibCageFrontVolume"
        root.addChildNode(ribVolume)

        let sternum = capsule(radius: 0.0038, height: 0.24, color: uniformShadow, position: SCNVector3(0, 0.53, -0.136), rotation: SCNVector4(0, 0, 1, 0))
        sternum.name = "studentStructuralSternumDepression"
        root.addChildNode(sternum)

        let abdomen = roundedBox(width: 0.31, height: 0.11, length: 0.032, chamfer: 0.026, color: uniformShadow.withAlphaComponent(0.18), position: SCNVector3(0, 0.36, -0.108))
        abdomen.name = "studentStructuralAbdomenDeskCompression"
        root.addChildNode(abdomen)

        let pelvis = sphere(radius: 0.09, color: clothDark.withAlphaComponent(0.16), position: SCNVector3(0, 0.215, 0.025), scale: SCNVector3(2.2, 0.42, 1.15))
        pelvis.name = "studentStructuralPelvisSeatMass"
        root.addChildNode(pelvis)

        let backCurve = capsule(radius: 0.005, height: 0.42, color: uniformShadow.withAlphaComponent(0.18), position: SCNVector3(0, 0.49, 0.1), rotation: SCNVector4(0, 0, 1, 0.035))
        backCurve.name = "studentStructuralSpineBackCurve"
        root.addChildNode(backCurve)

        for sideIndex in 0..<2 {
            let side: Float = sideIndex == 0 ? -1 : 1
            let sideName = sideIndex == 0 ? "Left" : "Right"

            let clavicle = capsule(radius: 0.0036, height: 0.15, color: skinCatch, position: SCNVector3(side * 0.072, 0.676, -0.126), rotation: SCNVector4(0, 0, 1, side * 1.12))
            clavicle.name = "studentStructural\(sideName)ClavicleRidge"
            root.addChildNode(clavicle)

            let shoulderSocket = sphere(radius: 0.045, color: uniformCatch.withAlphaComponent(0.18), position: SCNVector3(side * 0.188, 0.635, -0.02), scale: SCNVector3(1.16, 0.72, 0.9))
            shoulderSocket.name = "studentStructural\(sideName)ShoulderSocketMass"
            root.addChildNode(shoulderSocket)

            let armpitPocket = box(width: 0.04, height: 0.13, length: 0.028, color: uniformShadow.withAlphaComponent(0.2), position: SCNVector3(side * 0.17, 0.515, -0.086))
            armpitPocket.name = "studentStructural\(sideName)ArmpitPocketShadow"
            armpitPocket.eulerAngles.z = side * 0.08
            root.addChildNode(armpitPocket)

            let elbowContact = sphere(radius: 0.025, color: uniformShadow.withAlphaComponent(0.18), position: SCNVector3(side * 0.22, 0.382, -0.05), scale: SCNVector3(1.3, 0.54, 0.72))
            elbowContact.name = "studentStructural\(sideName)ElbowBoneContact"
            root.addChildNode(elbowContact)

            let hipPocket = sphere(radius: 0.046, color: clothDark.withAlphaComponent(0.14), position: SCNVector3(side * 0.112, 0.245, 0.03), scale: SCNVector3(1.25, 0.38, 0.9))
            hipPocket.name = "studentStructural\(sideName)HipSeatPocket"
            root.addChildNode(hipPocket)

            let kneeMass = sphere(radius: 0.042, color: pantsCatch, position: SCNVector3(side * 0.082, 0.07, -0.018), scale: SCNVector3(0.9, 0.34, 0.78))
            kneeMass.name = "studentStructural\(sideName)KneeVolumeCatch"
            root.addChildNode(kneeMass)

            let shinPlane = capsule(radius: 0.0035, height: 0.18, color: clothDark.withAlphaComponent(0.13), position: SCNVector3(side * 0.108, -0.035, -0.062), rotation: SCNVector4(0, 0, 1, side * 0.18))
            shinPlane.name = "studentStructural\(sideName)ShinCompressionLine"
            root.addChildNode(shinPlane)
        }

        for index in 0..<5 {
            let rib = capsule(
                radius: 0.0026,
                height: 0.18 - CGFloat(index % 2) * 0.025,
                color: index % 2 == 0 ? uniformCatch.withAlphaComponent(0.12) : uniformShadow.withAlphaComponent(0.13),
                position: SCNVector3(-0.12 + Float(index) * 0.06, 0.61 - Float(index % 3) * 0.045, -0.138),
                rotation: SCNVector4(0, 0, 1, -0.18 + Float(index) * 0.09)
            )
            rib.name = "studentStructuralBreathRibTrace\(index)"
            root.addChildNode(rib)
        }

        root.opacity = 0.16
        return root
    }

    private func makeStudentLeg(side: Float, pantsColor: NSColor, shoeColor: NSColor, seed: Int) -> SCNNode {
        let root = SCNNode()
        root.name = side < 0 ? "leftLeg" : "rightLeg"
        root.position = SCNVector3(side * 0.075, 0.25, 0.02)
        root.eulerAngles.x = side < 0 ? 0.08 : -0.08
        root.eulerAngles.z = side < 0 ? 0.035 : -0.035

        let thigh = capsule(radius: 0.042, height: 0.26, color: pantsColor, position: SCNVector3(0, -0.045, 0.02))
        thigh.name = side < 0 ? "leftThigh" : "rightThigh"
        thigh.eulerAngles.x = -0.12
        root.addChildNode(thigh)

        let knee = sphere(radius: 0.043, color: pantsColor.blended(withFraction: 0.15, of: .white) ?? pantsColor, position: SCNVector3(side * 0.008, -0.175, -0.01), scale: SCNVector3(0.9, 0.68, 0.82))
        knee.name = side < 0 ? "leftKnee" : "rightKnee"
        root.addChildNode(knee)

        let shin = capsule(radius: 0.036, height: 0.22, color: pantsColor.blended(withFraction: 0.07, of: .black) ?? pantsColor, position: SCNVector3(side * 0.014, -0.28, -0.025))
        shin.name = side < 0 ? "leftShin" : "rightShin"
        shin.eulerAngles.x = 0.16
        root.addChildNode(shin)

        let sock = roundedBox(width: 0.062, height: 0.04, length: 0.06, chamfer: 0.014, color: NSColor(calibratedWhite: 0.82, alpha: 1), position: SCNVector3(side * 0.015, -0.385, -0.038))
        sock.name = side < 0 ? "leftSock" : "rightSock"
        root.addChildNode(sock)

        let shoe = roundedBox(width: 0.13, height: 0.048, length: 0.19, chamfer: 0.025, color: shoeColor, position: SCNVector3(side * 0.018, -0.43, -0.075))
        shoe.name = side < 0 ? "leftFoot" : "rightFoot"
        shoe.eulerAngles.y = side * (0.04 + Float(seed % 3) * 0.018)
        root.addChildNode(shoe)

        let toeHighlight = box(width: 0.095, height: 0.01, length: 0.026, color: NSColor(calibratedWhite: 0.18, alpha: 0.45), position: SCNVector3(side * 0.018, -0.402, -0.155))
        toeHighlight.name = side < 0 ? "leftToeHighlight" : "rightToeHighlight"
        root.addChildNode(toeHighlight)
        return root
    }

    private func makeStudentArm(side: Float, uniformColor: NSColor, skin: NSColor, seed: Int) -> SCNNode {
        let root = SCNNode()
        root.name = side < 0 ? "leftArm" : "rightArm"
        root.position = SCNVector3(side * 0.205, 0.58, -0.012)
        root.eulerAngles.z = side < 0 ? 0.12 : -0.12

        let upperArm = capsule(radius: 0.031, height: 0.24, color: uniformColor, position: SCNVector3(0, -0.08, 0.0))
        upperArm.name = side < 0 ? "leftUpperArm" : "rightUpperArm"
        upperArm.eulerAngles.x = 0.08
        root.addChildNode(upperArm)

        let elbow = sphere(radius: 0.033, color: uniformColor.blended(withFraction: 0.12, of: .black) ?? uniformColor, position: SCNVector3(side * 0.015, -0.2, -0.018), scale: SCNVector3(0.85, 0.72, 0.85))
        elbow.name = side < 0 ? "leftElbow" : "rightElbow"
        root.addChildNode(elbow)

        let forearm = capsule(radius: 0.026, height: 0.25, color: skin, position: SCNVector3(side * 0.032, -0.32, -0.035))
        forearm.name = side < 0 ? "leftForearm" : "rightForearm"
        forearm.eulerAngles = SCNVector3(0.18, 0, side < 0 ? 0.08 : -0.08)
        root.addChildNode(forearm)

        let cuff = roundedBox(width: 0.075, height: 0.035, length: 0.06, chamfer: 0.014, color: uniformColor.blended(withFraction: 0.18, of: .white) ?? uniformColor, position: SCNVector3(side * 0.02, -0.23, -0.024))
        cuff.name = side < 0 ? "leftCuff" : "rightCuff"
        cuff.eulerAngles.z = side < 0 ? 0.08 : -0.08
        root.addChildNode(cuff)
        root.addChildNode(box(width: 0.062, height: 0.006, length: 0.062, color: NSColor(calibratedWhite: 0.02, alpha: 0.2), position: SCNVector3(side * 0.02, -0.21, -0.057)))

        let hand = sphere(radius: 0.043, color: skin, position: SCNVector3(side * 0.055, -0.45, -0.065), scale: SCNVector3(0.82, 0.54, 1.0))
        hand.name = side < 0 ? "leftHand" : "rightHand"
        hand.eulerAngles.z = side < 0 ? 0.18 : -0.18
        addStudentFingerDetails(to: hand, side: side, skin: skin)
        if side > 0 {
            let pencil = capsule(radius: 0.0055, height: 0.18, color: seed % 2 == 0 ? NSColor(calibratedRed: 0.86, green: 0.58, blue: 0.16, alpha: 1) : NSColor(calibratedRed: 0.08, green: 0.1, blue: 0.22, alpha: 1), position: SCNVector3(-0.005, -0.01, -0.045), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
            pencil.name = "classmatePencil"
            pencil.eulerAngles.x = 0.32
            hand.addChildNode(pencil)
        }
        root.addChildNode(hand)
        return root
    }

    private func addStudentFingerDetails(to hand: SCNNode, side: Float, skin: NSColor) {
        for index in 0..<3 {
            let finger = capsule(radius: 0.0065, height: 0.055, color: skin.blended(withFraction: 0.08, of: .white) ?? skin, position: SCNVector3(side * (0.008 + Float(index) * 0.008), -0.005, -0.038 - Float(index) * 0.006), rotation: SCNVector4(1, 0, 0, 1.1))
            finger.name = side < 0 ? "leftFinger\(index)" : "rightFinger\(index)"
            finger.eulerAngles.z = side < 0 ? -0.18 : 0.18
            hand.addChildNode(finger)
        }
        let thumb = capsule(radius: 0.008, height: 0.052, color: skin.blended(withFraction: 0.04, of: .black) ?? skin, position: SCNVector3(-side * 0.022, -0.006, -0.018), rotation: SCNVector4(0, 0, 1, side * 0.8))
        thumb.name = side < 0 ? "leftThumb" : "rightThumb"
        hand.addChildNode(thumb)
    }

    private func makeUniformDetails(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let stripeColor = profile?.orderliness ?? 0 > 72
            ? NSColor(calibratedRed: 0.86, green: 0.9, blue: 1.0, alpha: 1)
            : NSColor(calibratedRed: 0.88, green: 0.88, blue: 0.82, alpha: 0.86)
        root.addChildNode(box(width: 0.3, height: 0.012, length: 0.018, color: stripeColor, position: SCNVector3(0, 0.53, -0.102)))
        root.addChildNode(box(width: 0.018, height: 0.24, length: 0.018, color: NSColor(calibratedWhite: 0.06, alpha: 0.22), position: SCNVector3(-0.152, 0.49, -0.102)))
        root.addChildNode(box(width: 0.018, height: 0.24, length: 0.018, color: NSColor(calibratedWhite: 0.06, alpha: 0.22), position: SCNVector3(0.152, 0.49, -0.102)))

        let badgeColor = profile?.empathy ?? 0 > 72
            ? NSColor(calibratedRed: 0.2, green: 0.72, blue: 0.62, alpha: 1)
            : NSColor(calibratedRed: 0.78, green: 0.22, blue: 0.18, alpha: 1)
        let badge = box(width: 0.055, height: 0.04, length: 0.016, color: badgeColor, position: SCNVector3(seed % 2 == 0 ? -0.075 : 0.075, 0.58, -0.107))
        root.addChildNode(badge)

        if profile?.maskStrength ?? 50 > 70 {
            root.addChildNode(box(width: 0.21, height: 0.012, length: 0.018, color: NSColor(calibratedRed: 0.16, green: 0.18, blue: 0.24, alpha: 1), position: SCNVector3(0, 0.37, -0.104)))
        }
        return root
    }

    private func makeUniformWearDetails(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let wrinkleColor = NSColor(calibratedWhite: 0.03, alpha: 0.18)
        let highlightColor = NSColor(calibratedWhite: 0.96, alpha: 0.12)
        for index in 0..<5 {
            let x = -0.11 + Float(index) * 0.055
            let y = 0.43 + Float((index * 17 + seed) % 17) / 100
            let wrinkle = capsule(radius: 0.0035, height: 0.12 + CGFloat(index % 2) * 0.025, color: index % 2 == 0 ? wrinkleColor : highlightColor, position: SCNVector3(x, y, -0.108), rotation: SCNVector4(0, 0, 1, 0.08 + Float(index - 2) * 0.08))
            root.addChildNode(wrinkle)
        }

        let idCordColor = (profile?.orderliness ?? 0) > 72
            ? NSColor(calibratedRed: 0.12, green: 0.28, blue: 0.68, alpha: 1)
            : NSColor(calibratedRed: 0.16, green: 0.16, blue: 0.18, alpha: 1)
        root.addChildNode(capsule(radius: 0.004, height: 0.28, color: idCordColor, position: SCNVector3(-0.045, 0.57, -0.116), rotation: SCNVector4(0, 0, 1, -0.28)))
        root.addChildNode(capsule(radius: 0.004, height: 0.28, color: idCordColor, position: SCNVector3(0.045, 0.57, -0.116), rotation: SCNVector4(0, 0, 1, 0.28)))

        let card = roundedBox(width: 0.07, height: 0.052, length: 0.012, chamfer: 0.006, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(0, 0.43, -0.122))
        card.name = "studentIdCard"
        root.addChildNode(card)
        root.addChildNode(box(width: 0.048, height: 0.008, length: 0.006, color: NSColor(calibratedRed: 0.16, green: 0.22, blue: 0.42, alpha: 0.72), position: SCNVector3(0, 0.442, -0.13)))
        root.addChildNode(box(width: 0.038, height: 0.006, length: 0.006, color: NSColor(calibratedWhite: 0.18, alpha: 0.54), position: SCNVector3(0, 0.422, -0.13)))

        if profile?.anxiety ?? 0 > 68 {
            root.addChildNode(box(width: 0.1, height: 0.012, length: 0.016, color: NSColor(calibratedRed: 0.96, green: 0.84, blue: 0.24, alpha: 1), position: SCNVector3(-0.12, 0.35, -0.116)))
        }
        return root
    }

    private func makeUniformSilhouetteDetails(uniformColor: NSColor, seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let shoulderColor = uniformColor.blended(withFraction: 0.18, of: .white) ?? uniformColor
        let shadowColor = uniformColor.blended(withFraction: 0.34, of: .black) ?? uniformColor
        let crisp = (profile?.orderliness ?? 0) > 72
        let rebellious = (profile?.rebelliousness ?? 0) > 72

        let leftShoulder = roundedBox(width: 0.14, height: 0.05, length: 0.19, chamfer: 0.026, color: shoulderColor, position: SCNVector3(-0.185, 0.665, -0.002))
        let rightShoulder = roundedBox(width: 0.14, height: 0.05, length: 0.19, chamfer: 0.026, color: shoulderColor, position: SCNVector3(0.185, 0.665, -0.002))
        leftShoulder.name = "leftUniformShoulderVolume"
        rightShoulder.name = "rightUniformShoulderVolume"
        leftShoulder.eulerAngles.z = 0.08
        rightShoulder.eulerAngles.z = -0.08
        root.addChildNode(leftShoulder)
        root.addChildNode(rightShoulder)

        let leftSideFold = capsule(radius: 0.0045, height: 0.3, color: shadowColor.withAlphaComponent(0.55), position: SCNVector3(-0.156, 0.48, -0.116), rotation: SCNVector4(0, 0, 1, -0.08))
        let rightSideFold = capsule(radius: 0.0045, height: 0.3, color: shadowColor.withAlphaComponent(0.55), position: SCNVector3(0.156, 0.48, -0.116), rotation: SCNVector4(0, 0, 1, 0.08))
        root.addChildNode(leftSideFold)
        root.addChildNode(rightSideFold)

        for index in 0..<4 {
            let x = -0.105 + Float(index) * 0.07
            let fold = capsule(radius: 0.0035, height: crisp ? 0.18 : 0.14 + CGFloat(index % 2) * 0.04, color: index % 2 == 0 ? shadowColor.withAlphaComponent(0.5) : shoulderColor.withAlphaComponent(0.38), position: SCNVector3(x, 0.44 + Float(index % 2) * 0.025, -0.121), rotation: SCNVector4(0, 0, 1, -0.1 + Float(index) * 0.07))
            fold.name = "uniformFrontFold\(index)"
            root.addChildNode(fold)
        }

        let hemColor = rebellious
            ? NSColor(calibratedRed: 0.72, green: 0.18, blue: 0.22, alpha: 1)
            : shadowColor.withAlphaComponent(0.82)
        let hem = roundedBox(width: 0.33, height: 0.035, length: 0.19, chamfer: 0.012, color: hemColor, position: SCNVector3(0, 0.29, 0.006))
        hem.name = "uniformLowerHem"
        hem.eulerAngles.x = -0.03
        root.addChildNode(hem)

        let collarShadow = box(width: 0.24, height: 0.01, length: 0.018, color: NSColor(calibratedWhite: 0.02, alpha: 0.36), position: SCNVector3(0, 0.66, -0.116))
        collarShadow.name = "uniformCollarContactShadow"
        root.addChildNode(collarShadow)
        return root
    }

    private func makeTeacherBody() -> SCNNode {
        let root = SCNNode()
        let skin = NSColor(calibratedRed: 0.9, green: 0.78, blue: 0.66, alpha: 1)
        let jacket = NSColor(calibratedRed: 0.14, green: 0.17, blue: 0.2, alpha: 1)
        let shirt = NSColor(calibratedWhite: 0.9, alpha: 1)
        let pants = NSColor(calibratedRed: 0.08, green: 0.09, blue: 0.11, alpha: 1)

        root.addChildNode(capsule(radius: 0.04, height: 0.15, color: skin, position: SCNVector3(0, 1.12, 0)))
        root.addChildNode(box(width: 0.36, height: 0.52, length: 0.18, color: jacket, position: SCNVector3(0, 0.83, 0)))
        root.addChildNode(box(width: 0.16, height: 0.45, length: 0.022, color: shirt, position: SCNVector3(0, 0.85, -0.095)))
        root.addChildNode(box(width: 0.06, height: 0.18, length: 0.024, color: NSColor(calibratedRed: 0.42, green: 0.08, blue: 0.08, alpha: 1), position: SCNVector3(0, 0.92, -0.11)))
        root.addChildNode(box(width: 0.42, height: 0.08, length: 0.19, color: jacket, position: SCNVector3(0, 1.04, 0)))
        root.addChildNode(box(width: 0.018, height: 0.48, length: 0.024, color: NSColor(calibratedWhite: 0.02, alpha: 0.28), position: SCNVector3(-0.19, 0.82, -0.102)))
        root.addChildNode(box(width: 0.018, height: 0.48, length: 0.024, color: NSColor(calibratedWhite: 0.02, alpha: 0.28), position: SCNVector3(0.19, 0.82, -0.102)))
        root.addChildNode(box(width: 0.34, height: 0.018, length: 0.028, color: NSColor(calibratedWhite: 0.04, alpha: 0.32), position: SCNVector3(0, 0.61, -0.104)))
        root.addChildNode(makeTeacherSuitDetails(jacket: jacket, shirt: shirt))
        root.addChildNode(makeTeacherArm(side: -1, jacket: jacket, skin: skin))
        root.addChildNode(makeTeacherArm(side: 1, jacket: jacket, skin: skin))
        root.addChildNode(makeTeacherLeg(side: -1, pants: pants))
        root.addChildNode(makeTeacherLeg(side: 1, pants: pants))

        let notebook = box(width: 0.18, height: 0.025, length: 0.25, color: NSColor(calibratedRed: 0.08, green: 0.16, blue: 0.34, alpha: 1), position: SCNVector3(-0.36, 0.65, -0.08))
        notebook.name = "teacherNotebook"
        notebook.eulerAngles.z = -0.28
        root.addChildNode(notebook)
        notebook.addChildNode(box(width: 0.16, height: 0.006, length: 0.016, color: NSColor(calibratedWhite: 0.9, alpha: 0.72), position: SCNVector3(0, 0.02, -0.07)))
        notebook.addChildNode(box(width: 0.12, height: 0.006, length: 0.012, color: NSColor(calibratedWhite: 0.9, alpha: 0.56), position: SCNVector3(-0.01, 0.022, -0.02)))
        let chalk = box(width: 0.018, height: 0.018, length: 0.16, color: NSColor(calibratedWhite: 0.9, alpha: 1), position: SCNVector3(0.34, 0.58, -0.08))
        chalk.name = "teacherChalk"
        root.addChildNode(chalk)
        return root
    }

    private func makeTeacherSuitDetails(jacket: NSColor, shirt: NSColor) -> SCNNode {
        let root = SCNNode()
        let jacketLight = jacket.blended(withFraction: 0.22, of: .white) ?? jacket
        let jacketShadow = jacket.blended(withFraction: 0.38, of: .black) ?? jacket
        let lapelLeft = roundedBox(width: 0.09, height: 0.34, length: 0.024, chamfer: 0.01, color: jacketLight, position: SCNVector3(-0.075, 0.87, -0.116))
        let lapelRight = roundedBox(width: 0.09, height: 0.34, length: 0.024, chamfer: 0.01, color: jacketLight, position: SCNVector3(0.075, 0.87, -0.116))
