    private func makeTeacherArm(side: Float, jacket: NSColor, skin: NSColor) -> SCNNode {
        let root = SCNNode()
        root.name = side < 0 ? "teacherLeftArm" : "teacherRightArm"
        root.position = SCNVector3(side * 0.255, 0.96, -0.01)
        root.eulerAngles.z = side < 0 ? 0.1 : -0.1

        let upper = capsule(radius: 0.038, height: 0.28, color: jacket, position: SCNVector3(0, -0.12, 0))
        upper.name = side < 0 ? "teacherLeftUpperArm" : "teacherRightUpperArm"
        upper.eulerAngles.x = 0.05
        root.addChildNode(upper)

        let elbow = sphere(radius: 0.04, color: jacket.blended(withFraction: 0.12, of: .white) ?? jacket, position: SCNVector3(side * 0.012, -0.265, -0.01), scale: SCNVector3(0.82, 0.68, 0.82))
        elbow.name = side < 0 ? "teacherLeftElbow" : "teacherRightElbow"
        root.addChildNode(elbow)

        let forearm = capsule(radius: 0.032, height: 0.25, color: jacket, position: SCNVector3(side * 0.026, -0.38, -0.018))
        forearm.name = side < 0 ? "teacherLeftForearm" : "teacherRightForearm"
        forearm.eulerAngles = SCNVector3(0.12, 0, side < 0 ? 0.08 : -0.08)
        root.addChildNode(forearm)

        let cuff = roundedBox(width: 0.076, height: 0.034, length: 0.056, chamfer: 0.012, color: NSColor(calibratedWhite: 0.88, alpha: 1), position: SCNVector3(side * 0.034, -0.505, -0.028))
        cuff.name = side < 0 ? "teacherLeftCuff" : "teacherRightCuff"
        root.addChildNode(cuff)

        let hand = sphere(radius: 0.042, color: skin, position: SCNVector3(side * 0.044, -0.55, -0.032), scale: SCNVector3(0.82, 0.58, 0.95))
        hand.name = side < 0 ? "teacherLeftHand" : "teacherRightHand"
        addTeacherFingerDetails(to: hand, side: side, skin: skin)
        root.addChildNode(hand)
        return root
    }

    private func addTeacherFingerDetails(to hand: SCNNode, side: Float, skin: NSColor) {
        for index in 0..<3 {
            let finger = capsule(radius: 0.006, height: 0.058, color: skin, position: SCNVector3(side * (0.006 + Float(index) * 0.008), -0.004, -0.038 - Float(index) * 0.005), rotation: SCNVector4(1, 0, 0, 1.0))
            finger.name = side < 0 ? "teacherLeftFinger\(index)" : "teacherRightFinger\(index)"
            hand.addChildNode(finger)
        }
    }

