    private func makeStudentFace(seed: Int, profile: ClassmateProfile?) -> SCNNode {
        let root = SCNNode()
        let eyeColor = NSColor(calibratedWhite: 0.035, alpha: 1)
        let eyeWhite = NSColor(calibratedWhite: 0.94, alpha: 1)
        let browColor = NSColor(calibratedWhite: 0.035 + CGFloat(seed % 2) * 0.025, alpha: 1)
        let mouthColor = NSColor(calibratedRed: 0.36, green: 0.12, blue: 0.11, alpha: 1)
        let noseColor = NSColor(calibratedRed: 0.78, green: 0.55, blue: 0.43, alpha: 1)
        let anxious = (profile?.anxiety ?? 0) > 68
        let calm = (profile?.empathy ?? 0) > 72

        let leftEyeWhite = sphere(radius: 0.02, color: eyeWhite, position: SCNVector3(-0.052, 0.034, -0.139), scale: SCNVector3(1.25, anxious ? 0.58 : 0.78, 0.2))
        let rightEyeWhite = sphere(radius: 0.02, color: eyeWhite, position: SCNVector3(0.052, 0.034, -0.139), scale: SCNVector3(1.25, anxious ? 0.58 : 0.78, 0.2))
        leftEyeWhite.name = "leftEyeWhite"
        rightEyeWhite.name = "rightEyeWhite"
        root.addChildNode(leftEyeWhite)
        root.addChildNode(rightEyeWhite)

        let leftPupil = sphere(radius: 0.009, color: eyeColor, position: SCNVector3(-0.052, 0.032, -0.157), scale: SCNVector3(0.85, 1.0, 0.25))
        let rightPupil = sphere(radius: 0.009, color: eyeColor, position: SCNVector3(0.052, 0.032, -0.157), scale: SCNVector3(0.85, 1.0, 0.25))
        leftPupil.name = "leftPupil"
        rightPupil.name = "rightPupil"
        root.addChildNode(leftPupil)
        root.addChildNode(rightPupil)

        let leftHighlight = sphere(radius: 0.0035, color: NSColor(calibratedWhite: 1.0, alpha: 0.82), position: SCNVector3(-0.048, 0.037, -0.164), scale: SCNVector3(1, 0.7, 0.2))
        let rightHighlight = sphere(radius: 0.0035, color: NSColor(calibratedWhite: 1.0, alpha: 0.82), position: SCNVector3(0.056, 0.037, -0.164), scale: SCNVector3(1, 0.7, 0.2))
        leftHighlight.name = "leftEyeHighlight"
        rightHighlight.name = "rightEyeHighlight"
        root.addChildNode(leftHighlight)
        root.addChildNode(rightHighlight)

        let leftBrow = capsule(radius: 0.005, height: 0.065, color: browColor, position: SCNVector3(-0.052, 0.076, -0.15), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        let rightBrow = capsule(radius: 0.005, height: 0.065, color: browColor, position: SCNVector3(0.052, 0.076, -0.15), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        leftBrow.name = "leftBrow"
        rightBrow.name = "rightBrow"
        leftBrow.eulerAngles.z = CGFloat.pi / 2 + (anxious ? -0.18 : (calm ? 0.06 : 0))
        rightBrow.eulerAngles.z = CGFloat.pi / 2 + (anxious ? 0.18 : (calm ? -0.06 : 0))
        root.addChildNode(leftBrow)
        root.addChildNode(rightBrow)

        let upperLidColor = NSColor(calibratedWhite: 0.055, alpha: 0.52)
        let leftLid = box(width: 0.05, height: 0.008, length: 0.012, color: upperLidColor, position: SCNVector3(-0.052, 0.047, -0.162))
        let rightLid = box(width: 0.05, height: 0.008, length: 0.012, color: upperLidColor, position: SCNVector3(0.052, 0.047, -0.162))
        leftLid.name = "leftUpperLid"
        rightLid.name = "rightUpperLid"
        leftLid.opacity = anxious ? 0.4 : 0.12
        rightLid.opacity = anxious ? 0.4 : 0.12
        root.addChildNode(leftLid)
        root.addChildNode(rightLid)

        root.addChildNode(capsule(radius: 0.006, height: 0.045, color: noseColor, position: SCNVector3(0, 0.004, -0.155)))
        root.addChildNode(sphere(radius: 0.014, color: noseColor, position: SCNVector3(0, -0.022, -0.158), scale: SCNVector3(0.86, 0.72, 0.5)))

        let mouth = capsule(radius: 0.006, height: calm ? 0.078 : 0.066, color: mouthColor, position: SCNVector3(0, -0.062, -0.154), rotation: SCNVector4(0, 0, 1, Float.pi / 2))
        mouth.name = "mouth"
        mouth.eulerAngles.z = CGFloat.pi / 2 + (calm ? 0.04 : (anxious ? -0.04 : 0))
        root.addChildNode(mouth)

        let cheekColor = calm
            ? NSColor(calibratedRed: 0.92, green: 0.42, blue: 0.42, alpha: 0.18)
            : NSColor(calibratedRed: 0.5, green: 0.16, blue: 0.16, alpha: 0.08)
        root.addChildNode(sphere(radius: 0.018, color: cheekColor, position: SCNVector3(-0.09, -0.018, -0.152), scale: SCNVector3(1.2, 0.5, 0.18)))
        root.addChildNode(sphere(radius: 0.018, color: cheekColor, position: SCNVector3(0.09, -0.018, -0.152), scale: SCNVector3(1.2, 0.5, 0.18)))

        let tearColor = NSColor(calibratedRed: 0.58, green: 0.78, blue: 1.0, alpha: 0.58)
        let leftTear = capsule(radius: 0.0045, height: 0.06, color: tearColor, position: SCNVector3(-0.055, -0.004, -0.164), rotation: SCNVector4(1, 0, 0, 0.12))
        let rightTear = capsule(radius: 0.0045, height: 0.048, color: tearColor, position: SCNVector3(0.052, 0.0, -0.164), rotation: SCNVector4(1, 0, 0, -0.08))
        leftTear.name = "leftTear"
        rightTear.name = "rightTear"
        leftTear.opacity = 0
        rightTear.opacity = 0
        root.addChildNode(leftTear)
        root.addChildNode(rightTear)

        if anxious {
            let shadowColor = NSColor(calibratedWhite: 0.08, alpha: 0.72)
            root.addChildNode(capsule(radius: 0.004, height: 0.046, color: shadowColor, position: SCNVector3(-0.052, 0.01, -0.154), rotation: SCNVector4(0, 0, 1, Float.pi / 2)))
            root.addChildNode(capsule(radius: 0.004, height: 0.046, color: shadowColor, position: SCNVector3(0.052, 0.01, -0.154), rotation: SCNVector4(0, 0, 1, Float.pi / 2)))
        }

        return root
    }

    private func makeTeacherFace() -> SCNNode {
        let root = SCNNode()
        let eyeColor = NSColor(calibratedWhite: 0.025, alpha: 1)
        let eyeWhite = NSColor(calibratedWhite: 0.94, alpha: 1)
