        let noseColor = NSColor(calibratedRed: 0.75, green: 0.52, blue: 0.42, alpha: 1)
        root.addChildNode(capsule(radius: 0.006, height: 0.048, color: noseColor, position: SCNVector3(0, 0.003, -0.158)))
