        let root = SCNNode()
        root.addChildNode(box(width: 0.09, height: 0.012, length: 0.018, color: NSColor(calibratedWhite: 0.04, alpha: 1), position: SCNVector3(-0.045, 0.805, -0.118)))
        root.addChildNode(box(width: 0.09, height: 0.012, length: 0.018, color: NSColor(calibratedWhite: 0.04, alpha: 1), position: SCNVector3(0.045, 0.805, -0.118)))
        root.addChildNode(box(width: 0.028, height: 0.008, length: 0.014, color: NSColor(calibratedWhite: 0.04, alpha: 1), position: SCNVector3(0, 0.805, -0.12)))
        return root
    }

    private func studentUniformColor(seed: Int, profile: ClassmateProfile?, fallback: NSColor) -> NSColor {
        guard let profile else { return fallback }
        if profile.rebelliousness > 72 {
            return NSColor(calibratedRed: 0.46, green: 0.18, blue: 0.28, alpha: 1)
        }
        if profile.orderliness > 72 {
            return NSColor(calibratedRed: 0.15, green: 0.2, blue: 0.46, alpha: 1)
        }
        if profile.empathy > 72 {
            return NSColor(calibratedRed: 0.22, green: 0.42, blue: 0.38, alpha: 1)
        }
        if profile.anxiety > 68 {
            return NSColor(calibratedRed: 0.36, green: 0.34, blue: 0.46, alpha: 1)
        }
        return fallback
    }

    private func hairScale(seed: Int, profile: ClassmateProfile?) -> SCNVector3 {
        if profile?.rebelliousness ?? 0 > 72 {
            return SCNVector3(1.12, 0.58, 0.92)
        }
        if profile?.orderliness ?? 0 > 72 {
            return SCNVector3(0.94, 0.36, 0.94)
        }
        if profile?.empathy ?? 0 > 72 {
            return SCNVector3(1.02, 0.52, 1.12)
        }
        return SCNVector3(1, 0.45 + Float(seed % 3) * 0.04, 1)
    }

    private func applyCinematicMaterialPass(to root: SCNNode) {
        applyCinematicMaterialResponse(to: root)
        root.enumerateChildNodes { node, _ in
            self.applyCinematicMaterialResponse(to: node)
        }
    }

    private func applyCinematicMaterialResponse(to node: SCNNode) {
        guard let geometry = node.geometry else { return }
        let nodeName = (node.name ?? "").lowercased()
        for material in geometry.materials {
            configureCinematicMaterial(material, nodeName: nodeName)
        }
    }

    private func configureCinematicMaterial(_ material: SCNMaterial, nodeName: String) {
        material.lightingModel = .physicallyBased
        material.isDoubleSided = true
        material.locksAmbientWithDiffuse = false
        material.ambient.contents = NSColor(calibratedWhite: 0.035, alpha: 1)
        material.multiply.contents = NSColor(calibratedWhite: 0.96, alpha: 1)
        material.selfIllumination.contents = NSColor(calibratedWhite: 0.0, alpha: 1)

        let isTransparent = material.transparency < 0.99
            || nodeName.contains("glass")
            || nodeName.contains("window")
            || nodeName.contains("lens")
            || nodeName.contains("reflection")
            || nodeName.contains("glare")
            || nodeName.contains("bloom")
            || nodeName.contains("halo")
            || nodeName.contains("veil")
            || nodeName.contains("fog")
            || nodeName.contains("shaft")
            || nodeName.contains("mote")
            || nodeName.contains("dust")
            || nodeName.contains("rain")
            || nodeName.contains("condensation")
            || nodeName.contains("wet")
            || nodeName.contains("water")
            || nodeName.contains("tear")
            || nodeName.contains("cornea")
            || nodeName.contains("sclera")
            || nodeName.contains("sweat")
        if isTransparent {
            material.blendMode = .alpha
            material.writesToDepthBuffer = false
        }

        if nodeName.contains("gum") || nodeName.contains("sticker") || nodeName.contains("residue") {
            setMaterialResponse(material, roughness: 0.72, metalness: 0, specular: NSColor(calibratedWhite: 0.28, alpha: 1), fresnel: 1.1)
            setMaterialMicroSurface(material, occlusion: 0.68, normal: 0.16, multiply: NSColor(calibratedRed: 0.96, green: 0.92, blue: 0.84, alpha: 1), emission: NSColor(calibratedWhite: 0.0, alpha: 1))
        } else if nodeName.contains("rust") || nodeName.contains("oxid") {
