    private func setMaterialResponse(_ material: SCNMaterial, roughness: CGFloat, metalness: CGFloat, specular: NSColor, fresnel: CGFloat) {
        material.roughness.contents = NSNumber(value: Double(roughness))
        material.metalness.contents = NSNumber(value: Double(metalness))
        material.specular.contents = specular
        material.fresnelExponent = fresnel
    }

    private func setMaterialMicroSurface(_ material: SCNMaterial, occlusion: CGFloat, normal: CGFloat, multiply: NSColor, emission: NSColor) {
        material.ambientOcclusion.contents = NSColor(calibratedWhite: occlusion, alpha: 1)
        material.normal.intensity = normal
        material.multiply.contents = multiply
        material.selfIllumination.contents = emission
        material.emission.contents = emission
    }

    private func material(_ color: NSColor) -> SCNMaterial {
        let material = SCNMaterial()
        let displayColor = color.usingColorSpace(.deviceRGB) ?? color
        material.diffuse.contents = displayColor
        material.lightingModel = .physicallyBased
        material.roughness.contents = 0.68
        material.metalness.contents = 0.015
        material.specular.contents = NSColor(calibratedWhite: 0.22, alpha: 1)
        material.ambientOcclusion.contents = NSColor(calibratedWhite: 0.72, alpha: 1)
        material.multiply.contents = NSColor(calibratedWhite: 0.96, alpha: 1)
        material.normal.intensity = 0.08
        material.isDoubleSided = true
        if displayColor.alphaComponent < 0.99 {
            material.transparency = displayColor.alphaComponent
            material.blendMode = .alpha
            material.writesToDepthBuffer = false
        }
        return material
    }

    private func skinColor(_ seed: Int) -> NSColor {
        let colors = [
            NSColor(calibratedRed: 0.95, green: 0.82, blue: 0.68, alpha: 1),
            NSColor(calibratedRed: 0.86, green: 0.68, blue: 0.52, alpha: 1),
            NSColor(calibratedRed: 0.76, green: 0.56, blue: 0.4, alpha: 1)
        ]
        return colors[seed % colors.count]
    }

    private var wallColor: NSColor {
        NSColor(calibratedRed: 0.82, green: 0.84, blue: 0.78, alpha: 1)
    }

    private var skinTone: NSColor {
        NSColor(calibratedRed: 0.92, green: 0.74, blue: 0.58, alpha: 1)
    }
